window.HADITH_CACHE["abu-dawud_7"] = {"3501":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ إِسْحَقَ بْنِ سَعِيدِ بْنِ عَمْرٍو الْقُرَشِيِّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّهُ رَأَى رُفْقَةً مِنْ أَهْلِ الْيَمَنِ رِحَالُهُمْ الْأَدَمُ فَقَالَ مَنْ أَحَبَّ أَنْ يَنْظُرَ إِلَى أَشْبَهِ رُفْقَةٍ كَانُوا بِأَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَنْظُرْ إِلَى هَؤُلَاءِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dari [Waki'] dari [Ishaq bin Sa'id bin Amru Al Qurasyi] dari [Bapaknya] dari [Ibnu Umar] Bahwasanya ia melihat sekelompok orang-orang Yaman duduk di atas tikar dari kulit. Lalu ia berkata, \"Barangsiapa ingin melihat sekelompok orang seperti para sahabat Nabi shallallahu 'alaihi wasallam, maka lihatlah mereka.\""},"3502":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَّخَذْتُمْ أَنْمَاطًا قُلْتُ وَأَنَّى لَنَا الْأَنْمَاطُ قَالَ أَمَا إِنَّهَا سَتَكُونُ لَكُمْ أَنْمَاطٌ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnul Munkadir] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku, \"Apakah kalian memakai permadani? ' Aku menjawab, \"bagaimana boleh kami memakai permadani?\" beliau bersabda: \"Sesungguhnya ia baik untuk kalian.\""},"3503":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَأَحْمَدُ بْنُ مَنِيعٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ وِسَادَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ مَنِيعٍ الَّتِي يَنَامُ عَلَيْهَا بِاللَّيْلِ ثُمَّ اتَّفَقَا مِنْ أَدَمٍ حَشْوُهَا لِيفٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ahmad bin Mani'] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] ia berkata, \"Bantal Rasulullah shallallahu 'alaihi wasallam, -Ibnu Mani' menyebutkan-, 'yang beliau gunakan untuk tidur di waktu malam' dari kulit dan isinya dari serabut.\""},"3504":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ حَيَّانَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَتْ ضِجْعَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ","id":"Telah menceritakan kepada kami [Abu Taubah] berkata, telah menceritakan kepada kami [Sulaiman] -maksudnya Sulaiman bin Hayyan- dari [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] ia berkata, \"Tempat tidur Rasulullah shallallahu 'alaihi wasallam terbuat dari kulit dan isinya dari serabut.\""},"3505":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ فِرَاشُهَا حِيَالَ مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] ia berkata, \"Ranjang Ummu Salamah ada di hadapan masjid Rasulullah shallallahu 'alaihi wasallam.\""},"3506":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا فَوَجَدَ عَلَى بَابِهَا سِتْرًا فَلَمْ يَدْخُلْ قَالَ وَقَلَّمَا كَانَ يَدْخُلُ إِلَّا بَدَأَ بِهَا فَجَاءَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَرَآهَا مُهْتَمَّةً فَقَالَ مَا لَكِ قَالَتْ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيَّ فَلَمْ يَدْخُلْ فَأَتَاهُ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ فَاطِمَةَ اشْتَدَّ عَلَيْهَا أَنَّكَ جِئْتَهَا فَلَمْ تَدْخُلْ عَلَيْهَا قَالَ وَمَا أَنَا وَالدُّنْيَا وَمَا أَنَا وَالرَّقْمَ فَذَهَبَ إِلَى فَاطِمَةَ فَأَخْبَرَهَا بِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ قُلْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَأْمُرُنِي بِهِ قَالَ قُلْ لَهَا فَلْتُرْسِلْ بِهِ إِلَى بَنِي فُلَانٍحَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْأَسَدِيُّ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ بِهَذَا الْحَدِيثِ قَالَ وَكَانَ سِتْرًا مَوْشِيًّا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Numair] berkata, telah menceritakan kepada kami [Fudhail bin Ghazwan] dari [Nafi'] dari [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi Fatimah radliallahu 'anha dan mendapati di depan pintunya sebuah tirai, sehingga beliau tidak jadi masuk.\" Abdullah bin Umar berkata, \"jarang sekali beliau masuk melainkan menemui Fathimah dahulu, lalu Ali radliallahu 'anhu masuk dan melihat Fatimah dalam keadaan sedih. Maka ia bertanya, \"ada apa denganmu?\" Fathimah menjawab; \"Rasulullah shallallahu 'alaihi wasallam telah datang namun tidak masuk\", maka Ali datang menemui beliau dan berkata; \"Wahai Rasulullah sesungguhnya Fathimah sangat bersedih, karena engkau datang kepadanya namun tidak menemuinya\" Rasulullah shallallahu 'alaihi wasallam bersabda; \"aku tidak mencintai dunia, dan aku tidak menyukai lukisan (gambar).\", lalu Ali pergi menemui Fathimah dan memberitahukan sabda Rasulullah kepadanya, Fathimah berkata; katakan kepada Rasulullah apa yang beliau perintahkan dengan tirai yang berlukis tersebut, Rasulullah shallallahu 'alaihi wasallam bersabda; \"katakan kepadanya agar mengirim tirai berlukis itu kepada Bani Fulan.\", (perawi berkata;) telah menceritakan hadits ini kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Ibnu Fudhail] dari [bapaknya] ia berkata; \"tirai tersebut adalah tirai yang berlukis (bergambar).\""},"3507":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى حَدَّثَنَا عِمْرَانُ بْنُ حِطَّانَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَتْرُكُ فِي بَيْتِهِ شَيْئًا فِيهِ تَصْلِيبٌ إِلَّا قَضَبَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Aban] berkata, telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Imran bin Hithan] dari ['Aisyah radliallahu 'anha] berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam meninggalkan sesuatu yang berbentuk salib di rumahnya kecuali beliau pasti memotongnya.\""},"3508":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ صُورَةٌ وَلَا كَلْبٌ وَلَا جُنُبٌ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abdullah bin Nujay] dari [Bapaknya] dari [Ali radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan masuk ke rumah yang di dalamnya ada gambar, atau anjing, atau orang junub (yang tidak bersuci dari dari junubnya dan menjadikannya kebiasaan).\""},"3509":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ سُهَيْلٍ يَعْنِي ابْنَ أَبِي صَالِحٍ عَنْ سَعِيدِ بْنِ يَسَارٍ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ عَنْ أَبِي طَلْحَةَ الْأَنْصَارِيِّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا تِمْثَالٌ وَقَالَ انْطَلِقْ بِنَا إِلَى أُمِّ الْمُؤْمِنِينَ عَائِشَةَ نَسْأَلْهَا عَنْ ذَلِكَ فَانْطَلَقْنَا فَقُلْنَا يَا أُمَّ الْمُؤْمِنِينَ إِنَّ أَبَا طَلْحَةَ حَدَّثَنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَذَا وَكَذَا فَهَلْ سَمِعْتِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ ذَلِكَ قَالَتْ لَا وَلَكِنْ سَأُحَدِّثُكُمْ بِمَا رَأَيْتُهُ فَعَلَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ مَغَازِيهِ وَكُنْتُ أَتَحَيَّنُ قُفُولَهُ فَأَخَذْتُ نَمَطًا كَانَ لَنَا فَسَتَرْتُهُ عَلَى الْعَرَضِ فَلَمَّا جَاءَ اسْتَقْبَلْتُهُ فَقُلْتُ السَّلَامُ عَلَيْكَ يَا رَسُولَ اللَّهِ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ الْحَمْدُ لِلَّهِ الَّذِي أَعَزَّكَ وَأَكْرَمَكَ فَنَظَرَ إِلَى الْبَيْتِ فَرَأَى النَّمَطَ فَلَمْ يَرُدَّ عَلَيَّ شَيْئًا وَرَأَيْتُ الْكَرَاهِيَةَ فِي وَجْهِهِ فَأَتَى النَّمَطَ حَتَّى هَتَكَهُ ثُمَّ قَالَ إِنَّ اللَّهَ لَمْ يَأْمُرْنَا فِيمَا رَزَقَنَا أَنْ نَكْسُوَ الْحِجَارَةَ وَاللَّبِنَ قَالَتْ فَقَطَعْتُهُ وَجَعَلْتُهُ وِسَادَتَيْنِ وَحَشَوْتُهُمَا لِيفًا فَلَمْ يُنْكِرْ ذَلِكَ عَلَيَّحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ بِإِسْنَادِهِ مِثْلِهِ قَالَ فَقُلْتُ يَا أُمَّهْ إِنَّ هَذَا حَدَّثَنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَالَ فِيهِ سَعِيدُ بْنُ يَسَارٍ مَوْلَى بَنِي النَّجَّارِ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] berkata, telah mengabarkan kepada kami [Khalid] dari [Suhail] -maksudnya Suhail bin Abu Shalih- dari [Sa'id bin Yasar Al Anshari] dari [Zaid bin Khalid Al Juhani] dari [Abu Thalhah Al Anshari] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing atau patung.\" Zaid bin Khalid berkata, \"Mari kita menemui 'Aisyah Ummul Mukminin untuk bertanya kepadanya tentang hal itu.\" Maka kami berangkat menemui 'Aisyah, kami lalu bertanya, \"Wahai Ummul Mukmini, Abu Thalhah menceritakan kepada kami dari Rasulullah shallallahu 'alaihi wasallam begini dan begini, maka apakah engkau mendengar Nabi shallallahu 'alaihi wasallam mengatakan itu?\" 'Aisyah menjawab, \"Tidak, tetapi akan aku ceritakan kepada kalian apa yang beliau lakukan. Rasulullah shallallahu 'alaihi wasallam pernah keluar dalam salah satu peperangannya, terkadang aku membawa kunci rumah hingga aku dapat mengambil permadani bergambar dan kujadikan sebagai tirai jendela. Ketika beliau datang, aku menyambutnya seraya mengucapkan, 'Wahai Rasulullah, assalaamu 'alaikum warahmatullah wa barakaatuhu. Segala puji bagi Allah yang memuliakan dan mengagungkanmu. Beliau lantas melihat ke arah rumah dan melihat permadani tersebut, beliau tidak menjawab salamku. Dan aku melihat kebencian di wajahnya. Beliau mendatangi permadani itu dan melepaskannya. Kemudian beliau bersabda: \"Allah tidak memerintahkan kepada kita atas apa yang Ia berikan kepada kita untuk memberi pakaian pada batu dan bata.\" 'Aisyah berkata, \"Aku lalu memotong kain tersebut dan menjadikannya dua bantal yang bagian dalamnya aku isi dengan serabut, dan beliau tidak mengingkarinya.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Suhail] dengan sanad yang sama. Ia berkata; Aku berkata, \"Wahai ibu ('Aisyah), orang menyampaikan hadits kepadaku, bahwa Rasulullah shallallahu 'alaihi wasallam mengatakan begini dan begini.\" Sa'id bin Yasar mantan budak bani An Najar juga menyebutkan hadits ini. "},"3510":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ عَنْ أَبِي طَلْحَةَ أَنَّهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ صُورَةٌقَالَ بُسْرٌ ثُمَّ اشْتَكَى زَيْدٌ فَعُدْنَاهُ فَإِذَا عَلَى بَابِهِ سِتْرٌ فِيهِ صُورَةٌ فَقُلْتُ لِعُبَيْدِ اللَّهِ الْخَوْلَانِيِّ رَبِيبِ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ يُخْبِرْنَا زَيْدٌ عَنْ الصُّوَرِ يَوْمَ الْأَوَّلِ فَقَالَ عُبَيْدُ اللَّهِ أَلَمْ تَسْمَعْهُ حِينَ قَالَ إِلَّا رَقْمًا فِي ثَوْبٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Busr bin Said] dari [Zaid bin Khalid] dari [Abu Thalhah] Bahwasanya ia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya para malaikat tidak akan masuk ke dalam rumah yang di dalamnya ada gambar.\" Busr berkata, \"Ketika Zaid jatuh sakit kami menjenguknya, sementara di pintunya ada tirai yang bergambar. Maka aku berkata kepada [Ubaidullah Al Khaulani], pembantu Maimunah isteri Nabi shallallahu 'alaihi wasallam, \"Bukankah Zaid telah mengabarkan kepada kita tentang hukum, gambar sejak awal!\" Ubaidullah berkata, \"Tidakkah engkau mendengar ketika ia mengatakan, \"Kecuali gambar ukiran pada kain?\""},"3511":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ أَنَّ إِسْمَعِيلَ بْنَ عَبْدِ الْكَرِيمِ حَدَّثَهُمْ قَالَ حَدَّثَنِي إِبْرَاهِيمُ يَعْنِي ابْنَ عَقِيلٍ عَنْ أَبِيهِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ زَمَنَ الْفَتْحِ وَهُوَ بِالْبَطْحَاءِ أَنْ يَأْتِيَ الْكَعْبَةَ فَيَمْحُوَ كُلَّ صُورَةٍ فِيهَا فَلَمْ يَدْخُلْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى مُحِيَتْ كُلَّ صُورَةٍ فِيهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah] bahwa [Isma'il bin Abdul Karim] menceritakan kepada mereka, ia berkata; telah menceritakan kepadaku [Ibrahim] -maksudnya Ibrahim bin Aqil- dari [bapaknya] dari [Wahb bin Munabbih] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan Umar Ibnul Khaththab radliallahu 'anhu -pada waktu pembukaan (penaklukan) kota Makkah, dan ia berada di daerah Bathha- agar datang ke Ka'bah untuk menghapus semua gambar yang ada di dalamnya. Dan Nabi shallallahu 'alaihi wasallam tidak akan masuk ke dalam Ka'bah hingga semua gambar yang ada di dalamnya telah dihapus.\""},"3512":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ السَّبَّاقِ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَتْنِي مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام كَانَ وَعَدَنِي أَنْ يَلْقَانِي اللَّيْلَةَ فَلَمْ يَلْقَنِي ثُمَّ وَقَعَ فِي نَفْسِهِ جَرْوُ كَلْبٍ تَحْتَ بِسَاطٍ لَنَا فَأَمَرَ بِهِ فَأُخْرِجَ ثُمَّ أَخَذَ بِيَدِهِ مَاءً فَنَضَحَ بِهِ مَكَانَهُ فَلَمَّا لَقِيَهُ جِبْرِيلُ عَلَيْهِ السَّلَام قَالَ إِنَّا لَا نَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ فَأَصْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَتْلِ الْكِلَابِ حَتَّى إِنَّهُ لَيَأْمُرُ بِقَتْلِ كَلْبِ الْحَائِطِ الصَّغِيرِ وَيَتْرُكُ كَلْبَ الْحَائِطِ الْكَبِيرِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Ibnu As Sabbaq] dari [Ibnu Abbas] ia berkata; telah menceritakan kepadaku [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jibril Alaihis Salam pernah berjanji untuk menemuiku pada waktu malam, tetapi ia tidak datang.\" Kemudian beliau teringat bahwa ada anak anjing berada di bawah permadani milik kami, beliau memerintahkan (agar anjing itu dikeluarkan). Anak anjing itu lalu dikeluarkan, kemudian beliau mengambil air dengan tangannya seraya memercikkan pada bekasnya. Ketika Jibril Alaihis Salam menemui beliau, ia berkata, \"Sesungguhnya kami tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing atau gambar.\" Setelah itu Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing-anjing hingga beliau juga memerintahkan untuk membunuh anjing penjaga kebun yang masih kecil, dan membiarkan anjing penjaga kebun yang sudah besar.\""},"3513":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ لِي أَتَيْتُكَ الْبَارِحَةَ فَلَمْ يَمْنَعْنِي أَنْ أَكُونَ دَخَلْتُ إِلَّا أَنَّهُ كَانَ عَلَى الْبَابِ تَمَاثِيلُ وَكَانَ فِي الْبَيْتِ قِرَامُ سِتْرٍ فِيهِ تَمَاثِيلُ وَكَانَ فِي الْبَيْتِ كَلْبٌ فَمُرْ بِرَأْسِ التِّمْثَالِ الَّذِي فِي الْبَيْتِ يُقْطَعُ فَيَصِيرُ كَهَيْئَةِ الشَّجَرَةِ وَمُرْ بِالسِّتْرِ فَلْيُقْطَعْ فَلْيُجْعَلْ مِنْهُ وِسَادَتَيْنِ مَنْبُوذَتَيْنِ تُوطَآَنِ وَمُرْ بِالْكَلْبِ فَلْيُخْرَجْ فَفَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا الْكَلْبُ لِحَسَنٍ أَوْ حُسَيْنٍ كَانَ تَحْتَ نَضَدٍ لَهُمْ فَأُمِرَ بِهِ فَأُخْرِجَقَالَ أَبُو دَاوُد وَالنَّضَدُ شَيْءٌ تُوضَعُ عَلَيْهِ الثِّيَابُ شَبَهُ السَّرِيرِ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa] berkata, telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Yunus bin Abu Ishaq] dari [Mujahid] ia berkata; telah menceritakan kepada kami [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril Alaihis Salam datang menemuiku dan berkata, \"Tadi malam aku datang untuk menemuimu, dan tidak ada yang menghalangiku untuk masuk kecuali patung yang ada di atas pintu. Di dalam rumah juga ada kain satir tipis yang bergambar patung, serta terdapat anjing, maka perintahkanlah memotong kepala patung yang berada di rumah hingga berbentuk pohon, dan perintahkanlah memotong tirai untuk dijadikan dua bantal yang diduduki, dan perintahkanlah untuk mengeluarkan anjing.\" Rasulullah shallallahu 'alaihi wasallam pun melakukan saran Jibril, namun tiba-tiba anjing milik Hasan atau Husain berada di bawah ranjang (rak), maka beliau memerintahkan untuk mengeluarkan hingga ia pun dikeluarkan.\" Abu Dawud berkata, \"An Nadhad adalah sesuatu yang digunakan untuk meletakkan pakaian, semisal ranjang.\""},"3514":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّرَجُّلِ إِلَّا غِبًّا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam bin Hassan] dari [Al Hasan] dari [Abdullah bin Mughaffal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengurai rambut untuk dibersihkan atau dibaguskan kecuai sesekali saja.\""},"3515":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَأَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحَلَ إِلَى فَضَالَةَ بْنِ عُبَيْدٍ وَهُوَ بِمِصْرَ فَقَدِمَ عَلَيْهِ فَقَالَ أَمَا إِنِّي لَمْ آتِكَ زَائِرًا وَلَكِنِّي سَمِعْتُ أَنَا وَأَنْتَ حَدِيثًا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَوْتُ أَنْ يَكُونَ عِنْدَكَ مِنْهُ عِلْمٌ قَالَ وَمَا هُوَ قَالَ كَذَا وَكَذَا قَالَ فَمَا لِي أَرَاكَ شَعِثًا وَأَنْتَ أَمِيرُ الْأَرْضِ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَانَا عَنْ كَثِيرٍ مِنْ الْإِرْفَاهِ قَالَ فَمَا لِي لَا أَرَى عَلَيْكَ حِذَاءً قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نَحْتَفِيَ أَحْيَانًا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Al Jurairi] dari [Abdullah bin Buraidah] berkata, \"Seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam berkunjung ke rumah [Fadhalah bin Ubaid] yang berada di Mesir. Ia lalu datang kepadanya seraya berkata, \"Aku datang kepadamu bukan untuk berkunjung, tetapi aku dan kamu sendiri telah mendengar hadits Rasulullah shallallahu 'alaihi wasallam, maka aku berharap engkau mempunyai ilmu tentang itu.\" Fadhalah bertanya, \"Hadits tentang apa itu?\" sahabat Nabi itu menjawab, \"Begini dan begini.\" Fadhalah bertanya, \"Kenapa rambutmu tampak kusut dan berantakan, padahal engkau adalah seorang pemimpin?\" ia menjawab, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kita untuk bermewah-mewah.\" Fadhalah lalu bertanya lagi, \"Kenapa aku juga melihatmu tidak mengenakan sepatu?\" ia menjawab, \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk berjalan dengan tanpa alas kaki sesekali.\""},"3516":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أُمَامَةَ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي أُمَامَةَ قَالَذَكَرَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا عِنْدَهُ الدُّنْيَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَسْمَعُونَ أَلَا تَسْمَعُونَ إِنَّ الْبَذَاذَةَ مِنْ الْإِيمَانِ إِنَّ الْبَذَاذَةَ مِنْ الْإِيمَانِ يَعْنِي التَّقَحُّلَقَالَ أَبُو دَاوُد هُوَ أَبُو أُمَامَةَ بْنُ ثَعْلَبَةَ الْأَنْصَارِيُّ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Umamah] dari [Abdullah bin Ka'b bin Malik] dari [Abu Umamah] ia berkata, \"Pada suatu hari sahabat Rasulullah shallallahu 'alaihi wasallam memperbincangkan tentang dunia di sisinya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kalian mendengar? Tidakkah kalian mendengar? Sesungguhnya sederhana dalam berpakaian adalah bagian dari iman. Sesungguhnya sederhana dalam berpakaian adalah bagian dari iman.\" Maksudnya adalah berpakaian apa adanya dan pantas.\", Abu Dawud berkata; \"Dia adalah Abu Umamah bin Tsa'labah Al Anshari.\""},"3517":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ عَنْ شَيْبَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ الْمُخْتَارِ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُكَّةٌ يَتَطَيَّبُ مِنْهَا","id":"Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Abu Ahmad] dari [Syaiban bin 'Abdurrahman] dari [Abdullah Ibnul Mukhtar] dari [Musa bin Anas] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam mempunyai sukkah (minyak terbagus) yang biasa beliau gunakan untuk wewangian.\""},"3518":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي ابْنُ أَبِي الزِّنَادِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ لَهُ شَعْرٌ فَلْيُكْرِمْهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al mahri] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepadaku [Ibnu Abu Az Zinad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempunyai rambut hendaklah ia memuliakannya (merawat).\""},"3519":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ قَالَ حَدَّثَتْنِي كَرِيمَةُ بِنْتُ هَمَّامٍأَنَّ امْرَأَةً أَتَتْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَسَأَلَتْهَا عَنْ خِضَابِ الْحِنَّاءِ فَقَالَتْ لَا بَأْسَ بِهِ وَلَكِنْ أَكْرَهُهُ كَانَ حَبِيبِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ رِيحَهُقَالَ أَبُو دَاوُد تَعْنِي خِضَابَ شَعْرِ الرَّأْسِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ali Ibnul Mubarak] ia berkata; telah menceritakan kepadaku [Karimah binti Hammam] berkata, \"bahwasanya ada seorang wanita yang datang menemui ['Aisyah radliallahu 'anha], lalu ia bertanya kepadanya tentang pewarna dari pacar?\" maka ia menjawab, \"Tidak apa-apa, hanya saja aku tidak menyukainya karena kekasihku, Rasulullah shallallahu 'alaihi wasallam tidak menyukai baunya.\" Abu Dawud berkata, \"Yakni pewarna rambut.\""},"3520":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَتْنِي غِبْطَةُ بِنْتُ عَمْرٍو الْمُجَاشِعِيَّةُ قَالَتْ حَدَّثَتْنِي عَمَّتِي أُمُّ الْحَسَنِ عَنْ جَدَّتِهَا عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ هِنْدَ بِنْتَ عُتْبَةَ قَالَتْ يَا نَبِيَّ اللَّهِ بَايِعْنِي قَالَ لَا أُبَايِعُكِ حَتَّى تُغَيِّرِي كَفَّيْكِ كَأَنَّهُمَا كَفَّا سَبُعٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepadaku [Ghibthah binti Amru Al Mujasyi'iyah] ia berkata; telah menceritakan kepadaku bibiku [Ummul Hasan] dari [Neneknya] dari ['Aisyah radliallahu 'anha] bahwa Hind binti Utbah berkata, \"Wahai Nabi Allah, baiatlah aku.\" Beliau bersabda: \"Aku tidak akan membaiatmu hingga kamu mengubah (pewarna) kedua telapak tanganmu, sebab kedua telapak tangannya seperti telapak tangan binatang buas.\""},"3521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُحَمَّدٍ الصُّورِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا مُطِيعُ بْنُ مَيْمُونٍ عَنْ صَفِيَّةَ بِنْتِ عِصْمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَوْمَتْ امْرَأَةٌ مِنْ وَرَاءِ سِتْرٍ بِيَدِهَا كِتَابٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقَالَ مَا أَدْرِي أَيَدُ رَجُلٍ أَمْ يَدُ امْرَأَةٍ قَالَتْ بَلْ امْرَأَةٌ قَالَ لَوْ كُنْتِ امْرَأَةً لَغَيَّرْتِ أَظْفَارَكِ يَعْنِي بِالْحِنَّاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Muhammad Ash Shuri] berkata, telah menceritakan kepada kami [Khalid bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Muthi' bin Maimun] dari [Shafiyah binti Ishmah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Seorang wanita dari balik satir memberikan kitab (Al Qur'an kepada Rasulullah shallallahu 'alaihi wasallam, lalu Nabi shallallahu 'alaihi wasallam memegang tangannya. Beliau bersabda: \"Aku tidak tahu, ini tangan laki-laki atau tangan perempuan?\" Wanita itu menjawab, \"Ini tangan perempuan.\" Beliau bersabda lagi: \"Jika kamu perempuan maka ubahlah warna kulitmu.\" Yaitu dengan pacar. "},"3522":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِأَنَّهُ سَمِعَ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ عَامَ حَجَّ وَهُوَ عَلَى الْمِنْبَرِ وَتَنَاوَلَ قُصَّةً مِنْ شَعْرٍ كَانَتْ فِي يَدِ حَرَسِيٍّ يَقُولُ يَا أَهْلَ الْمَدِينَةِ أَيْنَ عُلَمَاؤُكُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ مِثْلِ هَذِهِ وَيَقُولُ إِنَّمَا هَلَكَتْ بَنُو إِسْرَائِيلَ حِينَ اتَّخَذَ هَذِهِ نِسَاؤُهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] Bahwasanya ia mendengar [Mu'awiyah bin Abu Sufyan] berkata di atas mimbar pada tahun haji -saat itu ia memegang wig yang berada di tangan penjaga, \"Wahai penduduk Madinah, di mana ulama kalian! Aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari perkara semacam ini, beliau bersabda: \"Hanyasanya orang-orang bani Isra'il hancur karena wanita-wanita mereka menggunakan barang ini.\""},"3523":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; telah menceritakan kepadaku [Nafi'] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan wanita yang minta untuk disambung rambutnya, wanita yang mentato dan wanita yang minta untuk ditato.\""},"3524":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ عَزَّ وَجَلَّ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ زَادَ عُثْمَانُ كَانَتْ تَقْرَأُ الْقُرْآنَ ثُمَّ اتَّفَقَا فَأَتَتْهُ فَقَالَتْ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ قَالَ عُثْمَانُ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ تَعَالَى فَقَالَ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ تَعَالَى قَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ لَوْحَيْ الْمُصْحَفِ فَمَا وَجَدْتُهُ فَقَالَ وَاللَّهِ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ ثُمَّ قَرَأَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ إِنِّي أَرَى بَعْضَ هَذَا عَلَى امْرَأَتِكَ قَالَ فَادْخُلِي فَانْظُرِي فَدَخَلَتْ ثُمَّ خَرَجَتْ فَقَالَ مَا رَأَيْتِو قَالَ عُثْمَانُ فَقَالَتْ مَا رَأَيْتُ فَقَالَ لَوْ كَانَ ذَلِكَ مَا كَانَتْ مَعَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Isa] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Allah melaknat wanita yang mentato dan wanita yang minta untuk ditato.\" Muhammad menyebutkan, \"dan wanita yang meyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur bulu alis.\" Dan keduanya sepakat dengan penyebutan, \"dan mengikir gigi untuk kecantikan dengan merubah ciptaan Allah Azza Wa Jalla. Hadits ini kemudian di dengar oleh seorang wanita dari bani Asad yang biasa di panggil dengan nama Ummu Ya'qub, Utsman menambahkan, \"yang sedang membaca Al-Qur'an. Ia lalu mendatangi Abdullah dan berkata, \"Telah sampai kabar kepadaku bahwa engkau melaknat Wanita yang mentato dan wanita yang minta untuk ditato?\" Muhammad menyebutkan, \"dan wanita yang menyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur alis. Kemudian keduanya sepakat dengan penyebutan, \"wanita yang mengikir gigi, Utsman menyebutkan, \"untuk kecantikan dengan merubah ciptaan Allah Ta'ala.\" Ummu Ya'qub berkata, \"Aku telah membaca lembaran-lembaran Al-Qur'an tetapi aku tidak mendapatkannya.\" Abdullah berkata, \"Demi Allah, jika engkau membacanya, sungguh engkau pasti mendapatkannya.\" Kemudian Abdullah membaca: (Apa yang diberikan Rasul kepadamu maka terimalah dia, dan apa yang dilarangnya bagimu maka tinggalkanlah.. (Qs. Al Hasyr: 7).\" Ummu Ya'qub berkata, \"Aku melihat hal ini ada pada isterimu!\" Abdullah berkata, \"Masuk dan lihatlah.\" Ummu Ya'qub kemudian masuk dan keluar lagi. Abdullah berkata, \"Apa yang engkau lihat?\" Utsman berkata (dalam riwayatnya) maka Ummu Ya'qub berkata; \"Aku tidak melihatnya\", Ibnu Mas'ud berkata; \"Jikalau hal itu ada pada istriku niscaya dia tidak akan ada bersama kami.\""},"3525":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ أُسَامَةَ عَنْ أَبَانَ بْنِ صَا��ِحٍ عَنْ مُجَاهِدِ بْنِ جَبْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلُعِنَتْ الْوَاصِلَةُ وَالْمُسْتَوْصِلَةُ وَالنَّامِصَةُ وَالْمُتَنَمِّصَةُ وَالْوَاشِمَةُ وَالْمُسْتَوْشِمَةُ مِنْ غَيْرِ دَاءٍقَالَ أَبُو دَاوُد وَتَفْسِيرُ الْوَاصِلَةِ الَّتِي تَصِلُ الشَّعْرَ بِشَعْرِ النِّسَاءِ وَالْمُسْتَوْصِلَةُ الْمَعْمُولُ بِهَا وَالنَّامِصَةُ الَّتِي تَنْقُشُ الْحَاجِبَ حَتَّى تُرِقَّهُ وَالْمُتَنَمِّصَةُ الْمَعْمُولُ بِهَا وَالْوَاشِمَةُ الَّتِي تَجْعَلُ الْخِيلَانَ فِي وَجْهِهَا بِكُحْلٍ أَوْ مِدَادٍ وَالْمُسْتَوْشِمَةُ الْمَعْمُولُ بِهَا","id":"Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Usamah] dari [Aban bin Shalih] dari [Mujahid bin Jabr] dari [Ibnu Abbas] ia berkata, \"Telah dilaknat wanita yang menyambung rambut dan wanita yang minta untuk disambung rambutnya, wanita yang mencabut alis dan wanita yang minta dicabut alisnya, wanita yang mentato dan wanita yang minta antuk ditato, tanpa ada penyakit.\" Abu Dawud berkata, \"Al Washilah adalah wanita yang menyambung rambutnya dengan rambut wanita (wig). Al Mustaushilat adalah orang yang disambung rambutnya. An Namishat adalah orang yang mencabut alisnya hingga tipis, dan Al Mutanamishat adalah orang yang minta dicabut alisnya. Al Wasyimah adalah orang yang membuat tato di wajahnya baik dengan celak atau tinta, Al Mustausyimah adalah orang yang minta ditato.\""},"3526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرِ بْنِ زِيَادٍ قَالَ حَدَّثَنَا شَرِيَكٌ عَنْ سَالِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَلَا بَأْسَ بِالْقَرَامِلِقَالَ أَبُو دَاوُد كَأَنَّهُ يَذْهَبُ إِلَى أَنَّ الْمَنْهِيَّ عَنْهُ شُعُورُ النِّسَاءِ قَالَ أَبُو دَاوُد كَانَ أَحْمَدُ يَقُولُ الْقَرَامِلُ لَيْسَ بِهِ بَأْسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far bin Ziyad] ia berkata; telah menceritakan kepada kami [Syarik] dari [Salim] dari [Sa'id bin Jubair] ia berkata, \"Benang sutera tidak apa-apa.\" Abu Dawud berkata, \"Seakan-akan ia berpendapat bahwa yang dilarang adalah rambut wanita.\" Abu Dawud berkata, \"Ahmad berkata, \"Benang dari sutera tidak ada masalah (boleh).\""},"3527":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْمَعْنَى أَنَّ أَبَا عَبْدِ الرَّحْمَنِ الْمُقْرِئَ حَدَّثَهُمْ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عُرِضَ عَلَيْهِ طِيبٌ فَلَا يَرُدَّهُ فَإِنَّهُ طَيِّبُ الرِّيحِ خَفِيفُ الْمَحْمَلِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Harun bin Abdullah] secara makna, bahwa [Abu 'Abdurrahman Al Muqri] menceritakan kepada mereka dari [Sa'id bin Abu Ayyub] dari [Ubaidullah bin Abu Ja'far] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ditawari minyak wangi janganlah menolak, karena minyak wangi itu enak aromanya dan ringan membawanya.\""},"3528":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى أَخْبَرَنَا ثَابِتُ بْنُ عُمَارَةَ حَدَّثَنِي غُنَيْمُ بْنُ قَيْسٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَعْطَرَتْ الْمَرْأَةُ فَمَرَّتْ عَلَى الْقَوْمِ لِيَجِدُوا رِيحَهَا فَهِيَ كَذَا وَكَذَا قَالَ قَوْلًا شَدِيدًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] berkata, telah mengabarkan kepada kami [Tsabit bin Umarah] berkata, telah menceritakan kepadaku [Ghunaim bin Qais] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang wanita memakai wewangian, lalu sengaja melewati suatu kaum agar mereka mencium baunya, maka ia adalah begini dan begini.\" Beliau mengatakan itu dengan intonasi yang keras.\""},"3529":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عُبَيْدٍ مَوْلَى أَبِي رُهْمٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَقِيَتْهُ امْرَأَةٌ وَجَدَ مِنْهَا رِيحَ الطِّيبِ يَنْفَحُ وَلِذَيْلِهَا إِعْصَارٌ فَقَالَ يَا أَمَةَ الْجَبَّارِ جِئْتِ مِنْ الْمَسْجِدِ قَالَتْ نَعَمْ قَالَ وَلَهُ تَطَيَّبْتِ قَالَتْ نَعَمْ قَالَ إِنِّي سَمِعْتُ حِبِّي أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْبَلُ صَلَاةٌ لِامْرَأَةٍ تَطَيَّبَتْ لِهَذَا الْمَسْجِدِ حَتَّى تَرْجِعَ فَتَغْتَسِلَ غُسْلَهَا مِنْ الْجَنَابَةِقَالَ أَبُو دَاوُد الْإِعْصَارُ غُبَارٌ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah menceritakan kepada kami [Sufyan] dari [Ashim bin Ubaidullah] dari [Ubaid] mantan budak Abu Ruhm, dari [Abu Hurairah] ia berkata, \"Ia bertemu seorang wanita dan mencium bau harum darinya, dan ujung pakaiannya menjuntai (menyapu tanah). Ia lalu berkata, \"Wahai Budak Al Jabbar, apakah engkau datang dari masjid?\" wanita itu menjawab, \"Ya.\" Abu Hurairah bertanya lagi, \"Karena ingin ke masjidkah kamu memakai wewangian?\" wanita itu menjawab, \"Ya.\" Abu Hurairah lalu berkata, \"Sesungguhnya aku mendengar kekasihku, Abu Al Qasim shallallahu 'alaihi wasallam bersabda: \"Tidak akan diterima shalat seorang wanita yang memakai wewangian karena ingin pergi ke masjid ini, sehingga ia kembali dan mandi sebagaimana ia mandi dari junub.\" Abu Dawud berkata, \"Al I'shar maksudnya adalah debu.\""},"3530":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ وَسَعِيدُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَبُو عَلْقَمَةَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ أَصَابَتْ بَخُورًا فَلَا تَشْهَدَنَّ مَعَنَا الْعِشَاءَ قَالَ ابْنُ نُفَيْلٍ عِشَاءَ الْآخِرَةِ","id":"Telah menceritakan kepada kami [An nufaili] dan [Sa'id bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Muhammad Abu Alqamah] ia berkata; telah menceritakan kepadaku [Yazid bin Khushaifah] dari [Busr bin Sa'id] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang terkena bakhur (wewangian), maka jangan sekali-kali ia shalat isya bersama kami.\" Ia (perawi) berkata, \"Maksudnya adalah shalat isya yang akhir (larut malam).\""},"3531":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَطَاءٌ الْخُرَاسَانِيُّ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَقَدِمْتُ عَلَى أَهْلِي لَيْلًا وَقَدْ تَشَقَّقَتْ يَدَايَ فَخَلَّقُونِي بِزَعْفَرَانٍ فَغَدَوْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ وَلَمْ يُرَحِّبْ بِي وَقَالَ اذْهَبْ فَاغْسِلْ هَذَا عَنْكَ فَذَهَبْتُ فَغَسَلْتُهُ ثُمَّ جِئْتُ وَقَدْ بَقِيَ عَلَيَّ مِنْهُ رَدْعٌ فَسَلَّمْتُ فَلَمْ يَرُدَّ عَلَيَّ وَلَمْ يُرَحِّبْ بِي وَقَالَ اذْهَبْ فَاغْسِلْ هَذَا عَنْكَ فَذَهَبْتُ فَغَسَلْتُهُ ثُمَّ جِئْتُ فَسَلَّمْتُ عَلَيْهِ فَرَدَّ عَلَيَّ وَرَحَّبَ بِي وَقَالَ إِنَّ الْمَلَائِكَةَ لَا تَحْضُرُ جَنَازَةَ الْكَافِرِ بِخَيْرٍ وَلَا الْمُتَضَمِّخَ بِالزَّعْفَرَانِ وَلَا الْجُنُبَ قَالَ وَرَخَّصَ لِلْجُنُبِ إِذَا نَامَ أَوْ أَكَلَ أَوْ شَرِبَ أَنْ يَتَوَضَّأَحَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءِ ابْنِ أَبِي الْخُوَارِ أَنَّهُ سَمِعَ يَحْيَى بْنَ يَعْمَرَ يُخْبِرُ عَنْ رَجُلٍ أَخْبَرَهُ عَنْ عَمَّارِ بْنِ يَاسِرٍ زَعَمَ عُمَرُ أَنَّ يَحْيَى سَمَّى ذَلِكَ الرَّجُلَ فَنَسِيَ عُمَرُ اسْمَهُ أَنَّ عَمَّارًا قَالَ تَخَلَّقْتُ بِهَذِهِ الْقِصَّةِ وَالْأَوَّلُ أَتَمُّ بِكَثِيرٍ فِيهِ ذِكْرُ الْغُسْلِ قَالَ قُلْتُ لِعُمَرَ وَهُمْ حُرُمٌ قَالَ لَا الْقَوْمُ مُقِيمُونَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Atha Al Khurasani] dari [Yahya bin Ya'mar] dari [Ammar bin Yasir] ia berkata, \"Aku kembali ke rumah di waktu yang sudah malam, dan tanganku terlihat pecah-pecah hingga mereka melumuri aku dengan Za'faran (yang berwarna kuning). Aku lalu mendatangi Nabi shallallahu 'alaihi wasallam di waktu pagi, aku mengucapkan salam namun beliau tidak menjawab salam atau menyambutku. Bahkan beliau bersabda: \"Pergi dan bersihkanlah ini darimu.\" Aku lantas pergi dan membersihkan Za'faran tersebut. Kemudian aku mendatangi beliau meskipun masih ada sisa-sisa Za'faran. Aku mengucapkan salam namun beliau tidak menjawab atau menyambutku. Beliau bersabda: \"Bersihkan ini darimu.\" Aku lalu pergi dan membersihkannya. Kemudian aku datang dan mengucapkan salam kepadanya, lalu beliau menjawab atau menyambutku. Beliau lantas bersabda: \"Sesungguhnya malaikat tidak akan datang menghadiri jenazah orang kafir dengan kebaikan, dan pula orang yang melumuri dirinya dengan Za'faran dan orang yang junub.\" Ammar berkata, \"Beliau memberi keringanan kepada orang yang junub jika ingin tidur, atau makan, atau minum cukup dengan berwudhu.\" Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Muhammad bin Bakr] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Umar bin Atha bin Abu Al Khuwar] Bahwasanya ia mendengar [Yahya bin Ya'mar] mengabarkan dari [seorang laki-laki] ia mengabarkan kepadanya dari [Ammar bin Yasir] berkata -Umar berkeyakinan bahwa Yahya menyebut nama laki-laki itu, namun Umar lupa namanya-, \"Aku memakai wewangian…sama seperti hadits ini. namun yang pertama lebih lengkap dan sempurna, sebab disebutkan tentang mandi di dalamnya.\" Ia berkata, \"Aku bertanya kepada Umar, \"Apakah mereka sedang ihram?\" Umar berkata, \"Tidak, mereka sedang menetap di rumah.\""},"3532":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ الْأَسَدِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ ابْنِ الزُّبَيْرِ الْأَسَدِيُّ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ جَدَّيْهِ قَالَا سَمِعْنَا أَبَا مُوسَى يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ تَعَالَى صَلَاةَ رَجُلٍ فِي جَسَدِهِ شَيْءٌ مِنْ خَلُوقٍقَالَ أَبُو دَاوُد جَدَّاهُ زَيْدٌ وَزِيَادٌ","id":"Telah menceritakan kepada kami [Zuhair bin Harb Al Asadi] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah bin Az Zubair Al Asadi] berkata, telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Ar Rabi' bin Anas] dari [Kedua kakeknya] keduanya berkata; kami mendengar [Abu Musa] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala tidak menerima shalat seorang laki-laki yang pada tubuhnya Za'faran.\" Abu Dawud berkata, \"Kedua kakeknya adalah [Zaid] dan [Ziyad].\""},"3533":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ حَمَّادَ بْنَ زَيْدٍ وَإِسْمَعِيلَ بْنَ إِبْرَاهِيمَ حَدَّثَاهُمْ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّزَعْفُرِ لِلرِّجَالِ وَقَالَ عَنْ إِسْمَعِيلَ أَنْ يَتَزَعْفَرَ الرَّجُلُ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Hammad bin Zaid] dan [Isma'il bin Ibrahim] keduanya menceritakan kepada mereka dari [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang penggunakan Za'faran untuk laki-laki.\""},"3534":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ الْحَسَنِ بْنِ أَبِي الْحَسَنِ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا تَقْرَبُهُمْ الْمَلَائِكَةُ جِيفَةُ الْكَافِرِ وَالْمُتَضَمِّخُ بِالْخَلُوقِ وَالْجُنُبُ إِلَّا أَنْ يَتَوَضَّأَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abdullah Al Uwaisi] berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Tsaur bin Zaid] dari [Al Hasan bin Abu Al Hasan] dari [Ammar bin Yasir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga kelompok yang tidak akan didekati oleh malaikat; bangkai orang kafir, orang yang berlebihan dalam menggunakan wewangian dan orang junub kecuali jika ia berwudhu.\""},"3535":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ حَدَّثَنَا عُمَرُ بْنُ أَيُّوبَ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ ثَابِتِ بْنِ الْحَجَّاجِ عَنْ عَبْدِ اللَّهِ الْهَمْدَانِيِّ عَنْ الْوَلِيدِ بْنِ عُقْبَةَ قَالَلَمَّا فَتَحَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ جَعَلَ أَهْلُ مَكَّةَ يَأْتُونَهُ بِصِبْيَانِهِمْ فَيَدْعُو لَهُمْ بِالْبَرَكَةِ وَيَمْسَحُ رُءُوسَهُمْ قَالَ فَجِيءَ بِي إِلَيْهِ وَأَنَا مُخَلَّقٌ فَلَمْ يَمَسَّنِي مِنْ أَجْلِ الْخَلُوقِ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Ar Raqqi] berkata, telah menceritakan kepada kami [Umar bin Ayyub] dari [Ja'far bin Burqan] dari [Tsabit Ibnul Hajjaj] dari [Abdullah Al Hamdani] dari [Al Walid bin Uqbah] ia berkata, \"Ketika Nabi Allah shallallahu 'alaihi wasallam membuka kota Makkah, penduduk Makkah datang kepada beliau dengan membawa anak-anak mereka, lalu beliau mendoakan keberkahan bagi mereka dan mengusap kepala mereka.\" Al Walid berkata, \"Aku lalu dibawa menghadap beliau sementara aku penuh dengan Za'faran, maka beliau pun tidak mengusapku karena alasan Za'faran tersebut.\""},"3536":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا سَلْمٌ الْعَلَوِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ أَثَرُ صُفْرَةٍ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَلَّمَا يُوَاجِهُ رَجُلًا فِي وَجْهِهِ بِشَيْءٍ يَكْرَهُهُ فَلَمَّا خَرَجَ قَالَ لَوْ أَمَرْتُمْ هَذَا أَنْ يَغْسِلَ هَذَا عَنْهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar bin Maisarah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Salm Al 'Alawi] dari [Anas bin Malik] berkata, \"Seorang laki-laki masuk menemui Rasulullah shallallahu 'alaihi wasallam, sementara pada dirinya terdapat sisa-sisa warna kuning (Za'faran). Dan jarang sekali Nabi shallallahu 'alaihi wasallam menemui seseorang dengan wajah yang kurang senang karena sesuatu, maka ketika keluar beliau bersabda: \"Sekiranya kalian suruh orang ini untuk membersihkan dirinya dari sisa-sisa warna kuning.\""},"3537":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ وَمُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَمَا رَأَيْتُ مِنْ ذِي لِمَّةٍ أَحْسَنَ فِي حُلَّةٍ حَمْرَاءَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَ مُحَمَّدُ بْنُ سُلَيْمَانَ لَهُ شَعْرٌ يَضْرِبُ مَنْكِبَيْهِقَالَ أَبُو دَاوُد كَذَا رَوَاهُ إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ قَالَ يَضْرِبُ مَنْكِبَيْهِ و قَالَ شُعْبَةُ يَبْلُغُ شَحْمَةَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dan [Muhammad bin Sulaiman Al Anbari] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Aku belum pernah melihat seseorang berambut panjang yang lebih bagus ketika mengenakan pakaian berwarna merah melebihi Rasulullah shallallahu 'alaihi wasallam.\" [Muhammad bin Sulaiman] menambahkan, \"Beliau mempunyai rambut hingga kedua bahu.\" Abu Dawud berkata, \"Demikian [Isra'il] meriwayatkannya dari [Abu Ishaq], ia berkata, \"(Rambutnya) Hingga kedua pundaknya.\" Sementara Syu'bah menceritakan, \"Hingga daun telinga.\""},"3538":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ شَعْرٌ يَبْلُغُ شَحْمَةَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mempunyai rambut yang panjangnya hingga daun telinga.\""},"3539":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ شَعْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَحْمَةِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Tsabit] dari [Anas] ia berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam panjangnya hingga dua daun telinga.\""},"3540":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ شَعْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah mengabarkan kepada kami [Humaid] dari [Anas bin Malik] ia berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam panjangnya hingga pertengahan daun telinganya.\""},"3541":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ شَعْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوْقَ الْوَفْرَةِ وَدُونَ الْجُمَّةِ","id":"Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Az Zinad] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam panjangnya melebihi daun telinga tetapi belum sampai kedua pundaknya.\""},"3542":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ أَهْلُ الْكِتَابِ يَعْنِي يَسْدِلُونَ أَشْعَارَهُمْ وَكَانَ الْمُشْرِكُونَ يَفْرُقُونَ رُءُوسَهُمْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُعْجِبُهُ مُوَافَقَةُ أَهْلِ الْكِتَابِ فِيمَا لَمْ يُؤْمَرْ بِهِ فَسَدَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاصِيَتَهُ ثُمَّ فَرَقَ بَعْدُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] berkata, telah mengabarkan kepadaku [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] ia berkata, \"orang-orang ahli kitab biasa mengurai rambutnya dan orang-orang musyrik biasa membelah rambut kepada mereka menjadi dua bagian. Sedangkan Rasulullah shallallahu 'alaihi wasallam lebih senang menyamai orang-orang ahli kitab pada hal-hal yang tidak ada perintahnya. Maka Rasulullah shallallahu 'alaihi wasallam pun mengurai rambutnya bagian depan, kemudian membelahnya setelah itu.\""},"3543":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدٍ يَعْنِي ابْنَ إِسْحَقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ إِذَا أَرَدْتُ أَنْ أَفْرُقَ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَعْتُ الْفَرْقَ مِنْ يَافُوخِهِ وَأُرْسِلُ نَاصِيَتَهُ بَيْنَ عَيْنَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad] -yaitu Ibnu Ishaq- ia berkata; telah menceritakan kepadaku [Muhammad bin Ja'far bin Az Zubair] dari [Urwah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Jika aku ingin membelah (menyisir) rambut Rasulullah shallallahu 'alaihi wasallam, maka aku memulainya dari ubun-ubun dan mengurai rambut bagian depan antara dua matanya.\""},"3544":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ وَسُفْيَانُ بْنُ عُقْبَةَ السُّوَائِيُّ هُوَ أَخُو قَبِيصَةَ وَحُمَيْدُ بْنُ خُوَارٍ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِي شَعْرٌ طَوِيلٌ فَلَمَّا رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذُبَابٌ ذُبَابٌ قَالَ فَرَجَعْتُ فَجَزَزْتُهُ ثُمَّ أَتَيْتُهُ مِنْ الْغَدِ فَقَالَ إِنِّي لَمْ أَعْنِكَ وَهَذَا أَحْسَنُ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dan [Sufyan bin Uqbah As Suwa`i] -ia adalah saudara Qabishah dan [Humaid bin Khuwar] - dari [Sufyan Ats Tsauri] dari [Ashim bin Kulaib] dari [Bapaknya] dari [Wail bin Hujr] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam, sementara aku mempunyai rambut yang panjang. Ketika Rasulullah shallallahu 'alaihi wasallam melihatku beliau bersabda: \"Lalat, lalat.\" Wail bin Hujr berkata, \"Maka aku kembali pulang dan memangkasnya, setelah itu aku mendatangi beliau pada keesokan harinya. Beliau bersabda: \"Sesungguhnya aku tidak bermaksud untuk menjelekkanmu namun ini (sekarang) lebih baik.\""},"3545":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ قَالَتْ أُمُّ هَانِئٍقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ وَلَهُ أَرْبَعُ غَدَائِرَ تَعْنِي عَقَائِصَ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] ia berkata; [Ummu Hani] berkata, \"Nabi shallallahu 'alaihi wasallam datang ke Makkah, dan saat itu beliau mempunyai empat kepangan.\""},"3546":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ وَابْنُ الْمُثَنَّى قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ أَبِي يَعْقُوبَ يُحَدِّثُ عَنْ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْهَلَ آلَ جَعْفَرٍ ثَلَاثًا أَنْ يَأْتِيَهُمْ ثُمَّ أَتَاهُمْ فَقَالَ لَا تَبْكُوا عَلَى أَخِي بَعْدَ الْيَوْمِ ثُمَّ قَالَ ادْعُوا لِي بَنِي أَخِي فَجِيءَ بِنَا كَأَنَّا أَفْرُخٌ فَقَالَ ادْعُوا لِي الْحَلَّاقَ فَأَمَرَهُ فَحَلَقَ رُءُوسَنَا","id":"Telah menceritakan kepada kami [Uqbah bin Mukram] dan [Ibnu Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] ia berkata, \"Aku mendengar [Muhammad bin Abu Ya'qub] ia menceritakan dari [Al Hasan bin Sa'd] dari [Abdullah bin Ja'far] berkata, \"Nabi shallallahu 'alaihi wasallam memberi tenggang waktu untuk keluarga Ja'far selama tiga hari, setelah itu beliau datang kepada mereka dan bersabda: \"Setelah ini, janganlah kalian menangisi saudaraku.\" Setelah itu beliau bersabda: \"Undanglah kemari bani saudaraku.\" kami lalu dihadapkan kepada beliau layaknya anak-anak ayam, beliau lantas bersabda: \"Panggilkan tukang cukur kepadaku.\" Beliau lalu memerintah tukang tukur itu (untuk mencukur), hingga kami semua dicukur olehnya.\""},"3547":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عُثْمَانُ بْنُ عُثْمَانَ قَالَ أَحْمَدُ كَانَ رَجُلًا صَالِحًا قَالَ أَخْبَرَنَا عُمَرُ بْنُ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَزَعِ وَالْقَزَعُ أَنْ يُحْلَقَ رَأْسُ الصَّبِيِّ فَيُتْرَكَ بَعْضُ شَعْرِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Utsman bin Utsman] -Ahmad berkata; ia adalah seorang laki-laki yang shalih- ia berkata; telah mengabarkan kepada kami [Umar bin Nafi'] dari [Bapaknya] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Al Qaza', Al Qaza' adalah kepala anak kecil yang dicukur sebagiannya dan dibiarkan sebagian.\""},"3548":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْقَزَعِ وَهُوَ أَنْ يُحْلَقَ رَأْسُ الصَّبِيِّ فَتُتْرَكَ لَهُ ذُؤَابَةٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melarang Al Qaza'. Yaitu mencukur kepala anak kecil dengan menyisakan sedikit (dikepang).\""},"3549":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى صَبِيًّا قَدْ حُلِقَ بَعْضُ شَعْرِهِ وَتُرِكَ بَعْضُهُ فَنَهَاهُمْ عَنْ ذَلِكَ وَقَالَ احْلِقُوهُ كُلَّهُ أَوْ اتْرُكُوهُ كُلَّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melihat melihat anak kecil yang rambutnya dicukur sebagian dan disisakan sebagian, lalu beliau melarang hal itu. Beliau bersabda: \"Cukurlah semua atau sisakan semua.\""},"3550":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مَيْمُونِ بْنِ عَبْدِ اللَّهِ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَتْ لِي ذُؤَابَةٌ فَقَالَتْ لِي أُمِّي لَا أَجُزُّهَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمُدُّهَا وَيَأْخُذُ بِهَا","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] dari [Maimun bin Abdullah] dari [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata, \"Aku mempunyai jambul. Ibuku lalu berkata kepadaku, \"Aku tidak akan memotongnya, Rasulullah shallallahu 'alaihi wasallam biasa memanjangkan dan memegangnya.\""},"3551":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْحَجَّاجُ بْنُ حَسَّانَ قَالَ دَخَلْنَا عَلَى أَنَسِ بْنِ مَالِكٍ فَحَدَّثَتْنِي أُخْتِي الْمُغِيرَةُ قَالَتْوَأَنْتَ يَوْمَئِذٍ غُلَامٌ وَلَكَ قَرْنَانِ أَوْ قُصَّتَانِ فَمَسَحَ رَأْسَكَ وَبَرَّكَ عَلَيْكَ وَقَالَ احْلِقُوا هَذَيْنِ أَوْ قُصُّوهُمَا فَإِنَّ هَذَا زِيُّ الْيَهُودِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Al Hajjaj bin Hassan] ia berkata; Kami masuk menemui [Anas bin Malik], lalu [saudara pererempuan Al Mughirah] menceritakan kepadaku, ia berkata, \"Dahulu kamu masih bocah, dan kamu mempunyai dua tanduk (jambul), lalu Anas mengusap kepalamu dan mendoakan keberkahan untukmu. Ia lalu berkata, \"cukurlah atau pangkaslah dua jambul ini, karena ini adalah hiasan orang-orang yahudi.\""},"3552":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفِطْرَةُ خَمْسٌ أَوْ خَمْسٌ مِنْ الْفِطْرَةِ الْخِتَانُ وَالِاسْتِحْدَادُ وَنَتْفُ الْإِبِطِ وَتَقْلِيمُ الْأَظْفَارِ وَقَصُّ الشَّارِبِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, \"Fitrah (suci) itu ada pada lima hal, atau ada lima hal dari fitrah; khitan, mencukur bulu kemaluan, mencabut bulu ketiak, memotong kuku dan mencukur kumis.\""},"3553":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي بَكْرِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِإِحْفَاءِ الشَّوَارِبِ وَإِعْفَاءِ اللِّحَى","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Abu Bakr bin Nafi'] dari [Bapaknya] dari [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan mencukur kumis dan membiarkan janggut.\""},"3554":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا صَدُقَةُ الدَّقِيقِيُّ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَوَقَّتَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلْقَ الْعَانَةِ وَتَقْلِيمَ الْأَظْفَارِ وَقَصَّ الشَّارِبِ وَنَتْفَ الْإِبِطِ أَرْبَعِينَ يَوْمًا مَرَّةًقَالَ أَبُو دَاوُد رَوَاهُ جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ أَبِي عِمْرَانَ عَنْ أَنَسٍ لَمْ يَذْكُرْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وُقِّتَ لَنَا وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Shadaqah Ad Daqiqi] berkata, telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi waktu kita untuk mencukur bulu kemaluan, memotong kuku, mencukur kumis dan mencabut bulu ketiak selama empat puluh hari sekali.\" Abu Dawud berkata \" [Ja'far bin Sulaiman] menceritakannya dari [Abu Imran], dari [Anas]. Namun ia tidak menyebut Nabi shallallahu 'alaihi wasallam. Ia berkata, \"Kami diberi waktu…\", dan ini yang benar. "},"3555":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا زُهَيْرٌ قَرَأْتُ عَلَى عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ وَقَرَأَهُ عَبْدُ الْمَلِكِ عَلَى أَبِي الزُّبَيْرِ وَرَوَاهُ أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَكُنَّا نُعْفِي السِّبَالَ إِلَّا فِي حَجٍّ أَوْ عُمْرَةٍقَالَ أَبُو دَاوُد الِاسْتِحْدَادُ حَلْقُ الْعَانَةِ","id":"Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami [Zuhair] aku membaca di hadapan [Abdul Malik bin Abu Sualiman] dan Abdul Malik membacanya di hadapan [Abu Az Zubair] dan Abu Az Zubair meriwayatkannya dari [Jabir] ia berkata, \"Kami membiarkan Sibal (bulu janggut yang panjang hingga dada) kecuali pada saat haji dan umrah.\" Abu Dawud berkata, \"Al Istihdad artinya adalah mencukur bulu kemaluan.\""},"3556":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ الْمَعْنَى عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْتِفُوا الشَّيْبَ مَا مِنْ مُسْلِمٍ يَشِيبُ شَيْبَةً فِي الْإِسْلَامِ قَالَ عَنْ سُفْيَانَ إِلَّا كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَة�� وَقَالَ فِي حَدِيثِ يَحْيَى إِلَّا كَتَبَ اللَّهُ لَهُ بِهَا حَسَنَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Sufyan] secara makna, dari [Ibnu 'Ajlan] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencabut uban, tidaklah seorang muslim tumbuh uban padanya dalam Islam -disebutkan oleh Sufyan dalam riwayatnya- \"Kecuali ia akan menjadi cahaya baginya pada hari kiamat.\" Dalam riwayat lain (oleh Yahya) disebutkan, \"Kecuali dengannya Allah akan menuliskan satu kebaikan dan dihapuskan darinya satu dosa.\""},"3557":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا يَصْبُغُونَ فَخَالِفُوهُمْ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dan [Sulaiman bin Yasar] dari [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang-orang Yahudi dan Nashara tidak mencelup (menyemir rambut), maka selisihilah mereka.\""},"3558":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَأَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأُتِيَ بِأَبِي قُحَافَةَ يَوْمَ فَتْحِ مَكَّةَ وَرَأْسُهُ وَلِحْيَتُهُ كَالثَّغَامَةِ بَيَاضًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا هَذَا بِشَيْءٍ وَاجْتَنِبُوا السَّوَادَ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] dan [Ahmad bin Sa'id Al Hamdani] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Pada saat pembukaan kota Makkah, Abu Kuhafah dihadapkan kepada Rasulullah, sementara rambut dan janggutnya putih seperti bunga berwarna putih, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rubahlah warna rambutmu ini dengan sesuatu, dan jauhilah warna hitam.\""},"3559":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا غُيِّرَ بِهِ هَذَا الشَّيْبُ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Sa'id Al Jurairi] dari [Abdullah bin Buraidah] dari [Abu Al Aswad Ad dili] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling baik untuk mengubah warna uban ini adalah pacar dan Al Katam (sejenis pacar).\""},"3560":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ إِيَادٍ قَالَ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ ذُو وَفْرَةٍ بِهَا رَدْعُ حِنَّاءٍ وَعَلَيْهِ بُرْدَانِ أَخْضَرَانِحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ ابْنَ أَبْجَرَ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ فِي هَذَا الْخَبَرِ قَالَ فَقَالَ لَهُ أَبِي أَرِنِي هَذَا الَّذِي بِظَهْرِكَ فَإِنِّي رَجُلٌ طَبِيبٌ قَالَ اللَّهُ الطَّبِيبُ بَلْ أَنْتَ رَجُلٌ رَفِيقٌ طَبِيبُهَا الَّذِي خَلَقَهَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Ubaidullah] - maksudnya Ubaidullah bin Had- ia berkata; telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah] ia berkata, \"Aku bersama bapakku pergi menemui Nabi shallallahu 'alaihi wasallam, dan ternyata rambut beliau panjangnya hingga daun telinga yang diberi warna dengan daun pacar, dan beliau mengenakan dua kain berwarna hijau.\" Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Ibnu Idris] ia berkata; Aku mendengar [Ibnu Abjar] dari [Iyad bin Laqith] dari [Abu Rimtsah] berkenaan dengan kabar ini. Ia (perawi) berkata; Lalu bapakku berkata kepadanya, \"Perlihatkanlah kepadaku apa yang ada di punggungmu, karena aku adalah seorang tabib.\" Ia berkata, \"Demi Allah, engkau hanyalah perantara. Tabib yang sebenarnya adalah Dzat Yang telah menciptakannya (sakit).\""},"3561":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي فَقَالَ لِرَجُلٍ أَوْ لِأَبِيهِ مَنْ هَذَا قَالَ ابْنِي قَالَ لَا تَجْنِي عَلَيْهِ وَكَانَ قَدْ لَطَّخَ لِحْيَتَهُ بِالْحِنَّاءِ","id":"Telah menceritakan kepada kami [Ibnu Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Iyad bin Laqith] dari [Abu Rimtsah] ia berkata, \"Aku dan bapakku mendatangi Nabi shallallahu 'alaihi wasallam, lalu beliau bertanya kepada seorang laki-laki, atau kepada bapaknya: \"Siapa ini?\" orang itu menjawab, \"Anakku.\" Beliau bersabda: \"Jangan engkau berlaku jahat kepadanya.\" Dan saat itu ia sedang mewarnai janggutnya dengan pacar.\""},"3562":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّهُ سُئِلَ عَنْ خِضَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّهُ لَمْ يَخْضِبْ وَلَكِنْ قَدْ خَضَبَ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] Bahwasanya ia pernah ditanya tentang warna cat (rambut) Nabi shallallahu 'alaihi wasallam. Lalu ia menyebutkan bahwa Rasulullah tidak pernah mengecat rambutnya, hanya saja hal itu pernah dilakukan oleh Abu Bakar dan Umar radliallahu 'anhuma.\""},"3563":{"ar":"حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ مُطَرِّفٍ أَبُو سُفْيَانَ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَلْبَسُ النِّعَالَ السِّبْتِيَّةَ وَيُصَفِّرُ لِحْيَتَهُ بِالْوَرْسِ وَالزَّعْفَرَانِوَكَانَ ابْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdurrahim bin Mutaharrif Abu Sufyan] berkata, telah menceritakan kepada kami [Amru bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam mengenakan sandal yang bertali dan memberi warna janggutnya dengan Al Waras (semacam tumbuhan) dan Za'faran. Dan Ibnu Umar juga melakukan hal itu.\""},"3564":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ حُمَيْدِ بْنِ وَهْبٍ عَنْ ابْنِ طَاوُسٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ قَدْ خَضَّبَ بِالْحِنَّاءِ فَقَالَ مَا أَحْسَنَ هَذَا قَالَ فَمَرَّ آخَرُ قَدْ خَضَّبَ بِالْحِنَّاءِ وَالْكَتَمِ فَقَالَ هَذَا أَحْسَنُ مِنْ هَذَا قَالَ فَمَرَّ آخَرُ قَدْ خَضَّبَ بِالصُّفْرَةِ فَقَالَ هَذَا أَحْسَنُ مِنْ هَذَا كُلِّهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Humaid bin Wahb] dari [Ibnu Thawus] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki yang mengecat rambutnya dengan pacar lewat dihadapan Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Betapa bagusnya ini.\" Setelah itu lewat orang lain yang mewarnai rambutnya dengan pacar dan Al Katam (tanaman semacam daun pacar), beliau bersabda: \"Orang ini lebih bagus dari yang tadi.\" Setelah itu lewat orang lain yang mewarnai rambutnya dengan warna kuning, beliau bersabda: \"Orang ini lebih bagus dari yang tadi-tadi.\""},"3565":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ قَوْمٌ يَخْضِبُونَ فِي آخِرِ الزَّمَانِ بِالسَّوَادِ كَحَوَاصِلِ الْحَمَامِ لَا يَرِيحُونَ رَائِحَةَ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Taubah] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Abdul Karim Al jazari] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada akhir zaman nanti akan ada orang-orang yang mengecat rambutnya dengan warna hitam seperti warna mayoritas dada merpati, mereka tidak akan mendapat bau surga.\""},"3566":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ حُمَيْدٍ الشَّامِيِّ عَنْ سُلَيْمَانَ الْمُنَبِّهِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ كَانَ آخِرُ عَهْدِهِ بِإِنْسَانٍ مِنْ أَهْلِهِ فَاطِمَةَ وَأَوَّلُ مَنْ يَدْخُلُ عَلَيْهَا إِذَا قَدِمَ فَاطِمَةَ فَقَدِمَ مِنْ غَزَاةٍ لَهُ وَقَدْ عَلَّقَتْ مِسْحًا أَوْ سِتْرًا عَلَى بَابِهَا وَحَلَّتْ الْحَسَنَ وَالْحُسَيْنَ قُلْبَيْنِ مِنْ فِضَّةٍ فَقَدِمَ فَلَمْ يَدْخُلْ فَظَنَّتْ أَنَّ مَا مَنَعَهُ أَنْ يَدْخُلَ مَا رَأَى فَهَتَكَتْ السِّتْرَ وَفَكَّكَتْ الْقُلْبَيْنِ عَنْ الصَّبِيَّيْنِ وَقَطَّعَتْهُ بَيْنَهُمَا فَانْطَلَقَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمَا يَبْكِيَانِ فَأَخَذَهُ مِنْهُمَا وَقَالَ يَا ثَوْبَانُ اذْهَبْ بِهَذَا إِلَى آلِ فُلَانٍ أَهْلِ بَيْتٍ بِالْمَدِينَةِ إِنَّ هَؤُلَاءِ أَهْلُ بَيْتِي أَكْرَهُ أَنْ يَأْكُلُوا طَيِّبَاتِهِمْ فِي حَيَاتِهِمْ الدُّنْيَا يَا ثَوْبَانُ اشْتَرِ لِفَاطِمَةَ قِلَادَةً مِنْ عَصَبٍ وَسِوَارَيْنِ مِنْ عَاجٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Muhammad bin Juhadah] dari [Humaid Asy Syami] dari [Sulaiman Al Munabbihi] dari [Tsauban] mantan budak (yang telah dimerdekakan oleh) Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam melakukan safar, maka orang yang paling akhir beliau beri nasihat dari keluarganya adalah Fatimah, dan orang yang pertama kali beliau temui saat datang adalah Fatimah. Satu kali beliau tiba dari peperangan yang dilakukannya, sementara Fatimah telah memasang satir di pintunya dan memasang perhiasan gelang perak pada hasan dan husain. Beliau datang namun tidak masuk, hal itu menjadikan Fatimah berperasangka bahwa tidak masuknya Rasulullah adalah karena apa yang beliau lihat dari yang ia lakukan. Lalu ia menyobek tirai dan melepas dua gelang yang ada pada kedua anaknya. Setelah itu ia membawa kedua anaknya yang masih menangis untuk menemui Rasulullah shallallahu 'alaihi wasallam. Beliau lantas meraih gelang tersebut dari keduanya dan bersabda: \"Wahai Tsauban, pergilah dengan membawa ini (gelang) ke keluarga fulan -ahlu bait di Madinah-, mereka (keluarga Fathimah) adalah ahli baitku, aku tidak ingin mereka makan dengan enak dalam kehidupan mereka di dunia. Wahai Tsauban, belikanlah Fatimah kalung dari ashab (sejenis tumbuhan) dan dua gelang dari gading.\""},"3567":{"ar":"حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ مُطَرِّفٍ الرُّوَاسِيُّ حَدَّثَنَا عِيسَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى بَعْضِ الْأَعَاجِمِ فَقِيلَ لَهُ إِنَّهُمْ لَا يَقْرَءُونَ كِتَابًا إِلَّا بِخَاتَمٍ فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَا��ِدٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ بِمَعْنَى حَدِيثِ عِيسَى بْنِ يُونُسَ زَادَ فَكَانَ فِي يَدِهِ حَتَّى قُبِضَ وَفِي يَدِ أَبِي بَكْرٍ حَتَّى قُبِضَ وَفِي يَدِ عُمَرَ حَتَّى قُبِضَ وَفِي يَدِ عُثْمَانَ فَبَيْنَمَا هُوَ عِنْدَ بِئْرٍ إِذْ سَقَطَ فِي الْبِئْرِ فَأَمَرَ بِهَا فَنُزِحَتْ فَلَمْ يَقْدِرْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdurrahim bin Mutharrif Ar Ruwasi] berkata, telah menceritakan kepada kami [Isa] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ingin menulis surat untuk orang-orang di luar arab, lalu dikatakan kepada beliau, \"Sesungguhnya mereka tidak mau membaca surat tanpa ada setempelnya.\" Rasulullah kemudian membuat cincin dari perak dan memberi ukiran Muhammad Rasulullah.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari [Sa'id] dari [Qatadah] dari [Anas] sebagaimana makna hadits Isa bin Yunus. Namun ia menambahkan, \"cincin itu tetap berada dijarinya hingga meninggal, lalu pindah ke Abu Bakar hingga meninggal, lalu pindah ke Umar hingga meninggal, lalu pindah ke tangan Utsman. Dan ketika Utsman sedang berada di dekat sumur, cincin itu jatuh. Utsman memerintahkan untuk mencarinya namun tidak ketemu.\""},"3568":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَحْمَدُ بْنُ صَالِحٍ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَنَسٌ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ وَرِقٍ فَصُّهُ حَبَشِيٌّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ahmad bin Shalih] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] ia berkata; telah menceritakan kepadaku [Anas] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari perak, sedangkan mata cincinnya dari Habasyah.\""},"3569":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ كُلُّهُ فَصُّهُ مِنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari perak, demikian juga dengan mata cincinnya.\""},"3570":{"ar":"حَدَّثَنَا نُصَيْرُ بْنُ الْفَرَجِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ مِمَّا يَلِي بَطْنَ كَفِّهِ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَاتَّخَذَ النَّاسُ خَوَاتِمَ الذَّهَبِ فَلَمَّا رَآهُمْ قَدْ اتَّخَذُوهَا رَمَى بِهِ وَقَالَ لَا أَلْبَسُهُ أَبَدًا ثُمَّ اتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ نَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ ثُمَّ لَبِسَ الْخَاتَمَ بَعْدَهُ أَبُو بَكْرٍ ثُمَّ لَبِسَهُ بَعْدَ أَبِي بَكْرٍ عُمَرُ ثُمَّ لَبِسَهُ بَعْدَهُ عُثْمَانُ حَتَّى وَقَعَ فِي بِئْرِ أَرِيسٍقَالَ أَبُو دَاوُد وَلَمْ يَخْتَلِفْ النَّاسُ عَلَى عُثْمَانَ حَتَّى سَقَطَ الْخَاتَمُ مِنْ يَدِهِ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ فِي هَذَا الْخَبَرِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ وَقَالَ لَا يَنْقُشُ أَحَدٌ عَلَى نَقْشِ خَاتَمِي هَذَا ثُمَّ سَاقَ الْحَدِيثَ حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بِنِ فَارِسٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ الْمُغِيرَةِ بْنِ زِيَادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ بِهَذَا الْخَبَرِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَالْتَمَسُوهُ فَلَمْ يَجِدُوهُ فَاتَّخَذَ عُثْمَانُ خَاتَمًا وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ قَالَ فَكَانَ يَخْتِمُ بِهِ أَوْ يَتَخَتَّمُ بِهِ","id":"Telah menceritakan kepada kami [Nushair bin Faraj] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin dari emas, beliau menghadapkan mata cincinnya ke arah telapak tangan, dan beliau memberi ukiran pada cincin itu dengan tulisan 'Muhammad Rasulullah'. Orang-orang lalu ikut membuat cincin dari emas, ketika beliau melihat mereka membuat cincin seperti itu, beliau membuang cincinnya seraya mengatakan: \"Selamanya aku tidak akan memakainya lagi.\" Kemudian beliau membuat cincin dari perak dan memberi ukiran pada cincin tersebut 'Muhammad Rasulullah'. Cincin itu kemudian dipakai oleh Abu Bakar, kemudian Umar, kemudian Utsman hingga akhirnya cincin tersebut jatuh ke dalam sumur Aris.\" Abu Dawud berkata, \"Orang-orang belum berselisih dengan Utsman hingga cincin itu jatuh dari tangannya (ke dalam sumur).\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub bin Musa] dari [Nafi'] dari [Ibnu Umar] tentang hadits ini, dari Nabi shallallahu 'alaihi wasallam, \"Beliau memberi ukiran 'Muhammad Rasulullah', dan beliau bersabda: \"Janganlah seseorang membuat ukiran sebagaimana ukiran yang aku buat ini.\" kemudian ia menyebutkan hadits secara lengkap. Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Abu Ashim] dari [Al Mughirah bin Ziyad] dari [Nafi'] dari [Ibnu Umar] seperti hadits ini, dari Nabi shallallahu 'alaihi wasallam, ia menyebutkan, \"Orang-orang lalu mencari cincin itu namun tidak ketemu. Maka Utsman pun membuat cincin lagi dan memberi ukiran 'Muhammad Rasulullah'.\" Ibnu Umar berkata, \"Utsman lantas memberi setempel dengan cincin tersebut.\""},"3571":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ لُوَيْنٌ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ رَأَى فِي يَدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ يَوْمًا وَاحِدًا فَصَنَعَ النَّاسُ فَلَبِسُوا وَطَرَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَرَحَ النَّاسُقَالَ أَبُو دَاوُد رَوَاهُ عَنْ الزُّهْرِيِّ زِيَادُ بْنُ سَعْدٍ وَشُعَيْبٌ وَابْنُ مُسَافِرٍ كُلُّهُمْ قَالَ مِنْ وَرِقٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Luwain] dari [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Anas bin Malik] Bahwasanya ia pernah melihat pada tangan Nabi shallallahu 'alaihi wasallam cincin perak selama satu hari. Orang-orang lalu ikut membuat cincin hingga Nabi shallallahu 'alaihi wasallam membuang cincinnya, lalu orang-orang pun ikut membuangnya.\" Abu Dawud berkata, \" [Ziyad bin Sa'd] dan [Syu'aib] dan [Ibnu Musafir] diriwayatkan hadits itu dari [Az Zuhri], ia berkata, \"Yaitu dari perak.\""},"3572":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ الرُّكَيْنَ بْنَ الرَّبِيعِ يُحَدِّثُ عَنْ الْقَاسِمِ بْنِ حَسَّانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ أَنَّ ابْنَ مَسْعُودٍ كَانَ يَقُولُكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ عَشْرَ خِلَالٍ الصُّفْرَةَ يَعْنِي الْخَلُوقَ وَتَغْيِيرَ الشَّيْبِ وَجَرَّ الْإِزَارِ وَالتَّخَتُّمَ بِالذَّهَبِ وَالتَّبَرُّجَ بِالزِّينَةِ لِغَيْرِ مَحَلِّهَا وَالضَّرْبَ بِالْكِعَابِ وَالرُّقَى إِلَّا بِالْمُعَوِّذَاتِ وَعَقْدَ التَّمَائِمِ وَعَزْلَ الْمَاءِ لِغَيْرِ أَوْ غَيْرَ مَحَلِّهِ أَوْ عَنْ مَحَلِّهِ وَفَسَادَ الصَّبِيِّ غَيْرَ مُحَرِّمِهِقَالَ أَبُو دَاوُد انْفَرَدَ بِإِسْنَادِ هَذَا الْحَدِيثِ أَهْلُ الْبَصْرَةِ وَاللَّهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Al Mu'tamir] ia berkata; Aku mendengar [Ar Rukain bin Ar Rabi'] ia menceritakan dari [Al Qasim bin Hassan] dari ['Abdurrahman bin Harmalah] bahwa [Ibnu Mas'ud] berkata, \"Rasulullah shallallahu 'alaihi wasallam membenci sepuluh hal; warna kuning -Za'faran-, mengecat uban (dengan warna hitam), memanjangkan sarung, memakai cincin emas, memakai perhiasan bukan pada tempatnya, dadu, jampi-jampi selain dengan Al Mu'awwidzat, menggantungkan jimat dan meng'azl air mani bukan pada tempatnya serta menyetubuhi wanita yang menyusui balita lalu hamil hingga membuat balita kering dari susu ibunya (karena hamil), dan beliau tidak mengharamkannya (hanya membencinya).\" Abu Dawud berkata, \"Penduduk Bashrah meriwayatkan hadits ini secara sendirian (tidak ada yang meriwayatkan selain mereka).\" Wallahu a'lam. "},"3573":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ الْمَعْنَى أَنَّ زَيْدَ بْنَ حُبَابٍ أَخْبَرَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ السُّلَمِيِّ الْمَرْوَزِيِّ أَبِي طَيْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَاتَمٌ مِنْ شَبَهٍ فَقَالَ لَهُ مَا لِي أَجِدُ مِنْكَ رِيحَ الْأَصْنَامِ فَطَرَحَهُ ثُمَّ جَاءَ وَعَلَيْهِ خَاتَمٌ مِنْ حَدِيدٍ فَقَالَ مَا لِي أَرَى عَلَيْكَ حِلْيَةَ أَهْلِ النَّارِ فَطَرَحَهُ فَقَالَ يَا رَسُولَ اللَّهِ مِنْ أَيِّ شَيْءٍ أَتَّخِذُهُ قَالَ اتَّخِذْهُ مِنْ وَرِقٍ وَلَا تُتِمَّهُ مِثْقَالًاوَلَمْ يَقُلْ مُحَمَّدٌ عَبْدَ اللَّهِ بْنَ مُسْلِمٍ وَلَمْ يَقُلْ الْحَسَنُ السُّلَمِيَّ الْمَرْوَزِيَّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Muhammad bin Abdul Aziz bin Abu Rizmah] secara makna, bahwa [Zaid bin Hubab] mengabarkan kepada mereka dari [Abdullah bin Muslim As Sulami Al Mawarzi Abu Thaubah] dari [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, sementara ia mengenakan cincin dari kuningan tembaga. Beliau lalu berkata kepadanya: \"Kenapa aku mendapatkan bau berhala darimu!\" laki-laki itu lantas membuang cincinnya. Setelah itu ia datang lagi dengan mengenakan cincin besi, beliau bersabda: \"Kenapa melihatmu mengenakan perhiasan penduduk neraka!\" laki-laki lantas membuangnya kembali, lalu ia bertanya, \"Wahai Rasulullah, lalu dari apa aku harus membuatnya?\" beliau menjawab: \"Dari perak, namun jangan engkau genapkan hingga (beratnya) satu mitsqal.\" Muhammad tidak menyebutkan, \"Abdullah bin Muslim, atau Al Hasan As Sulami Al Mawarzi.\" "},"3574":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى وَزِيَادُ بْنُ يَحْيَى وَالْحَسَنُ بْنُ عَلِيٍّ قَالُوا حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ أَبُو عَتَّابٍ حَدَّثَنَا أَبُو مَكِينٍ نُوحُ بْنُ رَبِيعَةَ حَدَّثَنِي إِيَاسُ بْنُ الْحَارِثِ بْنِ الْمُعَيْقِيبِ وَجَدُّهُ مِنْ قِبَلِ أُمِّهِ أَبُو ذُبَابٍ عَنْ جَدِّهِ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حَدِيدٍ مَلْوِيٌّ عَلَيْهِ فِضَّةٌ قَالَ فَرُبَّمَا كَانَ فِي يَدِهِ قَالَ وَكَانَ الْمُعَيْقِيبُ عَلَى خَاتَمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ziyad bin Yahya] dan [Al hasan bin Ali] mereka berkata; telah menceritakan kepada kami [Sahl bin Hammad Abu Attab] berkata, telah menceritakan kepada kami [Abu Makin Nuh bin Rabi'ah] berkata, telah menceritakan kepadaku [Iyas Ibnul Harits Ibnul Mu'aiqib] dan kakeknya dari pihak ibunya Abu Dzubab dari [Kakeknya] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari besi bercampur perak.\" Ia melanjutkan, \"Dan mungkin itu masih di tangannya. Sementara cincin Mu'aiqib mengatakan seperti Nabi shallallahu 'alaihi wasallam.\""},"3575":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ اللَّهُمَّ اهْدِنِي وَسَدِّدْنِي وَاذْكُرْ بِالْهِدَايَةِ هِدَايَةَ الطَّرِيقِ وَاذْكُرْ بِالسَّدَادِ تَسْدِيدَكَ السَّهْمَ قَالَ وَنَهَانِي أَنْ أَضَعَ الْخَاتَمَ فِي هَذِهِ أَوْ فِي هَذِهِ لِلسَّبَّابَةِ وَالْوُسْطَى شَكَّ عَاصِمٌ وَنَهَانِي عَنْ الْقَسِّيَّةِ وَالْمِيثَرَةِقَالَ أَبُو بُرْدَةَ فَقُلْنَا لِعَلِيٍّ مَا الْقَسِّيَّةُ قَالَ ثِيَابٌ تَأْتِينَا مِنْ الشَّامِ أَوْ مِنْ مِصْرَ مُضَلَّعَةٌ فِيهَا أَمْثَالُ الْأُتْرُجِّ قَالَ وَالْمِيثَرَةُ شَيْءٌ كَانَتْ تَصْنَعُهُ النِّسَاءُ لِبُعُولَتِهِنَّ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Ibnul Mufadhdhal] berkata, telah menceritakan kepada kami [Ashim bin Kulaib] dari [Abu Burdah] dari [Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Ucapkanlah; ALLAHUMMAHDINII WA SADDIDNII WADZKUR BILHIDAAYAH HIDAAYATATH THARIIQI WADZKUR BIS SADDAADI TASDIIDAKA AS SAHMI (Ya Allah, tunjukkanlah kami, luruskanlah kami, tunjukkan kami kepada jalan yang benar, dan tunjukkan kepada kami kebenaran sebagaimana Engkau tancapkan anak panah kepada sasarannya).\" Ali berkata, \"Beliau juga melarangku untuk meletakkan cincin pada ini dan ini; jari telunjuk dan jari tengah -Ashim masih merasa ragu-. Beliau juga melarangku dari Al Qasiyah dan Al Mitsarah.\" Abu Burdah berkata, \"Kami bertanya kepada Ali, \"Apa itu Al Qasiyah?\" Ia menjawab, \"Kain yang berasal dari Syam atau Mesir yang bergaris-garis bengkok. Sementara Al Mitsarah adalah sesuatu yang dibuat oleh kaum wanita untuk suami-suaminya.\""},"3576":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ شَرِيكِ بْنِ أَبِي نَمِرَةَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَرِيكٌ و أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَتَّمُ فِي يَمِينِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Syarik bin Abu Namirah] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, [Syarik] berkata, \"Telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman], bahwa Nabi shallallahu 'alaihi wasallam mengenakan cincin pada tangan kanannya.\""},"3577":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنِي أَبِي حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَتَّمُ فِي يَسَارِهِ وَكَانَ فَصُّهُ فِي بَاطِنِ كَفِّهِقَالَ أَبُو دَاوُد قَالَ ابْنُ إِسْحَقَ وَأُسَامَةُ يَعْنِي ابْنَ زَيْدٍ عَنْ نَافِعٍ بِإِسْنَادِهِ فِي يَمِينِهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam biasa menggenakan cincin pada tangan kirinya dan mata cincinnya menghadap telapak tangannya.\" Abu Dawud berkata, \" [Ibnu Ishaq] berkata, \" [Usamah] -maksudnya Usamah bin Zaid- juga meriwayatkan dari [Nafi'] dengan sanadnya, \"pada tangan kanannya.\""},"3578":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ عَبْدَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ يَلْبَسُ خَاتَمَهُ فِي يَدِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Hannad] dari [Abdah] dari [Ubaidullah] dari [Nafi'] berkata, \" [Ibnu Umar] mengenakan cincinnya pada tangan kirinya.\""},"3579":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَرَأَيْتُ عَلَى الصَّلْتِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلِ بْنِ عَبْدِ الْمُطَّلِبِ خَاتَمًا فِي خِنْصَرِهِ الْيُمْنَى فَقُلْتُ مَا هَذَا قَالَ رَأَيْتُ ابْنَ عَبَّاسٍ يَلْبَسُ خَاتَمَهُ هَكَذَا وَجَعَلَ فَصَّهُ عَلَى ظَهْرِهَا قَالَ وَلَا يَخَالُ ابْنَ عَبَّاسٍ إِلَّا قَدْ كَانَ يَذْكُرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَلْبَسُ خَاتَمَهُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] ia berkata, \"Aku melihat [Ash Shalt bin Abdullah bin Naufal bin Abdul Muthallib] mengenakan cincin pada jari kelingking sebelah kanan. Aku lalu bertanya, \"Apa ini?\" ia menjawab, \"Aku melihat [Ibnu Abbas] mengenakan cincinnya seperti ini, ia menghadapkan mata cincinnya ke punggung telapak tangannya.\" Ia (Muhammad bin Ishaq) berkata, \"dia tidak berpendapat kecuali Ibnu Abbas sendiri yang menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam mengenakan cincinnya seperti itu.\""},"3580":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ وَإِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَا حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ حَفْصٍ أَنَّ عَامِرَ بْنَ عَبْدِ اللَّهِ قَالَ عَلِيُّ بْنُ سَهْلِ بْنِ الزُّبَيْرِ أَخْبَرَهُأَنَّ مَوْلَاةً لَهُمْ ذَهَبَتْ بِابْنَةِ الزُّبَيْرِ إِلَى عُمَرَ بْنِ الْخَطَّابِ وَفِي رِجْلِهَا أَجْرَاسٌ فَقَطَعَهَا عُمَرُ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مَعَ كُلِّ جَرَسٍ شَيْطَانًا","id":"Telah menceritakan kepada kami [Ali bin Sahl] dan [Ibrahim Ibnul Hasan] keduanya berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Umar bin Hafsh] bahwa [Amir bin Abdullah] berkata; Ali bin Sahl bin Az Zubair mengabarkan kepadanya bahwa mantan budak perempuannya (yang telah ia merdekakan) pergi bersama puteri Az Zubair menemui [Umar Ibnul Khaththab], sementara pada kakinya terdapat kerincing (lonceng) hingga Umar memotongnya. Kemudian Umar berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada setiap lonceng ada setan (yang menyertainya).\""},"3581":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ بُنَانَةَ مَوْلَاةِ عَبْدِ الرَّحْمَنِ بْنِ حَسَّانَ الْأَنْصَارِيِّ عَنْ عَائِشَةَ قَالَتْبَيْنَمَا هِيَ عِنْدَهَا إِذْ دُخِلَ عَلَيْهَا بِجَارِيَةٍ وَعَلَيْهَا جَلَاجِلُ يُصَوِّتْنَ فَقَالَتْ لَا تُدْخِلْنَهَا عَلَيَّ إِلَّا أَنْ تَقْطَعُوا جَلَاجِلَهَا وَقَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ جَرَسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Bunanah] -mantan budak (yang dimerdekakan oleh) 'Abdurrahman bin Hassan Al Anshari- dari ['Aisyah radliallahu 'anha], ia mengatakan bahwa ketika ia sedang bersama Bunanah, ada seorang budak wanita datang kepadanya dengan mengenakan gelang kaki yang berbunyi keras. 'Aisyah lalu berkata, \"Jangan kalian masukkan ia untuk menemuiku hingga kalian memotong gelangnya. Setelah itu ia berkata lagi, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat lonceng.\""},"3582":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَأَنَّ جَدَّهُ عَرْفَجَةَ بْنَ أَسْعَدَ قُطِعَ أَنْفُهُ يَوْمَ الْكُلَابِ فَاتَّخَذَ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّخَذَ أَنْفًا مِنْ ذَهَبٍحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَأَبُو عَاصِمٍ قَالَا حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ عَنْ عَرْفَجَةَ بْنِ أَسْعَدَ بِمَعْنَاهُ قَالَ يَزِيدُ قُلْتُ لِأَبِي الْأَشْهَبِ أَدْرَكَ عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ جَدَّهُ عَرْفَجَةَ قَالَ نَعَمْ حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَبِي الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ عَنْ عَرْفَجَةَ بْنِ أَسْعَدَ عَنْ أَبِيهِ أَنَّ عَرْفَجَةَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muhammad bin Abdullah Al Khuza'i] keduanya berkata; telah menceritakan kepada kami [Abu Al Asyhab] dari ['Abdurrahman bin Tharafah] bahwa kakeknya [Arfajah bin As'ad], hidungnya terpotong saat perang Al Kilab. Lalu ia membuat hidung palsu dari perak, tetapi justru hidungnya menjadi busuk. Nabi shallallahu 'alaihi wasallam lalu memerintahkan kepadanya (untuk membuat hidung dari emas), hingga ia pun membuat hidung dari emas.\" Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Yazid bin Harun] dan [Abu Ashim] keduanya berkata; telah menceritakan kepada kami [Abu Al Asyhab] dari ['Abdurrahman bin Tharafah] dari [Arfajah bin As'ad] dengan makna yang sama. Yazid berkata, \"Aku berkata kepada Abu Al Asyhab, \"Apakah 'Abdurrahman bin Tharafah mendapati kakeknya, Arfajah?\" Ia menjawab, \"Ya.\" Telah menceritakan kepada kami [Muammal bin Hisyam] berkata, telah menceritakan kepada kami [Isma'il] dari [Abu Al Asyhab] dari ['Abdurrahman bin Tharafah] dari Arfajah bin As'ad dari [Bapaknya] bahwa [Arfajah] …. dengan makna yang sama.\""},"3583":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي يَحْيَى بْنُ عَبَّادٍ عَنْ أَبِيهِ عَبَّادِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَدِمَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِلْيَةٌ مِنْ عِنْدِ النَّجَاشِيِّ أَهْدَاهَا لَهُ فِيهَا خَاتَمٌ مِنْ ذَهَبٍ فِيهِ فَصٌّ حَبَشِيٌّ قَالَتْ فَأَخَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُودٍ مُعْرِضًا عَنْهُ أَوْ بِبَعْضِ أَصَابِعِهِ ثُمَّ دَعَا أُمَامَةَ ابْنَةَ أَبِي الْعَاصِ ابْنَةَ ابْنَتِهِ زَيْنَبَ فَقَالَ تَحَلَّيْ بِهَذَا يَا بُنَيَّةُ","id":"Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] ia berkata; telah menceritakan kepadaku [Yahya bin Abbad] dari bapaknya [Abbad bin Abdullah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendapat kiriman perhiasan dari An Najasyi sebagai hadiah. Di antara perhiasan tersebut terdapat sebuah cincin emas yang mata cincinnya dari habasyah. 'Aisyah berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu mengambilnya dengan sebatang kayu, atau jarinya karena tidak suka. Beliau kemudian memanggil Umamah binti Abu Al Ash, anak perempuan dari puterinya Zainab, beliau bersabda: \"Wahai anakku, pakailah perhiasan ini.\""},"3584":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ أَسِيدِ بْنِ أَبِي أَسِيدٍ الْبَرَّادِ عَنْ نَافِعِ بْنِ عَيَّاشٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ أَنْ يُحَلِّقَ حَبِيبَهُ حَلْقَةً مِنْ نَارٍ فَلْيُحَلِّقْهُ حَلْقَةً مِنْ ذَهَبٍ وَمَنْ أَحَبَّ أَنْ يُطَوِّقَ حَبِيبَهُ طَوْقًا مِنْ نَارٍ فَلْيُطَوِّقْهُ طَوْقًا مِنْ ذَهَبٍ وَمَنْ أَحَبَّ أَنْ يُسَوِّرَ حَبِيبَهُ سِوَارًا مِنْ نَارٍ فَلْيُسَوِّرْهُ سِوَارًا مِنْ ذَهَبٍ وَلَكِنْ عَلَيْكُمْ بِالْفِضَّةِ فَالْعَبُوا بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Abdul Aziz] -maksudnya Abdul Aziz bin Muhammad- dari [Asid bin Abu Asid Al Barrad] dari [Nafi' bin Ayyasy] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin memberi cincin kekasihnya dengan cincin dari api, hendaklah ia memberinya cincin dari emas. Barangsiapa ingin memberi gelang kepada kekasihnya dengan gelang dari api, hendaklah ia memberinya gelang dari emas. Dan barangsiapa ingin memberi gelang kepada kekasihnya dengan gelang dari api, hendaklah ia memberinya gelang dari emas. Hendaklah kalian menggunakan perak, dan bersenang-senanglah kalian dengannya.\""},"3585":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ امْرَأَتِهِ عَنْ أُخْتٍ لِحُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا مَعْشَرَ النِّسَاءِ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ بِهِ أَمَا إِنَّهُ لَيْسَ مِنْكُنَّ امْرَأَةٌ تَحَلَّى ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Manshur] dari [Rib'I bin Hirasy] dari [Isterinya] dari [Saudara perempuan Hudzaifah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai sekalian wanita, tidak cukupkah perak sebagai perhiasan kalian? Tidaklah salah seorang wanita dari kalian mengenakan perhiasan emas, lalu memperlihatkannya (kepada orang lain) kecuali ia akan disiksa.\""},"3586":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ حَدَّثَنَا يَحْيَى أَنَّ مَحْمُودَ بْنَ عَمْرٍو الْأَنْصَارِيَّ حَدَّثَهُ أَنَّ أَسْمَاءَ بِنْتَ يَزِيدَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ تَقَلَّدَتْ قِلَادَةً مِنْ ذَهَبٍ قُلِّدَتْ فِي عُنُقِهَا مِثْلَهُ مِنْ النَّارِ يَوْمَ الْقِيَامَةِ وَأَيُّمَا امْرَأَةٍ جَعَلَتْ فِي أُذُنِهَا خُرْصًا مِنْ ذَهَبٍ جُعِلَ فِي أُذُنِهَا مِثْلُهُ مِنْ النَّارِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Aban bin Yazid Al 'Aththar] berkata, telah menceritakan kepada kami [Yahya] bahwa [Mahmud bin Amru Al Anshari] menceritakan kepadanya, bahwa [Asma binti Yazid] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja memakai kalung emas, maka pada hari kiamat kelak ia akan diberi kalung yang semisal dari api. Dan wanita mana saja yang di telinganya terdapat anting emas, maka pada hari kiamat kelak ia akan diberi anting yang semisal dari api.\""},"3587":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا خَالِدٌ عَنْ مَيْمُونٍ الْقَنَّادِ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ رُكُوبِ النِّمَارِ وَعَنْ لُبْسِ الذَّهَبِ إِلَّا مُقَطَّعًاقَالَ أَبُو دَاوُد أَبُو قِلَابَةَ لَمْ يَلْقَ مُعَاوِيَةَ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Khalid] dari [Maimun Al Qannad] dari [Abu Qilabah] dari [Mu'awiyah bin Abu Sufyan] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengendarai macan dan mengenakan emas kecuali yang telah diputus-putus.\" Abu Dawud berkata, \"Abu Qilabah belum pernah bertemu Mu'awiyah.\""},"3588":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا فَمَا تَرَكَ شَيْئًا يَكُونُ فِي مَقَامِهِ ذَلِكَ إِلَى قِيَامِ السَّاعَةِ إِلَّا حَدَّثَهُ حَفِظَهُ مَنْ حَفِظَهُ وَنَسِيَهُ مَنْ نَسِيَهُ قَدْ عَلِمَهُ أَصْحَابُهُ هَؤُلَاءِ وَإِنَّهُ لَيَكُونُ مِنْهُ الشَّيْءُ فَأَذْكُرُهُ كَمَا يَذْكُرُ الرَّجُلُ وَجْهَ الرَّجُلِ إِذَا غَابَ عَنْهُ ثُمَّ إِذَا رَآهُ عَرَفَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari [Hudzaifah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berdiri di hadapan kami (khutbah), tidak ada sesuatu pun yang bakal terjadi hingga datang hari kiamat kecuali beliau jelaskan saat itu (berdiri). Maka hafallah orang yang hafal dan lupalah orang yang lupa, dan para sahabatnya telah mengetahui hal itu. Sungguh, aku dapat mengingat apa yang disampaikan saat itu, sebagaimana seorang laki-laki yang mengingat wajah orang yang pergi kemudian bertemu lagi.\""},"3589":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ بَدْرِ بْنِ عُثْمَانَ عَنْ عَامِرٍ عَنْ رَجُلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَكُونُ فِي هَذِهِ الْأُمَّةِ أَرْبَعُ فِتَنٍ فِي آخِرِهَا الْفَنَاءُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Badr bin Utsman] dari [Amir] dari [seorang laki-laki] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada umatku akan terjadi empat macam fitnah, dan yang terakhir adalah kebinasaan.\""},"3590":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدٍ الْحِمْصِيُّ حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَالِمٍ حَدَّثَنِي الْعَلَاءُ بْنُ عُتْبَةَ عَنْ عُمَيْرِ بْنِ هَانِئٍ الْعَنْسِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُكُنَّا قُعُودًا عِنْدَ رَسُولِ اللَّهِ فَذَكَرَ الْفِتَنَ فَأَكْثَرَ فِي ذِكْرِهَا حَتَّى ذَكَرَ فِتْنَةَ الْأَحْلَاسِ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ وَمَا فِتْنَةُ الْأَحْلَاسِ قَالَ هِيَ هَرَبٌ وَحَرْبٌ ثُمَّ فِتْنَةُ السَّرَّاءِ دَخَنُهَا مِنْ تَحْتِ قَدَمَيْ رَجُلٍ مِنْ أَهْلِ بَيْتِي يَزْعُمُ أَنَّهُ مِنِّي وَلَيْسَ مِنِّي وَإِنَّمَا أَوْلِيَائِي الْمُتَّقُونَ ثُمَّ يَصْطَلِحُ النَّاسُ عَلَى رَجُلٍ كَوَرِكٍ عَلَى ضِلَعٍ ثُمَّ فِتْنَةُ الدُّهَيْمَاءِ لَا تَدَعُ أَحَدًا مِنْ هَذِهِ الْأُمَّةِ إِلَّا لَطَمَتْهُ لَطْمَةً فَإِذَا قِيلَ انْقَضَتْ تَمَادَتْ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا حَتَّى يَصِيرَ النَّاسُ إِلَى فُسْطَاطَيْنِ فُسْطَاطِ إِيمَانٍ لَا نِفَاقَ فِيهِ وَفُسْطَاطِ نِفَاقٍ لَا إِيمَانَ فِيهِ فَإِذَا كَانَ ذَاكُمْ فَانْتَظِرُوا الدَّجَّالَ مِنْ يَوْمِهِ أَوْ مِنْ غَدِهِ","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id Al Himshi] berkata, telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepadaku [Abdullah bin Salim] berkata, telah menceritakan kepadaku [Al 'Ala bin Utbah] dari [Umair bin Hani Al 'Ansi] ia berkata; Aku mendengar [Abdullah bin Umar] berkata, \"Saat kami duduk-duduk di sisi Rasulullah shallallahu 'alaihi wasallam, beliau bercerita tentang fitnah, panjang lebar beliau bercerita seputar fitnah itu hingga beliau menyebutkan tentang fitnah Al Ahlas. Seorang laki-laki lalu bertanya, \"Wahai Rasulullah, apa itu fitnah Al Ahlas?\" beliau menjawab: \"Adanya permusuhan dan peperangan, kemudian fitnah kesenangan yang asapnya muncul dari bawah kedua kaki seorang laki-laki ahli baitku. Ia mengaku berasal dari keturunanku, padahal bukan. Wali-waliku hanya orang-orang yang bertakwa. Kemudian orang-orang akan berdamai pada seorang laki-laki layaknya pangkal paha yang bertumpuk di tulang rusuk (kesepakatan yang semu). Kemudian akan muncul fitnah seorang yang buta (dengan kekuasaan), tidak seorang pun dari umat ini kecuali ia akan mendapat satu tamparan di mukanya (bencana kerusakan darinya). Ketika fitnah itu telah dianggap usai, namun fitnah tersebut justru berkelanjutan. Seorang laki-laki yang paginya beriman menjadi kafir di waktu sore, sehingga manusia akan menjadi dua kelompok; sekelompok orang yang beriman dan tidak ada kemunafikan dalam keimanannya, dan sekelompok orang yang penuh kemunafikan dan tidak ada keimanan padanya. Jika kondisi kalian sudah begitu, maka tunggulah munculnya Dajjal pada hari itu atau keesokan harinya.\""},"3591":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا ابْنُ فَرُّوخَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَخْبَرَنِي ابْنٌ لِقَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ أَبِيهِ قَالَ قَالَ حُذَيْفَةُ بْنُ الْيَمَانِوَاللَّهِ مَا أَدْرِي أَنَسِيَ أَصْحَابِي أَمْ تَنَاسَوْا وَاللَّهِ مَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قَائِدِ فِتْنَةٍ إِلَى أَنْ تَنْقَضِيَ الدُّنْيَا يَبْلُغُ مَنْ مَعَهُ ثَلَاثَ مِائَةٍ فَصَاعِدًا إِلَّا قَدْ سَمَّاهُ لَنَا بِاسْمِهِ وَاسْمِ أَبِيهِ وَاسْمِ قَبِيلَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Ibnu Farrukh] berkata, telah mengabarkan kepadaku [Usamah bin Zaid] berkata, telah mengabarkan kepadaku [Ibnu Qabishah bin Dzuaib] dari [Bapaknya] ia berkata; [Hudzaifah bin Yaman] berkata, \"Demi Allah, aku tidak tahu apakah para sahabatku lupa atau pura-pura lupa. Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak pernah meninggalkan penyeru fitnah hingga berakhirnya masa kehidupan dunia, yang jumlahlah lebih dari tiga ratus orang kecuali beliau menyebutkan kepada kami akan namanya, nama bapak dan kabilahnya.\""},"3592":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ سُبَيْعِ بْنِ خَالِدٍ قَالَأَتَيْتُ الْكُوفَةَ فِي زَمَنِ فُتِحَتْ تُسْتَرُ أَجْلُبُ مِنْهَا بِغَالًا فَدَخَلْتُ الْمَسْجِدَ فَإِذَا صَدْعٌ مِنْ الرِّجَالِ وَإِذَا رَجُلٌ جَالِسٌ تَعْرِفُ إِذَا رَأَيْتَهُ أَنَّهُ مِنْ رِجَالِ أَهْلِ الْحِجَازِ قَالَ قُلْتُ مَنْ هَذَا فَتَجَهَّمَنِي الْقَوْمُ وَقَالُوا أَمَا تَعْرِفُ هَذَا هَذَا حُذَيْفَةُ بْنُ الْيَمَانِ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ حُذَيْفَةُ إِنَّ النَّاسَ كَانُوا يَسْأَلُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَيْرِ وَكُنْتُ أَسْأَلُهُ عَنْ الشَّرِّ فَأَحْدَقَهُ الْقَوْمُ بِأَبْصَارِهِمْ فَقَالَ إِنِّي أَرَى الَّذِي تُنْكِرُونَ إِنِّي قُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ هَذَا الْخَيْرَ الَّذِي أَعْطَانَا اللَّهُ أَيَكُونُ بَعْدَهُ شَرٌّ كَمَا كَانَ قَبْلَهُ قَالَ نَعَمْ قُلْتُ فَمَا الْعِصْمَةُ مِنْ ذَلِكَ قَالَ السَّيْفُ قُلْتُ يَا رَسُولَ اللَّهِ ثُمَّ مَاذَا يَكُونُ قَالَ إِنْ كَانَ لِلَّهِ خَلِيفَةٌ فِي الْأَرْضِ فَضَرَبَ ظَهْرَكَ وَأَخَذَ مَالَكَ فَأَطِعْهُ وَإِلَّا فَمُتْ وَأَنْتَ عَاضٌّ بِجِذْلِ شَجَرَةٍ قُلْتُ ثُمَّ مَاذَا قَالَ ثُمَّ يَخْرُجُ الدَّجَّالُ مَعَهُ نَهْرٌ وَنَارٌ فَمَنْ وَقَعَ فِي نَارِهِ وَجَبَ أَجْرُهُ وَحُطَّ وِزْرُهُ وَمَنْ وَقَعَ فِي نَهْرِهِ وَجَبَ وِزْرُهُ وَحُطَّ أَجْرُهُ قَالَ قُلْتُ ثُمَّ مَاذَا قَالَ ثُمَّ هِيَ قِيَامُ السَّاعَةِحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ خَالِدِ بْنِ خَالِدٍ الْيَشْكُرِيِّ بِهَذَا الْحَدِيثِ قَالَ قُلْتُ بَعْدَ السَّيْفِ قَالَ بَقِيَّةٌ عَلَى أَقْذَاءٍ وَهُدْنَةٌ عَلَى دَخَنٍ ثُمَّ سَاقَ الْحَدِيثَ قَالَ وَكَانَ قَتَادَةُ يَضَعُهُ عَلَى الرِّدَّةِ الَّتِي فِي زَمَنِ أَبِي بَكْرٍ عَلَى أَقْذَاءٍ يَقُولُ قَذًى وَهُدْنَةٌ يَقُولُ صُلْحٌ عَلَى دَخَنٍ عَلَى ضَغَائِنَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ حُمَيْدٍ عَنْ نَصْرِ بْنِ عَاصِمٍ اللَّيْثِيِّ قَالَ أَتَيْنَا الْيَشْكُرِيَّ فِي رَهْطٍ مِنْ بَنِي لَيْثٍ فَقَالَ مَنْ الْقَوْمُ قُلْنَا بَنُو لَيْثٍ أَتَيْنَاكَ نَسْأَلُكَ عَنْ حَدِيثِ حُذَيْفَةَ فَذَكَرَ الْحَدِيثَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ هَلْ بَعْدَ هَذَا الْخَيْرِ شَرٌّ قَالَ فِتْنَةٌ وَشَرٌّ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ هَلْ بَعْدَ هَذَا الشَّرِّ خَيْرٌ قَالَ يَا حُذَيْفَةُ تَعَلَّمْ كِتَابَ اللَّهِ وَاتَّبِعْ مَا فِيهِ ثَلَاثَ مِرَارٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ هَلْ بَعْدَ هَذَا الشَّرِّ خَيْرٌ قَالَ هُدْنَةٌ عَلَى دَخَنٍ وَجَمَاعَةٌ عَلَى أَقْذَاءٍ فِيهَا أَوْ فِيهِمْ قُلْتُ يَا رَسُولَ اللَّهِ الْهُدْنَةُ عَلَى الدَّخَنِ مَا هِيَ قَالَ لَا تَرْجِعُ قُلُوبُ أَقْوَامٍ عَلَى الَّذِي كَانَتْ عَلَيْهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَبَعْدَ هَذَا الْخَيْرِ شَرٌّ قَالَ فِتْنَةٌ عَمْيَاءُ صَمَّاءُ عَلَيْهَا دُعَاةٌ عَلَى أَبْوَابِ النَّارِ فَإِنْ تَمُتْ يَا حُذَيْفَةُ وَأَنْ��َ عَاضٌّ عَلَى جِذْلٍ خَيْرٌ لَكَ مِنْ أَنْ تَتَّبِعَ أَحَدًا مِنْهُمْ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَبُو التَّيَّاحِ عَنْ صَخْرِ بْنِ بَدْرِ الْعِجْلِيِّ عَنْ سُبَيْعِ بْنِ خَالِدٍ بِهَذَا الْحَدِيثِ عَنْ حُذَيْفَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنْ لَمْ تَجِدْ يَوْمَئِذٍ خَلِيفَةً فَاهْرُبْ حَتَّى تَمُوتَ فَإِنْ تَمُتْ وَأَنْتَ عَاضٌّ وَقَالَ فِي آخِرِهِ قَالَ قُلْتُ فَمَا يَكُونُ بَعْدَ ذَلِكَ قَالَ لَوْ أَنَّ رَجُلًا نَتَجَ فَرَسًا لَمْ تُنْتَجْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Nashr bin Ashim] dari [Subai' bin Khalid] ia berkata, \"Aku pernah datang ke Kufah saat penaklukan kota Tustar tempat yang biasa aku membeli domba. Aku lantas masuk ke sebuah masjid, orang-orang banyak berkumpul, dan ternyata di sana ada seorang lelaki -jika kamu melihat, kamu akan tahu bahwa ia dari wilayah Hijaz; Makkah dan Madinah-. Aku bertanya, \"Siapakah lelaki ini?\" orang-orang memandangiku dengan sorotan tajam, mereka berkata, \"Engkau tidak tahu orang ini! ini adalah [Hudzaifah Ibnul Yaman], seorang sahabat Rasulullah shallallahu 'alaihi wasallam.\" Hudzaifah lalu berkata, \"Orang-orang banyak bertanya Rasulullah shallallahu 'alaihi wasallam tentang kebaikan, sementara aku bertanya beliau tentang keburukan.\" Orang-orang sepontan memperhatikan Hudzaifah dengan pandangan tajam, Hudzaifah melanjutkan, \"Aku tahu apa yang kalian ingkari (cemaskan). Aku pernah bertanya kepada Rasulullah, \"Wahai Rasulullah, apakah setelah kebaikan yang Allah berikan kepada kita ini, akan muncul keburukan setelahnya seperti masa-masa sebelumnya?\" Beliau menjawab: \"Benar.\" Aku bertanya lagi, \"Bagaimana bisa selamat dari hal itu?\" beliau menjawab: \"Dengan pedang.\" Aku bertanya lagi, \"Wahai Rasulullah, lantas apa yang bakal terjadi?\" Beliau menjawab: \"Jika Allah mempunyai Khalifah di muka bumi, lalu ia memukul punggung dan mengambil hartamu, maka taatilah ia. Jika tidak begitu, maka matilah kamu dalam keadaan menggigit akar pohon (tidak taat dan pergi menyepi).\" Aku bertanya lagi, \"Lalu apa yang akan terjadi?\" beliau menjawab: \"Akan muncul dajjal dengan membawa sungai dan api. Siapa yang jatuh ke dalam apinya, maka ia akan mendapatkan pahala dan akan dihapus dosanya. Dan siapa yang jatuh ke dalam sungainya, maka ia akan mendapat dosa dan digugurkan pahalanya.\" Aku bertanya lagi, \"Lalu apa lagi?\" beliau menjawab: \"Kiamat akan datang.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Qatadah] dari [Nashr bin Ashim] dari [Khalid bin Khalid Al Yasykuri] dengan hadits yang sama. Ia (Hudzaifah) berkata, \"Setelah pedang apa lagi?\" beliau menjawab: \"Akan tersisa kotoran mata (keburukan) dan kerisuhan yang berkedok kedamaian.\" Lalu ia menyebutkan hadits selengkapnya.\" Ia (perawai) berkata, \"Qatadah menganalogikan 'kotoran mata' adalah peristiwa riddah (pemurtadan) yang ada di masa Abu Bakar. Dan 'kerisuhan yang berkedok kedamaian' adalah upaya damai yang semu.\" Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] berkata, telah menceritakan kepada kami [Sulaiman] -maksudnya Sulaiman bin Al Mughirah- dari [Humaid] dari [Nashr bin Ashim Al Laitsi] ia berkata, \"Kami pernah mendatangi [Al Yasykuri] dalam sebuah rombongan bani Laits, ia bertanya, \"Siapakah orang-orang itu?\" kami menjawab, \"Mereka adalah orang-orang bani Laits. Kami mendatangimu untuk menanyakan seputar hadits Hudzaifah.. lalu ia menyebutkan hadits tersebut. Hudzaifah berkata, \"Aku bertanya, \"Wahai Rasulullah, apakah setelah kebaikan ini akan ada keburukan?\" beliau menjawab: \"Fitnah dan keburukan.\" Aku bertanya lagi, \"Wahai Rasulullah, apakah setelah keburukan ini akan muncul kebaikan?\" beliau menjawab: \"Wahai Hudzaifah, pelajarilah Al-Qur'an dan ikuti apa yang ada di dalamnya.\" Beliau ulangi kata-kata itu hingga tiga kali. Aku bertanya lagi, \"Wahai Rasulullah, apakah setelah keburukan ini ada kebaikan?\" beliau menjawab: \"Kericuhan berkedok kedamaian, dan kelompok yang diselimuti oleh kekufuran.\" Aku berkata, \"Wahai Rasulullah, maksud kerisuhan berkedok kedamaian itu apa?\" beliau menjawab: \"Jika hati orang-orang tidak lagi sebagaimana fitrahnya.\" Aku bertanya lagi, \"Wahai Rasulullah, apakah setelah kebaikan ini akan muncul keburukan?\" beliau menjawab: \"Fitnahnya orang yang buta dan tuli (dari kebenaran), mereka mempunyai penyeru-penyeru yang berada di pintu neraka. Wahai Hudzaifah, jika engkau mati dalam keadaan menggigit akar pohon (pergi menjauh), maka itu lebih baik dari pada kamu mengikuti mereka.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami [Abu At Tayyah] dari [Shakhr bin Badr Al 'Ijli] dari [Subai' bin Khalid] dengan hadits ini, dari [Hudzaifah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika pada hari itu engkau tidak mendapatkan seorang khalifah (yang adil), maka menjauhlah hingga engkau mendapati kematian, meskipun engkau mati dalam keadaan menggigit akar pohon.\" Dan pada penghujung hadits Hudzaifah berkata, \"Aku bertanya, \"Apa yang akan terjadi setelah itu?\" beliau menjawab: \"Andai kala itu ada seorang laki-laki yang mengawinkan kuda, maka ia tidak akan mendapatkan hasil hingga datang kiamat.\""},"3593":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَدِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ مَا اسْتَطَاعَ فَإِنْ جَاءَ آخَرُ يُنَازِعُهُ فَاضْرِبُوا رَقَبَةَ الْآخَرِ قُلْتُ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي قُلْتُ هَذَا ابْنُ عَمِّكَ مُعَاوِيَةُ يَأْمُرُنَا أَنْ نَفْعَلَ وَنَفْعَلَ قَالَ أَطِعْهُ فِي طَاعَةِ اللَّهِ وَاعْصِهِ فِي مَعْصِيَةِ اللَّهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al A'masy] dari [Zaid bin Wahb] dari ['Abdurrahman bin Abdu Rabbil Ka'bah] dari [Abdullah bin Amru] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaiat seorang imam, ia jabat tangannya dan menyerahkan keikhlasan hatinya (untuk setia), maka hendaklah ia berikan hak ketaatan padanya semampu mungkin. Jika ada pihak lain yang ingin mengambil kekuasaannya hendaklah ia penggal lehernya.\" Aku (perawi) bertanya, \"Apakah engkau benar-benar mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" Abdullah bin Amru menjawab: \"Kedua telingaku mendengarnya dan hatiku mengingatnya.\" Aku berkata, \"Sepupumu ini (Mu'awiyah), memerintahkan kami untuk melakukan begini dan begini?\" ia menjawab, \"Taatilah ia dalam ketaatan kepada Allah, dan ingkarilah dalam kemaksiatan kepada-Nya.\""},"3594":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ أَفْلَحَ مَنْ كَفَّ يَدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Syaiban] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Celakalah orang-orang Arab dari keburukan yang kian mendekat, dan beruntunglah orang yang dapat menahan tangannya.\""},"3595":{"ar":"قَالَ أَبُو دَاوُد حُدِّثْتُ عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْمُسْلِمُونَ أَنْ يُحَاصَرُوا إِلَى الْمَدِينَةِ حَتَّى يَكُونَ أَبْعَدَ مَسَالِحِهِمْ سَلَاحِحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ عَنْ عَنْبَسَةَ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ وَسَلَاحِ قَرِيبٌ مِنْ خَيْبَرَ","id":"Abu Dawud berkata; aku mendapat cerita dari [Ibnu Wahb] ia berkata; telah menceritakan kepada kami [Jarir bin Hazim] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir-hampir kaum muslimin terkepung hingga Madinah, sampai-sampai batas akhir pertahanan mereka adalah Silah (tempat dekat Khaibar).\", telah menceritakan kepada kami Ahmad bin Shalih dari Anbasah dari Yunus dari Az Zuhri ia berkata; \"Silah adalah nama tempat yang dekat dengan Khaibar.\""},"3596":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنِي أَبِي قَالَ ابْنُ عَوْفٍ وَقَرَأْتُ فِي أَصْلِ إِسْمَعِيلَ قَالَ حَدَّثَنِي ضَمْضَمٌ عَنْ شُرَيْحٍ عَنْ أَبِي مَالِكٍ يَعْنِي الْأَشْعَرِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ أَجَارَكُمْ مِنْ ثَلَاثِ خِلَالٍ أَنْ لَا يَدْعُوَ عَلَيْكُمْ نَبِيُّكُمْ فَتَهْلَكُوا جَمِيعًا وَأَنْ لَا يَظْهَرَ أَهْلُ الْبَاطِلِ عَلَى أَهْلِ الْحَقِّ وَأَنْ لَا تَجْتَمِعُوا عَلَى ضَلَالَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Auf Ath Tha`i] berkata, telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepadaku [Bapakku]. [Ibnu Auf] berkata; Aku membaca dalam buku Isma'il; ia berkata; telah menceritakan kepadaku [Dhamdham] dari [Syuraih] dari [Abu Malik] -maksudnya Abul Malik Al Asy'ari- ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melindungi kalian dari tiga hal; jangan sampai Nabi kalian mendoakan (keburukan), hingga kalian mendapat kecelakaan, jangan sampai pendukung kebatilan (orang-orang kafir) mengalahkan pendukung kebenaran, dan jangan sampai kalian berkumpul dalam kesesatan.\""},"3597":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ الْبَرَاءِ بْنِ نَاجِيَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَدُورُ رَحَى الْإِسْلَامِ لِخَمْسٍ وَثَلَاثِينَ أَوْ سِتٍّ وَثَلَاثِينَ أَوْ سَبْعٍ وَثَلَاثِينَ فَإِنْ يَهْلَكُوا فَسَبِيلُ مَنْ هَلَكَ وَإِنْ يَقُمْ لَهُمْ دِينُهُمْ يَقُمْ لَهُمْ سَبْعِينَ عَامًا قَالَ قُلْتُ أَمِمَّا بَقِيَ أَوْ مِمَّا مَضَى قَالَ مِمَّا مَضَىقَالَ أَبُو دَاوُد مَنْ قَالَ خِرَاشٍ فَقَدْ أَخْطَأَ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] berkata, telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Manshur] dari [rib'I bin Hirasy] dari [Al Bara bin Najiah] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Roda Islam akan berputar (berlangsung) selama tiga puluh lima, atau tiga puluh enam, atau tiga puluh tujuh (tahun). Jika mereka binasa maka itulah jalan orang-orang yang binasa (sebelum mereka), namun jika mereka menegakkan agama, maka mereka akan tetap ada hingga tujuh puluh tahun.\" Ibnu Mas'ud berkata, \"Aku lalu bertanya, \"Dihitung dari pasca tiga puluh lima tahun, atau mulai dari awal berdirinya daulah Islam (di masa kenabian)?\" beliau menjawab: \"Dihitung dari awal.\" Abu Dawud berkata, \"Siapa yang mengatakan (Rib'ie bin) Khirasy, ia telah keliru.\""},"3598":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عُثْمَانَ الشَّحَّامِ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ فِتْنَةٌ يَكُونُ الْمُضْطَجِعُ فِيهَا خَيْرًا مِنْ الْجَالِسِ وَالْجَالِسُ خَيْرًا مِنْ الْقَائِمِ وَالْقَائِمُ خَيْرًا مِنْ الْمَاشِي وَالْمَاشِي خَيْرًا مِنْ السَّاعِي قَالَ يَا رَسُولَ اللَّهِ مَا تَأْمُرُنِي قَالَ مَنْ كَانَتْ لَهُ إِبِلٌ فَلْيَلْحَقْ بِإِبِلِهِ وَمَنْ كَانَتْ لَهُ غَنَمٌ فَلْيَلْحَقْ بِغَنَمِهِ وَمَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَلْحَقْ بِأَرْضِهِ قَالَ فَمَنْ لَمْ يَكُنْ لَهُ شَيْءٌ مِنْ ذَلِكَ قَالَ فَلْيَعْمِدْ إِلَى سَيْفِهِ فَلْيَضْرِبْ بِحَدِّهِ عَلَى حَرَّةٍ ثُمَّ لِيَنْجُ مَ�� اسْتَطَاعَ النَّجَاءَحَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الرَّمْلِيُّ حَدَّثَنَا مُفَضِّلٌ عَنْ عَيَّاشٍ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ حُسَيْنِ بْنِ عَبْدِ الرَّحْمَنِ الْأَشْجَعِيِّ أَنَّهُ سَمِعَ سَعْدَ بْنَ أَبِي وَقَّاصٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْحَدِيثِ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ دَخَلَ عَلَيَّ بَيْتِي وَبَسَطَ يَدَهُ لِيَقْتُلَنِي قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْ كَابْنَيْ آدَمَ وَتَلَا يَزِيدُ{ لَئِنْ بَسَطْتَ إِلَيَّ يَدَكَ }الْآيَةَ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا أَبِي حَدَّثَنَا شِهَابُ بْنُ خِرَاشٍ عَنْ الْقَاسِمِ بْنِ غَزْوَانَ عَنْ إِسْحَقَ بْنِ رَاشِدٍ الْجَزَرِيِّ عَنْ سَالِمٍ حَدَّثَنِي عَمْرُو بْنُ وَابِصَةَ الْأَسَدِيُّ عَنْ أَبِيهِ وَابِصَةَ عَنْ ابْنِ مَسْعُودٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَ بَعْضَ حَدِيثِ أَبِي بَكْرَةَ قَالَ قَتْلَاهَا كُلُّهُمْ فِي النَّارِ قَالَ فِيهِ قُلْتُ مَتَى ذَلِكَ يَا ابْنَ مَسْعُودٍ قَالَ تِلْكَ أَيَّامُ الْهَرْجِ حَيْثُ لَا يَأْمَنُ الرَّجُلُ جَلِيسَهُ قُلْتُ فَمَا تَأْمُرُنِي إِنْ أَدْرَكَنِي ذَلِكَ الزَّمَانُ قَالَ تَكُفُّ لِسَانَكَ وَيَدَكَ وَتَكُونُ حِلْسًا مِنْ أَحْلَاسِ بَيْتِكَ فَلَمَّا قُتِلَ عُثْمَانُ طَارَ قَلْبِي مَطَارَهُ فَرَكِبْتُ حَتَّى أَتَيْتُ دِمَشْقَ فَلَقِيتُ خُرَيْمَ بْنَ فَاتِكٍ فَحَدَّثْتُهُ فَحَلَفَ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ لَسَمِعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا حَدَّثَنِيهِ ابْنُ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Utsman Asy Syahham] ia berkata; telah menceritakan kepadaku [Muslim bin Abu Bakrah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan muncul fitnah, saat itu orang yang berbaring lebih baik dari orang yang duduk, orang yang duduk lebih baik dari orang yang berdiri, orang yang berdiri lebih baik dari orang yang berjalan, dan orang yang berjalan lebih baik dari orang yang lari (jalan cepat).\" Ia (Abu Bakrah) berkata, \"Wahai Rasulullah, apa yang engkau perintahkan kepadaku?\" beliau menjawab: \"Barangsiapa memiliki unta hendaklah ia membawanya (pergi mengasingkan diri, jauh dari manusia pada saat itu), barangsiapa memiliki kambing hendaklah ia membawanya (pergi mengasingkan diri), barangsiapa memiliki tanah (yang jauh dari manusia) hendaklah ia pergi menujunya.\" Abu Bakrah berkata, \"Wahai Rasulullah, bagaimana dengan seseorang yang tidak memiliki sesuatu?\" beliau menjawab: \"Hendaklah ia menancapkan pedangnya pada tanah berbatu dan berpegangan dengannya, setelah itu hendaklah ia berusaha mencari perlindungan untuk keselamatan dirinya.\" Telah menceritakan kepada kami [Yazid bin Khalid Ar Ramli] berkata, telah menceritakan kepada kami [Mufadhdhil] dari [Ayyasy] dari [Bukair] dari [Busr bin Sa'id] dari [Husain bin 'Abdurrahman Al Asyja'i] Bahwasanya ia mendengar [Sa'd bin Abu Waqash] dari Nabi shallallahu 'alaihi wasallam…seperti hadits ini. Sa'd berkata, \"Aku bertanya, \"Wahai Rasulullah, apa pendapatmu jika ada seseorang masuk ke dalam rumahku dan mengacungkan tangannya untuk membunuhku?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Jadilah engkau sebagaimana dua anak Adam.\" Yazid lalu membaca firman Allah: '(Sungguh, kalau kamu menggerakkan tanganmu kepadaku untuk membunuhku..) ' Al Maidah: 28. Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Syihab bin Khirasy] dari [Al Qasim bin Ghazwan] dari [Ishaq bin Rasyid Al Jazari] dari [Salim] berkata, telah menceritakan kepadaku [Amru bin Wabishah Al Asadi] dari bapaknya [Wabishah] dari [Ibnu Mas'ud] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda…lalu ia menyebutkan sebagian hadits Abu Bakrah. Ibnu Mas'ud berkata, \"Semua korban pembunuhan (pada masa fitnah karena pertikaian dan perebutan kekuasaan serta harta) akan masuk neraka.\" Aku bertanya, \"Wahai Ibnu Mas'ud, kapan itu terjadi?\" Ibnu Mas'ud menjawab, \"Itu terjadai pada hari-hari tersebarnya Al Harj (pembunuhan), seorang laki-laki tidak lagi bisa mempercayai teman duduknya.\" Aku berkata, \"Lalu apa yang engkau perintahkan kepadaku jika menemui masa itu?\" Ibnu Mas'ud menjawab, \"Engkau jaga lisan dan tanganmu, lalu jadilah permadani bagi rumahmu (berdiam diri dan tidak keluar).\" (Wabishah) berkata, \"Maka saat Utsman dibunuh, hatiku melayang karena kepergiannya. Lantas aku pergi dengan kendaraan hingga aku memasuki Damasykus, lalu aku bertemu dengan [Khuraim bin Fatik] dan aku ceritakan hal itu kepadanya. Maka ia bersumpah atas nama Allah Yang tidak ada Tuhan yang berhak untuk disembah selain Dia, bahwa ia juga pernah mendengar hadits itu dari Rasulullah shallallahu 'alaihi wasallam, sebagaimana Ibnu Mas'ud menceritakannya kepadaku.\""},"3599":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَرْوَانَ عَنْ هُزَيْلٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي فَكَسِّرُوا قِسِيَّكُمْ وَقَطِّعُوا أَوْتَارَكُمْ وَاضْرِبُوا سُيُوفَكُمْ بِالْحِجَارَةِ فَإِنْ دُخِلَ يَعْنِي عَلَى أَحَدٍ مِنْكُمْ فَلْيَكُنْ كَخَيْرِ ابْنَيْ آدَمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Muhammad bin Juhadah] dari ['Abdurrahman bin Tsarwan] dari [Huzail] dari [Abu Musa Al Asy'ari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menjelang datangnya hari kiamat akan muncul fitnah seperti malam yang gelam gulita, seorang laki-laki beriman di pagi hari lalu kafir di sore hari, sore hari beriman lalu pagi hari kafir. Pada waktu itu orang yang duduk lebih baik dari orang yang berdiri, dan orang yang berjalan lebih baik dari orang yang berlari (jalan cepat). Patahkanlah anak panah kalian dan potonglah tali busur kalian, serta tancapkanlah pedang kalian di bebatuan. Jika ada seseorang yang masuk pada salah seorang dari kalian (untuk membunuh), maka berlakulah seperti sebaik-baik dari kedua anak Adam (Qabil dan Habil).\""},"3600":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ رَقَبَةَ بْنِ مَصْقَلَةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ سَمُرَةَ قَالَكُنْتُ آخِذًا بِيَدِ ابْنِ عُمَرَ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ إِذْ أَتَى عَلَى رَأْسٍ مَنْصُوبٍ فَقَالَ شَقِيَ قَاتِلُ هَذَا فَلَمَّا مَضَى قَالَ وَمَا أُرَى هَذَا إِلَّا قَدْ شَقِيَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ مَشَى إِلَى رَجُلٍ مِنْ أُمَّتِي لِيَقْتُلَهُ فَلْيَقُلْ هَكَذَا فَالْقَاتِلُ فِي النَّارِ وَالْمَقْتُولُ فِي الْجَنَّةِقَالَ أَبُو دَاوُد رَوَاهُ الثَّوْرِيُّ عَنْ عَوْنٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سُمَيْرٍ أَوْ سُمَيْرَةَ وَرَوَاهُ لَيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ عَوْنٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سُمَيْرَةَ قَالَ أَبُو دَاوُد قَالَ لِي الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو الْوَلِيدِ يَعْنِي بِهَذَا الْحَدِيثِ عَنْ أَبِي عَوَانَةَ و قَالَ هُوَ فِي كِتَابِي ابْنُ سَبَرَةَ وَقَالُوا سَمُرَةَ وَقَالُوا سُمَيْرَةَ هَذَا كَلَامُ أَبِي الْوَلِيدِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Raqabah bin Mashqalah] dari [Aun bin Abu Juhaifah] dari ['Abdurrahman] -maksudnya Abdur Rahman bin Samurah- ia berkata, \"Aku meraih tangan [Ibnu Umar] saat berada di jalanan kota Madinah; yakni saat mendatangi kepala yang ditancapkan (kepala Abdullah bin Az Zubair), ia berkata, \"Calakalah orang yang telah membunuh orang ini!\" Ketika telah berlalu ia berkata lagi, \"Aku tidak melihat kecuali orang ini telah celaka. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendatangi seorang laki-laki dari umatku untuk membunuhnya, hendaklah ia mengatakan begini 'orang yang membunuh dineraka dan yang dibunuh disurga.\" Abu Daud berkata; [At Tsauri] telah meriwayatkannya dari [Aun] dari [Abdur Rahman bin Sumair atau Sumairah] serta [Laits bin Abu Sulaim] meriwayatkannya dari [Aun] dari [Abdur Rahman bin Sumairah], Abu Daud berkata; \" [Al Hasan bin Ali] berkata kepadaku, telah menceritakan kepadaku [Abu Walid] -maksudnya menceritakan hadits ini-; dari [Abu Awanah] dan ia (Abu Walid) berkata; \"dia (Abdur Rahman) di dalam kitab saya (bernama Abdur Rahman) bin Sabarah, dan mereka berkata; Samurah, dan mereka juga berkata; Sumairah, ini adalah perkataannya Abu Walid.\""},"3601":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ الْمُشَعَّثِ بْنِ طَرِيفٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ فَذَكَرَ الْحَدِيثَ قَالَ فِيهِ كَيْفَ أَنْتَ إِذَا أَصَابَ النَّاسَ مَوْتٌ يَكُونُ الْبَيْتُ فِيهِ بِالْوَصِيفِ يَعْنِي الْقَبْرَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ أَوْ قَالَ مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ عَلَيْكَ بِالصَّبْرِ أَوْ قَالَ تَصْبِرُ ثُمَّ قَالَ لِي يَا أَبَا ذَرٍّ قُلْتُ لَبَّيْكَ وَسَعْدَيْكَ قَالَ كَيْفَ أَنْتَ إِذَا رَأَيْتَ أَحْجَارَ الزَّيْتِ قَدْ غَرِقَتْ بِالدَّمِ قُلْتُ مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ عَلَيْكَ بِمَنْ أَنْتَ مِنْهُ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا آخُذُ سَيْفِي وَأَضَعُهُ عَلَى عَاتِقِي قَالَ شَارَكْتَ الْقَوْمَ إِذَنْ قُلْتُ فَمَا تَأْمُرُنِي قَالَ تَلْزَمُ بَيْتَكَ قُلْتُ فَإِنْ دُخِلَ عَلَيَّ بَيْتِي قَالَ فَإِنْ خَشِيتَ أَنْ يَبْهَرَكَ شُعَاعُ السَّيْفِ فَأَلْقِ ثَوْبَكَ عَلَى وَجْهِكَ يَبُوءُ بِإِثْمِكَ وَإِثْمِهِقَالَ أَبُو دَاوُد لَمْ يَذْكُرْ الْمُشَعَّثَ فِي هَذَا الْحَدِيثِ غَيْرَ حَمَّادِ بْنِ زَيْدٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Imran Al Jauni] dari [Musya'ats bin Tharif] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abu Dzar!\" Aku menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu dan kebahagiaan semoga bersamamu, \" -lalu ia menyebutkan hadits secara lengkap-. Dalam hadits tersebut beliau bertanya: \"Apa yang akan kamu lakukan jika datang kematian kepada manusia, kemudian rumahnya pindah ke kuburan?\" Aku menjawab, \"Allah dan Rasul-Nya lebih tahu.\" Atau ia menyebutkan, \"(Aku akan melakukan) apa yang Allah dan Rasul-Nya kehendaki (pilih).\" Beliau bersabda: \"Hendaklah engkau sabar, atau beliau mengatakan: \"Bersabarlah.\" Kemudian beliau berkata lagi kepadaku: \"Wahai Abu Dzar!\" aku menjawab, \"Aku penuhi panggilanmu dan kebahagiaan semoga bersamamu, \"Apa pendapatmu jika Ahjar Az Zait (nama suatu tempat di Madinah) berlumuran darah?\" Aku menjawab, \"(Aku akan melakukan) apa yang Allah dan Rasul-Nya kehendaki untukku.\" Beliau bersabda: \"Hendaklah engkau bergabung bersama orang terdekatmu (keluarga, atau Imam yang kamu berbaiat kepadanya).\" Aku bertanya, \"Wahai Rasulullah, apa tidak lebih baik jika aku ambil pedangku, lalu aku letakkan di atas pundakku?\" beliau menjawab: \"Kalau begitu kamu telah ikut serta bersama orang-orang (dalam dosa).\" Aku lalu bertanya lagi, \"Lantas apa yang engkau perintahkan untukku?\" beliau menjawab: \"Berdiamlah engkau dirumahmu.\" Aku terus bertanya, \"Bagaimana jika ada seseorang yang masuk ke dalam rumahku!\" beliau menjawab: \"Jika engkau merasa takut dengan kilauan pedang musuh, maka letakkanlah kain baju di mukamu (pasrah), maka ia akan menanggung dosamu dan dosanya sendiri.\" Abu Dawud berkata, \"Al Musya'ats dalam hadits ini tidak menyebutkan selain Hammad bin Zaid.\""},"3602":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي كَبْشَةَ قَالَ سَمِعْتُ أَبَا مُوسَى يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ أَيْدِيكُمْ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي قَالُوا فَمَا تَأْمُرُنَا قَالَ كُونُوا أَحْلَاسَ بُيُوتِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Farits] berkata, telah menceritakan kepada kami [Affan bin Muslim] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Ashim Al Ahwal] dari [Abu Kabsyah] ia berkata; Aku mendengar [Abu Musa] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang kepada kalian fitnah sebagaimana malam yang gelap gulita, pada masa itu seorang beriman di pagi hari lalu kafir di sore hari, orang yang duduk lebih baik dari orang yang berdiri, orang yang berdiri lebih baik dari orang yang berjalan dan orang yang berjalan lebih baik dari orang yang berlari.\" Para sahabat bertanya, \"Lalu apa yang engkau perintahkan kepada kami?\" Beliau menjawab: \"Tetaplah kalian di rumah-rumah kalian.\""},"3603":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجٌ يَعْنِي ابْنَ مُحَمَّدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ قَالَايْمُ اللَّهِ لَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ السَّعِيدَ لَمَنْ جُنِّبَ الْفِتَنَ إِنَّ السَّعِيدَ لَمَنْ جُنِّبَ الْفِتَنِ إِنَّ السَّعِيدَ لَمَنْ جُنِّبَ الْفِتَنُ وَلَمَنْ ابْتُلِيَ فَصَبَرَ فَوَاهًا","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Hasan Al Misshishi] berkata, telah menceritakan kepada kami [Hajjaj] -maksudnya Hajjaj bin Muhammad- ia berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] ia berkata; telah menceritakan kepadaku [Mu'awiyah bin Shalih] bahwa ['Abdurrahman bin Jubair] menceritakan kepadanya dari [Bapaknya] dari [Al Miqdad Ibnul Aswad] ia berkata, \"Demi Allah, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bahagia adalah orang yang terhindar dari fitnah, orang yang bahagia adalah orang yang terhindar dari fitnah, orang yang bahagia adalah orang yang terhindar dari fitnah dan orang yang tertimpa musibah lalu bersabar seraya mengucapkan, \"Betapa baiknya cobaan ini!\""},"3604":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي ابْنُ وَهْبٍ حَدَّثَنِي اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ قَالَ خَالِدُ بْنُ أَبِي عِمْرَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَتَكُونُ فِتْنَةٌ صَمَّاءُ بَكْمَاءُ عَمْيَاءُ مَنْ أَشْرَفَ لَهَا اسْتَشْرَفَتْ لَهُ وَإِشْرَافُ اللِّسَانِ فِيهَا كَوُقُوعِ السَّيْفِ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] berkata, telah menceritakan kepadaku [Ibnu Wahb] berkata, telah menceritakan kepadaku [Al Laits] dari [Yahya bin Sa'id] ia berkata; [Khalid bin Abu Imran] berkata dari ['Abdurrahman Ibnil Bailamani] dari ['Abdurrahman bin Hurmuz] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah, orang-orang tidak lagi dapat mendengar, bisu dan tuli dari kebenaran, barang siapa yang mencoba untuk mendekati fitnah tersebut maka ia akan tertarik ke dalamnya, dan ikut serta dalam mengumbar lisan di dalamnya seperti memukulkan pedang (dalam mengakibatkan bahaya dan luka).\""},"3605":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا لَيْثٌ عَنْ طَاوُسٍ عَنْ رَجُلٍ يُقَالُ لَهُ زِيَادٌ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ فِتْنَةٌ تَسْتَنْظِفُ الْعَرَبَ قَتْلَاهَا فِي النَّارِ اللِّسَانُ فِيهَا أَشَدُّ مِنْ وَقْعِ السَّيْفِقَالَ أَبُو دَاوُد رَوَاهُ الثَّوْرِيُّ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ الْأَعْجَمِ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى بْنِ الطَّبَّاعِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْقُدُّوسِ قَالَ زِيَادٌ سِيْمِينُ كُوشَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Laits] dari [Thawus] dari seorang laki-laki yang bernama [Ziyad] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah, yang akan membersihkan bangsa Arab, orang-orang yang terbunuh akan masuk ke dalam neraka (karena perebutan harta dan kekuasaan), dan lisan pada hari itu lebih tajam dari sabetan pedang.\" Abu Dawud berkata, \"Hadits diriwayatkan oleh [Ats Tsauri] dari [Laits], dari [Thawus], dari [Al A'jam].\" Telah menceritakan kepada kami [Muhammad bin Isa bin Ath Thaba'].\" Telah menceritakan kepada kami [Abdullah bin Abdul Qudus] berkata, \"Ziyad adalah seorang laki-laki yang berkuping putih.\""},"3606":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتَّبِعُ بِهَا شَغَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari ['Abdurrahman bin Abdullah bin 'Abdurrahman bin Abu Sha'sha'ah] dari [Bapaknya] dari [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir-hampir (tiba masanya) harta seorang muslim adalah seekor kambing, ia giring ke puncak gunung dan tempat turunnya embun; ia pergi menyelamatkan agamanya dari fitnah.\""},"3607":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ وَيُونُسَ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَخَرَجْتُ وَأَنَا أُرِيدُ يَعْنِي فِي الْقِتَالِ فَلَقِيَنِي أَبُو بَكْرَةَ فَقَالَ ارْجِعْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قَالَ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ أَرَادَ قَتْلَ صَاحِبِهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ الْحَسَنِ بِإِسْنَادِهِ وَمَعْنَاهُ مُخْتَصَرًا","id":"Telah menceritakan kepada kami [Abu Kamil] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dan [Yunus] dari [Al Hasan] dari [Al Ahnaf bin Qais] ia berkata, \"Saat aku keluar -yakni untuk perang-, [Abu bakrah] menemuiku seraya berkata, \"Kembalilah pulang! Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dua orang muslim saling berhadapan dengan pedang terhunus, maka baik yang membunuh atau yang terbunuh akan masuk neraka.\" Ia (perawi) berkata, \"Jika orang yang membunuh wajar masuk neraka, tapi bagaimana dengan yang terbunuh?\" beliau bersabda: \"Karena ia juga ingin membunuh saudaranya.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutawakkil Al Asqalani] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Al Hasan] dengan sanad dan maknanya secara ringkas. "},"3608":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ خَالِدِ بْنِ دِهْقَانَ قَالَكُنَّا فِي غَزْوَةِ الْقُسْطَنْطِينِيَّةِ بِذُلُقْيَةَ فَأَقْبَلَ رَجُلُ مِنْ أَهْلِ فِلَسْطِينَ مِنْ أَشْرَافِهِمْ وَخِيَارِهِمْ يَعْرِفُونَ ذَلِكَ لَهُ يُقَالُ لَهُ هَانِئُ بْنُ كُلْثُومِ بْنِ شَرِيكٍ الْكِنَانِيُّ فَسَلَّمَ عَلَى عَبْدِ اللَّهِ بْنِ أَبِي زَكَرِيَّا وَكَانَ يَعْرِفُ لَهُ حَقَّهُ قَالَ لَنَا خَالِدٌ فَحَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زَكَرِيَّا قَالَ سَمِعْتُ أُمَّ الدَّرْدَاءِ تَقُولُ سَمِعْتُ أَبَا الدَّرْدَاءِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ ذَنْبٍ عَسَى اللَّهُ أَنْ يَغْفِرَهُ إِلَّا مَنْ مَاتَ مُشْرِكًا أَوْ مُؤْمِنٌ قَتَلَ مُؤْمِنًا مُتَعَمِّ��ًافَقَالَ هَانِئُ بْنُ كُلْثُومٍ سَمِعْتُ مَحْمُودَ بْنَ الرَّبِيعِ يُحَدِّثُ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّهُ سَمِعَهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قَتَلَ مُؤْمِنًا فَاعْتَبَطَ بِقَتْلِهِ لَمْ يَقْبَلْ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا قَالَ لَنَا خَالِدٌ ثُمَّ حَدَّثَنِي ابْنُ أَبِي زَكَرِيَّا عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ الْمُؤْمِنُ مُعْنِقًا صَالِحًا مَا لَمْ يُصِبْ دَمًا حَرَامًا فَإِذَا أَصَابَ دَمًا حَرَامًا بَلَّحَ وَحَدَّثَ هَانِئُ بْنُ كُلْثُومٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ سَوَاءً حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو عَنْ مُحَمَّدِ بْنِ مُبِارَكٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ أَوْ غَيْرُهُ قَالَ قَالَ خَالِدُ بْنُ دِهْقَانَ سَأَلْتُ يَحْيَى بْنَ يَحْيَى الْغَسَّانِيَّ عَنْ قَوْلِهِ اعْتَبَطَ بِقَتْلِهِ قَالَ الَّذِينَ يُقَاتِلُونَ فِي الْفِتْنَةِ فَيَقْتُلُ أَحَدُهُمْ فَيَرَى أَنَّهُ عَلَى هُدًى لَا يَسْتَغْفِرُ اللَّهَ يَعْنِي مِنْ ذَلِكَ قَالَ أَبُو دَاوُد فَاعْتَبَطَ يَصُبُّ دَمَهُ صَبًّا","id":"Telah menceritakan kepada kami [Muammal Ibnul Fadhl Al Harrani] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib] dari [Khalid bin Dihqan] ia berkata, \"Saat kami sedang berada dalam peperangan Qastantiniyah di daerah Dzuluqyah, seorang laki-laki terpandang dan paling baik dari penduduk Palestina, orang-orang biasa memanggilnya dengan nama Hani bin Kultsum bin Syarik Al Kinani, datang seraya mengucapkan salam kepada [Abullah bin Abu Zakariya]. Orang yang tahu akan kedudukannya -Hani-. lalu Khalid berkata kepada kami, \"Abdullah bin Abu Zakariya telah menceritakan kepadaku, ia berkata; Aku mendengar [Ummu Darda] berkata, \"Aku mendengar [Abu Darda] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dosa berharap bisa diampuni oleh Allah kecuali seseorang yang meninggal dalam keadaan musyrik, atau seorang mukmin yang membunuh mukmin lainnya dengan sengaja.\" [Hani bin Kultsum] berkata, \"Aku mendengar [Mahmud bin Ar Rabi'] menceritakan dari [Ubadah bin Ash Shamit], Bahwasanya ia pernah mendengarnya menceritakan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membunuh seorang mukmin dengan zhalim, maka Allah tidak akan menerima taubat atau ibadah sunahnya.\" [Khalid] lantas berkata lagi kepada kami; [Ibnu Abu Zakariya] menceritakan kepadaku dari [Ummu Darda], dari [Abu Darda], dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin akan senantiasa dalam keshalihan selama ia tidak terlumuri darah yang haram (membunuh), jika berlumuran maka ia telah terjerumus dalam kehancuran.\" Hani bin Kultsum juga menceritakan dari Mahmud bin Ar Rabi', dari Ubadah bin Ash Shamit, dari Rasulullah shallallahu 'alaihi wasallam, persis sebagaimana hadits tersebut. Telah menceritakan kepada kami 'Abdurrahman bin Amru dari Muhammad bin Mubarak berkata, telah menceritakan kepada kami Shadaqah bin Khalid atau selainnya, ia berkata; Khalid bin Dihqan berkata; Aku bertanya kepada Yahya bin Yahya Al Ghassani tentang sabda beliau, 'membunuhnya dengan zhalim'? ia menjawab, \"(Yaitu) orang-orang yang saling bunuh dalam fitnah hingga salah seorang dari mereka terbunuh, namun ia melihat bahwa dirinya di atas petunjuk dan tidak meminta ampun kepada Allah -yaitu dari dosa membunuh tersebut-.\" Abu Dawud berkata, \"Maka kata I'tabatha adalah menumpahkan darah.\""},"3609":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ مُجَالِدِ بْنِ عَوْفٍ أَنَّ خَارِجَةَ بْنَ زَيْدٍ قَالَ سَمِعْتُ زَيْدَ بْنَ ثَابِتٍفِي هَذَا الْمَكَانِ يَقُولُ أُنْزِلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ خَالِدًا فِيهَا }بَعْدَ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }بِسِتَّةِ أَشْهُرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami ['Abdurrahman bin Ishaq] dari [Abu Az Zinad] dari [Mujalid bin Auf] bahwa [Kharijah bin Zaid] berkata; Aku mendengar [Zaid bin Tsabit] berkata di tempat ini, \"Firman Allah ini: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam, ia kekal di dalamnya..) -An Nisa: 93-, diturunkan setelah ayat Allah yang ada dalam surat Al Furqan: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68- jaraknya adalah enam bulam.\""},"3610":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","id":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},"3611":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }قَالَ مَا نَسَخَهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja…) -Qs. An Nisa: 94-, tidak pernah dihapus oleh ayat manapun.\""},"3612":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍفِي قَوْلِهِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }قَالَ هِيَ جَزَاؤُهُ فَإِنْ شَاءَ اللَّهُ أَنْ يَتَجَاوَزَ عَنْهُ فَعَلَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Abu Syihab] dari [Sulaiman At Taimi] dari [Abu Mijlaz] tentang firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja, maka balasannya ialah Jahannam..) -Qs. An Nisa: 93- ia berkata, \"Itu adalah ganjaran baginya, jika Allah akan mengampuninya, maka Allah akan melakukannya.\""},"3613":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ سَلَّامُ بْنُ سُلَيْمٍ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ فِتْنَةً فَعَظَّمَ أَمْرَهَا فَقُلْنَا أَوْ قَالُوا يَا رَسُولَ اللَّهِ لَئِنْ أَدْرَكَتْنَا هَذِهِ لَتُهْلِكَنَّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا إِنَّ بِحَسْبِكُمْ الْقَتْلَقَالَ سَعِيدٌ فَرَأَيْتُ إِخْوَانِي قُتِلُوا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Al Ahwash Salam bin Sulaim] dari [Manshur] dari [Hilal bin Yasaf] dari [Sa'id bin Zaid] ia berkata, \"Saat kami berada di sisi Nabi shallallahu 'alaihi wasallam, beliau menyebutkan tentang fitnah dan memperbesar masalahnya, kami lalu berkata, atau mereka mengatakan, \"Wahai Rasulullah, jika hal itu menimpa kami, maka hancurlah kami!\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Tidak, itu bergantung kalian dalam menjaga dari pembunuhan.\" Sa'id berkata, \"Aku melihat saudara-saudaraku terbunuh.\""},"3614":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّتِي هَذِهِ أُمَّةٌ مَرْحُومَةٌ لَيْسَ عَلَيْهَا عَذَابٌ فِي الْآخِرَةِ عَذَابُهَا فِي الدُّنْيَا الْفِتَنُ وَالزَّلَازِلُ وَالْقَتْلُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Katsir bin Hisyam] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Sa'id bin Abu Burdah] dari [Bapaknya] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umatku adalah umat yang terhormat, di akhirat tidak akan mendapatkan siksa, siksa mereka adalah di dunia; yakni dengan adanya fitnah, gempa bumi dan peperangan.\""},"3615":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ إِسْمَعِيلَ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ هَذَا الدِّينُ قَائِمًا حَتَّى يَكُونَ عَلَيْكُمْ اثْنَا عَشَرَ خَلِيفَةً كُلُّهُمْ تَجْتَمِعُ عَلَيْهِ الْأُمَّةُ فَسَمِعْتُ كَلَامًا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أَفْهَمْهُ قُلْتُ لِأَبِي مَا يَقُولُ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Isma'il] -maksudnya Ismail bin Abu Khalid- dari [Bapaknya] dari [Jabir bin Samurah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Agama ini akan senantiasa tegak hingga muncul di antara kalian dua belas khalifah, dan manusia akan ikut bersama mereka.\" Aku mendengar ucapan dari Nabi shallallahu 'alaihi wasallam yang tidak aku mengerti, lalu aku kepada bertanya bapakku tentang apa yang beliau katakan itu, ia (bapakku) menjawab, \"Mereka semua (para khalifah) dari bangsa Quraisy.\""},"3616":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ هَذَا الدِّينُ عَزِيزًا إِلَى اثْنَيْ عَشَرَ خَلِيفَةً قَالَ فَكَبَّرَ النَّاسُ وَضَجُّوا ثُمَّ قَالَ كَلِمَةً خَفِيفَةً قُلْتُ لِأَبِي يَا أَبَتِ مَا قَالَ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍحَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا زِيَادُ بْنُ خَيْثَمَةَ حَدَّثَنَا الْأَسْوَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ عَنْ جَابِرِ بْنِ سَمُرَةَ بِهَذَا الْحَدِيثِ زَادَ فَلَمَّا رَجَعَ إِلَى مَنْزِلِهِ أَتَتْهُ قُرَيْشٌ فَقَالُوا ثُمَّ يَكُونُ مَاذَا قَالَ ثُمَّ يَكُونُ الْهَرْجُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Dawud] dari [Amir] dari [Jabir bin Samurah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Agama ini akan tetap mulia hingga khalifah ke dua belas.\" Jabir berkata, \"Orang-orang bertakbir dan berteriak. Kemudian beliau mengatakan suatu ucapan yang pelan (hingga aku tidak mendengarnyanya, lalu aku bertanya kepada bapakku, \"Wahai bapakku, apa yang beliau katakan?\" Ia menjawab, \"Beliau mengatakan bahwa mereka dari bangsa Quraisy.\" Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Ziyad bin Khaitsamah] berkata, telah menceritakan kepada kami [Al Aswad bin Sa'id Al Hamdani] dari [Jabir bin Samurah] dengan hadits yang sama. Namun ia menambahkan, \"Ketika beliau kembali ke rumahnya, orang-orang Quraisy mendatanginya seraya bertanya, \"Setelah itu akan terjadi peristiwa apa?\" beliau menjawab: \"Akan terjadi pembunuhan.\""},"3617":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ عُمَرَ بْنَ عُبَيْدٍ حَدَّثَهُمْ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ ح و حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا زَائِدَةُ ح و حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ فِطْرٍ الْمَعْنَى وَاحِدٌ كُلُّهُمْ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ لَمْ يَبْقَ مِنْ الدُّنْيَا إِلَّا يَوْمٌ قَالَ زَائِدَةُ فِي حَدِيثِهِ لَطَوَّلَ اللَّهُ ذَلِكَ الْيَوْمَ ثُمَّ اتَّفَقُوا حَتَّى يَبْعَثَ فِيهِ رَجُلًا مِنِّي أَوْ مِنْ أَهْلِ بَيْتِي يُوَاطِئُ اسْمُهُ اسْمِي وَاسْمُ أَبِيهِ اسْمُ أَبِي زَادَ فِي حَدِيثِ فِطْرٍ يَمْلَأُ الْأَرْضَ قِسْطًا وَعَدْلًا كَمَا مُلِئَتْ ظُلْمًا وَجَوْرًا وَقَالَ فِي حَدِيثِ سُفْيَانَ لَا تَذْهَبُ أَوْ لَا تَنْقَضِي الدُّنْيَا حَتَّى يَمْلِكَ الْعَرَبَ رَجُلٌ مِنْ أَهْلِ بَيْتِي يُوَاطِئُ اسْمُهُ اسْمِيقَالَ أَبُو دَاوُد لَفْظُ عُمَرَ وَأَبِي بَكْرٍ بِمَعْنَى سُفْيَانَ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Umar bin Ubaid] menceritakan kepada mereka. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al 'Ala] berkata, telah menceritakan kepada kami [Abu Bakr] -maksudnya Abu Bakar bin 'Ayyasy-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah mengabarkan kepada kami [Zaidah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepadaku [Ubaidullah bin Musa] dari [Fithr] dengan makna hadits yang sama. Dan semuanya dari [Ashim] dari [Zir] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sekiranya dunia ini tidak tersisa kecuali hanya sehari, Zaidah menyebutkan dalam haditsnya, \"maka Allah akan memanjangkan hari itu, \" kemudian mereka bersepakat -dalam menyebutkan lafadz- hingga Allah mengutus seorang laki-laki dariku, atau dari keluargaku; namanya mirip dengan namaku, dan nama bapaknya juga mirip dengan nama bapakku. Dalam hadits Fithr ditambahkan, \"Ia akan memenuhi bumi dengan keadilan, sebagaimana kezhaliman dan kelaliman pernah memenuhinya.\" Dalam hadits riwayat Sufyan beliau mengatakan: \"(Dunia) tidak akan pergi, atau tidak akan hancur hingga seorang laki-laki dari ahli baitku menguasai Arab; namanya seperti namanku.\" Abu Daud berkata; \"lafadz hadits Umar dan Abu Bakar semakna dengan lafadz Abu Sufyan.\""},"3618":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا فِطْرٌ عَنْ الْقَاسِمِ بْنِ أَبِي بَزَّةَ عَنْ أَبِي الطُّفَيْلِ عَنْ عَلِيٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ لَمْ يَبْقَ مِنْ الدَّهْرِ إِلَّا يَوْمٌ لَبَعَثَ اللَّهُ رَجُلًا مِنْ أَهْلِ بَيْتِي يَمْلَؤُهَا عَدْلًا كَمَا مُلِئَتْ جَوْرًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Fadhl bin Dukain] berkata, telah menceritakan kepada kami [Fithr] dari [Al Qasim bin Abu Bazzah] dari [Abu Ath Thufail] dari [Ali radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sekiranya dunia ini tidak lagi tersisa kecuali hanya sehari, sungguh Allah akan mengutus seorang laki-laki dari ahli baitku, ia akan memenuhi bumi dengan keadilan sebagaimana bumi pernah dipenuhi kajahatan.\""},"3619":{"ar":"��َدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا أَبُو الْمَلِيحِ الْحَسَنُ بْنُ عُمَرَ عَنْ زِيَادِ بْنِ بَيَانٍ عَنْ عَلِيِّ بْنِ نُفَيْلٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أُمِّ سَلَمَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمَهْدِيُّ مِنْ عِتْرَتِي مِنْ وَلَدِ فَاطِمَةَقَالَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ وَسَمِعْتُ أَبَا الْمَلِيحِ يُثْنِي عَلَى عَلِيِّ بْنِ نُفَيْلٍ وَيَذْكُرُ مِنْهُ صَلَاحًا","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] berkata, telah menceritakan kepada kami [Abu Al Malih Al Hasan bin Umar] dari [Ziyad bin Bayan] dari [Ali bin Nufail] dari [Sa'id Ibnul Musayyab] dari [Ummu Salamah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Mahdi dari keturunanku, dari jalur Fatimah.\" Abdullah bin Ja'far berkata, \"Aku mendengar Abul Malih memuji Ali bin Nufail, dan ia menyebutkan akan kebaikannya.\""},"3620":{"ar":"حَدَّثَنَا سَهْلُ بْنُ تَمَّامِ بْنِ بَزِيعٍ حَدَّثَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَهْدِيُّ مِنِّي أَجْلَى الْجَبْهَةِ أَقْنَى الْأَنْفِ يَمْلَأُ الْأَرْضَ قِسْطًا وَعَدْلًا كَمَا مُلِئَتْ جَوْرًا وَظُلْمًا يَمْلِكُ سَبْعَ سِنِينَ","id":"Telah menceritakan kepada kami [Sahl bin Tammam bin Bazi'] berkata, telah menceritakan kepada kami [Imran Al Qaththan] dari [Qatadah] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Mahdi itu dari keturunanku, dahinya lebar dan hidungnya mancung, ia akan memenuhi bumi dengan keadilan sebagaimana bumi pernah dipenuhi dengan kejahatan dan kezhaliman. Ia akan berkuasa selama tujuh tahun.\""},"3621":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ صَاحِبٍ لَهُ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَكُونُ اخْتِلَافٌ عِنْدَ مَوْتِ خَلِيفَةٍ فَيَخْرُجُ رَجُلٌ مِنْ أَهْلِ الْمَدِينَةِ هَارِبًا إِلَى مَكَّةَ فَيَأْتِيهِ نَاسٌ مِنْ أَهْلِ مَكَّةَ فَيُخْرِجُونَهُ وَهُوَ كَارِهٌ فَيُبَايِعُونَهُ بَيْنَ الرُّكْنِ وَالْمَقَامِ وَيُبْعَثُ إِلَيْهِ بَعْثٌ مِنْ أَهْلِ الشَّامِ فَيُخْسَفُ بِهِمْ بِالْبَيْدَاءِ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَإِذَا رَأَى النَّاسُ ذَلِكَ أَتَاهُ أَبْدَالُ الشَّامِ وَعَصَائِبُ أَهْلِ الْعِرَاقِ فَيُبَايِعُونَهُ بَيْنَ الرُّكْنِ وَالْمَقَامِ ثُمَّ يَنْشَأُ رَجُلٌ مِنْ قُرَيْشٍ أَخْوَالُهُ كَلْبٌ فَيَبْعَثُ إِلَيْهِمْ بَعْثًا فَيَظْهَرُونَ عَلَيْهِمْ وَذَلِكَ بَعْثُ كَلْبٍ وَالْخَيْبَةُ لِمَنْ لَمْ يَشْهَدْ غَنِيمَةَ كَلْبٍ فَيَقْسِمُ الْمَالَ وَيَعْمَلُ فِي النَّاسِ بِسُنَّةِ نَبِيِّهِمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُلْقِي الْإِسْلَامُ بِجِرَانِهِ فِي الْأَرْضِ فَيَلْبَثُ سَبْعَ سِنِينَ ثُمَّ يُتَوَفَّى وَيُصَلِّي عَلَيْهِ الْمُسْلِمُونَقَالَ أَبُو دَاوُد قَالَ بَعْضُهُمْ عَنْ هِشَامٍ تِسْعَ سِنِينَ و قَالَ بَعْضُهُمْ سَبْعَ سِنِينَ حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الصَّمَدِ عَنْ هَمَّامٍ عَنْ قَتَادَةَ بِهَذَا الْحَدِيثِ وَقَالَ تِسْعَ سِنِينَ قَالَ أَبُو دَاوُد و قَالَ غَيْرُ مُعَاذٍ عَنْ هِشَامٍ تِسْعَ سِنِينَ حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا أَبُو الْعَوَّامِ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ وَحَدِيثُ مُعَاذٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Shalih Abu Al Khalil] dari [Sahabatnya] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan terjadi perselisihan saat matinya khalifah, lalu seorang laki-laki (Al Mahdi) akan keluar dari Madinah pergi menuju Makkah. Lantas beberapa orang dari penduduk Makkah mendatanginya, mereka memaksanya keluar (dari dalam rumah) meskipun ia tidak menginginkannya. Orang-orang itu kemudian membaiatnya pada suatu tempat antara Rukun (Hajar Asawad) dan Maqam (Ibrahim). Lalu dikirimlah sepasukan dari penduduk Syam untuk memeranginya, tetapi pasukan itu justru ditenggelamkan oleh (Allah) di Al Baida, tempat antara Makkah dan Madinah. Maka ketika manusia melihat hal itu, orang-orang shalih dari Syam dan orang-orang terbaik dari penduduk Irak membaiatnya antara rukun dan Maqam. Lalu tumbuhlah seorang laki-laki dari bangsa Quraisy, paman-pamannya dari suku Kalb, ia lalu mengirimkan sepasukan untuk memerangi mereka (orang-orang yang berbaiat kepada Al mahdi) namun mereka dapat mengalahkan mereka (pasukan yang dikirim oleh lelaki Quraisy dari suku Kalb). Alangkah ruginya orang yang tidak ikut serta dalam pembagian ghanimah perang melawan suku Kalb. ia (Al Mahdi) lalu membagi ghanimah, dan membina manusia dengan sunnah Nabi mereka shallallahu 'alaihi wasallam dan menyampaikan Islam ke semua penduduk bumi. Ia berkuasa selama tujuh tahun, kemudian wafat dan dishalati oleh kaum muslimin.\" Abu Dawud berkata, \"Sebagian mereka menyebutkan dari Hisyam, \" selama sembilan tahun.\" Dan sebagian yang lain menyebutkan, \"Selama tujuh tahun.\" Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abdu Ash Shamad] dari [Hammam] dari [Qatadah] dengan hadits yang sama. Beliau mengatakan, \"sembilan tahun.\" Abu Dawud berkata, \"Selain Mu'adz menyebutkan dari Hisyam, \"selama sembilan tahun.\" Telah menceritakan kepada kami [Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Amru bin Ashim] berkata, telah menceritakan kepada kami [Abu Al Awwam] berkata, telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini, namun hadits Mu'adz lebih lengkap.\""},"3622":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِصَّةِ جَيْشِ الْخَسْفِ قُلْتُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَيْفَ بِمَنْ كَانَ كَارِهًا قَالَ يُخْسَفُ بِهِمْ وَلَكِنْ يُبْعَثُ يَوْمَ الْقِيَامَةِ عَلَى نِيَّتِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Abdul Aziz bin rufai'] dari [Ubaidullah bin Al Qibthiyyah] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam berkenaan dengan kisah pasukan yang ditenggelamkan. Aku bertanya, \"Wahai Rasulullah shallallahu 'alaihi wasallam, bagaimana dengan orang yang terpaksa (bersama tentara yang ditenggelamkan)?\" beliau menjawab: \"Ia juga akan ditenggelamkan, hanyasaja pada hari kiamat ia akan dibangkitkan sesuai dengan niatnya.\""},"3623":{"ar":"قَالَ أَبُو دَاوُد حُدِّثْتُ عَنْ هَارُونَ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ شُعَيْبِ بْنِ خَالِدٍ عَنْ أَبِي إِسْحَقَ قَالَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ وَنَظَرَ إِلَى ابْنِهِ الْحَسَنِ فَقَالَ إِنَّ ابْنِي هَذَا سَيِّدٌ كَمَا سَمَّاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَيَخْرُجُ مِنْ صُلْبِهِ رَجُلٌ يُسَمَّى بِاسْمِ نَبِيِّكُمْ يُشْبِهُهُ فِي الْخُلُقِ وَلَا يُشْبِهُهُ فِي الْخَلْقِ ثُمَّ ذَكَرَ قِصَّةً يَمْلَأُ الْأَرْضَ عَدْلًاو قَالَ هَارُونُ حَدَّثَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ مُطَرِّفِ بْنِ طَرِيفٍ عَنْ أَبِي الْحَسَنِ عَنْ هِلَالِ بْنِ عَمْرٍو قَالَ سَمِعْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ رَجُلٌ مِنْ وَرَاءِ النَّهْرِ يُقَالُ لَهُ الْحَارِثُ بْنُ حَرَّاثٍ عَلَى مُقَدِّمَتِهِ رَجُلٌ يُقَالُ لَهُ مَنْصُورٌ يُوَطِّئُ أَوْ يُمَكِّنُ لِآلِ مُحَمَّدٍ كَمَا مَكَّنَتْ قُرَيْشٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَ عَلَى كُلِّ مُؤْمِنٍ نَصْرُهُ أَوْ قَالَ إِجَابَتُهُ","id":"Abu Dawud berkata; Aku diceritakan dari [Harun Ibnul Mughirah] ia berkata; telah menceritakan kepada kami [Amru bin Abu Qais] dari [Syu'aib bin Khalid] dari [Abu Ishaq] ia berkata; Sambil melihat puteranya Al hasan, Ali radliallahu 'anhu berkata berkata, \"Puteraku ini adalah seorang pemimpin sebagaimana yang disebutkan oleh Nabi shallallahu 'alaihi wasallam, dan akan keluar dari keturunannya seorang laki-laki yang bernama seperti nama Nabi kalian, akhlaqnya sama tetapi tidak untuk postur tubuhnya.\" Kemudian beliau menyebutkan kisahnya, \"Ia akan memenuhi bumi dengan keadilan.\" Harun berkata, \"Telah menceritakan kepada kami [Amru bin Abu Qais] dari [Mutharrif bin Tharif] dari [Abu Al Hasan] dari [Hilal bin Amru] ia berkata; Aku mendengar [Ali radliallahu 'anhu] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Akan keluar seorang laki-laki dari seberang sungai (seperti Bukhara dan Samarqan), dia bernama Al Harits bin Hurrats, lalu setelahnya akan keluar seorang laki-laki bernama Manshur. Ia memperkokoh keluarga Muhammad sebagaimana bangsa Quraisy memperkokoh Rasulullah shallallahu 'alaihi wasallam. Maka wajib atas setiap mukmin menolongnya, atau beliau mengatakan: \"memenuhi seruannya.\""},"3624":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ شَرَاحِيلَ بْنِ يَزِيدَ الْمُعَافِرِيِّ عَنْ أَبِي عَلْقَمَةَ عَنْ أَبِي هُرَيْرَةَ فِيمَا أَعْلَمُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَبْعَثُ لِهَذِهِ الْأُمَّةِ عَلَى رَأْسِ كُلِّ مِائَةِ سَنَةٍ مَنْ يُجَدِّدُ لَهَا دِينَهَاقَالَ أَبُو دَاوُد رَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ الْإِسْكَنْدَرَانِيُّ لَمْ يَجُزْ بِهِ شَرَاحِيلَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Sa'id bin Abu Ayyub] dari [Syarahil bin Yazid Al Mu'arifi] dari [Abu Alqamah] dari [Abu Hurairah] yang aku tahu hadits itu dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap seratus tahun Allah mengutus kepada umat ini seseorang yang akan memperbaharui agama ini (dari penyimpangan).\" Abu Dawud berkata, \"'Abdurrahman bin Syuraih Al Iskandarani meriwayatkan hadits ini, namun tidak menyebutkan Syarahil.\""},"3625":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَ مَالَ مَكْحُولٌ وَابْنُ أَبِي زَكَرِيَّا إِلَى خَالِدِ بْنِ مَعْدَانَ وَمِلْتُ مَعَهُمْ فَحَدَّثَنَا عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ الْهُدْنَةِ قَالَقَالَ جُبَيْرٌ انْطَلِقْ بِنَا إِلَى ذِي مِخْبَرٍ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْنَاهُ فَسَأَلَهُ جُبَيْرٌ عَنْ الْهُدْنَةِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُصَالِحُونَ الرُّومَ صُلْحًا آمِنًا فَتَغْزُونَ أَنْتُمْ وَهُمْ عَدُوًّا مِنْ وَرَائِكُمْ فَتُنْصَرُونَ وَتَغْنَمُونَ وَتَسْلَمُونَ ثُمَّ تَرْجِعُونَ حَتَّى تَنْزِلُوا بِمَرْجٍ ذِي تُلُولٍ فَيَرْفَعُ رَجُلٌ مِنْ أَهْلِ النَّصْرَانِيَّةِ الصَّلِيبَ فَيَقُولُ غَلَبَ الصَّلِيبُ فَيَغْضَبُ رَجُلٌ مِنْ الْمُسْلِمِينَ فَيَدُقُّهُ فَعِنْدَ ذَلِكَ تَغْدِرُ الرُّومُ وَتَجْمَعُ لِلْمَلْحَمَةِحَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو ��َمْرٍو عَنْ حَسَّانَ بْنِ عَطِيَّةَ بِهَذَا الْحَدِيثِ وَزَادَ فِيهِ وَيَثُورُ الْمُسْلِمُونَ إِلَى أَسْلِحَتِهِمْ فَيَقْتَتِلُونَ فَيُكْرِمُ اللَّهُ تِلْكَ الْعِصَابَةَ بِالشَّهَادَةِ إِلَّا أَنَّ الْوَلِيدَ جَعَلَ الْحَدِيثَ عَنْ جُبَيْرٍ عَنْ ذِي مِخْبَرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد وَرَوَاهُ رَوْحٌ وَيَحْيَى بْنُ حَمْزَةَ وَبِشْرُ بْنُ بَكْرٍ عَنْ الْأَوْزَاعِيِّ كَمَا قَالَ عِيسَى","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin Athiyah] ia berkata; Makhul dan Ibnu Abu Zakariya menemui [Khalid bin Ma'dan], sementara aku juga ikut mereka. Lalu Khalid menceritakan kepada kami dari [Jubair bin Nufair] tentang Hudnah (perjanjian damai). Hassan berkata, \"Selanjutnya [Jubair] berkata, \"Mari bersama kami menemui [Dzu Mikhbar], seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam. Akhirnya kami pun mendatangi laki-laki tersebut, Jubair lantas bertanya kepadanya tentang perjanjian damai. Sahabat Nabi itu menjawab, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian akan mengadakan perjanjian dengan bangsa Ramawi, namun kalian akan memerangi mereka dan mereka menjadi musuh di belakang kalian. Kalian akan mendapatkan kemenangan dan ghanimah, dan keselamatan. Setelah itu kalian akan kembali pulang, saat kalian singgah di suatu tempat tinggi yang subur dan banyak tanamannya, ada seorang laki-laki nashrani mengangkat salib seraya berkata, \"Salib telah menang!\" hal itu menjadikan seorang laki-laki dari kaum muslimin marah hingga mematahkan kayu salibnya. Maka saat itulah orang-orang Ramawi berkhianat dan berkumpul untuk mengadakan peperangan.\" Telah menceritakan kepada kami [Muammal Ibnul Fadhl Al harrani] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Abu Amru] dari [Hassan bin Athiyyah] dengan hadits yang sama. Namun ia menambahkan, \"Kaum muslimin lalu segera meraih senjata mereka dan berperang. Allah kemudian memuliakan mereka dengan syahid.\" Hanya saja Al Walid menyebutkan hadits ini melalui jalur Jubair, dari [Dzu Mikhbar], dari Nabi shallallahu 'alaihi wasallam. Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Rauh], [Yahya bin Hamzah] dan [Bisyr bin Bakr], dari [Al Auza'I] sebagaimana yang dikatakan oleh Isa.\""},"3626":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ مَالِكِ بْنِ يَخَامِرَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَانُ بَيْتِ الْمَقْدِسِ خَرَابُ يَثْرِبَ وَخَرَابُ يَثْرِبَ خُرُوجُ الْمَلْحَمَةِ وَخُرُوجُ الْمَلْحَمَةِ فَتْحُ قُسْطَنْطِينِيَّةَ وَفَتْحُ الْقُسْطَنْطِينِيَّةِ خُرُوجُ الدَّجَّالِ ثُمَّ ضَرَبَ بِيَدِهِ عَلَى فَخِذِ الَّذِي حَدَّثَهُ أَوْ مَنْكِبِهِ ثُمَّ قَالَ إِنَّ هَذَا لَحَقٌّ كَمَا أَنَّكَ هَاهُنَا أَوْ كَمَا أَنَّكَ قَاعِدٌ يَعْنِي مُعَاذَ بْنَ جَبَلٍ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari] berkata, telah menceritakan kepada kami [Hasyim Ibnul Qasim] berkata, telah menceritakan kepada kami ['Abdurrahman bin Tsabit bin Tsauban] dari [Bapaknya] dari [Makhul] dari [Jubair bin Nufair] dari [Malik bin Yukhamir] dari [Mu'adz bin Jabal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ramainya Baitul Maqdis adalah tanda kehancuran kota Madinah, hancurnya kota Madinah adalah tanda terjadinya peperangan besar, terjadinya peperangan besar adalah tanda dari pembukaan kota Konstantinopel, dan pembukaan kota Konstantinopel adalah tanda keluarnya Dajjal.\" Kemudian beliau menepuk-nepuk paha orang yang beliau ceritakan tentang hadits tersebut, atau dalam riwayat lain, 'pundaknya'. Kemudian bersabda: \"Semua ini adalah sesuatu yang benar, sebagaimana engkau -Mu'adz bin Jabal- sekarang berada di sini adalah sesuatu yang benar.\""},"3627":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ الْوَلِيدِ بْنِ سُفْيَانَ الْغَسَّانِيِّ عَنْ يَزِيدَ بْنِ قُتَيْبٍ السَّكُونِيِّ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَلْحَمَةُ الْكُبْرَى وَفَتْحُ الْقُسْطَنْطِينِيَّةِ وَخُرُوجُ الدَّجَّالِ فِي سَبْعَةِ أَشْهُرٍ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufail] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Abu Bakr bin Abu Maryam] dari [Al Walid bin Sufyan Al Ghassani] dari [Yazid bin Qutaib As Sakuni] dari [Abu Bahriyah] dari [Mu'adz bin Jabal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Peperangan besar, pembukaan Konstantinopel dan keluarnya Dajjal terjadi selama tujuh bulan.\""},"3628":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ عَنْ ابْنِ أَبِي بِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ الْمَلْحَمَةِ وَفَتْحِ الْمَدِينَةِ سِتُّ سِنِينَ وَيَخْرُجُ الْمَسِيحُ الدَّجَّالُ فِي السَّابِعَةِقَالَ أَبُو دَاوُد هَذَا أَصَحُّ مِنْ حَدِيثِ عِيسَى","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [bahir] dari [Khalid] dari [Ibnu Abu Bilal] dari [Abdullah bin Busr] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara peperangan dan pembukaan kota Konstantinopel jaraknya enam tahun, lalu Al Masih Ad Dajjal keluar pada awal tahun ke tujuh.\" Abu Dawud berkata, \"Ini lebih shahih ketimbang hadits Isa.\""},"3629":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي أَبُو عَبْدِ السَّلَامِ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْأُمَمُ أَنْ تَدَاعَى عَلَيْكُمْ كَمَا تَدَاعَى الْأَكَلَةُ إِلَى قَصْعَتِهَا فَقَالَ قَائِلٌ وَمِنْ قِلَّةٍ نَحْنُ يَوْمَئِذٍ قَالَ بَلْ أَنْتُمْ يَوْمَئِذٍ كَثِيرٌ وَلَكِنَّكُمْ غُثَاءٌ كَغُثَاءِ السَّيْلِ وَلَيَنْزَعَنَّ اللَّهُ مِنْ صُدُورِ عَدُوِّكُمْ الْمَهَابَةَ مِنْكُمْ وَلَيَقْذِفَنَّ اللَّهُ فِي قُلُوبِكُمْ الْوَهْنَ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ وَمَا الْوَهْنُ قَالَ حُبُّ الدُّنْيَا وَكَرَاهِيَةُ الْمَوْتِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim bin Ad Dimasyqi] berkata, telah menceritakan kepada kami [Bisyr bin Bakr] berkata, telah menceritakan kepada kami [Ibnu Jabir] berkata, telah menceritakan kepadaku [Abu Abdus Salam] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir-hampir bangsa-bangsa memperebutkan kalian (umat Islam), layaknya memperebutkan makanan yang berada di mangkuk.\" Seorang laki-laki berkata, \"Apakah kami waktu itu berjumlah sedikit?\" beliau menjawab: \"Bahkan jumlah kalian pada waktu itu sangat banyak, namun kalian seperti buih di genangan air. Sungguh Allah akan mencabut rasa takut kepada kalian, dan akan menanamkan ke dalam hati kalian Al wahn.\" Seseorang lalu berkata, \"Wahai Rasulullah, apa itu Al wahn?\" beliau menjawab: \"Cinta dunia dan takut mati.\""},"3630":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي زَيْدُ بْنُ أَرْطَاةَ قَالَ سَمِعْتُ جُبَيْرَ بْنَ نُفَيْرٍ يُحَدِّثُ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فُسْطَاطَ الْمُسْلِمِينَ يَوْمَ الْمَلْحَمَةِ بِالْغُوطَةِ إِلَى جَانِبِ مَدِينَةٍ يُقَالُ لَهَا دِمَشْقُ مِنْ خَيْرِ مَدَائِنِ الشَّامِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepada kami [Ibnu Jabir] berkata, telah menceritakan kepadaku [Zaid bin Arthah] ia berkata; Aku mendengar [Jubair bin Nufair] menceritakan dari [Abu Darda] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat terjadinya peperangan yang besar, pangkalan kaum muslimin berada di daerah Ghuthah, sebuah wilayah di pinggiran kota yang dikenal dengan nama Damaskus, salah satu kota terbaik di negeri Syam.\""},"3631":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا إِسْمَعِيلُ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا سُلَيْمَانُ بْنُ سُلَيْمٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ قَالَ هَارُونُ فِي حَدِيثِهِ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يَجْمَعَ اللَّهُ عَلَى هَذِهِ الْأُمَّةِ سَيْفَيْنِ سَيْفًا مِنْهَا وَسَيْفًا مِنْ عَدُوِّهَا","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] berkata, telah menceritakan kepada kami [Isma'il]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Al Hasan bin Sawwar] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Sulaiman bin Sulaim] dari [Yahya bin Jabir Ath Tha`i] berkata; Harun dalam haditsnya menyebutkan dari [Auf bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekali-kali Allah tidak akan mengumpulkan dua pedang pada umat ini; satu pedang dari mereka dan satu pedang lagi dari musuh mereka.\""},"3632":{"ar":"حَدَّثَنَا عِيسَى بْنُ مُحَمَّدٍ الرَّمْلِيُّ حَدَّثَنَا ضَمْرَةُ عَنْ السَّيْبَانِيِّ عَنْ أَبِي سُكَيْنَةَ رَجُلٌ مِنْ الْمُحَرَّرِينَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ دَعُوا الْحَبَشَةَ مَا وَدَعُوكُمْ وَاتْرُكُوا التُّرْكَ مَا تَرَكُوكُمْ","id":"Telah menceritakan kepada kami [Isa bin Muhammad Ar Ramli] berkata, telah menceritakan kepada kami [Dhamrah] dari [As Saibani] dari [Abu Sukainah] seorang lelaki dari Al Muhararaini, dari [seorang laki-laki] di antara sahabat Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Biarkanlah orang-orang Habasyah sebagaimana mereka membiarkan kalian, dan tinggalkanlah orang-orang Turki sebagaimana mereka meninggalkan kalian.\""},"3633":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ يَعْنِي الْإِسْكَنْدَرَانِيَّ عَنْ سُهَيْلٍ يَعْنِي ابْنَ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يُقَاتِلَ الْمُسْلِمُونَ التُّرْكَ قَوْمًا وُجُوهُهُمْ كَالْمَجَانِّ الْمُطْرَقَةِ يَلْبَسُونَ الشَّعْرَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ya'qub] -maksudnya Ya'qub Al Iskandarani- dari [Suhail] -maksudnya Suhail bin Abu Shalih- dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kiamat tidak akan terjadi hingga kaum muslimin memerangi bangsa Turki, wajah mereka seperti perisai dan mengenakan sandal dari rambut.\""},"3634":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَابْنُ السَّرْحِ وَغَيْرُهُمَا قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَرِوَايَةً قَالَ ابْنُ السَّرْحِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا صِغَارَ الْأَعْيُنِ ذُلْفَ الْآنُفِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Ibnu As Sarh] dan selain keduanya, mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] secara riwayat. Ibnu Suraih berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari kiamat hingga kalian memerangi kaum yang mengenakan sandal dari rambut, dan tidak akan terjadai hari kiamat hingga kalian memerangi suatu kaum yang matanya sipit, hidung pesek dan wajah mereka seperti tameng untuk perang.\""},"3635":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ التِّنِّيسِيُّ حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا بَشِيرُ بْنُ الْمُهَاجِرِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَدِيثِ يُقَاتِلُكُمْ قَوْمٌ صِغَارُ الْأَعْيُنِ يَعْنِي التُّرْكَ قَالَ تَسُوقُونَهُمْ ثَلَاثَ مِرَارٍ حَتَّى تُلْحِقُوهُمْ بِجَزِيرَةِ الْعَرَبِ فَأَمَّا فِي السِّيَاقَةِ الْأُولَى فَيَنْجُو مَنْ هَرَبَ مِنْهُمْ وَأَمَّا فِي الثَّانِيَةِ فَيَنْجُو بَعْضٌ وَيَهْلَكُ بَعْضٌ وَأَمَّا فِي الثَّالِثَةِ فَيُصْطَلَمُونَ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir At Tinnisi] berkata, telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Basyir Ibnul Muhajir] berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam berkenaan dengan hadits Nabi, 'Akan memerangi kalian suatu kaum yang mata mereka sipit -yakni bangsa Turki-', beliau bersabda: \"Kalian akan menguasai mereka sebanyak tiga kali, sehingga kalian dapat menyusul mereka hingga jazirah arab. Pada kemenangan pertama orang-orang yang lari dari mereka selamat, pada kemenangan kedua sebagian dari mereka selamat dan sebagian yang lain binasa, dan pada kemenangan ketiga mereka menyerah total. ' Atau sebagaimana yang beliau sabdakan.\""},"3636":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي أَبِي حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ حَدَّثَنَا مُسْلِمُ بْنُ أَبِي بَكْرَةَ قَالَ سَمِعْتُ أَبِي يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ نَاسٌ مِنْ أُمَّتِي بِغَائِطٍ يُسَمُّونَهُ الْبَصْرَةَ عِنْدَ نَهْرٍ يُقَالُ لَهُ دِجْلَةُ يَكُونُ عَلَيْهِ جِسْرٌ يَكْثُرُ أَهْلُهَا وَتَكُونُ مِنْ أَمْصَارِ الْمُهَاجِرِينَ قَالَ ابْنُ يَحْيَى قَالَ أَبُو مَعْمَرٍ وَتَكُونُ مِنْ أَمْصَارِ الْمُسْلِمِينَ فَإِذَا كَانَ فِي آخِرِ الزَّمَانِ جَاءَ بَنُو قَنْطُورَاءَ عِرَاضُ الْوُجُوهِ صِغَارُ الْأَعْيُنِ حَتَّى يَنْزِلُوا عَلَى شَطِّ النَّهْرِ فَيَتَفَرَّقُ أَهْلُهَا ثَلَاثَ فِرَقٍ فِرْقَةٌ يَأْخُذُونَ أَذْنَابَ الْبَقَرِ وَالْبَرِّيَّةِ وَهَلَكُوا وَفِرْقَةٌ يَأْخُذُونَ لِأَنْفُسِهِمْ وَكَفَرُوا وَفِرْقَةٌ يَجْعَلُونَ ذَرَارِيَّهُمْ خَلْفَ ظُهُورِهِمْ وَيُقَاتِلُونَهُمْ وَهُمْ الشُّهَدَاءُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Abdu Ash Shamad bin Abdul Warits] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Sa'id bin Jumhan] berkata, telah menceritakan kepada kami [Muslim bin Abu Bakrah] ia berkata; Aku mendengar [Bapakku] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beberapa orang dari umatku singgah di suatu tempat yang luas, mereka menamakannya Bashrah. Yakni di sisi sungai yang bernama Dijlah, sungai itu mempunyai jembatan. Tempat itu penduduknya sangat banyak, dan mayoritas berasal dari orang-orang yang hijrah. Ibnu Ishaq berkata, \"Abu Ma'mar menyebutkan, 'Penduduk tempat itu berasal dari penjuru kaum muslimin'. Di akhir zaman nanti akan datang suatu kaum yang bernama Qanthura, wajah mereka lebar dan matanya sipit, hingga kaum itu sampai ke daerah tepian sungai lalu para penduduknya pecah menjadi tiga kelompok; satu kelompok pergi mengikuti ekor sapi dan binatang ternak (pergi ke tempat yang jauh dengan membawa binatang ternak mereka untuk bercocok tanam) hingga mereka hancur. Satu kelompok mengambil untuk keamanan mereka (mengajukan atau menerima jaminan keamanan dari bani Qanthura) hingga akhirnya menjadi kafir. Dan satu kelompok melindungi anak dan istri mereka dan berperang melawan musuh (Bani Qanthura) hingga mereka mati sebagai syuhada.\""},"3637":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ حَدَّثَنَا مُوسَى الْحَنَّاطُ لَا أَعْلَمُهُ إِلَّا ذَكَرَهُ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا أَنَسُ إِنَّ النَّاسَ يُمَصِّرُونَ أَمْصَارًا وَإِنَّ مِصْرًا مِنْهَا يُقَالُ لَهُ الْبَصْرَةُ أَوْ الْبُصَيْرَةُ فَإِنْ أَنْتَ مَرَرْتَ بِهَا أَوْ دَخَلْتَهَا فَإِيَّاكَ وَسِبَاخَهَا وَكِلَاءَهَا وَسُوقَهَا وَبَابَ أُمَرَائِهَا وَعَلَيْكَ بِضَوَاحِيهَا فَإِنَّهُ يَكُونُ بِهَا خَسْفٌ وَقَذْفٌ وَرَجْفٌ وَقَوْمٌ يَبِيتُونَ يُصْبِحُونَ قِرَدَةً وَخَنَازِيرَ","id":"Telah menceritakan kepada kami [Abdullah bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abdu Ash Shamad] berkata, telah menceritakan kepada kami [Musa Al Hannath] -aku tidak mengetahuinya kecuali ia menyebutkannya- dari [Musa bin Anas] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadanya: \"Wahai Anas, sesungguhnya manusia akan menempati banyak tempat, dan salah satu tempat itu bernama Bashrah, atau Bushairah. Jika kamu melewati tempat itu, atau masuk ke dalamnya, maka hindarilah tempat-tempat yang tanahnya asin (lapang karena sidikit pohon), dan tempat penambatan kapal (dermaga), serta pasar-pasar dan para penguasanya. Pergilah ke tempat-tempat pelosok (daerah pegunungan), karena wilayah wilayah tersebut banyak terjadi penenggelaman (ke dasar bumi), angin topan dan gempa bumi. Di sana kalian juga akan menemui suatu kaum, mereka bermalam dan pagi harinya telah menjadi kera dan babi.\""},"3638":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي إِبْرَاهِيمُ بْنُ صَالِحِ بْنِ دِرْهَمٍ قَالَ سَمِعْتُ أَبِي يَقُولُانْطَلَقْنَا حَاجِّينَ فَإِذَا رَجُلٌ فَقَالَ لَنَا إِلَى جَنْبِكُمْ قَرْيَةٌ يُقَالُ لَهَا الْأُبُلَّةُ قُلْنَا نَعَمْ قَالَ مَنْ يَضْمَنُ لِي مِنْكُمْ أَنْ يُصَلِّيَ لِي فِي مَسْجِدِ الْعَشَّارِ رَكْعَتَيْنِ أَوْ أَرْبَعًا وَيَقُولَ هَذِهِ لِأَبِي هُرَيْرَةَ سَمِعْتُ خَلِيلِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَبْعَثُ مِنْ مَسْجِدِ الْعَشَّارِ يَوْمَ الْقِيَامَةِ شُهَدَاءَ لَا يَقُومُ مَعَ شُهَدَاءِ بَدْرٍ غَيْرُهُمْقَالَ أَبُو دَاوُد هَذَا الْمَسْجِدُ مِمَّا يَلِي النَّهْرَ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepadaku [Ibrahim bin Shalih bin Dirham] ia berkata; Aku mendengar [Bapakku] berkata, \"Kami berangkat untuk menunaikan haji, lalu ada seorang laki-laki (Abu Hurairah) berkata, \"Di sisi kalian ada sebuah kampung bernama Ubullah, \" kami menjawab, \"Benar.\" Laki-laki itu berkata lagi, \"Siapakah di antara kalian bersedia memberi jaminan padaku, bahwa ia mau shalat untukku di masjid Al Asysyar sebanyak dua atau empat rakaat, setelah itu mengatakan '(pahala shalat ini untuk [Abu Hurairah]? Aku pernah mendengar kekasihku Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat Allah akan membangkitkan para syuhada dari masjid Al Asysyar, tidak ada yang bangkit (berdiri) bersama para syuhada perang badar selain mereka.\" Abu Dawud berkata, \"Masjid ini ada di sisi sungai.\""},"3639":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ أَحْمَدَ الْبَغْدَادِيُّ حَدَّثَنَا أَبُو عَامِرٍ عَنْ زُهَيْرِ بْنِ مُحَمَّدٍ عَنْ مُوسَى بْنِ جُبَيْرٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حَنِيفٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اتْرُكُوا الْحَبَشَةَ مَا تَرَكُوكُمْ فَإِنَّهُ لَا يَسْتَخْرِجُ كَنْزَ الْكَعْبَةِ إِلَّا ذُو السُّوَيْقَتَيْنِ مِنْ الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Al Qasim bin Ahmad Al Baghdadi] berkata, telah menceritakan kepada kami [Abu Amir] dari [Zuhair bin Muhammad] dari [Musa bin Jubair] dari [Abu Umamah bin Sahl bin Hanif] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Biarkanlah orang-orang Habasyah sebagaimana mereka membiarkan kalian, sebab tidaklah harta simpanan ka'bah itu dikeluarkan kecuali oleh Dzu As Suwaiqataini (seorang yang berjuluk pemilik dua betis) dari negeri Habasyah.\""},"3640":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ أَبِي زُرْعَةَ قَالَجَاءَ نَفَرٌ إِلَى مَرْوَانَ بِالْمَدِينَةِ فَسَمِعُوهُ يُحَدِّثُ فِي الْآيَاتِ أَنَّ أَوَّلَهَا الدَّجَّالُ قَالَ فَانْصَرَفْتُ إِلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو فَحَدَّثْتُهُ فَقَالَ عَبْدُ اللَّهِ لَمْ يَقُلْ شَيْئًا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ الْآيَاتِ خُرُوجًا طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا أَوْ الدَّابَّةُ عَلَى النَّاسِ ضُحًى فَأَيَّتُهُمَا كَانَتْ قَبْلَ صَاحِبَتِهَا فَالْأُخْرَى عَلَى أَثَرِهَا قَالَ عَبْدُ اللَّهِ وَكَانَ يَقْرَأُ الْكُتُبَ وَأَظُنُّ أَوَّلَهُمَا خُرُوجًا طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا","id":"Telah menceritakan kepada kami [Muammal bin Hisyam] berkata, telah menceritakan kepada kami [Isma'il] dari [Abu Hayyan At taimi] dari [Abu Zur'ah] ia berkata, \"Beberapa orang datang menemui Marwan di Madinah, mereka mendengar Marwan menceritakan tentang tanda-tanda datangnya hari kiamat. Bahwa pertama kali yang akan muncul adalah Dajjal.\" Abu Zur'ah berkata, \"Aku lantas menemui Abdullah bin Amru dan aku ceritakan hal itu kepadanya. [Abdullah] lalu berkata, \"Perkataan Marwan tidak dianggap, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda hari kiamat pertama yang akan muncul adalah terbitnya matahari dari arah barat, atau keluarnya binatang melata kepada manusia di waktu dhuha. Mana pun dari keduanya muncul pertama kali, maka yang lain akan segera menyusul.\" Abdullah berkata -sambil membaca buku-, \"Aku kira yang pertama kali akan muncul adalah terbitnya matahari dari arah terbenamnya.\""},"3641":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَهَنَّادٌ الْمَعْنَى قَالَ مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا فُرَاتٌ الْقَزَّازُ عَنْ عَامِرِ بْنِ وَاثِلَةَ وَقَالَ هَنَّادٌ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّ قَالَكُنَّا قُعُودًا نَتَحَدَّثُ فِي ظِلِّ غُرْفَةٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا السَّاعَةَ فَارْتَفَعَتْ أَصْوَاتُنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ تَكُونَ أَوْ لَنْ تَقُومَ السَّاعَةُ حَتَّى يَكُونَ قَبْلَهَا عَشْرُ آيَاتٍ طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَخُرُوجُ الدَّابَّةِ وَخُرُوجُ يَأْجُوجَ وَمَأْجُوجَ وَالدَّجَّالُ وَعِيسَى ابْنُ مَرْيَمَ وَالدُّخَانُ وَثَلَاثَةُ خُسُوفٍ خَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَآخِرُ ذَلِكَ تَخْرُجُ نَارٌ مِنْ الْيَمَنِ مِنْ قَعْرِ عَدَنٍ تَسُوقُ النَّاسَ إِلَى الْمَحْشَرِ","id":"Telah menceritakan kepada kami [Musaddad] dan [Hannad] secara makna, [Musaddad] berkata; telah menceritakan kepada kami [Abu Al Ahwash] berkata, telah menceritakan kepada kami [Furat Al Qazzaz] dari [Amir bin Watsilah]. Dan [Hannad] berkata dari [Abu Thufail] dari [Hudzaifah bin Asid Al Ghifari] ia berkata, \"Kami duduk bersama di sisi kamar Rasulullah shallallahu 'alaihi wasallam sambil membicarakan seputar hari kiamat, suara kami sangat keras hingga Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi, atau tidak akan datang hari kiamat hingga muncul sepuluh tanda; terbitnya matahari dari barat, munculnya binatang melata, keluarnya Ya'juj dan Ma'juj, Dajjal, Isa putera Maryam, asap dan tiga gempa bumi (longsor), longsor di barat, timur dan di Jazirah Arab. Dan tanda terakhir adalah keluarnya api dari Yaman, dari dasar tanah Adn yang akan menggiring manusia menuju mahsyar.\""},"3642":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ وَرَآهَا النَّاسُ آمَنَ مَنْ عَلَيْهَا فَذَاكَ حِينَ{ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا }الْآيَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani] berkata, telah menceritakan kepada kami [Muhammad Fudhail] dari [Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan tegak hari kiamat hingga matahari terbit dari arah terbenamnya, jika manusia melihat hal itu maka mereka akan beriman semuanya. Dan waktu itu adalah saat 'Tidak bermanfaat lagi iman seseorang bagi dirinya sendiri yang belum beriman sebelum itu, atau dia (belum) mengusahakan kebaikan dalam masa imannya) '-Al An'am 158-.\""},"3643":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنِي عُقْبَةُ بْنُ خَالِدٍ السَّكُونِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ كَنْزٍ مِنْ ذَهَبٍ فَمَنْ حَضَرَهُ فَلَا يَأْخُذْ مِنْهُ شَيْئًاحَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنِي عُقْبَةُ يَعْنِي ابْنَ خَالِدٍ حَدَّثَنِي عُبَيْدُ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ يَحْسِرُ عَنْ جَبَلٍ مِنْ ذَهَبٍ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] berkata, telah menceritakan kepadaku [Uqbah bin Khalid As Sakuni] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Khubaib bin 'Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"begitu dekat (hari kiamat) yaitu ketika sungai Furat menyibak harta kekayaan berupa emas yang terkandung di dalamnya, barangsiapa yang datang kepadanya maka janganlah ia mengambil sesuatu pun darinya.\" Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] berkata, telah menceritakan kepadaku [Uqbah] -maksudnya Uqbah bin Khalid- berkata, telah menceritakan kepadaku [Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits tersebut, hanya saja beliau mengatakan: \"menyibak gunung emas.\""},"3644":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَمْرٍو حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ قَالَاجْتَمَعَ حُذَيْفَةُ وَأَبُو مَسْعُودٍ فَقَالَ حُذَيْفَةُ لَأَنَا بِمَا مَعَ الدَّجَّالِ أَعْلَمُ مِنْهُ إِنَّ مَعَهُ بَحْرًا مِنْ مَاءٍ وَنَهْرًا مِنْ نَارٍ فَالَّذِي تَرَوْنَ أَنَّهُ نَارٌ مَاءٌ وَالَّذِي تَرَوْنَ أَنَّهُ مَاءٌ نَارٌ فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَأَرَادَ الْمَاءَ فَلْيَشْرَبْ مِنْ الَّذِي يَرَى أَنَّهُ نَارٌ فَإِنَّهُ سَيَجِدُهُ مَاءًقَالَ أَبُو مَسْعُودٍ الْبَدْرِيُّ هَكَذَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","id":"Telah menceritakan kepada kami [Al Hasan bin Amru] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Rib'I bin Hirasy] ia berkata; [Hudzaifah] dan [Abu Mas'ud] berkumpul, lalu Hudzaifah berkata, \"Aku adalah orang yang paling tahu tentang (kapan munculnya) dajjal. Sesungguhnya dajjal mempunyai lautan dari air dan sungai dari api. Apa yang kalian lihat sebagai api sebenarnya adalah air, dan apa yang kalian lihat sebagai air sebenarnya adalah api. Maka, siapa dari kalian yang mendapati hal itu dan ingin minum, hendaklah ia minum (air) yang berupa api dalam pandangannya, sebab ia akan mendapatkan air yang sesungguhnya.\" Abu Mas'ud Al Badri berkata, \"Demikianlah aku mendengar Rasulullah shallallahu 'alaihi wasallam mengatakannya.\""},"3645":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا بُعِثَ نَبِيٌّ إِلَّا قَدْ أَنْذَرَ أُمَّتَهُ الدَّجَّالَ الْأَعْوَرَ الْكَذَّابَ أَلَا وَإِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ وَإِنَّ بَيْنَ عَيْنَيْهِ مَكْتُوبًا كَافِرٌحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ شُعْبَةَ ك ف ر حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْحَدِيثِ قَالَ يَقْرَؤُهُ كُلُّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata; Aku mendengar [Anas bin Malik] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tiada seorang Nabi yang diutus kecuali ia telah menjelaskan kepada umatnya tentang dajjal, si buta sebelah dan pendusta. Ketahuilah, bahwa ia benar-benar buta sebelah, dan Rabb kalian tidak buta sebelah. Antara kedua matanya tertulis 'kafir'.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dari [Muhammad bin Ja'far] dari [Syu'bah] berkata, \"Bertuliskan Kaf-Fa'-Ra.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits] dari [Syu'aib Ibnul Habhab] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits, beliau mengatakan: \"Setiap muslim akan dapat membacanya.\""},"3646":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا جَرِيرٌ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ أَبِي الدَّهْمَاءِ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ يُحَدِّثُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَمِعَ بِالدَّجَّالِ فَلْيَنْأَ عَنْهُ فَوَاللَّهِ إِنَّ الرَّجُلَ لَيَأْتِيهِ وَهُوَ يَحْسِبُ أَنَّهُ مُؤْمِنٌ فَيَتَّبِعُهُ مِمَّا يَبْعَثُ بِهِ مِنْ الشُّبُهَاتِ أَوْ لِمَا يَبْعَثُ بِهِ مِنْ الشُّبُهَاتِ هَكَذَا قَالَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Jarir] berkata, telah menceritakan kepada kami [Humaid bin Hilal] dari [Abu Ad Dahma] ia berkata; aku mendengar [Imran bin Hushain] menceritakan, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mendengar (kedatangan) Dajjal hendaklah menjauhinya. Demi Allah, seorang laki-laki benar-benar akan mendatangi Dajjal dan mengira bahwa ia adalah seorang mukmin, lalu ia akan mengikuti setiap subhat yang ditebarkannya.\" Demikian beliau mengatakannya. "},"3647":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرٌ عَنْ خَالِدِ بْنِ مَ��ْدَانَ عَنْ عَمْرِو بْنِ الْأَسْوَدِ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّهُ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي قَدْ حَدَّثْتُكُمْ عَنْ الدَّجَّالِ حَتَّى خَشِيتُ أَنْ لَا تَعْقِلُوا إِنَّ مَسِيحَ الدَّجَّالِ رَجُلٌ قَصِيرٌ أَفْحَجُ جَعْدٌ أَعْوَرُ مَطْمُوسُ الْعَيْنِ لَيْسَ بِنَاتِئَةٍ وَلَا حَجْرَاءَ فَإِنْ أُلْبِسَ عَلَيْكُمْ فَاعْلَمُوا أَنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَقَالَ أَبُو دَاوُد عَمْرُو بْنُ الْأَسْوَدِ وَلِي الْقَضَاءَ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepadaku [Bahir] dari [Khalid bin Ma'dan] dari [Amru Ibnul Aswad] dari [Junadah bin Abu Umayyah] dari [Ubadah bin Ash Shamit] bahwa ia menceritakan kepada mereka, Bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku telah menceritakan perihal Dajjal kepada kalian, hingga aku kawatir kalian tidak lagi mampu memahaminya. Sesungguhnya Al Masih Dajjal adalah seorang laki-laki yang pendek, berkaki bengkok, berambut keriting, buta sebelah dan matanya tidak terlalu menonjol dan tidak pula terlalu tenggelam. Jika kalian merasa bingung, maka ketahuilah bahwa Rabb kalian tidak bermata juling.\" Abu Dawud berkata, \"Amru Ibnul Aswad adalah seorang hakim.\""},"3648":{"ar":"حَدَّثَنَا صَفْوَانُ بْنُ صَالِحٍ الدِّمَشْقِيُّ الْمُؤَذِّنُ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي يَحْيَى بْنُ جَابِرٍ الطَّائِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ النَّوَّاسِ بْنِ سَمْعَانَ الْكِلَابِيِّ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالَ فَقَالَ إِنْ يَخْرُجْ وَأَنَا فِيكُمْ فَأَنَا حَجِيجُهُ دُونَكُمْ وَإِنْ يَخْرُجْ وَلَسْتُ فِيكُمْ فَامْرُؤٌ حَجِيجُ نَفْسِهِ وَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ فَمَنْ أَدْرَكَهُ مِنْكُمْ فَلْيَقْرَأْ عَلَيْهِ فَوَاتِحَ سُورَةِ الْكَهْفِ فَإِنَّهَا جِوَارُكُمْ مِنْ فِتْنَتِهِ قُلْنَا وَمَا لَبْثُهُ فِي الْأَرْضِ قَالَ أَرْبَعُونَ يَوْمًا يَوْمٌ كَسَنَةٍ وَيَوْمٌ كَشَهْرٍ وَيَوْمٌ كَجُمُعَةٍ وَسَائِرُ أَيَّامِهِ كَأَيَّامِكُمْ فَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا الْيَوْمُ الَّذِي كَسَنَةٍ أَتَكْفِينَا فِيهِ صَلَاةُ يَوْمٍ وَلَيْلَةٍ قَالَ لَا اقْدُرُوا لَهُ قَدْرَهُ ثُمَّ يَنْزِلُ عِيسَى ابْنُ مَرْيَمَ عِنْدَ الْمَنَارَةِ الْبَيْضَاءِ شَرْقِيَّ دِمَشْقَ فَيُدْرِكُهُ عِنْدَ بَابِ لُدٍّ فَيَقْتُلُهُحَدَّثَنَا عِيسَى بْنُ مُحَمَّدٍ حَدَّثَنَا ضَمْرَةُ عَنْ السَّيْبَانِيِّ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَذَكَرَ الصَّلَوَاتِ مِثْلَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Shafwan bin Shalih Ad Dimasyqi Al Mu'adzdzin] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Ibnu Jabir] berkata, telah menceritakan kepadaku [Yahya bin Jabir Ath Tha`i] dari ['Abdurrahman bin Jubair bin Nufair] dari [Bapaknya] dari [An Nawwas bin Sam'an Al Kilabi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang Dajjal, beliau bersabda: \"Jika saat Dajjal keluar aku masih bersama kalian maka akulah yang akan melindungi kalian darinya. Namun jika ia keluar dan aku tidak lagi bersama kalian, maka setiap orang harus melindungi dirinya sendiri. Allah adalah pelindung bagiku dan setiap muslim. Barangsiapa dari kalian berjumpa dengannya, hendaklah ia bacakan awal surat Al Kahfi, sebab itu akan melindungi kalian dari fitnahnya.\" Kami lalu bertanya, \"Berapa lama ia akan tinggal di bumi?\" beliau menjawab: \"Empat puluh hari. Satu hari seakan setahun, dan sehari seakan sebulan, dan sehari seakan sepekan dan hari-harinya dia sama sebagaimana hari-hari kalian.\" Kami bertanya lagi, \"Wahai Rasulullah, pada hari yang seakan satu tahun, apakah shalat kami akan mencukupi untuk waktu sehari semalam?\" beliau menjawab: \"Tidak, namun sesuaikanlah (setiap waktu shalat). Kemudian Isa putera Maryam akan turun di sisi menara putih, sebelah timur kota Damaskus. Lalu ia menemukan Dajjal di pintu Lud (sebuah tempat di dekat Baitul Maqdis), lantas ia pun membunuhnya.\" Telah menceritakan kepada kami [Isa bin Muhammad] berkata, telah menceritakan kepada kami [Dhamrah] dari [Asy Syaibani] dari [Amru bin Abdullah] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, sebagaimana dalam hadits tersebut. Lalu beliau menyebutkan beberapa shalat seperti makna dalam hadits tersebut.\""},"3649":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ حَدِيثِ أَبِي الدَّرْدَاءِ يَرْوِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَفِظَ عَشْرَ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْكَهْفِ عُصِمَ مِنْ فِتْنَةِ الدَّجَّالِقَالَ أَبُو دَاوُد وَكَذَا قَالَ هِشَامٌ الدَّسْتُوَائِيُّ عَنْ قَتَادَةَ إِلَّا أَنَّهُ قَالَ مَنْ حَفِظَ مِنْ خَوَاتِيمِ سُورَةِ الْكَهْفِ و قَالَ شُعْبَةُ عَنْ قَتَادَةَ مِنْ آخِرِ الْكَهْفِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari hadits [Abu Darda] yang ia riwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menghafal sepuluh ayat awal dari surat Al Kahfi, maka ia akan dijaga dari fitnah Dajjal.\" Abu Dawud berkata, \"Seperti ini pula yang dikatakan oleh [Hisyam Ad Dustuwa`i] dari [Qatadah], hanya saja (dalam hadits itu) Rasulullah bersabda: \"Barangsiapa menghafal akhir-akhir dari surat Al kahfi, \" [Syu'bah] menyebutkan dari [Qatadah], \"Akhir dari surat Al Kahfi.\""},"3650":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ آدَمَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ بَيْنِي وَبَيْنَهُ نَبِيٌّ يَعْنِي عِيسَى وَإِنَّهُ نَازِلٌ فَإِذَا رَأَيْتُمُوهُ فَاعْرِفُوهُ رَجُلٌ مَرْبُوعٌ إِلَى الْحُمْرَةِ وَالْبَيَاضِ بَيْنَ مُمَصَّرَتَيْنِ كَأَنَّ رَأْسَهُ يَقْطُرُ وَإِنْ لَمْ يُصِبْهُ بَلَلٌ فَيُقَاتِلُ النَّاسَ عَلَى الْإِسْلَامِ فَيَدُقُّ الصَّلِيبَ وَيَقْتُلُ الْخِنْزِيرَ وَيَضَعُ الْجِزْيَةَ وَيُهْلِكُ اللَّهُ فِي زَمَانِهِ الْمِلَلَ كُلَّهَا إِلَّا الْإِسْلَامَ وَيُهْلِكُ الْمَسِيحَ الدَّجَّالَ فَيَمْكُثُ فِي الْأَرْضِ أَرْبَعِينَ سَنَةً ثُمَّ يُتَوَفَّى فَيُصَلِّي عَلَيْهِ الْمُسْلِمُونَ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] berkata, telah menceritakan kepada kami [Hammam bin Yahya] dari [Qatadah] dari ['Abdurrahman bin Adam] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada Nabi antara aku dan dia -maksudnya Isa-. Sungguh, kelak ia akan turun, jika kalian melihatnya maka kenalilah. Ia adalah seorang laki-laki yang sedang (tidak tinggi ataupun pendek), berkulit merah keputih-putihan, mengenakan kain berwarna kekuningan. Seakan rambut kepala menetes meski tidak basah. Ia akan memerangi manusia hingga mereka masuk ke dalam Islam, ia memecahkan salib, membunuh babi dan membebaskan jizyah (pajak). Pada masanya Allah akan membinasakan semua agama selain Islam, Isa akan membunuh Dajjal, dan akan tinggal di dunia selama empat puluh tahun. Setelah itu ia meninggal dan kaum muslimin menshalatinya.\""},"3651":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَّرَ الْعِشَاءَ الْآخِرَةَ ذَاتَ لَيْلَةٍ ثُمَّ خَرَجَ فَقَالَ إِنَّهُ حَبَسَنِي حَدِيثٌ كَانَ يُحَدِّثُنِيهِ تَمِيمٌ الدَّارِيُّ عَنْ رَجُلٍ كَانَ فِي جَزِيرَةٍ مِنْ جَزَائِرِ الْبَحْرِ فَإِذَا أَنَا بِامْرَأَةٍ تَجُرُّ شَعْرَهَا قَالَ مَا أَنْتِ قَالَتْ أَنَا الْجَسَّاسَةُ اذْهَبْ إِلَى ذَلِكَ الْقَصْرِ فَأَتَيْتُهُ فَإِذَا رَجُلٌ يَجُرُّ شَعْرَهُ مُسَلْسَلٌ فِي الْأَغْلَالِ يَنْزُو فِيمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ فَقُلْتُ مَنْ أَنْتَ قَالَ أَنَا الدَّجَّالُ خَرَجَ نَبِيُّ الْأُمِّيِّينَ بَعْدُ قُلْتُ نَعَمْ قَالَ أَطَاعُوهُ أَمْ عَصَوْهُ قُلْتُ بَلْ أَطَاعُوهُ قَالَ ذَاكَ خَيْرٌ لَهُمْحَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ حُسَيْنًا الْمُعَلِّمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ حَدَّثَنَا عَامِرُ بْنُ شَرَاحِيلَ الشَّعْبِيُّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ سَمِعْتُ مُنَادِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَادِي أَنْ الصَّلَاةُ جَامِعَةٌ فَخَرَجْتُ فَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ جَلَسَ عَلَى الْمِنْبَرِ وَهُوَ يَضْحَكُ قَالَ لِيَلْزَمْ كُلُّ إِنْسَانٍ مُصَلَّاهُ ثُمَّ قَالَ هَلْ تَدْرُونَ لِمَ جَمَعْتُكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ إِنِّي مَا جَمَعْتُكُمْ لِرَهْبَةٍ وَلَا رَغْبَةٍ وَلَكِنْ جَمَعْتُكُمْ أَنَّ تَمِيمًا الدَّارِيَّ كَانَ رَجُلًا نَصْرَانِيًّا فَجَاءَ فَبَايَعَ وَأَسْلَمَ وَحَدَّثَنِي حَدِيثًا وَافَقَ الَّذِي حَدَّثْتُكُمْ عَنْ الدَّجَّالِ حَدَّثَنِي أَنَّهُ رَكِبَ فِي سَفِينَةٍ بَحْرِيَّةٍ مَعَ ثَلَاثِينَ رَجُلًا مِنْ لَخْمٍ وَجُذَامٍ فَلَعِبَ بِهِمْ الْمَوْجُ شَهْرًا فِي الْبَحْرِ وَأَرْفَئُوا إِلَى جَزِيرَةٍ حِينَ مَغْرِبِ الشَّمْسِ فَجَلَسُوا فِي أَقْرُبْ السَّفِينَةِ فَدَخَلُوا الْجَزِيرَةَ فَلَقِيَتْهُمْ دَابَّةٌ أَهْلَبُ كَثِيرَةُ الشَّعْرِ قَالُوا وَيْلَكِ مَا أَنْتِ قَالَتْ أَنَا الْجَسَّاسَةُ انْطَلِقُوا إِلَى هَذَا الرَّجُلِ فِي هَذَا الدَّيْرَ فَإِنَّهُ إِلَى خَبَرِكُمْ بِالْأَشْوَاقِ قَالَ لَمَّا سَمَّتْ لَنَا رَجُلًا فَرِقْنَا مِنْهَا أَنْ تَكُونَ شَيْطَانَةً فَانْطَلَقْنَا سِرَاعًا حَتَّى دَخَلْنَا الدَّيْرَ فَإِذَا فِيهِ أَعْظَمُ إِنْسَانٍ رَأَيْنَاهُ قَطُّ خَلْقًا وَأَشَدُّهُ وَثَاقًا مَجْمُوعَةٌ يَدَاهُ إِلَى عُنُقِهِ فَذَكَرَ الْحَدِيثَ وَسَأَلَهُمْ عَنْ نَخْلِ بَيْسَانَ وَعَنْ عَيْنِ زُغَرَ وَعَنْ النَّبِيِّ الْأُمِّيِّ قَالَ إِنِّي أَنَا الْمَسِيحُ وَإِنَّهُ يُوشَكُ أَنْ يُؤْذَنَ لِي فِي الْخُرُوجِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّهُ فِي بَحْرِ الشَّامِ أَوْ بَحْرِ الْيَمَنِ لَا بَلْ مِنْ قِبَلِ الْمَشْرِقِ مَا هُوَ مَرَّتَيْنِ وَأَوْمَأَ بِيَدِهِ قِبَلَ الْمَشْرِقِ قَالَتْ حَفِظْتُ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ حَدَّثَنَا مُحَمَّدُ بْنُ صُدْرَانَ حَدَّثَنَا الْمُعْتَمِرُ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ مُجَالِدِ بْنِ سَعِيدٍ عَنْ عَامِرٍ قَالَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ ثُمَّ صَعِدَ الْمِنْبَرَ وَكَانَ لَا يَصْعَدُ عَلَيْهِ إِلَّا يَوْمَ جُمُعَةٍ قَبْلَ يَوْمَئِذٍ ثُمَّ ذَكَرَ هَذِهِ الْقِصَّةَ قَالَ أَبُو دَاوُد وَابْنُ صُدْرَانَ بَصْرِيٌّ غَرِقَ فِي الْبَحْرِ مَعَ ابْنِ مِسْو��رٍ لَمْ يَسْلَمْ مِنْهُمْ غَيْرُهُ حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى أَخْبَرَنَا ابْنُ فُضَيْلٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ بْنِ جُمَيْعٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ عَلَى الْمِنْبَرِ إِنَّهُ بَيْنَمَا أُنَاسٌ يَسِيرُونَ فِي الْبَحْرِ فَنَفِدَ طَعَامُهُمْ فَرُفِعَتْ لَهُمْ جَزِيرَةٌ فَخَرَجُوا يُرِيدُونَ الْخُبْزَ فَلَقِيَتْهُمْ الْجَسَّاسَةُ قُلْتُ لِأَبِي سَلَمَةَ وَمَا الْجَسَّاسَةُ قَالَ امْرَأَةٌ تَجُرُّ شَعْرَ جِلْدِهَا وَرَأْسِهَا قَالَتْ فِي هَذَا الْقَصْرِ فَذَكَرَ الْحَدِيثَ وَسَأَلَ عَنْ نَخْلِ بَيْسَانَ وَعَنْ عَيْنِ زُغَرَ قَالَ هُوَ الْمَسِيحُ فَقَالَ لِي ابْنُ أَبِي سَلَمَةَ إِنَّ فِي هَذَا الْحَدِيثِ شَيْئًا مَا حَفِظْتُهُ قَالَ شَهِدَ جَابِرٌ أَنَّهُ هُوَ ابْنُ صَيَّادٍ قُلْتُ فَإِنَّهُ قَدْ مَاتَ قَالَ وَإِنْ مَاتَ قُلْتُ فَإِنَّهُ أَسْلَمَ قَالَ وَإِنْ أَسْلَمَ قُلْتُ فَإِنَّهُ قَدْ دَخَلَ الْمَدِينَةَ قَالَ وَإِنْ دَخَلَ الْمَدِينَةَ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Utsman bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Abu Salamah] dari [Fatimah binti Qais] berkata, \"Pada suatu malam pernah Rasulullah shallallahu 'alaihi wasallam mengakhirkan shalat isya` yang akhir, lalu beliau keluar dan bersabda: \"Sesungguhnya yang menghalangiku (untuk segera keluar) adalah kisah yang diceritakan Tamim Ad Dari kepadaku dari seorang laki-laki yang berada di sebuah pulau dari gugusan pulau-pulau. Tamim berkata, \"Saat itu tiba-tiba ada seorang wanita yang berambut panjang.\" Tamim selanjutnya bertanya, \"Siapa kamu?\" Ia menjawab, \"Aku adalah Jasasah. Pergilah kamu ke istana itu.\" Tamim berkata, \"Aku pun mendatanginya, ternyata di sana ada seorang laki-laki berambut panjang yang terikat dengan sebuah rantai. Tingginya menjulang antara langit dan bumi. Aku lalu bertanya, \"Siapa kamu?\" Ia menjawab, \"Aku adalah Dajjal. Apakah telah ada seorang Nabi buta huruf yang diutus?\" Aku menjawab, \"Ya.\" Ia kembali bertanya, \"Apakah orang-orang mentaatinya atau mengingkarinya?\" Aku menjawab, \"Orang-orang mentaatinya.\" Ia berkata, \"Itu yang lebih baik bagi mereka.\" Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] berkata, telah menceritakan kepada kami [Abdu Ash Shamad] berkata, telah menceritakan kepada kami [Bapakku] ia berkata; Aku mendengar [Husain Al Mu'allim] berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] berkata, telah menceritakan kepada kami [Amir bin Syurahil Asy Sya'bi] dari [Fatimah binti Qais] ia berkata; Aku mendengar tukang adzan Rasulullah shallallahu 'alaihi wasallam menyeru 'Ash Shalatu Jami'ah (shalatlah berjamaah) ', maka aku keluar dan ikut shalat berjamaah bersama Rasulullah shallallahu 'alaihi wasallam. Ketika Rasulullah shallallahu 'alaihi wasallam selesai dari shalatnya, beliau duduk sambil tertawa, beliau bersabda: \"Hendaklah setiap orang tetap di tempat shalatnya (duduk).\" Kemudian beliau melanjutkan sabdanya: \"Apakah kalian tahu, kenapa aku kumpulkan kalian di sini?\" Para sahabat, \"Allah dan Rasul-Nya lebih tahu.\" Beliau bersabda: \"Aku kumpulkan kalian bukan atas sesuatu yang membuat takut atau senang, namun aku kumpulkan kalian adalah karena Tamim Ad Dari, seorang lelaki Nashrani yang datang dan berbaiat masuk Islam, ia menceritakan kepadaku sebuah kisah yang mirip dengan cerita yang pernah aku ceritakan kepada kalian tentang Dajjal. Ia ceritakan kepadaku bahwasanya ia pernah menaiki sebuah perahu bersama tiga puluh laki-laki dari kaum Lakhm dan Judzam, mereka kemudian diombang-ambingkan oleh ombak selama satu bulan di tengah laut, sampai akhirnya mereka menepi ke sebuah pulau saat matahari terbenam. Mereka lantas duduk di sisi kapal mereka, setelah itu mereka bergegas memasuki pulau tersebut hingga akhirnya bertemu dengan binatang melata besar dan berbulu lebat. Mereka berkata, \"Celaka engkau, siapa kamu ini!\" binatang itu menjawab, \"Aku adalah Jasasah. Temuilah laki-laki yang ada dalam sebuah gua, karena ia sangat berkeinginan untuk mendengar berita dari kalian.\" Tamim berkata, \"Saat ia menyebut laki-laki, maka kami ketakutan jikalau dia adalah setan lalu kami cepat pergi hingga memasuki gua tersebut. Dan ternyata di dalamnya terdapat manusia yang paling besar yang pernah kami lihat, talinya sangat kuat, dan tangannya menyatu dengan leher (terikat dengan rantai).\" Lalu perawi menyebutkan hadits tersebut dengan lengkap. Manusia besar (Dajjal) itu bertanya kepada mereka tentang Nakhl Baisan (nama tempat dekat Yordania), mata air Zughar (nama tempat di Syam) dan seorang Nabi yang buta huruf. Manusia besar itu berkata, \"Aku adalah Al Masih Dajjal, dan hampir-hampir aku mendapat izin untuk segera keluar.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Sesunggunya ia (Dajjal) berada di laut Syam, atau laut Yaman. Bahkan ia akan muncul dari arah timur tempat ia berasal -beliau ucapkan hingga dua kali seraya menunjuk ke arah timur-. Fatimah berkata, \"Aku hafal perkataan ini dari Rasulullah shallallahu 'alaihi wasallam, lalu ia menyebutkan hadits selengkapnya.\" Telah menceritakan kepada kami [Muhammad bin Shadran] berkata, telah menceritakan kepada kami [Al Mu'tamir] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Mujalid bin Sa'id] dari [Amir] ia berkata; [Fatimah bin Qais] menceritakan kepadaku bahwa pernah Nabi shallallahu 'alaihi wasallam shalat zhuhur kemudian naik ke atas mimbar, padahal sebelum hari itu beliau tidak penah naik ke atas mimbar tersebut kecuali di hari jum'at. Kemudian beliau menyebutkan kisah ini.\" Abu Dawud berkata, \"Ibnu Shadran adalah orang Bashrah, ia pernah tenggelam di lautan bersama Ibnu Miswar, dan tidak ada yang selamat dari mereka selain dia.\" Telah menceritakan kepada kami [Washil bin Abdul A'la] berkata, telah mengabarkan kepada kami [Ibnu Fudhail] dari [Al Walid bin Abdullah bin Jumai'] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir] ia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Ketika ada beberapa orang berlayar di lautan, makanan mereka hilang (habis), lalu tampaklah oleh mereka sebuah pulau. Mereka pun menuju pulau tersebut untuk mencari roti, namun mereka dihadang oleh Jasasah.\" Aku (Walid bin Abdullah) lantas bertanya kepada Abu Salamah, \"apa itu Jassasah?\" Ia menjawab, \"Seorang wanita yang rambutnya menutupi kulit dan kepalanya. Wanita itu berkata, \"Dalam istana ini.\" Lalu ia menceritakan haditsnya, dan ia bertanya tentang Nakhl Baisan dan mata air Zughar, ia menjawab; \"Dia adalah Al Masih\", maka Abu Salamah berkata kepadaku; Dalam hadits ini ada beberapa lafadz yang tidak aku hafal. Abu Salamah berkata, \"Jabir bersaksi bahwa laki-laki itu adalah Ibnu Shayyad.\" Aku berkata, \"Tapi Ibnu Shayyad telah mati!\" Jabir menjawab, \"Meskipun ia telah mati.\" Aku bertanya lagi, \"Ia juga telah masuk Islam.\" Jabir berkata, \"Meskipun ia telah masuk Islam.\" Aku bertanya, \"Ia juga telah masuk ke kota Madinah.\" Jabir menjawab, \"Meskipun ia telah masuk kota Madinah.\""},"3652":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِابْنِ صَائِدٍ فِي نَفَرٍ مِنْ أَصْحَابِهِ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَهُوَ يَلْعَبُ مَعَ الْغِلْمَانِ عِنْدَ أُطُمِ بَنِي مَغَالَةَ وَهُوَ غُلَامٌ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَهْرَهُ بِيَدِهِ ثُمَّ قَالَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ قَالَ فَنَظَرَ إِلَيْهِ ابْنُ صَيَّادٍ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ ثُمَّ قَالَ ابْنُ صَيَّادٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمَنْتُ بِاللَّهِ وَرُسُلِهِ ثُمَّ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَأْتِيكَ قَالَ يَأْتِينِي صَادِقٌ وَكَاذِبٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِطَ عَلَيْكَ الْأَمْرُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ خَبَّأْتُ لَكَ خَبِيئَةً وَخَبَّأَ لَهُ{ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }قَالَ ابْنُ صَيَّادٍ هُوَ الدُّخُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ ائْذَنْ لِي فَأَضْرِبَ عُنُقَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْ فَلَنْ تُسَلَّطَ عَلَيْهِ يَعْنِي الدَّجَّالَ وَإِلَّا يَكُنْ هُوَ فَلَا خَيْرَ فِي قَتْلِهِ","id":"Telah menceritakan kepada kami [Abu Ashim Khusyaisy bin Ashram] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam bersama beberapa orang sahabatnya, termasuk di dalamnya adalah Umar Ibnul Khaththab, melewati Ibnu Shaid ketika sedang bermain-main dengan beberapa anak kecil di sebuah bangunan tinggi milik bani Maghalah. Dan Ibnu Shaid waktu itu juga masih seorang bocah. Ia tidak sadar dengan kedatangan Rasulullah shallallahu 'alaihi wasallam hingga beliau menepuk pundaknya dengan tangan, beliau lantas bertanya: \"Apakah kamu bersaksi bahwa aku adalah utusan Allah?\" Ibnu Shaid memperhatikan beliau, lalu ia menjawab, \"Aku bersaksi bahwa engkau adalah utusan Allah yang buta aksara. Setelah itu Ibnu Shaid berkata kepada Nabi shallallahu 'alaihi wasallam, \"Apakah kamu juga bersaksi bahwa aku adalah utusan Allah?\" Nabi shallallahu 'alaihi wasallam balik berkata, \"Aku beriman kepada Allah dan para rasul-Nya.\" Nabi shallallahu 'alaihi wasallam kemudian bertanya kepadanya: \"(Berita ghaib) apa yang kamu bawa?\" Ibnu Shaid menjawab, \"Telah datang kepadaku berita (ghaib) yang benar dan berita bohong.\" Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Perkaramu membingungkan (bercampur antara kebenaran dengan kedustaan).\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Sesungguhnya aku telah menyembunyikan sesuatu darimu, \" beliau menyembunyikan darinya: '(Maka tunggulah ketika langit membawa kabut yang nyata) '. Ibnu Shaid berkata, \"Yang dimaksud itu adalah awan.\" Rasulullah shallallahu 'alaihi wasallam lantas berkata kepadanya: \"His! Sekali-kali engkau tidak akan dapat mendahului takdirmu.\" Kemudian Umar berkata, \"Wahai Rasulullah, izinkanlah aku memenggal lehernya!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika memang ia Dajjal, maka engkau tidak diberi kuasa untuk membunuhnya. Namun jika bukan dia, maka tidak ada manfaat membunuhnya.\""},"3653":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ قَالَكَانَ ابْنُ عُمَرَ يَقُولُ وَاللَّهِ مَا أَشُكُّ أَنَّ الْمَسِيحَ الدَّجَّالَ ابْنُ صَيَّادٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Ya'qub] -maksudnya Ya'qub bin 'Abdurrahman- dari [Musa bin Uqbah] dari [Nafi'] ia berkata, \" [Ibnu Umar] berkata, \"Demi Allah, aku tidak ragu bahwa Al Masih Dajjal adalah Ibnu Shayyad.\""},"3654":{"ar":"حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَرَأَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَحْلِفُ بِاللَّهِ أَنَّ ابْنَ صَائِدٍ الدَّجَّالُ فَقُلْتُ تَحْلِفُ بِاللَّهِ فَقَالَ إِنِّي سَمِعْتُ عُمَرَ يَحْلِفُ عَلَى ذَلِكَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُنْكِرْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Mu'adz] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Muhammad bin Al Munkadir] ia berkata, \"Aku melihat [Jabir bin Abdullah] bersumpah dengan nama Allah bahwa Ibnu Shaid adalah Dajjal.\" Aku lalu berkata, \"Engkau benar-benar bersumpah kepada Allah!\" Ia lalu menjawab, \"Aku mendengar Umar bersumpah dengan hal yang sama di hadapan Rasulullah shallallahu 'alaihi wasallam dan beliau tidak mengingkarinya.\""},"3655":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ جَابِرٍ قَالَفَقَدْنَا ابْنَ صَيَّادٍ يَوْمَ الْحَرَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Musa- berkata, telah menceritakan kepada kami [Syaiban] dari [Al A'masy] dari [Salim] dari [Jabir] ia berkata, \"Kami kehilangan Ibnu Shayyad pada hari Al harrah.\""},"3656":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَخْرُجَ ثَلَاثُونَ دَجَّالُونَ كُلُّهُمْ يَزْعُمُ أَنَّهُ رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Abdul Aziz] -maksudnya Abdul Aziz bin Muhammad- dari [Al 'Ala`] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan datang hari kiamat hingga muncul tiga puluh Dajjal, mereka semua mengaku sebagai utusan Allah.\""},"3657":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَخْرُجَ ثَلَاثُونَ كَذَّابًا دَجَّالًا كُلُّهُمْ يَكْذِبُ عَلَى اللَّهِ وَعَلَى رَسُولِهِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ جَرِيرٍ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عُبَيْدَةُ السَّلْمَانِيُّ بِهَذَا الْخَبَرِ قَالَ فَذَكَرَ نَحْوَهُ فَقُلْتُ لَهُ أَتَرَى هَذَا مِنْهُمْ يَعْنِي الْمُخْتَارَ فَقَالَ عُبَيْدَةُ أَمَا إِنَّهُ مِنْ الرُّءُوسِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Muhammad] -maksudnya Muhammad bin Amru- dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan datang hari kiamat hingga muncul tiga puluh Dajjal pendusta, mereka semua berdusta kepada Allah dan Rasul-Nya.\" Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] dari [Jarir] dari [Mughirah] dari [Ibrahim] ia berkata; [Ubaidah As Sulami] menyebutkan dengan hadits ini. ia berkata, \"Lalu ia menyebutkan sebagaimana hadits tersebut.\" Aku (Ibrahim) lalu berkata kepada Ubaidah, \"Apakah engkau mengira bahwa orang ini -Al Mukhtar- berasal dari mereka (para dajjal pendusta)?\" Ubaidah menjawab, \"(Bahkan) Ia dari pembesarnya.\""},"3658":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا يُونُسُ بْنُ رَاشِدٍ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ مَا دَخَلَ النَّقْصُ عَلَى بَنِي إِسْرَائِيلَ كَانَ الرَّجُلُ يَلْقَى الرَّجُلَ فَيَقُولُ يَا هَذَا اتَّقِ اللَّهَ وَدَعْ مَا تَصْنَعُ فَإِنَّهُ لَا يَحِلُّ لَكَ ثُمَّ يَلْقَاهُ مِنْ الْغَدِ فَلَا يَمْنَعُهُ ذَلِكَ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَقَعِيدَهُ فَلَمَّا فَعَلُوا ذَلِكَ ضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ ثُمَّ قَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ إِلَى قَوْلِهِ فَاسِقُونَ }ثُمَّ قَالَ كَلَّا وَاللَّهِ لَتَأْمُرُنَّ بِالْمَعْرُوفِ وَلَتَنْهَوُنَّ عَنْ الْمُنْكَرِ وَلَتَأْخُذُنَّ عَلَى يَدَيْ الظَّالِمِ وَلَتَأْطُرُنَّهُ عَلَى الْحَقِّ أَطْرًا وَلَتَقْصُرُنَّهُ عَلَى الْحَقِّ قَصْرًاحَدَّثَنَا خَلَفُ بْنُ هِشَامٍ حَدَّثَنَا أَبُو شِهَابٍ الْحَنَّاطُ عَنْ الْعَلَاءِ بْنِ الْمُسَيِّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمٍ عَنْ أَبِي عُبَيْدَةَ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ زَادَ أَوْ لَيَضْرِبَنَّ اللَّهُ بِقُلُوبِ بَعْضِكُمْ عَلَى بَعْضٍ ثُمَّ لَيَلْعَنَنَّكُمْ كَمَا لَعَنَهُمْ قَالَ أَبُو دَاوُد رَوَاهُ الْمُحَارِبِيُّ عَنْ الْعَلَاءِ بْنِ الْمُسَيِّبِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمٍ الْأَفْطَسِ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ وَرَوَاهُ خَالِدٌ الطَّحَّانُ عَنْ الْعَلَاءِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] berkata, telah menceritakan kepada kami [Yunus bin Rasyid] dari [Ali bin Badzimah] dari [Abu Ubaidah] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kemaksiatan pertama kali yang terjadi pada bani Isra'il adalah ketika seorang laki-laki berjumpa seorang laki-laki lain, ia berkata, \"Wahai saudaraku, bertakwalah kepada Allah, tinggalkan apa yang telah engkau lakukan, karena itu tidak halal untuk kamu lakukan.\" Kemudian keesokan harinya ia berjumpa lagi dengannya, namun perbuatan maksiat yang ia larang (kepada temannya) tidak mencegah dirinya untuk menjadikannya sebagai teman makan dan minum serta duduknya (yakni ikut bersama dalam kemaksiatan), maka ketika mereka melakukan hal itu, Allah menghitamkan hati sebagian mereka karena sebab sebagian yang lain. Kemudian beliau membaca: (Telah dila'nati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam) hingga firmannya: (orang-orang yang fasik) '. Kemudian beliau bersabda; \"Demi Allah hendaklah kalian benar-benar memerintahkan kebaikan, mencegah kemungkaran dan mencabutnya dari tangan orang zhalim lalu mengambalikannya (membelokkannya) kepada kebenaran serta konsisten terhadap kebenaran itu.\", telah menceritakan kepada kami [Khalaf bin Hisyam] telah menceritakan kepada kami [Abu Syihab Al Hannath] dari [Al 'Ala` bin Al Musayyib] dari [Amru bin Murrah] dari [Salim] dari [Abu Ubaidah] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut, dengan tambahan redaksi; \"atau (jika tidak) Allah benar-benar akan menutup hati kalian karena (tutupnya) sebagian yang lain, kemudian melaknat kalian sebagaimana telah melaknat mereka (orang-orang bani Israil).\", Abu Daud berkata; [Al Muharibi] telah meriwayatkan hadits ini dari [Al 'Ala` bin Al Musayyib] dari [Abdullah bin Amru bin Murrah] dari [Salim Al Afthas] dari [Abu Ubaidah] dari [Abdullah], dan [Khalid] meriwayatkan hadits ini dari [Al 'Ala`] dari [Amru bin Murrah] dari [Abu Ubaidah].\""},"3659":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ ح و حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ الْمَعْنَى عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ قَالَ قَالَ أَبُو بَكْرٍبَعْدَ أَنْ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ وَتَضَعُونَهَا عَلَى غَيْرِ مَوَاضِعِهَا{ عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }قَالَ عَنْ خَالِدٍ وَإِنَّا سَمِعْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الظَّالِمَ فَلَمْ يَأْخُذُوا عَلَى يَدَيْهِ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابٍ و قَالَ عَمْرٌو عَنْ هُشَيْمٍ وَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ قَوْمٍ يُعْمَلُ فِيهِمْ بِالْمَعَاصِي ثُمَّ يَقْدِرُونَ عَلَى أَنْ يُغَيِّرُوا ثُمَّ لَا يُغَيِّرُوا إِلَّا يُوشِكُ أَنْ يَعُمَّهُمْ اللَّهُ مِنْهُ بِعِقَابٍقَالَ أَبُو دَاوُد وَرَوَاهُ كَمَا قَالَ خَالِدٌ أَبُو أُسَامَةَ وَجَمَاعَةٌ وَقَالَ شُعْبَةُ فِيهِ مَا مِنْ قَوْمٍ يُعْمَلُ فِيهِمْ بِالْمَعَاصِي هُمْ أَكْثَرُ مِمَّنْ يَعْمَلُهُ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Aun] berkata, telah mengabarkan kepada kami [Husyaim] secara makna, dari [Isma'il] dari [Qais] ia berkata, \"Setelah mengucapkan pujian dan mengagungkan-Nya, [Abu Bakar] berkata, \"Wahai manusia sekalian, kalian telah membaca ayat ini, namun kalian tidak meletakkannya sebagaimana mestinya: '(.. jagalah dirimu; tidaklah orang yang sesat itu akan memberi madharat kepadamu apabila kamu telah mendapatkan petunjuk..) ' -Al Maidah: 105-. Wahb menyebutkan dari [Khalid], (Abu Bakar berkata;) \"Kami mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang melihat kezhaliman kemudian tidak mencegah dengan tangannya, maka sangat dikawatirkan Allah akan menimpakan siksa kepada mereka secara merata.\" [Amru] menyebutkan dari [Husyaim], \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah kemaksiatan yang dilakukan pada suatu kaum, kemudian mereka mampu mencegahnya tetapi tidak mau mencegah, melainkan Allah akan meratakan siksa kepada mereka.\" Abu Dawud berkata; \" [Abu Usamah] dan sekelompok orang juga meriwayatkannya sebagaimana yang dikatakan oleh Khalid\". sedangkan Syu'bah meriwayatkan dengan lafadz di dalamnya, \"Tidaklah suatu kemaksiatan dilakukan pada suatu kaum, sementara jumlah mereka lebih banyak dari orang-orang yang melakukannya (kemaksiatan), ….).\""},"3660":{"ar":"حَدَّثَنَا مُسَّدَدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَبُو إِسْحَقَ أَظُنُّهُ عَنْ ابْنِ جَرِيرٍ عَنْ جَرِيرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يَكُونُ فِي قَوْمٍ يُعْمَلُ فِيهِمْ بِالْمَعَاصِي يَقْدِرُونَ عَلَى أَنْ يُغَيِّرُوا عَلَيْهِ فَلَا يُغَيِّرُوا إِلَّا أَصَابَهُمْ اللَّهُ بِعَذَابٍ مِنْ قَبْلِ أَنْ يَمُوتُوا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Al Ahwash] berkata, telah menceritakan kepada kami [Abu Ishaq] aku mengira bahwa itu berasal dari [Ibnu Jarir] dari [Jarir] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berada pada sebuah kaum yang di dalamnya dilakukan suatu kemaksiatan, mereka mampu mengubah kemaksiatan tersebut lalu tidak melakukannya, maka Allah akan menimpakan siksa kepada mereka sebelum mereka meninggal.\""},"3661":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ وَعَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مُنْكَرًا فَاسْتَطَاعَ أَنْ يُغَيِّرَهُ بِيَدِهِ فَلْيُغَيِّرْهُ بِيَدِهِ وَقَطَعَ هَنَّادٌ بَقِيَّةَ الْحَدِيثِ وَفَّاهُ ابْنُ الْعَلَاءِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ بِلِسَانِهِ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] dan [Hannad bin As Sari] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Isma'il bin Raja] dari [Bapaknya] dari [Abu Sa'id] dan dari [Qais bin Muslim] dari [Thariq bin Syihab] dari [Abu Sa'id Al Khudri] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dari kalian melihat kemungkaran lalu ia mampu mengubahnya dengan tangan, hendaklah ia ubah kemungkaran tersebut dengan tangannya.\" Hannad kemudian memotong (tidak melanjutkan) sisa hadits tersebut. Kemudian [Ibnul 'Ala] melengkapinya, \"jika ia tidak mampu hendaklah dengan lisannya, jika tidak mampu dengan lisan hendaklah dengan hatinya, dan itu adalah selemah-lemah iman.\""},"3662":{"ar":"حَدَّثَنَا أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عُتْبَةَ بْنِ أَبِي حَكِيمٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ جَارِيَةَ اللَّخْمِيُّ حَدَّثَنِي أَبُو أُمَيَّةَ الشَّعْبَانِيُّ قَالَسَأَلْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ فَقُلْتُ يَا أَبَا ثَعْلَبَةَ كَيْفَ تَقُولُ فِي هَذِهِ الْآيَةِ{ عَلَيْكُمْ أَنْفُسَكُمْ }قَالَ أَمَا وَاللَّهِ لَقَدْ سَأَلْتَ عَنْهَا خَبِيرًا سَأَلْتُ عَنْهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَلْ ائْتَمِرُوا بِالْمَعْرُوفِ وَتَنَاهَوْا عَنْ الْمُنْكَرِ حَتَّى إِذَا رَأَيْتَ شُحًّا مُطَاعًا وَهَوًى مُتَّبَعًا وَدُنْيَا مُؤْثَرَةً وَإِعْجَابَ كُلِّ ذِي رَأْيٍ بِرَأْيِهِ فَعَلَيْكَ يَعْنِي بِنَفْسِكَ وَدَعْ عَنْكَ الْعَوَامَّ فَإِنَّ مِنْ وَرَائِكُمْ أَيَّامَ الصَّبْرِ الصَّبْرُ فِيهِ مِثْلُ قَبْضٍ عَلَى الْجَمْرِ لِلْعَامِلِ فِيهِمْ مِثْلُ أَجْرِ خَمْسِينَ رَجُلًا يَعْمَلُونَ مِثْلَ عَمَلِهِوَزَادَنِي غَيْرُهُ قَالَ يَا رَسُولَ اللَّهِ أَجْرُ خَمْسِينَ مِنْهُمْ قَالَ أَجْرُ خَمْسِينَ مِنْكُمْ","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Sulaiman bin Dawud Al 'Ataki] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari [Utbah bin Abu Hakim] ia berkata; telah menceritakan kepadaku [Amru bin Jariyah Al Lakhmi] berkata, telah menceritakan kepadaku [Abu Umayyah Asy Sya'bani] ia berkata, \"Aku pernah bertanya kepada [Abu Tsa'labah Al Khusyani], aku katakan kepadanya, \"Wahai Abu Tsa'labah, apa pendapatmu tentang ayat ini: '(.. jagalah dirimu..) -Al Maidah: 105-?\" Ia menjawab, \"Demi Allah, engkau telah menanyakan hal itu kepada orang yang tepat. Aku pernah menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu menjawab: \"Bahkan perintahkanlah kepada perkara yang ma'ruf dan cegahlah dari perkara yang munkar, sehingga ketika engkau melihat sifat kikir ditaati, hawa nafsu diikuti, dunia lebih diutamakan (dari urusan agama), dan setiap orang bangga dengan pendapatnya sendiri, maka hendaklah engkau jaga dirimu sendiri, dan jauhilah orang-orang awam (bodoh). Sebab di belakang kalian ada hari-hari (yang kalian wajib) bersabar, sabar pada saat itu seperti seseorang yang memegang bara api, dan orang yang beramal pada saat itu pahalanya sebanding dengan lima puluh kali amalan orang yang beramal seperti amalnya, ia menambahkan untukku, \"seperti amalan selainnya.\" Abu Tsa'labah bertanya, \"Wahai Rasulullah, seperti pahala lima puluh orang dari mereka!\" beliau menjawab: \"(Bahkan) seperti pahala lima puluh orang dari kalian.\""},"3663":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ أَنَّ عَبْدَ الْعَزِيزِ بْنَ أَبِي حَازِمٍ حَدَّثَهُمْ عَنْ أَبِيهِ عَنْ عُمَارَةَ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَيْفَ بِكُمْ وَبِزَمَانٍ أَوْ يُوشِكُ أَنْ يَأْتِيَ زَمَانٌ يُغَرْبَلُ النَّاسُ فِيهِ غَرْبَلَةً تَبْقَى حُثَالَةٌ مِنْ النَّاسِ قَدْ مَرِجَتْ عُهُودُهُمْ وَأَمَانَاتُهُمْ وَاخْتَلَفُوا فَكَانُوا هَكَذَا وَشَبَّكَ بَيْنَ أَصَابِعِهِ فَقَالُوا وَكَيْفَ بِنَا يَا رَسُولَ اللَّهِ قَالَ تَأْخُذُونَ مَا تَعْرِفُونَ وَتَذَرُونَ مَا تُنْكِرُونَ وَتُقْبِلُونَ عَلَى أَمْرِ خَاصَّتِكُمْ وَتَذَرُونَ أَمْرَ عَامَّتِكُمْقَالَ أَبُو دَاوُد هَكَذَا رُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] bahwa [Abdul Aziz bin Abu Hazim] menceritakan kepada mereka, dari [Bapaknya] dari [Umarah bin Amru] dari [Abdullah bin Amru bin Al Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana kondisi kalian pada zaman, atau beliau mengatakan, \"Hampir-hampir akan datang kepada kalian suatu masa, orang-orang yang baik telah pergi dan tinggal orang-orang yang jelek. Janji-janji dan amanah mereka telah rusak, mereka berselisih, dan mereka menjadi seperti ini -beliau menganyam antara jemarinya-\". Para sahabat bertanya, \"Wahai Rasulullah, lalu bagaimana dengan kami; apa yang engkau perintahkan?\" beliau menjawab: \"Ambillah apa yang kalian ketahui (dari kebenarannya) dan jauhi apa yang kalian ingkari, terimalah apa yang menjadi hak kalian dan tinggalkan apa yang menjadi hak khalayak umum.\" Abu Dawud berkata, \"Demikianlah hadits ini diriwayatkan oleh Abdullah bin Amru dari Nabi shallallahu 'alaihi wasallam dengan banyaknya jalur periwayatan.\""},"3664":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ هِلَالِ بْنِ خَبَّابٍ أَبِي الْعَلَاءِ قَالَ حَدَّثَنِي عِكْرِمَةُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ قَالَبَيْنَمَا نَحْنُ حَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ ذَكَرَ الْفِتْنَةَ فَقَالَ إِذَا رَأَيْتُمْ النَّاسَ قَدْ مَرِجَتْ عُهُودُهُمْ وَخَفَّتْ أَمَانَاتُهُمْ وَكَانُوا هَكَذَا وَشَبَّكَ بَيْنَ أَصَابِعِهِ قَالَ فَقُمْتُ إِلَيْهِ فَقُلْتُ كَيْفَ أَفْعَلُ عِنْدَ ذَلِكَ جَعَلَنِي اللَّهُ فِدَاكَ قَالَ الْزَمْ بَيْتَكَ وَامْلِكْ عَلَيْكَ لِسَانَكَ وَخُذْ بِمَا تَعْرِفُ وَدَعْ مَا تُنْكِرُ وَعَلَيْكَ بِأَمْرِ خَاصَّةِ نَفْسِكَ وَدَعْ عَنْكَ أَمْرَ الْعَامَّةِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Al Fadhl bin Dukain] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Hilal bin Khabbab Abul 'Ala] ia berkata; telah menceritakan kepadaku [Ikrimah] berkata, telah menceritakan kepadaku [Abdullah bin Amru bin Al Ash] ia berkata, \"Saat kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, beliau menyebutkan tentang fitnah. Beliau bersabda: \"Jika kalian melihat manusia telah rusak janji-janji mereka dan telah luntur amanah mereka, sementara mereka begini -beliau menganyam antara jemarinya-, \" Abdullah berkata, \"Aku lantas bangkit ke arah beliau seraya bertanya, \"(Semoga Allah menjadikan aku sebagai tebusanmu) apa yang harus aku lakukan pada saat itu?\" beliau menjawab: \"Tetaplah engkau berdiam di dalam rumahmu, kuasailah lisanmu, ambilah (lakukan) apa saja yang kamu ketahui dan tinggalkan apa saja yang kamu pungkiri (tidak ketahui), urusilah perkaramu sendiri dan jauhilah urusan orang banyak, \""},"3665":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ هَارُونَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الْجِهَادِ كَلِمَةُ عَدْلٍ عِنْدَ سُلْطَانٍ جَائِرٍ أَوْ أَمِيرٍ جَائِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ubadah Al Wasithi] berkata, telah menceritakan kepada kami [Yazid] -makasudnya Yazid bin Harun- berkata, telah mengabarkan kepada kami [Isra'il] berkata, telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jihad yang paling utama adalah menyampaikan kebenaran kepada penguasa yang dhalim, atau pemimpin yang dhalim.\""},"3666":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو بَكْرٍ حَدَّثَنَا مُغِيرَةُ بْنُ زِيَادٍ الْمُوصِلِيُّ عَنْ عَدِيِّ بْنِ عَدِيٍّ عَنْ الْعُرْسِ ابْنِ عَمِيرَةَ الْكِنْدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا عُمِلَتْ الْخَطِيئَةُ فِي الْأَرْضِ كَانَ مَنْ شَهِدَهَا فَكَرِهَهَا وَقَالَ مَرَّةً أَنْكَرَهَا كَانَ كَمَنْ غَابَ عَنْهَا وَمَنْ غَابَ عَنْهَا فَرَضِيَهَا كَانَ كَمَنْ شَهِدَهَاحَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ مُغِيرَةَ ابْنِ زِيَادٍ عَنْ عَدِيِّ بْنِ عَدِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ مَنْ شَهِدَهَا فَكَرِهَهَا كَانَ كَمَنْ غَابَ عَنْهَا","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah mengabarkan kepada kami [Abu Bakr] berkata, telah menceritakan kepada kami [Mughirah bin Ziyad Al Mushili] dari [Adi bin Adi] dari [Al 'urs bin Amirah Al Kindi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika ada satu kemaksiatan dikerjakan dimuka bumi, maka orang yang melihat lalu membencinya, dalam riwayat lain, \"lalu ia mengingkarinya, ia seperti orang yang tidak melihatnya. Sedangkan bagi orang yang tidak melihatnya, namun ia ridha dengan kemaksiatan tersebut, maka ia seperti orang yang melihatnya.\" Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Abu Syihab] dari [Al Mughirah bin Ziyad] dari [Adi bin Adi] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits tersebut. Beliau bersabda: \"Barangsiapa melihat lalu mengingkarinya, maka ia seperti orang yang tidak melihatnya.\""},"3667":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَحَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا شُعْبَةُ وَهَذَا لَفْظُهُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ قَالَ أَخْبَرَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ و قَالَ سُلَيْمَانُ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنْ يَهْلَكَ النَّاسُ حَتَّى يَعْذِرُوا أَوْ يُعْذِرُوا مِنْ أَنْفُسِهِمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Hafsh bin Umar] keduanya berkata; telah menceritakan kepada kami [Syu'bah] -dan ini adalah lafadz darinya- dari [Amru bin Murrah] dari [Abu Al Bakhtari] ia berkata, \"Telah mengabarkan kepadaku [orang] yang telah mendengarnya dari Nabi shallallahu 'alaihi wasallam, beliau bersabda, sementara Sulaiman menyebutkan, \"Telah menceritakan kepadaku seorang laki-laki sahabat Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sekali-kali manusia tidak akan binasa hingga mereka banyak melakukan kesalahan, atau beliau mengatakan, \"hingga mereka mencari dalih dari kesalahan mereka.\""},"3668":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ وَأَبُو بَكْرِ بْنُ سُلَيْمَانَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ صَلَاةَ الْعِشَاءِ فِي آخِرِ حَيَاتِهِ فَلَمَّا سَلَّمَ قَامَ فَقَالَ أَرَأَيْتُكُمْ لَيْلَتَكُمْ هَذِهِ فَإِنَّ عَلَى رَأْسِ مِائَةِ سَنَةٍ مِنْهَا لَا يَبْقَى مِمَّنْ هُوَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ قَالَ ابْنُ عُمَرَ فَوَهِلَ النَّاسُ فِي مَقَالَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ فِيمَا يَتَحَدَّثُونَ عَنْ هَذِهِ الْأَحَادِيثِ عَنْ مِائَةِ سَنَةٍ وَإِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْقَى مِمَّنْ هُوَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ يُرِيدُ بِأَنْ يَنْخَرِمَ ذَلِكَ الْقَرْنُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] dan [Abu Bakr bin Sulaiman] bahwa [Abdullah bin Umar] berkata; Pada sutau malam Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat isya bersama kami di masa-masa akhir hidup beliau. Setelah salam beliau kemudian berdiri dan bersabda: \"Aku perhatikan malam kalian ini, sungguh dalam seratus tahun (kedepan), tidak seorang pun yang ada di muka bumi ini (dari malam tersebut) yang masih tersisa (hidup).\" Ibnu Umar berkata, \"Mendengar ucapan Rasulullah shallallahu 'alaihi wasallam, orang-orang mereka-reka berkenaan dengan makna 'seratus tahun' dari ucapan beliau tersebut. Padahal sebenarnya, Rasulullah shallallahu 'alaihi wasallam mengatakan: \"Orang-orang yang hidup hari ini, maka seratus tahun ke depan tidak akan ada lagi yang masih hidup di muka bumi.\" Maksudnya, beliau menegaskan bahwa masa itu akan terjadi.\""},"3669":{"ar":"حَدَّثَنَا مُوسَى بْنُ سَهْلٍ حَدَّثَنَا حَجَّاجُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يُعْجِزَ اللَّهُ هَذِهِ الْأُمَّةَ مِنْ نِصْفِ يَوْمٍ","id":"Telah menceritakan kepada kami [Musa bin Sahl] berkata, telah menceritakan kepada kami [Hajjaj bin Ibrahim] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepadaku [Mu'awiyah bin Shalih] dari ['Abdurrahman bin Jubair] dari [Bapaknya] dari [Abu Tsa'labah Al Khusyani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekali-kali Allah tidak akan melemahkan umat ini dari waktu setengah hari (pada hari kiamat).\""},"3670":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنِي صَفْوَانُ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَرْجُو أَنْ لَا تَعْجِزَ أُمَّتِي عِنْدَ رَبِّهَا أَنْ يُؤَخِّرَهُمْ نِصْفَ يَوْمٍقِيلَ لِسَعْدٍ وَكَمْ نِصْفُ ذَلِكَ الْيَوْمِ قَالَ خَمْسُ مِائَةِ سَنَةٍ","id":"Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepadaku [Shafwan] dari [Syuraih bin Ubaid] dari [Sa'd bin Abu Waqash] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku sangat berharap bahwa umatku tidak akan merasa lemah di sisi Rabbnya, ketika Dia mengakhirkan bagi mereka setengah hari.\" Sa'd lalu ditanya, \"Setengah hari pada waktu itu berapa lama?\" Ia menjawab, \"Lima ratus tahun.\""},"3671":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ عِكْرِمَةَأَنَّ عَلِيًّا عَلَيْهِ السَّلَام أَحْرَقَ نَاسًا ارْتَدُّوا عَنْ الْإِسْلَامِ فَبَلَغَ ذَلِكَ ابْنَ عَبَّاسٍ فَقَالَ لَمْ أَكُنْ لِأُحْرِقَهُمْ بِالنَّارِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُعَذِّبُوا بِعَذَابِ اللَّهِ وَكُنْتُ قَاتِلَهُمْ بِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ فَبَلَغَ ذَلِكَ عَلِيًّا عَلَيْهِ السَّلَام فَقَالَ وَيْحَ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah mengabarkan kepada kami [Ayyub] dari [Ikrimah] bahwa Ali Alaihis salam pernah membakar orang-orang yang murtad dari Islam. Lalu sampailah berita itu kepada [Ibnu Abbas] hingga ia berkata, \"Sungguh, aku tidak akan pernah membakar mereka dengan api. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyiksa dengan siksaan Allah.\" dan aku memerangi mereka berdasarkan sabda Rasulullah shallallahu 'alaihi wasallam. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengganti agamanya, maka bunuhlah ia.\" Hal itu akhirnya juga sampai kepada Ali Alaihis salam, hingga ia berkata, \"Ibnu Abbas benar.\""},"3672":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ رَجُلٍ مُسْلِمٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ إِلَّا بِإِحْدَى ثَلَاثٍ الثَّيِّبُ الزَّانِي وَالنَّفْسُ بِالنَّفْسِ وَالتَّارِكُ لِدِينِهِ الْمُفَارِقُ لِلْجَمَاعَةِ","id":"Telah menceritakan kepada kami [Amru bin Aun] berkata, telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim yang bersaksi bahwa tidak ada Ilah yang berhak disembah selain Allah dan aku adalah utusan Allah kecuali dengan salah satu dari tiga sebab; orang tua yang berzina, membunuh jiwa (qisas) dan keluar dari Islam (murtad) yang memisahkan diri dari jama'ah (jama'ah muslimin).\""},"3673":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ الْبَاهِلِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ إِلَّا بِإِحْدَى ثَلَاثٍ رَجُلٌ زَنَى بَعْدَ إِحْصَانٍ فَإِنَّهُ يُرْجَمُ وَرَجُلٌ خَرَجَ مُحَارِبًا لِلَّهِ وَرَسُولِهِ فَإِنَّهُ يُقْتَلُ أَوْ يُصْلَبُ أَوْ يُنْفَى مِنْ الْأَرْضِ أَوْ يَقْتُلُ نَفْسًا فَيُقْتَلُ بِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Sinan Al bahili] berkata, telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Abdul Aziz bin Rufai'] dari [Ubaid bin Umair] dari ['Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim yang bersaksi bahwa tidak ada Ilah -yang berhak disembah- selain Allah dan Muhammad adalah utusan Allah kecuali dengan salah satu dari tiga sebab; orang yang berzina setelah menikah, maka ia harus dirajam; seorang laki-laki yang keluar untuk memerangi Allah dan Rasul-Nya, maka ia harus dibunuh, disalib atau dibuang dari negri terebut. Serta seseorang yang membunuh orang lain maka harus dihukum mati karena membunuh.\""},"3674":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ مُسَدَّدٌ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنَا أَبُو بُرْدَةَ قَالَ قَالَ أَبُو مُوسَىأَقْبَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي رَجُلَانِ مِنْ الْأَشْعَرِيِّينَ أَحَدُهُمَا عَنْ يَمِينِي وَالْآخَرُ عَنْ يَسَارِي فَكِلَاهُمَا سَأَلَ الْعَمَلَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاكِتٌ فَقَالَ مَا تَقُولُ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَطْلَعَانِي عَلَى مَا فِي أَنْفُسِهِمَا وَمَا شَعَرْتُ أَنَّهُمَا يَطْلُبَانِ الْعَمَلَ وَكَأَنِّي أَنْظُرُ إِلَى سِوَاكِهِ تَحْتَ شَفَتِهِ قَلَصَتْ قَالَ لَنْ نَسْتَعْمِلَ أَوْ لَا نَسْتَعْمِلُ عَلَى عَمَلِنَا مَنْ أَرَادَهُ وَلَكِنْ اذْهَبْ أَنْتَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ فَبَعَثَهُ عَلَى الْيَمَنِ ثُمَّ أَتْبَعَهُ مُعَاذَ بْنَ جَبَلٍ قَالَ فَلَمَّا قَدِمَ عَلَيْهِ مُعَاذٌ قَالَ انْزِلْ وَأَلْقَى لَهُ وِسَادَةً وَإِذَا رَجُلٌ عِنْدَهُ مُوثَقٌ قَالَ مَا هَذَا قَالَ هَذَا كَانَ يَهُودِيًّا فَأَسْلَمَ ثُمَّ رَاجَعَ دِينَهُ دِينَ السُّوءِ قَالَ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ قَالَ اجْلِسْ نَعَمْ قَالَ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ ثَلَاثَ مَرَّاتٍ فَأَمَرَ بِهِ فَقُتِلَ ثُمَّ تَذَاكَرَا قِيَامَ اللَّيْلِ فَقَالَ أَحَدُهُمَا مُعَاذُ بْنُ جَبَلٍ أَمَّا أَنَا فَأَنَامُ وَأَقُومُ أَوْ أَقُومُ وَأَنَامُ وَأَرْجُو فِي نَوْمَتِي مَا أَرْجُو فِي قَوْمَتِي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata; [Musaddad] berkata; telah menceritakan kepada kami [Qurrah bin Khalid] berkata, telah menceritakan kepada kami [Humaid bin Hilal] berkata, telah menceritakan kepada kami [Abu Burdah] ia berkata; [Abu Musa] berkata, \"Aku menemui Nabi shallallahu 'alaihi wasallam bersama dua orang laki-laki dari Al Asy'ari; seorang dari keduanya ada di sebelah kananku dan seorang lagi di sebelah kiri. Keduanya minta dicarikan pekerjaan, sementara Nabi shallallahu 'alaihi wasallam hanya terdiam. Kemudian beliau bersabda: \"Wahai Abu Musa, apa pendapatmu? Atau beliau mengatakan, \"Wahai Abdullah bin Qais?\" Aku (Abu Musa) berkata, \"Demi Dzat yang mengutusmu dengan kebenaran, aku tidak tahu apa yang mereka inginkan, aku juga tidak tahu bahwa keduanya juga minta pekerjaan. Seakan aku melihat siwak yang berada di bawah bibir beliau telah menyusut. Beliau lalu bersabda: \"Sekali-kali kami tidak akan memperkerjakan, atau beliau mengatakan, \"tidak akan memperkerjakan orang yang menghendakinya untuk melakukan pekerjaan kami. Wahai Abu Musa, pergilah engkau, atau beliau mengatakan, \"Wahai Abu Abdullah bin Qais.\" Rasulullah kemudian mengutus Abu Musa ke Yaman yang kemudian disusul Mu'adz bin Jabal. Ketika Mu'adz datang, Abu Musa berkata, \"Turunlah kemari.\" Kemudian Abu Musa mengambilkan bantal untuk Mu'adz. Namun tiba-tiba di sisinya (Mu'adz) ada seorang laki-laki yang terikat, Mu'adz bertanya, \"Siapa ini?\" Abu Musa menjawab, \"Ini adalah seorang laki-laki yahudi, ia pernah masuk Islam, namun ia kembali lagi kepada agamanya yang jelek.\" Mu'adz lalu berkata, \"Aku tidak akan duduk hingga ia dibunuh, sebagai bentuk dari ketetapan Allah dan Rasul-Nya.\" Hal itu ia ucapkan hingga tiga kali. Abu Musa berkata, \"Baiklah, sekarang duduklah.\" Mu'adz berkata, \"Aku tidak akan duduk hingga ia dibunuh, sebagai bentuk dari ketetapan Allah dan Rasul-Nya.\" Hal itu ia ucapkan hingga tiga kali. Abu Musa kemudian memerintahkan hukuman tersebut, dan laki-laki itu pun dihumum mati. Setelah itu mereka menyebut-nyebut tentang shalat malam, salah seorang dari keduanya (Mu'adz bin Jabal) lalu berkata, \"Aku tidur dan bangun, atau ia mengatakan, \"bangun dan tidur. Dan aku berharap disaat tidurku mendapatkan (pahala) sebagaimana saat aku terjaga.\""},"3675":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا الْحِمَّانِيُّ يَعْنِى عَبْدَ الْحَمِيدِ ابْنَ عَبْدِ الرَّحْمَنِ عَنْ طَلْحَةَ بْنِ يَحْيَى وَبُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَدِمَ عَلَيَّ مُعَاذٌ وَأَنَا بِالْيَمَنِ وَرَجُلٌ كَانَ يَهُودِيًّا فَأَسْلَمَ فَارْتَدَّ عَنْ الْإِسْلَامِ فَلَمَّا قَدِمَ مُعَاذٌ قَالَ لَا أَنْزِلُ عَنْ دَابَّتِي حَتَّى يُقْتَلَ فَقُتِلَ قَالَ أَحَدُهُمَا وَكَانَ قَدْ اسْتُتِيبَ قَبْلَ ذَلِكَحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَفْصٌ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ أَبِي بُرْدَةَ بِهَذِهِ الْقِصَّةِ قَالَ فَأُتِيَ أَبُو مُوسَى بِرَجُلٍ قَدْ ارْتَدَّ عَنْ الْإِسْلَامِ فَدَعَاهُ عِشْرِينَ لَيْلَةً أَوْ قَرِيبًا مِنْهَا فَجَاءَ مُعَاذٌ فَدَعَاهُ فَأَبَى فَضَرَبَ عُنُقَهُ قَالَ أَبُو دَاوُد وَرَوَاهُ عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ أَبِي بُرْدَةَ لَمْ يَذْكُرْ الِاسْتِتَابَةَ وَرَوَاهُ ابْنُ فُضَيْلٍ عَنْ الشَّيْبَانِيِّ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى لَمْ يَذْكُرْ فِيهِ الِاسْتِتَابَةَ حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْمَسْعُودِيُّ عَنْ الْقَاسِمِ بِهَذِهِ الْقِصَّةِ قَالَ فَلَمْ يَنْزِلْ حَتَّى ضُرِبَ عُنُقُهُ وَمَا اسْتَتَابَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Al Himmani] -maksudnya Abdul Hamid bin 'Abdurrahman Al Himmani- dari [Thalhah bin Yahya] dan [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Muadz pernah datang kepadaku saat aku berada di Yaman dan ada seorang yahudi yang telah masuk Islam kemudian murtad. Saat Mu'adz tiba, ia berkata, \"Aku tidak akan turun dari tungganganku ini hingga ia (yahudi itu) dibunuh.\" Yahudi itu akhirnya dibunuh. Salah seorang dari keduanya (Abu Musa dan Mu'adz) berkata, \"Yahudi itu telah diminta untuk bertaubat sebelum diekskusi mati.\" Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Hafsh] berkata, telah menceritakan kepada kami [Asy Syaibani] dari [Abu Burdah] dengan kisah cerita yang sama. Ia (Abu Burdah) berkata, \"Didatangkan kepada [Abu Musa] seorang laki-laki yang telah murtad dari Islam. Lalu ia menyerunya (untuk bertaubat) selama dua puluh hari, atau kurang dari itu. Kemudian Mu'adz tiba dan menyerunya (untuk taubat), namun laki-laki itu enggan, hingga akhirnya Mu'adz memenggal lehernya.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Abdul Malik bin Umair] dari [Abu Burdah], namun ia tidak menyebutkan kata 'permintaan untuk bertubat'. [Ibnu Fudhail] juga meriwayatkan dari [Asy Syaibani] dari [Sa'id bin Abu Burdah], dari [bapaknya], dari [Abu Musa], dan ia juga tidak menyebutkan kata 'permintaan untuk taubat' dalam haditsnya. Telah menceritakan kepada kami [Ibnu Mu'adz] berkata, telah menceritakan kepada kami [bapakku] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Al Qasim] dengan kisah ini, ia berkata, \"Mu'adz belum juga turun dari kendaraannya hingga laki-laki (murtad) itu dipenggal lehernya tanpa memintanya untuk bertaubat dahulu.\""},"3676":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ أَبِي سَرْحٍ يَكْتُبُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَزَلَّهُ الشَّيْطَانُ فَلَحِقَ بِالْكُفَّارِ فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْتَلَ يَوْمَ الْفَتْحِ فَاسْتَجَارَ لَهُ عُثْمَانُ بْنُ عَفَّانَ فَأَجَارَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] berkata, telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] dari [Bapaknya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Abdullah bin Sa'd bin Abu Sarh pernah menulis surat perjanjian dengan Rasulullah shallallahu 'alaihi wasallam, namun setan menggelincirkannya hingga ia bergabung dengan orang-orang kafir. Rasulullah shallallahu 'alaihi wasallam pun memerintahkan untuk membunuhnya saat pembukaan (penaklukan) kota Makkah. Namun Utsman bin Affan memberikan jaminan perlindungan kepadanya, dan Rasulullah shallallahu 'alaihi wasallam menjamin keamanannya.\""},"3677":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ الْمُفَضَّلِ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ قَالَ زَعَمَ السُّدِّيُّ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ اخْتَبَأَ عَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ أَبِي سَرْحٍ عِنْدَ عُثْمَانَ بْنِ عَفَّانَ فَجَاءَ بِهِ حَتَّى أَوْقَفَهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ بَايِعْ عَبْدَ اللَّهِ فَرَفَعَ رَأْسَهُ فَنَظَرَ إِلَيْهِ ثَلَاثًا كُلُّ ذَلِكَ يَأْبَى فَبَايَعَهُ بَعْدَ ثَلَاثٍ ثُمَّ أَقْبَلَ عَلَى أَصْحَابِهِ فَقَالَ أَمَا كَانَ فِيكُمْ رَجُلٌ رَشِيدٌ يَقُومُ إِلَى هَذَا حَيْثُ رَآنِي كَفَفْتُ يَدِي عَنْ بَيْعَتِهِ فَيَقْتُلُهُ فَقَالُوا مَا نَدْرِي يَا رَسُولَ اللَّهِ مَا فِي نَفْسِكَ أَلَّا أَوْمَأْتَ إِلَيْنَا بِعَيْنِكَ قَالَ إِنَّهُ لَا يَنْبَغِي لِنَبِيٍّ أَنْ تَكُونَ لَهُ خَائِنَةُ الْأَعْيُنِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ahmad bin Al Mufadhdhal] berkata, telah menceritakan kepada kami [Asbath bin Nashr] ia berkata; [As Sudi] menyakini bahwa ia meriwayatkan dari [Mush'ab bin Sa'd] dari [Sa'd] ia berkata, \"Saat terjadi pembukaan (penaklukan) kota Makkah, Abdullah bin Sa'd bin Abu Sarh bersembunyi di belakang Utsman bin Affan (minta perlindungan). Utsman lantas membawanya menghadap Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, baiatlah Abdullah.\" Beliau kemudian mengangkat kepalanya dan memandang ke arahnya sebanyak tiga kali, setiap kali itu pula beliau enggan menerimanya. Namun pada kali ketiganya beliau menerima dan membaiatnya. Setelah itu beliau berbalik menghadap para sahabat, beliau bersabda: \"Bukankah telah ada di antara kalian seorang yang bijaksana (yang percaya dengan keputusan Rasulullah) yang berdiri menuju orang ini (untuk memohon jaminan perlindungan), yang jika sekiranya ia melihatku menahan tanganku untuk membaiatnya maka ia akan membunuhnya.\" maka mereka (para sahabat) berkata; \"Kami tidak mengetahui apa yang ada dalam dirimu wahai Rasulullah jika engkau tidak memberikan isyarat kepada kami dengan mata, Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya tidak layak bagi seorang Nabi tidak jujur dengan isyarat matanya.\""},"3678":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَبَقَ الْعَبْدُ إِلَى الشِّرْكِ فَقَدْ حَلَّ دَمُهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Humaid bin 'Abdurrahman] dari [Bapaknya] dari [Abu Ishaq] dari [Asy Sya'bi] dari [Jarir] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba sahaya melarikan diri ke negeri kafir, maka darahnya telah halal.\""},"3679":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ الْمَدَنِيُّ عَنْ إِسْرَائِيلَ عَنْ عُثْمَانَ الشَّحَّامِ عَنْ عِكْرِمَةَ قَالَ حَدَّثَنَا ابْنُ عَبَّاسٍأَنَّ أَعْمَى كَانَتْ لَهُ أُمُّ وَلَدٍ تَشْتُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقَعُ فِيهِ فَيَنْهَاهَا فَلَا تَنْتَهِي وَيَزْجُرُهَا فَلَا تَنْزَجِرُ قَالَ فَلَمَّا كَانَتْ ذَاتَ لَيْلَةٍ جَعَلَتْ تَقَعُ فِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَشْتُمُهُ فَأَخَذَ الْمِغْوَلَ فَوَضَعَهُ فِي بَطْنِهَا وَاتَّكَأَ عَلَيْهَا فَقَتَلَهَا فَوَقَعَ بَيْنَ رِجْلَيْهَا طِفْلٌ فَلَطَّخَتْ مَا هُنَاكَ بِالدَّمِ فَلَمَّا أَصْبَحَ ذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَمَعَ النَّاسَ فَقَالَ أَنْشُدُ اللَّهَ رَجُلًا فَعَلَ مَا فَعَلَ لِي عَلَيْهِ حَقٌّ إِلَّا قَامَ فَقَامَ الْأَعْمَى يَتَخَطَّى النَّاسَ وَهُوَ يَتَزَلْزَلُ حَتَّى قَعَدَ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا صَاحِبُهَا كَانَتْ تَشْتُمُكَ وَتَقَعُ فِيكَ فَأَنْهَاهَا فَلَا تَنْتَهِي وَأَزْجُرُهَا فَلَا تَنْزَجِرُ وَلِي مِنْهَا ابْنَانِ مِثْلُ اللُّؤْلُؤَتَيْنِ وَكَانَتْ بِي رَفِيقَةً فَلَمَّا كَانَ الْبَارِحَةَ جَعَلَتْ تَشْتُمُكَ وَتَقَعُ فِيكَ فَأَخَذْتُ الْمِغْوَلَ فَوَضَعْتُهُ فِي بَطْنِهَا وَاتَّكَأْتُ عَلَيْهَا حَتَّى قَتَلْتُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا اشْهَدُوا أَنَّ دَمَهَا هَدَرٌ","id":"Telah menceritakan kepada kami [Abbad bin Musa Al Khuttali] berkata, telah mengabarkan kepada kami [Isma'il bin Ja'far Al madani] dari [Isra'il] dari [Utsman Asy Syahham] dari [Ikrimah] ia berkata, [Ibnu Abbas] pernah bercerita kepada kami; \"Seorang laki-laki buta mempunyai Ummul Walad (budak wanita yang dijadikan isteri) yang menghina Nabi shallallahu 'alaihi wasallam, dan ia benar-benar telah melakukannya (penghinaan). Laki-laki itu melarang dan mengancamnya namun ia tidak berhenti dan ia terus melarangnya namun wanita itu tidak menggubris. Ibnu Abbas melanjutkan ceritanya, \"Pada suatu malam wanita itu kembali mencela Nabi shallallahu 'alaihi wasallam, maka laki-laki itu mengambil sebuah pisau tajam dan meletakkan di atas perut wanita itu seraya menusuknya. Laki-laki itu membunuhnya, sementara antara kedua kaki wanita tersebut lahir seorang banyi mungil hingga ia pun berlumuran darah. Ketika hari telah pagi, kejadian tersebut disampaikan kepada Nabi shallallahu 'alaihi wasallam. Beliau lantas mengumpulkan orang-orang dan bersabda: \"Aku bersumpah kepada Allah atas seorang laki-laki, ia telah melakukan suatu perbuatan karena aku, ia dalam kebenaran.\" Kemudian laki-laki buta itu melangkah di antara manusia hingga ia duduk di hadapan nabi shallallahu 'alaihi wasallam. Ia lalu berkata, \"Wahai Rasulullah, aku adalah suaminya. Namun ia mencela dan menghinamu, aku telah melarang dan mengancamnya, namun ia tidak berhenti atau menggubrisnya. Darinya aku telah dikaruniakan dua orang anak yang cakep layaknya bintang yang bersinar, wanita itu sangat sayang kepadaku. Namun, tadi malam ia mencela dan menghinamu, lantas aku mengambil pisau tajam, pisau itu aku letakkan di atas perutnya dan aku tusukkan hingga ia mati.\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Ketahuilah, bahwa darah wanita itu adalah sia-sia (halal).\""},"3680":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ جَرِيرٍ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيَّةً كَانَتْ تَشْتُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقَعُ فِيهِ فَخَنَقَهَا رَجُلٌ حَتَّى مَاتَتْ فَأَبْطَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَمَهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Abdullah Ibnul jarrah] dari [Jarir] dari [Mughirah] dari [Asy Sya'bi] dari [Ali radliallahu 'anhu] ia berkata, \"Seorang wanita yahudi mencela Nabi shallallahu 'alaihi wasallam, lalu seorang laki-laki mencekik lehernya hingga mati. Rasulullah shallallahu 'alaihi wasallam lalu menjadikan darahnya sia-sia.\""},"3681":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ يُونُسَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَنُصَيْرُ بْنُ الْفَرَجِ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ يَزِيدَ بْنِ زُرَيْعٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ مُطَرِّفٍ عَنْ أَبِي بَرْزَةَ قَالَكُنْتُ عِنْدَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَتَغَيَّظَ عَلَى رَجُلٍ فَاشْتَدَّ عَلَيْهِ فَقُلْتُ تَأْذَنُ لِي يَا خَلِيفَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَضْرِبُ عُنُقَهُ قَالَ فَأَذْهَبَتْ كَلِمَتِي غَضَبَهُ فَقَامَ فَدَخَلَ فَأَرْسَلَ إِلَيَّ فَقَالَ مَا الَّذِي قُلْتَ آنِفًا قُلْتُ ائْذَنْ لِي أَضْرِبُ عُنُقَهُ قَالَ أَكُنْتَ فَاعِلًا لَوْ أَمَرْتُكَ قُلْتُ نَعَمْ قَالَ لَا وَاللَّهِ مَا كَانَتْ لِبَشَرٍ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد هَذَا لَفْظُ يَزِيدَ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ أَيْ لَمْ يَكُنْ لِأَبِي بَكْرٍ أَنْ يَقْتُلَ رَجُلًا إِلَّا بِإِحْدَى الثَّلَاثِ الَّتِي قَالَهَا رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفْرٌ بَعْدَ إِيمَانٍ أَوْ زِنًا بَعْدَ إِحْصَانٍ أَوْ قَتْلُ نَفْسٍ بِغَيْرَ نَفْسٍ وَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْتُلَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Yunus] dari [Humaid bin Hilal] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Abdullah] dan [Nushair Ibnul Faraj] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Yazid bin Zurai'] dari [Yunus bin Ubaid] dari [Humaid bin Hilal] dari [Abdullah bin Mutharrif] dari [Abu Barzah] ia berkata, \"Aku pernah di dekat [Abu Bakar radliallahu 'anhu], ia marah kepada seorang laki-laki dan amarahnya semakin memuncak. Aku lalu berkata, \"Wahai Khalifah Rasulullah shallallahu 'alaihi wasallam, bolehkan aku memenggal kepalanya?\" Abu Barzah berkata, \"Kata-kataku itu menjadikan amarahnya hilang. Ia lalu berdiri dan masuk ke dalam rumah. Kemudian Abu Bakar mengutus utusan (untuk memanggilku), Abu Bakar berkata, \"Apa yang kamu katakan tadi?\" aku menjawab, \"Tadi aku minta izin untuk memenggal lehernya.\" Abu Bakar berkata lagi, \"Apakah kamu akan melakukannya jika aku perintahkan untuk itu?\" Aku menjawab, \"Tentu.\" Abu Bakr lalu berkata, \"Demi Allah, tidak! Tidak ada seorang pun boleh melebihi (petuah) Muhammad shallallahu 'alaihi wasallam.\" Abu Dawud berkata, \"Ini adalah lafadz Yazid. Ahmad bin Hanbal berkata, \"Maksudnya, Abu Bakar tidak akan membunuh seorang pun kecuali dengan salah satu dari tiga sebab (dibolehkannya membunuh seorang muslim) sebagaimana yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam. Yakni; kafir setelah beriman, zina setelah menikah dan membunuh jiwa. Itulah alasan yang dibolehkan Nabi shallallahu 'alaihi wasallam untuk membunuh.\""},"3682":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ قَوْمًا مِنْ عُكْلٍ أَوْ قَالَ مِنْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِقَاحٍ وَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَانْطَلَقُوا فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا النَّعَمَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرُهُمْ مِنْ أَوَّلِ النَّهَارِ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آثَارِهِمْ فَمَا ارْ��َفَعَ النَّهَارُ حَتَّى جِيءَ بِهِمْ فَأَمَرَ بِهِمْ فَقُطِعَتْ أَيْدِيهِمْ وَأَرْجُلُهُمْ وَسُمِرَ أَعْيُنُهُمْ وَأُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَقَالَ أَبُو قِلَابَةَ فَهَؤُلَاءِ قَوْمٌ سَرَقُوا وَقَتَلُوا وَكَفَرُوا بَعْدَ إِيمَانِهِمْ وَحَارَبُوا اللَّهَ وَرَسُولَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ بِإِسْنَادِهِ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَأَمَرَ بِمَسَامِيرَ فَأُحْمِيَتْ فَكَحَلَهُمْ وَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَمَا حَسَمَهُمْ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ قَالَ أَخْبَرَنَا ح و حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ قَافَةً فَأُتِيَ بِهِمْ قَالَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى فِي ذَلِكَ{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا }الْآيَةَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ وَقَتَادَةُ وَحُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ ذَكَرَ هَذَا الْحَدِيثَ قَالَ أَنَسٌ فَلَقَدْ رَأَيْتُ أَحَدَهُمْ يَكْدِمُ الْأَرْضَ بِفِيهِ عَطَشًا حَتَّى مَاتُوا حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ نَحْوَهُ زَادَ ثُمَّ نَهَى عَنْ الْمُثْلَةِ وَلَمْ يَذْكُرْ مِنْ خِلَافٍ وَرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ وَسَلَّامُ بْنُ مِسْكِينٍ عَنْ ثَابِتٍ جَمِيعًا عَنْ أَنَسٍ لَمْ يَذْكُرَا مِنْ خِلَافٍ وَلَمْ أَجِدْ فِي حَدِيثِ أَحَدٍ قَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ مِنْ خِلَافٍ إِلَّا فِي حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Beberapa orang dari 'Ukl, atau ia mengatakan, \"dari Urainah datang menemui Rasulullah shallallahu 'alaihi wasallam. Namun mereka tidak cocok dengan iklim Madinah (hingga jatuh sakit). Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk menyediakan liqah (unta hamil) bagi mereka. Beliau perintahkan mereka minum air kencing dan susu unta tersebut. Mereka pun pergi (menuju kandang unta), namun ketika telah sembuh mereka justru membunuh pengembala Rasulullah shallallahu 'alaihi wasallam dan membawa lari unta-unta tersebut. Menjelang siang hari, berita yang menimpa mereka sampai kepada Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lalu mengirim (beberapa orang) untuk mengikuti jejak mereka. Matahari belum tinggi, orang-orang tersebut telah ditangkap dan dihadapkan kepada beliau. Beliau pun memberi perintah untuk memberi hukuman kepada mereka, tangan dan kaki mereka lalu dipotong, matanya dicongkel kemudian mereka dibuang ke padang pasir. Mereka minta minum namun tidak diberi.\" [Abu Qilabah] berkata, \"Orang-orang itu telah mencuri dan membunuh, murtad setelah beriman, serta memerangi Allah dan Rasul-Nya.\" Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dengan sanadnya sebagaimana dalam hadits tersebut. Namun ia menambahkan dalam haditsnya, \"Beliau memerintahkan untuk mengambil beberapa paku yang dipanaskan, lalu mereka disayat (dengan paku tersebut), tangan dan kaki mereka juga dipotong, namun beliau tidak memerintahkan untuk menghentikan darah mereka dengan menempelkan besi panas.\" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah bin Sufyan] ia berkata; telah mengabarkan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya] -maksudnya Yahya bin Abu Katsir- dari [Abu Qilabah] dari [Anas bin Malik] dengan hadits yang sama. Dalam hadits tersebut ia mengatakan, \"Rasulullah shallallahu 'alaihi wasallam lalu mengirim teliksandi untuk mencari mereka, hingga akhirnya mereka tertangkap. Anas berkata, \"Allah Tabaaraka Wa Ta'ala lalu menurunkan ayat: '(Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan..) ' -Qs. Al Maidah: 33-. Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Tsabit] dan [Qatadah] dan [Humaid] dari [Anas bin Malik] ia lalu menyebutkan hadits tersebut. Anas berkata, \"Aku melihat salah seorang dari mereka menjilati bumi dengan mulutnya karena haus, hingga akhirnya mati.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam] dari [Qatadah] dari [Anas bin Malik] sama dengan hadits tersebut, namun ia menambahkan, \"kemudian beliau melarang untuk melakukan mutslah (Mutilasi atau menyayat mayat). dan ia tidak menyebut kata; 'min khilaf' (secara bersilang). [Syu'bah] juga meriwayatkan dari [Qatadah] dan [Salam bin Miskin], dari [Tsabit]. Semuanya juga berasal dari [Anas], namun keduanya juga tidak menyebutkan kata; min khilaf (dipotong tangan dan kakinya secara bersilang). Aku tidak pernah mendapatkan dalam hadits seorang pun yang menyebutkan; 'beliau memotong tangan dan kaki mereka secara bersilang', kecuali hadits hadits riwayat Hammad bin Salamah.\""},"3683":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ أَبِي الزِّنَادِ عَنْ عَبِدْ اللَّهِ بْنِ عُبَيْدِ اللَّهِ قَالَ أَحْمَدُ هُوَ يَعْنِي عَبْدَ اللَّهِ بْنَ عُبَيْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ ابْنِ عُمَرَأَنَّ نَاسًا أَغَارُوا عَلَى إِبِلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَاقُوهَا وَارْتَدُّوا عَنْ الْإِسْلَامِ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤْمِنًا فَبَعَثَ فِي آثَارِهِمْ فَأُخِذُوا فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْقَالَ وَنَزَلَتْ فِيهِمْ آيَةُ الْمُحَارَبَةِ وَهُمْ الَّذِينَ أَخْبَرَ عَنْهُمْ أَنَسُ بْنُ مَالِكٍ الْحَجَّاجَ حِينَ سَأَلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Amru] dari [Sa'id bin Abu Hilal] dari [Abu Az Zinad] dari [Abdullah bin Ubaidullah] -Ahmad berkata; dia adalah Abdullah bin Ubaidullah bin Umar bin Al Khaththab- dari [Ibnu Umar] ia berkata, \"Ada beberapa orang mencuri unta Nabi shallallahu 'alaihi wasallam, mereka murtad dari Islam dan membunuh para pengembala Rasulullah shallallahu 'alaihi wasallam yang telah beriman. Beliau lalu mengirim mata-mata untuk mengikuti jejak mereka, mereka pun ditangkap. Beliau memotong tangan dan kaki, serta mencongkel mata mereka.\" Ibnu Umar melanjutkan, \"Lalu turunlah ayat Al Muharabah (peperangan) berkenaan dengan mereka. itu pulalah yang dikabarkan Anas bin Malik kepada Al Hajjaj saat ia bertanya kepadanya.\""},"3684":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي اللَّيْثُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ أَبِي الزِّنَادِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَطَّعَ الَّذِينَ سَرَقُوا لِقَاحَهُ وَسَمَلَ أَعْيُنَهُمْ بِالنَّارِ عَاتَبَهُ اللَّهُ تَعَالَى فِي ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا أَنْ يُقَتَّلُوا أَوْ يُصَلَّبُوا }الْآيَةَحَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ كَانَ هَذَا قَبْلَ أَنْ تَنْزِلَ الْحُدُودُ يَعْنِي حَدِيثَ أَنَسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Al laits bin Sa'd] dari [Muhammad bin 'Ajlan] dari [Abu Az Zinad] berkata, \"Ketika Rasulullah memotong (tangan dan kaki) serta mencongkel mata orang-orang yang mencuri unta miliknya dengan api, Allah Ta'ala mencela perbuatan tersebut. Allah kemudian menurunkan ayat: '(Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan rasul-Nya serta membuat kerusakan di muka bumi, hanyalah mereka dibunuh atau disalib..) '.\" Telah menceritakan kepada kami Muhammad bin Katsir ia berkata; telah mengabarkan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami Musa bin Isma'il berkata, telah menceritakan kepada kami Hammam dari Qatadah dari Muhammad bin Sirin ia berkata, \"Ini adalah ketika belum turun syariat hudud, yaitu sebagaimana tersebut dalam hadits Anas.\""},"3685":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا أَنْ يُقَتَّلُوا أَوْ يُصَلَّبُوا أَوْ تُقَطَّعَ أَيْدِيهِمْ وَأَرْجُلُهُمْ مِنْ خِلَافٍ أَوْ يُنْفَوْا مِنْ الْأَرْضِ إِلَى قَوْلِهِ غَفُورٌ رَحِيمٌ }نَزَلَتْ هَذِهِ الْآيَةُ فِي الْمُشْرِكِينَ فَمَنْ تَابَ مِنْهُمْ قَبْلَ أَنْ يُقْدَرَ عَلَيْهِ لَمْ يَمْنَعْهُ ذَلِكَ أَنْ يُقَامَ فِيهِ الْحَدُّ الَّذِي أَصَابَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit] berkata, telah menceritakan kepada kami [Ali bin Husain] dari [Bapaknya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata berkenaan dengan ayat: '(Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan di muka bumi, hanyalah mereka dibunuh atau disalib, atau dipotong tangan dan kaki mereka dengan bertimbal balik, atau dibuang dari negeri (tempat kediamannya). Hingga firman Allah: '(Allah Maha Pengampun lagi Maha Penyayang) ' ia mengatakan, \"Ayat ini turun kepada orang-orang musyrik, jika salah seorang dari mereka bertaubat sebelum dilaksanakannya (hudud), ia tidak dapat terhindar dari hukuman hudud.\""},"3686":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الْهَمْدَانِيُّ قَالَ حَدَّثَنِي ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ قُرَيْشًا أَهَمَّهُمْ شَأْنُ الْمَرْأَةِ الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ فِيهَا يَعْنِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَمَنْ يَجْتَرِئُ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَهُ أُسَامَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُسَامَةُ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ ثُمَّ قَامَ فَاخْتَطَبَ فَقَالَ إِنَّمَا هَلَكَ الَّذِينَ مِنْ قَبْلِكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَاحَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ ومُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَتْ امْرَأَةٌ مَخْزُومِيَّةٌ تَسْتَعِيرُ الْمَتَاعَ وَتَجْحَدُهُ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَطْعِ يَدِهَا وَقَصَّ نَحْوَ حَدِيثِ اللَّيْثِ قَالَ فَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهَا قَالَ أَبُو دَاوُد رَوَى ابْنُ وَهْبٍ هَذَا الْحَدِيثَ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ وَقَالَ فِيهِ كَمَا قَالَ اللَّيْثُ إِنَّ امْرَأَةً سَرَقَتْ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ الْفَتْحِ وَرَوَاهُ اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ فَقَالَ اسْتَعَارَتْ امْرَأَةٌ وَرَوَى مَسْعُودُ بْنُ الْأَسْوَدِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا الْخَبَرِ قَالَ سَرَقَتْ قَطِيفَةً مِنْ بَيْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ أَبُو الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ امْرَأَةً سَرَقَتْ فَعَاذَتْ بِزَيْنَبَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Mauhab Al Hambdani] ia berkata; telah menceritakan kepadaku. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Qutaibah bin Sa'id Ats Tsaqafi] berkata, telah menceritakan kepada kami [Al laits] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah radliallahu 'anha] berkata, \"Bangsa Quraisy pernah dikagetkan dengan kasus pencurian seorang wanita Makhzumiyah. Orang-orang berkata, \"Siapakah yang akan memintakan amnesti kepada Rasulullah shallallahu 'alaihi wasallam?\" sebagian yang lain menjawab, \"Tidak ada yang berani melakukan hal itu selain Usamah bin Zaid, kekasih Rasulullah shallallahu 'alaihi wasallam?\" Usamah kemudian menyampaikan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, hingga beliau pun bersabda: \"Wahai Usamah! Apakah engkau akan meminta keringanan dalam masalah hukum had Allah? Beliau kemudian berdiri dan berkhutbah: \"Hanyasanya orang-orang sebelum kalian binasa karena jika ada orang terhormat dari mereka mencuri, mereka tidak menegakkan had. Tetapi jika ada orang rendahan yang mencuri, mereka menegakkan had atasnya. Demi Allah, sekiranya Fatimah binti Muhammad mencuri, sungguh aku akan memotong tangannya.\" Telah menceritakan kepada kami [Abbas bin Abdul Azhim] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Pernah seorang wanita Makhzumiyah meminjam barang, kemudian ia mengingkari bahwa dirinya pernah meminjamnya. Maka Nabi shallallahu 'alaihi wasallam memerintahkan untuk memotong tangannya. Lalu ia mengisahkan sebagaimana dalam hadits Al Laits. Ia (perawi) berkata, \"Nabi shallallahu 'alaihi wasallam kemudian memotong tangan wanita tersebut.\" Abu Dawud berkata, \" [Ibnu Wahb] meriwayatkan hadits ini dari [Yunus], dari [Az Zuhri], dalam hadits tersebut ia menyebutkan sebagaimana yang pernah disebutkan oleh Al Laits, \"Seorang wanita mencuri pada masa Nabi shallallahu 'alaihi wasallam, yaitu ketika terjadinya penaklukan kota Makkah.\" [Al Laits] juga meriwayatkannya dari [Yunus], dari [Ibnu Syihab] dengan sanadnya. Ia menyebutkan, \"Seorang wanita meminjam..\" Mas'ud Ibnul Aswad juga meriwayatkan dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. Ia menyebutkan, \"Wanita tersebut mencuri kain beludru dari rumah Rasulullah shallallahu 'alaihi wasallam.\" Dan [Abu Az Zubair] juga meriwayatkannya dari [Jabir]; \"bahwasanya ada seorang wanita yang mencuri, maka ia berlindung kepada Zainab anak Rasulullah Shallahu 'Alaihi Wasallam.\""},"3687":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ وَمُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ قَالَا أَخْبَرَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الْمَلِكِ بْنِ زَيْدٍ نَسَبَهُ جَعْفَرٌ إِلَى سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقِيلُوا ذَوِي الْهَيْئَاتِ عَثَرَاتِهِمْ إِلَّا الْحُدُودَ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] dan [Muhammad bin Sulaiman Al Anbari] keduanya berkata; telah mengabarkan kepada kami [Ibnu Abu Fudaik] dari [Abdul Malik bin Zaid]. Ja'far menyandarkannya kepada Sa'id bin Zaid bin Amru bin Nufail dari [Muhammad bin Abu Bakr] dari [Amrah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maafkanlah kekeliruan (tergelincirnya) orang-orang yang baik, kecuali dalam masalah hukum had.\""},"3688":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ ابْنَ جُرَيْجٍ يُحَدِّثُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَافُّوا الْحُدُودَ فِيمَا بَيْنَكُمْ فَمَا بَلَغَنِي مِنْ حَدٍّ فَقَدْ وَجَبَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri] berkata, telah mengabarkan kepada kami [Ibnu Wahb] ia berkata; Aku mendengar [Ibnu Juraij] menceritakan dari [Amru bin Syu'aib] dari [Bapaknya] dari [Abdullah bin Amru bin Al Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian saling memaafkan dalam masalah hukuman had yang terjadi di antara kalian, sebab jika had telah sampai kepadaku maka wajib untuk dilaksanakan.\""},"3689":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ يَزِيدَ بْنِ نُعَيْمٍ عَنْ أَبِيهِأَنَّ مَاعِزًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقَرَّ عِنْدَهُ أَرْبَعَ مَرَّاتٍ فَأَمَرَ بِرَجْمِهِ وَقَالَ لِهَزَّالٍ لَوْ سَتَرْتَهُ بِثَوْبِكَ كَانَ خَيْرًا لَكَحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ الْمُنْكَدِرِ أَنْ هَزَّالًا أَمَرَ مَاعِزًا أَنْ يَأْتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُخْبِرَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Zaid bin Aslam] dari [Yazid bin Nu'aim] dari [Bapaknya] ia berkata, \"Ma'iz datang menemui Nabi shallallahu 'alaihi wasallam dan mengakui -sebanyak empat kali- bahwa dirinya telah berzina. Beliau lalu memerintahkan untuk merajamnya. Beliau bersabda kepada Hazzal (bapaknya Nu'aim): \"Sekiranya engkau menutupinya dengan kainmu (tidak menyampaikan), sungguh itu akan lebih baik bagi kamu.\" Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Yahya] dari [Ibnul Munkadir] bahwa [Hazzal] menyuruh Ma'iz untuk mendatangi nabi shallallahu 'alaihi wasallam dan mengabarkan kepada beliau (bahwa ia pernah berzina).\""},"3690":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا الْفِّرْيَابِيُّ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِأَنَّ امْرَأَةً خَرَجَتْ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُرِيدُ الصَّلَاةَ فَتَلَقَّاهَا رَجُلٌ فَتَجَلَّلَهَا فَقَضَى حَاجَتَهُ مِنْهَا فَصَاحَتْ وَانْطَلَقَ فَمَرَّ عَلَيْهَا رَجُلٌ فَقَالَتْ إِنَّ ذَاكَ فَعَلَ بِي كَذَا وَكَذَا وَمَرَّتْ عِصَابَةٌ مِنْ الْمُهَاجِرِينَ فَقَالَتْ إِنَّ ذَلِكَ الرَّجُلَ فَعَلَ بِي كَذَا وَكَذَا فَانْطَلَقُوا فَأَخَذُوا الرَّجُلَ الَّذِي ظَنَّتْ أَنَّهُ وَقَعَ عَلَيْهَا فَأَتَوْهَا بِهِ فَقَالَتْ نَعَمْ هُوَ هَذَا فَأَتَوْا بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَمَرَ بِهِ قَامَ صَاحِبُهَا الَّذِي وَقَعَ عَلَيْهَا فَقَالَ يَا رَسُولَ اللَّهِ أَنَا صَاحِبُهَا فَقَالَ لَهَا اذْهَبِي فَقَدْ غَفَرَ اللَّهُ لَكِ وَقَالَ لِلرَّجُلِ قَوْلًا حَسَنًاقَالَ أَبُو دَاوُد يَعْنِي الرَّجُلَ الْمَأْخُوذَ وَقَالَ لِلرَّجُلِ الَّذِي وَقَعَ عَلَيْهَا ارْجُمُوهُ فَقَالَ لَقَدْ تَابَ تَوْبَةً لَوْ تَابَهَا أَهْلُ الْمَدِينَةِ لَقُبِلَ مِنْهُمْ قَالَ أَبُو دَاوُد رَوَاهُ أَسْبَاطُ بْنُ نَصْرٍ أَيْضًا عَنْ سِمَاكٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Al Faryabi] berkata telah menceritakan kepada kami [Isra'il] berkata, telah menceritakan kepada kami [Simak bin Harb] dari [Alqamah bin Wail] dari [bapaknya] ia berkata, \"Pada masa Nabi shallallahu 'alaihi wasallam ada seorang wanita keluar rumah untuk melaksanakan shalat berjamaah. Lalu, ia bertemu dengan seorang laki-laki yang kemudian memaksanya untuk melakukan hubungan intim, laki-laki itu akhirnya memerkosanya sementara ia hanya bisa berteriak. Setelah puas laki-laki itu kabur melarikan diri. Kemudian lewatlah seorang laki-laki di hadapannya, wanita itu berkata, \"Orang itu telah memperlakukan aku begini dan begini (memperkosa)! Pada saat yang bersamaan lewat juga sekelompok orang dari Muhajirin, wanita itu berkata, \"laki-laki itu telah melakukan begini dan begini kepadaku (memperkosa).\" Rombongan itu lalu mengejar laki-laki yang disangka oleh wanita itu telah memperkosanya. Mereka kemudian membawanya ke hadapan wanita itu, wanita berkata, \"Benar, laki-laki inilah yang telah memperkosaku! ' Mereka kemudian membawa laki-laki malang itu kepada Nabi shallallahu 'alaihi wasallam, maka ketika beliau memerintahkan untuk menghukum (rajam) laki-laki tersebut, laki-laki yang memperkosa wanita itu berdiri dan berkata, \"Wahai Rasulullah, akulah yang telah memperkosanya.\" Beliau bersabda kepada wanita itu: \"Pergilah, semoga Allah mengampuni kekeliruanmu (salah tuduh).\" Beliau juga mengatakan ucapan yang baik kepada laki-laki itu.\" Abu Dawud berkata, \"maksudnya laki-laki yang diambil karena salah tangkap. Dan Rasulullah berkata untuk si pelaku: \"Rajamlah ia.\" Kemudian beliau melanjutkan: \"Dia telah bertaubat, dan sekiranya taubatnya dibagikan kepada seluruh penduduk Madinah, niscaya taubatnya akan diterima.\" Abu Dawud berkata, \" [Asbath bin Nashr] juga meriwayatkannya dari [Simak].\""},"3691":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الْمُنْذِرِ مَوْلَى أَبِي ذَرٍّ عَنْ أَبِي أُمَيَّةَ الْمَخْزُومِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلِصٍّ قَدْ اعْتَرَفَ اعْتِرَافًا وَلَمْ يُوجَدْ مَعَهُ مَتَاعٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى فَأَعَادَ عَلَيْهِ مَرَّتَيْنِ أَوْ ثَلَاثًا فَأَمَرَ بِهِ فَقُطِعَ وَجِيءَ بِهِ فَقَالَ اسْتَغْفِرْ اللَّهَ وَتُبْ إِلَيْهِ فَقَالَ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فَقَالَ اللَّهُمَّ تُبْ عَلَيْهِ ثَلَاثًاقَالَ أَبُو دَاوُد رَوَاهُ عَمْرُو بْنُ عَاصِمٍ عَنْ هَمَّامٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ قَالَ عَنْ أَبِي أُمَيَّةَ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Ishaq bin Abdullah bin Abu thalhah] dari [Abu Al Mundzir] -mantan budak (yang telah dimerdekakan oleh) Abu Dzar- dari [Abu Umayyah Al Makhzumi] berkata, \"Pernah dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam seorang pencuri yang telah mengakui kesalahannya, namun barang yang dicurinya tidak lagi bersamanya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Benarkah kamu telah mencuri?\" Ia menjawab, \"Benar.\" Beliau ulangi pertanyaan itu dua atau tiga kali. Beliau lalu memerintahkan untuk memotong tangannya, setelah itu ia dihadapkan lagi kepada beliau. Beliau bersabda: \"Mintalah ampun kepada Allah, bertaubatlah kepada-Nya.\" Laki-laki itu lalu berkata, \"Aku minta ampun kepada Allah dan bertaubat kepada-Nya.\" Beliau lalu berdoa: \"Ya Allah, ampunilah dia.\" Doa itu beliau ucapkan hingga tiga kali. Abu Dawud berkata, \" [Amru bin Ashim] meriwayatkannya dari [Hammam], dari [Ishaq bin Abdullah], ia berkata; dari [Abu Umayyah] -lelaki dari Anshar-, dari Nabi shallallahu 'alaihi wasallam.\""},"3692":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي أَبُو عَمَّارٍ حَدَّثَنِي أَبُو أُمَامَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ قَالَ تَوَضَّأْتَ حِينَ أَقْبَلْتَ قَالَ نَعَمْ قَالَ هَلْ صَلَّيْتَ مَعَنَا حِينَ صَلَّيْنَا قَالَ نَعَمْ قَالَ اذْهَبْ فَإِنَّ اللَّهَ تَعَالَى قَدْ عَفَا عَنْكَ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] berkata, telah menceritakan kepada kami [Umar bin Abdul Wahid] dari [Al Auza'i] ia berkata; telah menceritakan kepadaku [Abu Ammar] berkata, telah menceritakan kepadaku [Abu Umamah] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku telah melakukan dosa yang wajib atasnya hukuman had, maka hukumlah aku!\" beliau balik bertanya: \"Apakah engkau berwudhu ketika datang kemari?\" ia menjawab, \"Ya.\" beliau bertanya lagi: \"Ketika kami shalat apakah kamu juga ikut shalat bersama kami?\" ia menjawab, \"Ya.\" beliau bersabda: \"Pergilah sesungguhnya Allah telah mengampuni kamu.\""},"3693":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا صَفْوَانُ حَدَّثَنَا أَزْهَرُ بْنُ عَبْدِ اللَّهِ الْحَرَازِيُّأَنَّ قَوْمًا مِنْ الْكَلَاعِيِّينَ سُرِقَ لَهُمْ مَتَاعٌ فَاتَّهَمُوا أُنَاسًا مِنْ الْحَاكَةِ فَأَتَوْا النُّعْمَانَ بْنَ بَشِيرٍ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَبَسَهُمْ أَيَّامًا ثُمَّ خَلَّى سَبِيلَهُمْ فَأَتَوْا النُّعْمَانَ فَقَالُوا خَلَّيْتَ سَبِيلَهُمْ بِغَيْرِ ضَرْبٍ وَلَا امْتِحَانٍ فَقَالَ النُّعْمَانُ مَا شِئْتُمْ إِنْ شِئْتُمْ أَنْ أَضْرِبَهُمْ فَإِنْ خَرَجَ مَتَاعُكُمْ فَذَاكَ وَإِلَّا أَخَذْتُ مِنْ ظُهُورِكُمْ مِثْلَ مَا أَخَذْتُ مِنْ ظُهُورِهِمْ فَقَالُوا هَذَا حُكْمُكَ فَقَالَ هَذَا حُكْمُ اللَّهِ وَحُكْمُ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد إِنَّمَا أَرْهَبَهُمْ بِهَذَا الْقَوْلِ أَيْ لَا يَجِبُ الضَّرْبُ إِلَّا بَعْدَ الِاعْتِرَافِ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Shafwan] berkata, telah menceritakan kepada kami [Azhar bin Abdullah Al Harazi] ia berkata, \"Barang-barang milik kaum Kala'iyin dicuri, lalu mereka menyakini bahwa pelakunya adalah para tukang tenun. Mereka kemudian mendatangi [Nu'man bin Basyir], salah seorang sahabat Nabi shallallahu 'alaihi wasallam. Nu'man pun menahan para tukang tenun tersebut selama beberapa hari kemudian melepaskannya lagi. Orang-orang dari Kala'iyin itu lalu mendatangi Nu'man dan berkata, \"Kenapa engkau bebaskan mereka tanpa engkau beri pukulan atau hukuman!\" Nu'man menjawab, \"Itu terserah kalian, jika kalian ingin, dan kalau benar barang curian itu ada (terbukti) maka aku akan pukul mereka. Namun jika tidak, maka aku akan memukul punggung kalian sebagaimana aku menghukum mereka.\" Orang-orang itu berkata, \"Beginikah cara kamu mengadili!\" Nu'man menjawab, \"Ini adalah hukum Allah dan hukum Rasul-Nya shallallahu 'alaihi wasallam.\" Abu Dawud berkata, \"Nu'man menakut-nakuti mereka dengan ucapannya tersebut, karena hukuman tidak bisa diterapkan sehingga adanya pengakuan dari pihak tertuduh.\""},"3694":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُهُ مِنْهُ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْطَعُ فِي رُبُعِ دِينَارٍ فَصَاعِدًا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] ia berkata; Aku mendengar hadits itu darinya, dari [Amrah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Nabi shallallahu 'alaihi wasallam memotong tangan pencuri, jika barang yang dicuri senilai seperempat dinar atau lebih.\""},"3695":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَوَهْبُ بْنُ بَيَانٍ قَالَا حَدَّثَنَا ح و حَدَّثَنَا ابْنُ السَّرْحِ قَالَ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةً وَعَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبُعِ دِينَارٍ فَصَاعِدًا قَالَ أَحْمَدُ بْنُ صَالِحٍ الْقَطْعُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Wahb bin Bayan] keduanya berkata; telah menceritakan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu As Sarh] ia berkata; telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Urwah] dan [Amrah] dari ['Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dipotongnya tangan pencuri jika ia mengambil seperempat dinar atau lebih.\" Ahmad bin Shalih berkata, \"Pemotongan itu jika telah sampai kadar seperempat dinar atau lebih.\""},"3696":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memotong (tangan pencuri) senilai baju perang yang harganya tiga dirham.\""},"3697":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ أَنَّ نَافِعًا مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ يَدَ رَجُلٍ سَرَقَ تُرْسًا مِنْ صُفَّةِ النِّسَاءِ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Isma'il bin Umayyah] bahwa [nafi'] -mantan budak (yang telah dimerdekakan oleh) Abdullah bin Umar- menceritakan kepadanya, bahwa [Abdullah bin Umar] menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah memotong tangan seorang laki-laki yang mencuri tameng (dari tempat shalatnya wanita) senilai tiga dirham.\""},"3698":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ أَبِي السَّرِيِّ الْعَسْقَلَانِيُّ وَهَذَا لَفْظُهُ وَهُوَ أَتَمُّ قَالَا حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ رَجُلٍ فِي مِجَنٍّ قِيمَتُهُ دِينَارٌ أَوْ عَشَرَةُ دَرَاهِمَقَالَ أَبُو دَاوُد رَوَاهُ مُحَمَّدُ بْنُ سَلَمَةَ وَسَعْدَانُ بْنُ يَحْيَى عَنْ ابْنِ إِسْحَقَ بِإِسْنَادِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin Abu As Sari Al Asqalani] -ini adalah lafadz darinya, dan ini juga lebih lengkap- dari [Ibnu Numair] dari [Muhammad bin Ishaq] dari [Ayyub bin Musa] dari [Atha] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memotong tangan seorang laki-laki karena mencuri baju perang yang harganya satu dinar, atau sepuluh dirham.\" Abu Dawud berkata, \" [Muhammad bin Salamah] dan [Sa'dan bin Yahya] juga meriwayatkannya dari [Ibnu Ishaq] dengan sanadnya.\""},"3699":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَأَنَّ عَبْدًا سَرَقَ وَدِيًّا مِنْ حَائِطِ رَجُلٍ فَغَرَسَهُ فِي حَائِطِ سَيِّدِهِ فَخَرَجَ صَاحِبُ الْوَدِيِّ يَلْتَمِسُ وَدِيَّهُ فَوَجَدَهُ فَاسْتَعْدَى عَلَى الْعَبْدِ مَرْوَانَ بْنَ الْحَكَمِ وَهُوَ أَمِيرُ الْمَدِينَةِ يَوْمَئِذٍ فَسَجَنَ مَرْوَانُ الْعَبْدَ وَأَرَادَ قَطْعَ يَدِهِ فَانْطَلَقَ سَيِّدُ الْعَبْدِ إِلَى رَافِعِ بْنِ خَدِيجٍ فَسَأَلَهُ عَنْ ذَلِكَ فَأَخْبَرَهُ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ فَقَالَ الرَّجُلُ إِنَّ مَرْوَانَ أَخَذَ غُلَامِي وَهُوَ يُرِيدُ قَطْعَ يَدِهِ وَأَنَا أُحِبُّ أَنْ تَمْشِيَ مَعِي إِلَيْهِ فَتُخْبِرَهُ بِالَّذِي سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَشَى مَعَهُ رَافِعُ بْنُ خَدِيجٍ حَتَّى أَتَى مَرْوَانَ بْنَ الْحَكَمِ فَقَالَ لَهُ رَافِعٌ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ فَأَمَرَ مَرْوَانُ بِالْعَبْدِ فَأُرْسِلَقَالَ أَبُو دَاوُد الْكَثَرُ الْجُمَّارُ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ بِهَذَا الْحَدِيثِ قَالَ فَجَلَدَهُ مَرْوَانُ جَلَدَاتٍ وَخَلَّى سَبِيلَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik bin Anas] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] berkata, \"Seorang budak mencuri pohon kurma kecil dari kebun seseorang, lalu ia menanamnya di kebun milik tuannya. Pemilik pohon itu lalu keluar mencari pohonnya yang telah hilang. Kemudian ia mendapatkannya tengah berada (bersama budak tersebut). Lantas ia membawa budak itu kepada Marwan Ibnul Hakam, gubernur Madinah saat itu. Marwan kemudian memenjarakan budak itu dan ingin memotong tangannya. Maka, majikan budak tersebut berangkat menemui [Rafi' bin Khadij]. Ia bertanya kepadanya tentang hukum dari kasus tersebut. Rafi' kemudian mengabarkan kepadanya, bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hukuman potong tangan karena sebiji kurma atau mayang kurma.\" Laki-laki (majikan budak) itu berkata, \"Marwan telah menahan budak milikku, dan ia ingin memotong tangannya. Maka aku berharap engkau bersedia bersamaku menemui Marwan hingga engkau dapat mengabarkan apa yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Rafi' bin Khadij kemudian berangkat menemui Marwan bersama majikan budak tersebut, ketika telah tiba Rafi' berkata kepada Marwan, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hukuman potong tangan karena sebiji kurma atau mayang kurma.\" Setelah mendengar Rafi', Marwan kemudian membebaskan budak tersebut.\" Abu Dawud berkata, \"Yang dimaksud dengan Al Katsar (mayang kurma) adalah bagian pada pohon kurma yang dapat dimakan.\" Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Yahya] dari [Muhammad bin Yahya bin Habban] dengan hadits yang sama. Ia berkata, \"Marwan kemudian mencambuknya dengan beberapa kali cambukan, setelah itu melepasnya.\""},"3700":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ الثَّمَرِ الْمُعَلَّقِ فَقَالَ مَنْ أَصَابَ بِفِيهِ مِنْ ذِي حَاجَةٍ غَيْرَ مُتَّخِذٍ خُبْنَةً فَلَا شَيْءَ عَلَيْهِ وَمَنْ خَرَجَ بِشَيْءٍ مِنْهُ فَعَلَيْهِ غَرَامَةُ مِثْلَيْهِ وَالْعُقُوبَةُ وَمَنْ سَرَقَ مِنْهُ شَيْئًا بَعْدَ أَنْ يُؤْوِيَهُ الْجَرِينُ فَبَلَغَ ثَمَنَ الْمِجَنِّ فَعَلَيْهِ الْقَطْعُ وَمَنْ سَرَقَ دُونَ ذَلِكَ فَعَلَيْهِ غَرَامَةُ مِثْلَيْهِ وَالْعُقُوبَةُقَالَ أَبُو دَاوُد الْجَرِينُ الْجُوخَانُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Amru bin Syu'aib] dari [Bapaknya] dari kakeknya [Abdullah bin Amru bin Al Ash] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau pernah ditanya tentang kurma yang masih menggantung di pohon? Maka beliau menjawab: \"Barangsiapa makan darinya karena kebutuhan, tidak menyembunyikan (buah yang lain), maka ia tidak berdosa. Barangsiapa keluar dari (kebun) tersebut dengan mengambil sesuatu darinya, maka ia harus mengganti dua kali lipat beserta hukuman tambahan. Barangsiapa mencuri sesuatu darinya setelah dikumpulkan dalam keranjang dan senilai tameng, maka baginya hukuman potong tangan. Dan barangsiapa mencuri sesuatu yang kurang dari nilai tersebut, maka harus mengganti dua kali lipat beserta hukuman tambahan.\" Abu Dawud berkata, \"Al Jarin adalah keranjang kurma.\""},"3701":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ قَالَ أَبُو الزُّبَيْرِ قَالَ جَابِرُ بْنُ عَبْدِ اللَّهِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُنْتَهِبِ قَطْعٌ وَمَنْ انْتَهَبَ نُهْبَةً مَشْهُورَةً فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah mengabarkan kepada kami [Muhammad bin Bakr] berkata, telah menceritakan kepada kami [Ibnu Juraij] ia berkata; [Abu Az Zubair] berkata; [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hukuman potong tangan bagi perampas, dan barangsiapa merampas secara terang-terangan maka ia bukan dari golongan kami.\""},"3702":{"ar":"وَبِهَذَا الْإِسْنَادِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْخَائِنِ قَطْعٌحَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ زَادَ وَلَا عَلَى الْمُخْتَلِسِ قَطْعٌ قَالَ أَبُو دَاوُد هَذَانِ الْحَدِيثَانِ لَمْ يَسْمَعْهُمَا ابْنُ جُرَيْجٍ مِنْ أَبِي الزُّبَيْرِ وَبَلَغَنِي عَنْ أَحْمَدَ بْنِ حَنْبَلٍ أَنَّهُ قَالَ إِنَّمَا سَمِعَهُمَا ابْنُ جُرَيْجٍ مَنْ يَاسِينَ الزَّيَّاتِ قَالَ أَبُو دَاوُد وَقَدْ رَوَاهُمَا الْمُغِيرَةُ بْنُ مُسْلِمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dengan sanad ini pula ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghianat tidak mendapat hukuman potong tangan.\" Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah mengabarkan kepada kami [Isa bin Yunus] dari [ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti dalam hadits tersebut. Namun ia menambahkan, \"Dan bagi orang yang mencopet (korupsi) juga tidak ada hukuman potong tangan.\" Abu Dawud berkata, \"Dua hadits ini belum pernah didengar oleh Ibnu Juraij dari Abu Az Zubair. Telah sampai kepadaku dari jalur Ahmad, bahwa ia berkata, \"Ibnu Juraij mendengar kedua hadits tersebut justru dari Yasin bin Az Zayyat.\" Abu Dawud melanjutkan, \" [Al Mughirah bin Muslim] juga telah meriwayatkannya dari [Abu Az Zubair], dari [Jabir], dari Nabi shallallahu 'alaihi wasallam.\""},"3703":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ ��َدَّثَنَا عَمْرُو بْنُ حَمَّادِ بْنِ طَلْحَةَ حَدَّثَنَا أَسْبَاطٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ حُمَيْدِ ابْنِ أُخْتِ صَفْوَانَ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَكُنْتُ نَائِمًا فِي الْمَسْجِدِ عَلَيَّ خَمِيصَةٌ لِي ثَمَنُ ثَلَاثِينَ دِرْهَمًا فَجَاءَ رَجُلٌ فَاخْتَلَسَهَا مِنِّي فَأُخِذَ الرَّجُلُ فَأُتِيَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِ لِيُقْطَعَ قَالَ فَأَتَيْتُهُ فَقُلْتُ أَتَقْطَعُهُ مِنْ أَجْلِ ثَلَاثِينَ دِرْهَمًا أَنَا أَبِيعُهُ وَأُنْسِئُهُ ثَمَنَهَا قَالَ فَهَلَّا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنِي بِهِقَالَ أَبُو دَاوُد وَرَوَاهُ زَائِدَةُ عَنْ سِمَاكٍ عَنْ جُعَيْدِ بْنِ حُجَيْرٍ قَالَ نَامَ صَفْوَانُ وَرَوَاهُ مُجَاهِدٌ وَطَاوُسٌ أَنَّهُ كَانَ نَائِمًا فَجَاءَ سَارِقٌ فَسَرَقَ خَمِيصَةً مِنْ تَحْتِ رَأْسِهِ وَرَوَاهُ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ فَاسْتَلَّهُ مِنْ تَحْتِ رَأْسِهِ فَاسْتَيْقَظَ فَصَاحَ بِهِ فَأُخِذَ وَرَوَاهُ الزُّهْرِيُّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ قَالَ فَنَامَ فِي الْمَسْجِدِ وَتَوَسَّدَ رِدَاءَهُ فَجَاءَ سَارِقٌ فَأَخَذَ رِدَاءَهُ فَأُخِذَ السَّارِقُ فَجِيءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Amru bin Hammad bin Thalhah] berkata, telah menceritakan kepada kami [Asbath] dari [Simak bin Harb] dari [Humaid bin Ukhti Shafwan] dari [Shafwan bin Umayyah] ia berkata, \"Aku tidur di dalam masjid dengan berselimut kain seharga tiga puluh dirham. Lalu datang seorang laki-laki dan mencuri kain tersebut dariku. laki-laki itu tertangkap dan dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam. Beliau lantas memerintahkan untuk memotong tangannya. Aku mendatangi beliau dan bertanya, \"Apakah engkau akan memotongnya hanya karena tiga puluh dirham? Padahal bisa saja aku jual kain itu dan pembayarannya ditangguhkan?\" Beliau bersabda: \"kenapa hal tersebut tidak kamu lakukan sebelum kamu membawanya kepadaku?\" Abu Dawud berkata, \"Hadits ini juga diriwayatkan oleh [Zaidah] dari [Simak], dari [Ju'aid bin hujair], ia berkata, \" [Shafwan] tidur…\" [Mujahid] dan [Thawus] juga meriwayatkan, bahwasanya Shafwan tertidur, lalu datang seorang pencuri dan mengambil kain dari bahwa kepalanya.\" [Abu Salamah bin 'Abdurrahman] juga meriwayatkan, ia berkata, \"Maling itu mengambilnya dari bawah kepalanya, tetapi Shafwan terbangun dan berteriak sehingga maling itu tertangkap.\" [Az Zuhri] meriwayatkannya dari [Shafwan bin Abdullah], ia berkata, \"Shafwan tidur di masjid, dan ia menjadikan kain selendangnya sebagai bantal. Lalu datang maling mengambil selendangnya tersebut, tetapi maling itu tertangkap dan dibawa ke hadapan Nabi shallallahu 'alaihi wasallam.\""},"3704":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمَخْلَدُ بْنُ خَالِدٍ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ مَخْلَدٌ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ امْرَأَةً مَخْزُومِيَّةً كَانَتْ تَسْتَعِيرُ الْمَتَاعَ فَتَجْحَدُهُ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا فَقُطِعَتْ يَدُهَاقَالَ أَبُو دَاوُد رَوَاهُ جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَوْ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ زَادَ فِيهِ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ خَطِيبًا فَقَالَ هَلْ مِنْ امْرَأَةٍ تَائِبَةٍ إِلَى اللَّهِ عَزَّ وَجَلَّ وَرَسُولِهِ ثَلَاثَ مَرَّاتٍ وَتِلْكَ شَاهِدَةٌ فَلَمْ تَقُمْ وَلَمْ تَتَكَلَّمْ وَرَوَاهُ ابْنُ غَنَجٍ عَنْ نَافِعٍ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ قَالَ فِيهِ فَشَهِدَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Makhlad bin Khalid] secara makna, keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] berkata; [Makhlad] berkata dari [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata, \"Seorang wanita Makhzumiyah meminjam suatu barang kemudian mengingkarinya. Nabi shallallahu 'alaihi wasallam lalu memerintahkan untuk memotong tangannya.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Juwairiyah] dari [Nafi'], dari [Ibnu Umar]. Atau, dari [Shafiyah binti Abu Ubaid]. Dalam riwayat tersebut ditambahkan, bahwa Nabi shallallahu 'alaihi wasallam berdiri khutbah, beliau bersabda: \"Apakah ada seorang wanita yang akan bertaubat kepada Allah Azza Wa Jalla dan Rasul-Nya?.\" Beliau ulangi hingga tiga kali. Wanita (pencuri) itu juga hadir, namun ia enggan untuk berdiri atau berkata-kata.\" [Ibnu Ghanaj] meriwayatkan hadits itu dari [Nafi'], dari [Shafiyah binti Abu Ubaid], dalam hadits itu ia mengatakan, \"Nabi lalu membuat persaksian atas wanita tersebut.\""},"3705":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا أَبُو صَالِحٍ عَنْ اللَّيْثِ قَالَ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ كَانَ عُرْوَةُ يُحَدِّثُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَعَارَتْ امْرَأَةٌ تَعْنِي حُلِيًّا عَلَى أَلْسِنَةِ أُنَاسٍ يُعْرَفُونَ وَلَا تُعْرَفُ هِيَ فَبَاعَتْهُ فَأُخِذَتْ فَأُتِيَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِ يَدِهَا وَهِيَ الَّتِي شَفَعَ فِيهَا أُسَامَةُ بْنُ زَيْدٍ وَقَالَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَحَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كَانَتْ امْرَأَةً مَخْزُومِيَّةً تَسْتَعِيرُ الْمَتَاعَ وَتَجْحَدُهُ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَطْعِ يَدِهَا وَقَصَّ نَحْوَ حَدِيثِ قُتَيْبَةَ عَنْ اللَّيْثِ عَنْ ابْنِ شِهَابٍ زَادَ فَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin faris] berkata, telah menceritakan kepada kami [Abu Shalih] dari [Al Laits] ia berkata; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; [Urwah] menceritakan bahwa ['Aisyah radliallahu 'anha] berkata, \"Seorang wanita meminjam perhiasan, banyak orang yang mengetahuinya namun ia tidak tahu. Wanita itu menjual perhiasan tersebut, sehingga ia ditangkap dan dibawa ke hadapan Nabi shallallahu 'alaihi wasallam. Beliau lantas memerintahkan untuk memotong tangannya, dan wanita itulah yang pernah dimintakan amnesti oleh Usamah bin Zaid, lalu Rasulullah shallallahu 'alaihi wasallam memberi jawaban kepada Usamah sebagaimana yang beliau katakan.\" Telah menceritakan kepada kami [Abbas bin Abdul Azhim] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Aisyah] ia berkata, \"Ada seorang wanita Makhzumiyah meminjam barang kemudian mengingkarinya. Maka Nabi shallallahu 'alaihi wasallam memerintahkan untuk memotong tangannya…lalu ia menceritakan sebagaimana hadits Qutaibah, dari Al Laits, dari Ibnu Syihab. Namun dalam hadits itu ia menambahkan, \"Nabi shallallahu 'alaihi wasallam lalu memotong tangannya.\""},"3706":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الْمُبْتَلَى حَتَّى يَبْرَأَ وَعَنْ الصَّبِيِّ حَتَّى يَكْبُرَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Hammad bin Salamah] dari [hammad] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pena pencatat amal dan dosa itu diangkat dari tiga golongan; orang yang tidur hingga terbangun, orang gila hingga ia waras, dan anak kecil hingga ia balig.\""},"3707":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي ظَبْيَانَ عَنْ ابْنِ عَبَّاسٍ قَالَأُتِيَ عُمَرُ بِمَجْنُونَةٍ قَدْ زَنَتْ فَاسْتَشَارَ فِيهَا أُنَاسًا فَأَمَرَ بِهَا عُمَرُ أَنْ تُرْجَمَ مُرَّ بِهَا عَلَى عَلِيِّ بْنِ أَبِي طَالِبٍ رِضْوَانُ اللَّهِ عَلَيْهِ فَقَالَ مَا شَأْنُ هَذِهِ قَالُوا مَجْنُونَةُ بَنِي فُلَانٍ زَنَتْ فَأَمَرَ بِهَا عُمَرُ أَنْ تُرْجَمَ قَالَ فَقَالَ ارْجِعُوا بِهَا ثُمَّ أَتَاهُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ أَمَا عَلِمْتَ أَنَّ الْقَلَمَ قَدْ رُفِعَ عَنْ ثَلَاثَةٍ عَنْ الْمَجْنُونِ حَتَّى يَبْرَأَ وَعَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّبِيِّ حَتَّى يَعْقِلَ قَالَ بَلَى قَالَ فَمَا بَالُ هَذِهِ تُرْجَمُ قَالَ لَا شَيْءَ قَالَ فَأَرْسِلْهَا قَالَ فَأَرْسَلَهَا قَالَ فَجَعَلَ يُكَبِّرُحَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ نَحْوَهُ وَقَالَ أَيْضًا حَتَّى يَعْقِلَ وَقَالَ وَعَنْ الْمَجْنُونِ حَتَّى يَفِيقَ قَالَ فَجَعَلَ عُمَرُ يُكَبِّرُ حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي جَرِيرُ بْنُ حَازِمٍ عَنْ سُلَيْمَانَ بْنِ مِهْرَانَ عَنْ أَبِي ظَبْيَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ مُرَّ عَلَى عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ بِمَعْنَى عُثْمَانَ قَالَ أَوَ مَا تَذْكُرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ الْمَجْنُونِ الْمَغْلُوبِ عَلَى عَقْلِهِ حَتَّى يَفِيقَ وَعَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّبِيِّ حَتَّى يَحْتَلِمَ قَالَ صَدَقْتَ قَالَ فَخَلَّى عَنْهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Zhabyan] dari [Ibnu Abbas] ia berkata, \"Didatangkan kepada Umar seorang wanita gila yang berbuat zina, Umar lalu minta masukan pendapat kepada orang-orang. Kemudian ia memerintahkan agar wanita itu dirajam. Wanita itu lalu dibawa melewati [Ali bin Abu Thalib] -semoga Allah meridhainya-, ia bertanya, \"Ada apa dengan wanita ini?\" orang-orang menjawab, \"Wanita gila dari bani fulan, ia telah berbuat zina. Dan Umar memerintahkan agar ia dirajam saja.\" Ibnu Abbas berkata, \"Ali kemudian berkata, \"Bawalah ia kembali.\" Ali lantas mendatangi Umar dan berkata, \"Wahai Amirul Mukminin, tidakkah engkau tahu bahwa pena pencatat amal itu diangkat dari tiga golongan manusia; orang gila hingga ia sembuh, orang tidur hingga ia terbangun dan anak kecil hingga ia balig?\" Umar menjawab, \"Tentu.\" Ali bertanya lagi, \"Lalu kenapa wanita ini dirajam?\" Umar menjawab, \"Tidak apa-apa.\" Ali berkata, \"Lepaskanlah ia.\" Ibnu Abbas berkata, \"Umar kemudian membebaskan wanita tersebut. Lalu Umar pun bertakbir.\" Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] seperti hadits tersebut. Ia menyebutkan, \"Hingga berakal.\" Dalam riwayat lain, \"Orang gila hingga ia sadar.\" Perawi berkata, \"Umar kemudian bertakbir.\" Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Jarir bin Hazim] dari [Sulaiman bin Mihran] dari [Abu Zhabyan] dari [Ibnu Abbas] ia berkata, \"(wanita) itu lalu dibawa melewati [Ali bin Abu Thalib] -yakni sama dengan hadits Utsman- ia berkata, \"Tidakkah engkau ingat (wahai Amirul Mukminin) bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Pena pencatat dosa itu diangkat dari tiga golongan; orang gila hingga ia waras, orang tidur hingga ia terbangun dan anak kecil hingga bermimpi basah?\" Umar menjawab, \"Engkau benar.\" Lalu Umar melepaskan wanita itu.\""},"3708":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ أَبِي الْأَحْوَصِ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ الْمَعْنَى عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي ظَبْيَانَ قَالَ هَنَّادٌ الْجَنْبيُّ قَالَأُتِيَ عُمَرُ بِامْرَأَةٍ قَدْ فَجَرَتْ فَأَمَرَ بِرَجْمِهَا فَمَرَّ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَأَخَذَهَا فَخَلَّى سَبِيلَهَا فَأُخْبِرَ عُمَرُ قَالَ ادْعُوا لِي عَلِيًّا فَجَاء�� عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ لَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ الصَّبِيِّ حَتَّى يَبْلُغَ وَعَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الْمَعْتُوهِ حَتَّى يَبْرَأَ وَإِنَّ هَذِهِ مَعْتُوهَةُ بَنِي فُلَانٍ لَعَلَّ الَّذِي أَتَاهَا وَهِيَ فِي بَلَائِهَا قَالَ فَقَالَ عُمَرُ لَا أَدْرِي فَقَالَ عَلِيٌّ عَلَيْهِ السَّلَام وَأَنَا لَا أَدْرِي","id":"Telah menceritakan kepada kami [Hannad] dari [Abu Al Ahwash]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] secara makna, dari [Atha bin As Sa`ib] dari [Abu Zhabyan] berkata; Hannad Al janbi berkata, \"Pernah didatangkan kepada Umar seorang wanita yang berbuat zina, lalu ia memerintahkan agar wanita itu dirajam. Ketika Ali radliallahu 'anhu lewat, ia mengambil wanita itu dan melepaskannya. Umar lalu diberi kabar dengan kejadian tersebut, ia lantas berkata, \"Pangilkanlah Ali agar ia menemuiku.\" [Ali radliallahu 'anhu] kemudian datang dan berkata, \"Wahai Amirul Mukminin, engkau telah mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Pena pencatat amal dan dosa itu diangkat dari tiga golongan; anak kecil hingga ia balig, orang tidur hingga ia bangun dan orang gila hingga ia waras.\" Dan wanita ini adalah wanita gila dari bani Fulan. Mungkin saja perzinaan itu terjadi disaat gilanya kambuh.\" Umar menanggapi, \"Aku tidak tahu.\" Ali langsung menimpali, \"Aku juga tidak tahu.\""},"3709":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ عَنْ أَبِي الضُّحَى عَنْ عَلِيٍّ عَلَيْهِ السَّلَامعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّبِيِّ حَتَّى يَحْتَلِمَ وَعَنْ الْمَجْنُونِ حَتَّى يَعْقِلَقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ جُرَيْجٍ عَنْ الْقَاسِمِ بْنِ يَزِيدَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَ فِيهِ وَالْخَرِفِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Khalid] dari [Abu Adh Dhuha] dari [Ali Alais Salam] dari nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pena pencatat amal dan dosa itu diangkat dari tiga golongan; orang tidur hingga ia bangun, anak kecil hingga ia bermimpi dan orang gila hingga ia berakal.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Ibnu Juraij], dari [Al Qasim bin Yazid] dari [Ali radliallahu 'anhu], dari Nabi shallallahu 'alaihi wasallam.\" Ia menambahkan di dalamnya, \"dan kharif (orang yang kurang akalnya).\""},"3710":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ حَدَّثَنِي عَطِيَّةُ الْقُرَظِيُّ قَالَكُنْتُ مِنْ سَبْيِ بَنِي قُرَيْظَةَ فَكَانُوا يَنْظُرُونَ فَمَنْ أَنْبَتَ الشَّعْرَ قُتِلَ وَمَنْ لَمْ يُنْبِتْ لَمْ يُقْتَلْ فَكُنْتُ فِيمَنْ لَمْ يُنْبِتْحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ بِهَذَا الْحَدِيثِ قَالَ فَكَشَفُوا عَانَتِي فَوَجَدُوهَا لَمْ تَنْبُتْ فَجَعَلُونِي مِنْ السَّبْيِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah mengabarkan kepada kami [Abdul Malik bin Umair] berkata, telah menceritakan kepadaku [Athiyah Al Qurazhi] ia berkata, \"Aku termasuk salah satu dari tawanan bani Quraizhah, mereka mengamati siapa yang telah tumbuh bulu kemaluannya maka akan dibunuh, dan siapa yang belum tumbuh bulu kemaluannya maka tidak akan dibunuh. Sementara aku termasuk orang yang bulu kemaluannya belum tumbuh.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Abdul malik bin Umair] dengan hadits yang sama. Ia berkata, \"Mereka lalu menyingkap auratku, namun mereka tidak mendapati bulu pada kemaluanku, sehingga mereka hanya menjadikan aku sebagai tawanan.\""},"3711":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَضَهُ يَوْمَ أُحُدٍ وَهُوَ ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْهُ وَعَرَضَهُ يَوْمَ الْخَنْدَقِ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَهُحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ قَالَ نَافِعٌ حَدَّثْتُ بِهَذَا الْحَدِيثِ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ فَقَالَ إِنَّ هَذَا الْحَدُّ بَيْنَ الصَّغِيرِ وَالْكَبِيرِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam pernah memeriksa dirinya pada waktu perang uhud, waktu itu umurnya baru empat belas tahun. Sehingga beliau tidak mengizinkan untuk ikut berperang. Dan pada perang Khandaq beliau juga memeriksanya, waktu itu umurnya lima belas tahun, maka beliau pun memberinya izin.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Idris] dari [Ubaidullah bin Umar] ia berkata, \" [Nafi'] berkata, \"Aku telah menceritakan hadits ini kepada Umar bin Abdul Aziz, lalu ia berkata, \"(maka) hadits ini adalah batas untuk membedakan anak kecil dengan orang dewasa.\""},"3712":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ بْنُ شُرَيْحٍ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْقِتْبَانِيِّ عَنْ شِيَيْمِ بْنِ بَيْتَانَ وَيَزِيدَ بْنِ صُبْحٍ الْأَصْبَحِيِّ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ قَالَكُنَّا مَعَ بُسْرِ بْنِ أَرْطَاةَ فِي الْبَحْرِ فَأُتِيَ بِسَارِقٍ يُقَالُ لَهُ مِصْدَرٌ قَدْ سَرَقَ بُخْتِيَّةً فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْطَعُ الْأَيْدِي فِي السَّفَرِ وَلَوْلَا ذَلِكَ لَقَطَعْتُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Haiwah bin Syuraih] dari [Ayyasy bin Ayyasy Al Qitbani] dari [Syiyaim bin Baitan] dan [Yazid bin Shubh Al Ashbahi] dari [Junadah bin Abu Umayyah] ia berkata, \"Ketika aku dan [Busr bin Arthah] berlayar di lautan, seorang pencuri yang bernama mishdar dihadapkan kepada kami. Ia telah mencuri unta yang berleher panjang. Busr bin Arthah berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangan (pencuri) tidak boleh dipotong dalam perjalanan, \" kalaulah bukan karena hal itu, tentu aku sudah memotongnya.\""},"3713":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي عِمْرَانَ عَنْ الْمُشَعَّثِ بْنِ طَرِيفٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ فَقَالَ كَيْفَ أَنْتَ إِذَا أَصَابَ النَّاسَ مَوْتٌ يَكُونُ الْبَيْتُ فِيهِ بِالْوَصِيفِ يَعْنِي الْقَبْرَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ أَوْ مَا خَارَ اللَّهُ وَرَسُولُهُ قَالَ عَلَيْكَ بِالصَّبْرِ أَوْ قَالَ تَصْبِرُقَالَ أَبُو دَاوُد قَالَ حَمَّادُ بْنُ أَبِي سُلَيْمَانَ يُقْطَعُ النَّبَّاشُ لِأَنَّهُ دَخَلَ عَلَى الْمَيِّتِ بَيْتَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Imran] dari [Al Musya'ats bin Tharif] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abu Dzar!\" Aku menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu. Dan semoga kebahagiaan selalu menyertaimu.\" Beliau bersabda: \"Wahai Abu Dzar, bagaimana menurutmu jika manusia mendapati kematian kemudian rumahnya ada dalam kuburan?\" Aku menjawab, \"Allah dan Rasul-Nya lebih tahu, atau ia mengatakan, \"Sebagaimana yang menjadi pilihan Allah dan Rasul-Nya.\" Beliau bersabda: \"Hendaknya engkau bersabar, atau beliau mengatakan, \"bersabarlah.\" Abu Dawud berkata, \"Hammad bin Sulaiman berkata, \"Tangan An Nabbasy (orang yang menggali kuburan untuk mengambil harta mayit) itu harus dipotong, sebab ia memasuki rumah mayit (kuburan).\""},"3714":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ الْهِلَالِيُّ حَدَّثَنَا جَدِّي عَنْ مُصْعَبِ بْنِ ثَابِتِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجِيءَ بِسَارِقٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ فَقَالَ اقْطَعُوهُ قَالَ فَقُطِعَ ثُمَّ جِيءَ بِهِ الثَّانِيَةَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ فَقَالَ اقْطَعُوهُ قَالَ فَقُطِعَ ثُمَّ جِيءَ بِهِ الثَّالِثَةَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ فَقَالَ اقْطَعُوهُ ثُمَّ أُتِيَ بِهِ الرَّابِعَةَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ قَالَ اقْطَعُوهُ فَأُتِيَ بِهِ الْخَامِسَةَ فَقَالَ اقْتُلُوهُ قَالَ جَابِرٌ فَانْطَلَقْنَا بِهِ فَقَتَلْنَاهُ ثُمَّ اجْتَرَرْنَاهُ فَأَلْقَيْنَاهُ فِي بِئْرٍ وَرَمَيْنَا عَلَيْهِ الْحِجَارَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Ubaid bin Aqil Al Hilali] berkata, telah menceritakan kepada kami [Kakekku] dari [Mush'ab bin Tsabit bin Abdullah bin Az Zubair] dari [Muhammad Ibnul Munkadir] dari [Jabir bin Abdullah] ia berkata, \"Seorang pencuri dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Bunuhlah.\" Para sahabat bertanya, \"Wahai Rasulullah, ia hanya mencuri!\" beliau bersabda: \"Kalau begitu, potonglah tangannya.\" Jabir berkata, \"Tangan pencuri itu lantas dipotong.\" Setelah itu, pencuri tersebut kembali dibawa ke hadapan Nabi shallallahu 'alaihi wasallam untuk yang kedua kalinya, beliau lalu bersabda: \"Bunuhlah.\" Para sahabat bertanya, \"Wahai Rasulullah, ia hanya mencuri!\" beliau bersabda: \"Kalau begitu, potonglah tangannya.\" Kemudian pencuri itu kembali dibawa ke hadapan Nabi shallallahu 'alaihi wasallam untuk yang ketiga kalinya, beliau lalu bersabda: \"Bunuhlah.\" Para sahabat berkata, \"Wahai Rasulullah, ia hanya mencuri!\" beliau bersabda: \"Kalau begitu, potonglah.\" Kemudian pencuri itu di bawah ke hadapan Nabi shallallahu 'alaihi wasallam untuk keempat kalinya, beliau bersabda: \"Bunuhlah.\" Para sahabat berkata, \"Wahai Rasulullah, ia hanya mencuri!\" beliau bersabda: \"Kalau begitu, maka potonglah.\" Kemudian pencuri itu di bawah ke hadapan Nabi shallallahu 'alaihi wasallam untuk kelima kalinya, beliau bersabda: \"Bunuhlah.\" Jabir berkata, \"Kami lalu membawanya pergi dan membunuhnya. Setelah itu, kami menyeret mayatnya dan membuangnya ke dalam sumur, kemudian kami melemparinya dengan bebatuan.\""},"3715":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ حَدَّثَنَا الْحَجَّاجُ عَنْ مَكْحُولٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُحَيْرِيزٍ قَالَسَأَلْنَا فَضَالَةَ بْنَ عُبَيْدٍ عَنْ تَعْلِيقِ الْيَدِ فِي الْعُنُقِ لِلسَّارِقِ أَمِنَ السُّنَّةِ هُوَ قَالَ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَارِقٍ فَقُطِعَتْ يَدُهُ ثُمَّ أَمَرَ بِهَا فَعُلِّقَتْ فِي عُنُقِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Umar bin Ali] berkata, telah menceritakan kepada kami [Al Hajjaj] dari [Makhul] dari ['Abdurrahman bin Muhairiz] ia berkata, \"Kami bertanya kepada [Fadhalah bin Ubaid] bagaimana hukum menggantungkan tangan ke leher bagi seorang pencuri, apakah hal itu termasuk sunah?\" ia menjawab, \"Pernah seorang pencuri dibawah ke hadapan Rasulullah shallallahu 'alaihi wasallam, beliau lantas memotong tangannya dan memerintahkan (agar tangannya digantungkan ke leher), maka tangannya digantungkan ke lehernya.\""},"3716":{"ar":"حَدَّثَنَا مُوسَى يَعْنِي ابْنَ إِسْمَعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَرَقَ الْمَمْلُوكُ فَبِعْهُ وَلَوْ بِنَشٍّ","id":"Telah menceritakan kepada kami [Musa] -maksudnya Musa bin Isma'il- berkata, telah menceritakan kepada kami [Abu Awanah] dari [Umar bin Abu Salamah] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak mencuri maka juallah meskipun seharga dua puluh dirham.\""},"3717":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ مِنْ نِسَائِكُمْ فَاسْتَشْهِدُوا عَلَيْهِنَّ أَرْبَعَةً مِنْكُمْ فَإِنْ شَهِدُوا فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ حَتَّى يَتَوَفَّاهُنَّ الْمَوْتُ أَوْ يَجْعَلَ اللَّهُ لَهُنَّ سَبِيلًا }وَذَكَرَ الرَّجُلَ بَعْدَ الْمَرْأَةِ ثُمَّ جَمَعَهُمَا فَقَالَ{ وَاللَّذَانِ يَأْتِيَانِهَا مِنْكُمْ فَآذُوهُمَا فَإِنْ تَابَا وَأَصْلَحَا فَأَعْرِضُوا عَنْهُمَا }فَنَسَحَ ذَلِكَ بِآيَةِ الْجَلْدِ فَقَالَ{ الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ }حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ مَسْعُودٍ عَنْ شِبْلٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجِاهِدٍ قَالَ السَّبِيلُ الْحَدُّ قَالَ سُفْيَانُ{ فَآذُوهُمَا }الْبِكْرَانِ{ فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ }الثَّيِّبَاتُ","id":"Telah menceritakan kepada kami [Amad bin Muhammad bin Tsabit Al Marwazi] berkata, telah menceritakan kepadaku [Ali bin Al Husain] dari [Bapaknya] dari [Yazid bin An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata tentang firman Allah: '(Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya) ' -Qs. An Nisa: 15-. Allah menyebutkan laki-laki setelah perempuan, kemudian Dia menggabungkan keduanya. Allah berfirman: '(Dan terhadap dua orang yang melakukan perbuatan keji di antara kamu, maka berilah hukuman kepada keduanya, kemudian jika keduanya bertaubat dan memperbaiki diri, maka biarkanlah mereka..) ' -Qs. An Nisa: 16-. Ayat ini kemudian dihapus dengan ayat cambuk, Allah berfirman: '(perempuan yang berzina dan laki-laki yang berzina, maka deralah tiap-tiap seorang dari keduanya seratus kali dera…) ' -Qs. An Nuur: 2-. Telah menceritakan kepada kami Ahmad bin Muhammad bin Tsabit berkata, telah menceritakan kepada kami Musa -maksudnya Musa bin Mas'ud- dari Syibl dari Ibnu Abu Najih dari Mujahid ia berkata, \"Kata 'as sabil' maksudnya adalah hukuman had.\" Mujahid berkata, \"Firman Allah 'maka berilah hukuman kepada keduanya', maksudnya adalah pezina yang masih lajang. Sementara firman Allah 'maka kurunglah mereka (wanita-wanita itu) dalam rumah', maksudnya adalah para janda.\""},"3718":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ حَطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا عَنِّي خُذُوا عَنِّي قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الثَّيِّبُ بِالثَّيِّبِ جَلْدُ مِائَةٍ وَرَمْيٌ بِالْحِجَارَةِ وَالْبِكْرُ بِالْبِكْرِ جَلْدُ مِائَةٍ وَنَفْيُ سَنَةٍحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ قَالَا حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورٍ عَنْ الْحَسَنِ بِإِسْنَادِ يَحْيَى وَمَعْنَاهُ قَالَ جَلْدُ مِائَةٍ وَالرَّجْمُ حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا الرَّبِيعُ بْنُ رَوْحِ بْنِ خُلَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ يَعْنِي الْوَهْبِيَّ حَدَّثَنَا الْفَضْلُ بْنُ دَلْهَمٍ عَنْ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ فَقَالَ نَاسٌ لِسَعْدِ بْنِ عُبَادَةَ يَا أَبَا ثَابِتٍ قَدْ نَزَلَتْ الْحُدُودُ لَوْ أَنَّكَ وَجَدْتَ مَعَ امْرَأَتِكَ رَجُلًا كَيْفَ كُنْتَ صَانِعًا قَالَ كُنْتُ ضَارِبَهُمَا بِالسَّيْفِ حَتَّى يَسْكُتَا أَفَأَنَا أَذْهَبُ فَأَجْمَعُ أَرْبَعَةَ شُهَدَاءٍ فَإِلَى ذَلِكَ قَدْ قَضَى الْحَاجَةَ فَانْطَلَقُوا فَاجْتَمَعُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ أَلَمْ تَرَ إِلَى أَبِي ثَابِتٍ قَالَ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَى بِالسَّيْفِ شَاهِدًا ثُمَّ قَالَ لَا لَا أَخَافُ أَنْ يَتَتَابَعَ فِيهَا السَّكْرَانُ وَالْغَيْرَانُ قَالَ أَبُو دَاوُد رَوَى وَكِيعٌ أَوَّلَ هَذَا الْحَدِيثِ عَنْ الْفَضْلِ بْنِ دَلْهَمٍ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّمَا هَذَا إِسْنَادُ حَدِيثِ ابْنِ الْمُحَبَّقِ أَنَّ رَجُلًا وَقَعَ عَلَى جَارِيَةِ امْرَأَتِهِ قَالَ أَبُو دَاوُد الْفَضْلُ بْنُ دَلْهَمٍ لَيْسَ بِالْحَافِظِ كَانَ قَصَّابًا بِوَاسِطَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Al Hasan] dari [Haththan bin Abdullah Ar Raqqasyi] dari [Ubadah bin Ash Shamit] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah dariku, abillah dariku. Allah telah menjadikan bagi wanita-wanita itu hukuman had. Janda dan duda yang berzina, hukumannya adalah dera seratus kali dan dirajam. Perawan dan perjaka yang berzina, maka hukumannya adalah dera seratus kali dan diasingkan selama satu tahun.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] dan [Muhammad bin Ash Shabbah bin Sufyan] keduanya berkata; telah menceritakan kepada kami [Husyaim] dari [Manshur] dari [Al Hasan] dengan sanad dan makna yang sama dengan hadits Yahya. Ia menyebutkan, \"Dera seratus kali dan rajam.\" Telah menceritakan kepada kami [Muhamad bin auf Ath Tha`i] berkata, telah menceritakan kepada kami [Ar rabi' bin rauh bin Khulaid] berkata, telah menceritakan kepada kami [Muhammad bin Khalid] -maksudnya Muhammad bin Khalid Al Wahbi- berkata, telah menceritakan kepada kami [Al Fadhl bin Dalham] dari [Al Hasan] dari [Salamah bin Al Muhabbaq] dari [Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini; Orang-orang berkata kepada Sa'd bin Ubadah, \"Wahai Abu Tsabit, hudud telah ditetapkan. Sekiranya engkau mendapati seorang laki-laki sedang bersama isterimu, maka apa yang engkau lakukan?\" Sa'd menjawab, \"Aku akan membunuh keduanya dengan pedang hingga mereka mati. Sebab tidak masuk akal jika aku pergi mencari empat orang saksi! Jika aku lakukan, tentu mereka telah selesai (melakukan zina).\" Orang-orang itu lalu pergi dan berkumpul di sisi Rasulullah shallallahu 'alaihi wasallam, mereka bertanya, \"Wahai Rasulullah, apa pendapatmu dengan jawaban Abu Tsabit, ia mengatakan begini dan begini?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Cukuplah pedang sebagai saksi.\" Kemudian beliau bersabda lagi: \"Tidak, aku tidak kawatir orang yang lagi marah dan cemburu (suami) akan bertambah mewabah (semua suami yang cemburu main hakim hakim sendiri).\", Abu Daud berkata; [Waki'] meriwayatkan permulaan hadits ini dari [Al Fadhal bin Dahlam] dari [Al Hasan] dari [Qabishah bin Huraits] dari [Salamah bin Al Muhabbaq] dari Nabi shallallahu 'alaihi wasallam, hanyasanya sanad ini (yang disebutkan oleh Waki') adalah sanad hadits Ibnu Al Muhabbaq (yaitu hadits;) \"bahwasanya ada seorang laki-laki yang berbuat zina dengan seorang budak perempuan istrinya\", Abu Daud berkata; \"Al Fadhal bin Dalham bukan seorang yang hafidh (hafal ribuan hadits) namun dia hanya seorang tukang jagal di Washitha\""},"3719":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّ عُمَرَ يَعْنِي ابْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ خَطَبَ فَقَالَإِنَّ اللَّهَ بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ وَأَنْزَلَ عَلَيْهِ الْكِتَابَ فَكَانَ فِيمَا أُنْزِلَ عَلَيْهِ آيَةُ الرَّجْمِ فَقَرَأْنَاهَا وَوَعَيْنَاهَا وَرَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَمْنَا مِنْ بَعْدِهِ وَإِنِّي خَشِيتُ إِنْ طَالَ بِالنَّاسِ الزَّمَانُ أَنْ يَقُولَ قَائِلٌ مَا نَجِدُ آيَةَ الرَّجْمِ فِي كِتَابِ اللَّهِ فَيَضِلُّوا بِتَرْكِ فَرِيضَةٍ أَنْزَلَهَا اللَّهُ تَعَالَى فَالرَّجْمُ حَقٌّ عَلَى مَنْ زَنَى مِنْ الرِّجَالِ وَالنِّسَاءِ إِذَا كَانَ مُحْصَنًا إِذَا قَامَتْ الْبَيِّنَةُ أَوْ كَانَ حَمْلٌ أَوْ اعْتِرَافٌ وَايْمُ اللَّهِ لَوْلَا أَنْ يَقُولَ النَّاسُ زَادَ عُمَرُ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ لَكَتَبْتُهَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abdullah bin Abbas] berkata, \" [Umar Ibnul Khaththab] berpidato, ia mengatakan, \"Sesungguhnya Allah telah mengutus Muhammad shallallahu 'alaihi wasallam dengan kebenaran dan menurunkan kepadanya Al Kitab (Al-Qur'an). Termasuk yang diturunkan kepada beliau adalah ayat rajam. Kami membaca dan memahaminya, Rasulullah shallallahu 'alaihi wasallam melaksanakan (ayat) rajam dan kami juga memberlakukannya setelah beliau. Aku kawatir ketika zaman terus berlalu, lalu ada seseorang mengatakan, 'Kami tidak mendapati ayat rajam dalam Kitabullah'. Maka mereka akan sesat dengan meninggalkan kewajiban yang telah Allah turunkan. Rajam adalah hukum yang pas bagi laki-laki dan perempuan yang berzina dan telah menikah; jika bukti telah ada, atau adanya kehamilan, atau pengakuan. Demi Allah, sekiranya manusia tidak akan mengatakan 'Umar telah menambahi Kitabullah', sungguh aku akan menuliskannya.\""},"3720":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ سَعْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ نُعَيْمِ بْنِ هَزَّالٍ عَنْ أَبِيهِ قَالَكَانَ مَاعِزُ بْنُ مَالِكٍ يَتِيمًا فِي حِجْرِ أَبِي فَأَصَابَ جَارِيَةً مِنْ الْحَيِّ فَقَالَ لَهُ أَبِي ائْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ بِمَا صَنَعْتَ لَعَلَّهُ يَسْتَغْفِرُ لَكَ وَإِنَّمَا يُرِيدُ بِذَلِكَ رَجَاءَ أَنْ يَكُونَ لَهُ مَخْرَجًا فَأَتَاهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ فَأَعْرَضَ عَنْهُ فَعَادَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ فَأَعْرَضَ عَنْهُ فَعَادَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ حَتَّى قَالَهَا أَرْبَعَ مِرَارٍ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ قَدْ قُلْتَهَا أَرْبَعَ مَرَّاتٍ فَبِمَنْ قَالَ بِفُلَانَةٍ فَقَالَ هَلْ ضَاجَعْتَهَا قَالَ نَعَمْ قَالَ هَلْ بَاشَرْتَهَا قَالَ نَعَمْ قَالَ هَلْ جَامَعْتَهَا قَالَ نَعَمْ قَالَ فَأَمَرَ بِهِ أَنْ يُرْجَمَ فَأُخْرِجَ بِهِ إِلَى الْحَرَّةِ فَلَمَّا رُجِمَ فَوَجَدَ مَسَّ الْحِجَارَةِ جَزِعَ فَخَرَجَ يَشْتَدُّ فَلَقِيَهُ عَبْدُ اللَّهِ بْنُ أُنَيْسٍ وَقَدْ عَجَزَ أَصْحَابُهُ فَنَزَعَ لَهُ بِوَظِيفِ بَعِيرٍ فَرَمَاهُ بِهِ فَقَتَلَهُ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ هَلَّا تَرَكْتُمُوهُ لَعَلَّهُ أَنْ يَتُوبَ فَيَتُوبَ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Sa'd] ia berkata; telah menceritakan kepadaku [Yazid bin Nu'aim bin Hazzal] dari [Bapaknya] ia berkata, \"Ma'iz bin Malik adalah seorang anak yatim yang diasuh oleh bapakku. Dan ia pernah berzina dengan seorang budak wanita dari suatu kampung. Bapakku lalu berkata kepadanya, \"Datanglah kepada Rasulullah shallallahu 'alaihi wasallam, kabarkan kepada beliau dengan apa yang telah engkau lakukan, semoga saja beliau mau memintakan ampun untukmu.\" Hanyasanya ayahku menginginkan hal itu agar Maiz mendapatkan jalan keluar, lalu ia bergegas menemui Rasulullah. Ma'iz lantas berkata, \"Wahai Rasulullah, aku telah berzina, maka laksanakanlah hukum Kitabullah terhadapku!\" Beliau berpaling darinya. Maka Ma'iz mengulangi lagi, \"Wahai Rasulullah, aku telah berzina, maka laksanakanlah hukum Kitabullah terhadapku!\" Beliau berpaling. Ma'iz mengulanginya lagi, \"Wahai Rasulullah, aku telah berzina, maka laksanakanlah hukum Kitabullah terhadapku!\" Ia ulangi hal itu hingga empat kali. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Engkau telah mengatakannya hingga empat kali, lalu dengan siapa kamu melakukannya?\" Ma'iz menjawab, \"Dengan Fulanah.\" Beliau bertanya lagi: \"Apakah menidurinya?\" Ma'iz menjawab, \"Ya.\" beliau bertanya lagi: \"Apakah kamu menyentuhnya?\" Ma'iz menjawab, \"Ya.\" beliau bertanya lagi: \"Apakah kamu menyetubuhinya?\" Ma'iz menjawab, \"Ya.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk merajamnya. Ma'iz lantas dibawa ke padang pasir, maka ketika ia sedang dirajam dan mulai merasakan sakitnya terkena lemparan batu, ia tidak tahan dan lari dengan kencang. Namun ia bertemu dengan Abdullah bin Unais, orang-orang yang merajam Ma'iz sudah tidak sanggup lagi (lelah), maka Abdullah mendorongnya dengan tulang unta, ia melempari Ma'iz dengan tulang tersebut hingga tewas. Kemudian Abdullah menemui Nabi shallallahu 'alaihi wasallam dan menyebutkan kejadian tersebut, beliau bersabda: \"Kenapa kalian tidak membiarkannya, siapa tahu ia bertaubat dan Allah menerima taubatnya.\""},"3721":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَ��َةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ ذَكَرْتُ لِعَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ قِصَّةَ مَاعِزِ ابْنِ مَالِكٍ فَقَالَ لِي حَدَّثَنِي حَسَنُ بْنُ مُحَمَّدِ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَحَدَّثَنِي ذَلِكَ مِنْ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا تَرَكْتُمُوهُ مَنْ شِئْتُمْ مِنْ رِجَالِ أَسْلَمَ مِمَّنْ لَا أَتَّهِمُ قَالَ وَلَمْ أَعْرِفْ هَذَا الْحَدِيثَ قَالَ فَجِئْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ فَقُلْتُ إِنَّ رِجَالًا مِنْ أَسْلَمَ يُحَدِّثُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمْ حِينَ ذَكَرُوا لَهُ جَزَعَ مَاعِزٍ مِنْ الْحِجَارَةِ حِينَ أَصَابَتْهُ أَلَّا تَرَكْتُمُوهُ وَمَا أَعْرِفُ الْحَدِيثَ قَالَ يَا ابْنَ أَخِي أَنَا أَعْلَمُ النَّاسِ بِهَذَا الْحَدِيثِ كُنْتُ فِيمَنْ رَجَمَ الرَّجُلَ إِنَّا لَمَّا خَرَجْنَا بِهِ فَرَجَمْنَاهُ فَوَجَدَ مَسَّ الْحِجَارَةِ صَرَخَ بِنَا يَا قَوْمُ رُدُّونِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ قَوْمِي قَتَلُونِي وَغَرُّونِي مِنْ نَفْسِي وَأَخْبَرُونِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ قَاتِلِي فَلَمْ نَنْزَعْ عَنْهُ حَتَّى قَتَلْنَاهُ فَلَمَّا رَجَعْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرْنَاهُ قَالَ فَهَلَّا تَرَكْتُمُوهُ وَجِئْتُمُونِي بِهِ لِيَسْتَثْبِتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُ فَأَمَّا لِتَرْكِ حَدٍّ فَلَا قَالَ فَعَرَفْتُ وَجْهَ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar bin maisarah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Muhammad bin Ishaq] ia berkata; Aku menceritakan kisah Ma'iz bin Malik kepada [Ashim bin Umar bin Qatadah], lalu ia berkata kepadaku; telah menceritakan kepadaku [Hasan bin Muhammad bin Ali bin Abu Thalib] ia berkata, \"Aku mendengar kisah itu dari sabda Rasulullah shallallahu 'alaihi wasallam, 'Mengapa kalian tidak membiarkannya' dari orang-orang bani Aslam yang aku tidak merasa ragu dengan mereka.\" Hasan bin Muhammad berkata lagi, \"Tetapi aku tidak tahu hadits ini.\" Aku (Muhammad bin Ishaq) lalu mendatangi [Jabir bin Abdullah], dan kukatakan kepadanya, \"Beberapa lelaki dari bani Aslam menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam pernah berkata kepada mereka 'Mengapa kalian tidak membiarkan (Ma'iz lari) saja? ', yakni ketika mereka menceritakan tentang kejadian kaburnya Ma'iz karena tidak tahan dengan sakitnya lemparan batu, dan aku juga tidak tahu keberadaan hadits tersebut.\" Jabir berkata, \"Wahai keponakanku, aku adalah orang yang paling tahu dengan hadits ini, karena aku termasuk orang yang ikut merajam Ma'iz. Ketika kami keluar dan merajam Ma'iz, dan ia merasakan sakitnya lemparan batu, maka ia kesakitan dan berteriak kepada kami, \"Wahai kaum, kembalikanlah aku kepada Rasulullah shallallahu 'alaihi wasallam. Sungguh, kaumku telah menipuku dan ingin membunuhku. Mereka kabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam tidak akan membunuhku.\" Namun kami tidak berhenti merajam Ma'iz, sehingga kami pun membunuhnya. Maka ketika kami kembali dan kami kabarkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Kenapa kalian tidak biarkan saja, lalu kalian bawa ia kemari?\" Hal itu beliau lakukan untuk mendapat kepastian darinya, bukan untuk melepaskan hukuman had.\" Hasan bin Muhammad berkata, \"Dari situlah aku tahu konteks hadits itu sebenarnya.\""},"3722":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ مَاعِزَ بْنَ مَالِكٍ حِينَ جِيءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا قَصِيرًا أَعْضَلَ لَيْسَ عَلَيْهِ رِدَاءٌ فَشَهِدَ عَلَى نَفْسِهِ أَرْبَعَ مَرَّاتٍ أَنَّهُ قَدْ زَنَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَعَلَّكَ قَبَّلْتَهَا قَالَ لَا وَاللَّهِ إِنَّهُ قَدْ زَنَى الْآخِرُ قَالَ فَرَجَمَهُ ثُمَّ خَطَبَ فَقَالَ أَلَا كُلَّمَا نَفَرْنَا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ خَلَفَ أَحَدُهُمْ لَهُ نَبِيبٌ كَنَبِيبِ التَّيْسِ يَمْنَحُ إِحْدَاهُنَّ الْكُثْبَةَ أَمَا إِنَّ اللَّهَ إِنْ يُمَكِّنِّي مِنْ أَحَدٍ مِنْهُمْ إِلَّا نَكَلْتُهُ عَنْهُنَّحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سِمَاكٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ بِهَذَا الْحَدِيثِ وَالْأَوَّلُ أَتَمُّ قَالَ فَرَدَّهُ مَرَّتَيْنِ قَالَ سِمَاكٌ فَحَدَّثْتُ بِهِ سَعِيدَ بْنَ جُبَيْرٍ فَقَالَ إِنَّهُ رَدَّهُ أَرْبَعَ مَرَّاتٍ حَدَّثَنَا عَبْدُ الْغَنِيِّ بْنُ أَبِي عَقِيلٍ الْمِصْرِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ قَالَ قَالَ شُعْبَةُ فَسَأَلْتُ سِمَاكًا عَنْ الْكُثْبَةِ فَقَالَ اللَّبَنُ الْقَلِيلُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Simak] dari [Jabir bin Samurah] ia berkata, \"Saat Ma'iz bin Malik dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, aku melihat bahwa ia adalah seorang laki-laki pendek, berotot besar dan tidak mengenakan selendang. Ia bersaksi -sebanyak empat kali- atas dirinya sendiri bahwa ia telah berbuat zina. Rasulullah shallallahu 'alaihi wasallam lalu bertanya: \"Mungkin kamu hanya menciumnya?\" ia menjawab, \"Demi Allah, tidak! Ma'iz justru mengakui bahwa ia benar-benar telah berzina. Jabir berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian merajamnya kemudian berpidato: \"Ketahuilah, ketika kita sedang jihad di jalan Allah 'azza wajalla, ada seorang laki-laki (yang bertugas menjaga para wanita di rumah) dari mereka suka mendesah layaknya kambing bandot. Ia memberikan kepada salah seorang wanita dari mereka sesuatu yang sedikit (memberi sedikit susu untuk menipu, kemudian menzinainya). Demi Allah, jika Allah memberiku kemampuan untuk menangkapnya, maka aku akan menghukumnya.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dari [Muhammad bin Ja'far] dari [Syu'bah] dari [Simak] ia berkata; Aku mendengar [Jabir bin Samurah] dengan hadits ini, tapi hadits yang pertama lebih lengkap. Ia (perawi) berkata, \"Ia ulangi hingga dua kali.\" [Simak] berkata, \"Hadits itu kemudian aku ceritakan kepada [Sa'id bin Jubair], ia balik berkata, \"(Bahkan) ia mengulanginya hingga empat kali.\" Telah menceritakan kepada kami Abdul Ghani bin Abu Aqil Al Mishri berkata, telah menceritakan kepada kami Khalid -makasudnya Khalid bin 'Abdurrahman- ia berkata; Syu'bah berkata; Aku pernah bertanya Simak maksud dari 'Al Kutsbah' (sesuatu yang sedikit), lalu ia menjawab, \"Itu adalah susu yang sedikit.\""},"3723":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَاعِزِ بْنِ مَالِكٍ أَحَقٌّ مَا بَلَغَنِي عَنْكَ قَالَ وَمَا بَلَغَكَ عَنِّي قَالَ بَلَغَنِي عَنْكَ أَنَّكَ وَقَعْتَ عَلَى جَارِيَةِ بَنِي فُلَانٍ قَالَ نَعَمْ فَشَهِدَ أَرْبَعَ شَهَادَاتٍ فَأَمَرَ بِهِ فَرُجِمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Simak bin Harb] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ma'iz bin Malik: \"Apa benar berita yang sampai kepadaku tentang dirimu?\" Ma'iz balik bertanya, \"Berita apa yang telah engkau dengar tentang aku?\" beliau menjawab: \"Telah sampai kabar kepadaku bahwa engkau telah berzina dengan seorang budak wanita dari bani fulan.\" Ma'iz berkata, \"Benar.\" Lalu ia bersaksi hingga empat kali, Nabi kemudian memerintahkan untuk merajamnya, maka Ma'iz pun dirajam.\""},"3724":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا جَرِيرٌ حَدَّثَنِي يَعْلَى عَنْ عِكْرِمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُقْبَةُ بْنُ مُكْرَمٍ قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يَعْلَى يَعْنِي ابْنَ حَكِيمٍ يُحَدِّثُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِمَاعِزِ بْنِ مَالِكٍ لَعَلَّكَ قَبَّلْتَ أَوْ غَمَزْتَ أَوْ نَظَرْتَ قَالَ لَا قَالَ أَفَنِكْتَهَا قَالَ نَعَمْ قَالَ فَعِنْدَ ذَلِكَ أَمَرَ بِرَجْمِهِوَلَمْ يَذْكُرْ مُوسَى عَنْ ابْنِ عَبَّاسٍ وَهَذَا لَفْظُ وَهْبٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Jarir] berkata, telah menceritakan kepadaku [Ya'la] dari [Ikrimah] bahwa Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] dan [Uqbah bin Mukram] keduanya berkata; telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] ia berkata; aku mendengar [Ya'la] -maksudnya Ya'la bin Hakim- menceritakan dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bertanya kepada Ma'iz bin Malik: \"Mungkin kamu hanya mencium, melirik atau meraba saja?\" Ma'iz menjawab, \"Tidak.\" Beliau bertanya: \"Apa kamu telah menggaulinya?\" Ma'iz berkata, \"Ya.\" Ibnu Abbas berkata, \"Maka saat itulah beliau memerintahkan untuk merajamnya.\" Namun Musa tidak menyebutkan dari Ibnu Abbas. Dan ini adalah lafadz Wahb. "},"3725":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الصَّامِتِ ابْنَ عَمِّ أَبِي هُرَيْرَةَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُجَاءَ الْأَسْلَمِيُّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَهِدَ عَلَى نَفْسِهِ أَنَّهُ أَصَابَ امْرَأَةً حَرَامًا أَرْبَعَ مَرَّاتٍ كُلُّ ذَلِكَ يُعْرِضُ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ فِي الْخَامِسَةِ فَقَالَ أَنِكْتَهَا قَالَ نَعَمْ قَالَ حَتَّى غَابَ ذَلِكَ مِنْكَ فِي ذَلِكَ مِنْهَا قَالَ نَعَمْ قَالَ كَمَا يَغِيبُ الْمِرْوَدُ فِي الْمُكْحُلَةِ وَالرِّشَاءُ فِي الْبِئْرِ قَالَ نَعَمْ قَالَ فَهَلْ تَدْرِي مَا الزِّنَا قَالَ نَعَمْ أَتَيْتُ مِنْهَا حَرَامًا مَا يَأْتِي الرَّجُلُ مِنْ امْرَأَتِهِ حَلَالًا قَالَ فَمَا تُرِيدُ بِهَذَا الْقَوْلِ قَالَ أُرِيدُ أَنْ تُطَهِّرَنِي فَأَمَرَ بِهِ فَرُجِمَ فَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَيْنِ مِنْ أَصْحَابِهِ يَقُولُ أَحَدُهُمَا لِصَاحِبِهِ انْظُرْ إِلَى هَذَا الَّذِي سَتَرَ اللَّهُ عَلَيْهِ فَلَمْ تَدَعْهُ نَفْسُهُ حَتَّى رُجِمَ رَجْمَ الْكَلْبِ فَسَكَتَ عَنْهُمَا ثُمَّ سَارَ سَاعَةً حَتَّى مَرَّ بِجِيفَةِ حِمَارٍ شَائِلٍ بِرِجْلِهِ فَقَالَ أَيْنَ فُلَانٌ وَفُلَانٌ فَقَالَا نَحْنُ ذَانِ يَا رَسُولَ اللَّهِ قَالَ انْزِلَا فَكُلَا مِنْ جِيفَةِ هَذَا الْحِمَارِ فَقَالَا يَا نَبِيَّ اللَّهِ مَنْ يَأْكُلُ مِنْ هَذَا قَالَ فَمَا نِلْتُمَا مِنْ عِرْضِ أَخِيكُمَا آنِفًا أَشَدُّ مِنْ أَكْلٍ مِنْهُ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهُ الْآنَ لَفِي أَنْهَارِ الْجَنَّةِ يَنْقَمِسُ فِيهَاحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ ابْنِ عَمِّ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ بِنَحْوِهِ زَادَ وَاخْتَلَفُوا عَلَيَّ فَقَالَ بَعْضُهُمْ رُبِطَ إِلَى شَجَرَةٍ وَقَالَ بَعْضُهُمْ وُقِفَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ['Abdurrahman bin Ash Shamit] -anak pamannya Abu Hurairah- ia mengabarkan kepadanya, Bahwasanya ia mendengar [Abu Hurairah] berkata, \"Al Aslami datang menemui Nabi shallallahu 'alaihi wasallam, ia bersaksi atas dirinya sendiri bahwa ia pernah berzina dengan seorang wanita ia ulangi pernyataannya itu hingga empat kali, dan setiap itu pula Nabi shallallahu 'alaihi wasallam selalu berpaling. Pada kali kelimanya, Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah benar kamu melakukan itu?\" ia menjawab, \"Benar.\" Beliau bertanya lagi: \"Hingga waktu itu (kemaluanmu) hilang (masuk ke dalam kemaluannya)?\" ia menjawab, \"Ya.\" beliau bertanya lagi: \"Seperti pensil celak masuk ke dalam botolnya, dan seperti tali timba masuk ke dalam sumur?\" ia menjawab, \"Ya.\" beliau bertanya lagi: \"Apakah kamu tahu zina itu apa?\" ia menjawab, \"Ya. Aku mendatangi wanita yang haram bagiku layaknya laki-laki yang mendatangi isterinya secara halal.\" Beliau bertanya lagi: \"Apa yang kamu inginkan dari jawaban itu?\" Ia menjawab, \"Aku ingin agar engkau membersihkan dosaku.\" Beliau lalu memerintahkan agar ia dirajam, maka ia pun dirajam. Kemudian Nabi shallallahu 'alaihi wasallam mendengar dua orang sahabatnya bercakap-cakap, salah seorang dari keduanya berkata kepada yang lain, \"Lihatlah kepada laki-laki ini, Allah telah menutupi dirinya (jika ia tidak mengaku), namun dirinya tidak mau diam (justru mengaku), maka ia pun dirajam layaknya anjing.\" Beliau diam saja, hingga ketika beliau berjalan beberapa saat dan melewati bangkai, beliau bersabda: \"Di mana Fulan dan Fulan tadi?\", keduanya menjawab; \"Kami wahai Rasulullah!.\", beliau bersabda; \"Kalian berdua silahkan turun, ambil dan makanlah bangkai himar ini!\" keduanya lalu berkata, \"Wahai Rasulullah, siapakah orang yang mau makan bangkai ini.\" beliau bersabda: \"Apa yang kalian bicarakan berkenaan dengan harga diri saudara kalian tadi, itu lebih buruk dari bangkai ini. Demi Dzat Yang jiwaku ada dalam tangan-Nya, sungguh sekarang ini sahabat kalian (yang dirajam) tengah berada di antara sungai-sungai surga di berenang di dalamnya.\" Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abu Ashim] berkata, telah menceritakan kepada kami [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] dari [Anak pamannya Abu Hurairah] dari [Abu Hurairah] sebagaimana hadits tersebut. Ia (Hasan bin Ali) menambahkan, \"mereka berselisih denganku, sebagian mereka berkata, \"Ikat saja di batang pohon, \" sedangkan yang lain berkata, \"Suruh berdiri.\""},"3726":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ وَالْحَسَنُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا مِنْ أَسْلَمَ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَرَفَ بِالزِّنَا فَأَعْرَضَ عَنْهُ ثُمَّ اعْتَرَفَ فَأَعْرَضَ عَنْهُ حَتَّى شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبِكَ جُنُونٌ قَالَ لَا قَالَ أُحْصِنْتَ قَالَ نَعَمْ قَالَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ فِي الْمُصَلَّى فَلَمَّا أَذَلَقَتْهُ الْحِجَارَةُ فَرَّ فَأُدْرِكَ فَرُجِمَ حَتَّى مَاتَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا وَلَمْ يُصَلِّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutawakkil Al Asqalani] dan [Al Hasan bin Ali] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdullah] bahwa seorang laki-laki dari Aslam datang menemui Rasulullah shallallahu 'alaihi wasallam mengakui bahwa dirinya telah berzina, namun beliau berpaling darinya. Laki-laki itu kembali mengakuinya dan beliau berpaling, sehingga laki-laki itu bersaksi (mengaku) sebanyak empat kali. Akhirnya Nabi shallallahu 'alaihi wasallam bertanya kepadanya: \"Apakah kamu gila?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah kamu sudah menikah?\" ia menjawab, \"Ya.\" Nabi shallallahu 'alaihi wasallam lalu memerintahkan untuk merajamnya, ia pun dirajam di tempat yang lapang. Maka ketika ia merasakan sakit karena lemparan batu, ia kabur. Lalu ia ditangkap dan dirajam lagi hingga meninggal. Nabi shallallahu 'alaihi wasallam lalu berkomentar untuk laki-laki itu, \"Ia dalam kebaikan.\" Namun beliau tidak menshalatinya.\""},"3727":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى بْنِ الْحَارِثِ حَدَّثَنَا أَبِي عَنْ غَيْلَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَنْكَهَ مَاعِزًا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Ya'la Ibnul Harits] berkata, telah menceritakan kepada kami [Bapakku] dari [Ghailan] dari [Alqamah bin Martsad] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam mencium (bau) mulut Ma'iz (mungkin jika ada bau khamer).\""},"3728":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ الْأَهْوَازِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا بُشَيْرُ بْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكُنَّا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَتَحَدَّثُ أَنَّ الْغَامِدِيَّةَ وَمَاعِزَ بْنَ مَالِكٍ لَوْ رَجَعَا بَعْدَ اعْتِرَافِهِمَا أَوْ قَالَ لَوْ لَمْ يَرْجِعَا بَعْدَ اعْتِرَافِهِمَا لَمْ يَطْلُبْهُمَا وَإِنَّمَا رَجَمَهُمَا عِنْدَ الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Ishaq Al Ahwazi] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Busyair Ibnul Muhajir] berkata, telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Kami para sahabat Rasulullah shallallahu 'alaihi wasallam, pernah memperbincangkan kisah wanita Al Ghamidiyah dan Ma'iz bin Malik, andaikata keduanya mau mencabut pengakuannya, atau ia mengatakan, \"tidak kembali menghadap Nabi setelah mengakui, tentu beliau tidak akan mencari mereka lagi (minta pengakuannya kembali). Beliau baru merajam mereka ketika pengakuan itu berulang hingga empat kali.\""},"3729":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَفْصٍ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا أَتَاهُ فَأَقَرَّ عِنْدَهُ أَنَّهُ زَنَى بِامْرَأَةٍ سَمَّاهَا لَهُ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَرْأَةِ فَسَأَلَهَا عَنْ ذَلِكَ فَأَنْكَرَتْ أَنْ تَكُونَ زَنَتْ فَجَلَدَهُ الْحَدَّ وَتَرَكَهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Thalq bin Ghannam] berkata, telah menceritakan kepada kami [Abdussalam bin Hafsh] berkata, telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd] dari Nabi shallallahu 'alaihi wasallam, bahwa ada seorang laki-laki yang datang menemui beliau dan mengaku telah berzina dengan seorang wanita yang namanya ia sebutkan kepada beliau. Rasulullah shallallahu 'alaihi wasallam lalu memanggil wanita itu dan bertanya kepadanya tentang kebenaran dari pengakuan laki-laki itu. Namun wanita tersebut tidak mengakuinya, maka Nabi mendera laki-laki itu dan membiarkan wanita tersebut.\""},"3730":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ أَنَّ هِشَامًا الدَّسْتُوَائِيَّ وَأَبَانَ ابْنَ يَزِيدَ حَدَّثَاهُمْ الْمَعْنَى عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ امْرَأَةً قَالَ فِي حَدِيثِ أَبَانَ مِنْ جُهَيْنَةَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّهَا زَنَتْ وَهِيَ حُبْلَى فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِيًّا لَهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسِنْ إِلَيْهَا فَإِذَا وَضَعَتْ فَجِئْ بِهَا فَلَمَّا أَنْ وَضَعَتْ جَاءَ بِهَا فَأَمَرَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشُكَّتْ عَلَيْهَا ثِيَابُهَا ثُمَّ أَمَرَ بِهَا فَرُجِمَتْ ثُمَّ أَمَرَهُمْ فَصَلُّوا عَلَيْهَا فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهَا وَقَدْ زَنَتْ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ تَابَتْ تَوْبَةً لَوْ قُسِّمَتْ بَيْنَ سَبْعِينَ مِنْ أَهْلِ الْمَدِينَةِ لَوَسِعَتْهُمْ وَهَلْ وَجَدْتَ أَفْضَلَ مِنْ أَنْ جَادَتْ بِنَفْسِهَا لَمْ يَقُلْ عَنْ أَبَانَ فَشُكَّتْ عَلَيْهَا ثِيَابُهَاحَدَّثَنَا مُحَمَّدُ بْنُ الْوَزِيرِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ فَشُكَّتْ عَلَيْهَا ثِيَابُهَا يَعْنِي فَشُدَّتْ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] bahwa [Hisyam Ad Dustuwa`i] dan [Aban bin Yazid] keduanya menceritakan kepada mereka secara makna, dari [Yahya] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] bahwa ada seorang wanita -dalam hadits Aban ia dari Juhainah- datang kepada Nabi shallallahu 'alaihi wasallam dan mengatakan bahwa dirinya telah berzina dan sedang mengandung. Nabi shallallahu 'alaihi wasallam kemudian memanggil walinya, Rasulullah shallallahu 'alaihi wasallam bersabda kepada wali tersebut: \"Perlakukan ia dengan baik, jika ia telah melahirkan, maka bawalah ia kemari.\" Ketika wanita itu telah melahirkan, ia dibawa ke hadapan nabi shallallahu 'alaihi wasallam, beliau pun memerintahkan agar hukuman dilaksanakan. Pakaian wanita itu kemudian dirapatkan (agar auratnya tidak tersingkap), dan beliau kembali memerintahkan agar hukuman segera dilaksanakan, maka ia pun dirajam. Beliau lalu memerintahkan para sahabatnya (untuk menshalatkannya), mereka pun menshalatinya. Umar lantas berkata, \"Wahai Rasulullah, kenapa engkau menshalatinya padahal ia telah berzina!\" beliau bersabda: \"Demi Dzat yang jiwaku ada dalam tangan-Nya, ia telah bertaubat, dan sekiranya taubatnya dibagikan kepada tujuh puluh penduduk Madinah maka akan mencukupi. Apakah engkau menemukan yang lebih utama dari upaya wanita ini, ia datang sendiri dengan kerelaan hati?\". Namun perawi tidak menyebutkan dari Aban dengan lafadz 'Pakaian wanita itu kemudian dirapatkan (agar auratnya tidak tersingkap) '. Telah menceritakan kepada kami [Muhammad Ibnul Wazir Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] ia berkata, \"Pakaian wanita itu kemudian dirapatkan (agar auratnya tidak tersingkap), maksudnya adalah diikat.\""},"3731":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ بُشَيْرِ بْنِ الْمُهَاجِرِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ امْرَأَةً يَعْنِي مِنْ غَامِدٍ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي قَدْ فَجَرْتُ فَقَالَ ارْجِعِي فَرَجَعَتْ فَلَمَّا أَنْ كَانَ الْغَدُ أَتَتْهُ فَقَالَتْ لَعَلَّكَ أَنْ تَرُدَّنِي كَمَا رَدَدْتَ مَاعِزَ بْنَ مَالِكٍ فَوَاللَّهِ إِنِّي لَحُبْلَى فَقَالَ لَهَا ارْجِعِي فَرَجَعَتْ فَلَمَّا كَانَ الْغَدُ أَتَتْهُ فَقَالَ لَهَا ارْجِعِي حَتَّى تَلِدِي فَرَجَعَتْ فَلَمَّا وَلَدَتْ أَتَتْهُ بِالصَّبِيِّ فَقَالَتْ هَذَا قَدْ وَلَدْتُهُ فَقَالَ لَهَا ارْجِعِي فَأَرْضِعِيهِ حَتَّى تَفْطِمِيهِ فَجَاءَتْ بِهِ وَقَدْ فَطَمَتْهُ وَفِي يَدِهِ شَيْءٌ يَأْكُلُهُ فَأَمَرَ بِالصَّبِيِّ فَدُفِعَ إِلَى رَجُلٍ مِنْ الْمُسْلِمِينَ وَأَمَرَ بِهَا فَحُفِرَ لَهَا وَأَمَرَ بِهَا فَرُجِمَتْ وَكَانَ خَالِدٌ فِيمَنْ يَرْجُمُهَا فَرَجَمَهَا بِحَجَرٍ فَوَقَعَتْ قَطْرَةٌ مِنْ دَمِهَا عَلَى وَجْنَتِهِ فَسَبَّهَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْلًا يَا خَالِدُ فَوَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ تَابَتْ تَوْبَةً لَوْ تَابَهَا صَاحِبُ مَكْسٍ لَغُفِرَ لَهُ وَأَمَرَ بِهَا فَصُلِّيَ عَلَيْهَا وَدُفِنَتْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] berkata, telah mengabarkan kepada kami [Isa bin Yunus] dari [Busyair Ibnul Muhajir] berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Seorang wanita -dari Ghamid- datang menemui Nabi shallallahu 'alaihi wasallam, ia berkata, \"Aku telah berbuat kehinaan (zina).\" Beliau bersabda: \"Pulanglah.\" Wanita itu lalu kembali pulang. Keesokan harinya ia datang lagi kepada beliau dan berkata, \"Apakah engkau akan menyuruhku untuk kembali lagi sebagaimana engkau perintahkan kepada Ma'iz! Demi Allah, sesungguhnya aku telah hamil.\" Beliau lalu bersabda kepadanya: \"Pulanglah.\" Wanita itu lalu kembali pulang. Keesokan harinya ia datang lagi kepada beliau, maka beliau pun bersabda: \"Kembalilah pulang hingga engkau melahirkan.\" Wanita itu lalu pulang. Ketika ia telah melahirkan, ia datang lagi menghadap Nabi shallallahu 'alaihi wasallam dengan membawa bayi, ia berkata, \"Aku telah melahirkan bayi ini.\" Beliau lalu bersabda kepadanya: \"Pulang dan susuilah anak itu hingga engkau menyapihnya.\" Setelah menyapihnya, wanita itu kembali menghadap Nabi shallallahu 'alaihi wasallam dengan membawa bayinya yang sedang makan sesuatu ditangannya. Beliau memerintahkan agar anak itu diserahkan kepada salah seorang laki-laki dari kaum muslimin, selanjutnya beliau memerintahkan (untuk merajamnya). Lalu dibuatlah lubang untuknya, hingga wanita itu dimasukkan ke dalam lubang dan dirajam. Dan Khalid adalah salah seorang yang ikut merajam wanita itu, ia melempar wanita itu dengan batu hingga darahnya mengenainya, ia pun mencela wanita tersebut. Nabi shallallahu 'alaihi wasallam kemudian bersabda kepada Khalid: \"Tunggu wahai Khalid! Demi Dzat yang jiwaku ada dalam tangan-Nya, ia telah bertaubat, sekiranya taubatnya dilakukan oleh seorang penganiaya, pasti ia akan diampuni.\" Beliau lantas memerintahkan (untuk mengurus jenazah wanita itu), wanita itu lalu dishalati dan dikuburkan.\""},"3732":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ زَكَرِيَّا أَبِي عِمْرَانَ قَالَ سَمِعْتُ شَيْخًا يُحَدِّثُ عَنْ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَمَ امْرَأَةً فَحُفِرَ لَهَا إِلَى الثَّنْدُوَةِقَالَ أَبُو دَاوُد أَفْهَمَنِي رَجُلٌ عَنْ عُثْمَانَ قَالَ أَبُو دَاوُد قَالَ الْغَسَّانِيُّ جُهَيْنَةُ وَغَامِدٌ وَبَارِقٌ وَاحِدٌ قَالَ أَبُو دَاوُد حُدِّثْتُ عَنْ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ سُلَيْمٍ بِإِسْنَادِهِ نَحْوَهُ زَادَ ثُمَّ رَمَاهَا بِحَصَاةٍ مِثْلَ الْحِمِّصَةِ ثُمَّ قَالَ ارْمُوا وَاتَّقُوا الْوَجْهَ فَلَمَّا طَفِئَتْ أَخْرَجَهَا فَصَلَّى عَلَيْهَا وَقَالَ فِي التَّوْبَةِ نَحْوَ حَدِيثِ بُرَيْدَةَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki' Ibnul Jarrah] dari [Zakariya Abu Imran] ia berkata; Aku mendengar [Seorang Syaikh] menceritakan dari [Ibnu Abu Bakrah] dari [Bapaknya] berkata, \"Nabi shallallahu 'alaihi wasallam merajam seorang wanita, lalu beliau membuat lubang untuknya hingga sebatas dada.\" Abu Daud berkata, \"Seorang laki-laki memahamkan kepadaku dari Utsman.\" Abu Daud berkata lagi, \"Al Ghassani berkata, \"Juhainah, Ghamid dan Bariq itu sama.\" Abu Daud berkata, \"Aku mendapat cerita dari [Abdu Ash Shamad bin Abdul Warits], ia berkata; [Zakariya bin Sulaim] telah menceritakan kepada kami dengan sanadnya seperti hadits tersebut. Namun ia menambahkan, 'kemudian beliau melemparnya dengan kerikil-kerikil semisal biji gandum. Setelah itu beliau bersabda: \"Lemparlah, tetapi jauhilah bagian wajah.\" Ketika wanita itu telah meninggal, beliau mengeluarkannya dari lubang dan menshalatinya.\" Dan ia mengatakan dalam haditsnya tentang masalah taubat sebagaimana hadits Buraidah.\""},"3733":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُمَا أَخْبَرَاهُأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا يَا رَسُولَ اللَّهِ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَقَالَ الْآخَرُ وَكَانَ أَفْقَهَهُمَا أَجَلْ يَا رَسُولَ اللَّهِ فَاقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي أَنْ أَتَكَلَّمَ قَالَ تَكَلَّمْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا وَالْعَسِيفُ الْأَجِيرُ فَزَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَبِجَارِيَةٍ لِي ثُمَّ إِنِّي سَأَلْتُ أَهْلَ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَإِنَّمَا الرَّجْمُ عَلَى امْرَأَتِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا غَنَمُكَ وَجَارِيَتُكَ فَرَدٌّ إِلَيْكَ وَجَلَدَ ابْنَهُ مِائَةً وَغَرَّبَهُ عَامًا وَأَمَرَ أُنَيْسًا الْأَسْلَمِيَّ أَنْ يَأْتِيَ امْرَأَةَ الْآخَرِ فَإِنْ اعْتَرَفَتْ رَجَمَهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] dari [Abu Hurairah] dan [Zaid bin Khalid Al juhani] bahwa keduanya telah mengabarkan kepadanya, bahwa ada dua orang laki-laki bersengketa dan mengadu kepada Rasulullah shallallahu 'alaihi wasallam. salah seorang dari mereka berkata, \"Wahai Rasulullah, berilah putusan kepada kami sesuai dengan Kitabullah. Kemudian yang lainnya -dan ia yang lebih paham di antara keduanya- berkata, \"Benar, wahai Rasulullah, berilah putusan kepada kami sesuai dengan Kitabullah. Dan berilah kesempatan kepadaku untuk berbicara.\" Beliau bersabda: \"Berbicaralah.\" Laki-laki itu lalu berkata, \"Anakku kerja kepada orang ini, lalu anakku berzina dengan isterinya. Kemudian orang-orang memberi kabar kepadaku bahwa anakku harus dirajam, maka aku menebusnya dengan seratus ekor domba dan seorang budak wanita kepunyaanku. Setelah itu aku bertanya kepada ahli ilmu, mereka memberi kabar kepadaku bahwa anakku harus didera seratus kali dan diasingkan selama satu tahun, sementara wanita tersebut harus dirajam.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada dalam tangan-Nya, sungguh aku akan memberi putusan kepada kalian sesuai dengan Kitabullah. Kambing dan pembantu wanita milikmu akan dikembalikan kepadamu.\" Beliau lalu mendera putera laki-laki itu dan mengasingkannya selama satu tahun. Kemudian memerintahkan Unais Al Aslami untuk mendatangkan wanita tersebut, jika ia mengakui maka akan dirajam, wanita itu pun mengakuinya dan akhirnya dirajam.\""},"3734":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَرَأْتُ عَلَى مِالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ قَالَإِنَّ الْيَهُودَ جَاءُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ أَنَّ رَجُلًا مِنْهُمْ وَامْرَأَةً زَنَيَا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَجِدُونَ فِي التَّوْرَاةِ فِي شَأْنِ الزِّنَا فَقَالُوا نَفْضَحُهُمْ وَيُجْلَدُونَ فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ كَذَبْتُمْ إِنَّ فِيهَا الرَّجْمَ فَأَتَوْا بِالتَّوْرَاةِ فَنَشَرُوهَا فَجَعَلَ أَحَدُهُمْ يَدَهُ عَلَى آيَةِ الرَّجْمِ ثُمَّ جَعَلَ يَقْرَأُ مَا قَبْلَهَا وَمَا بَعْدَهَا فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ سَلَامٍ ارْفَعْ يَدَيْكَ فَرَفَعَهَا فَإِذَا فِيهَا آيَةُ الرَّجْمِ فَقَالُوا صَدَقَ يَا مُحَمَّدُ فِيهَا آيَةُ الرَّجْمِ فَأَمَرَ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَاقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ فَرَأَيْتُ الرَّجُلَ يَحْنِي عَلَى الْمَرْأَةِ يَقِيهَا الْحِجَارَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] ia berkata; aku membaca di hadapan [Malik bin Anas] dari [nafi'] dari [Ibnu Umar] Bahwasanya ia berkata, \"Orang-orang yahudi datang kepada Nabi shallallahu 'alaihi wasallam, mereka menyebutkan di hadapan beliau bahwa ada seorang laki-laki dan perempuan dari kalangan mereka telah berbuat zina. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada mereka: \"Hukum apa yang kalian temukan dalam Kitab Taurat kaitannya dengan zina?\" Mereka menjawab, \"Kami akan mencela dan mencambuk pelakunya.\" Abdullah bin Salam berkata, \"Kalian dusta! Dalam Taurat ada perintah rajam.\" Mereka lalu mendatangkan Taurat seraya membukanya. Salah seorang dari mereka lalu menutup ayat rajam dengan tangannya, kemudian ia membaca pada ayat sebelum dan sesudahnya (yakni tidak membaca pada bagian yang ditutup dengan tangan). Abdullah bin Salam lalu berkata, \"Angkatlah tanganmu!\" Ia pun mengangkat tangannya, maka didapatilah ayat yang berbicara tentang rajam. Mereka lantas berkata, \"Wahai Muhammad, ia benar! Di dalam taurat memang ada ayat rajam.\" Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk merajam keduanya, maka keduanya dirajam.\" Abdullah bin Umar berkata, \"Aku melihat laki-laki itu mendekap wanitanya agar tidak terkena batu.\""},"3735":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمَرُّوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ قَدْ حُمِّمَ وَجْهُهُ وَهُوَ يُطَافُ بِهِ فَنَاشَدَهُمْ مَا حَدُّ الزَّانِي فِي كِتَابِهِمْ قَالَ فَأَحَالُوهُ عَلَى رَجُلٍ مِنْهُمْ فَنَشَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَدُّ الزَّانِي فِي كِتَابِكُمْ فَقَالَ الرَّجْمُ وَلَكِنْ ظَهَرَ الزِّنَا فِي أَشْرَافِنَا فَكَرِهْنَا أَنْ يُتْرَكَ الشَّرِيفُ وَيُقَامُ عَلَى مَنْ دُونَهُ فَوَضَعْنَا هَذَا عَنَّا فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ ثُمَّ قَالَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا مَا أَمَاتُوا مِنْ كِتَابِكَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Bara bin Azib] ia berkata, \"Orang-orang melewati Rasulullah shallallahu 'alaihi wasallam dengan membawa seorang Yahudi yang wajahnya telah diberi arang untuk diarak. Beliau lalu bertanya kepada mereka: \"Apa hukum pezina yang termaktub dalam kitab suci mereka?\" Mereka lalu mengalihkan jawaban untuk soal itu kepada salah seorang dari mereka. Beliau lalu bertanya kepadanya: \"Apa hukum bagi pezina dalam kitab suci kalian?\" Ia menjawab, \"Rajam. Tetapi perzinaan kerap terjadi di kalangan petinggi kami, dan kami juga tidak senang jika orang terhormat tidak dikenakan hukuman dan hanya dikenakan kepada orang-orang yang rendah saja, maka akhirnya kami pun meniadakan hukuman tersebut.\" Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan agar pezina itu dihukum dengan rajam, maka ia pun dirajam. Setelah itu beliau bersabda: \"Ya Allah, aku adalah orang pertama kali yang menghidupkan terhadap apa yang mereka bekukan dari hukuman yang ada dalam kitab-Mu.\""},"3736":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمٍ مَجْلُودٍ فَدَعَاهُمْ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فَقَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ قَالَ لَهُ نَشَدْتُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ فَقَالَ اللَّهُمَّ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُ حَدَّ الزَّانِي فِي كِتَابِنَا الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الرَّجُلَ الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الرَّجُلَ الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ فَقُلْنَا تَعَالَوْا فَنَجْتَمِعُ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَاجْتَمَعْنَا عَلَى التَّحْمِيمِ وَالْجَلْدِ وَتَرَكْنَا الرَّجْمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنّ��ي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ إِلَى قَوْلِهِ يَقُولُونَ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ وَإِنْ لَمْ تُؤْتَوْهُ فَاحْذَرُوا إِلَى قَوْلِهِ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ فِي الْيَهُودِ إِلَى قَوْلِهِ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ فِي الْيَهُودِ إِلَى قَوْلِهِ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }قَالَ هِيَ فِي الْكُفَّارِ كُلُّهَا يَعْنِي هَذِهِ الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al bara bin Azib] ia berkata, \"Seorang yahudi yang wajahnya menghitam (karena dilumuri arang) dan telah dicambuk dibawa melewati Rasulullah shallallahu 'alaihi wasallam, beliau lantas memanggil mereka seraya bertanya: \"Beginikah kalian mendapati hukum bagi pezina?\" Mereka menjawab, \"Benar.\" Beliau lalu memanggil seorang laki-laki dari ulama mereka, beliau bersabda: \"Kami bersumpah kepada Allah atas kamu, Dzat yang menurunkan Taurat kepada Musa. Apakah begini kalian mendapati hukuman bagi pezina dalam kitab kalian?\" Laki-laki itu berkata, \"Demi Allah, tidak. Sekiranya engkau tidak bersumpah kepada Allah aku tidak akan mengabarimu. Kami mendapati hukum bagi pezina dalam kitab kami adalah dengan hukum rajam. Tetapi perzinaan itu justru banyak terjadi dikalangan orang-orang terhormat di antara kami, ketika kami mendapati mereka melakukannya, kami tidak memberlakukan hukuman rajam tersebut. Namun jika itu dilakukan oleh orang-orang rendahan di antara kami, maka kami melaksanakannya. Lalu kami berembuk untuk mencari hukuman yang bisa kami terapkan kepada pezina baik dari kalangan terhormat maupun kalangan rendahan di antara kami. Maka kami bersepakat dengan hukuman tahmim (mencoreng muka dengan arang) dan hukuman cambuk.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Ya Allah, sungguh aku adalah orang pertama yang menghidupkan kembali perintah-Mu (hukuman had) ketika mereka mematikannya (tidak melaksanakannya).\" Beliau lalu memerintahkan agar pezina itu dirajam, akhirnya pezina itu pun dirajam. Allah Azza Wa Jalla lalu menurunkan ayat: '(Hai Rasul, janganlah hendaknya kamu disedihkan oleh orang-orang yang bersegera (memperlihatkan) kekafirannya..) ', hingga firman-Nya; '(Mereka mengatakan: \"Jika diberikan ini (yang sudah di robah-robah oleh mereka) kepada kamu, maka terimalah, dan jika kamu diberi yang bukan ini maka hati-hatilah'), hingga firman-Nya; '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ', ayat ini berkenaan dengan orang-orang yahudi, hingga firman-Nya; '(Barangsiapa tidak memutuskan perkara menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang zalim) ', ayat ini berkenaan dengan orang-orang yahudi, hingga firman-Nya; '(Barangsiapa tidak memutuskan perkara menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang fasik) ', semua ayat-ayat tersebut berkenaan dengan orang-orang kafir.\""},"3737":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي هِشَامُ بْنُ سَعْدٍ أَنَّ زَيْدَ بْنَ أَسْلَمَ حَدَّثَهُ عَنْ ابْنِ عُمَرَ قَالَأَتَى نَفَرٌ مِنْ يَهُودٍ فَدَعَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْقُفِّ فَأَتَاهُمْ فِي بَيْتِ الْمِدْرَاسِ فَقَالُوا يَا أَبَا الْقَاسِمِ إِنَّ رَجُلًا مِنَّا زَنَى بِامْرَأَةٍ فَاحْكُمْ بَيْنَهُمْ فَوَضَعُوا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وِسَادَةً فَجَلَسَ عَلَيْهَا ثُمَّ قَالَ بِالتَّوْرَاةِ فَأُتِيَ بِهَا فَنَزَعَ الْوِسَادَةَ مِنْ تَحْتِهِ فَوَضَعَ التَّوْرَاةَ عَلَيْهَا ثُمَّ قَالَ آمَنْتُ بِكِ وَبِمَنْ أَنْزَلَكِ ثُمَّ قَالَ ائْتُونِي بِأَعْلَمِكُمْ فَأُتِيَ بِفَتًى شَابٍّثُمَّ ذَكَرَ قِصَّةَ الرَّجْمِ نَحْوَ حَدِيثِ مَالِكٍ عَنْ نَافِعٍ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepadaku [Hisyam bin Sa'd] bahwa [Zaid bin Aslam] ia menceritakan kepadanya dari [Ibnu Umar] ia berkata, \"Beberapa orang yahudi datang dan mengundang Rasulullah shallallahu 'alaihi wasallam untuk hadir ke Quff (tempat dekat Madinah), lalu beliau mendatangi mereka di tempat yang biasa mereka gunakan untuk mengaji. Mereka berkata, \"Wahai Abul Qasim, seorang laki-laki di antara kami berzina dengan seorang wanita, maka tetapkanlah hukum bagi mereka.\" Mereka lantas memberi bantal Rasulullah shallallahu 'alaihi wasallam untuk digunakan duduk, beliau pun duduk. Kemudian beliau minta diambilkan Taurat, naskah Taurat itu lalu diberikan kepada beliau. Beliau menarik bantal yang didudukinya dan meletakkan Taurat tersebut di atasnya seranya bersabda: \"Aku beriman kepadamu dan kepada Dzat Yang menurunkanmu.\" Setelah itu beliau bersabda: \"Hadirkanlah kepadaku orang yang paling paham di antara kalian.\" Lalu dihadirkanlah seorang pemuda, lalu ia menyebutkan kisah rajam sebagaimana hadits Malik dari Nafi'.\""},"3738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنَا رَجُلٌ مِنْ مُزَيْنَةَ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ قَالَ قَالَ مُحَمَّدُ بْنُ مُسْلِمٍ سَمِعْتُ رَجُلًا مِنْ مُزَيْنَةَ مِمَّنْ يَتَّبِعُ الْعِلْمَ وَيَعِيهِ ثُمَّ اتَّفَقَا وَنَحْنُ عِنْدَ سَعِيدِ بْنِ الْمُسَيِّبِ فَحَدَّثَنَا عَنْ أَبِي هُرَيْرَةَ وَهَذَا حَدِيثُ مَعْمَرٍ وَهُوَ أَتَمُّ قَالَزَنَى رَجُلٌ مِنْ الْيَهُودِ وَامْرَأَةٌ فَقَالَ بَعْضُهُمْ لِبَعْضٍ اذْهَبُوا بِنَا إِلَى هَذَا النَّبِيِّ فَإِنَّهُ نَبِيٌّ بُعِثَ بِالتَّخْفِيفِ فَإِنْ أَفْتَانَا بِفُتْيَا دُونَ الرَّجْمِ قَبِلْنَاهَا وَاحْتَجَجْنَا بِهَا عِنْدَ اللَّهِ قُلْنَا فُتْيَا نَبِيٍّ مِنْ أَنْبِيَائِكَ قَالَ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فِي الْمَسْجِدِ فِي أَصْحَابِهِ فَقَالُوا يَا أَبَا الْقَاسِمِ مَا تَرَى فِي رَجُلٍ وَامْرَأَةٍ زَنَيَا فَلَمْ يُكَلِّمْهُمْ كَلِمَةً حَتَّى أَتَى بَيْتَ مِدْرَاسِهِمْ فَقَامَ عَلَى الْبَابِ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى مَا تَجِدُونَ فِي التَّوْرَاةِ عَلَى مَنْ زَنَى إِذَا أَحْصَنَ قَالُوا يُحَمَّمُ وَيُجَبَّهُ وَيُجْلَدُ وَالتَّجْبِيهُ أَنْ يُحْمَلَ الزَّانِيَانِ عَلَى حِمَارٍ وَتُقَابَلُ أَقْفِيَتُهُمَا وَيُطَافُ بِهِمَا قَالَ وَسَكَتَ شَابٌّ مِنْهُمْ فَلَمَّا رَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَكَتَ أَلَظَّ بِهِ النِّشْدَةَ فَقَالَ اللَّهُمَّ إِذْ نَشَدْتَنَا فَإِنَّا نَجِدُ فِي التَّوْرَاةِ الرَّجْمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا أَوَّلُ مَا ارْتَخَصْتُمْ أَمْرَ اللَّهِ قَالَ زَنَى ذُو قَرَابَةٍ مِنْ مَلِكٍ مِنْ مُلُوكِنَا فَأَخَّرَ عَنْهُ الرَّجْمَ ثُمَّ زَنَى رَجُلٌ فِي أُسْرَةٍ مِنْ النَّاسِ فَأَرَادَ رَجْمَهُ فَحَالَ قَوْمُهُ دُونَهُ وَقَالُوا لَا يُرْجَمُ صَاحِبُنَا حَتَّى تَجِيءَ بِصَاحِبِكَ فَتَرْجُمَهُ فَاصْطَلَحُوا عَلَى هَذِهِ الْعُقُوبَةِ بَيْنَهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي أَحْكُمُ بِمَا فِي التَّوْرَاةِ فَأَمَرَ بِهِمَا فَرُجِمَاقَالَ الزُّهْرِيُّ فَبَلَغَنَا أَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِيهِمْ{ إِنَّا أَنْزَلْنَا التَّوْرَاةَ فِيهَا هُدًى وَنُورٌ يَحْكُمُ بِهَا النَّبِيُّونَ الَّذِينَ أَسْلَمُوا }كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah menceritakan kepada kami [laki-laki Muzainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Anbasah] berkata, telah menceritakan kepada kami [Yunus] ia berkata; [Muhammad bin Muslim] ia berkata; Aku mendengar [seorang laki-laki] Muzainah, orang yang tekun dalam menuntut ilmu dan menghafalnya, keduanya (Ma'mar dan Yunus) lalu sepakat, sementara kami sedang berada di sisi Sa'id Ibnul Musayyab, ia berkata; telah menceritakan kepada kami dari [Abu Hurairah] -dan ini adalah hadits Ma'mar, dan ini lebih lengkap-, ia berkata, \"Seorang laki-laki yahudi berzina dengan seorang wanita. Lalu sebagian mereka berkata kepada sebagian yang lain, \"Mari kita mendatangi Nabi ini (Muhammad shallallahu 'alaihi wasallam), ia adalah seorang Nabi yang diutus dengan membawa kemudahan, jika nanti ia memberi fatwa kepada kita dengan hukuman selain rajam, hendaklah kita terima, lalu kita gunakan sebagai hujah di sisi Allah 'Ini adalah fatwa dari seorang Nabi di antara para Nabi-Mu'.\" Ia (perawi) berkata, \"Mereka akhirnya mendatangi Nabi shallallahu 'alaihi wasallam yang sedang duduk-duduk di masjid bersama para sahabatnya. Mereka mengatakan, \"Wahai Abul Qasim, apa pendapatmu jika laki-laki dan perempuan melakukan perzinaan?\" Beliau tidak memberi mereka jawaban satu kata pun hingga beliau mendatangi mereka di tempat mereka mengaji. Beliau lalu berdiri di depan pintu seraya bersabda: \"Aku bersumpah kepadamu dengan nama Allah yang telah menurunkan Taurat kepada Musa, hukuman apa yang kalian dapati dalam Kitab suci kalian bagi pezina yang telah menikah?\" mereka menjawab, \"Wajahnya dilumuri arang, lalu dinaikkan himar (dengan saling membelakangi), lalu diarak dan didera.\" Seorang pemuda dari mereka terdiam. Maka ketika Nabi shallallahu 'alaihi wasallam melihat pemuda itu diam, beliau menguatkan sumpah kepadanya agar ia memberi jawaban. Ia pun berkata, \"(Ya Allah), jika engkau (Muhammad) bersumpah kepada kami, maka sesungguhnya kami mendapati dalam kitab Taurat adalah hukuman rajam.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Lalu siapa yang pertama kali kalian ringankan dari hukuman Allah (rajam) tersebut? Pemuda itu menjawab, \"Ketika salah seorang kerabat raja kami berbuat zina, maka hukuman rajam itu ditangguhkan. Kemudian ketika ada salah seorang laki-laki dari suatu kaum berbuat zina dan akan ditegakkan hukuman rajam atasnya, kaumnya ikut menghalang-halanginya. Mereka mengatakan, \"Sahabat kami tidak akan dirajam hingga engkau datang dengan sahabat kamu untuk dirajam (bersama-sama). ' Maka mereka semua akhirnya sepakat dengan hukuman ini.\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Aku akan menghukumi sebagaimana yang ada dalam Taurat.\" Beliau lalu memerintahkan (agar keduanya dirajam), maka keduanya pun dirajam.\" Az Zuhri berkata, \"Telah sampai kabar kepada kami bahwa ayat ini turun berkenaan dengan mereka: '(Sesungguhnya Kami telah menurunkan Kitab Taurat di dalamnya (ada) petunjuk dan cahaya (yang menerangi), yang dengan Kitab itu diputuskan perkara orang-orang Yahudi oleh nabi-nabi yang menyerah diri kepada Allah..) ' dan Nabi shallallahu 'alaihi wasallam adalah termasuk dari para Nabi tersebut.\""},"3739":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَبُو الْأَصْبَغِ الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ رَجُلًا مِنْ مُزَيْنَةَ يُحَدِّثُ سَعِيدَ بْنَ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَزَنَى رَجُلٌ وَامْرَأَةٌ مِنْ الْيَهُودِ وَقَدْ أُحْصِنَا حِينَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَقَدْ كَانَ الرَّجْمُ مَكْتُوبًا عَلَيْهِمْ فِي التَّوْرَاةِ فَتَرَكُوهُ وَأَخَذُوا بِالتَّجْبِيهِ يُضْرَبُ مِائَةً بِحَبْلٍ مَطْلِيٍّ بِقَارٍ وَيُحْمَلُ عَلَى حِمَارٍ وَجْهُهُ مِمَّا يَلِي دُبُرَ الْحِمَارِ فَاجْتَمَعَ أَحْبَارٌ مِنْ أَحْبَارِهِمْ فَبَعَثُوا قَوْمًا آخَرِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا سَلُوهُ عَنْ حَدِّ الزَّانِي وَسَاقَ الْحَدِيثَ فَقَالَ فِيهِ قَالَ وَلَمْ يَكُونُوا مِنْ أَهْلِ دِينِهِ فَيَحْكُمَ بَيْنَهُمْ فَخُيِّرَ فِي ذَلِكَ قَالَ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Abu Al Ashbagh Al Harrani] berkata, telah menceritakan kepadaku [Muhammad] -maksudnya Muhammad bin Salamah- dari [Muhammad bin Ishaq] dari [Az Zuhri] ia berkata, \"Aku mendengar [seorang laki-laki] dari Muzainah menceritakan dari Sa'id Ibnul Musayyab, dari [Abu Hurairah] ia berkata, \"Seorang laki-laki dan perempuan yahudi melakukan perbuatan zina, sementara keduanya sama-sama telah menikah ketika Rasulullah shallallahu 'alaihi wasallam datang ke Madinah. Padahal, sesuai dengan ketentuan Taurat mereka harus mendapatkan hukuman rajam. Namun mereka tidak melaksanakan hukuman itu dan menggantinya dengan Tajbih, yakni didera dengan cambuk sebanyak seratus kali dengan cambuk yang dilumuri warna hitam. Lalu diarak dengan dinaikkan himar, sementara wajah mereka menghadap ke arah bokong himar. Para ulama` mereka lalu berkumpul, mereka kemudian mengutus beberapa orang untuk menemui Rasulullah shallallahu 'alaihi wasallam. Para ulama` itu berkata, \"Bertanyalah kepada Muhammad apa hukum bagi pezina…lalu ia menyebutkan hadits selengkapnya. Ia berkata, \"Orang-orang yahudi itu bukan termasuk orang yang seagama dengannya (Rasulullah) namun beliau harus memberi putusan kepada mereka. Maka beliau diberi pilihan, Allah berfirman: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka..) ' -Al Maidah: 42-. "},"3740":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ مُجَالِدٌ أَخْبَرَنَا عَنْ عَامِرٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَتْ الْيَهُودُ بِرَجُلٍ وَامْرَأَةٍ مِنْهُمْ زَنَيَا فَقَالَ ائْتُونِي بِأَعْلَمِ رَجُلَيْنِ مِنْكُمْ فَأَتَوْهُ بِابْنَيْ صُورِيَا فَنَشَدَهُمَا كَيْفَ تَجِدَانِ أَمْرَ هَذَيْنِ فِي التَّوْرَاةِ قَالَا نَجِدُ فِي التَّوْرَاةِ إِذَا شَهِدَ أَرْبَعَةٌ أَنَّهُمْ رَأَوْا ذَكَرَهُ فِي فَرْجِهَا مِثْلَ الْمِيلِ فِي الْمُكْحُلَةِ رُجِمَا قَالَ فَمَا يَمْنَعُكُمَا أَنْ تَرْجُمُوهُمَا قَالَا ذَهَبَ سُلْطَانُنَا فَكَرِهْنَا الْقَتْلَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّهُودِ فَجَاءُوا بِأَرْبَعَةٍ فَشَهِدُوا أَنَّهُمْ رَأَوْا ذَكَرَهُ فِي فَرْجِهَا مِثْلَ الْمِيلِ فِي الْمُكْحُلَةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجْمِهِمَاحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ هُشَيْمٍ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ وَالشَّعْبِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ لَمْ يَذْكُرْ فَدَعَا بِالشُّهُودِ فَشَهِدُوا حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ هُشَيْمٍ عَنْ ابْنِ شُبْرُمَةَ عَنْ الشَّعْبِيِّ بِنَحْوٍ مِنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Musa Al Balkhi] berkata, telah menceritakan kepada kami [Abu Usamah] berkata; [Mujalid] berkata; telah mengabarkan kepada kami dari [Amir] dari [Jabir bin Abdullah] ia berkata, \"Orang-orang yahudi datang dengan membawa seorang laki-laki dan perempuan mereka yang telah melakukan perzinaan. Beliau lalu bersabda: \"Datangkan kepadaku orang yang paling tahu dari cendikia kalian.\" Mereka lalu mendatangkan dua anak Shuriya, beliau bertanya kepada keduanya: \"Hukuman apa yang kalian dapatkan dalam kitab Taurat berkenaan dengan kedua pezina ini?\" keduanya menjawab, \"Kami mendapatkan dalam kitab taurat; jika ada empat orang saksi yang menyatakan bahwa mereka telah melihat kemaluan si laki-laki masuk ke dalam kemaluan wanita seperti pena celak masuk ke dalam botolnya, maka mereka harus dirajam.\" Beliau bertanya lagi: \"Lalu apa yang menghalangi kalian untuk merajam mereka berdua?\" keduanya menjawab, \"Kekuasaan kami telah hilang, maka kami takut untuk dibunuh.\" Rasulullah shallallahu 'alaihi wasallam lantas meminta didatangkan beberapa orang saksi, mereka lalu datang dengan membawa empat orang saksi yang kemudian menyatakan kesaksiannya, bahwa mereka melihat kemaluan si lelaki masuk ke dalam kemaluan wanita layaknya pena celak masuk ke dalam botolnya. Maka, Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk merajam keduanya.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Husyaim] dari [Mugirah] dari [Ibrahim] dan [Asy Sya'bi] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits tersebut. Namun tidak disebutkan, 'beliau lalu minta didatangkan empat orang saksi, lalu mereka pun bersaksi.\" Telah menceritakan kepada kami [Wahb bin baqiyyah] dari [Husyaim] dari [Ibnu Syubrumah] dari [Asy Sya'bi] seperti hadits tersebut.\""},"3741":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَسَنٍ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَنَّهُ سَمِعَ أَبَا الزُّبَيْرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُرَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْيَهُودِ وَامْرَأَةً زَنَيَا","id":"Telah menceritakan kepada kami [Ibrahim bin Hasan Al Mishishi] berkata, telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata; telah menceritakan kepada kami [Ibnu Juraij] Bahwasanya ia mendengar [Abu Az Zubair] pernah mendengar [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah merajam seorang laki-laki dan perempuan yahudi yang berbuat zina.\""},"3742":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُطَرِّفٌ عَنْ أَبِي الْجَهْمِ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَبَيْنَا أَنَا أَطُوفُ عَلَى إِبِلٍ لِي ضَلَّتْ إِذْ أَقْبَلَ رَكْبٌ أَوْ فَوَارِسُ مَعَهُمْ لِوَاءٌ فَجَعَلَ الْأَعْرَابُ يَطِيفُونَ بِي لِمَنْزِلَتِي مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَتَوْا قُبَّةً فَاسْتَخْرَجُوا مِنْهَا رَجُلًا فَضَرَبُوا عُنُقَهُ فَسَأَلْتُ عَنْهُ فَذَكَرُوا أَنَّهُ أَعْرَسَ بِامْرَأَةِ أَبِيهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Khalid bin Abdullah] berkata, telah menceritakan kepada kami [Mutharrif] dari [Abul Jahm] dari [Al Bara bin Azib] ia berkata, \"Ketika aku sedang berkeliling mencari untaku yang hilang, aku berpapasan dengan sekelompok penunggang kuda, dan mereka membawa bendera. Lalu orang-orang itu mengajakku untuk ikut serta karena kedekatanku dengan nabi shallallahu 'alaihi wasallam. saat mereka mendatangi sebuah qubah (rumah), mereka mengeluarkan seorang laki-laki darinya dengan paksa dan membunuhnya. Aku lantas bertanya (tentang hal itu), mereka lalu menyebutkan bahwasanya ia telah menikahi isteri bapaknya.\""},"3743":{"ar":"حَدَّثَنَا عَمْرُو بْنُ قُسَيْطٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ يَزِيدَ بْنِ الْبَرَاءِ عَنْ أَبِيهِ قَالَلَقِيتُ عَمِّي وَمَعَهُ رَايَةٌ فَقُلْتُ لَهُ أَيْنَ تُرِيدُ قَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ نَكَحَ امْرَأَةَ أَبِيهِ فَأَمَرَنِي أَنْ أَضْرِبَ عُنُقَهُ وَآخُذَ مَالَهُ","id":"Telah menceritakan kepada kami [Amru bin Qusaith Ar raqqi] berkata, telah menceritakan kepada kami [Ubaidullah bin Amru] dari [Zaid bin Abu Unaisah] dari [Adi bin Tsabit] dari [Yazid Ibnul Bara] dari [Bapaknya] ia berkata, \"Aku pernah bertemu dengan pamanku yang ketika itu sedang membawa bendera. Aku lalu bertanya kepadanya, \"Mau kemana engkau akan pergi?\" ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam mengutusku untuk mendatangi seorang laki-laki yang menikahi isteri bapaknya, beliau memerintahkan kepadaku untuk memenggal lehernya dan mengambil hartanya.\""},"3744":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ عَنْ خَالِدِ بْنِ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍأَنَّ رَجُلًا يُقَالُ لَهُ عَبْدُ الرَّحْمَنِ بْنُ حُنَيْنٍ وَقَعَ عَلَى جَارِيَةِ امْرَأَتِهِ فَرُفِعَ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ وَهُوَ أَمِيرٌ عَلَى الْكُوفَةِ فَقَالَ لَأَقْضِيَنَّ فِيكَ بِقَضِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَتْ أَحَلَّتْهَا لَكَ جَلَدْتُكَ مِائَةً وَإِنْ لَمْ تَكُنْ أَحَلَّتْهَا لَكَ رَجَمْتُكَ بِالْحِجَارَةِ فَوَجَدُوهُ قَدْ أَحَلَّتْهَا لَهُ فَجَلَدَهُ مِائَةًقَالَ قَتَادَةُ كَتَبْتُ إِلَى حَبِيبِ بْنِ سَالِمٍ فَكَتْبَ إِلَيَّ بِهَذَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Aban] berkata, telah menceritakan kepada kami [Qatadah] dari [Khalid bin Urfuthah] dari [Habib bin Salim] berkata, \"Bahwa ada seorang laki-laki yang bernama 'Abdurrahman bin Hunain berzina dengan budak wanita milik isterinya. Maka kasus itu disampaikan kepada Nu'man bin Basyir, gubernur Kufah saat itu. [Nu'man] lalu berkata, \"Sunguh, aku akan memberi putusan kepada kamu sebagaimana putusan Rasulullah shallallahu 'alaihi wasallam. Jika isterimu menghalalkannya untukmu maka aku akan menderamu sebanyak seratus kali, namun jika isterimu tidak menghalalkannya untukmu maka aku akan merajam kamu dengan batu. Orang-orang lalu mendapatkan (kejelasan) bahwa isterinya telah menghalalkan budak wanita itu untuknya, maka Nu'man menderanya sebanyak seratus kali.\" Qatadah berkata, \"Aku menulis surat kepada Habib bin Salim, lalu ia memberi balasan dengan hadits tersebut.\""},"3745":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ عَنْ خَالِدِ بْنِ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَأْتِي جَارِيَةَ امْرَأَتِهِ قَالَ إِنْ كَانَتْ أَحَلَّتْهَا لَهُ جُلِدَ مِائَةً وَإِنْ لَمْ تَكُنْ أَحَلَّتْهَا لَهُ رَجَمْتُهُ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Abu Bisyr] dari [Khalid bin Urfuthah] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dari Nabi shallallahu 'alaihi wasallam, tentang seorang laki-laki yang mensetubuhi budak wanita milik isterinya: \"Jika isterinya menghalalkan baginya (suami), maka hukumannya adalah dera seratus kali. Namun jika tidak menghalalkan baginya, maka aku akan merajamnya.\""},"3746":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي رَجُلٍ وَقَعَ عَلَى جَارِيَةِ امْرَأَتِهِ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ وَعَلَيْهِ لِسَيِّدَتِهَا مِثْلُهَا فَإِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ لَهُ وَعَلَيْهِ لِسَيِّدَتِهَا مِثْلُهَاقَالَ أَبُو دَاوُد رَوَى يُونُسُ بْنُ عُبَيْدٍ وَعَمْرُو بْنُ دِينَارٍ وَمَنْصُورُ بْنُ زَاذَانَ وَسَلَّامٌ عَنْ الْحَسَنِ هَذَا الْحَدِيثَ بِمَعْنَاهُ لَمْ يَذْكُرْ يُونُسُ وَمَنْصُورٌ قَبِيصَةَ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ الدِّرْهَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ وَإِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ وَمِثْلُهَا مِنْ مَالِهِ لَسَيِّدَتِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Qatadah] dari [Al Hasan] dari [Qabishah bin Huraits] dari [Salamah Ibnul Muhabbaq] berkata, \"Bahwasanya Rasulullah shallallahu 'alaihi wasallam memberi putusan atas seorang laki-laki yang mensetubuhi budak wanita milik isterinya. Jika sang suami memaksanya maka sang budak menjadi merdeka, dan suami tetap menunaikan segala tanggung jawab terhadap isterinya sebagaimana tanggung jawabnya terhadap budaknya. Namun jika sang budak mempersilahkan dirinya secara sukarela, budak itu berpindah tangan menjadi budak suaminya, dan suami tetap menunaikan tanggung jawab terhadap isterinya.\" Abu Dawud berkata, \" [Yunus bin Ubaid], [Amru bin dinar], [Manshur bin Zadzan] dan [Salam] meriwayatkan hadits ini dari [Al Hasan] secara makna. Sementara Yunus dan Manshur tidak menyebutkan nama Qabishah.\" Telah menceritakan kepada kami [Ali bin Husain Ad Dirhami] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Salamah Ibnul Muhabbaq] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini, hanya saja ia menyebutkan, \"Jika budak wanita itu menurut dengan suka rela, maka ia (budak wanita) dan harta yang ia dapat dari si suami menjadi milik majikannya (isteri).\""},"3747":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدْتُمُوهُ يَعْمَلُ عَمَلَ قَوْمِ لُوطٍ فَاقْتُلُوا الْفَاعِلَ وَالْمَفْعُولَ بِهِقَالَ أَبُو دَاوُد رَوَاهُ سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو مِثْلَهُ وَرَوَاهُ عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَفَعَهُ وَرَوَاهُ ابْنُ جُرَيْجٍ عَنْ إِبْرَاهِيمَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَفَعَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Ali An Nufaili] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Amru bin Abu Amru] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang kalian dapati sedang melakukan perbuatan kaum Luth, maka bunuhlah; pelaku dan objeknya.\" Abu Dawud berkata, \" [Sulaiman bin Bilal] meriwayatkannya dari [Amru bin Abu Amru] seperti hadits tersebut. Dan [Abbad bin Manshur] meriwayatkannya dari [Ikrimah], dari [Ibnu Abbas], dan ia memarfu'kannya. [Ibnu Juraij] meriwayatkannya dari [Ibrahim], dari [Dawud Ibnul Hushain], dari [Ikrimah], dari [Ibnu Abbas], dan ia memarfu'kannya.\""},"3748":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ رَاهَوَيْهِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ خُثَيْمٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ وَمُجَاهِدًا يُحَدِّثَانِ عَنْ ابْنِ عَبَّاسٍفِي الْبِكْرِ يُؤْخَذُ عَلَى اللُّوطِيَّةِ قَالَ يُرْجَمُقَالَ أَبُو دَاوُد حَدِيثُ عَاصِمٍ يُضَعِّفُ حَدِيثَ عَمْرِو بْنِ أَبِي عَمْرٍو","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Rahawaih] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Ibnu Khutsaim] ia berkata, \"Aku mendengar [Sa'id bin Jubair] dan [Mujahid] menceritakan dari [Ibnu Abbas] tentang seorang gadis yang melakukan perbuatan kaum Luth, ia berkata, \"Hukumannya adalah rajam.\" Abu Dawud berkata, \"Hadits Abu Dawud ini melemahkan hadits Amru bin Abu Amru.\""},"3749":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ حَدَّثَنِي عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَتَى بَهِيمَةً فَاقْتُلُوهُ وَاقْتُلُوهَا مَعَهُ قَالَ قُلْتُ لَهُ مَا شَأْنُ الْبَهِيمَةِ قَالَ مَا أُرَاهُ قَالَ ذَلِكَ إِلَّا أَنَّهُ كَرِهَ أَنْ يُؤْكَلَ لَحْمُهَا وَقَدْ عُمِلَ بِهَا ذَلِكَ الْعَمَلُقَالَ أَبُو دَاوُد لَيْسَ هَذَا بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] berkata, telah menceritakan kepadaku [Amru bin Abu Amru] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mensetubuhi binatang maka bunuhlah ia beserta binatang tersebut.\" Ibnu Abbas berkata, \"Aku lantas bertanya kepada Rasulullah, \"Apa salah binatang tersebut?\" Ibnu abbas berkata, \"Aku tidak melihat beliau mengatakan begitu kecuali karena sebab, bahwa beliau tidak suka jika binatang yang telah disetubuhi itu dimakan dagingnya.\" Abu Dawud berkata, \"Namun derajat hadits ini tidak kuat.\""},"3750":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ أَنَّ شَرِيكًا وَأَبَا الْأَحْوَصِ وَأَبَا بَكْرِ بْنَ عَيَّاشٍ حَدَّثُوهُمْ عَنْ عَاصِمٍ عَنْ أَبِي رَزِينٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَيْسَ عَلَى الَّذِي يَأْتِي الْبَهِيمَةَ حَدٌّقَالَ أَبُو دَاوُد وَكَذَا قَالَ عَطَاءٌ و قَالَ الْحَكَمُ أَرَى أَنْ يُجْلَدَ وَلَا يُبْلَغَ بِهِ الْحَدَّ و قَالَ الْحَسَنُ هُوَ بِمَنْزِلَةِ الزَّانِي قَالَ أَبُو دَاوُد حَدِيثُ عَاصِمٍ يُضَعِّفُ حَدِيثَ عَمْرِو بْنِ أَبِي عَمْرٍو","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] bahwa [Syarik] dan [Abu Al Ahwash] dan [Abu bakr bin Ayyasy] menceritakan kepada mereka dari [Ashim] dari [Abu Razin] dari [Ibnu Abbas] ia berkata, \"Orang yang mensetubuhi binatang tidak ada hukuman hadnya.\" Abu Dawud berkata, \"Atha juga mengatakan begitu.\" Al hakam berkata, \"Menurutku ia harus didera, meskipun jumlahnya tidak melebihi hukuman had.\" Al Hasan berkata, \"Hukumannya sama dengan hukukan pezina.\" Abu Dawud berkata, \"Hadits Ashim ini melemahkan hadits Amru bin Abu Amru.\""},"3751":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَفْصٍ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا أَتَاهُ فَأَقَرَّ عِنْدَهُ أَنَّهُ زَنَى بِامْرَأَةٍ سَمَّاهَا لَهُ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَرْأَةِ فَسَأَلَهَا عَنْ ذَلِكَ فَأَنْكَرَتْ أَنْ تَكُونَ زَنَتْ فَجَلَدَهُ الْحَدَّ وَتَرَكَهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Thalq bin Ghannam] berkata, telah menceritakan kepada kami [Abdussalam bin Hafsh] berkata, telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd] dari Nabi shallallahu 'alaihi wasallam, Bahwasanya seorang laki-laki pernah mendatanginya dan mengaku bahwa dirinya telah berbuat zina dengan seorang wanita yang namanya telah ia sebutkan kepada beliau. Rasulullah shallallahu 'alaihi wasallam kemudian mengutus seseorang untuk bertanya kepada wanita itu; apakah benar yang dikatakan oleh laki-laki tersebut. Wanita itu mengingkari bahwa dirinya telah berzina, maka beliau mendera laki-laki itu sebagai had dan membiarkan wanita tersebut.\""},"3752":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا مُوسَى بْنُ هَارُونَ الْبُرْدِيُّ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ الْقَاسِمِ بْنِ فَيَّاضٍ الْأَبْنَاوِيِّ عَنْ خَلَّادِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ الْمُسَيِّبِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا مِنْ بَكْرِ بْنِ لَيْثٍ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقَرَّ أَنَّهُ زَنَى بِامْرَأَةٍ أَرْبَعَ مَرَّاتٍ فَجَلَدَهُ مِائَةً وَكَانَ بِكْرًا ثُمَّ سَأَلَهُ الْبَيِّنَةَ عَلَى الْمَرْأَةِ فَقَالَتْ كَذَبَ وَاللَّهِ يَا رَسُولَ اللَّهِ فَجَلَدَهُ حَدَّ الْفِرْيَةِ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin faris] berkata, telah menceritakan kepada kami [Musa bin Harun Al Burdi] berkata, telah menceritakan kepada kami [Hisyam bin Yusuf] dari [Al Qasim bin Fayyadh Al Anbari] dari [Khallad bin 'Abdurrahman] dari [ibnul Musayyab] dari [Ibnu Abbas] berkata, \"Seorang laki-laki dari bani Bakr bin Laits mendatangi Nabi shallallahu 'alaihi wasallam. Laki-laki itu lalu mengaku -ia ulangi hingga empat kali- bahwa dirinya pernah berzina dengan seorang wanita, maka beliau menderanya sebanyak seratus kali karena ia belum menikah. Kemudian beliau bertanya kepadanya tentang bukti bahwa wanita itu berzina (dengannya), wanita itu berkata, \"Wahai Rasulullah, demi Allah ia telah berdusta.\" Beliau lalu mendera laki-laki itu sebanyak delapan puluh kali karena tuduhan zinanya kepada wanita itu.\""},"3753":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا سِمَاكٌ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَا قَالَ عَبْدُ اللَّهِجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي عَالَجْتُ امْرَأَةً مِنْ أَقْصَى الْمَدِينَةِ فَأَصَبْتُ مِنْهَا مَا دُونَ أَنْ أَمَسَّهَا فَأَنَا هَذَا فَأَقِمْ عَلَيَّ مَا شِئْتَ فَقَالَ عُمَرُ قَدْ سَتَرَ اللَّهُ عَلَيْكَ لَوْ سَتَرْتَ عَلَى نَفْسِكَ فَلَمْ يَرُدَّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَانْطَلَقَ الرَّجُلُ فَأَتْبَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَدَعَاهُ فَتَلَا عَلَيْهِ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ يَا رَسُولَ اللَّهِ أَلَهُ خَاصَّةً أَمْ لِلنَّاسِ كَافَّةً فَقَالَ لِلنَّاسِ كَافَّةً","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] berkata, telah menceritakan kepada kami [Abul Ahwash] berkata, telah menceritakan kepada kami [Simak] dari [Ibrahim] dari [Alqamah] dan [Al Aswad] keduanya berkata, \" [Abdullah] berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku telah mencumbui seorang wanita dari pinggiran kota, aku telah melakukan semuanya kecuali persetubuhan. Dan sekarang aku ada dihadapanmu, maka hukumlah aku sekehendakmu.\" Umar menimpali, \"Allah telah menutupimu sekirannya kamu menutupi dirimu sendiri.\" Nabi shallallahu 'alaihi wasallam tidak memberi komentar apapun juga. Laki-laki itu lalu pergi dan Nabi shallallahu 'alaihi wasallam menyuruh orang mengikutinya dari belakang, beliau lantas memanggil laki-laki tersebut seraya membaca ayat: '(Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat) '. Lalu ada seorang laki-laki dari kaum muslimin yang bertanya, \"Wahai Rasulullah, ayat itu khusus untuknya atau berlaku untuk semua orang?\" beliau menjawab: \"Berlaku untuk semua orang.\""},"3754":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْأَمَةِ إِذَا زَنَتْ وَلَمْ تُحْصَنْ قَالَ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَبِيعُوهَا وَلَوْ بِضَفِيرٍقَالَ ابْنُ شِهَابٍ لَا أَدْرِي فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ وَالضَّفِيرُ الْحَبْلُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abu Hurairah] dan [Zaid bin Khalid Al Juhani] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang seorang budak wanita yang berzina, tetapi ia belum menikah? Beliau menjawab: \"Jika ia melakukan zina maka cambuklah, jika melakukan zina lagi maka cambuklah, jika melakukan zina lagi maka cambuklah, kemudian jika ia melakukan zina lagi maka juallah meskipun dengan seharga tali pengikat rambut.\" Ibnu Syihab berkata, \"Aku tidak tahu, itu berlaku pada kali ketiga atau keempat. Sementara Adh dhafir adalah tali (rambut).\""},"3755":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَنَتْ أَمَةُ أَحَدِكُمْ فَلْيَحُدَّهَا وَلَا يُعَيِّرْهَا ثَلَاثَ مِرَارٍ فَإِنْ عَادَتْ فِي الرَّابِعَةِ فَلْيَجْلِدْهَا وَلْيَبِعْهَا بِضَفِيرٍ أَوْ بِحَبْلٍ مِنْ شَعْرٍحَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ فِي كُلِّ مَرَّةٍ فَلْيَضْرِبْهَا كِتَابُ اللَّهِ وَلَا يُثَرِّبْ عَلَيْهَا وَقَالَ فِي الرَّابِعَةِ فَإِنْ عَادَتْ فَلْيَضْرِبْهَا كِتَابُ اللَّهِ ثُمَّ لِيَبِعْهَا وَلَوْ بِحَبْلٍ مِنْ شَعْرٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ubaidullah] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika budak wanita salah seorang dari kalian berbuat zina maka tegakkanlah hukuman had dan jangan kalian cela dia -beliau ulangi hal itu hingga tiga kali-. Jika ia tetap mengulanginya pada kali keempat, maka cambuk dan juallah meskipun seharga tali rambut.\" Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang sama. Setiap kali budak itu melakukan zina beliau bersabda: \"Hukumilah dengan Kitabullah dan jangan engkau cela.\" Maka pada kali keempat, beliau bersabda: \"Jika ia tetap mengulanginya, maka hukumilah dengan kitabullah, setelah itu juallah meski seharga tali rambut.\""},"3756":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ أَنَّهُ أَخْبَرَهُ بَعْضُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَنْصَارِأَنَّهُ اشْتَكَى رَجُلٌ مِنْهُمْ حَتَّى أُضْنِيَ فَعَادَ جِلْدَةً عَلَى عَظْمٍ فَدَخَلَتْ عَلَيْهِ جَارِيَةٌ لِبَعْضِهِمْ فَهَشَّ لَهَا فَوَقَعَ عَلَيْهَا فَلَمَّا دَخَلَ عَلَيْهِ رِجَالُ قَوْمِهِ يَعُودُونَهُ أَخْبَرَهُمْ بِذَلِكَ وَقَالَ اسْتَفْتُوا لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي قَدْ وَقَعْتُ عَلَى جَارِيَةٍ دَخَلَتْ عَلَيَّ فَذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا مَا رَأَيْنَا بِأَحَدٍ مِنْ النَّاسِ مِنْ الضُّرِّ مِثْلَ الَّذِي هُوَ بِهِ لَوْ حَمَلْنَاهُ إِلَيْكَ لَتَفَسَّخَتْ عِظَامُهُ مَا هُوَ إِلَّا جِلْدٌ عَلَى عَظْمٍ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْخُذُوا لَهُ مِائَةَ شِمْرَاخٍ فَيَضْرِبُوهُ بِهَا ضَرْبَةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Abu Umamah bin Sahl bin Hanif] Bahwasanya [sebagian sahabat] Rasulullah shallallahu 'alaihi wasallam dari kalangan Anshar pernah mengabarkan kepadanya, bahwa ada seorang laki-laki Anshar terserang penyakit hingga tubuhnya hanya kulit dan tulang saja. Kemudian budak wanita salah seorang dari mereka masuk menemuinya, hingga ia berhasrat kepada budak itu dan mensetubuhinya. Maka, ketika para sahabatnya datang menjenguk, hal itu ia kabarkan kepada mereka. Ia berkata, \"Mintakanlah aku fatwa kepada Rasulullah shallallahu 'alaihi wasallam; aku telah mensetubuhi budak wanita yang masuk menemuiku.\" Lalu mereka menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, mereka berkata, \"Kami tidak pernah melihat seorang pun dari manusia yang mengalami sakit separah itu, jika kami membawanya kehadapanmu maka tulangnya akan berserakan. Sungguh, ia kini tinggal kulit pembungkus tulang!\" Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan mereka untuk mengambil seratus biji adas, agar mereka melemparkannya kepada laki-laki tersebut dengan sekali lemparan.\""},"3757":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ أَبِي جَمِيلَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَفَجَرَتْ جَارِيَةٌ لِآلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عَلِيُّ انْطَلِقْ فَأَقِمْ عَلَيْهَا الْحَدَّ فَانْطَلَقْتُ فَإِذَا بِهَا دَمٌ يَسِيلُ لَمْ يَنْقَطِعْ فَأَتَيْتُهُ فَقَالَ يَا عَلِيُّ أَفَرَغْتَ قُلْتُ أَتَيْتُهَا وَدَمُهَا يَسِيلُ فَقَالَ دَعْهَا حَتَّى يَنْقَطِعَ دَمُهَا ثُمَّ أَقِمْ عَلَيْهَا الْحَدَّ وَأَقِيمُوا الْحُدُودَ عَلَى مَا مَلَكَتْ أَيْمَانُكُمْقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ أَبُو الْأَحْوَصِ عَنْ عَبْدِ الْأَعْلَى وَرَوَاهُ شُعْبَةُ عَنْ عَبْدِ الْأَعْلَى فَقَالَ فِيهِ قَالَ لَا تَضْرِبْهَا حَتَّى تَضَعَ وَالْأَوَّلُ أَصَحُّ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Isra'il] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Abu Jamilah] dari [Ali radliallahu 'anhu] ia berkata, \"Seorang budak wanita milik keluarga Rasulullah shallallahu 'alaihi wasallam berbuat serong (zina), maka beliau bersabda: \"Wahai Ali, pergi dan tegakkanlah had atas dirinya.\" Aku lalu pergi menemui wanita itu, dan ternyata darah (nifas) nya belum berhenti.\" Maka aku kembali mendatangi Nabi shallallahu 'alaihi wasallam, beliau bertanya kepadaku: \"Wahai Ali, apakah engkau telah selesai?\" Aku menjawab, \"Saat aku mendatanginya, darah nifasnya masih mengalir.\" Beliau bersabda: \"Biarkanlah hingga masa nifasnya selesai, setelah itu tegakkanlah hudud atasnya. Dan laksanakanlah hukum hudud itu atas budak-budak kalian.\" Abu Dawud berkata, \" [Abu Al Ahwash] juga meriwayatkannya dari [Abdul A'la]. [Syu'bah] juga meriwayatkannya dari [Abdul A'la], ia menyebutkan dalam haditsnya, \"janganlah kamu rajam hingga ia melahirkan.\" Dan hadits pertama lebih shahih. "},"3758":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ وَمَالِكُ بْنُ عَبْدِ الْوَاحِدِ الْمِسْمَعِيُّ وَهَذَا حَدِيثُهُ أَنَّ ابْنَ أَبِي عَدِيٍّ حَدَّثَهُمْ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَ عُذْرِي قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَذَكَرَ ذَاكَ وَتَلَا تَعْنِي الْقُرْآنَ فَلَمَّا نَزَلَ مِنْ الْمِنْبَرِ أَمَرَ بِالرَّجُلَيْنِ وَالْمَرْأَةِ فَضُرِبُوا حَدَّهُمْحَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ بِهَذَا الْحَدِيثِ لَمْ يَذْكُرْ عَائِشَةَ قَالَ فَأَمَرَ بِرَجُلَيْنِ وَامْرَأَةٍ مِمَّنْ تَكَلَّمَ بِالْفَاحِشَةِ حَسَّانَ بْنِ ثَابِتٍ وَمِسْطَحِ بْنِ أُثَاثَةَ قَالَ النُّفَيْلِيُّ وَيَقُولُونَ الْمَرْأَةُ حَمْنَةُ بِنْتُ جَحْشٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id Ats Tsaqafi] dan [Malik bin Abdul Wahid Al Misma'i] -dan ini adalah haditsnya- bahwa [Ibnu Abu Adi] menceritakan kepada mereka dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakr] dari [Amrah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Ketika Allah menurunkan udzurku (Ayat yang membebaskan 'Aisyah dari kasus fitnah yang dituduhkan padanya), Nabi shallallahu 'alaihi wasallam berpidato di atas mimbar dan menyampaikan hal itu seraya membacakan ayat Al-Qur'an. Ketika turun dari mimbar, beliau langsung memerintahkan untuk menghukum dua orang laki-laki dan seorang wanita (pelaku fitnah), maka mereka pun dicambuk sebagai had.\" Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] seperti hadits ini, hanya saja ia tidak menyebutkan nama 'Aisyah. Ia menyebutkan, \"Beliau kemudian memerintahkan untuk menghukum dua orang lelaki -Hassan bin Tsabit dan Misthah bin utsatsah- dan seorang wanita karena termasuk orang-orang yang menyebarkan fitnah (atas diri 'Aisyah) tersebut.\" An Nufaili berkata, \"Mereka mengatakan bahwa wanita itu adalah Hamnah binti Jahsy.\""},"3759":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَهَذَا حَدِيثُهُ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ رُكَانَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَقِتْ فِي الْخَمْرِ حَدًّا وَقَالَ ابْنُ عَبَّاسٍ شَرِبَ رَجُلٌ فَسَكِرَ فَلُقِيَ يَمِيلُ فِي الْفَجِّ فَانْطُلِقَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا حَاذَى بِدَارِ الْعَبَّاسِ انْفَلَتَ فَدَخَلَ عَلَى الْعَبَّاسِ فَالْتَزَمَهُ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ وَقَالَ أَفَعَلَهَا وَلَمْ يَأْمُرْ فِيهِ بِشَيْءٍقَالَ أَبُو دَاوُد هَذَا مِمَّا تَفَرَّدَ بِهِ أَهْلُ الْمَدِينَةِ حَدِيثُ الْحَسَنِ بْنِ عَلِيٍّ هَذَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Muhammad Ibnul Mutsanna] -dan ini adalah haditsnya- keduanya berkata; telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dari [Muhammad bin Ali bin Rukanah] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Berkaitan dengan khamer Rasulullah shallallahu 'alaihi wasallam belum menentukan hukuman had.\" Ibnu Abbas berkata, \"Seorang laki-laki minum khamer hingga mabuk, lalu orang itu terlihat berada di jalan yang besar, maka ia pun dibawa untuk dihadapkan kepada Nabi shallallahu 'alaihi wasallam. Ketika hampir sampai rumah Al Abbas, ia menyelinap dan kabur sembunyi di rumah Al Abbas. Hal itu lalu disampaikan kepada Nabi shallallahu 'alaihi wasallam hingga beliau tertawa. Beliau bersabda: \"Apakah ia benar-benar melakukannya?\" Beliau tidak memerintahkan hukuman apapun.\" Abu Dawud berkata, \"Ini merupakan hadits yang hanya diriwayatkan oleh penduduk Madinah, yakni hadits Al Hasan bin Ali.\""},"3760":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو ضَمْرَةَ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِرَجُلٍ قَدْ شَرِبَ فَقَالَ اضْرِبُوهُ قَالَ أَبُو هُرَيْرَةَ فَمِنَّا الضَّارِبُ بِيَدِهِ وَالضَّارِبُ بِنَعْلِهِ وَالضَّارِبُ بِثَوْبِهِ فَلَمَّا انْصَرَفَ قَالَ بَعْضُ الْقَوْمِ أَخْزَاكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا هَكَذَا لَا تُعِينُوا عَلَيْهِ الشَّيْطَانَحَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ أَبِي نَاجِيَةَ الْإِسْكَنْدَرَانِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ وَحَيْوَةُ بْنُ شُرَيْحٍ وَابْنُ لَهِيعَةَ عَنْ ابْنِ الْهَادِ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فِيهِ بَعْدَ الضَّرْبِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ بَكِّتُوهُ فَأَقْبَلُوا عَلَيْهِ يَقُولُونَ مَا اتَّقَيْتَ اللَّهَ مَا خَشِيتَ اللَّهَ وَمَا اسْتَحْيَيْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَرْسَلُوهُ وَقَالَ فِي آخِرِهِ وَلَكِنْ قُولُوا اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ وَبَعْضُهُمْ يَزِيدُ الْكَلِمَةَ وَنَحْوَهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Dhamrah] dari [Yazid Ibnul Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Seorang yang telah minum khamer didatangkan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Pukullah ia.\" Abu Hurairah berkata, \"Di antara kita ada yang memukul dengan tangan, sandal dan kain. Ketika beliau beranjak pergi, sebagian kami ada yang mengucapkan, \"Semoga Allah menghinakanmu!\" maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Janganlah kalian mengatakan begitu, jangan kalian bantu setan dalam memperdayanya.\" Telah menceritakan kepada kami [Muhammad bin Daud bin Abu Najiyah Al Iskandarani] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yahya bin Ayyub] dan [Haiwah bin Syuraih] dan [Ibnu Lahi'ah] dari [Ibnul Had] dengan sanad dan maknanya. Setelah pemukulan (terhadap peminum khamer), ia menyebutkan dalam haditsnya, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Jelekkanlah ia.\" Maka orang-orang kembali menemui peminum khamer itu dan berkata, \"Kamu tidak bertakwa kepada Allah!\" Ada yang berkata, \"Kamu tidak takut kepada Allah!\" Ada yang berkata, \"Kamu tidak punya malu kepada Rasulullah shallallahu 'alaihi wasallam! ' Kemudian mereka membebaskan orang tersebut. Dan diakhir ucapannya, beliau mengatakan: \"Jangan kalian katakan yang demikian, tetapi ucapkanlah 'Ya Allah ampunilah ia, ya Allah rahmatilah ia'.\" Dan sebagian mereka ada yang menambahkan kalimat dan semisalnya.\""},"3761":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ الْمَعْنَى عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَدَ فِي الْخَمْرِ بِالْجَرِيدِ وَالنِّعَالِوَجَلَدَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ أَرْبَعِينَ فَلَمَّا وُلِّيَ عُمَرُ دَعَا النَّاسَ فَقَالَ لَهُمْ إِنَّ النَّاسَ قَدْ دَنَوْا مِنْ الرِّيفِ وَقَالَ مُسَدَّدٌ مِنْ الْقُرَى وَالرِّيفِ فَمَا تَرَوْنَ فِي حَدِّ الْخَمْرِ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ نَرَى أَنْ تَجْعَلَهُ كَأَخَفِّ الْحُدُودِ فَجَلَدَ فِيهِ ثَمَانِينَ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ جَلَدَ بِالْجَرِيدِ وَالنِّعَالِ أَرْبَعِينَ وَرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَرَبَ بِجَرِيدَتَيْنِ نَحْوَ الْأَرْبَعِينَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] secara makna, dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam menghukum peminum khamer dengan cambukan pelepah kurma dan sandal. Abu Bakar radliallahu 'anhu mencambuk sebanyak empat puluh kali, maka ketika umar diangkat menjadi khalifah, ia menyeru orang-orang dan berpesan, \"Sekarang manusia sudah banyak menghuni Ar Rif (perkampungan yang banyak tumbuh pohon kurma), lalu bagaimana batasan hukum (dera) bagi peminum khamer menurut kalian?\" 'Abdurrahman bin Auf lalu berkata kepadanya, \"Menurutku, hendaklah engkau beri hukuman yang paling ringan, \" Umar lalu menghukumnya dengan delapan puluh deraan.\" Abu Dawud berkata, \" [Ibnu Abu Arubah] meriwayatkannya dari [Qatadah], dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau mendera (peminum khamer) dengan pelepah kurma dan sandal sebanyak empat puluh kali.\" Dan [Syu'bah] meriwayatkan dari [Qatadah], dari [Anas], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Beliau memukul dengan dua pelepah kurma sebanyak empat puluh kali.\""},"3762":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ وَمُوسَى بْنُ إِسْمَعِيلَ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا عَبْدُ اللَّهِ الدَّانَاجُ حَدَّثَنِي حُضَيْنُ بْنُ الْمُنْذِرِ الرَّقَاشِيُّ هُوَ أَبُو سَاسَانَ قَالَشَهِدْتُ عُثْمَانَ بْنَ عَفَّانَ وَأُتِيَ بِالْوَلِيدِ بْنِ عُقْبَةَ فَشَهِدَ عَلَيْهِ حُمْرَانُ وَرَجُلٌ آخَرُ فَشَهِدَ أَحَدُهُمَا أَنَّهُ رَآهُ شَرِبَهَا يَعْنِي الْخَمْرَ وَشَهِدَ الْآخَرُ أَنَّهُ رَآهُ يَتَقَيَّأُ فَقَالَ عُثْمَانُ إِنَّهُ لَمْ يَتَقَيَّأْ حَتَّى شَرِبَهَا فَقَالَ لِعَلِيٍّ رَضِيَ اللَّهُ عَنْهُ أَقِمْ عَلَيْهِ الْحَدَّ فَقَالَ عَلِيٌّ لِلْحَسَنِ أَقِمْ عَلَيْهِ الْحَدَّ فَقَالَ الْحَسَنُ وَلِّ حَارَّهَا مَنْ تَوَلَّى قَارَّهَا فَقَالَ عَلِيٌّ لِعَبْدِ اللَّهِ بْنِ جَعْفَرٍ أَقِمْ عَلَيْهِ الْحَدَّ قَالَ فَأَخَذَ السَّوْطَ فَجَلَدَهُ وَعَلِيٌّ يَعُدُّ فَلَمَّا بَلَغَ أَرْبَعِينَ قَالَ حَسْبُكَ جَلَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ أَحْسَبُهُ قَالَ وَجَلَدَ أَبُو بَكْرٍ أَرْبَعِينَ وَعُمَرُ ثَمَانِينَ وَكُلٌّ سُنَّةٌ وَهَذَا أَحَبُّ إِلَيَّ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhid] dan [Musa bin Isma'il] secara makna, keduanya berkata; telah menceritakan kepada kami [Abdul Aziz Ibnul Mukhtar] berkata, telah menceritakan kepada kami [Abdullah Ad Danaj] berkata, telah menceritakan kepadaku [Hudhain Ibnul Mundzir Ar Raqasyi] -maksudnya Abu Yasan- ia berkata, \"Ketika aku ada di sisi Utsman bin Affan, Al Walid bin Uqbah dihadapkan kepadanya, lalu Humran dan seorang laki-laki lain bersaksi, bahwa salah seorang dari mereka melihat (Al Walid) minum khamer, dan yang lain melihatnya muntah (karena khamer). Utsman lantas berkata, \"Ia tidak mungkin muntah kecuali karena sebab minum khamer! ' Lalu ia berkata kepada [Ali] radliallahu 'anhu, \"Laksanakan hukuman had atasnya.\" Kemudian Ali juga berkata kepada Al Hasan, \"Laksanakan hukuman had atasnya.\" Maka Al Hasan pun berkomentar, \"Berikanlah kekuasaan kepada orang yang layak memikulnya.\" Ali radliallahu 'anhu akhirnya berkata kepada Abdullah bin Ja'far, \"Laksanakan hukuman had atasnya.\" Maka Abdullah segera mengambil pecut dan mencambuknya (Al Walid), sementara Ali menghitungnya. Maka ketika sampai pada hitungan keempat puluh, Ali berkata, \"Cukup! Nabi shallallahu 'alaihi wasallam mendera sebanyak empat puluh kali, Abu Bakar empat puluh kali dan Umar delapan puluh kali. Semua itu sunnah, namun aku lebih suka yang ini (empat puluh kali).\""},"3763":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ الدَّانَاجِ عَنْ حُضَيْنِ بْنِ الْمُنْذِرِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَجَلَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمْرِوَأَبُو بَكْرٍ أَرْبَعِينَ وَكَمَّلَهَا عُمَرُ ثَمَانِينَ وَكُلٌّ سُنَّةٌ قَالَ أَبُو دَاوُد و قَالَ الْأَصْمَعِيُّ وَلِّ حَارَّهَا مَنْ تَوَلَّيْ قَارَّهَا وَلِّ شَدِيدَهَا مَنْ تَوَلَّى هَيِّنَهَا قَالَ أَبُو دَاوُد هَذَا كَانَ سَيِّدَ قَوْمِهِ حُضَيْنُ بْنُ الْمُنْذِرِ أَبُو سَاسَانَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ibnu Abu Arubah] dari [Ad Danaj] dari [Hudhain Ibnul Mundzir] dari [Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar mendera peminum khamer sebanyak empat puluh kali, lalu Umar menggenapkannya menjadi delapan puluh kali, dan semua itu adalah sunnah.\" Abu Dawud berkata, \"Al Ashma'I berkata, \"Berikanlah kekuasaan kepada orang yang layak menjalaninya, yakni berikanlah orang yang bisa berlaku keras maupun lembut.\" Abu Dawud berkata lagi, \"Pemimpun kaumnya adalah Khudhain Ibnul Mundzir Abu Sasan.\""},"3764":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ ذَكْوَانَ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبُوا الْخَمْرَ فَاجْلِدُوهُمْ ثُمَّ إِنْ شَرِبُوا فَاجْلِدُوهُمْ ثُمَّ إِنْ شَرِبُوا فَاجْلِدُوهُمْ ثُمَّ إِنْ شَرِبُوا فَاقْتُلُوهُمْحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدِ بْنِ يَزِيدَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِهَذَا الْمَعْنَى قَالَ وَأَحْسِبُهُ قَالَ فِي الْخَامِسَةِ إِنْ شَرِبَهَا فَاقْتُلُوهُ قَالَ أَبُو دَاوُد وَكَذَا فِي حَدِيثِ أَبِي غُطَيْفٍ فِي الْخَامِسَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Aban] dari [Ashim] dari [Abu Shalih Dzakwan] dari [Mu'awiyah bin Abu Sufyan] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika mereka minum khamer maka cambuklah, jika mereka minum lagi maka cambuklah, jika mereka minum lagi maka cambuklah, dan jika mereka minum lagi maka bunuhlah.\" Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Humaid bin Yazid] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda dengan makna tersebut. Ia (perawi) berkata, \"Menurutku beliau bersabda pada kali kelima: \"Jika ia meminumnya lagi maka bunuhlah.\" Abu Dawud berkata, \"Dalam hadits Abu Ghuthaif juga dengan lafadz 'pada kali kelima'.\""},"3765":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ الْأَنْطَاكِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ الْوَاسِطِيُّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكَرَ فَاجْلِدُوهُ ثُمَّ إِنْ سَكَرَ فَاجْلِدُوهُ ثُمَّ إِنْ سَكَرَ فَاجْلِدُوهُ فَإِنْ عَادَ الرَّابِعَةَ فَاقْتُلُوهُقَالَ أَبُو دَاوُد وَكَذَا حَدِيثُ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبَ الْخَمْرَ فَاجْلِدُوهُ فَإِنْ عَادَ الرَّابِعَةَ فَاقْتُلُوهُ قَالَ أَبُو دَاوُد وَكَذَا حَدِيثُ سُهَيْلٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شَرِبُوا الرَّابِعَةَ فَاقْتُلُوهُمْ وَكَذَا حَدِيثُ ابْنِ أَبِي نُعْمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَا حَدِيثُ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالشَّرِيدِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَدِيثِ الْجَدَلِيِّ عَنْ مُعَاوِيَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنْ عَادَ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ فَاقْتُلُوهُ","id":"Telah menceritakan kepada kami [Nashr bin Ashim Al Anthaki] berkata, telah menceritakan kepada kami [Yazid bin Harun Al Wasithi] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Harits bin 'Abdurrahman] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ia mabuk maka cembuklah, kemudian jika ia mabuk lagi maka cambuklah, kemudian jika ia mabuk lagi maka cambuklah, kemudian jika ia mengulangi lagi pada kali keempat maka bunuhlah.\" Abu Dawud berkata, \"demikian juga hadits [Umar bin Abu Salamah], dari [bapaknya], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika ia minum khamer maka cambuklah, jika ia mengulanginya lagi untuk kali keempat maka bunuhlah.\" Demikan juga dalam hadits [Suhail] dari [Abu Shalih], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika mereka minum pada kali keempat, maka bunuhlah mereka.\" Demikian juga dalam hadits [Ibnu Abu Nu'm] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam. Demikian juga dengan hadits Abdullah bin Amru dari Nabi shallallahu 'alaihi wasallam, dan Asy Syarid dari Nabi shallallahu 'alaihi wasallam dalam hadits riwayat [Al Jadali], dari [Mu'awiyah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika ia mengulanginya lagi pada kali ketiga, atau keempat maka bunuhlah ia.\""},"3766":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ أَخْبَرَنَا عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فَاجْلِدُوهُ فَإِنْ عَادَ فَاجْلِدُوهُ فَإِنْ عَادَ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ فَاقْتُلُوهُ فَأُتِيَ بِرَجُلٍ قَدْ شَرِبَ فَجَلَدَهُ ثُمَّ أُتِيَ بِهِ فَجَلَدَهُ ثُمَّ أُتِيَ بِهِ فَجَلَدَهُ ثُمَّ أُتِيَ بِهِ فَجَلَدَهُ وَرَفَعَ الْقَتْلَ وَكَانَتْ رُخْصَةٌقَالَ سُفْيَانُ حَدَّثَ الزُّهْرِيُّ بِهَذَا الْحَدِيثِ وَعِنْدَهُ مَنْصُورُ بْنُ الْمُعْتَمِرِ وَمِخْوَلُ بْنُ رَاشِدٍ فَقَالَ لَهُمَا كُونَا وَافِدَيْ أَهْلِ الْعِرَاقِ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ الشَّرِيدُ بْنُ سُوَيْدٍ وَشُرَحْبِيلُ بْنُ أَوْسٍ وَعَبْدُ اللَّهِ بْنُ عَمْرٍو وَعَبْدُ اللَّهِ بْنُ عُمَرَ وَأَبُو غُطَيْفٍ الْكِنْدِيُّ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adh Dhabbi] berkata, telah menceritakan kepada kami [Sufyan], [Az Zuhri] berkata; telah mengabarkan kepada kami dari [Qabishah bin Dzuaib] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer maka cambuklah, jika ia mengulanginya lagi maka cambuklah, jika ia mengulanginya lagi pada kali ketiga atau keempat maka bunuhlah ia.\" Kemudian dihadapkan kepada beliau seorang laki-laki yang telah minum khamer, beliau lalu menderanya, kemudian orang itu dihadapkan lagi lalu beliau menderanya, kemudian orang itu dihadapkan lagi lalu beliau menderanya, kemudian orang itu dihadapkan lagi lalu beliau menderanya dan tidak dibunuh, namun itu adalah keringanan.\" [Sufyan] berkata, \"Az Zuhri menceritakan hadits ini, sementara di sisinya ada Manshur Ibnul Mu'tamir dan Mikhwal bin Rasyid. Maka ia berkata kepada keduanya, \"Kalian berdua jadilah kurir bagi penduduk Irak dengan hadits ini.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh Asy Syarid bin Suwaid, Syurahbil bin Aus, Abdullah bin Amru, Abdullah bin Umar, Abu Ghuthaif Al Kindi, dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah].\""},"3767":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي حُصَيْنٍ عَنْ عُمَيْرِ بْنِ سَعِيدٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَلَا أَدِي أَوْ مَا كُنْتُ لِأَدِيَ مَنْ أَقَمْتُ عَلَيْهِ حَدًّا إِلَّا شَارِبَ الْخَمْرِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسُنَّ فِيهِ شَيْئًا إِنَّمَا هُوَ شَيْءٌ قُلْنَاهُ نَحْنُ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Faari] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Hushain] dari [Umair bin Sa'id] dari [Ali radliallahu 'anhu] ia berkata, \"Aku tidak pernah menerapkan hukuman had kecuali pada peminum khamer, sebab Rasulullah shallallahu 'alaihi wasallam tidak memberi contoh dalam hal itu sesuatu pun. Tetapi itu hanyalah (suatu) perkataan kami.\""},"3768":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ الْمِصْرِيُّ ابْنُ أَخِي رِشْدِينَ بْنِ سَعْدٍ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ قَالَكَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآنَ وَهُوَ فِي الرِّحَالِ يَلْتَمِسُ رَحْلَ خَالِدِ بْنِ الْوَلِيدِ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أُتِيَ بِرَجُلٍ قَدْ شَرِبَ الْخَمْرَ فَقَالَ لِلنَّاسِ اضْرِبُوهُ فَمِنْهُمْ مَنْ ضَرَبَهُ بِالنِّعَالِ وَمِنْهُمْ مَنْ ضَرَبَهُ بِالْعَصَا وَمِنْهُمْ مَنْ ضَرَبَهُ بِالْمِيتَخَةِ قَالَ ابْنُ وَهْبٍ الْجَرِيدَةُ الرَّطْبَةُ ثُمَّ أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُرَابًا مِنْ ال��أَرْضِ فَرَمَى بِهِ فِي وَجْهِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri Al Mishri bin Akhi Risydina bin Sa'd] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Usamah bin Zaid] bahwa [Ibnu Syihab] menceritakan kepadanya dari ['Abdurrahman bin Azhar] berkata, \"Saat ini seakan aku melihat Rasulullah shallallahu 'alaihi wasallam sedang berada di sebuah pemukiman, beliau mencari rumah Khalid Ibnul Walid. Ketika beliau dalam keadaan seperti itu, seorang laki-laki yang telah minum khamer dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda kepada orang banyak: \"Pukullah ia!\" kemudian di antara mereka ada yang memukul dengan sandal, tongkat dan Mitakhah -Ibnu Wahb mengartikan dengan pelepah kurma yang basah-.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam mengambil pasir dan melemparkannya ke wajah laki-laki itu.\""},"3769":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ قَالَ وَجَدْتُ فِي كِتَابِ خَالِي عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ الْحَمِيدِ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْأَزْهَرِ أَخْبَرَهُ عَنْ أَبِيهِ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَارِبٍ وَهُوَ بِحُنَيْنٍ فَحَثَى فِي وَجْهِهِ التُّرَابَ ثُمَّ أَمَرَ أَصْحَابَهُ فَضَرَبُوهُ بِنِعَالِهِمْ وَمَا كَانَ فِي أَيْدِيهِمْ حَتَّى قَالَ لَهُمْ ارْفَعُوا فَرَفَعُوافَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَلَدَ أَبُو بَكْرٍ فِي الْخَمْرِ أَرْبَعِينَ ثُمَّ جَلَدَ عُمَرُ أَرْبَعِينَ صَدْرًا مِنْ إِمَارَتِهِ ثُمَّ جَلَدَ ثَمَانِينَ فِي آخِرِ خِلَافَتِهِ ثُمَّ جَلَدَ عُثْمَانُ الْحَدَّيْنِ كِلَيْهِمَا ثَمَانِينَ وَأَرْبَعِينَ ثُمَّ أَثْبَتَ مُعَاوِيَةُ الْحَدَّ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] ia berkata; Aku mendapatkan dalam buku pamanku ['Abdurrahman bin Abdul hamid] dari [Uqail] dari [Ibnu Syihab] mengabarkan kepadanya, bahwa [Abdullah bin 'Abdurrahman Ibnul Azhar] mengabarkan kepadanya dari [Bapaknya] ia berkata, \"Saat Nabi shallallahu 'alaihi wasallam berada di Hunain, seorang peminum khamer dihadapkan kepada beliau, maka beliau melemparkan pasir ke wajah laki-laki itu. Kemudian beliau memerintahkan kepada para sahabatnya untuk (memberi hukuman), maka mereka pun memukulinya dengan sandal dan apa saja yang ada di tangan mereka, hingga beliau mengatakan: \"Cukup!\" mereka pun berhenti. Ketika Rasulullah shallallahu 'alaihi wasallam wafat, Abu Bakar mendera peminum khamer sebanyak empat puluh kali, Umar juga mendera sebanyak empat puluh kali pada awal pemerintahannya, kemudian mendera sebanyak delapan puluh kali pada akhir masa pemerintahannya. Kemudian Utsman melaksanakan kedua hukuman tersebut (empat puluh dan delapan puluh). Setelah itu Mu'awiyah menetapkan jumlahnya menjadi delapan puluh kali.\""},"3770":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ الْفَتْحِ وَأَنَا غُلَامٌ شَابٌّ يَتَخَلَّلُ النَّاسَ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِشَارِبٍ فَأَمَرَهُمْ فَضَرَبُوهُ بِمَا فِي أَيْدِيهِمْ فَمِنْهُمْ مَنْ ضَرَبَهُ بِالسَّوْطِ وَمِنْهُمْ مَنْ ضَرَبَهُ بِعَصًا وَمِنْهُمْ مَنْ ضَرَبَهُ بِنَعْلِهِ وَحَثَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التُّرَابَ فَلَمَّا كَانَ أَبُو بَكْرٍ أُتِيَ بِشَارِبٍ فَسَأَلَهُمْ عَنْ ضَرْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي ضَرَبَهُ فَحَزَرُوهُ أَرْبَعِينَفَضَرَبَ أَبُو بَكْرٍ أَرْبَعِينَ فَلَمَّا كَانَ عُمَرُ كَتَبَ إِلَيْهِ خَالِدُ بْنُ الْوَلِيدِ إِنَّ النَّاسَ قَدْ انْهَمَكُوا فِي الشُّرْبِ وَتَحَاقَرُوا الْحَدَّ وَالْعُقُوبَةَ قَالَ هُمْ عِنْدَكَ فَسَلْهُمْ وَعِنْدَهُ الْمُهَاجِرُونَ الْأَوَّلُونَ فَسَأَلَهُمْ فَأَجْمَعُوا عَلَى أَنْ يَضْرِبَ ثَمَانِينَ قَالَ و قَالَ عَلِيٌّ إِنَّ الرَّجُلَ إِذَا شَرِبَ افْتَرَى فَأَرَى أَنْ يَجْعَلَهُ كَحَدِّ الْفِرْيَةِ قَالَ أَبُو دَاوُد أَدْخَلَ عُقَيْلُ بْنُ خَالِدٍ بَيْنَ الزُّهْرِيِّ وَبَيْنَ ابْنِ الْأَزْهَرِ فِي هَذَا الْحَدِيثِ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْأَزْهَرِ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Al hasan bin Ali] berkata, telah menceritakan kepada kami [Utsman bin Umar] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari [Az Zuhri] dari ['Abdurrahman bin Azhar] ia berkata, \"Saat aku masih kecil, dipagi hari penaklukan kota Makkah, aku melihat Rasulullah shallallahu 'alaihi wasallam bertanya kepada orang-orang di mana letak rumah Khalid bin Walid. Lalu didatangkanlah seorang peminum khamer kepada beliau, beliau lalu memerintahkan kepada orang-orang untuk menghukumnya. Maka mereka memukuli orang itu dengan apa saja yang ada di tangan mereka; di antara mereka ada yang memukul dengan pecut, tongkat dan sandal, sementara Rasulullah shallallahu 'alaihi wasallam melemparnya dengan pasir. Ketika dihadapkan seorang peminum khamer kepada Abu Bakar, maka ia bertanya kepada orang-orang bagaimana Nabi shallallahu 'alaihi wasallam memberi hukuman. Mereka lalu memeritahukan bahwa Rasulullah memukulnya sebanyak empat puluh kali, maka ia memukul (peminum itu) sebanyak empat puluh kali. Ketika Umar memerintah, Khalid Ibnul Walid menulis surat kepadanya bahwa orang-orang telah banyak minum khamer dan meremehkan hukuman hudud. Umar menjawab, \"Kasus mereka terserah kamu, maka tanyakanlah kepada mereka (kaum muhajirin).\" Karena di sisi Khalid banyak sahabat-sahabat Muhajirin, maka ia bertanya kepada mereka, dan mereka pun sepakat untuk mendera peminum khamer sebanyak delapan puluh kali.\" Ali radliallahu 'anhu berkata, \"Seorang laki-laki jika minum khamer, maka ia akan mudah berdusta, maka aku berpandangan untuk menyamakan hukuman mereka dengan pelaku firyah (menuduh zina tanpa bukti).\" Abu Dawud berkata, \" [Uqail bin Khalid] menempatkan [Abdullah bin 'Abdurrahman Ibnul Azhar] dari [ayahnya] (sebagai sanad) dalam hadits ini berada di antara Az Zuhri dan Ibnul Azhar.\""},"3771":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ يَعْنِي ابْنَ خَالِدٍ حَدَّثَنَا الشُّعَيْثِيُّ عَنْ زُفَرَ بْنِ وَثِيمَةَ عَنْ حَكِيمِ بْنِ حِزَامٍ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسْتَقَادَ فِي الْمَسْجِدِ وَأَنْ تُنْشَدَ فِيهِ الْأَشْعَارُ وَأَنْ تُقَامَ فِيهِ الْحُدُودُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Shadaqah] -maksudnya Shadaqah bin Khalid- berkata, telah menceritakan kepada kami [Asy Syu'aitsi] dari [Zufar bin Watsimah] dari [Hakim bin Hizam] bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang pelaksanaan hukuman qishas dalam masjid, melantunkan syair (buruk) dan pelaksanaan hudud secara umum.\""},"3772":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا يُجْلَدُ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ بُكَيْرَ بْنَ الْأَشَجِّ حَدَّثَهُ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا بُرْدَةَ الْأَنْصَارِيَّ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَ مَعْنَاهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah Ibnul Asyaj] dari [Sulaiman bin Yasar] dari ['Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang tidak boleh didera lebih dari sepuluh kali deraan, kecuali pada pelaksanaan hudud Allah Azza Wa Jalla.\" Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Amru] bahwa [Bukair Ibnul Asyaj] menceritakan kepadanya dari [Sulaiman bin Yasar] ia berkata; telah menceritakan kepadaku ['Abdurrahman bin Jabir] bahwa [Bapaknya] menceritakan kepadanya, bahwa ia mendengar [Abu Burdah Al Anshari] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda…lalu ia menyebutkan sebagaimana maknanya.\""},"3773":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُمَرَ يَعْنِي ابْنَ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا ضَرَبَ أَحَدُكُمْ فَلْيَتَّقِ الْوَجْهَ","id":"Telah menceritakan kepada kami [Abu Kamil] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Umar] -maksudnya Umar bin Abu Salamah- dari [Bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian memukul maka jauhilah muka.\""},"3774":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ مُوسَى عَنْ عَلِيِّ بْنِ صَالِحٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ قُرَيْظَةُ وَالنَّضِيرُ وَكَانَ النَّضِيرُ أَشْرَفَ مِنْ قُرَيْظَةَ فَكَانَ إِذَا قَتَلَ رَجُلٌ مِنْ قُرَيْظَةَ رَجُلًا مِنْ النَّضِيرِ قُتِلَ بِهِ وَإِذَا قَتَلَ رَجُلٌ مِنْ النَّضِيرِ رَجُلًا مِنْ قُرَيْظَةَ فُودِيَ بِمِائَةِ وَسْقٍ مِنْ تَمْرٍ فَلَمَّا بُعِثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتَلَ رَجُلٌ مِنْ النَّضِيرِ رَجُلًا مِنْ قُرَيْظَةَ فَقَالُوا ادْفَعُوهُ إِلَيْنَا نَقْتُلُهُ فَقَالُوا بَيْنَنَا وَبَيْنَكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْهُ فَنَزَلَتْ{ وَإِنْ حَكَمْتَ فَاحْكُمْ بَيْنَهُمْ بِالْقِسْطِ }وَالْقِسْطُ النَّفْسُ بِالنَّفْسِ ثُمَّ نَزَلَتْ{ أَفَحُكْمَ الْجَاهِلِيَّةِ يَبْغُونَ }قَالَ أَبُو دَاوُد قُرَيْظَةُ وَالنَّضِيرُ جَمِيعًا مِنْ وَلَدِ هَارُونَ النَّبِيِّ عَلَيْهِ السَّلَام","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Musa- dari [Ali bin Shalih] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Antara bani Quraidhah dan bani Nadhir yang lebih mulia adalah bani Nadhir. Jika seorang laki-laki bani Quraidhah membunuh laki-laki dari bani Nadhir maka harus diqishah, sementara jika seorang laki-laki dari bani Nadhir membunuh laki-laki dari bani Quraidhah, cukup dengan memberikan tebusan seratus gantang kurma. Ketika Nabi shallallahu 'alaihi wasallam diutus, lalu ada seorang laki-laki dari bani Nadhir membunuh laki-laki dari bani Quraidhah, maka orang-orang dari bani Quraidhah berkata, \"Berikan pembunuh itu kepada kami sehingga kami dapat membunuhnya.\" Orang-orang bani Nadhir kemudian berkata, \"Antara kami dengan kalian ada Nabi Muhammad shallallahu 'alaihi wasallam!\" mereka lalu mendatangi beliau. Kemudian Allah menurunkan ayat: '(dan jika kamu memutuskan perkara mereka, maka putuskanlah perkara itu di antara mereka dengan adil..) ' -Al Maidah: 42-. Al Qisth (adil) itu adalah jiwa dibalas dengan jiwa.\" Kemudian setelah itu turun ayat: '(Apakah hukum Jahilliyah yang mereka kehendaki) ' -Al Maidah: 50-. Abu Dawud berkata, \"Bani Quraidhah dan bani Nadhir keduanya dari keturunan Nabi Harun Alaihis Salam.\""},"3775":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي ابْنُكَ هَذَا قَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبْتِ شَبَهِي فِي أَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","id":"Telah menceritakan kepada kami [Ahmad bin yunus] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Iyad- berkata, telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah] ia berkata; Aku dan bapakku berangkat menemui Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepada bapakku: \"Apakah ini anakmu?\" bapakku menjawab, \"Benar, demi Tuhannya Ka'bah.\" Beliau bertanya lagi: \"Apakah itu benar?\" bapakku menjawab, \"Aku bersaksi atasnya.\" Abu Rismtsah berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu tersenyum karena aku mirip dengan bapakku dan karena sumpah yang dilakukannya atas diriku. Kemudian beliau bersabda: \"Ketahuilah, dia tidak akan memikul dosamu dan kamu tidak akan memikul dosanya.\" Lalu beliau membaca ayat: '(dan orang yang berdosa tidak akan memikul dosa orang lain) ' -Qs. Al Isra: 15-. "},"3776":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الْحَارِثِ بْنِ فُضَيْلٍ عَنْ سُفْيَانَ بْنِ أَبِي الْعَوْجَاءِ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ و��سَلَّمَ قَالَ مَنْ أُصِيبَ بِقَتْلٍ أَوْ خَبْلٍ فَإِنَّهُ يَخْتَارُ إِحْدَى ثَلَاثٍ إِمَّا أَنْ يَقْتَصَّ وَإِمَّا أَنْ يَعْفُوَ وَإِمَّا أَنْ يَأْخُذَ الدِّيَةَ فَإِنْ أَرَادَ الرَّابِعَةَ فَخُذُوا عَلَى يَدَيْهِ وَمَنْ اعْتَدَى بَعْدَ ذَلِكَ فَلَهُ عَذَابٌ أَلِيمٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Al Harits bin Fudhail] dari [Sufyan bin Abu Al 'Auja] dari [Abu Syuraih Al AKhuza'i] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapat musibah berupa pembunuhan atau cacat anggota badan maka ia mempunyai tiga pilihan; minta qishas, memberi maaf, atau meminta tebusan denda. Jika ia menginginkan yang keempat maka halangilah, dan barangsiapa melampaui batas setelah itu maka baginya siksa yang pedih.\""},"3777":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُفِعَ إِلَيْهِ شَيْءٌ فِيهِ قِصَاصٌ إِلَّا أَمَرَ فِيهِ بِالْعَفْوِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Abdullah bin bakr bin Abdullah Al Muzani] dari [Atha bin Abu Maimunah] dari [Anas bin Malik] ia berkata, \"Aku tidak pernah melihat Nabi shallallahu 'alaihi wasallam mendapat pengaduan yang padanya ada Qishas, kecuali beliau menganjurkan untuk memaafkan.\""},"3778":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقُتِلَ رَجُلٌ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَهُ إِلَى وَلِيِّ الْمَقْتُولِ فَقَالَ الْقَاتِلُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا أَرَدْتُ قَتْلَهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْوَلِيِّ أَمَا إِنَّهُ إِنْ كَانَ صَادِقًا ثُمَّ قَتَلْتَهُ دَخَلْتَ النَّارَ قَالَ فَخَلَّى سَبِيلَهُ قَالَ وَكَانَ مَكْتُوفًا بِنِسْعَةٍ فَخَرَجَ يَجُرُّ نِسْعَتَهُ فَسُمِّيَ ذَا النِّسْعَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Ada seorang laki-laki dibunuh pada masa Rasulullah shallallahu 'alaihi wasallam. Maka kasus itu diajukan kepada Nabi shallallahu 'alaihi wasallam. Nabi lantas melimpahkan kasus ini kepada wali korban. Si pembunuh lantas menyampaikan uneg-unegnya kepada Nabi ' Wahai Rasulullah, sungguh aku semula tidak berniat membunuhnya! Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada wali korban: \"Jika ucapan pembunuh itu benar, kemudian kamu membunuhnya, maka kamu masuk neraka.\" Abu Hurairah berkata, \"Lantas wali korban itu pun membebaskan sang pembunuh.\" Abu Hurairah melanjutkan lagi, \"Sang pembunuh saat itu sudah diikat tali, ia pun pulang dengan keadaan terikat tali hingga dijuluki 'Orang terikat tali'. "},"3779":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ الْجُشَمِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَوْفٍ حَدَّثَنَا حَمْزَةُ أَبُو عُمَرَ الْعَائِذِيُّ حَدَّثَنِي عَلْقَمَةُ بْنُ وَائِلٍ حَدَّثَنِي وَائِلُ بْنُ حُجْرٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جِيءَ بِرَجُلٍ قَاتِلٍ فِي عُنُقِهِ النِّسْعَةُ قَالَ فَدَعَا وَلِيَّ الْمَقْتُولِ فَقَالَ أَتَعْفُو قَالَ لَا قَالَ أَفَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ أَفَتَقْتُلُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَلَمَّا وَلَّى قَالَ أَتَعْفُو قَالَ لَا قَالَ أَفَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ أَفَتَقْتُلُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَلَمَّا كَانَ فِي الرَّابِعَةِ قَالَ أَمَا إِنَّكَ إِنْ عَفَوْتَ عَنْهُ يَبُوءُ بِإِثْمِهِ وَإِثْمِ صَاحِبِهِ قَالَ فَعَفَا عَنْهُ قَالَ فَأَنَا رَأَيْتُهُ يَجُرُّ النِّسْعَةَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي جَامِعُ بْنُ مَطَرٍ حَدَّثَنِي عَلْقَمَةُ بْنُ وَائِلٍ بِإِسْنَادِهِ وَمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar bin Maisarah Al Jusyami] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Auf] berkata; telah menceritakan kepada kami [Hamzah Abu Umar Al 'Aidzi] berkata, telah menceritakan kepadaku [Alqamah bin Wail] berkata, telah menceritakan kepadaku [Wail bin Hujr] ia berkata, \"Aku pernah di sisi Nabi shallallahu 'alaihi wasallam, lalu didatangkan ke hadapan beliau seorang pembunuh yang pada lehernya telah diikat dengan tali.\" Wail berkata, \"Beliau lalu mengundang wali korban dan bertanya: \"Apa kamu tidak memberi maaf?\" Ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apa kamu tidak ingin mengambil tebusan?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apa kamu ingin membunuhnya?\" ia menjawab, \"Benar.\" Beliau bersabda: \"Kalau begitu bawalah ia pergi.\" Ketika wali korban itu beranjak pergi, beliau kembali bertanya: \"Apa kamu tidak memberi maaf?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apa kamu tidak ingin mengambil tebusan?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apa kamu ingin membunuhnya?\" ia menjawab, \"Benar.\" Beliau bersabda: \"Kalau begitu bawalah ia pergi.\" Maka pada kali keempatnya beliau bersabda: \"Jika engkau memberinya maaf, maka ia akan menanggung dosanya sendiri dan dosa saudaramu.\" Wail berkata, \"Wali korban itu akhirnya memaafkannya.\" Wail berkata, \"Aku melihat pembunuh melepas tali pengikatnya.\" Telah menceritakan kepada kami [Ubaidullah bin Umar bin Umar bin Maisarah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; telah menceritakan kepadaku [Jami' bin Mathar] berkata, telah menceritakan kepadaku [Alqamah bin Wail] dengan sanad dan maknanya.\""},"3780":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ الْحَجَّاجِ حَدَّثَنَا يَزِيدُ بْنُ عَطَاءٍ الْوَاسِطِيُّ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَبَشِيٍّ فَقَالَ إِنَّ هَذَا قَتَلَ ابْنَ أَخِي قَالَ كَيْفَ قَتَلْتَهُ قَالَ ضَرَبْتُ رَأْسَهُ بِالْفَأْسِ وَلَمْ أُرِدْ قَتْلَهُ قَالَ هَلْ لَكَ مَالٌ تُؤَدِّي دِيَتَهُ قَالَ لَا قَالَ أَفَرَأَيْتَ إِنْ أَرْسَلْتُكَ تَسْأَلُ النَّاسَ تَجْمَعُ دِيَتَهُ قَالَ لَا قَالَ فَمَوَالِيكَ يُعْطُونَكَ دِيَتَهُ قَالَ لَا قَالَ لِلرَّجُلِ خُذْهُ فَخَرَجَ بِهِ لِيَقْتُلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ إِنْ قَتَلَهُ كَانَ مِثْلَهُ فَبَلَغَ بِهِ الرَّجُلُ حَيْثُ يَسْمَعُ قَوْلَهُ فَقَالَ هُوَ ذَا فَمُرْ فِيهِ مَا شِئْتَ فَقَالَ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ وَقَالَ مَرَّةً دَعْهُ يَبُوءُ بِإِثْمِ صَاحِبِهِ وَإِثْمِهِ فَيَكُونُ مِنْ أَصْحَابِ النَّارِ قَالَ فَأَرْسَلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Auf Ath Tha`i] berkata, telah menceritakan kepada kami [Abdul Qudus Ibnul Hajjaj] berkata, telah menceritakan kepada kami [Yazid bin Atha Al Wasithi] dari [Simak] dari [Alqamah bin Wail] dari [Bapaknya] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa seorang habsyi, ia berkata, \"Sesungguhnya orang habsyi ini telah membunuh anak saudaraku!\" Beliau bertanya kepada habsyi tersebut: \"Bagaimana kamu membunuhnya?\" Ia menjawab, \"Aku memukul kepalanya dengan kapak, tetapi aku tidak bermaksud membunuhnya.\" Beliau bertanya lagi: \"Apa kamu mempunyai harta untuk membayar tebusan?\" Ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Bagaimana menurutmu jika aku bebaskan kamu, lalu kamu mencari bantuan dana kepada orang-orang?\" Ia menjawab, \"Tidak perlu.\" Beliau bertanya lagi: \"Apa barangkali wali-walimu yang akan memberikan uang tebusannya?\" Ia menjawab, \"Tidak.\" Beliau lalu bersabda kepada laki-laki (wali korban): \"Bawalah ia.\" Maka laki-laki membawa pergi orang habsyi tersebut untuk dibunuh. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sebenarnya jika laki-laki itu membunuh orang habsyi tersebut, maka kedudukannya akan sama dengan orang habsyi itu.\" Ucapan Rasulullah itu akhirnya sampai ke telinganya laki-laki tersebut, ia lalu berkata, \"Ini aku serahkan kembali. Maka berilah perintah sesukamu.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Bebaskanlah orang habsyi itu.\" Dalam riwayat lain beliau mengatakan, \"Biarkanlah, maka ia akan menanggung dosa temannya (korban) dan dosanya sendiri. Lalu ia akan masuk ke dalam neraka.\" Wali korban itu lantas membebaskannya. "},"3781":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى ابْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ قَالَكُنَّا مَعَ عُثْمَانَ وَهُوَ مَحْصُورٌ فِي الدَّارِ وَكَانَ فِي الدَّارِ مَدْخَلٌ مَنْ دَخَلَهُ سَمِعَ كَلَامَ مَنْ عَلَى الْبَلَاطِ فَدَخَلَهُ عُثْمَانُ فَخَرَجَ إِلَيْنَا وَهُوَ مُتَغَيِّرٌ لَوْنُهُ فَقَالَ إِنَّهُمْ لَيَتَوَاعَدُونَنِي بِالْقَتْلِ آنِفًا قَالَ قُلْنَا يَكْفِيكَهُمُ اللَّهُ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ وَلِمَ يَقْتُلُونَنِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ كُفْرٌ بَعْدَ إِسْلَامٍ أَوْ زِنًا بَعْدَ إِحْصَانٍ أَوْ قَتْلُ نَفْسٍ بِغَيْرِ نَفْسٍ فَوَاللَّهِ مَا زَنَيْتُ فِي جَاهِلِيَّةٍ وَلَا فِي إِسْلَامٍ قَطُّ وَلَا أَحْبَبْتُ أَنَّ لِي بِدِينِي بَدَلًا مُنْذُ هَدَانِي اللَّهُ وَلَا قَتَلْتُ نَفْسًا فَبِمَ يَقْتُلُونَنِيقَالَ أَبُو دَاوُد عُثْمَانُ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا تَرَكَا الْخَمْرَ فِي الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahl] ia berkata, \"Aku pernah bersama [Utsman] saat ia dikepung dalam rumahnya. Dalam rumahnya ada sebuah lorong, jika seseorang masuk ke dalamnya maka ia akan dapat mendengar percakapan orang yang berada di atasnya. Utsman masuk ke dalam lorong itu, lalu ia keluar dengan wajah telah berubah pucat. Ia berkata, \"Mereka berkeinginan untuk membunuhku.\" Ia (perawi) berkata, \"Lalu kami berkata, \"Cukuplah Allah sebagai pelindungmu wahai Amirul Mukminin.\" Utsman bertanya (bingung), \"Kenapa mereka ingin membunuhku?, padahal aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali karena tiga hal; kafir setelah beriman, zina setelah nikah, dan membunuh jiwa orang lain.\" Demi Allah, aku tidak pernah melakukan perzinaan baik di masa Jahilliyah atau setelah Islam, aku juga tidak pernah berharap untuk mengganti agamaku setelah Allah memberi petunjuk kepadaku, dan aku juga tidak pernah membunuh jiwa seorang pun (tanpa hak). Lalu dengan alasan apa mereka akan membunuhku?\" Abu Dawud berkata, \"Utsman dan Abu Bakar radliallahu 'anhuma tidak pernah minum khamer pada masa Jahilliyah.\""},"3782":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ فَحَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ زِيَادَ بْنَ ضُمَيْرَةَ الضُّمَرِيَّ ح و أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ وَأَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ أَنَّهُ سَمِعَ زِيَادَ بْنَ سَعْدِ بْنِ ضُمَيْرَةَ السُّلَمِيَّ وَهَذَا حَدِيثُ وَهْبٍ وَهُوَ أَتَمُ يُحَدِّثُ عُرْوَةَ بْنَ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ مُوسَى وَجَدِّهِوَكَانَا شَهِدَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُنَيْنًا ثُمَّ رَجَعْنَا إِلَى حَدِيثِ وَهْبٍ أَنْ مُحَلِّمَ بْنَ جَثَّامَةَ اللَّيْثِيَّ قَتَلَ رَجُلًا مِنْ أَشْجَعَ فِي الْإِسْلَامِ وَذَلِكَ أَوَّلُ غِيَرٍ قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمَ عُيَيْنَةُ فِي قَتْلِ الْأَشْجَعِيِّ لِأَنَّهُ مِنْ غَطَفَانَ وَتَكَلَّمَ الْأَقْرَعُ بْنُ حَابِسٍ دُونَ مُحَلِّمٍ لِأَنَّهُ مِنْ خِنْدِفَ فَارْتَفَعَتْ الْأَصْوَاتُ وَكَثُرَتْ الْخُصُومَةُ وَاللَّغَطُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُيَيْنَةُ أَلَا تَقْبَلُ الْغِيَرَ فَقَالَ عُيَيْنَةُ لَا وَاللَّهِ حَتَّى أُدْخِلَ عَلَى نِسَائِهِ مِنْ الْحَرْبِ وَالْحُزْنِ مَا أَدْخَلَ عَلَى نِسَائِي قَالَ ثُمَّ ارْتَفَعَتْ الْأَصْوَاتُ وَكَثُرَتْ الْخُصُومَةُ وَاللَّغَطُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُيَيْنَةُ أَلَا تَقْبَلُ الْغِيَرَ فَقَالَ عُيَيْنَةُ مِثْلَ ذَلِكَ أَيْضًا إِلَى أَنْ قَامَ رَجُلٌ مِنْ بَنِي لَيْثٍ يُقَالُ لَهُ مُكَيْتِلٌ عَلَيْهِ شِكَّةٌ وَفِي يَدِهِ دَرِقَةٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمْ أَجِدْ لِمَا فَعَلَ هَذَا فِي غُرَّةِ الْإِسْلَامِ مَثَلًا إِلَّا غَنَمًا وَرَدَتْ فَرُمِيَ أَوَّلُهَا فَنَفَرَ آخِرُهَا اسْنُنْ الْيَوْمَ وَغَيِّرْ غَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُونَ فِي فَوْرِنَا هَذَا وَخَمْسُونَ إِذَا رَجَعْنَا إِلَى الْمَدِينَةِ وَذَلِكَ فِي بَعْضِ أَسْفَارِهِ وَمُحَلِّمٌ رَجُلٌ طَوِيلٌ آدَمُ وَهُوَ فِي طَرَفِ النَّاسِ فَلَمْ يَزَالُوا حَتَّى تَخَلَّصَ فَجَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَيْنَاهُ تَدْمَعَانِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ فَعَلْتُ الَّذِي بَلَغَكَ وَإِنِّي أَتُوبُ إِلَى اللَّهِ تَبَارَكَ وَتَعَالَى فَاسْتَغْفِرْ اللَّهَ عَزَّ وَجَلَّ لِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَتَلْتَهُ بِسِلَاحِكَ فِي غُرَّةِ الْإِسْلَامِ اللَّهُمَّ لَا تَغْفِرْ لِمُحَلِّمٍ بِصَوْتٍ عَالٍ زَادَ أَبُو سَلَمَةَ فَقَامَ وَإِنَّهُ لَيَتَلَقَّى دُمُوعَهُ بِطَرَفِ رِدَائِهِقَالَ ابْنُ إِسْحَقَ فَزَعَمَ قَوْمُهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَغْفَرَ لَهُ بَعْدَ ذَلِكَ قَالَ أَبُو دَاوُد قَالَ النَّضْرُ بْنُ شُمَيْلٍ الْغِيَرُ الدِّيَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] ia berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] berkata, telah menceritakan kepadaku [Muhammad bin Ja'far bin Az Zubair] ia berkata; Aku mendengar [Ziyad bin Dhamrah Adh Dhumari]. (dalam jalur lain disebutkan) Telah mengabarkan kepada kami [Wahb bin Bayan] dan [Ahmad bin Sa'id Al Hamdani] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku ['Abdurrahman bin Abu Az Zinad] dari ['Abdurrahman Ibnul Harits] dari [Muhammad bin Ja'far] Bahwasanya ia pernah mendengar [Ziyad bin Sa'd bin Dhumairah As Sulami] -ini adalah hadits Wahb, dan hadits ini lebih lengkap, ia menceritakan kepada Urwah bin Az Zubair- dari [Bapaknya] ia berkata, \" [Musa] dan [kakeknya] pernah mengikuti perang Hunain bersama Rasulullah shallallahu 'alaihi wasallam. ' kemudian kami kembali kepada hadits Wahb, bahwa Muhallim bin Jatstsamah Al Laitsi pernah membunuh seorang laki-laki dari Asyja' (nama tempat) padahal ia telah masuk Islam, dan itu adalah diyat pertama yang ditebus oleh Rasulullah shallallahu 'alaihi wasallam. Uyainah lalu memperbincangkan tentang pembunuhan Al Asyja'I, sebab ia berasal dari Ghathafan. Sementara Al Aqra' bin Habis berbicara membela Muhallim, sebab ia berasal dari Khindiq. Suara mereka meninggi hingga banyak terjadi perselisihan dan kegaduhan. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Uyainah, tidakkah kamu mau menerima diyat (tebusan)?\" Ia menjawab, \"Demi Allah, tidak! Sehingga kami dapat mendatangkan kerugian dan kesedihan untuk wanita-wanitanya sebagaimana ia telah mendatangkan kerugian dan kesedihan untuk wanita-wanitaku.\" Sa'd berkata, \"Kemudian suara mereka kembali meninggi hingga banyak terjadi perselisihan dan kegaduhan.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Uyainah, tidakkah kamu mau menerima diyat (tebusan)?\" Uyainah menjawab seperti jawabannya semula, sehingga berdirilah seorang laki-laki dari bani Laits yang bernama Mukaitil, ia membawa senjata dan perisai. Lalu ia berkata, \"Wahai Rasulullah, dalam Islam aku belum pernah mendapatkan tebusan untuk pelanggaran yang dilakukan oleh orang ini (Muhallim si pembunuh) kecuali seperti serombongan kambing yang minum (di sungai) karena haus. Lalu barisan pertama dilempar hingga barisan yang terakhir lari menjauh (maksudnya; adanya qishah itu agar yang lain takut dan mengambil pelajaran sebagaimana kambing yang dilempar agar yang lain takut dan pergi). Tegakkanlah sunnah sekarang dan rubahlah esok hari.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Lima puluh (unta) dibayar tunai dan lima puluh lagi ketika tiba di Madinah.\" Itu terjadi dalam salah satu safar beliau. Sementara Muhallim adalah seorang laki-laki tinggi yang berkulit coklat, ia duduk di antara orang banyak. Dan kawan-kawannya masih saja menolongnya hingga ia terbebas dari pembunuhan (qishas). Muhallim lalu duduk di sisi Rasulullah shallallahu 'alaihi wasallam dengan meneteskan air mata. Ia lalu berkata, \"Wahai Rasulullah, aku telah melakukan sesuatu sebagaimana yang engkau telah ketahui (membunuh), aku sekarang bertaubat kepada Allah Tabaaraka Wa Ta'ala, maka mintakan aku ampunan kepada Allah Azza Wa Jalla.\" Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Apakah kamu membunuhnya dengan senjatamu padahal ia masih diawalmula keislamannya? Ya Allah, jangan engkau ampuni Muhallim.\" Beliau ucapkan kata-kata itu dengan suara yang keras.\" Abu Salamah menambahkan, \"Muhallim lalu bangkit dan mengusap air matanya dengan ujung selendang.\" Ibnu Ishaq berkata, \"Kaumnya merasa yakin bahwa Rasulullah shallallahu 'alaihi wasallam akan memintakan ampun untuk Muhallim setelah itu.\" Abu Dawud berkata, \"An Nadhr bin Syumail mengatakan bahwa Al Ghiyar adalah diyat (tebusan).\""},"3783":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ قَالَ سَمِعْتُ أَبَا شُرَيْحٍ الْكَعْبِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنَّكُمْ يَا مَعْشَرَ خُزَاعَةَ قَتَلْتُمْ هَذَا الْقَتِيلَ مِنْ هُذَيْلٍ وَإِنِّي عَاقِلُهُ فَمَنْ قُتِلَ لَهُ بَعْدَ مَقَالَتِي هَذِهِ قَتِيلٌ فَأَهْلُهُ بَيْنَ خِيَرَتَيْنِ أَنْ يَأْخُذُوا الْعَقْلَ أَوْ يَقْتُلُوا","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] ia berkata; telah menceritakan kepadaku [Sa'id Ibnu Abu Sa'id] ia berkata; Aku mendengar [Abu Syuraih Al ka'bi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai penduduk Khuza'ah! Ketahuilah oleh kalian semua, kalian telah membunuh orang Hudzail ini, sesungguhnya aku adalah penggantinya (yang akan membayarkan diyatnya), karena itu siapa yang terbunuh setelah perkataanku ini, maka bagi ahli warisnya aku beri dua pilihan; minta tebusan atau balas bunuh.\""},"3784":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ أَخْبَرَنِي أَبِي حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى ح و حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي أَبُو دَاوُدَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَلَمَّا فُتِحَتْ مَكَّةُ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُودَى أَوْ يُقَادَ فَقَامَ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ يُقَالُ لَهُ أَبُو شَاةٍ فَقَالَ يَا رَسُولَ اللَّهِ اكْتُبْ لِي قَالَ الْعَبَّاسُ اكْتُبُوا لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبُوا لِأَبِي شَاةٍوَهَذَا لَفْظُ حَدِيثِ أَحْمَدَ قَالَ أَبُو دَاوُد اكْتُبُوا لِي يَعْنِي خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abbas Ibnul Walid bin Mazyad] berkata, telah mengabarkan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Yahya]. (dalam jalur lain disebutkan) telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepadaku [Abu Dawud] berkata, telah menceritakan kepada kami [Harb bin Syaddad] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata, telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Abu Hurairah] ia berkata, \"Saat pembukaan kota Makkah Rasulullah shallallahu 'alaihi wasallam berdiri dan berkhutbah, beliau bersabda: \"Barang siapa di antara kalian ada yang (keluarganya) terbunuh, maka ia mempunyai dua pilihan terbaik; minta tebusan atau balas bunuh.\" Lalu seorang laki-laki dari penduduk Yaman yang bernama Abu Syah berdiri dan berkata, \"Wahai Rasulullah, tuliskanlah untukku.\" Al Abbas berkata, \"Kalian menulislah untukku.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Buatlah tulisan untuk Abu Syah.\" Dan ini adalah lafadz hadits dari Ahmad. Abu Dawud berkata, \"kalian menulislah untukku' maksudnya adalah khutbah yang disampaikan oleh Nabi shallallahu 'alaihi wasallam.\""},"3785":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا دُفِعَ إِلَى أَوْلِيَاءِ الْمَقْتُولِ فَإِنْ شَاءُوا قَتَلُوهُ وَإِنْ شَاءُوا أَخَذُوا الدِّيَةَ","id":"Telah menceritakan kepada kami [Muslim] berkata, telah menceritakan kepada kami [Muhammad bin rasyid] berkata, telah menceritakan kepada kami [Sulaiman bin Musa] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin tidak boleh dibunuh karena orang kafir (sebagai qishas). Maka barangsiapa membunuh seorang mukmin dengan sengaja, perkaranya diserahkan kepada wali korban; jika mereka berkehendak maka mereka boleh balas membunuh, dan jika mereka berkehendak maka mereka boleh minta tebusan.\""},"3786":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا مَطَرٌ الْوَرَّاقُ وَأَحْسَبُهُ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُعْفِيَ مَنْ قَتَلَ بَعْدَ أَخْذِهِ الدِّيَةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Mathar Al Warraq] dan aku mengira itu dari [Al Hasan] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak akan memberi maaf kepada orang yang membunuh setelah ia mengambil tebusannya.\""},"3787":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ امْرَأَةً يَهُودِيَّةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ مَسْمُومَةٍ فَأَكَلَ مِنْهَا فَجِيءَ بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهَا عَنْ ذَلِكَ فَقَالَتْ أَرَدْتُ لِأَقْتُلَكَ فَقَالَ مَا كَانَ اللَّهُ لِيُسَلِّطَكِ عَلَى ذَلِكَ أَوْ قَالَ عَلَيَّ فَقَالُوا أَلَا نَقْتُلُهَا قَالَ لَا فَمَا زِلْتُ أَعْرِفُهَا فِي لَهَوَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Habib bin Arabi] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik] berkata, \"Seorang wanita Yahudi datang kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa daging kambing yang telah diberi racun, lalu beliau memakannya. Setelah itu, wanita Yahudi tersebut dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam. beliau lantas menanyakan tentang hal tersebut, wanita itu menjawab, \"Aku ingin membunuhmu!\" beliau bersabda: \"Allah tidak akan memberikan kemudahan bagimu untuk melakukan itu, atau beliau mengatakan, \"untuk melakukan (hal itu) terhadapku.\" Para sahabat berkata, \"Bagaimana jika kami membunuhnya saja?\" beliau bersabda: \"Jangan.\" Anas berkata, \"Dan aku masih melihat sisa-sisa racun itu di tenggorokan Rasulullah shallallahu 'alaihi wasallam.\""},"3788":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ ��َدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّادٌ عَنْ سُفْيَانَ ابْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وأَبِي سَلَمَةَ قَالَ هَارُونُ عَنْ أَبِي هُرَيْرَةَأَنَّ امْرَأَةً مِنْ الْيَهُودِ أَهْدَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً مَسْمُومَةً قَالَ فَمَا عَرَضَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد هَذِهِ أُخْتُ مَرْحَبٍ الْيَهُودِيَّةُ الَّتِي سَمَّتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Dawud bin Rasyid] berkata, telah menceritakan kepada kami [Abbad Ibnul Awwam]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Sa'id bin Sulaiman] berkata, telah menceritakan kepada kami [Abbad] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Sa'id] dan [Abu Salamah]. [Harun] berkata; dari [Abu Hurairah] ia berkata, \"Seorang wanita Yahudi memberi hadiah Nabi shallallahu 'alaihi wasallam daging kambing yang telah diberi racun.\" Abu Hurairah melanjutkan, \"Tetapi Nabi shallallahu 'alaihi wasallam tidak menyentuh wanita itu sama sekali (yakni dengan qishash).\" Abu Dawud berkata, \"Wanita ini adalah saudara perempuan dari perempuan Yahudi yang meracuni Nabi shallallahu 'alaihi wasallam.\""},"3789":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ كَانَ جَابِرُ بْنُ عَبْدِ اللَّهِ يُحَدِّثُأَنَّ يَهُودِيَّةً مِنْ أَهْلِ خَيْبَرَ سَمَّتْ شَاةً مَصْلِيَّةً ثُمَّ أَهْدَتْهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذِّرَاعَ فَأَكَلَ مِنْهَا وَأَكَلَ رَهْطٌ مِنْ أَصْحَابِهِ مَعَهُ ثُمَّ قَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفَعُوا أَيْدِيَكُمْ وَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَهُودِيَّةِ فَدَعَاهَا فَقَالَ لَهَا أَسَمَمْتِ هَذِهِ الشَّاةَ قَالَتْ الْيَهُودِيَّةُ مَنْ أَخْبَرَكَ قَالَ أَخْبَرَتْنِي هَذِهِ فِي يَدِي لِلذِّرَاعِ قَالَتْ نَعَمْ قَالَ فَمَا أَرَدْتِ إِلَى ذَلِكَ قَالَتْ قُلْتُ إِنْ كَانَ نَبِيًّا فَلَنْ يَضُرَّهُ وَإِنْ لَمْ يَكُنْ نَبِيًّا اسْتَرَحْنَا مِنْهُ فَعَفَا عَنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُعَاقِبْهَا وَتُوُفِّيَ بَعْضُ أَصْحَابِهِ الَّذِينَ أَكَلُوا مِنْ الشَّاةِ وَاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كَاهِلِهِ مِنْ أَجْلِ الَّذِي أَكَلَ مِنْ الشَّاةِ حَجَمَهُ أَبُو هِنْدٍ بِالْقَرْنِ وَالشَّفْرَةِ وَهُوَ مَوْلًى لِبَنِي بَيَاضَةَ مِنْ الْأَنْصَارِحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ حَدَّثَنَا خَالِدٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْدَتْ لَهُ يَهُودِيَّةٌ بِخَيْبَرَ شَاةً مَصْلِيَّةً نَحْوَ حَدِيثِ جَابِرٍ قَالَ فَمَاتَ بِشْرُ بْنُ الْبَرَاءِ بْنِ مَعْرُورٍ الْأَنْصَارِيُّ فَأَرْسَلَ إِلَى الْيَهُودِيَّةِ مَا حَمَلَكِ عَلَى الَّذِي صَنَعْتِ فَذَكَرَ نَحْوَ حَدِيثِ جَابِرٍ فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُتِلَتْ وَلَمْ يَذْكُرْ أَمْرَ الْحِجَامَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri] berkata, telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata, \" [Jabir bin Abdullah] pernah menceritakan bahwa seorang wanita Yahudi dari penduduk Khaibar menaburi racun pada daging kambing panggang. Kemudian ia menghadiahkan daging itu kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lantas mengambil lengan kambing tersebut dan memakannya bersama para sahabatnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka semua: \"Angkatlah tangan kalian semuanya (jangan dimakan lagi).\" Rasulullah shallallahu 'alaihi wasallam kemudian mengirim utusan untuk memanggil wanita Yahudi tersebut. Lalu beliau bertanya kepada wanita itu: \"Apakah kamu memberi racun pada daging ini?\" wanita Yahudi itu menjawab, \"Siapa yang memberimu kabar?\" beliau menjawab: \"Yang memberiku kabar adalah apa yang ada di tanganku ini.\" wanita Yahudi itu berkata, \"Benar.\" Beliau bertanya lagi: \"Apa yang kamu inginkan?\" wanita Yahudi itu menjawab, \"Dalam hati aku berkata, 'Jika dia memang seorang Nabi maka dia tidak akan mendapatkan bahaya, tetapi jika bukan seorang Nabi maka kami dapat beristirahat darinya'. Rasulullah shallallahu 'alaihi wasallam lalu memaafkan wanita Yahudi tersebut dan tidak menghukumnya. Para sahabat beliau yang ikut makan daging kambing itu meninggal, sementara Rasulullah shallallahu 'alaihi wasallam membekam pada bagian tengkuknya karena daging yang dimakannya. Lalu beliau dibekam oleh Abu Hind -seorang mantan budak bani Bayadhah dari kaum Anshar- dengan menggunakan tanduk dan pisau tajam.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] berkata, telah menceritakan kepada kami [Khalid] dari [Muhammad bin Amru] dari [Abu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah diberi hadiah kambing panggang oleh seorang wanita Yahudi Khaibar, seperti dalam hadits Jabir. Ia (perawi) berkata, \"Bisyr bin Al Bara bin Ma'rur Al Anshari meninggal dunia (karena makan daging kambing), maka Rasulullah mengutus seseorang untuk menjemput wanita Yahudi tersebut. Beliau bersabda: \"Apa yang mendorongmu untuk melakukan itu?\" kemudian disebutkan sebagaimana dalam hadits Jabir. Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan supaya wanita itu dihukum, maka wanita itu pun dibunuh. Namun ia tidak menyebutkan tentang cerita bekam.\""},"3790":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْبَلُ الْهَدِيَّةَ وَلَا يَأْكُلُ الصَّدَقَةَحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ فِي مَوْضِعٍ آخَرَ عَنْ خَالِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ وَلَمْ يَذْكُرْ أَبَا هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْبَلُ الْهَدِيَّةَ وَلَا يَأْكُلُ الصَّدَقَةَ زَادَ فَأَهْدَتْ لَهُ يَهُودِيَّةٌ بِخَيْبَرَ شَاةً مَصْلِيَّةً سَمَّتْهَا فَأَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا وَأَكَلَ الْقَوْمُ فَقَالَ ارْفَعُوا أَيْدِيَكُمْ فَإِنَّهَا أَخْبَرَتْنِي أَنَّهَا مَسْمُومَةٌ فَمَاتَ بِشْرُ بْنُ الْبَرَاءِ بْنِ مَعْرُورٍ الْأَنْصَارِيُّ فَأَرْسَلَ إِلَى الْيَهُودِيَّةِ مَا حَمَلَكِ عَلَى الَّذِي صَنَعْتِ قَالَتْ إِنْ كُنْتَ نَبِيًّا لَمْ يَضُرَّكَ الَّذِي صَنَعْتُ وَإِنْ كُنْتَ مَلِكًا أَرَحْتُ النَّاسَ مِنْكَ فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُتِلَتْ ثُمَّ قَالَ فِي وَجَعِهِ الَّذِي مَاتَ فِيهِ مَازِلْتُ أَجِدُ مِنْ الْأَكْلَةِ الَّتِي أَكَلْتُ بِخَيْبَرَ فَهَذَا أَوَانُ قَطَعَتْ أَبْهَرِي","id":"Telah menceritakan kepada kami [Wahab bin Baqiyyah] dari [Khalid] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menerima hadiah namun tidak makan zakat.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] -dalam riwayat lain- dari [Khalid] dari [Muhammad bin Amru] dari [Abu Salamah] -namun ia tidak menyebutkan Abu Hurairah, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menerima hadiah namun tidak makan zakat.\" Ia menambahkan, \"Maka ada seorang wanita Yahudi Khaibar yang memberi hadiah daging guling yang telah dilumuri racun kepada beliau. Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya lalu makan daging kambing tersebut. Namun kemudian, beliau bersabda: \"Angkatlah tangan kalian (berhenti makan), karena sesungguhnya daging kambing ini telah memberiku kabar bahwa ia telah dibubuhi racun.\" Bisyr Ibnul Al Bara bin Ma'rur Al Anshari akhirnya meninggal dunia. Rasulullah kemudian mengutus utusan kepada wanita Yahudi tersebut. Beliau bertanya: \"Apa yang mendorongmu untuk melakukan hal itu?\" Wanita itu menjawab, \"Jika engkau seorang Nabi, maka apa yang aku lakukan tidak akan membahayakanmu. Namun jika engkau hanya seorang raja, maka dengan begitu aku telah mengistirahatkan manusia darimu.\" Rasulullah shallallahu 'alaihi wasallam lantas memerintahkan agar wanita itu dibunuh, maka ia pun dibunuh. Kemudian beliau berkata pada saat sakit yang membawanya kepada kematian: \"Aku masih merasakan apa yang pernah aku makan di Khaibar, dan sekarang adalah waktu terputusnya punggungku (kematianku).\""},"3791":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ أُمَّ مُبَشِّرٍ قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ مَا يُتَّهَمُ بِكَ يَا رَسُولَ اللَّهِ فَإِنِّي لَا أَتَّهِمُ بِابْنِي شَيْئًا إِلَّا الشَّاةَ الْمَسْمُومَةَ الَّتِي أَكَلَ مَعَكَ بِخَيْبَرَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا لَا أَتَّهِمُ بِنَفْسِي إِلَّا ذَلِكَ فَهَذَا أَوَانُ قَطَعَتْ أَبْهَرِيقَالَ أَبُو دَاوُد وَرُبَّمَا حَدَّثَ عَبْدُ الرَّزَّاقِ بِهَذَا الْحَدِيثِ مُرْسَلًا عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُبَّمَا حَدَّثَ بِهِ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ وَذَكَرَ عَبْدُ الرَّزَّاقِ أَنَّ مَعْمَرًا كَانَ يُحَدِّثُهُمْ بِالْحَدِيثِ مَرَّةً مُرْسَلًا فَيَكْتُبُونَهُ وَيُحَدِّثُهُمْ مَرَّةً بِهِ فَيُسْنِدُهُ فَيَكْتُبُونَهُ وَكُلٌّ صَحِيحٌ عِنْدَنَا قَالَ عَبْدُ الرَّزَّاقِ فَلَمَّا قَدِمَ ابْنُ الْمُبَارَكِ عَلَى مَعْمَرٍ أَسْنَدَ لَهُ مَعْمَرٌ أَحَادِيثَ كَانَ يُوقِفُهَا حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أُمِّهِ أُمِّ مُبَشِّرٍ قَالَ أَبُو سَعِيدِ بْنُ الْأَعْرَابِيِّ كَذَا قَالَ عَنْ أُمِّهِ وَالصَّوَابُ عَنْ أَبِيهِ عَنْ أُمِّ مُبَشِّرٍ دَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَى حَدِيثِ مَخْلَدِ بْنِ خَالِدٍ نَحْوَ حَدِيثِ جَابِرٍ قَالَ فَمَاتَ بِشْرُ بْنُ الْبَرَاءِ بْنِ مَعْرُورٍ فَأَرْسَلَ إِلَى الْيَهُودِيَّةِ فَقَالَ مَا حَمَلَكِ عَلَى الَّذِي صَنَعْتِ فَذَكَرَ نَحْوَ حَدِيثِ جَابِرٍ فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُتِلَتْ وَلَمْ يَذْكُرْ الْحِجَامَةَ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Ka'b bin Malik] dari [Bapaknya] berkata, \"Ummu Mubasysyir berkata kepada Nabi shallallahu 'alaihi wasallam pada saat sakit yang menghantarkan beliau kepada kematian, \"Apa yang engkau keluhkan ya Rasulullah? Aku tidak mengeluhkan apapun atas anakku kecuali daging kambing beracun yang ia makan bersamamu waktu di Khaibar.\" Nabi shallallahu 'alaihi wasallam lalu menjawab: \"Aku juga tidak mengeluhkan apapun selain daging kambing beracun itu, dan sekarang adalah waktu terputusnya punggungku (kematian).\" Abu Dawud berkata, \"Barangkali Abdurrazaq menceritakan hadits ini secara mursal dari Ma'mar, dari Az Zuhri, dari Nabi shallallahu 'alaihi wasallam. Dan barangkali ia juga menceritakan hadits dari Az Zuhri, dari 'Abdurrahman bin Ka'b bin Malik.\" Abdurrazaq menyebutkan bahwa Ma'mar menceritakan hadits ini kepada mereka sekali waktu secara mursal. Namun, sekali waktu mereka yang menulisnya sedangkan dia menceritakannya kepada mereka. Dan semua itu menurut kami shahih\" Abdurrazaq berkata, \"Ketika Ibnul Mubarak datang kepada Ma'mar, maka Ma'mar menyandarkan kepada Ibnu Mubarak beberapa hadits yang ia mauqufkan.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Az Zuhri] dari ['Abdurrahman bin Abdullah bin ka'b bin malik] dari ibunya Ummu Mubasysyir. Abu Sa'id Ibnul A'rabi berkata; demikian ia berkata dari ibunya. Namun yang benar adalah; dari [bapaknya], dari [Ummu Mubasysyir], ia berkata, \"Aku masuk menemui Nabi shallallahu 'alaihi wasallam... lalu ia menyebutkan sesuai makna hadits Makhlad bin Khalid, seperti hadits Jabir. Ia (perawi) berkata, \"Bisyr Ibnul Bara bin Ma'rur meninggal, maka beliau mengutus seseorang kepada wanita Yahudi tersebut. Beliau bertanya: \"Apa yang mendorongmu untuk melakukan hal itu?\" -lalu ia menyebutkan seperti hadits Jabir- Rasulullah shallallahu 'alaihi wasallam lalu memerintahkan untuk menghukum wanita tersebut, maka wanita itu pun dibunuh.\" Dan ia tidak menyebutkan tentang cerita bekam.\""},"3792":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَ عَبْدَهُ جَدَعْنَاهُحَدَّثَنَا مُحَمَّدُ ابْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ بِإِسْنَادِهِ مِثْلَهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَصَى عَبْدَهُ خَصَيْنَاهُ ثُمَّ ذَكَرَ مِثْلَ حَدِيثِ شُعْبَةَ وَحَمَّادٍ قَالَ أَبُو دَاوُد وَرَوَاهُ أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ هِشَامٍ مِثْلَ حَدِيثِ مُعَاذٍ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ بِإِسْنَادِ شُعْبَةَ مِثْلَهُ زَادَ ثُمَّ إِنَّ الْحَسَنَ نَسِيَ هَذَا الْحَدِيثَ فَكَانَ يَقُولُ لَا يُقْتَلُ حُرٌّ بِعَبْدٍ","id":"Telah menceritakan kepada kami [Ali Ibnul Ja'd] berkata, telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh budaknya maka kami akan membunuhnya, dan barangsiapa memotong hidung budaknya maka kami akan memotong hidungnya.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] dengan sanadnya yang sama. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengebiri budaknya maka kami akan mengebirinya.\" Kemudian ia menyebutkan sebagaimana hadits Syu'bah dan Hamamd.\" Abu Dawud berkata, \" [Abu Dawud Ath Thayalisi] meriwayatkannya dari [Hisyam] seperti hadits [Mu'adz]. Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Sa'id bin Amir] dari [Ibnu Abu Arubah] dari [Qatadah] dengan sanad [Syu'bah] seperti hadits itu. Hanya saja ia menambahkan, bahwa Al Hasan melupakan hadits ini. Ia menyebutkan, \"Orang merdeka tidak boleh dibunuh karena seorang budak (yakni qishas).\""},"3793":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ قَالَلَا يُقَادُ الْحُرُّ بِالْعَبْدِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] ia berkata, \"Orang merdeka tidak boleh diqishas karena (membunuh) seorang budak.\""},"3794":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ بْنِ تَسْنِيمٍ الْعَتَكِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا سَوَّارٌ أَبُو حَمْزَةَ حَدَّثَنَا عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ رَجُلٌ مُسْتَصْرِخٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جَارِيَةٌ لَهُ يَا رَسُولَ اللَّهِ فَقَالَ وَيْحَكَ مَا لَكَ قَالَ شَرًّا أَبْصَرَ لِسَيِّدِهِ جَارِيَةً لَهُ فَغَارَ فَجَبَّ مَذَاكِيرَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ بِالرَّجُلِ فَطُلِبَ فَلَمْ يُقْدَرْ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَأَنْتَ حُرٌّ فَقَالَ يَا رَسُولَ اللَّهِ عَلَى مَنْ نُصْرَتِي قَالَ عَلَى كُلِّ مُؤْمِنٍ أَوْ قَالَ كُلِّ مُسْلِمٍقَالَ أَبُو دَاوُد الَّذِي عَتَقَ كَانَ اسْمُهُ رَوْحُ بْنُ دِينَارٍ قَالَ أَبُو دَاوُد الَّذِي جَبَّهُ زِنْبَاعٌ قَالَ أَبُو دَاوُد هَذَا زِنْبَاعٌ أَبُو رَوْحٍ كَانَ مَوْلَى الْعَبْدِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Hasan bin Tasnim Al 'Ataki] berkata, telah menceritakan kepada kami [Muhammad bin Bakr] berkata, telah mengabarkan kepada kami [Sawwar Abu Hamzah] berkata, telah menceritakan kepada kami [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sambil berteriak, ia mengatakan, \"Wahai Rasulullah, budak wanitanya!\" beliau bersabda: \"Celaka kamu, ada apa denganmu?\" ia menjawab, \"Keburukkan, ia (budak) melihat budak wanita milik tuannya. Lalu tuannya cemburu hingga ia memotong kemaluannya.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Bawa kemari laki-laki itu.\" Laki-laki itu kemudian dicari namun tidak ketemu. Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Engkau sekarang merdeka, silahkan pergi.\" Ia lalu bertanya, \"Wahai Rasulullah, kepada siapa aku minta pertolongan?\" beliau menjawab: \"Kepada setiap mukmin, atau beliau mengatakan, \"Kepada setiap muslim.\" Abu Dawud berkata, \"Budak yang dimerdekakan itu namanya adalah Rauh bin Dinar.\" Abu Dawud berkata lagi, \"Sementara orang yang memotong kemaluan budak itu namanya adalah Zinba'.\" Abu Dawud berkata, \"Zinba' Abu Rauh juga mantan budak.\""},"3795":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ وَرَافِعِ بْنِ خَدِيجٍأَنَّ مُحَيِّصَةَ بْنَ مَسْعُودٍ وَعَبْدَ اللَّهِ بْنَ سَهْلٍ انْطَلَقَا قِبَلَ خَيْبَرَ فَتَفَرَّقَا فِي النَّخْلِ فَقُتِلَ عَبْدُ اللَّهِ بْنُ سَهْلٍ فَاتَّهَمُوا الْيَهُودَ فَجَاءَ أَخُوهُ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَابْنَا عَمِّهِ حُوَيِّصَةُ وَمُحَيِّصَةُ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمَ عَبْدُ الرَّحْمَنِ فِي أَمْرِ أَخِيهِ وَهُوَ أَصْغَرُهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ الْكُبْرَ أَوْ قَالَ لِيَبْدَأْ الْأَكْبَرُ فَتَكَلَّمَا فِي أَمْرِ صَاحِبِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقْسِمُ خَمْسُونَ مِنْكُمْ عَلَى رَجُلٍ مِنْهُمْ فَيُدْفَعُ بِرُمَّتِهِ قَالُوا أَمْرٌ لَمْ نَشْهَدْهُ كَيْفَ نَحْلِفُ قَالَ فَتُبَرِّئُكُمْ يَهُودُ بِأَيْمَانِ خَمْسِينَ مِنْهُمْ قَالُوا يَا رَسُولَ اللَّهِ قَوْمٌ كُفَّارٌ قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قِبَلِهِقَالَ سَهْلٌ دَخَلْتُ مِرْبَدًا لَهُمْ يَوْمًا فَرَكَضَتْنِي نَاقَةٌ مِنْ تِلْكَ الْإِبِلِ رَكْضَةً بِرِجْلِهَا قَالَ حَمَّادٌ هَذَا أَوْ نَحْوَهُ قَالَ أَبُو دَاوُد رَوَاهُ بِشْرُ بْنُ الْمُفَضَّلِ وَمَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ فِيهِ أَتَحْلِفُونَ خَمْسِينَ يَمِينًا وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ أَوْ قَاتِلِكُمْ وَلَمْ يَذْكُرْ بِشْرٌ دَمًا و قَالَ عَبْدَةُ عَنْ يَحْيَى كَمَا قَالَ حَمَّادٌ وَرَوَاهُ ابْنُ عُيَيْنَةَ عَنْ يَحْيَى فَبَدَأَ بِقَوْلِهِ تُبَرِّئُكُمْ يَهُودُ بِخَمْسِينَ يَمِينًا يَحْلِفُونَ وَلَمْ يَذْكُرْ الِاسْتِحْقَاقَ قَالَ أَبُو دَاوُد وَهَذَا وَهْمٌ مِنْ ابْنِ عُيَيْنَةَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar bin Masarah] dan [Muhammad bin Ubaid] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] dan [Rafi' bin Khadij] berkata, \"Muhayishah bin Mas'ud dan Abdullah bin Sahl berangkat menuju Khaibar, namun keduanya berpisah di perkebunan kurma. Lalu Abdullah bin Sahl mati terbunuh, dan mereka menuduh orang-orang Yahudilah yang telah membunuhnya. Kemudian saudaranya bernama 'Abdurrahman bin Sahl datang bersama dua orang anak pamannya, Huwayishah dan Muhayishah kepada Nabi shallallahu 'alaihi wasallam. Lantas 'Abdurrahman menceritakan perihal saudaranya -dia adalah yang paling kecil di antara saudaranya-, beliau pun bersabda; \"Hendaknya dimulai dari yang lebih besar, hendaknya dimulai dari yang lebih besar. Atau beliau bersabda; \"Hendaknya yang lebih besar yang memulai.\" Lalu keduanya menceritakan perihal saudaranya (yang terbunuh), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah lima puluh orang dari kalian bersumpah atas seorang dari mereka (Yahudi yang membunuh), dengan demikian maka akan dapat menebus tulang belulang saudaramu yang telah rapuh.\" Mereka menjawab, \"Kami tidak melihat peristiwanya secara langsung, lalu bagaimana kami akan bersumpah!\" beliau bersabda: \"Orang-orang yahudi itu akan bersih dari tuduhan kalian jika mereka bisa memberikan sumpah dari lima puluh orang dari kalangan mereka.\" Para sahabat menimpali, \"Mereka itu orang-orang kafir!\" Ia (perawi) berkata, \"Lantas Rasulullah shallallahu 'alaihi wasallam menebus (diyat) jiwa korban itu dengan harta pribadinya sendiri.\" Sahl berkata, \"Suatu hari aku masuk ke dalam kandang unta mereka, tiba-tiba aku aku ditendang oleh seekor unta betina dengan kakinya.\" Hammad berkomentar, \"Beginilah haditsnya, atau seperti inilah kira-kira.\" Abu Dawud berkata, \" [Bisyr Ibnul Mufadhdhal] dan [Malik] meriwayatkannya dari [Yahya bin Sa'id]. Ia menyebutkan dalam hadits tersebut, \"Apakah kalian bersedia bersumpah dengan lima puluh kali sumpah, kemudian kalian berhak untuk menuntut balas atas pembunuhan sahabat kalian ini?\" namun Bisyr tidak menyebutkan kata 'darah'. [Abdah] juga berkata dari [Yahya] sebagaimana yang dikatakan oleh [Hammad].\" [Ibnu Uyainah] juga meriwayatkan dari [Yahya], namun ia memulai dengan kalimat, \"Mereka orang-orang Yahudi akan bersih dari tuduhan kalian jika mereka memberikan lima puluh sumpah kepada kalian, dan ia tidak menyebutkan lafadh 'berhak'. Abu Dawud berkata, \"Dan inilah kesamaran dari Ibnu Uyainah.\""},"3796":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكٌ عَنْ أَبِي لَيْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَهْلٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّهُ أَخْبَرَهُ هُوَ وَرِجَالٌ مِنْ كُبَرَاءِ قَوْمِهِ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ خَرَجَا إِلَى خَيْبَرَ مِنْ جَهْدٍ أَصَابَهُمْ فَأُتِيَ مُحَيِّصَةُ فَأُخْبِرَ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ قَدْ قُتِلَ وَطُرِحَ فِي فَقِيرٍ أَوْ عَيْنٍ فَأَتَى يَهُودَ فَقَالَ أَنْتُمْ وَاللَّهِ قَتَلْتُمُوهُ قَالُوا وَاللَّهِ مَا قَتَلْنَاهُ فَأَقْبَلَ حَتَّى قَدِمَ عَلَى قَوْمِهِ فَذَكَرَ لَهُمْ ذَلِكَ ثُمَّ أَقْبَلَ هُوَ وَأَخُوهُ حُوَيِّصَةُ وَهُوَ أَكْبَرُ مِنْهُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ فَذَهَبَ مُحَيِّصَةُ لِيَتَكَلَّمَ وَهُوَ الَّذِي كَانَ بِخَيْبَرَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ كَبِّرْ يُرِيدُ السِّنَّ فَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا أَنْ يَدُوا صَاحِبَكُمْ وَإِمَّا أَنْ يُؤْذَنُوا بِحَرْبٍ فَكَتَبَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَكَتَبُوا إِنَّا وَاللَّهِ مَا قَتَلْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ أَتَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ فَتَحْلِفُ لَكُمْ يَهُودُ قَالُوا لَيْسُوا مُسْلِمِينَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ فَبَعَثَ إِلَيْهِمْ مِائَةَ نَاقَةٍ حَتَّى أُدْخِلَتْ عَلَيْهِمْ الدَّارَقَالَ سَهْلٌ لَقَدْ رَكَضَتْنِي مِنْهَا نَاقَةٌ حَمْرَاءُ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] berkata, telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Malik] dari [Abu Laila bin Abdullah bin 'Abdurrahman bin Sahl] dari [Sahl bin Abu Hatsmah] Bahwasanya ia dan beberapa tokoh kaumnya mengabarkan kepadanya, bahwa Abdullah bin Sahl dan Muhayishah keluar menuju Khaibar karena penderitaan yang mereka alami. Muhayyishah lalu didatangkan, lalu dikabarkan bahwa Abddullah bin Sahl dibunuh dan dibuang ke dalam lubang atau sumur. Muhayishah lalu mendatangi orang-orang Yahudi dan bertanya, \"Demi Allah, kalian yang telah membunuhnya?\" orang-orang Yahudi itu menjawab, \"Demi Allah, kami tidak membunuhnya.\" Muhayishah lalu pergi hingga sampai ke Madinah, ia lantas ceritakan semua kejadian tersebut kepada kaumnya. Kemudian, ia bersama saudaranya Huwayishah -dan ia umurnya lebih tua- serta 'Abdurrahman bin Sahl pergi menghadap Rasulullah shallallahu 'alaihi wasallam. Muhayishah angkat bicara -karena dialah yang waktu itu di Khaibar-, namun Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang tua dahulu, yang tua dahulu.\" Huwayishah lalu berbicara dan diteruskan oleh Muhayishah, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka mau mambayar diyat untuk temanmu atau mereka mengumumkan peperangan!\" Rasulullah shallallahu 'alaihi wasallam kemudian menulis surat kepada mereka menuntut perkara tersebut, lalu mereka membalas (surat beliau) dengan menulis jawaban, \"Demi Allah kami tidak membunuhnya.\" Rasulullah shallallahu 'alaihi wasallam lalu berkata kepada Huwayishah, Muhayishah dan 'Abdurrahman bin Sahl, \"Apakah kalian mau bersumpah, sehingga kalian berhak mendapatkan hak atas pembunuhan saudara kalian?\" mereka menjawab, \"Tidak.\" Beliau bersabda: \"(Padahal) orang-orang Yahudi akan bersumpah atas tuduhan kalian.\" Mereka menimpali, \"Mereka bukan orang-orang muslim!\" Rasulullah shallallahu 'alaihi wasallam lalu menebus diyat itu dengan harta pribadinya, beliau kirimkan unta hingga unta-unta tersebut di masukkan ke dalam rumah mereka.\" Sahl berkata, \"Salah satu unta tersebut bahkan telah menendangku, yakni unta merah.\""},"3797":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ وَكَثِيرُ بْنُ عُبَيْدٍ قَالَا حَدَّثَنَا ح و حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ أَخْبَرَنَا الْوَلِيدُ عَنْ أَبِي عَمْرٍو عَنْ عَمْرِو بْنِ شُعَيْبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَتَلَ بِالْقَسَامَةِ رَجُلًا مِنْ بَنِي نَصْرِ بْنِ مَالِكٍ بِبَحْرَةِ الرُّغَاءِ عَلَى شَطِّ لِيَّةِ الْبَحْرَةِ قَالَ الْقَاتِلُ وَالْمَقْتُولُ مِنْهُمْ وَهَذَا لَفْظُ مَحْمُودٍ بِبَحْرَةٍ أَقَامَهُ مَحْمُودٌ وَحْدَهُ عَلَى شَطِّ لِيَّةَ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] dan [Katsir bin Ubaid] keduanya berkata; telah menceritakan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Ash Shabbah bin Sufyan] berkata, telah mengabarkan kepada kami [Al Walid] dari [Abu Amru] dari [Amru bin Syu'aib] dari Rasulullah shallallahu 'alaihi wasallam bahwasanya beliau membunuh laki-laki dari bani Nashr bin Malik karena sumpah, yaitu di suatu tempat dataran rendah bernama Rugha, di sisi pantai. Ia (Mahmud) berkata, \"Baik yang membunuh atau yang dibunuh adalah dari mereka (bani Nashr).\" Ini adalah lafadz Mahmud, yaitu Mahmud mempunyai lafdh sendiri (dalam riwayatnya berupa; \"di suatu tempat dataran rendah bernama Rugha', di sisi pantai.\""},"3798":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ الزَّعْفَرَانِيُّ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ عَنْ بُشَيْرِ بْنِ يَسَارٍزَعَمَ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ سَهْلُ بْنُ أَبِي حَثْمَةَ أَخْبَرَهُ أَنَّ نَفَرًا مِنْ قَوْمِهِ انْطَلَقُوا إِلَى خَيْبَرَ فَتَفَرَّقُوا فِيهَا فَوَجَدُوا أَحَدَهُمْ قَتِيلًا فَقَالُوا لِلَّذِينَ وَجَدُوهُ عِنْدَهُمْ قَتَلْتُمْ صَاحِبَنَا فَقَالُوا مَا قَتَلْنَاهُ وَلَا عَلِمْنَا قَاتِلًا فَانْطَلَقْنَا إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ لَهُمْ تَأْتُونِي بِالْبَيِّنَةِ عَلَى مَنْ قَتَلَ هَذَا قَالُوا مَا لَنَا بَيِّنَةٌ قَالَ فَيَحْلِفُونَ لَكُمْ قَالُوا لَا نَرْضَى بِأَيْمَانِ الْيَهُودِ فَكَرِهَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبْطِلَ دَمَهُ فَوَدَاهُ مِائَةً مِنْ إِبِلِ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah Az Za'farani] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sa'id bin Ubaid Ath Tha`i] dari [Busyair bin Yasar] ia berkeyakinan bahwa seorang laki-laki Anshar yang bernama [Sahl bin Abu Hatsmah] mengabarkan kepadanya, bahwa seorang laki-laki dari kaumnya berangkat menuju Khaibar. Lalu mereka mereka berpencar, hingga mereka mendapati salah seorang dari mereka telah terbunuh. Mereka pun berkata kepada orang-orang yang mereka temui, \"Kalian telah membunuh saudara kami!\" orang-orang itu menjawab, \"Kami tidak membunuhnya, dan kami juga tidak melihat seorang pembunuh.\" Maka kami pun berangkat menuju Nabi shallallahu 'alaihi wasallam. Ia (perawi) berkata, \"Beliau bertanya kepada mereka, \"Apakah kalian datang kepadaku dengan membawa bukti, siapa yang membunuhnya (temanmu)?\" mereka menjawab, \"Kami tidak punya bukti.\" Beliau menimpali: \"Mereka (orang-orang Yahudi) akan bersumpah atas kalian!\" mereka berkata, \"Kami tidak ridha dengan sumpahnya orang-orang yahudi.\" Nabi shallallahu 'alaihi wasallam tidak ingin kematiannya itu menjadi sia-sia, maka beliau pun membayar diyat tersebut dengan seratus ekor unta dari unta-unta sedekah.\""},"3799":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيِّ بْنِ رَاشِدٍ أَخْبَرَنَا هُشَيْمٌ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ حَدَّثَنَا عَبَايَةُ بْنُ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَأَصْبَحَ رَجُلٌ مِنْ الْأَنْصَارِ مَقْتُولًا بِخَيْبَرَ فَانْطَلَقَ أَوْلِيَاؤُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا ذَلِكَ لَهُ فَقَالَ لَكُمْ شَاهِدَانِ يَشْهَدَانِ عَلَى قَتْلِ صَاحِبِكُمْ قَالُوا يَا رَسُولَ اللَّهِ لَمْ يَكُنْ ثَمَّ أَحَدٌ مِنْ الْمُسْلِمِينَ وَإِنَّمَا هُمْ يَهُودُ وَقَدْ يَجْتَرِئُونَ عَلَى أَعْظَمَ مِنْ هَذَا قَالَ فَاخْتَارُوا مِنْهُمْ خَمْسِينَ فَاسْتَحْلَفُوهُمْ فَأَبَوْا فَوَدَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali bin Rasyid] berkata, telah mengabarkan kepada kami [Husyaim] dari [Abu hayyan At taimi] berkata, telah menceritakan kepada kami [Abayah bin Rifa'ah] dari [Rafi' bin Khadij] ia berkata, \"Seorang laki-laki Anshar terbunuh di Khaibar, maka para walinya datang menemui Nabi shallallahu 'alaihi wasallam. Mereka menceritakan kepada beliau perihal terbunuhnya saudaranya tersebut. Beliau lantas bertanya: \"Apakah kalian mempunyai dua saksi yang melihat pembunuhan itu?\" mereka menjawab, \"Wahai Rasulullah, tidak ada seorang muslim pun, mereka semua orang-orang Yahudi! Dan mungkin mereka akan lebih berani lagi untuk melakukan yang lebih besar dari ini.\" Rafi' bin Khadij berkata, \"Beliau lalu memilih lima puluh orang dari mereka untuk disumpah, namun mereka menolak. Maka diyat itu akhirnya dibayar oleh Nabi shallallahu 'alaihi wasallam dari harta sendiri.\""},"3800":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ قَالَإِنَّ سَهْلًا وَاللَّهِ أَوْهَمَ الْحَدِيثَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى يَهُودَ أَنَّهُ قَدْ وُجِدَ بَيْنَ أَظْهُرِكُمْ قَتِيلٌ فَدُوهُ فَكَتَبُوا يَحْلِفُونَ بِاللَّهِ خَمْسِينَ يَمِينًا مَا قَتَلْنَاهُ وَلَا عَلِمْنَا قَاتِلًا قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ بِمِائَةِ نَاقَةٍ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Al Harrani] berkata, telah menceritakan kepadaku [Muhammad] -maksudnya Muhammad bin Salamah- dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim Ibnul Harits] dari ['Abdurrahman bin Bujaid] ia berkata; Demi Allah, Sahl masih samar dalam haditsnya. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam menulis surat kepada orang-orang Yahudi, 'Telah didapati di antara kalian korban pembunuhan, maka tebuslah diyatnya'. Lalu orang-orang Yahudi itu memberi balasan dengan memberikan sumpah sebanyak lima puluh kali, 'kami tidak membunuhnya, dan kami juga tidak tahu siapa pembunuhnya'. Ia (perawi) berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu menebus diyat itu dengan seratus ekor unta miliknya sendiri.\""},"3801":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ رِجَالٍ مِنْ الْأَنْصَارِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْيَهُودِ وَبَدَأَ بِهِمْ يَحْلِفُ مِنْكُمْ خَمْسُونَ رَجُلًا فَأَبَوْا فَقَالَ لِلْأَنْصَارِ اسْتَحِقُّوا قَالُوا نَحْلِفُ عَلَى الْغَيْبِ يَا رَسُولَ اللَّهِ فَجَعَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةً عَلَى يَهُودَ لِأَنَّهُ وُجِدَ بَيْنَ أَظْهُرِهِمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] dan [Sulaiman bin Yasar] dari [Beberapa lelaki] Anshar bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada orang-orang Yahudi, dan beliau memulai dari mereka, \"Apakah ada lima puluh orang dari kalian yang mau bersumpah?\" namun mereka tidak ada yang bersedia. Lalu beliau berkata kepada orang-orang Anshar: \"Kalian berhak (untuk balas bersumpah).\" Mereka bertanya, \"Wahai Rasulullah, apakah kami harus bersumpah untuk sesuatu yang kami tidak ketahui!\" Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa diyat itu menjadi tanggungan bagi orang-orang Yahudi, sebab korban pembunuhan itu ada pada mereka.\""},"3802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ جَارِيَةً وُجِدَتْ قَدْ رُضَّ رَأْسُهَا بَيْنَ حَجَرَيْنِ فَقِيلَ لَهَا مَنْ فَعَلَ بِكِ هَذَا أَفُلَانٌ أَفُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأَوْمَتْ بِرَأْسِهَا فَأُخِذَ الْيَهُودِيُّ فَاعْتَرَفَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرَضَّ رَأْسُهُ بِالْحِجَارَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Hammam] dari [Qatadah] dari [Anas] berkata, \"Seorang budak wanita ditemukan dalam keadaan kepalanya telah retak di antara dua batu, ia lalu ditanya, \"Siapa yang melakukan ini? Apakah si fulan, apakah si fulan?\" Hingga disebutlah nama seorang Yahudi dengan isyarat kepalanya. Maka yahudi itu ditangkap dan Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk meremukkan kepalanya dengan batu (sebagaimana yang dilakukannya kepada budak tersebut).\""},"3803":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ يَهُودِيًّا قَتَلَ جَارِيَةً مِنْ الْأَنْصَارِ عَلَى حُلِيٍّ لَهَا ثُمَّ أَلْقَاهَا فِي قَلِيبٍ وَرَضَخَ رَأْسَهَا بِالْحِجَارَةِ فَأُخِذَ فَأُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِ أَنْ يُرْجَمَ حَتَّى يَمُوتَ فَرُجِمَ حَتَّى مَاتَقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ جُرَيْجٍ عَنْ أَيُّوبَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Anas] berkata, \"Seorang Yahudi membunuh serang wanita Anshar untuk merebut perhiasannya. Yahudi itu lalu membuang budak wanita tersebut ke dalam sumur tua dan menghimpit kepalanya dengan batu. Yahudi itu akhirnya ditangkap dan dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, beliau lalu memerintahkan agar yahudi itu dirajam hingga mati, maka yahudi itu dirajam hingga mati.\" Abu Dawud berkata, \" [Ibnu Juraij] meriwayatkannya dari [Ayyub] seperti itu pula.\""},"3804":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ جَدِّهِ أَنَسٍأَنَّ جَارِيَةً كَانَ عَلَيْهَا أَوْضَاحٌ لَهَا فَرَضَخَ رَأْسَهَا يَهُودِيٌّ بِحَجَرٍ فَدَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهَا رَمَقٌ فَقَالَ لَهَا مَنْ قَتَلَكِ فُلَانٌ قَتَلَكِ فَقَالَتْ لَا بِرَأْسِهَا قَالَ مَنْ قَتَلَكِ فُلَانٌ قَتَلَكِ قَالَتْ لَا بِرَأْسِهَا قَالَ فُلَانٌ قَتَلَكِ قَالَتْ نَعَمْ بِرَأْسِهَا فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُتِلَ بَيْنَ حَجَرَيْنِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Idris] dari [Syu'bah] dari [Hisyam bin Zaid] dari kakeknya [Anas] ia berkata, \"Seorang budak wanita memiliki perhiasan dari perak, lalu seorang Yahudi memukul kepalanya dengan batu hingga retak. Rasulullah shallallahu 'alaihi wasallam kemudian masuk menemui budak wanita itu di saat akhir dari hidupnya. Beliau bertanya: \"Siapa yang membunuhmu, apakah si fulan yang melakukannya?\" Dengan isyarat kepalanya ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Siapa yang membunuhmu, apakah si fulan yang melakukannya?\" Dengan isyarat kepalanya ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Siapa yang membunuhmu, apakah si fulan yang melakukannya?\" Dengan isyarat kepala ia menjawab, \"Benar.\" Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk menangkap pembunuh tersebut, maka pembunuh itu pun dibunuh dengan dihimpit (dibenturkan kepalanya) antara dua batu.\""},"3805":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَانْطَلَقْتُ أَنَا وَالْأَشْتَرُ إِلَى عَلِيٍّ عَلَيْهِ السَّلَام فَقُلْنَا هَلْ عَهِدَ إِلَيْكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ عَامَّةً قَالَ لَا إِلَّا مَا فِي كِتَابِي هَذَا قَالَ مُسَدَّدٌ قَالَ فَأَخْرَجَ كِتَابًا وَقَالَ أَحْمَدُ كِتَابًا مِنْ قِرَابِ سَيْفِهِ فَإِذَا فِيهِ الْمُؤْمِنُونَ تَكَافَأُ دِمَاؤُهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ وَيَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ أَلَا لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِ مَنْ أَحْدَثَ حَدَثًا فَعَلَى نَفْسِهِ وَمَنْ أَحْدَثَ حَدَثًا أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ قَالَ مُسَدَّدٌ عَنْ ابْنِ أَبِي عَرُوبَةَ فَأَخْرَجَ كِتَابًاحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا هُشَيْمٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ نَحْوَ حَدِيثِ عَلِيٍّ زَادَ فِيهِ وَيُجِيرُ عَلَيْهِمْ أَقْصَاهُمْ وَيَرُدُّ مُشِدُّهُمْ عَلَى مُضْعِفِهِمْ وَمُتَسَرِّيهِمْ عَلَى قَاعِدِهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah mengabarkan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Al Hasan] dari [Qais bin Ubad] ia berkata, \"Aku bersama Al Asytar berangkat menemui [Ali radliallahu 'anhu]. Kami lalu bertanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam memberimu suatu wasiat yang tidak disampaikan kepada manusia secara umum?\" Ali menjawab, \"Tidak, kecuali apa yang ada dalam catatanku ini -Musaddad menyebutkan- \"Ali lalu mengeluarkan sebuah catatan.\" -Dan Ahmad menyebutkan- \"catatan yang ada pada sarung pedangnya.\" Dalam catatan itu disebutkan, \"orang-orang yang beriman itu darahnya sama (dalam hal qishash dan tebusan), mereka saling membantu dengan sesamanya untuk menghadapi orang lain (kafir), dan orang-orang yang paling dekat dengan mereka yang mukmin itu dapat menanggung mereka. Ketahuilah, seorang mukmin tidak boleh dibunuh karena membunuh seorang kafir (sebagai qishas), dan juga tidak boleh membunuh seseorang yang berada dalam ikatan perjanjiannya. Siapa saja yang berbuat kejahatan maka dosanya ia tanggung sendiri, dan barangsiapa berbuat kejahatan atau melindungi seorang penjahat, maka ia akan mendapat laknat Allah, malaikat dan semua manusia.\" [Musaddad] menyebutkan dari [Ibnu Abu Arubah], \"Lalu Ali mengeluarkan catatan.\" Telah menceritakan kepada kami [Ubaidullah bin Umar] berkata, telah menceritakan kepada kami [Husyaim] dari [Yahya bin Sa'id] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, lalu beliau menyebutkan sebagaimana hadits Ali. Hanya saja perawi menambahkan, \"Orang-orang yang ada di tempat yang jauh (perbatasan) memberikan perlindungannya, yang kuat melindungi yang lemah dan ikut perang melindungi mereka yang berada di rumah.\""},"3806":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَعَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ الْحَوْطِيُّ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ سَعْدَ بْنَ عُبَادَةَ قَالَ يَا رَسُولَ اللَّهِ الرَّجُلُ يَجِدُ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ سَعْدٌ بَلَى وَالَّذِي أَكْرَمَكَ بِالْحَقِّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا إِلَى مَا يَقُولُ سَيِّدُكُمْ قَالَ عَبْدُ الْوَهَّابِ إِلَى مَا يَقُولُ سَعْدٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abdul Wahhab bin Najdah Al Hauthi] dengan satu makna, keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] bahwa Sa'd bin Ubadah berkata, \"Wahai Rasulullah, jika seorang laki-laki mendapati laki-laki (lain) bersama isterinya, apakah ia boleh membunuhnya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak.\" Sa'd berkata, \"Baiklah, demi Dzat yang memuliakanmu dengan kebenaran.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Dengarkanlah apa yang disampikan oleh pemimpinmu.\" Abdul Wahhab berkata dengan redaksi, \"Yakni kepada apa yang disampaikan oleh Sa'd.\""},"3807":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ سَعْدَ بْنَ عُبَادَةَ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ لَوْ وَجَدْتُ مَعَ امْرَأَتِي رَجُلًا أُمْهِلُهُ حَتَّى آتِيَ بِأَرْبَعَةِ شُهَدَاءَ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Sa'd bin Ubadah berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Apa pendapatmu jika aku mendapati isteriku bersama laki-laki asing, apakah aku harus menahan diri hingga aku dapat menghadirkan empat orang saksi?\" Beliau menjawab: \"Ya.\""},"3808":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا جَهْمِ بْنَ حُذَيْفَةَ مُصَدِّقًا فَلَاجَّهُ رَجُلٌ فِي صَدَقَتِهِ فَضَرَبَهُ أَبُو جَهْمٍ فَشَجَّهُ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا الْقَوَدَ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكُمْ كَذَا وَكَذَا فَلَمْ يَرْضَوْا فَقَالَ لَكُمْ كَذَا وَكَذَا فَلَمْ يَرْضَوْا فَقَالَ لَكُمْ كَذَا وَكَذَا فَرَضُوا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَاطِبٌ الْعَشِيَّةَ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ فَقَالُوا نَعَمْ فَخَطَبَ رَسُولُ اللَّهِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَؤُلَاءِ اللَّيْثِيِّينَ أَتَوْنِي يُرِيدُونَ الْقَوَدَ فَعَرَضْتُ عَلَيْهِمْ كَذَا وَكَذَا فَرَضُوا أَرَضِيتُمْ قَالُوا لَا فَهَمَّ الْمُهَاجِرُونَ بِهِمْ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكُفُّوا عَنْهُمْ فَكَفُّوا ثُمَّ دَعَاهُمْ فَزَادَهُمْ فَقَالَ أَرَضِيتُمْ فَقَالُوا نَعَمْ قَالَ إِنِّي خَاطِبٌ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ قَالُوا نَعَمْ فَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَرَضِيتُمْ قَالُوا نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin Dawud bin Sufyan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam mengutus Abu Jahm bin Hudzaifah sebagai penengah dalam persengketaan. Namun ada seorang laki-laki laki-laki yang memutar balikkan fakta hingga Abu jahm memukulnya hingga cidera. Mereka pun mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, kami minta qishsash! ' Rasulullah shallallahu 'alaihi wasallam kemudian berkata, \"Bagi kalian begini dan begini, \" namun mereka tidak rela. Beliau bersabda lagi: \"Bagi kalian begini dan begini, \" namun mereka tidak rela. Beliau bersabda lagi: \"Bagi kalian begini dan begini, ' mereka akhirnya rela. Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan berpidato di hadapan orang-orang petang nanti dan mengabarkan kepada mereka bahwa kalian telah rela.\" Mereka menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam lalu berpidato: \"Orang-orang bani Laits telah mendatangiku menginginkan qishsas, lalu aku tawarkan kepada mereka begini dan begini hingga mereka rela, maka apakah kalian juga rela?\" Mereka menjawab, \"Tidak.\" Orang-orang Muhajirin ingin menghajar mereka, namun Rasulullah shallallahu 'alaihi wasallam melarang mereka melakukan hal itu, sehingga mereka pun menahan diri. Kemudian beliau memanggil mereka semua dan berpidato lagi: \"Apakah kalian ridha?\" Mereka menjawab, \"Ya.\" Beliau bersabda: \"Aku akan berpidato di hadapan orang-orang untuk mengabarkan kepada mereka bahwa kalian telah ridha.\" Para sahabat menjawab, \"Ya.\" maka Nabi shallallahu 'alaihi wasallam berpidato seraya berkata: \"Apakah kalian ridha?\" Mereka menjawab, \"Ya.\""},"3809":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ جَارِيَةً وُجِدَتْ قَدْ رُضَّ رَأْسُهَا بَيْنَ حَجَرَيْنِ فَقِيلَ لَهَا مَنْ فَعَلَ بِكِ هَذَا أَفُلَانٌ أَفُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأَوْمَتْ بِرَأْسِهَا فَأُخِذَ الْيَهُودِيُّ فَاعْتَرَفَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرَضَّ رَأْسُهُ بِالْحِجَارَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] berkata, \"Seorang budak wanita ditemukan dalam keadaan kepalanya terhimpit antara dua batu, maka ditanyakan kepadanya, \"Siapa yang melakukan ini kepadamu? Apakah si fulan yang melakukannya?\" Hingga ketika nama seorang Yahudi disebut, dengan kepalanya ia menjawab, \"Ya.\" Yahudi itu kemudian dijemput dan ia mengakuinya. Maka Nabi shallallahu 'alaihi wasallam memerintakah agar kepala yahudi itu juga dipecahkan dengan dihipit antara dua batu.\""},"3810":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرٍو يَعْنِي ابْنَ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ عُبَيْدَةَ بْنِ مُسَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ قَسْمًا أَقْبَلَ رَجُلٌ فَأَكَبَّ عَلَيْهِ فَطَعَنَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُرْجُونٍ كَانَ مَعَهُ فَجُرِحَ بِوَجْهِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَ فَاسْتَقِدْ فَقَالَ بَلْ عَفَوْتُ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Amru] -maksudnya Amru bin harits- dari [Bukair Ibnul Asyaj] dari [Ubaidah bin Musafi'] dari [Abu Sa'id Al Khudri] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang membagi-bagikan sesuatu, tiba-tiba datang seorang laki-laki ke arah beliau hingga beliau pun memukul dengan tongkat yang dibawanya sehingga timbul luka di wajahnya. Rasulullah shallallahu 'alaihi wasallam lalu berkata kepadanya: \"Kemarilah, silahkan kamu qishas.\" Laki-laki itu menjawab, \"Tidak ya Rasulullah, aku telah memaafkanmu.\""},"3811":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي فِرَاسٍ قَالَخَطَبَنَا عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنِّي لَمْ أَبْعَثْ عُمَّالِي لِيَضْرِبُوا أَبْشَارَكُمْ وَلَا لِيَأْخُذُوا أَمْوَالَكُمْ فَمَنْ فُعِلَ بِهِ ذَلِكَ فَلْيَرْفَعْهُ إِلَيَّ أُقِصُّهُ مِنْهُ قَالَ عَمْرُو بْنُ الْعَاصِ لَوْ أَنَّ رَجُلًا أَدَّبَ بَعْضَ رَعِيَّتِهِ أَتُقِصُّهُ مِنْهُ قَالَ إِي وَالَّذِي نَفْسِي بِيَدِهِ أُقِصُّهُ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَصَّ مِنْ نَفْسِهِ","id":"Telah menceritakan kepada kami [Abu Shalih] berkata, telah mengabarkan kepada kami [Abu Ishaq Al Fazari] dari [Al Jurairi] dari [Abu Nadhrah] dari [Abu firas] ia berkata, \" [Umar Ibnul Khaththab] radliallahu 'anhu berkhutbah di hadapan kami, ia mengatakan, \"Aku tidak mengutus para petugasku untuk memukul badan atau mengambil harta kalian, maka siapa di antara kalian yang mendapatkan perlakukan seperti itu hendaklah ia datang kepadaku, sehingga aku dapat mengqishasnya.\" Amru Ibnul Ash berkata, \"Jika ada seorang laki-laki yang mendidik (dengan memukul) sebagian orang yang ada dalam pengawasannya apakah ada qishasnya?\" Umar menjawab, \"Benar. Demi Dzat yang jiwaku ada dalam tangan-Nya, aku tetap akan mengqishasnya. Sebab aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mengqishas karena (kesalahan) dirinya sendiri.\""},"3812":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ أَنَّهُ سَمِعَ حِصْنًا أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُخْبِرُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ عَلَى الْمُقْتَتِلِينَ أَنْ يَنْحَجِزُوا الْأَوَّلَ فَالْأَوَّلَ وَإِنْ كَانَتْ امْرَأَةًقَالَ أَبُو دَاوُد بَلَغَنِي أَنَّ عَفْوَ النِّسَاءِ فِي الْقَتْلِ جَائِزٌ إِذَا كَانَتْ إِحْدَى الْأَوْلِيَاءِ وَبَلَغَنِي عَنْ أَبِي عُبَيْدٍ فِي قَوْلِهِ يَنْحَجِزُوا يَكُفُّوا عَنْ الْقَوَدِ","id":"Telah menceritakan kepada kami [Dawud bin Rusyaid] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] Bahwasanya ia mendengar [Hishn] bahwa ia mendengar [Abu Salamah] mengabarkan dari ['Aisyah radliallahu 'anha] dari Rasulullah shallallahu 'alaihi wasallam, Bahwasanya beliau bersabda tentang orang-orang yang saling bunuh: \"Hendaklah mereka menahan dari meminta qishas dari orang yang lebih dekat, meskipun itu seorang wanita.\" Abu Dawud berkata, \"Telah sampai kabar kepadaku bahwa memaafkan wanita dalam perkara qishas itu di bolehkan jika ia termasuk salah satu dari sekian wali yang ada. Dan telah sampai kabar kepadaku tentang sabda Nabi 'hendaklah mereka meminta mundur dari qishash', artinya menahan diri dari meminta qihsas.\""},"3813":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا سُفْيَانُ وَهَذَا حَدِيثُهُ عَنْ عَمْرٍو عَنْ طَاوُوسٍ قَالَمَنْ قُتِلَ وَقَالَ ابْنُ عُبَيْدٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ فِي عِمِّيَّا فِي رَمْيٍ يَكُونُ بَيْنَهُمْ بِحِجَارَةٍ أَوْ بِالسِّيَاطِ أَوْ ضَرْبٍ بِعَصًا فَهُوَ خَطَأٌ وَعَقْلُهُ عَقْلُ الْخَطَإِ وَمَنْ قُتِلَ عَمْدًا فَهُوَ قَوَدٌ قَالَ ابْنُ عُبَيْدٍ قَوَدُ يَدٍ ثُمَّ اتَّفَقَا وَمَنْ حَالَ دُونَهُ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَغَضَبُهُ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌوَحَدِيثُ سُفْيَانَ أَتَمُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي غَالِبٍ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ سُلَيْمَانَ بْنِ كَثِيرٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ طَاوُوسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَى حَدِيثِ سُفْيَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah menceritakan kepada kami [Sufyan] -dan ini adalah haditsnya- dari [Amru] dari [Thawus] ia berkata, \"Barangsiapa terbunuh dalam keadaan gelap (tidak jelas siapa pembunuh dan bagaimana caranya), yaitu ketika saling lempar di antara mereka, baik itu dengan batu, cambuk, atau tongkat, maka itu adalah pembunuhan karena kesalahan, dan diyatnya adalah diyat (tebusannya) pembunuhan karena salah. Maka barangsiapa membunuh dengan sengaja, diyatnya adalah qishas - [Ibnu Ubaid] menyebutkan dalam riwayat lain- \"qishas dengan tangan. Kemudian riwayat itu sepakat pada lafadz, \"Barangsiapa menghalangi terlaksananya qishas, maka ia akan mendapat laknat dan murka Allah, serta tidak akan diterima ibadahnya baik amalam sunnah atau wajib.\" Dan hadits Sufyan redaksinya lebih lengkap. Telah menceritakan kepada kami [Muhammad bin Abu Ghalib] berkata, telah menceritakan kepada kami [Sa'id bin Sulaiman] dari [Sulaiman bin Katsir] berkata, telah menceritakan kepada kami [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, lalu ia menyebutkan makna hadits Sufyan.\""},"3814":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ ح و حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ مَنْ قُتِلَ خَطَأً فَدِيَتُهُ مِائَةٌ مِنْ الْإِبِلِ ثَلَاثُونَ بِنْتَ مَخَاضٍ وَثَلَاثُونَ بِنْتَ لَبُونٍ وَثَلَاثُونَ حِقَّةً وَعَشَرَةُ بَنِي لَبُونٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] ia berkata; telah menceritakan kepada kami [Muhammad bin rasyid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zaqa] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Muhammad bin rasyid] dari [Sulaiman bin Musa] dari [Amru bin Syu'aib] dari [bapaknya] dari [kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa orang yang membunuh karena salah maka diyatnya (tebusannya) adalah seratus ekor unta; tiga puluh anak unta makhadh, tiga puluh anak unta betina labun, tiga puluh hiqqah dan sepuluh anak unta jantan labun laki-laki.\""},"3815":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُثْمَانَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَتْ قِيمَةُ الدِّيَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانَ مِائَةِ دِينَارٍ أَوْ ثَمَانِيَةَ آلَافِ دِرْهَمٍ وَدِيَةُ أَهْلِ الْكِتَابِ يَوْمَئِذٍ النِّصْفُ مِنْ دِيَةِ الْمُسْلِمِينَ قَالَ فَكَانَ ذَلِكَ كَذَلِكَ حَتَّى اسْتُخْلِفَ عُمَرُ رَحِمَهُ اللَّهُ فَقَامَ خَطِيبًا فَقَالَ أَلَا إِنَّ الْإِبِلَ قَدْ غَلَتْ قَالَ فَفَرَضَهَا عُمَرُ عَلَى أَهْلِ الذَّهَبِ أَلْفَ دِينَارٍ وَعَلَى أَهْلِ الْوَرِقِ اثْنَيْ عَشَرَ أَلْفًا وَعَلَى أَهْلِ الْبَقَرِ مِائَتَيْ بَقَرَةٍ وَعَلَى أَهْلِ الشَّاءِ أَلْفَيْ شَاةٍ وَعَلَى أَهْلِ الْحُلَلِ مِائَتَيْ حُلَّةٍ قَالَ وَتَرَكَ دِيَةَ أَهْلِ الذِّمَّةِ لَمْ يَرْفَعْهَا فِيمَا رَفَعَ مِنْ الدِّيَةِ","id":"Telah menceritakan kepada kami [Yahya bin hakim] berkata, telah menceritakan kepada kami ['Abdurrahman bin Utsman] berkata, telah menceritakan kepada kami [Husain Al Muallim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [kakeknya] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam nilai tebusan diyat adalah delapan ratus dinar, atau delapan ribu dirham, sedangkan diyat bagi ahli kitab adalah setengah dari diyat kaum muslimin.\" Ia (perawi) berkata, \"Hal itu terus berlangsung hingga Umar diangkat menjadi khalifah, dan saat berpidato ia berkata, \"Ketahuilah, sesungguhnya harta unta telah naik.\" Perawi berkata lagi, \"Maka Umar mewajibkan bagi pemilik emas untuk membayar diyat sebanyak seribu dinar, bagi pemilik perak dua belas ribu dirham, bagi pemilik sapi sebanyak dua ratus ekor sapi, bagi pemilik kambing sebanyak dua ribu kambing, dan bagi pemilik pakaian sebanyak dua ratus pasang baju.\" Ia (perawi) berkata, \"Sementara diyat untuk ahli dzimmah tidak dinaikkan sebagaimana diyat yang lainnya.\""},"3816":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي الدِّيَةِ عَلَى أَهْلِ الْإِبِلِ مِائَةً مِنْ الْإِبِلِ وَعَلَى أَهْلِ الْبَقَرِ مِائَتَيْ بَقَرَةٍ وَعَلَى أَهْلِ الشَّاءِ أَلْفَيْ شَاةٍ وَعَلَى أَهْلِ الْحُلَلِ مِائَتَيْ حُلَّةٍ وَعَلَى أَهْلِ الْقَمْحِ شَيْئًا لَمْ يَحْفَظْهُ مُحَمَّدٌقَالَ أَبُو دَاوُد قَرَأْتُ عَلَى سَعِيدِ بْنِ يَعْقُوبَ الطَّالْقَانِيِّ قَالَ حَدَّثَنَا أَبُو تُمَيْلَةَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ قَالَ ذَكَرَ عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَ حَدِيثِ مُوسَى وَقَالَ وَعَلَى أَهْلِ الطَّعَامِ شَيْئ��ا لَا أَحْفَظُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Atha bin Abu Rabah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa besaran diyat bagi pemilik unta adalah seratus ekor unta, pemilik sapi adalah dua ratus ekor sapi, pemilik kambing adalah dua ribu ekor kambing, pemilik pakaian adalah dua pasang baju, pemilik gandum adalah sesuatu…-muhammad tidak menghafalnya-.\" Abu Dawud berkata, \"Aku membaca di hadapan [Sa'id bin Ya'qub Ath Thalqani], ia berkata; telah menceritakan kepada kami [Abu Tumailah] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] ia berkata; Atha menyebutkan dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mewajibkan…lalu ia menyebutkan sebagaimana hadits Musa. Ia berkata, \"Bagi pemilik makanan adalah sesuatu…aku tidak menghafalnya.\""},"3817":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْحَجَّاجُ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ خِشْفِ بْنِ مَالِكٍ الطَّائِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دِيَةِ الْخَطَإِ عِشْرُونَ حِقَّةً وَعِشْرُونَ جَذَعَةً وَعِشْرُونَ بِنْتَ مَخَاضٍ وَعِشْرُونَ بِنْتَ لَبُونٍ وَعِشْرُونَ بَنِي مَخَاضٍ ذُكُرٍ وَهُوَ قَوْلُ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Wahid] berkata, telah menceritakan kepada kami [Al Hajjaj] dari [Zaid bin Jubair] dari [Khisyf bin Malik Ath Tha`i] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda tentang pembunuhan yang tidak sengaja; dua puluh hiqqah, ditambah dua puluh jadz'ah, ditambah dua puluh anak unta betina makhadh, ditambah dua puluh anak unta betina labun, dan dua puluh anak unta jantan makhadh. ' Ini adalah perkataan Abdullah.\""},"3818":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا مِنْ بَنِي عَدِيٍّ قُتِلَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَتَهُ اثْنَيْ عَشَرَ أَلْفًاقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ عُيَيْنَةَ عَنْ عَمْرِو عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَذْكُرْ ابْنَ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] dari [Muhammad bin Muslim] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki dari bani Adi terbunuh, lalu Nabi shallallahu 'alaihi wasallam menetapkan bahwa diyatnya adalah dua belas ribu.\" Abu Dawud berkata, \" [Ibnu Uyainah] meriwayatkannya dari [Amru], dari [Ikrimah], dari Nabi shallallahu 'alaihi wasallam, namun ia tidak menyebutkan nama Ibnu Abbas.\""},"3819":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُسَدَّدٌ خَطَبَ يَوْمَ الْفَتْحِ بِمَكَّةَ فَكَبَّرَ ثَلَاثًا ثُمَّ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ صَدَقَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ إِلَى هَاهُنَا حَفِظْتُهُ عَنْ مُسَدَّدٍ ثُمَّ اتَّفَقَا أَلَا إِنَّ كُلَّ مَأْثُرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ تُذْكَرُ وَتُدْعَى مِنْ دَمٍ أَوْ مَالٍ تَحْتَ قَدَمَيَّ إِلَّا مَا كَانَ مِنْ سِقَايَةِ الْحَاجِّ وَسِدَانَةِ الْبَيْتِ ثُمَّ قَالَ أَلَا إِنَّ دِيَةَ الْخَطَإِ شِبْهِ الْعَمْدِ مَا كَانَ بِالسَّوْطِ وَالْعَصَا مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِ أَوْلَادِهَاوَحَدِيثُ مُسَدَّدٍ أَتَمُّ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ بِهَذَا الْإِسْنَادِ نَحْوَ مَعْنَاهُ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ خَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ أَوْ فَتْحِ مَكَّةَ عَلَى دَرَجَةِ الْبَيْتِ أَوْ الْكَعْبَةِ قَالَ أَبُو دَاوُد كَذَا رَوَاهُ ابْنُ عُيَيْنَةَ أَيْضًا عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَوَاهُ أَيُّوبُ السَّخْتِيَانِيُّ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو مِثْلَ حَدِيثِ خَالِدٍ وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ يَعْقُوبَ السَّدُوسِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَوْلُ زَيْدٍ وَأَبِي مُوسَى مِثْلُ حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Musaddad] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Khalid] dari [Al Qasim bin Rabi'ah] dari [Uqbah bin Aus] dari [Abdullah bin Amru] bahwa Rasulullah shallallahu 'alaihi wasallam -Musaddad menyebutkan- berkhutbah pada hari penaklukan kota Makkah. Beliau bertakbir sebanyak tiga kali kemudian mengatakan: \"Tidak ada Tuhan selain Allah Yang Maha Esa, Maha Benar janji-Nya, dan menolong hamba-Nya, serta satu-satunya yang mengalahkan golongan musuh yang bersekutu -sampai kalimat ini aku menghafalnya dari Musaddad, kemudian keduanya sepakat pada lafadz- Ketahuilah, semua peninggalan masa Jahilliyah baik itu yang diperoleh karena diyat pembunuhan atau pencurian, maka semua itu ada di bawah telapak kakiku (yakni bathil), kecuali apa-apa yang dihasilkan dari usaha memberi minum jamaah haji dan pengabdian kepada ka'bah.\" Kemudian beliau bersabda: \"Ketahuilah, diyat untuk pembunuhan yang tidak sengaja (yang menyerupai sengaja), seperti memukul dengan cambuk atau tongkat adalah seratus ekor unta, yang di antaranya adalah empat puluh ekor yang sedang hamil.\" Hadits Musaddad ini lebih sempurna. Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Khalid] dengan sanad ini, seperti makna hadits tersebut. Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits] dari [Ali bin Zaid] dari [Al Qasim bin Rabi'ah] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan makna yang sama. Ia (perawi) berkata, \"Pada hari penaklukan kota Makkah Rasulullah shallallahu 'alaihi wasallam berkhutbah di atas undakan rumah atau ka'bah.\" Abu Dawud berkata, \"Seperti ini pula [Ibnu Uyainah] meriwayatkan dari [Ali bin Zaid], dari [Al Qasim bin Rabi'ah], dari [Ibnu Umar] dari nabi shallallahu 'alaihi wasallam.\" [Ayyub As Sakhtiyani] juga meriwayatkan dari [Al Qasim bin Rabi'ah], dari [Abdullah bin Amru] sebagaimana hadits Khalid, dan [Hammad bin Salamah] juga meriwayatkannya dari [Ali bin Zaid] dari dari [Ya'qub As Sadusi], dari [Abdullah bin Amru], dari Nabi shallallahu 'alaihi wasallam.\" Dan perkataan Zaid dan Abu Musa seperti hadits Nabi shallallahu 'alaihi wasallam dan hadits Umar radliallahu 'anhu.\""},"3820":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَقَضَى عُمَرُ فِي شِبْهِ الْعَمْدِ ثَلَاثِينَ حِقَّةً وَثَلَاثِينَ جَذَعَةً وَأَرْبَعِينَ خَلِفَةً مَا بَيْنَ ثَنِيَّةٍ إِلَى بَازِلِ عَامِهَا","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] ia berkata, \" [Umar] memberi putusan bahwa pembunuhan semi sengaja diyatnya adalah tiga puluh hiqqah, ditambah tiga puluh jadz'ah dan empat puluh khalifah dari unta yang umurnya antara enam hingga sembilan tahun.\""},"3821":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ قَالَ فِي شِبْهِ الْعَمْدِ أَثْلَاثٌ ثَلَاثٌ وَثَلَاثُونَ حِقَّةً وَثَلَاثٌ وَثَلَاثُونَ جَذَعَةً وَأَرْبَعٌ وَثَلَاثُونَ ثَنِيَّةً إِلَى بَازِلِ عَامِهَا وَكُلُّهَا خَلِفَةٌ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Ashim bin Dhamrah] dari [Ali radliallahu 'anhu] Bahwasanya ia pernah berkata; \"tentang diyat pembunuhan semi sengaja (pembunuhan tidak sengaja menyerupai sengaja) adalah sepertiga, sepertiga yaitu, tiga puluh tiga unta yang berumur tiga tahun dan masuk tahun keempat, dan tiga puluh tiga unta betina yang berumur lima tahun, serta tiga puluh empat unta hamil yang berumur enam tahun hingga umur sembilan tahun.\""},"3822":{"ar":"وَبِهِ عَنْ أَبِي إِسْحَقَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَ عَبْدُ اللَّهِفِي شِبْهِ الْعَمْدِ خَمْسٌ وَعِشْرُونَ حِقَّةً وَخَمْسٌ وَعِشْرُونَ جَذَعَةً وَخَمْسٌ وَعِشْرُونَ بَنَاتِ لَبُونٍ وَخَمْسٌ وَعِشْرُونَ بَنَاتِ مَخَاضٍ","id":"dengan sanad itu juga, dari [Abu Ishaq] dari [Alqamah] dan [Al Aswad], [Abdullah] berkata tentang diyat pembunuhan semi sengaja, \"Dua puluh lima hiqqah, di tambah dua puluh lima jadz'ah, ditambah dua puluh lima bintu labun dan dua puluh lima bintu makhadh.\""},"3823":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُفِي الْخَطَإِ أَرْبَاعًا خَمْسٌ وَعِشْرُونَ حِقَّةً وَخَمْسٌ وَعِشْرُونَ جَذَعَةً وَخَمْسٌ وَعِشْرُونَ بَنَاتِ لَبُونٍ وَخَمْسٌ وَعِشْرُونَ بَنَاتِ مَخَاضٍ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Sufyan] dari [Abu Ishaq] dari [Ashim bin Dhamrah] ia berkata, \" [Ali radliallahu 'anhu] berkata tentang diyat pembunuhan tidak sengaja, \"Yakni seperempat, seperempat; dua puluh lima hiqqah, di tambah dua puluh lima jadz'ah, ditambah dua puluh lima bintu labun dan dua puluh lima bintu makhadh.\""},"3824":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عَبْدِ رَبِّهِ عَنْ أَبِي عِيَاضٍ عَنْ عُثْمَانَ بْنِ عَفَّانَ وَزَيْدِ بْنِ ثَابِتٍفِي الْمُغَلَّظَةِ أَرْبَعُونَ جَذَعَةً خَلِفَةً وَثَلَاثُونَ حِقَّةً وَثَلَاثُونَ بَنَاتِ لَبُونٍ وَفِي الْخَطَإِ ثَلَاثُونَ حِقَّةً وَثَلَاثُونَ بَنَاتِ لَبُونٍ وَعِشْرُونَ بَنُو لَبُونٍ ذُكُورٌ وَعِشْرُونَ بَنَاتِ مَخَاضٍحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي الدِّيَةِ الْمُغَلَّظَةِ فَذَكَرَ مِثْلَهُ سَوَاءً قَالَ أَبُو دَاوُد قَالَ أَبُو عُبَيْدٍ وَغَيْرُ وَاحِدٍ إِذَا دَخَلَتْ النَّاقَةُ فِي السَّنَةِ الرَّابِعَةِ فَهُوَ حِقٌّ وَالْأُنْثَى حِقَّةٌ لِأَنَّهُ يَسْتَحِقُّ أَنْ يُحْمَلَ عَلَيْهِ وَيُرْكَبَ فَإِذَا دَخَلَ فِي الْخَامِسَةِ فَهُوَ جَذَعٌ وَجَذَعَةٌ فَإِذَا دَخَلَ فِي السَّادِسَةِ وَأَلْقَى ثَنِيَّتَهُ فَهُوَ ثَنِيٌّ وَثَنِيَّةٌ فَإِذَا دَخَلَ فِي السَّابِعَةِ فَهُوَ رَبَاعٌ وَرَبَاعِيَةٌ فَإِذَا دَخَلَ فِي الثَّامِنَةِ وَأَلْقَى السِّنَّ الَّذِي بَعْدَ الرَّبَاعِيَةِ فَهُوَ سَدِيسٌ وَسَدَسٌ فَإِذَا دَخَلَ فِي التَّاسِعَةِ وَفَطَرَ نَابُهُ وَطَلَعَ فَهُوَ بَازِلٌ فَإِذَا دَخَلَ فِي الْعَاشِرَةِ فَهُوَ مُخْلِفٌ ثُمَّ لَيْسَ لَهُ اسْمٌ وَلَكِنْ يُقَالُ بَازِلُ عَامٍ وَبَازِلُ عَامَيْنِ وَمُخْلِفُ عَامٍ وَمُخْلِفُ عَامَيْنِ إِلَى مَا زَادَ وَقَالَ النَّضْرُ بْنُ شُمَيْلٍ ابْنَةُ مَخَاضٍ لِسَنَةٍ وَابْنَةُ لَبُونٍ لِسَنَتَيْنِ وَحِقَّةٌ لِثَلَاثٍ وَجَذَعَةٌ لِأَرْبَعٍ وَثَنِيٌّ لَخَمْسٍ وَرَبَاعٌ لِسِتٍّ وَسَدِيسٌ لِسَبْعٍ وَبَازِلٌ لِثَمَانٍ قَالَ أَ��ُو دَاوُد قَالَ أَبُو حَاتِمٍ وَالْأَصْمَعِيُّ وَالْجُذُوعَةُ وَقْتٌ وَلَيْسَ بِسِنٍّ قَالَ أَبُو حَاتِمٍ قَالَ بَعْضُهُمْ فَإِذَا أَلْقَى رَبَاعِيَتَهُ فَهُوَ رَبَاعٌ وَإِذَا أَلْقَى ثَنِيَّتَهُ فَهُوَ ثَنِيٌّ وَقَالَ أَبُو عُبَيْدٍ إِذَا لَقِحَتْ فَهِيَ خَلِفَةٌ فَلَا تَزَالُ خَلِفَةً إِلَى عَشَرَةِ أَشْهُرٍ فَإِذَا بَلَغَتْ عَشَرَةَ أَشْهُرٍ فَهِيَ عُشَرَاءُ قَالَ أَبُو حَاتِمٍ إِذَا أَلْقَى ثَنِيَّتَهُ فَهُوَ ثَنِيٌّ وَإِذَا أَلْقَى رَبَاعِيَتَهُ فَهُوَ رَبَاعٌ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abdu Rabbih] dari [Abu Iyadh] dari [Utsman bin Affan] dan [Zaid bin Tsabit] tentang pembunuhan semi sengaja adalah empat puluh Jadz'ah, tiga puluh hiqqah, dan tiga puluh bintu labun. Sedangkan pembunuhan tidak sengaja adalah tiga puluh hiqqah, tiga puluh bintu labun dan dua puluh banu labun laki-laki dan dua puluh bintu makhadh.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah] berkata, telah menceritakan kepada kami [Said] dari [Qatadah] dari [Sa'id Ibnul Musayyab] dari [Zaid bin Tsabit] tentang tebusan pembunuhan semi sengaja. Lalu beliau menyebutkan persis sebagaimana hadits tersebut.\" Abu Dawud berkata, \"Abu Ubaid dan beberapa orang lainnya menyebutkan, \"Jika umur unta telah masuk pada tahun keempat maka ia disebut hiqqun atau hiqqah, sebab ia telah boleh untuk membawa barang atau ditunggangi. Jika umurnya telah masuk pada tahun kelima, maka ia disebut Jadza' atau jadz'ah. Jika umurnya telah masuk pada tahun keenam dan gigi serinya telah tanggal, maka ia disebut tsaniyun atau tsaniyah. Jika umurnya telah masuk pada tahun ketujuh, maka ia disebut ruba' atau ruba'iyah. Jika umurnya telah masuk pada tahun kedelapan dan gigi setelah gigi gerahamnya telah tanggal, maka ia disebut sadis atau sadas. Jika umurnya telah masuk pada tahun kesembilan dan gigi taringnya telah tanggal namun tumbuh kembali, maka ia disebut dengan bazil. Jika umurnya telah masuk pada tahun kesepuluh, maka ia disebut mukhlif. Dan setelah itu tidak ada lagi penyebutan secara khusus, akan tetapi cukup disebut dengan bazil 'am (bazil lebih setahun) atau bazil 'ammaini (bazil lebih dua tahun), mukhlif 'am (Mukhlif lebih setahun) atau mukhlif 'ammaini (mukhlif lebih dua tahun) dan seterusnya.\" An Nadhr bin Syumail berkata, \"Bintu makhadh untuk unta yang berumur satu tahun, bintu labun untuk unta yang berumur dua tahun, hiqqah untuk unta yang berumur tiga tahun, jadza' untuk unta yang berumur empat tahun, tsaniyun untuk unta yang berumur lima tahun, raba' untuk unta yang berumur enam tahun, sadis untuk unta yang berumur tujuh tahun, dan bazil untuk unta yang berumur delapan tahun.\" Abu Dawud berkata, \"Abu Hatim dan Al Ashma'ie berkata, \"Al Judzu'ah adalah untuk waktu, bukan umur.\" Abu Hatim berkata, \"Sebagian ulama berkata, \"Jika unta tersebut telah tanggal gigi gerahamnya maka ia disebut raba', dan jika gigi serinya telah tanggal maka ia disebut tsaniyun.\" Abu Ubaid berkata, \"Jika ia telah siap menerima seperma maka disebut khalifah, dan hal itu tetap berlangsung hingga berlalu sepuluh bulan. Jika telah lewat sepuluh bulan maka ia disebut dengan 'usyara.\" Abu Hatim berkata, \"Jika telah tanggal gigi serinya maka disebut tsaniyun, dan jika gigi derahamnya telah tanggal maka disebut raba.\""},"3825":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَبْدَةُ يَعْنِي ابْنَ سُلَيْمَانَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ غَالِبٍ التَّمَّارِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ عَشْرٌ عَشْرٌ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il] berkata, telah menceritakan kepada kami [Abdah] -maksudnya Abdah bin Sulaiman- berkata, telah menceritakan kepada kami [Said bin Abu Arubah] dari [Ghalib At Tammar] dari [Humaid bin Hilal] dari [Masruq bin Aus] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Semua jari diyatnya sama; puluh ekor unta.\""},"3826":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ غَالِبٍ التَّمَّارِ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ قُلْتُ عَشْرٌ عَشْرٌ قَالَ نَعَمْقَالَ أَبُو دَاوُد رَوَاهُ مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ غَالِبٍ قَالَ سَمِعْتُ مَسْرُوقَ بْنَ أَوْسٍ وَرَوَاهُ إِسْمَعِيلُ قَالَ حَدَّثَنِي غَالِبٌ التَّمَّارُ بِإِسْنَادِ أَبِي الْوَلِيدِ وَرَوَاهُ حَنْظَلَةُ بْنُ أَبِي صَفِيَّةَ عَنْ غَالِبٍ بِإِسْنَادِ إِسْمَعِيلَ","id":"Telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ghalib At Tammar] dari [Masruq bin Aus] dari [Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jemari itu diyatnya sama.\" Aku bertanya, \"Setiap jari sepuluh ekor unta?\" beliau menjawab: \"Ya.\" Abu Dawud berkata, \" [Muhammad bin Ja'far] meriwayatkannya dari [Syu'bah], dari [Ghalib], ia berkata, \"aku mendengar [Masruq bin Aus].\" [Isma'il] juga meriwayatkannya, ia berkata, \" [Ghalib At Tammar] menceritakan kepadaku dengan sanad Abu Al Walid.\" Dan [Hanzhalah bin Abu Shafiah] juga meriwayatkan dari [Ghalib] dengan sanad Isma'il.\""},"3827":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ كُلُّهُمْ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ وَهَذِهِ سَوَاءٌ يَعْنِي الْإِبْهَامَ وَالْخِنْصَرَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Mu'adz] berkata, telah menceritakan kepada kami [Bapakku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah mengabarkan kepada kami [Yazid bin Zurai'] semuanya dari [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini dengan ini (tebusannya) sama, yakni ibu jari dengan jari kelingking.\""},"3828":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ وَالْأَسْنَانُ سَوَاءٌ الثَّنِيَّةُ وَالضِّرْسُ سَوَاءٌ هَذِهِ وَهَذِهِ سَوَاءٌقَالَ أَبُو دَاوُد وَرَوَاهُ النَّضْرُ بْنُ شُمَيْلٍ عَنْ شُعْبَةَ بِمَعْنَى عَبْدِ الصَّمَدِ قَالَ أَبُو دَاوُد حَدَّثَنَاه الدَّارِمِيُّ عَنْ النَّضْرِ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari] berkata, telah menceritakan kepada kami [Abdu Ash Shammad bin Abdul Warits] berkata, telah menceritakan kepadaku [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua jari itu sama (diyatnya), semua gigi sama (diyatnya), gigi seri dan gigi geraham sama, serta ini dan ini diyatnya sama.\" Abu Dawud berkata, \" [An Nadhr bin Syumail] meriwayatkannya dari [Syu'bah] dengan makna [Abdu Ash Shamad].\" Abu Dawud berkata lagi, \" [Ad Darimi] meriwayatkan kepada kami dari [An Nadhr].\""},"3829":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ أَخْبَرَنَا أَبُو حَمْزَةَ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَسْنَانُ سَوَاءٌ وَالْأَصَابِعُ سَوَاءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'] berkata, telah menceritakan kepada kami [Ali Ibnul hasan] berkata, telah mengabarkan kepada kami [Abu Hamzah] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua gigi sama diyatnya, dan semua jari jemari sama diyatnya.\""},"3830":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ مُحَمَّدِ بْنِ أَبَانَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابِعَ الْيَدَيْنِ وَالرِّجْلَيْنِ سَوَاءً","id":"Telah menceritakan kepada kami [Abdullah bin Umar bin Muhammad bin Aban] berkata, telah menceritakan kepada kami [Abu Tumailah] dari [Husain Al Muallim] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menjadikan diyat kedua tangan dan kedua kaki sama.\""},"3831":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي خُطْبَتِهِ وَهُوَ مُسْنِدٌ ظَهْرَهُ إِلَى الْكَعْبَةِ فِي الْأَصَابِعِ عَشْرٌ عَشْرٌ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda dalam pidatonya -sambil menyandarkan punggungnya ke Ka'bah-: \"(setiap) Jemari tangan diyatnya adalah sepuluh (unta).\""},"3832":{"ar":"قَالَ أَبُو دَاوُد وَجَدْتُ فِي كِتَابِي عَنْ شَيْبَانَ وَلَمْ أَسْمَعْهُ مِنْهُ فَحَدَّثَنَاهُ أَبُو بَكْرٍ صَاحِبٌ لَنَا ثِقَةٌ قَالَ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ رَاشِدٍ عَنْ سُلَيْمَانَ يَعْنِي ابْنَ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَوِّمُ دِيَةَ الْخَطَإِ عَلَى أَهْلِ الْقُرَى أَرْبَعَ مِائَةِ دِينَارٍ أَوْ عَدْلَهَا مِنْ الْوَرِقِ وَيُقَوِّمُهَا عَلَى أَثْمَانِ الْإِبِلِ فَإِذَا غَلَتْ رَفَعَ فِي قِيمَتِهَا وَإِذَا هَاجَتْ رُخْصًا نَقَصَ مِنْ قِيمَتِهَا وَبَلَغَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ أَرْبَعِ مِائَةِ دِينَارٍ إِلَى ثَمَانِ مِائَةِ دِينَارٍ وَعَدْلُهَا مِنْ الْوَرِقِ ثَمَانِيَةُ آلَافِ دِرْهَمٍ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ الْبَقَرِ مِائَتَيْ بَقَرَةٍ وَمَنْ كَانَ دِيَةُ عَقْلِهِ فِي الشَّاءِ فَأَلْفَيْ شَاةٍ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَقْلَ مِيرَاثٌ بَيْنَ وَرَثَةِ الْقَتِيلِ عَلَى قَرَابَتِهِمْ فَمَا فَضَلَ فَلِلْعَصَبَةِ قَالَ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَنْفِ إِذَا جُدِعَ الدِّيَةَ كَامِلَةً وَإِذَا جُدِعَتْ ثَنْدُوَتُهُ فَنِصْفُ الْعَقْلِ خَمْسُونَ مِنْ الْإِبِلِ أَوْ عَدْلُهَا مِنْ الذَّهَبِ أَوْ الْوَرِقِ أَوْ مِائَةُ بَقَرَةٍ أَوْ أَلْفُ شَاةٍ وَفِي الْيَدِ إِذَا قُطِعَتْ نِصْفُ الْعَقْلِ وَفِي الرِّجْلِ نِصْفُ الْعَقْلِ وَفِي الْمَأْمُومَةِ ثُلُثُ الْعَقْلِ ثَلَاثٌ وَثَلَاثُونَ مِنْ الْإِبِلِ وَثُلُثٌ أَوْ قِيمَتُهَا مِنْ الذَّهَبِ أَوْ الْوَرِقِ أَوْ الْبَقَرِ أَوْ الشَّاءِ وَالْجَائِفَةُ مِثْلُ ذَلِكَ وَفِي الْأَصَابِعِ فِي كُلِّ أُصْبُعٍ عَشْرٌ مِنْ الْإِبِلِ وَفِي الْأَسْنَانِ فِي كُلِّ سِنٍّ خَمْسٌ مِنْ الْإِبِلِ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ عَقْلَ الْمَرْأَةِ بَيْنَ عَصَبَتِهَا مَنْ كَانُوا لَا يَرِثُونَ مِنْهَا شَيْئًا إِلَّا مَا فَضَلَ عَنْ وَرَثَتِهَا وَإِنْ قُتِلَتْ فَعَقْلُهَا بَيْنَ وَرَثَتِهَا وَهُمْ يَقْتُلُونَ قَاتِلَهُمْ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لِلْقَاتِلِ شَيْءٌ وَإِنْ لَمْ يَكُنْ لَهُ وَارِثٌ فَوَارِثُهُ أَقْرَبُ النَّاسِ إِلَيْهِ وَلَا يَرِثُ الْقَاتِلُ شَيْئًاقَالَ مُحَمَّدٌ هَذَا كُلُّهُ حَدَّثَنِي بِهِ سُلَيْمَانُ بْنُ مُوسَى عَنْ عَمْر��و بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد مُحَمَّدُ بْنُ رَاشِدٍ مِنْ أَهْلِ دِمَشْقَ هَرَبَ إِلَى الْبَصْرَةِ مِنْ الْقَتْلِ","id":"Abu Dawud berkata, \"Aku mendapatkan dalam bukuku; dari [Syaiban] -namun aku belum pernah mendengarnya darinya- [Abu Bakr] -sahabat kami yang terpercaya- mengabarkannya kepada kami, ia berkata; telah menceritakan kepada kami [Muhammad] -maksudnya Muhammad bin Rasyid- dari [Sulaiman] -maksudnya Sulaiman bin Musa- dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa diyatnya pembunuh yang tidak sengaja bagi penduduk kampung adalah empat ratus dinar, atau dirham yang sebanding, serta menetapkan sesuai dengan harga unta. Jika harga unta naik maka beliau menaikkan nilainya dan jika turun maka beliau menurunkan nilainya. Sehingga, diyat pada masa Rasulullah shallallahu 'alaihi wasallam berkisar antara empat ratus dinar hingga delapan ratus dinar, atau sebanding dengan delapan ribu dirham. Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa bagi pemilik sapi dendanya adalah dua ratus ekor sapi, jika diyat itu dibayarkan berupa kambing maka dengan dua ribu ekor kambing.\" Ia (perawi) berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tebusan diyat adalah harta warisan untuk semua ahli waris korban untuk dibagi dengan kerabatnya, jika sisa maka itu untuk ashabah (orang-orang yang mendapatkan bagian sisa dalam warisan).\" Ia (perawi) berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan pada hidung bahwa; jika dipotong maka dendanya adalah diyat secara sempurna, jika hanya ujungnya maka diyatnya setengahnya, yaitu lima puluh ekor unta, atau nilai yang sebanding dengannya baik itu emas atau perak. Atau dengan seratus sapi atau seribu kambing. Dan jika tangan dipotong, maka dendanya adalah setengah diyat, pada kaki dendanya setengah diyat, muka sepertiga diyat; tiga puluh tiga unta dan sepertiga atau yang senilai baik itu berupa emas atau perak. Atau sapi, atau kambing, dan pada rongga juga seperti itu pula. Pada jemari, maka setiap jarinya adalah sepuluh unta, dan setiap gigi adalah lima unta. Rasulullah shallallahu 'alaihi wasallam juga telah menetapkan bahwa diyat yang harus ditanggung oleh seorang wanita ditanggung oleh para ashabahnya (wanita), yaitu kelompok orang yang tidak mendapatkan harta waris kecuali sisa dari ahli warinya. Jika ia dibunuh maka diyatnya bagi ahli warisnya atau mereka membunuh pembunuhnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembunuh tidak mendapatkan apa-apa, jika ia tidak mempunyai ahli waris, maka warisannya jatuh kepada orang yang paling dekat dengannya, dan bagi pembunuh tidak mendapatkan warisan sedikitpun.\" Muhammad berkata, \"Semua riwayat itu diceritakan kepadaku oleh Sulaiman bin Musa dari Amru bin Syu'aib, dari bapaknya, dari kakeknya, dari Nabi shallallahu 'alaihi wasallam.\" Abu Dawud berkata, \"Muhammad bin rasyid berasal dari Damaskus, ia melarikan diri ke Bashrah untuk menghindari pembunuhan.\""},"3833":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ بِلَالٍ الْعَامِلِيُّ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ رَاشِدٍ عَنْ سُلَيْمَانَ يَعْنِي ابْنَ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَقْلُ شِبْهِ الْعَمْدِ مُغَلَّظٌ مِثْلُ عَقْلِ الْعَمْدِ وَلَا يُقْتَلُ صَاحِبُهُقَالَ وَزَادَنَا خَلِيلٌ عَنْ ابْنِ رَاشِدٍ وَذَلِكَ أَنْ يَنْزُوَ الشَّيْطَانُ بَيْنَ النَّاسِ فَتَكُونُ دِمَاءٌ فِي عِمِّيَّا فِي غَيْرِ ضَغِينَةٍ وَلَا حَمْلِ سِلَاحٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Muhammad bin Bakkar bin Bilal Al 'Amili] berkata, telah mengabarkan kepada kami [Muhammad] -maksudnya Muhammad bin Rasyid- dari [Sulaiman] -maksudnya Sulaiman bin Musa- dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"tebusan (diyat) untuk pembunuhan semi sengaja diperberat seperti pembunuhan sengaja, namun pembunuhnya tidak dibunuh -Abu Dawud berkata; Kahlil menambahkan dari Ibnu Rasyid- \"Sebab hal itu akan membantu setan dalam menguasai manusia, hingga hukum darahnya itu adalah seperti pembunuhan yang dilakukan dalam kegelapan (tidak tahu siapa pembunuh dan bagaimana membunuhnya), bukan karena permusuhan atau peperangan.\""},"3834":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ أَنَّ خَالِدَ بْنَ الْحَارِثِ حَدَّثَهُمْ قَالَ أَخْبَرَنَا حُسَيْنٌ يَعْنِي الْمُعَلِّمَ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْمَوَاضِحِ خَمْسٌ","id":"Telah menceritakan kepada kami [Abu Kamil Fudhail bin Husain] bahwa [Khalid Ibnul Harits] menceritakan kepada mereka, ia berkata; telah mengabarkan kepada kami [Husain] -maksudnya Husain Al Mu'allim- dari [Amru bin Syu'aib] bahwa [Bapaknya] mengabarkan kepadanya dari [Abdullah bin Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diyat untuk tiap gigi yang nampak saat tertawa adalah lima (ekor unta).\""},"3835":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نَضْلَةَ عَنْ الْمُغِيَرةِ بْنِ شُعْبَةَأَنَّ امْرَأَتَيْنِ كَانَتَا تَحْتَ رَجُلٍ مِنْ هُذَيْلٍ فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِعَمُودٍ فَقَتَلَتْهَا وَجَنِينَهَا فَاخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُ الرَّجُلَيْنِ كَيْفَ نَدِي مَنْ لَا صَاحَ وَلَا أَكَلَ وَلَا شَرِبَ وَلَا اسْتَهَلَّ فَقَالَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ فَقَضَى فِيهِ بِغُرَّةٍ وَجَعَلَهُ عَلَى عَاقِلَةِ الْمَرْأَةِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ بِإِسْنَادِهِ وَمَعْنَاهُ وَزَادَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةَ الْمَقْتُولَةِ عَلَى عَصَبَةِ الْقَاتِلَةِ وَغُرَّةً لِمَا فِي بَطْنِهَا قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ الْحَكَمُ عَنْ مُجَاهِدٍ عَنْ الْمُغِيرَةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] berkata, telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Ubaid bin Nadhlah] dari [Al Mughirah bin Syu'bah] berkata, \"Ada dua orang wanita yang menjadi isteri seorang laki-laki Hudzail, lalu salah seorang dari isteri itu memukul isteri yang lainnya hingga tewas beserta janin yang ada di perutnya. Akhirnya mereka mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam, seorang dari dua laki-laki berkata, \"Bagaimana kami harus menebus diyat bagi jiwa yang belum lahir dari perut ibunya, belum makan, belum minum dan belum menangis!\" Beliau lalu menjawab: \"Apakah ini sajak seperti sajak orang-orang Arab badui?\" Beliau kemudian menetapkan diyatnya berupa pembebasan seorang budak yang ditanggung oleh wali wanita (pembunuh) tersebut.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [jarir] dari [Manshur] dengan sanad dan maknanya, ia menambahkan, \"Nabi shallallahu 'alaihi wasallam lalu menetapkan bahwa tebusan bagi wanita yang dibunuh itu ditanggung oleh keluarga wanita (yang membunuh), dan membebaskan budak sebagai diyat dari janin yang ada dalam perut.\" Abu Dawud berkata, \" [Al Hakam] juga meriwayatkannya dari [Mujahid] dari [Al Mughirah].\""},"3836":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَارُونُ بْنُ عَبَّادٍ الْأَزْدِيُّ الْمَعْنَى قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ عُمَرَ اسْتَشَارَ النَّاسَ فِي إِمْلَاصِ الْمَرْأَةِ فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِيهَا بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ فَقَالَ ائْتِنِي بِمَنْ يَشْهَدُ مَعَكَ فَأَتَاهُ بِمُحَمَّدِ بْنِ مَسْلَمَةَ زَادَ هَارُونُ فَشَهِدَ لَهُ يَعْنِي ضَرْبَ الرَّجُلِ بَطْنَ امْرَأَتِهِقَالَ أَبُو دَاوُد بَلَغَنِي عَنْ أَبِي عُبَيْدٍ إِنَّمَا سُمِّيَ إِمْلَاصًا لِأَنَّ الْمَرْأَةَ تُزْلِقُهُ قَبْلَ وَقْتِ الْوِلَادَةِ وَكَذَلِكَ كُلُّ مَا زَلَقَ مِنْ الْيَدِ وَغَيْرِهِ فَقَدْ مَلِصَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ عَنْ عُمَرَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد رَوَاهُ حَمَّادُ بْنُ زَيْدٍ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ عُمَرَ قَالَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Harun bin Abbad Al Azdi] secara makna, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Urwah] dari [Al Miswar bin Makhramah] berkata, \"Umar bermusyawah dengan orang-orang tentang hukum penguguran janin dalam perut wanita. Maka [Al Mughirah bin Syu'bah] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memberi putusan dalam hal itu dengan membebaskan seorang budak; laki-laki atau perempuan.\" Umar berkata, \"Datangkanlah kepadaku saksi yang pernah ikut bersamamu.\" Maka Al Mughirah menghadirkan [Muhammad bin Maslamah].\" [Harun] menambahkan, \"Lalu ia memberikan bukti dengan kisah seorang laki-laki yang memukul perut isterinya.\" Abu Dawud berkata, \"Telah sampai kepadaku dari Abu Ubaid bahwa dinamakan penguguran karena seorang wanita melahirkan (menjatuhkan dengan paksa) sebelum waktu kelahirannya.\", Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Hisyam] dari [Bapaknya] dari [Al Mughirah] dari Umar secara makna. Abu Dawud berkata, \" [Hammad bin Zaid] dan [Hammad bin Salamah] meriwayatkannya dari [Hisyam bin Urwah], dari [bapaknya], bahwa Umar berkata. "},"3837":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَسْعُودٍ الْمِصِّيصِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ طَاوُسًا عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَأَنَّهُ سَأَلَ عَنْ قَضِيَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَقَامَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ فَقَالَ كُنْتُ بَيْنَ امْرَأَتَيْنِ فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِمِسْطَحٍ فَقَتَلَتْهَا وَجَنِينَهَا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِهَا بِغُرَّةٍ وَأَنْ تُقْتَلَقَالَ أَبُو دَاوُد قَالَ النَّضْرُ بْنُ شُمَيْلٍ الْمِسْطَحُ هُوَ الصَّوْبَجُ قَالَ أَبُو دَاوُد و قَالَ أَبُو عُبَيْدٍ الْمِسْطَحُ عُودٌ مِنْ أَعْوَادِ الْخِبَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ طَاوُسٍ قَالَ قَامَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَلَى الْمِنْبَرِ فَذَكَرَ مَعْنَاهُ لَمْ يَذْكُرْ وَأَنْ تُقْتَلَ زَادَ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ قَالَ فَقَالَ عُمَرُ اللَّهُ أَكْبَرُ لَوْ لَمْ أَسْمَعْ بِهَذَا لَقَضَيْنَا بِغَيْرِ هَذَا حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ التَّمَّارُ أَنَّ عَمْرَو بْنَ طَلْحَةَ حَدَّثَهُمْ قَالَ حَدَّثَنَا أَسْبَاطٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ فِي قِصَّةِ حَمَلِ بْنِ مَالِكٍ قَالَ فَأَسْقَطَتْ غُلَامًا قَدْ نَبَتَ شَعْرُهُ مَيِّتًا وَمَاتَتْ الْمَرْأَةُ فَقَضَى عَلَى الْعَاقِلَةِ الدِّيَةَ فَقَالَ عَمُّهَا إِنَّهَا قَدْ أَسْقَطَتْ يَا نَبِيَّ اللَّهِ غُلَامًا قَدْ نَبَتَ شَعْرُهُ فَقَالَ أَبُو الْقَاتِلَةِ إِنَّهُ كَاذِبٌ إِنَّهُ وَاللَّهِ مَا اسْتَهَلَّ وَلَا شَرِبَ وَلَا أَكَلَ فَمِثْلُهُ يُطَلُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَجْعَ الْجَاهِلِيَّةِ وَكَهَانَتَهَا أَدِّ فِي الصَّبِيِّ غُرَّةً قَالَ ابْنُ عَبَّاسٍ كَانَ اسْمُ إِحْدَاهُمَا مُلَيْكَةَ وَالْأُخْرَى أُمَّ غُطَيْفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mas'ud Al Mishishi] berkata, telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Amru bin dinar] bahwa ia mendengar [Thawus] dari [Ibnu Abbas] dari [Umar] bahwa ia bertanya tentang keputusan Nabi shallallahu 'alaihi wasallam dalam urusan tersebut. [Haml bin Malik bin An Nabighah] lalu bangkit dan berkata, \"Aku mempunyai dua isteri, lalu salah seorang dari keduanya memukul yang lain dengan tongkat hingga membunuhnya berserta janin yang ada dalam perutnya. Rasulullah shallallahu 'alaihi wasallam kemudian memberi putusan bahwa tebusan bagi janinnya adalah dengan membebaskan seorang budak, sementara wanita itu dibunuh.\" Abu Dawud berkata, \"An Nadhr bin Syumail berkata, \"Al Misthah adalah Ash Shaubaj (semacam alat untuk meratakan tanah), \" Abu Dawud berkata lagi, \"Abu Ubaid berkata, \"Al Misthah adalah katu untuk meyangga kemah.\" Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri] berkata, telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Thawus] ia berkata, \"Umar berdiri di atas mimbar…lalu ia menyebutkan sebagaimana hadits tersebut secara makna. Namun ia tidak menyebutkan, \"dan wanita itu harus dibunuh.\" Ia (sufyan) menambahkan, \"Dengan memberikan budak laki-laki atau perempuan.\" Ia berkata, \"Umar lalu berkata, \"Allah Maha Besar, sekiranya aku tidak mendengar ini, sungguh pasti aku akan memberi keputusan dengan yang selain ini.\" Telah menceritakan kepada kami [Sulaiman bin 'Abdurrahman At Tammar] bahwa [Amru bin Thalhah] menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [Asbath] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] berkenaan dengan kisah [Haml bin Malik] ia berkata, \"Wanita itu lalu melahirkan (keguguran) janin yang rambutnya telah tumbuh, janin itu meninggal sebagaimana ia juga meninggal. Rasulullah shallallahu 'alaihi wasallam kemudian memberi keputusan bahwa wali (pembunuh) harus memberikan diyat. Lalu paman (wanita yang keguguran lalu meninggal) itu berkata, \"Wahai Nabi Allah, ia itu telah melahirkan bayi yang rambutnya telah tumbuh dalam keadaan meninggal!\" lalu ayah wanita yang membunuh berkata, \"Dia dusta! Demi Allah, belum menangis, belum minum, dan belum makan. Maka (membayar dendanya) adalah kesia-siaan.\" Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Apakah ini sajak jahilliyah dan perdukunannya. Bayarlah denda janin itu dengan memberikan seorang budak.\" [Ibnu Abbas] berkata, \"Wanita itu bernama Mulaikah dan yang lainnya bernama Ummu Ghuthaif.\""},"3838":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مُجَالِدٌ قَالَ حَدَّثَنَا الشَّعْبِيُّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ امْرَأَتَيْنِ مِنْ هُذَيْلٍ قَتَلَتْ إِحْدَاهُمَا الْأُخْرَى وَلِكُلِّ وَاحِدَةٍ مِنْهُمَا زَوْجٌ وَوَلَدٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةَ الْمَقْتُولَةِ عَلَى عَاقِلَةِ الْقَاتِلَةِ وَبَرَّأَ زَوْجَهَا وَوَلَدَهَا قَالَ فَقَالَ عَاقِلَةُ الْمَقْتُولَةِ مِيرَاثُهَا لَنَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا مِيرَاثُهَا لِزَوْجِهَا وَوَلَدِهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Mujalid] ia berkata; telah menceritakan kepada kami [Asy Sya'bi] dari [Jabir bin Abdullah] berkata, \"Dua orang wanita dari Hudzail, salah seorang dari keduanya membunuh wanita yang lainnya. Setiap dari wanita tersebut telah mempunyai suami dan anak. Rasulullah shallallahu 'alaihi wasallam kemudian memberi keputusan bahwa wanita yang terbunuh itu dendanya harus dibayar oleh wali dari wanita yang membunuhnya. Dan membebaskan suami serta anaknya.\" Jabir bin Abdullah berkata, \"Wali wanita yang terbunuh itu berkata, \"Harta warisanya untuk kami.\" Jabir bin Abdullah berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Tidak, warisannya untuk suami dan anaknya.\""},"3839":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَيَانٍ وَابْنُ السَّرْحِ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَاقْتَتَلَتْ امْرَأَتَانِ مِنْ هُذَيْلٍ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَقَتَلَتْهَا فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةَ جَنِينِهَا غُرَّةَ عَبْدٍ أَوْ وَلِيدَةٍ وَقَضَى بِدِيَةِ الْمَرْأَةِ عَلَى عَاقِلَتِهَا وَوَرَّثَهَا وَلَدَهَا وَمَنْ مَعَهُمْ فَقَالَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ الْهُذَلِيُّ يَا رَسُولَ اللَّهِ كَيْفَ أُغْرَمُ دِيَةَ مَنْ لَا شَرِبَ وَلَا أَكَلَ لَا نَطَقَ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذَا مِنْ إِخْوَانِ الْكُهَّانِ مِنْ أَجْلِ سَجْعِهِ الَّذِي سَجَعَحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ فِي هَذِهِ الْقِصَّةِ قَالَ ثُمَّ إِنَّ الْمَرْأَةَ الَّتِي قَضَى عَلَيْهَا بِالْغُرَّةِ تُوُفِّيَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَنَّ مِيرَاثَهَا لِبَنِيهَا وَأَنَّ الْعَقْلَ عَلَى عَصَبَتِهَا","id":"Telah menceritakan kepada kami [Wahb bin Bayan] dan [Ibnu As Sarh] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Dua orang wanita dari Hudzail saling bunuh, kemudian salah seorang dari mereka memlempar yang lainnya dengan batu hingga tewas. Maka orang-orang mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam memberi keputusan bahwa diyat bagi janin tersebut adalah budak laki-laki atau perempuan, dan menetapkan bahwa diyat bagi wanita itu harus dibayar oleh para ahli waris atau anak berserta orang-orang yang bergabung dengan mereka.\" Haml bin Malik bin An Nabighah Al Hudzli berkata, \"Wahai Rasulullah, bagaimana aku harus membayar diyat seseorang yang belum minum, belum makan, belum berbicara dan belum menangis? Apa semacam itu tidak memberatkan?\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Orang ini termasuk kawan-kawan dukun. Hal itu karena ungkapan yang ia katakan.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Ibnul Musayyab] dari [Abu Hurairah] berkenaan dengan kisah dalam hadits tersebut, ia berkata, \"Kemudian wanita yang diberi putusan untuk membayar dengan seorang budak meninggal, maka Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa harta warisannya diberikan kepada anak-anaknya, sedangkan denda itu kepada ashabahnya (ahli waritsnya yang terdekat yang mendapatkan sisa warisan).\""},"3840":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا يُوسُفُ بْنُ صُهَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ امْرَأَةً خَذَفَتْ امْرَأَةً فَأَسْقَطَتْ فَرُفِعَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ فِي وَلَدِهَا خَمْسَ مِائَةِ شَاةٍ وَنَهَى يَوْمَئِذٍ عَنْ الْخَذْفِقَالَ أَبُو دَاوُد كَذَا الْحَدِيثُ خَمْسَ مِائَةِ شَاةٍ وَالصَّوَابُ مِائَةُ شَاةٍ قَالَ أَبُو دَاوُد هَكَذَا قَالَ عَبَّاسٌ وَهُوَ وَهْمٌ","id":"Telah menceritakan kepada kami [Abbas bin Abdul Azhim] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah menceritakan kepada kami [Yusuf bin Shuhaib] dari [Abdullah bin Buraidah] dari [Bapaknya] berkata, \"Seorang wanita melempar wanita lain hingga bayi yang ada dalam perutnya keguguran. Maka hal itu kemudian disampaikan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memutuskan bahwa diyat bagi bayinya adalah lima ratus kambing. Kemudian saat itu pula beliau melarang untuk melempar.\" Abu Dawud berkata, \"Demikianlah, hadits tersebut menyebutkan lima ratus ekor kambing, padahal yang benar adalah seratus kambing.\" Abu Dawud melanjutkan, \"Demikianlah, Abbas mengatakan bahwa itu (riwayat yang menyebutkan lima ratus kambing) adalah riwayat yang masih diragukan.\""},"3841":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا عِيسَى عَنْ مُحَمَّدٍ يَعْنِي ابْنَ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنِينِ بِغُرَّةِ عَبْدٍ أَوْ أَمَةٍ أَوْ فَرَسٍ أَوْ بَغْلٍقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ حَمَّادُ بْنُ سَلَمَةَ وَخَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو لَمْ يَذْكُرَا أَوْ فَرَسٍ أَوْ بَغْلٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] berkata, telah menceritakan kepada kami [Isa] dari [Muhammad] -maksudnya Muhammad bin Amru- dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa diyat bagi janin adalah senilai budak laki-laki, atau perempuan, atau kuda, atau bighal.\" Abu Dawud berkata, \" [Hammad bin Salamah] dan [Khalid bin Abdullah] meriwayatkan hadits ini dari [Muhammad bin Amru], namun keduanya tidak menyebutkan 'kuda atau bighal'.\""},"3842":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ الْعَوَقِيُّ حَدَّثَنَا شَرِيكٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ وَجَابِرٍ عَنْ الشَّعْبِيِّ قَالَالْغُرَّةُ خَمْسُ مِائَةِ دِرْهَمٍقَالَ أَبُو دَاوُد قَالَ رَبِيعَةُ الْغُرَّةُ خَمْسُونَ دِينَارًا","id":"Telah menceritakan kepada kami [Muhammad bin Sinan Al 'Awaqi] berkata, telah menceritakan kepada kami [Syarik] dari [Mughirah] dari [Ibrahim] dan [Jabir] dari [Asy Sya'bi] berkata, \"ghurrah (terbusan memerdekakan budak) sama nilainya dengan lima ratus dirham.\" Abu Dawud berkata, \"Rabi'ah menyebutkan, \"ghurrah (tebusan memerdekakan budak) sama nilainya dengan lima puluh dinar.\""},"3843":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ و حَدَّثَنَا إِسْمَعِيلُ عَنْ هِشَامٍ و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا حَجَّاجٌ الصَّوَّافُ جَمِيعًا عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دِيَةِ الْمُكَاتَبِ يُقْتَلُ يُودَى مَا أَدَّى مِنْ مُكَاتَبَتِهِ دِيَةَ الْحُرِّ وَمَا بَقِيَ دِيَةَ الْمَمْلُوكِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan Telah menceritakan kepada kami [Isma'il] dari [Hisyam] dan Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ya'la bin Ubaid] berkata, telah menceritakan kepada kami [Hajjaj Ash Shawwaf] semuanya dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keputusan bahwa diyat Mukatib (budak yang ingin menebus dirinya supaya merdeka) yang terbunuh adalah dibayar sesuai dengan uang yang telah ia berikan untuk menebus kebebasan dirinya, dan selebihnya adalah diyat sebagai seorang budak.\""},"3844":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَصَابَ الْمُكَاتَبُ حَدًّا أَوْ وَرِثَ مِيرَاثًا يَرِثُ عَلَى قَدْرِ مَا عَتَقَ مِنْهُقَالَ أَبُو دَاوُد رَوَاهُ وُهَيْبٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرْسَلَهُ حَمَّادُ بْنُ زَيْدٍ وَإِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعَلَهُ إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَوْلَ عِكْرِمَةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak Mukatab (budak yang ingin menebus dirinya supaya merdeka) mendapatkan hukuman had, atau mewarisi harta warisan, maka ia menerima warisannya sesuai dengan harga kebebasan dirinya dari perbudakan.\" Abu Dawud berkata, \" [Wuhaib] meriwayatkannya dari [Ayyub], dari [Ikrimah], dari [Ali] dari Nabi shallallahu 'alaihi wasallam. [Hammad bin Zaid] dan [Isma'il] memursalkannya dari [Ayyub], dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam. Dan Isma'il bin Ulayyah memposisikan bahwa itu adalah ucapan Ikrimah.\""},"3845":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دِيَةُ الْمُعَاهِدِ نِصْفُ دِيَةِ الْحُرِّقَالَ أَبُو دَاوُد رَوَاهُ أُسَامَةُ بْنُ زَيْدٍ اللَّيْثِيُّ وَعَبْدُ الرَّحْمَنِ بْنُ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Mauhab Ar Ramli] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Muhammad bin Ishaq] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Diyat budak itu setengah dari diyat orang yang mereka.\" Abu Dawud berkata, \" [Usamah bin Zaid Al Laitsi] dan ['Abdurrahman Ibnul Harits] meriwayatkannya dari [Amru bin Syu'aib] seperti ini.\""},"3846":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَقَاتَلَ أَجِيرٌ لِي رَجُلًا فَعَضَّ يَدَهُ فَانْتَزَعَهَا فَنَدَرَتْ ثَنِيَّتُهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْدَرَهَا وَقَالَ أَتُرِيدُ أَنْ يَضَعَ يَدَهُ فِي فِيكَ تَقْضِمُهَا كَالْفَحْلِقَالَ وَأَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ جَدِّهِ أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ أَهْدَرَهَا وَقَالَ بَعِدَتْ سِنُّهُ حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ أَخْبَرَنَا هُشَيْمٌ حَدَّثَنَا حَجَّاجٌ وَعَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ يَعْلَى بْنِ أُمَيَّةَ بِهَذَا زَادَ ثُمَّ قَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَاضِّ إِنْ شِئْتَ أَنْ تُمَكِّنَهُ مِنْ يَدِكَ فَيَعَضُّهَا ثُمَّ تَنْزِعُهَا مِنْ فِيهِ وَأَبْطَلَ دِيَةَ أَسْنَانِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Atha] dari [Shafwan bin Ya'la] dari [Bapaknya] ia berkata, \"Seorang pekerjaku menyerang seorang laki-laki, lalu ia mengigit tangannya. Laki-laki itu menarik tangannya hingga giginya tanggal. Lalu ia mendatangi Nabi shallallahu 'alaihi wasallam, namun beliau tidak menggubrisnya. Beliau bersabda: \"Apakah kamu ingin ia meletakkan tangannya pada mulutmu hingga kamu dapat mengigitnya seperti unta jantan!\" Ia berkata, \"Telah menceritakan kepadaku Ibnu Abu Mulaikah dari Kakeknya bahwa Abu Bakar radliallahu 'anhu tidak menggubrisnya dan berkata, \"Semoga giginya tanggal.\" Telah menceritakan kepada kami [Ziyad bin Ayyub] berkata, telah mengabarkan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Hajjaj] dan [Abdul Malik] dari [Atha] dari [Ya'la bin Umayyah] dengan sanad ini. Namun ia menambahkan, \"Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepada orang yang mengigit: \"Jika kamu mau serahkanlah tanganmu kepadanya hingga ia dapat mengigitnya, lalu kamu tarik tanganmu dari mulutnya.\" Kemudian beliau menghapus diyat giginya. "},"3847":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ الْأَنْطَاكِيُّ وَمُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ أَنَّ الْوَلِيدَ بْنَ مُسْلِمٍ أَخْبَرَهُمْ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَطَبَّبَ وَلَا يُعْلَمُ مِنْهُ طِبٌّ فَهُوَ ضَامِنٌقَالَ نَصْرٌ قَالَ حَدَّثَنِي ابْنُ جُرَيْجٍ قَالَ أَبُو دَاوُد هَذَا لَمْ يَرْوِهِ إِلَّا الْوَلِيدُ لَا نَدْرِي هُوَ صَحِيحٌ أَمْ لَا","id":"Telah menceritakan kepada kami [Nashr bin Ashim Al Anthaki] dan [Muhammad bin Ash Shabbah bin Sufyan] bahwa [Al Walid bin Muslim] mengabarkan kepada mereka, dari [Ibnu Juraij] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengobati sedangkan ia dikenal bukan sebagai seorang dokter, maka ia harus bertanggung jawab (jika terjadi kecelakaan).\" Nashr berkata, \"Ibnu Juraij menceritakan kepadaku, Abu Dawud berkata, \"Hadits ini tidak ada yang meriwayatkannya kecuali Al Walid, dan kami tidak tahu hadits ini shahih atau tidak.\""},"3848":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَفْصٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ حَدَّثَنِي بَعْضُ الْوَفْدِ الَّذِينَ قُدِمُوا عَلَى أَبِي قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا طَبِيبٍ تَطَبَّبَ عَلَى قَوْمٍ لَا يُعْرَفُ لَهُ تَطَبُّبٌ قَبْلَ ذَلِكَ فَأَعْنَتَ فَهُوَ ضَامِنٌقَالَ عَبْدُ الْعَزِيزِ أَمَا إِنَّهُ لَيْسَ بِالنَّعْتِ إِنَّمَا هُوَ قَطْعُ الْعُرُوقِ وَالْبَطُّ وَالْكَيُّ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Hafsh] berkata, telah menceritakan kepada kami [Abdul Aziz bin Umar bin Abdul Aziz] berkata, telah menceritakan kepadaku [beberapa utusan] yang datang kepada bapakku, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dokter mana saja yang mengobati suatu kaum, padahal sebelum itu ia tidak dikenal sebagai dokter, kemudian memberi kecelakaan maka ia bertanggung jawab.\" Abdul Aziz berkata, \"Ketahuilah bukanlah maksud mengobati di sini secara umum, tetapi khusus dalam memotong urat, membelah perut atau mengobati dengan menempelkan besi yang dibakar pada luka.\""},"3849":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُسَدَّدٌ خَطَبَ يَوْمَ الْفَتْحِ ثُمَّ اتَّفَقَا فَقَالَ أَلَا إِنَّ كُلَّ مَأْثُرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ مِنْ دَمٍ أَوْ مَالٍ تُذْكَرُ وَتُدْعَى تَحْتَ قَدَمَيَّ إِلَّا مَا كَانَ مِنْ سِقَايَةِ الْحَاجِّ وَسِدَانَةِ الْبَيْتِ ثُمَّ قَالَ أَلَا إِنَّ دِيَةَ الْخَطَإِ شِبْهِ الْعَمْدِ مَا كَانَ بِالسَّوْطِ وَالْعَصَا مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَاحَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ بِهَذَا الْإِسْنَادِ نَحْوَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Musaddad] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Khalid] dari [Al Qasim bin Rabi'ah] dari [Uqbah bin Aus] dari [Abdullah bin Amru] bahwa Rasulullah shallallahu 'alaihi wasallam -Musaddad menyebutkan 'berkhutbah saat hari pembukaan (penaklukan) kota Makkah- lalu keduanya sepakat pada lafadz, lalu beliau mengatakan: \"Ketahuilah, setiap peninggalan masa Jahilliyah, baik itu yang diperoleh karena diyat pembunuhan atau pencurian, maka semua itu ada di bawah kakiku (bathil), kecuali apa-apa yang dihasilkan dari usaha memberi minum jamaah haji dan pengabdian kepada ka'bah.\" Kemudian beliau meneruskan: \"Ketahuilah, sesungguhnya diyat pembunuhan semi sengaja, yang dilakukan dengan cambuk atau tongkat adalah seratus unta, yang di antaranya terdiri dari empat puluh unta yang sedang hamil.\" Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Khalid] dengan sanad dan makna ini. "},"3850":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ غُلَامًا لِأُنَاسٍ فُقَرَاءَ قَطَعَ أُذُنَ غُلَامٍ لِأُنَاسٍ أَغْنِيَاءَ فَأَتَى أَهْلُهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا أُنَاسٌ فُقَرَاءُ فَلَمْ يَجْعَلْ عَلَيْهِ شَيْئًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Abu Nadhrah] dari [Imran bin Hushain] berkata, \"Bahwasanya ada budak laki-laki milik orang miskin memotong telinga budak laki-laki milik orang kaya. Lalu keluarga budak (milik orang miskin) tersebut mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, 'Wahai Rasulullah, kami ini adalah orang-orang yang miskin! ' Beliau akhirnya tidak memberikan hukuman apapun.\""},"3851":{"ar":"قَالَ أَبُو دَاوُد حُدِّثْتُ عَنْ سَعِيدِ بْنِ سُلَيْمَانَ عَنْ سُلَيْمَانَ بْنِ كَثِيرٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ فِي عِمِّيَّا أَوْ رِمِّيًّا يَكُونُ بَيْنَهُمْ بِحَجَرٍ أَوْ بِسَوْطٍ فَعَقْلُهُ عَقْلُ خَطَإٍ وَمَنْ قَتَلَ عَمْدًا فَقَوَدُ يَدَيْهِ فَمَنْ حَالَ بَيْنَهُ وَبَيْنَهُ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ","id":"Abu Dawud berkata, \"Aku mendapat cerita dari [Sa'id bin Sulaiman] dari [Sulaiman bin Katsir] berkata, telah menceritakan kepada kami [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh dalam keadaan gelap (tidak jelas siapa pembunuh dan bagaimana caranya), atau ketika terjadi saling lempar antara mereka baik dengan batu, cambuk, maka tebusannya adalah tebusan (pembunuhan) karena salah. Dan barangsiapa membunuh dengan sengaja, hukumannya adalah qishas. Barangsiapa menghalangi terlaksananya qishas, maka ia akan mendapat laknat Allah, para malaikat dan manusia.\""},"3852":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرِّجْلُ جُبَارٌقَالَ أَبُو دَاوُد الدَّابَّةُ تَضْرِبُ بِرِجْلِهَا وَهُوَ رَاكِبٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Yazid] berkata, telah menceritakan kepada kami [Sufyan bin Husain] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Kaki adalah sia-sia (tidak ada tebusan).\" Abu Dawud berkata, \"Maksudnya Binatang yang menginjak dengan dengan kakinya, sementara ia (pemilik) menungganginya.\""},"3853":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وأَبِي سَلَمَةَ سَمِعَا أَبَا هُرَيْرَةَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَجْمَاءُ جُرْحُهَا جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَفِي الرِّكَازِ الْخُمْسُقَالَ أَبُو دَاوُد الْعَجْمَاءُ الْمُنْفَلِتَةُ الَّتِي لَا يَكُونُ مَعَهَا أَحَدٌ وَتَكُونُ بِالنَّهَارِ لَا تَكُونُ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah] keduanya mendengar bahwa [Abu Hurairah] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesuatu yang dirusak oleh binatang tidak ada tebusannya, barang tambang tidak ada tebusannya, dan pada harta yang terpendam zakatnya adalah seperlima.\" Abu Dawud berkata, \" Al 'Ajma` maksudnya adalah hewan yang tidak ada penunggangnya atau penuntunnya, dan yang sesuatu yang dirusak oleh hewan di waktu siang tidak sama dengan sesuatu yang dirusak di waktu malam.\""},"3854":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ ح و حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ التِّنِّيسِيُّ حَدَّثَنَا زَيْدُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْمَلِكِ الصَّنْعَانِيُّ كِلَاهُمَا عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّارُ جُبَارٌ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutawakkil Al 'Asqalani] berkata, telah menceritakan kepada kami [Abdurrazaq]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ja'far bin Musafir At Tinnisi] berkata, telah menceritakan kepada kami [Zaid Ibnul Mubarak] berkata, telah menceritakan kepada kami [Abdul Malik Ash Shan'ani] keduanya dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Api adalah sia-sia (tidak ada tebusan bagi apa yang dirusak oleh api yang menjalar).\""},"3855":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَسَرَتْ الرُّبَيِّعُ أُخْتُ أَنَسِ بْنِ النَّضْرِ ثَنِيَّةَ امْرَأَةٍ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى بِكِتَابِ اللَّهِ الْقِصَاصَ فَقَالَ أَنَسُ بْنُ النَّضْرِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا تُكْسَرُ ثَنِيَّتُهَا الْيَوْمَ قَالَ يَا أَنَسُ كِتَابُ اللَّهِ الْقِصَاصُ فَرَضُوا بِأَرْشٍ أَخَذُوهُ فَعَجِبَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُقَالَ أَبُو دَاوُد سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ قِيلَ لَهُ كَيْفَ يُقْتَصُّ مِنْ السِّنِّ قَالَ تُبْرَدُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Al Mu'tamir] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Ruba' -saudara wanita Anas bin An Nadhr- memecahkan gigi seorang wanita, mereka lalu mendatangi Nabi shallallahu 'alaihi wasallam, lantas beliau memutuskan dengan kitab Allah, yakni qishas. Anas bin An Nadhr berkata, \"Demi Dzat yang mengutusmu dengan kebenaran, hari ini giginya tidak akan dipecah (qishas)!\" beliau bersabda: \"Wahai Anas, ketentuan Kitabullah adalah qishas!\" Kemudian mereka pun rela dengan mengambil diyatnya. Dengan ta'ajub Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh, di antara hamba Allah ada seseorang yang jika ia bersumpah pasti akan dikabulkan.\" Abu Dawud berkata, \"Aku mendengar Ahmad bin Hanbal ditanya, \"Bagaimana mengqishas gigi?\" Ia menjawab, \"Dirampalkan.\""},"3856":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَرَقَتْ الْيَهُودُ عَلَى إِحْدَى أَوْ ثِنْتَيْنِ وَسَبْعِينَ فِرْقَةً وَتَفَرَّقَتْ النَّصَارَى عَلَى إِحْدَى أَوْ ثِنْتَيْنِ وَسَبْعِينَ فِرْقَةً وَتَفْتَرِقُ أُمَّتِي عَلَى ثَلَاثٍ وَسَبْعِينَ فِرْقَةً","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yahudi terpecah menjadi tujuh puluh satu atau tujuh puluh dua golongan, Nashara terpecah menjadi tujuh puluh satu atau tujuh puluh dua golongan, dan umatku akan terpecah menjadi tujuh puluh tiga golongan.\""},"3857":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ ح و حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي صَفْوَانُ نَحْوَهُ قَالَ حَدَّثَنِي أَزْهَرُ بْنُ عَبْدِ اللَّهِ الْحَرَازِيُّ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّهُ قَامَ فِينَا فَقَالَ أَلَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِينَا فَقَالَ أَلَا إِنَّ مَنْ قَبْلَكُمْ مِنْ أَهْلِ الْكِتَابِ افْتَرَقُوا عَلَى ثِنْتَيْنِ وَسَبْعِينَ مِلَّةً وَإِنَّ هَذِهِ الْمِلَّةَ سَتَفْتَرِقُ عَلَى ثَلَاثٍ وَسَبْعِينَ ثِنْتَانِ وَسَبْعُونَ فِي النَّارِ وَوَاحِدَةٌ فِي الْجَنَّةِ وَهِيَ الْجَمَاعَةُ زَادَ ابْنُ يَحْيَى وَعَمْرٌو فِي حَدِيثَيْهِمَا وَإِنَّهُ سَيَخْرُجُ مِنْ أُمَّتِي أَقْوَامٌ تَجَارَى بِهِمْ تِلْكَ الْأَهْوَاءُ كَمَا يَتَجَارَى الْكَلْبُ لِصَاحِبِهِ وَقَالَ عَمْرٌو الْكَلْبُ بِصَاحِبِهِ لَا يَبْقَى مِنْهُ عِرْقٌ وَلَا مَفْصِلٌ إِلَّا دَخَلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepada kami [Shafwan]. (dalam jalur lain disebutkan) [Amru bin Utsman] berkata, telah menceritakan kepada kami [Baqiyyah] ia berkata; telah menceritakan kepadaku [Shafwan] seperti itu. Ia berkata, \"telah menceritakan kepadaku [Azhar bin Abdullah Al Harazi] dari [Abu Amir Al Hauzani] dari [Mu'awiyah bin Abu Sufyan] Bahwasanya saat sedang besama kami ia berkata, \"Ketahuilah, ketika sedang bersama kami Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah! Sesungguhnya orang-orang sebelum kalian dari kalangan ahlu kitab berpecah belah menjadi tujuh puluh dua golongan, dan umatku akan berpecah menjadi tujuh puluh tiga golongan; tujuh puluh dua golongan masuk neraka dan satu golongan masuk surga, yaitu Al Jama'ah.\" Ibnu Yahya dan Amru menambahkan dalam hadits keduanya, \"Sesungguhnya akan keluar dari umatku beberapa kaum yang mengikuti hawa nafsunya seperti anjing mengikuti tuannya.\" Amru berkata, \"Seekor lekat dengan tuannya, yang jika ada tulang bersamanya pasti dia akan mengikutinya.\""},"3858":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ التَّسْتُرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ إِلَى أُولُو الْأَلْبَابِ }قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَأَيْتُمْ الَّذِينَ يَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ فَأُولَئِكَ الَّذِينَ سَمَّى اللَّهُ فَاحْذَرُوهُمْ","id":"Telah menceritakan kepada kami [Al Qa'nabi] berkata, telah menceritakan kepada kami [Yazid bin Ibrahim At Tastutri] dari [Abdullah bin Abu Bulaikah] dari [Al Qasim bin Muhammad bin Muhammad] dari ['Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca ayat: '(Dia-lah yang menurunkan Al Kitab (Al-Qur'an) kepada kamu. Di antara isinya ada ayat-ayat yang muhkamat..) hingga ayat '(orang-orang yang berakal).\" 'Aisyah berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu melihat orang-orang yang mengikuti ayat-ayat mutasyabihat dari Al-Qur'an, maka mereka itulah orang-orang yang Allah maksud, maka berhati-hatilah terhadap mereka.\""},"3859":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الْأَعْمَالِ الْحُبُّ فِي اللَّهِ وَالْبُغْضُ فِي اللَّهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Khalid bin Abdullah] berkata, telah menceritakan kepada kami [Yazid bin Abu Ziyad] dari [Mujahid] dari [seorang laki-laki] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik amal adalah cinta karena Allah dan benci karena Allah.\""},"3860":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ وَذَكَرَ ابْنُ السَّرْحِ قِصَّةَ تَخَلُّفِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ قَالَوَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمِينَ عَنْ كَلَامِنَا أَيُّهَا الثَّلَاثَةَ حَتَّى إِذَا طَالَ عَلَيَّ تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ وَهُوَ ابْنُ عَمِّي فَسَلَّمْتُ عَلَيْهِ فَوَاللَّهِ مَا رَدَّ عَلَيَّ السَّلَامَ ثُمَّ سَاقَ خَبَرَ تَنْزِيلِ تَوْبَتِهِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah mengabarkan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku ['Abdurrahman bin Abdullah bin Ka'b bin Malik] bahwa [Abdullah bin Ka'b bin Malik] -di antara anak-anak Ka'ab Abdullah adalah orang yang menjadi penuntun Ka'b saat buta- ia berkata, \"Aku mendengar [Ka'b bin Malik] -Ibnu As Sarh menyebutkan kisah ketidak ikut sertaannya bersama Nabi shallallahu 'alaihi wasallam daam perang Tabuk- ia (Ka'b) berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kaum muslimin untuk berbicara dengan kami bertiga. Ketika suasana seperti berjalan lama, aku masuk ke dalam kebun milik anak pamanku, Abu Qatadah. Demi Allah, aku ucapkan salam kepadanya namun ia tidak menjawabnya.\" Kemudian Ka'ab menceritakan turunnya ayat yang mengabarkan atas diterimanya taubatnya. "},"3861":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَطَاءٌ الْخُرَاسَانِيُّ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَقَدِمْتُ عَلَى أَهْلِي وَقَدْ تَشَقَّقَتْ يَدَايَ فَخَلَّقُونِي بِزَعْفَرَانٍ فَغَدَوْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ وَقَالَ اذْهَبْ فَاغْسِلْ هَذَا عَنْكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Atha Al Akhurasani] dari [Yahya bin Ya'mar] dari [Ammar bin Yasir] ia berkata, \"Aku mendatangi isteriku saat tanganku lecet, kemudian ia membalur tanganku dengan za'faran. Pagi harinya aku datang menemui Nabi shallallahu 'alaihi wasallam, saat aku mengucapkan salam beliau tidak mau menjawabnya. Beliau bersabda: \"Pergi dan bersihkanlah ini (za'faran) darimu.\""},"3862":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ سُمَيَّةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهُ اعْتَلَّ بَعِيرٌ لِصَفِيَّةَ بِنْتِ حُيَيٍّ وَعِنْدَ زَيْنَبَ فَضْلُ ظَهْرٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِزَيْنَبَ أَعْطِيهَا بَعِيرًا فَقَالَتْ أَنَا أُعْطِي تِلْكَ الْيَهُودِيَّةَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَجَرَهَا ذَا الْحِجَّةِ وَالْمُحَرَّمَ وَبَعْضَ صَفَرٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani] dari [Sumayyah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Ketika unta Shafiyah binti Huyay sakit, Zainab masih mempunyai kendaraan yang bisa digunakan. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada Zainab: \"Berilah Shafiyah unta.\" Zainab menjawab, \"Aku harus memberi Yahudi itu!\" Rasulullah shallallahu 'alaihi wasallam pun marah, kemudian beliau mendiamkannya selama bulan Dzul hijjah, Muharram dan sebagian bulan Shafar.\""},"3863":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمِرَاءُ فِي الْقُرْآنِ كُفْرٌ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Yazid] -maksudnya Yazid bin Harun- berkata, telah mengabarkan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berbantah-bantahan dalam Al-Qur'an adalah kufur.\""},"3864":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا أَبُو عَمْرِو بْنُ كَثِيرِ بْنِ دِينَارٍ عَنْ حَرِيزِ بْنِ عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَوْفٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَلَا إِنِّي أُوتِيتُ الْكِتَابَ وَمِثْلَهُ مَعَهُ أَلَا يُوشِكُ رَجُلٌ شَبْعَانُ عَلَى أَرِيكَتِهِ يَقُولُ عَلَيْكُمْ بِهَذَا الْقُرْآنِ فَمَا وَجَدْتُمْ فِيهِ مِنْ حَلَالٍ فَأَحِلُّوهُ وَمَا وَجَدْتُمْ فِيهِ مِنْ حَرَامٍ فَحَرِّمُوهُ أَلَا لَا يَحِلُّ لَكُمْ لَحْمُ الْحِمَارِ الْأَهْلِيِّ وَلَا كُلُّ ذِي نَابٍ مِنْ السَّبُعِ وَلَا لُقَطَةُ مُعَاهِدٍ إِلَّا أَنْ يَسْتَغْنِيَ عَنْهَا صَاحِبُهَا وَمَنْ نَزَلَ بِقَوْمٍ فَعَلَيْهِمْ أَنْ يَقْرُوهُ فَإِنْ لَمْ يَقْرُوهُ فَلَهُ أَنْ يُعْقِبَهُمْ بِمِثْلِ قِرَاهُ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] berkata, telah menceritakan kepada kami [Abu Amru bin Katsir bin Dinar] dari [Hariz bin Utsman] dari ['Abdurrahman bin Abu Auf] dari [Al Miqdam bin Ma'di Karib] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Ketahuilah, sesungguhnya aku diberi Al -Qur'an dan yang semisal bersamanya (As Sunnah). Lalu ada seorang laki-laki yang dalam keadaan kekenyangan duduk di atas kursinya berkata, \"Hendaklah kalian berpegang teguh dengan Al-Qur'an! Apa yang kalian dapatkan dalam Al-Qur'an dari perkara halal maka halalkanlah. Dan apa yang kalian dapatkan dalam Al-Qur'an dari perkara haram maka haramkanlah. Ketahuilah! Tidak dihalalkan bagi kalian daging himar jinak, daging binatang buas yang bertaring dan barang temuan milik orang kafir mu'ahid (kafir dalam janji perlindungan penguasa Islam, dan barang temuan milik muslim lebih utama) kecuali pemiliknya tidak membutuhkannya. Dan barangsiapa singgah pada suatu kaum hendaklah mereka menyediakan tempat, jika tidak memberikan tempat hendaklah memberikan perlakukan sesuai dengan sikap jamuan mereka.\""},"3865":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ مُتَّكِئًا عَلَى أَرِيكَتِهِ يَأْتِيهِ الْأَمْرُ مِنْ أَمْرِي مِمَّا أَمَرْتُ بِهِ أَوْ نَهَيْتُ عَنْهُ فَيَقُولُ لَا نَدْرِي مَا وَجَدْنَا فِي كِتَابِ اللَّهِ اتَّبَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] dan [Abdullah bin Muhammad An nufaili] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Abu An Nadhr] dari [Ubaidullah bin Abu Rafi'] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh, akan ada salah seorang dari kalian duduk di atas kursi santainya, lalu datang kepadanya perkara yang aku perintahkan atau aku larang kemudian ia berkata, \"Aku tidak tahu! Apa yang kami dapatkan dalam Kitabullah selalu kami ikuti.\""},"3866":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَخْرَمِيُّ وَإِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ فِيهِ فَهُوَ رَدٌّقَالَ ابْنُ عِيسَى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَنَعَ أَمْرًا عَلَى غَيْرِ أَمْرِنَا فَهُوَ رَدٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Isa] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far Al Makhrami] dan [Ibrahim bin Sa'd] dari [Sa'd bin Ibrahim] dari [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam a bersabda: \"Barangsiapa membuat-buat suatu perkara yang tidak ada dalam agama kami, maka akan tertolak.\" Ibnu Isa menyebutkan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat perkara baru selain dari yang kami perintahkan maka akan tertolak.\""},"3867":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي خَالِدُ بْنُ مَعْدَانَ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو السُّلَمِيُّ وَحُجْرُ بْنُ حُجْرٍ قَالَاأَتَيْنَا الْعِرْبَاضَ بْنَ سَارِيَةَ وَهُوَ مِمَّنْ نَزَلَ فِيهِ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ قُلْتَ لَا أَجِدُ مَا أَحْمِلُكُمْ عَلَيْهِ }فَسَلَّمْنَا وَقُلْنَا أَتَيْنَاكَ زَائِرِينَ وَعَائِدِينَ وَمُقْتَبِسِينَ فَقَالَ الْعِرْبَاضُ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ ثُمَّ أَقْبَلَ عَلَيْنَا فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ كَأَنَّ هَذِهِ مَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا فَقَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الْمَهْدِيِّينَ الرَّاشِدِينَ تَمَسَّكُوا بِهَا وَعَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّ كُلَّ مُحْدَثَةٍ بِدْعَةٌ وَكُلَّ بِدْعَةٍ ضَلَالَةٌ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] ia berkata; telah menceritakan kepadaku [Khalid bin Ma'dan] ia berkata; telah menceritakan kepadaku ['Abdurrahman bin Amru As Sulami] dan [Hujr bin Hujr] keduanya berkata, \"Kami mendatangi [Irbadh bin Sariyah], dan ia adalah termasuk seseorang yang turun kepadanya ayat: '(dan tiada (pula dosa) atas orang-orang yang apabila mereka datang kepadamu, suapaya kami memberi mereka kendaraan, lalu kamu berkata, \"Aku tidak memperoleh kendaraan orang yang membawamu) ' -Qs. At Taubah: 92- kami mengucapkan salam kepadanya dan berkata, \"Kami datang kepadamu untuk ziarah, duduk-duduk mendengar sesuatu yang berharga darimu.\" Irbadh berkata, \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam shalat bersama kami, beliau lantas menghadap ke arah kami dan memberikan sebuah nasihat yang sangat menyentuh yang membuat mata menangis dan hati bergetar. Lalu seseorang berkata, \"Wahai Rasulullah, seakan-akan ini adalah nasihat untuk perpisahan! Lalu apa yang engkau washiatkan kepada kami?\" Beliau mengatakan: \"Aku wasiatkan kepada kalian untuk bertakwa kepada Allah, senantiasa taat dan mendengar meskipun yang memerintah adalah seorang budak habsyi yang hitam. Sesungguhnya orang-orang yang hidup setelahku akan melihat perselisihan yang banyak. Maka, hendaklah kalian berpegang dengan sunahku, sunah para khalifah yang lurus dan mendapat petunjuk, berpegang teguhlah dengannya dan gigitlah dengan gigi geraham. Jauhilah oleh kalian perkara-perkara baru (dalam urusan agama), sebab setiap perkara yang baru adalah bid'ah dan setaip bid'ah adalah sesat.\""},"3868":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي سُلَيْمَانُ يَعْنِي ابْنَ عَتِيقٍ عَنْ طَلْقِ بْنِ حَبِيبٍ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا هَلَكَ الْمُتَنَطِّعُونَ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] ia berkata; telah menceritakan kepadaku [Sulaiman] -maksudnya Sulaiman bin Atiq- dari [Thalq bin habib] dari [Al Ahnaf bin Qais] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ketahuilah, sesungguhnya celakalah orang-orang yang berlebih-lebihan dan melampaui batas.\" Beliau ucapkan hal itu hingga tiga kali. "},"3869":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَعْظَمَ الْمُسْلِمِينَ فِي الْمُسْلِمِينَ جُرْمًا مَنْ سَأَلَ عَنْ أَمْرٍ لَمْ يُحَرَّمْ فَحُرِّمَ عَلَى النَّاسِ مِنْ أَجْلِ مَسْأَلَتِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu syaibah] berkata, telah menceritakan kepada kami [Sufyan] dari [Az zuhri] dari [Amir bin Sa'd] dari [Bapaknya] ia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang muslim yang paling besar kejahatannya kepada kaum muslimin adalah seseorang yang bertanya tentang sesuatu yang belum diharamkan, lalu hal itu diharamkan atas semua manusia karena sebab pertanyaannya tersebut.\""},"3870":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الْهَمْدَانِيُّ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا إِدْرِيسَ الْخَوْلَانِيَّ عَائِذَ اللَّهِ أَخْبَرَهُ أَنَّ يَزِيدَ بْنَ عُمَيْرَةَ وَكَانَ مِنْ أَصْحَابِ مُعَاذِ بْنِ جَبَلٍ أَخْبَرَهُ قَالَكَانَ لَا يَجْلِسُ مَجْلِسًا لِلذِّكْرِ حِينَ يَجْلِسُ إِلَّا قَالَ اللَّهُ حَكَمٌ قِسْطٌ هَلَكَ الْمُرْتَابُونَ فَقَالَ مُعَاذُ بْنُ جَبَلٍ يَوْمًا إِنَّ مِنْ وَرَائِكُمْ فِتَنًا يَكْثُرُ فِيهَا الْمَالُ وَيُفْتَحُ فِيهَا الْقُرْآنُ حَتَّى يَأْخُذَهُ الْمُؤْمِنُ وَالْمُنَافِقُ وَالرَّجُلُ وَالْمَرْأَةُ وَالصَّغِيرُ وَالْكَبِيرُ وَالْعَبْدُ وَالْحُرُّ فَيُوشِكُ قَائِلٌ أَنْ يَقُولَ مَا لِلنَّاسِ لَا يَتَّبِعُونِي وَقَدْ قَرَأْتُ الْقُرْآنَ مَا هُمْ بِمُتَّبِعِيَّ حَتَّى أَبْتَدِعَ لَهُمْ غَيْرَهُ فَإِيَّاكُمْ وَمَا ابْتُدِعَ فَإِنَّ مَا ابْتُدِعَ ضَلَالَةٌ وَأُحَذِّرُكُمْ زَيْغَةَ الْحَكِيمِ فَإِنَّ الشَّيْطَانَ قَدْ يَقُولُ كَلِمَةَ الضَّلَالَةِ عَلَى لِسَانِ الْحَكِيمِ وَقَدْ يَقُولُ الْمُنَافِقُ كَلِمَةَ الْحَقِّ قَالَ قُلْتُ لِمُعَاذٍ مَا يُدْرِينِي رَحِمَكَ اللَّهُ أَنَّ الْحَكِيمَ قَدْ يَقُولُ كَلِمَةَ الضَّلَالَةِ وَأَنَّ الْمُنَافِقَ قَدْ يَقُولُ كَلِمَةَ الْحَقِّ قَالَ بَلَى اجْتَنِبْ مِنْ كَلَامِ الْحَكِيمِ الْمُشْتَهِرَاتِ الَّتِي يُقَالُ لَهَا مَا هَذِهِ وَلَا يُثْنِيَنَّكَ ذَلِكَ عَنْهُ فَإِنَّهُ لَعَلَّهُ أَنْ يُرَاجِعَ وَتَلَقَّ الْحَقَّ إِذَا سَمِعْتَهُ فَإِنَّ عَلَى الْحَقِّ نُورًاقَالَ أَبُو دَاوُد قَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ فِي هَذَا الْحَدِيثِ وَلَا يُنْئِيَنَّكَ ذَلِكَ عَنْهُ مَكَانَ يُثْنِيَنَّكَ و قَالَ صَالِحُ بْنُ كَيْسَانَ عَنْ الزُّهْرِيِّ فِي هَذَا الْمُشَبِّهَاتِ مَكَانَ الْمُشْتَهِرَاتِ وَقَالَ لَا يُثْنِيَنَّكَ كَمَا قَالَ عُقَيْلٌ و قَالَ ابْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ قَالَ بَلَى مَا تَشَابَهَ عَلَيْكَ مِنْ قَوْلِ الْحَكِيمِ حَتَّى تَقُولَ مَا أَرَادَ بِهَذِهِ الْكَلِمَةِ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Yazid bin Abdullah bin Mauhab Al hamdani] berkata, telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] bahwa [Abu Idris Al Khaulani 'Aidzaallah] telah mengabarkan kepadanya bahwa [Yazid bin Umairah] -salah seorang dari sahabat Mu'adz bin Jabal- mengabarkan kepadanya, ia berkata, \" [Mu'adz bin Jabal] tidak pernah duduk dalam sebuah majlis kecuali selalu berkata, \"Allah Maha Bijak, Allah Maha Adil, maka celakalah orang-orang yang merasa ragu.\" Suatu hari Mu'adz berkata, \"Di belakang kalian akan terjadi fitnah, harta semakin melimpah, Al Al Quran akan muda dibaca oleh siapa saja; seorang mukmin, munafik, laki-laki, wanita, anak kecil, orang dewasa, budak atau pun orang merdeka. Sehingga seseorang berkata, 'Kenapa orang-orang tidak mengikuti aku, padahal aku telah membaca Al-Qur'an! Sungguh, mereka tidak mengikuti kecuali aku melakukan bid'ah. ' Maka berhati-hatilah kalian dari bid'ah, sesungguhnya bi'dah akan membawa kepada kesesatan. Dan berhati-hatilah kalian dari hakim yang menyimpang, sebab setan akan mengucapkan kesasatan (kebathilan) melalui lisan hakim tersebut. Dan sungguh, seorang munafik terkadang akan mengucapkan kata-kata yang benar.\" Yazid berkata, \"Aku bertanya kepada Mu'adz, \"Semoga Allah merahmatimu, apakah aku pernah tahu dengan seorang hakim yang terkadang akan mengatakan sesuatu yang sesat dan munafik yang akan mengatakan sesuatu yang benar' ia menjawab, \"Ya. berhati-hatilah dengan perkataan hakim yang menyimpang (samar karena kebathilan) yang orang-orang mengingkarinya dan berkata; apa ini?. Meski demikian, janganlah kalian mengucilkannya. Sebab kemungkinan ia akan kembali kepada kebenaran hingga kamu dapat mendengar kebenaran darinya. karena di atas kebenaran pasti ada cahaya.\" Abu Dawud berkata, \" [Ma'mar] menyebutkan dari [Az Zuhri] dalam hadits ini, dengan lafdh berbeda yaitu; 'walaa yuts`iyannaka dzalikan 'ahu' (sekali-kali yang demikian itu janganlah membuatmu menyimpang) bukan \"yutsniyannaka\".\" [Shalih bin Kisan] menyebutkan dari [Az Zuhri], dengan lafadh, \"Musyabbihat\" sebagai ganti \"musytahirat\". Ia (perawi) menyebutkan, 'jangan menjauhkan kamu dari jalan yang lurus', yaitu seperti yang disebutkan oleh [Uqail].\" [Ibnu Ishaq] menyebutkan dari [Az Zuhri], \"Ia menjawab, \"Benar, perkataan hakim yang kamu merasa rancu darinya, hingga kamu mengingkarinya dan mengatakan, \"Apa yang ia inginkan dari perkataan ini?\""},"3871":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ قَالَ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ نَافِعٍ قَالَكَانَ لِابْنِ عُمَرَ صَدِيقٌ مِنْ أَهْلِ الشَّامِ يُكَاتِبُهُ فَكَتَبَ إِلَيْهِ عَبْدُ اللَّهِ بْنُ عُمَرَ إِنَّهُ بَلَغَنِي أَنَّكَ تَكَلَّمْتَ فِي شَيْءٍ مِنْ الْقَدَرِ فَإِيَّاكَ أَنْ تَكْتُبَ إِلَيَّ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ سَيَكُونُ فِي أُمَّتِي أَقْوَامٌ يُكَذِّبُونَ بِالْقَدَرِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] ia berkata; telah menceritakan kepada kami [Abdullah bin Yazid] ia berkata; telah menceritakan kepada kami [Sa'id] -maksudnya Said bin Abu Ayyub- ia berkata; telah mengabarkan kepadaku [Abu Shakr] dari [Nafi'] ia berkata, \"Ibnu Umar mempunyai seorang sahabat dari Syam yang menulis surat kepadanya, [Ibnu Umar] lantas menulis surat balasan yang isinya, \"Telah sampai kabar kepadaku bahwa engkau mempermasalahkan tentang takdir, maka janganlah engkau tanyakan hal itu kepdaku. Sungguh aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada dari umatku orang-orang yang mendustakan takdir.\""},"3872":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ خَالِدٍ الْحَذَّاءِ قَالَ قُلْتُ لِلْحَسَنِيَا أَبَا سَعِيدٍ أَخْبِرْنِي عَنْ آدَمَ أَلِلسَّمَاءِ خُلِقَ أَمْ لِلْأَرْضِ قَالَ لَا بَلْ لِلْأَرْضِ قُلْتُ أَرَأَيْتَ لَوْ اعْتَصَمَ فَلَمْ يَأْكُلْ مِنْ الشَّجَرَةِ قَالَ لَمْ يَكُنْ لَهُ مِنْهُ بُدٌّ قُلْتُ أَخْبِرْنِي عَنْ قَوْلِهِ تَعَالَى{ مَا أَنْتُمْ عَلَيْهِ بِفَاتِنِينَ إِلَّا مَنْ هُوَ صَالِ الْجَحِيمِ }قَالَ إِنَّ الشَّيَاطِينَ لَا يَفْتِنُونَ بِضَلَالَتِهِمْ إِلَّا مَنْ أَوْجَبَ اللَّهُ عَلَيْهِ الْجَحِيمَ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] ia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Khalid Al Hadzdza] ia berkata; Aku berkata kepada [Al Hasan], \"Wahai Abu Sa'id, beritahukanlah aku tentang Nabi Adam, apakah ia dicipta untuk langit atau untuk bumi?\" Ia menjawab, \"Untuk bumi.\" Aku bertanya lagi, \"Apa pendapatmu sekiranya Adam tidak makan buah khuldi?\" Ia menjawab, \"Itu tidak menjadi keharusan baginya.\" Aku berkata, \"Kabarkanlah kepadaku tentang firman Allah: (Sekali-kali tidak dapat menyesatkan kecuali (seseorang) terhadap Allah, kecuali orang-orang yang akan masuk neraka yang menyala). -Qs. Ash Shaffaat: 162-163- Abu Said menjawab; \"Sesungguhnya setan akan menggoda dengan kesesatan mereka, kecuali orang yang telah Allah wajibkan (tetapkan) neraka Al Jahim atasnya.\""},"3873":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ الْحَسَنِفِي قَوْلِهِ تَعَالَى{ وَلِذَلِكَ خَلَقَهُمْ }قَالَ خَلَقَ هَؤُلَاءِ لِهَذِهِ وَهَؤُلَاءِ لِهَذِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza] dari [Al Hasan] tentang firman Allah Ta'ala: '(dan untuk itulah Allah menciptakan mereka) ' -Qs. Huud: 119-. Ia menjawab, \"Allah telah menciptakan sekelompok orang untuk ini (syurga) dan sekelompok yang lain untuk ini (neraka).\""},"3874":{"ar":"حَدَّثَنَا هِلَالُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ أَخْبَرَنِي حُمَيْدٌ كَانَ الْحَسَنُ يَقُولُلَأَنْ يُسْقَطَ مِنْ السَّمَاءِ إِلَى الْأَرْضِ أَحَبُّ إِلَيْهِ مِنْ أَنْ يَقُولَ الْأَمْرُ بِيَدِي","id":"Telah menceritakan kepada kami [Hilal bin Bisyr] ia berkata; telah menceritakan kepada kami [Hammad] ia berkata; telah mengabarkan kepadaku [Humaid] berkata; [Al Hasan] berkata, \"Dijatuhkannya (adam) dari langit ke bumi lebih disukai daripada harus mengatakan segala urusan ada di tanganku (meniadakan takdir).\""},"3875":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا حُمَيْدٌ قَالَ قَدِمَ عَلَيْنَا الْحَسَنُ مَكَّةَفَكَلَّمَنِي فُقَهَاءُ أَهْلِ مَكَّةَ أَنْ أُكَلِّمَهُ فِي أَنْ يَجْلِسَ لَهُمْ يَوْمًا يَعِظُهُمْ فِيهِ فَقَالَ نَعَمْ فَاجْتَمَعُوا فَخَطَبَهُمْ فَمَا رَأَيْتُ أَخْطَبَ مِنْهُ فَقَالَ رَجُلٌ يَا أَبَا سَعِيدٍ مَنْ خَلَقَ الشَّيْطَانَ فَقَالَ سُبْحَانَ اللَّهِ هَلْ مِنْ خَالِقٍ غَيْرُ اللَّهِ خَلَقَ اللَّهُ الشَّيْطَانَ وَخَلَقَ الْخَيْرَ وَخَلَقَ الشَّرَّ قَالَ الرَّجُلُ قَاتَلَهُمْ اللَّهُ كَيْفَ يَكْذِبُونَ عَلَى هَذَا الشَّيْخِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] ia berkata; telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Humaid] ia berkata, \" [Al Hasan] mendatangi kami di Makkah, lalu para ulama Makkah berbicara kepadaku agar aku menyampaikan kepadanya permohonan mereka supaya Al Hasan bersedia meluangkan waktu untuk memberikan nasihat kepada mereka. Al Hasan lalu menjawab, \"Ya.\" Orang-orang lantas berkumpul dan Al Hasan berkhutbah di hadapan mereka, dan aku tidak pernah melihat seseorang berkhuthbah sebaik dirinya. kemudian ada seorang laki-laki berkata, \"Wahai Abu Sa'id, siapakah yang menciptakan setan?\" Al Hasan menjawab, \"Maha Suci Allah! Adakah pencipta selain Allah? Allah-lah yang menciptakan setan, kebaikan dan keburukkan.\" Laki-laki itu berkata lagi, \"Semoga Allah melaknat mereka semua, bagaimana mungkin mereka mendustai penjelasan syaikh ini.\""},"3876":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ رَجُلٍ قَدْ سَمَّاهُ غَيْرِ ابْنِ كَثِيرٍ عَنْ سُفْيَانَ عَنْ عُبَيْدٍ الصِّيدِ عَنْ الْحَسَنِفِي قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَحِيلَ بَيْنَهُمْ وَبَيْنَ مَا يَشْتَهُونَ }قَالَ بَيْنَهُمْ وَبَيْنَ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] ia berkata; telah mengabarkan kepada kami [Sufyan] dari [seorang laki-laki] yang banyak disebut namanya kecuali Ibnu Katsir, dari [Sufyan] dari [Ubaid Ash Shaid] dari [Al hasan] tentang firman Allah Azza Wa Jalla: '(Dan dihalangi antara mereka dengan apa yang mereka ingini….) ' -Qs. Saba: 54- ia berkata, \"Yaitu antara mereka dengan keimanan.\""},"3877":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُلَيْمٌ عَنْ ابْنِ عَوْنٍ قَالَكُنْتُ أَسِيرُ بِالشَّامِ فَنَادَانِي رَجُلٌ مِنْ خَلْفِي فَالْتَفَتُّ فَإِذَا رَجَاءُ بْنُ حَيْوَةَ فَقَالَ يَا أَبَا عَوْنٍ مَا هَذَا الَّذِي يَذْكُرُونَ عَنْ الْحَسَنِ قَالَ قُلْتُ إِنَّهُمْ يَكْذِبُونَ عَلَى الْحَسَنِ كَثِيرًا","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Sulaim] dari [Ibnu Aun] ia berkata, \"Ketika aku berjalan menuju Syam, seseorang memanggilku dari belakang, saat aku menoleh ke belakang ternyata orang itu adalah Raja` bin Haiwah. Ia lalu berkata, \"Wahai Abu Aun, apa yang diceritakan orang tentang Al Hasan?\" Aku menjawab, \"Mereka banyak mendustakan Al Hasan.\""},"3878":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ سَمِعْتُ أَيُّوبَ يَقُولُكَذَبَ عَلَى الْحَسَنِ ضَرْبَانِ مِنْ النَّاسِ قَوْمٌ الْقَدَرُ رَأْيُهُمْ وَهُمْ يُرِيدُونَ أَنْ يُنَفِّقُوا بِذَلِكَ رَأْيَهُمْ وَقَوْمٌ لَهُ فِي قُلُوبِهِمْ شَنَآنٌ وَبُغْضٌ يَقُولُونَ أَلَيْسَ مِنْ قَوْلِهِ كَذَا أَلَيْسَ مِنْ قَوْلِهِ كَذَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] ia berkata; telah menceritakan kepada kami [Hammad] ia berkata; Aku mendengar [Ayyub] berkata, \"Ada dua kelompok yang mendustakan Al Hasan; kelompok yang mengatakan bahwa takdir adalah kreasi mereka sendiri, mereka ingin menyebarkan fitnah kemunafikkan dengan pernyataan mereka itu; kelompok yang hatinya benci kepada Al Hasan. Mereka berkata, \"Bukahkah Al Hasan mengatakan begini? Bukankah Al Hasan mengatakan begini?\""},"3879":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَقُولُ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَعْدِلُ بِأَبِي بَكْرٍ أَحَدًا ثُمَّ عُمَرَ ثُمَّ عُثْمَانَ ثُمَّ نَتْرُكُ أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُفَاضِلُ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Pada masa Nabi shallallahu 'alaihi wasallam kami berkata, 'Kami tidak membandingkan antara Abu Bakar dengan seorang pun, begitu juga dengan Umar dan Utsman. Dan kami tidak pernah membanding-bandingkan antara para sahabat Nabi.\""},"3880":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ سَالِمُ بْنُ عَبْدِ اللَّهِ إِنَّ ابْنَ عُمَرَ قَالَكُنَّا نَقُولُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيٌّ أَفْضَلُ أُمَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ أَبُو بَكْرٍ ثُمَّ عُمَرُ ثُمَّ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُمْ أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Anbasah] berkata, telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] ia berkata; [Salim bin Abdullah] berkata; [Ibnu Umar] berkata, \"Kami pernah mengatakan sesuatu saat Nabi shallallahu 'alaihi wasallam masih hidup, \"Yang paling utama di antara umat Nabi shallallahu 'alaihi wasallam setelah beliau adalah Abu Bakar, lalu Umar, lalu Utsman. Semoga Allah meridhai mereka semua.\""},"3881":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا جَامِعُ بْنُ أَبِي رَاشِدٍ حَدَّثَنَا أَبُو يَعْلَى عَنْ مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ قَالَ قُلْتُ لِأَبِيأَيُّ النَّاسِ خَيْرٌ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ قَالَ قُلْتُ ثُمَّ مَنْ قَالَ ثُمَّ عُمَرُ قَالَ ثُمَّ خَشِيتُ أَنْ أَقُولَ ثُمَّ مَنْ فَيَقُولَ عُثْمَانُ فَقُلْتُ ثُمَّ أَنْتَ يَا أَبَةِ قَالَ مَا أَنَا إِلَّا رَجُلٌ مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Jami' bin Abu Rasyid] berkata, telah menceritakan kepada kami [Abu Ya'la] dari [Muhammad bin Al Hanafiyah] ia berkata, \"Aku bertanya kepada [bapakku], \"Siapakah manusia yang paling baik setelah Rasulullah shallallahu 'alaihi wasallam?\"Iia menjawab, \"Abu Bakar.\" Aku bertanya lagi, \"Kemudian siapa lagi?\" Ia menjawab, \"Umar.\" Muhammad bin Al hanafiyah berkata, \"Lalu timbul kecemasan jika aku bertanya 'lalu siapa lagi, kemudian ia menjawab 'Utsman'.\" Aku lalu bertanya, \"Apakah setelah itu engkau wahai bapakku?\" Ia menjawab, \"Aku hanyalah seorang laki-laki dari kaum muslimin.\""},"3882":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِسْكِينٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي الْفِرْيَابِيَّ قَالَ سَمِعْتُ سُفْيَانَ يَقُولُمَنْ زَعَمَ أَنَّ عَلِيًّا عَلَيْهِ السَّلَام كَانَ أَحَقَّ بِالْوِلَايَةِ مِنْهُمَا فَقَدْ خَطَّأَ أَبَا بَكْرٍ وَعُمَرَ وَالْمُهَاجِرِينَ وَالْأَنْصَارَ وَمَا أُرَاهُ يَرْتَفِعُ لَهُ مَعَ هَذَا عَمَلٌ إِلَى السَّمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Miskin] berkata, telah menceritakan kepada kami [Muhammad] -maksudnya Muhammad Al Firyabi- ia berkata; Aku mendengar [Sufyan] berkata, \"Siapa yang menyakini bahwa Ali Alaihis Salam lebih berhak untuk menjadi penguasa dari keduanya (Abu Bakar dan Umar), maka ia telah menyalahi Abu Bakar, Umar dan kaum Muhajirin dan Anshar. Dengan keyakinan dia seperti itu, maka aku melihat bahwa amalan baiknya tidak akan naik ke langit.\""},"3883":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا عَبَّادٌ السَّمَّاكُ قَالَ سَمِعْتُ سُفْيَانَ الثَّوْرِيَّ يَقُولُالْخُلَفَاءُ خَمْسَةٌ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَعُمَرُ بْنُ عَبْدِ الْعَزِيزِ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Abbad As Sammak] ia berkata, \"Aku mendengar [Sufyan Ats Tsauri] berkata, \"Khalifah (pemimpin) itu ada lima; Abu Bakar, Umar, Utsman, Ali dan Umar bin Abdul Aziz radliallahu 'anhum (semoga Allah meridhoi mereka).\""},"3884":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ مُحَمَّدٌ كَتَبْتُهُ مِنْ كِتَابِهِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُأَنَّ رَجُلًا أَتَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَرَى اللَّيْلَةَ ظُلَّةً يَنْطِفُ مِنْهَا السَّمْنُ وَالْعَسَلُ فَأَرَى النَّاسَ يَتَكَفَّفُونَ بِأَيْدِيهِمْ فَالْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ وَأَرَى سَبَبًا وَاصِلًا مِنْ السَّمَاءِ إِلَى الْأَرْضِ فَأَرَاكَ يَا رَسُولَ اللَّهِ أَخَذْتَ بِهِ فَعَلَوْتَ بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَانْقَطَعَ ثُمَّ وُصِلَ فَعَلَا بِهِ قَالَ أَبُو بَكْرٍ بِأَبِي وَأُمِّي لَتَدَعَنِّي فَلَأُعَبِّرَنَّهَا فَقَالَ اعْبُرْهَا قَالَ أَمَّا الظُّلَّةُ فَظُلَّةُ الْإِسْلَامِ وَأَمَّا مَا يَنْطِفُ مِنْ السَّمْنِ وَالْعَسَلِ فَهُوَ الْقُرْآنُ لِينُهُ وَحَلَاوَتُهُ وَأَمَّا الْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ فَهُوَ الْمُسْتَكْثِرُ مِنْ الْقُرْآنِ وَالْمُسْتَقِلُّ مِنْهُ وَأَمَّا السَّبَبُ الْوَاصِلُ مِنْ السَّمَاءِ إِلَى الْأَرْضِ فَهُوَ الْحَقُّ الَّذِي أَنْتَ عَلَيْهِ تَ��ْخُذُ بِهِ فَيُعْلِيكَ اللَّهُ ثُمَّ يَأْخُذُ بِهِ بَعْدَكَ رَجُلٌ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُ بِهِ رَجُلٌ آخَرُ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُ بِهِ رَجُلٌ آخَرُ فَيَنْقَطِعُ ثُمَّ يُوصَلُ لَهُ فَيَعْلُو بِهِ أَيْ رَسُولَ اللَّهِ لَتُحَدِّثَنِّي أَصَبْتُ أَمْ أَخْطَأْتُ فَقَالَ أَصَبْتَ بَعْضًا وَأَخْطَأْتَ بَعْضًا فَقَالَ أَقْسَمْتُ يَا رَسُولَ اللَّهِ لَتُحَدِّثَنِّي مَا الَّذِي أَخْطَأْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْسِمْحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ قَالَ فَأَبَى أَنْ يُخْبِرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Abdurrazaq] -Muhammad berkata; aku pernah menulis dari dalam bukunya- ia berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] ia berkata, \" [Abu Hurairah] pernah menceritakan bahwa ada seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Pada suatu malam aku bermimpi melihat suatu naungan yang mengeluarkan minyak dan madu. Lalu aku melihat orang-orang saling berebut untuk mengambilnya dengan tangan, ada yang mendapat banyak dan ada yang mendapat sedikit. Kemudian aku melihat ada sesuatu yang membentang dari langit ke bumi, dan ternyata itu adalah engkau wahai Rasulullah. Engkau mengambilnya hingga engkau menjadi mulia, lalu ada seorang laki-laki lain yang mengambilnya dan ia pun menjadi mulia, lalu ada seorang laki-laki lain yang mengambilnya dan ia pun menjadi mulia karenanya. Kemudian ada seorang laki-laki lain yang mengambilnya dan terputuslah kemuliaan itu. Setelah itu disambungkan lagi hingga ia menjadi mulia karenanya.\" Abu Bakar berkata, \"Demi bapak dan ibuku, biarkan aku menafsirkan mimpi itu?\" beliau bersabda: \"Silahkan.\" Abu Bakar berkata, \"Naungan itu adalah Islam, minyak dan madu itu adalah kelembutan dan manisnya Al-Qur'an. Orang yang mendapat sedikit dan banyak dalam mimpi itu adalah orang yang sedikit atau banyaknya dalam membaca Al-Qur'an. Dan yang menjadi wasilah (perantara) antara langit dan bumi adalah kebenaran yang engkau ada padannya engkau mengambilnya hingga Allah meninggikan dan memuliakanmu. Lalu setelahmu ada seorang laki-laki yang mengambilnya dan ia menjadi mulia, lalu setelah itu ada seorang laki-laki lain yang mengambilnya dan ia juga menjadi mulia. Kemudian ada lagi laki-laki lain yang mengambilnya, namun kemuliaan itu terputus. Allah lalu menyambungnya kembali hingga laki-laki itu pun menjadi mulia. Wahai Rasulullah, katakanlah kepadaku, benar atau salah yang aku katakan ini?\" beliau menjawab: \"Sebagian benar dan sebagian salah.\" Abu Bakar berkata lagi, \"Wahai Rasulullah, aku bersumpah, tolong anda katakan apa yang salah?\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Janganlah kamu bersumpah.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, dengan kisah seperti ini. Ia berkata, \"Beliau menolak untuk mengabarkannya (Tafsiran Abu Bakar yang salah).\""},"3885":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرِو بْنِ أَبَانَ بْنِ عُثْمَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرِيَ اللَّيْلَةَ رَجُلٌ صَالِحٌ أَنَّ أَبَا بَكْرٍ نِيطَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنِيطَ عُمَرُ بِأَبِي بَكْرٍ وَنِيطَ عُثْمَانُ بِعُمَرَ قَالَ جَابِرٌ فَلَمَّا قُمْنَا مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا أَمَّا الرَّجُلُ الصَّالِحُ فَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا تَنَوُّطُ بَعْضِهِمْ بِبَعْضٍ فَهُمْ وُلَاةُ هَذَا الْأَمْرِ الَّذِي بَعَثَ اللَّهُ بِهِ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد وَرَوَاهُ يُونُسُ وَشُعَيْبٌ لَمْ يَذْكُرَا عَمْرَو بْنَ أَبَانَ","id":"Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Ibnu Syihab] dari [Amru bin Aban bin Utsman] dari [Jabir bin Abdullah] ia bercerita bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Seorang laki-laki shalih bermimpi bahwa Abu Bakr dipautkan bersama Rasulullah shallallahu 'alaihi wasallam, Umar dipautkan bersama Abu Bakar dan Utsman juga dipautkan bersama Umar.\" Jabir berkata, \"Ketika kami bangkit dari sisi Rasulullah shallallahu 'alaihi wasallam, maka kami katakan, \"Laki-laki shalih itu adalah Rasulullah shallallahu 'alaihi wasallam. adapun keterpautan mereka satu sama lain itu adalah para pemimpin urusan ini (Islam) yang Allah utus kepada Nabi-Nya shallallahu 'alaihi wasallam.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Yunus] dan [Syu'aib], namun keduanya tidak menyebutkan Amru bin Aban.\""},"3886":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَشْعَثَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي رَأَيْتُ كَأَنَّ دَلْوًا دُلِّيَ مِنْ السَّمَاءِ فَجَاءَ أَبُو بَكْرٍ فَأَخَذَ بِعَرَاقِيهَا فَشَرِبَ شُرْبًا ضَعِيفًا ثُمَّ جَاءَ عُمَرُ فَأَخَذَ بِعَرَاقِيهَا فَشَرِبَ حَتَّى تَضَلَّعَ ثُمَّ جَاءَ عُثْمَانُ فَأَخَذَ بِعَرَاقِيهَا فَشَرِبَ حَتَّى تَضَلَّعَ ثُمَّ جَاءَ عَلِيٌّ فَأَخَذَ بِعَرَاقِيهَا فَانْتَشَطَتْ وَانْتَضَحَ عَلَيْهِ مِنْهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepadaku [Affan bin Muslim] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Asy'ats bin 'Abdurrahman] dari [Bapaknya] dari [Samurah bin Jundub] berkata, \"Seorang laki-laki berkata, \"Wahai Rasulullah, aku melihat seakan ada sebuah ember yang diulurkan dari atas langit, Abu Bakar lantas datang mengambil kayu pengaitnya lalu minum dengan sedikit, kemudian datang Umar mengambil kayu pengaitnya lalu minum dengan puas, kemudian datang Utsman mengambil kayu pengaitnya lalu minum dengan puas, kemudian datang Ali mengambil kayu pengaitnya lalu minum secara berlebihan hingga ia terkena air tersebut.\""},"3887":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ مَكْحُولٍ قَالَلَتَمْخُرَنَّ الرُّومُ الشَّامَ أَرْبَعِينَ صَبَاحًا لَا يَمْتَنِعُ مِنْهَا إِلَّا دِمَشْقَ وَعَمَّانَ","id":"Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Sa'id bin Abdul Aziz] dari [Makhul] ia berkata, \"Sungguh, Rum benar-benar akan memasuki Syam (mambawa fitnah) selama empat puluh hari, tidak ada yang selamat darinya selain Damaskus dan Amman.\""},"3888":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا بُرْدٌ أَبُو الْعَلَاءِ عَنْ مَكْحُولٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَوْضِعُ فُسْطَاطِ الْمُسْلِمِينَ فِي الْمَلَاحِمِ أَرْضٌ يُقَالُ لَهَا الْغُوطَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Burd Abul 'Ala] dari [Makhul] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kota kaum muslimin saat terjadi peperangan yang besar terletak pada sebuah wilayah yang bernama Al Ghuthah.\""},"3889":{"ar":"حَدَّثَنَا أَبُو ظَفَرٍ عَبْدُ السَّلَامِ حَدَّثَنَا جَعْفَرٌ عَنْ عَوْفٍ قَالَ سَمِعْتُ الْحَجَّاجَ يَخْطُبُ وَهُوَ يَقُولُإِنَّ مَثَلَ عُثْمَانَ عِنْدَ اللَّهِ كَمَثَلِ عِيسَى ابْنِ مَرْيَمَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ يَقْرَؤُهَا وَيُفَسِّرُهَا{ إِذْ قَالَ اللَّهُ يَا عِيسَى إِنِّي مُتَوَفِّيكَ وَرَافِعُكَ إِلَيَّ وَمُطَهِّرُكَ مِنْ الَّذِينَ كَفَرُوا }يُشِيرُ إِلَيْنَا بِيَدِهِ وَإِلَى أَهْلِ الشَّامِ","id":"Telah menceritakan kepada kami [Abu Zhafar Abdussalam] berkata, telah menceritakan kepada kami [Ja'far] dari [Auf] ia berkata; Aku mendengar [Al Hajjaj] berkhutbah, ia mengatakan, \"Permisalan Utsman di sisi Allah seperti Isa putra Maryam, lalu ia membaca ayat ini dan mentafsirkannya: '(Ingatlah), ketika Allah berfirman: \"Hai Isa, sesungguhnya Aku akan menyampaikan kamu kepada akhir ajalmu dan mengangkat kamu kepada-Ku serta membersihkan kamu dari orang-orang yang kafir…) ' -Qs. Ali Imran: 55- lalu dengan tangannya ia menunjuk ke arah kami dan ke arah penduduk Syam.\""},"3890":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ عَنْ الرَّبِيعِ بْنِ خَالِدٍ الضَّبِّيِّ قَالَ سَمِعْتُ الْحَجَّاجَ يَخْطُبُ فَقَالَ فِي خُطْبَتِهِرَسُولُ أَحَدِكُمْ فِي حَاجَتِهِ أَكْرَمُ عَلَيْهِ أَمْ خَلِيفَتُهُ فِي أَهْلِهِ فَقُلْتُ فِي نَفْسِي لِلَّهِ عَلَيَّ أَلَّا أُصَلِّيَ خَلْفَكَ صَلَاةً أَبَدًا وَإِنْ وَجَدْتُ قَوْمًا يُجَاهِدُونَكَ لَأُجَاهِدَنَّكَ مَعَهُمْ زَادَ إِسْحَقُ فِي حَدِيثِهِ قَالَ فَقَاتَلَ فِي الْجَمَاجِمِ حَتَّى قُتِلَ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il Ath Thalaqani] berkata, telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] berkata, telah menceritakan kepada kami [Jarir] dari [Al Mughirah] dari [Ar Rabi' bin Khalid Adh Dlabbi] ia berkata; Aku mendengar [Al Hajjaj] berkhutbah, dalam khutbahnya ia mengatakan, \"Utusan salah seorang dari kalian untuk memenuhi kebutuhannya lebih mulia dari dirinya atau lebih mulia dari orang yang diserahi untuk menjaga keluarganya?\" Maka aku pun berucap dalam diriku, \"Demi Allah, sungguh selamanya aku tidak akan shalat di belakangmu. Jika aku mendapati suatu kaum memerangimu maka aku akan ikut bergabung bersama mereka.\" Ishaq menambahkan dalam haditsnya, \" Ia berkata, \"Lalu Ar rabi' memerangi Al Hajaj di Jamajim hingga ia terbunuh.\""},"3891":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ الْحَجَّاجَ يَقُولُ عَلَى الْمِنْبَرِهَذِهِ الْحَمْرَاءُ هَبْرٌ هَبْرٌ أَمَا وَاللَّهِ لَوْ قَدْ قَرَعْتُ عَصًا بِعَصًا لَأَذَرَنَّهُمْ كَالْأَمْسِ الذَّاهِبِ يَعْنِي الْمَوَالِيَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Idris] dari [Al A'masy] ia berkata, \"Aku mendengar [Al Hajjaj] berkata di atas mimbar, \"Orang-orang Hamra (para badui) ini telah berhak untuk dipotong tangannya. Demi Allah, sekiranya aku menginginkan kebinasaan mereka, maka aku akan biarkan mereka seperti hari-hari kemarin.\" Maksudnya adalah orang-orang asing di luar Arab. "},"3892":{"ar":"حَدَّثَنَا قَطَنُ بْنُ نُسَيْرٍ حَدَّثَنَا جَعْفَرٌ يَعْنِي ابْنَ سُلَيْمَانَ حَدَّثَنَا دَاوُدُ بْنُ سُلَيْمَانَ عَنْ شَرِيكٍ عَنْ سُلَيْمَانَ الْأَعْمَشِ قَالَ جَمَّعْتُ مَعَ الْحَجَّاجِ فَخَطَبَ فَذَكَرَ حَدِيثَ أَبِي بَكْرِ بْنِ عَيَّاشٍ قَالَ فِيهَافَاسْمَعُوا وَأَطِيعُوا لِخَلِيفَةِ اللَّهِ وَصَفِيِّهِ عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ وَسَاقَ الْحَدِيثَ قَالَ وَلَوْ أَخَذْتُ رَبِيعَةَ بِمُضَرَ وَلَمْ يَذْكُرْ قِصَّةَ الْحَمْرَاءِ","id":"Telah menceritakan kepada kami [Qathan bin Nusair] berkata, telah menceritakan kepada kami [Ja'far] -maksudnya Ja'far bin Sulaiman- berkata, telah menceritakan kepada kami [Dawud bin Sulaiman] dari [Syarik] dari [Sulaiman Al A'masy] ia berkata, \"Aku shalat jum'at bersama [Al Hajjaj], lalu ia berkhutbah…. kemudian ia menyebutkan hadits Abu Bakar bin Ayyasy. Al Hajjaj mengatakan dalam khutbahnya, \"Dengarkan dan patuhilah khalifah dan kekasih Allah, Abdul Malik bin Marwan. Kemudian perawi menyebutkan hadits selanjutnya, \"Al Hajjaj berkata, \"Sekiranya aku hukum Rabi'ah di Mudhar…dan ia tidak menyebutkan kisah Al Hamra.\""},"3893":{"ar":"حَدَّثَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ جُمْهَانَ عَنْ سَفِينَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِلَافَةُ النُّبُوَّةِ ثَلَاثُونَ سَنَةً ثُمَّ يُؤْتِي اللَّهُ الْمُلْكَ أَوْ مُلْكَهُ مَنْ يَشَاءُقَالَ سَعِيدٌ قَالَ لِي سَفِينَةُ أَمْسِكْ عَلَيْكَ أَبَا بَكْرٍ سَنَتَيْنِ وَعُمَرُ عَشْرًا وَعُثْمَانُ اثْنَتَيْ عَشْرَةَ وَعَلِيٌّ كَذَا قَالَ سَعِيدٌ قُلْتُ لِسَفِينَةَ إِنَّ هَؤُلَاءِ يَزْعُمُونَ أَنَّ عَلِيًّا عَلَيْهِ السَّلَام لَمْ يَكُنْ بِخَلِيفَةٍ قَالَ كَذَبَتْ أَسْتَاهُ بَنِي الزَّرْقَاءِ يَعْنِي بَنِي مَرْوَانَ","id":"Telah menceritakan kepada kami [Sawwar bin Abdullah] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Sa'id bin Jumhan] dari [Safinah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khilafah kenabian itu selama tiga puluh tahun, kemudian Allah memberikan kekuasaan-Nya kepada siapa yang ia kehendaki.\" Sa'id berkata, \"Safinah berkata kepadaku, \"Hendaklah engkau tetap bersama Abu Bakar selama selama dua tahun, bersama Umar selama sepuluh tahun, bersama Utsman selama dua belas tahun, demikian juga dengan Ali.\" Sa'id berkata, \"Aku bertanya kepada Safinah, \"Mereka menganggap bahwa Ali bukan seorang khalifah?\" Ia menjawab, \"Keturunan Bani Az Zarqa, yaitu bani Marwan telah berdusta.\""},"3894":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ أَنْبَأَنَا ح و حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ أُمَّتِي الْقَرْنُ الَّذِينَ بُعِثْتُ فِيهِمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ وَاللَّهُ أَعْلَمُ أَذَكَرَ الثَّالِثَ أَمْ لَا ثُمَّ يَظْهَرُ قَوْمٌ يَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيَنْذِرُونَ وَلَا يُوفُونَ وَيَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَفْشُو فِيهِمْ السِّمَنُ","id":"Telah menceritakan kepada kami [Amru bin Aun] ia berkata; telah memberitakan kepada kami. (dalam jalur lain disebutkan) [Musaddad] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Imran bin Hushain] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik generasi adalah generasi saat aku diutus di dalamnya, kemudian generasi setelah mereka, kemudian generasi setelah mereka -Perawi berkata; 'Hanya Allah yang tahu, apakah beliau menyebutkan yang ketiga atau tidak'-. Setelah itu akan muncul orang-orang yang memberikan persaksian padahal mereka tidak diminta, berjanji namun tidak menepatinya, mereka suka melakukan khianat, tidak amanat dan menyebar di antara mereka kegemukan.\""},"3895":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا أَصْحَابِي فَوَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنْفَقَ أَحَدُكُمْ مِثْلَ أُحُدٍ ذَهَبًا مَا بَلَغَ مُدَّ أَحَدِهِمْ وَلَا نَصِيفَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlan kalian mencela sahabatku. Demi Dzat yang jiwaku ada dalam tangan-Nya, sekiranya salah seorang dari kalian bersedekah dengan emas sebesar gunung uhud, maka itu tidak akan bisa menyamai sedekah mereka meski hanya satu mud atau pun setengahnya.\""},"3896":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ الثَّقَفِيُّ حَدَّثَنَا عُمَرُ بْنُ قَيْسٍ الْمَاصِرُ عَنْ عَمْرِو بْنِ أَبِي قُرَّةَ قَالَكَانَ حُذَيْفَةُ بِالْمَدَائِنِ فَكَانَ يَذْكُرُ أَشْيَاءَ قَالَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُنَاسٍ مِنْ أَصْحَابِهِ فِي الْغَضَبِ فَيَنْطَلِقُ نَاسٌ مِمَّنْ سَمِعَ ذَلِكَ مِنْ حُذَيْفَةَ فَيَأْتُونَ سَلْمَانَ فَيَذْكُرُونَ لَهُ قَوْلَ حُذَيْفَةَ فَيَقُولُ سَلْمَانُ حُذَيْفَةُ أَعْلَمُ بِمَا يَقُولُ فَيَرْجِعُونَ إِلَى حُذَيْفَةَ فَيَقُولُونَ لَهُ قَدْ ذَكَرْنَا قَوْلَكَ لِسَلْمَانَ فَمَا صَدَّقَكَ وَلَا كَذَّبَكَ فَأَتَى حُذَيْفَةُ سَلْمَانَ وَهُوَ فِي مَبْقَلَةٍ فَقَالَ يَا سَلْمَانُ مَا يَمْنَعُكَ أَنْ تُصَدِّقَنِي بِمَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَلْمَانُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْضَبُ فَيَقُولُ فِي الْغَضَبِ لِنَاسٍ مِنْ أَصْحَابِهِ وَيَرْضَى فَيَقُولُ فِي الرِّضَا لِنَاسٍ مِنْ أَصْحَابِهِ أَمَا تَنْتَهِي حَتَّى تُوَرِّثَ رِجَالًا حُبَّ رِجَالٍ وَرِجَالًا بُغْضَ رِجَالٍ وَحَتَّى تُوقِعَ اخْتِلَافًا وَفُرْقَةً وَلَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَقَالَ أَيُّمَا رَجُلٍ مِنْ أُمَّتِي سَبَبْتُهُ سَبَّةً أَوْ لَعَنْتُهُ لَعْنَةً فِي غَضَبِي فَإِنَّمَا أَنَا مِنْ وَلَدِ آدَمَ أَغْضَبُ كَمَا يَغْضَبُونَ وَإِنَّمَا بَعَثَنِي رَحْمَةً لِلْعَالَمِينَ فَاجْعَلْهَا عَلَيْهِمْ صَلَاةً يَوْمَ الْقِيَامَةِوَاللَّهِ لَتَنْتَهِيَنَّ أَوْ لَأَكْتُبَنَّ إِلَى عُمَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zaidah bin Qudamah Ats Tsaqafi] berkata, telah menceritakan kepada kami [Umar bin Qais Al Mashiri] dari [Amru bin Abu Qurrah] ia berkata, \"Saat berada di Madain, [Hudzaifah] menyebutkan sesuatu yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam kepada para sahabatnya dengan marah. Orang-orang yang mendengar hal itu dari Hudzaifah langsung pergi dan mendatangi Salman. Mereka kemudian menceritakan apa yang dikatakan oleh Hudzaifah kepada Salman, namun Salaman justru berkata, \"Hudzaifah lebih tahu dengan apa yang ia katakan.\" Orang-orang itu akhirnya kembali lagi menemui Hudzaifah dan berkata, \"Ucapanmu tadi telah kami sampaikan kepada Salman, tetapi ia tidak membenarkan atau mendustakan kamu!\" Hudzifah lantas pergi mendatangi Salman saat ia berada di Mabqalah, Hudzaifah berkata, \"Wahai Salman, apa yang menghalangimu untuk membenarkan aku atas apa yang telah aku dengar dari Rasulullah shallallahu 'alaihi wasallam?\" Salman menjawab, \"Rasulullah shallallahu 'alaihi wasallam pernah marah dan berbicara dengan para sahabat dalam keadaam marah, tetapi beliau juga bisa ridha sehingga beliau berbicara dengan para sahabatnya dalam keadaan ridha. Tidakkah sebaiknya kamu tidak menceritakan apa yang telah kamu dengar hingga yang demikian itu dapat menjadikan sebagian cinta kepada sebagian dan benci kepada sebagian yang lain; agar tidak terjadi perpecahan. Engkau telah mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah: \"Laki-laki manapun dari umatku yang pernah aku cela atau laknat saat dalam kondisi marah, sesungguhnya aku hanyalah anak turun Adam, hingga aku pun dapat marah sebagaimana mereka marah. Hanya saja aku diutus sebagai rahmat bagi seluruh alam, (Ya Allah) jadikanlah celaanku itu sebagai rahmat bagi mereka pada hari kiamat.\" Demi Allah, engkau segera berhenti dari melakukan hal yang demikian itu atau aku akan menulis surat kepada Umar.\""},"3897":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَلَمَّا اسْتُعِزَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عِنْدَهُ فِي نَفَرٍ مِنْ الْمُسْلِمِينَ دَعَاهُ بِلَالٌ إِلَى الصَّلَاةِ فَقَالَ مُرُوا مَنْ يُصَلِّي لِلنَّاسِ فَخَرَجَ عَبْدُ اللَّهِ بْنُ زَمْعَةَ فَإِذَا عُمَرُ فِي النَّاسِ وَكَانَ أَبُو بَكْرٍ غَائِبًا فَقُلْتُ يَا عُمَرُ قُمْ فَصَلِّ بِالنَّاسِ فَتَقَدَّمَ فَكَبَّرَ فَلَمَّا سَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَهُ وَكَانَ عُمَرُ رَجُلًا مُجْهِرًا قَالَ فَأَيْنَ أَبُو بَكْرٍ يَأْبَى اللَّهُ ذَلِكَ وَالْمُسْلِمُونَ يَأْبَى اللَّهُ ذَلِكَ وَالْمُسْلِمُونَ فَبَعَثَ إِلَى أَبِي بَكْرٍ فَجَاءَ بَعْدَ أَنْ صَلَّى عُمَرُ تِلْكَ الصَّلَاةَ فَصَلَّى بِالنَّاسِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] ia berkata; telah menceritakan kepadaku [Az Zuhri] berkata, telah menceritakan kepadaku [Abdul Malik bin Abu Bakr bin 'Abdurrahman Ibnul Harits bin Hisaym] dari [Bapaknya] dari [Abdullah bin Zam'ah] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sakit keras, aku bersama beberapa kaum muslimin berada di sisi beliau, Bilal datang dan menyerunya untuk shalat. Beliau bersabda: \"Perintahkanlah seseorang untuk menjadi imam shalat.\" Abdullah bin Zam'ah lalu keluar, dan ternyata Umar tengah berada di antara orang-orang, sementara Abu Bakar tidak ada. Aku lalu berkata, \"Wahai Umar, berdiri dan imamilah orang-orang untuk melaksanakan shalat.\" Umar lalu berdiri dan bertakbir. Ketika Rasulullah shallallahu 'alaihi wasallam mendengar suaranya -umar adalah lelaki yang suaranya keras-, beliau bersabda: \"Di mana Abu Bakar? Sesungguhnya Allah dan kaum muslimin tidak menyukai yang seperti itu, sesungguhnya Allah dan kaum muslimin tidak menyukai yang seperti itu.\" Beliau lalu mengutus untuk mencarinya, kemudian Abu bakar ketika Umar telah selesai melaksanakan shalat, maka Abu Bakar pun shalat bersama orang-orang.\""},"3898":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ قَالَ حَدَّثَنِي مُوسَى بْنُ يَعْقُوبَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ زَمْعَةَ أَخْبَرَهُ بِهَذَا الْخَبَرِ قَالَلَمَّا سَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَ عُمَرَ قَالَ ابْنُ زَمْعَةَ خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَطْلَعَ رَأْسَهُ مِنْ حُجْرَتِهِ ثُمَّ قَالَ لَا لَا لَا لِيُصَلِّ لِلنَّاسِ ابْنُ أَبِي قُحَافَةَ يَقُولُ ذَلِكَ مُغْضَبًا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] ia berkata; telah menceritakan kepadaku [Musa bin Ya'qub] dari [Abdur Rahman bin Ishaq] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] bahwa [Abdullah bin Zam'ah] mengabarkan kepadanya dengan kabar tersebut. Ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam mendengar suara Umar, Ibnu Zam'ah berkata, \"Nabi shallallahu 'alaihi wasallam keluar hingga kepalanya terlihat dari balik kamarnya. Beliau lantas bersabda: \"Tidak, tidak, tidak. Hendaklah yang memimpin shalat adalah Ibnu Abu Quhafah.\" Beliau ucapkan itu dengan marah.\""},"3899":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَ حَدَّثَنِي الْأَشْعَثُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْحَسَنِ بْنِ عَلِيٍّ إِنَّ ابْنِي هَذَا سَيِّدٌ وَإِنِّي أَرْجُو أَنْ يُصْلِحَ اللَّهُ بِهِ بَيْنَ فِئَتَيْنِ مِنْ أُمَّتِي وَقَالَ فِي حَدِيثِ حَمَّادٍ وَلَعَلَّ اللَّهَ أَنْ يُصْلِحَ بِهِ بَيْنَ فِئَتَيْنِ مِنْ الْمُسْلِمِينَ عَظِيمَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] dan [Muslim bin Ibrahim] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Al Hasan] dari [Abu Bakrah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dari [Muhammad bin Abdullah Al Anshari] ia berkata; telah menceritakan kepadaku [Al Asy'ats] dari [Al Hasan] dari [Abu Bakrah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda untuk Al Hasan bin Ali: \"Sesungguhnya putraku ini adalah seorang pemimpin, aku berharap ia akan mendamaikan antara dua kelompok dari umatku yang bertikai.\" Dan dalam hadits Hammad, beliau mengatakan: \"Semoga dengan perantara anak ini Allah akan mendamaikan antara dua kelompok besar dari umatku yang bertikai.\""},"3900":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ قَالَ قَالَ حُذَيْفَةُمَا أَحَدٌ مِنْ النَّاسِ تُدْرِكُهُ الْفِتْنَةُ إِلَّا أَنَا أَخَافُهَا عَلَيْهِ إِلَّا مُحَمَّدُ بْنُ مَسْلَمَةَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَضُرُّكَ الْفِتْنَةُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Yazid] berkata, telah mengabarkan kepada kami [Hisyam] dari [Muhammad] ia berkata; [Hudzaifah] berkata, \"Tidak seorang pun dari manusia yang menemui fitnah kecuali aku akan mencemaskannya, kecuali Muhammad bin Maslamah. Sungguh aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Fitnah tidak akan membahayakanmu.\""},"3901":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِي بُرْدَةَ عَنْ ثَعْلَبَةَ بْنِ ضُبَيْعَةَ قَالَدَخَلْنَا عَلَى حُذَيْفَةَ فَقَالَ إِنِّي لَأَعْرِفُ رَجُلًا لَا تَضُرُّهُ الْفِتَنُ شَيْئًا قَالَ فَخَرَجْنَا فَإِذَا فُسْطَاطٌ مَضْرُوبٌ فَدَخَلْنَا فَإِذَا فِيهِ مُحَمَّدُ بْنُ مَسْلَمَةَ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ مَا أُرِيدُ أَنْ يَشْتَمِلَ عَلَيَّ شَيْءٌ مِنْ أَمْصَارِكُمْ حَتَّى تَنْجَلِيَ عَمَّا انْجَلَتْحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَشْعَثَ بْنِ سُلَيْمٍ عَنْ أَبِي بُرْدَةَ عَنْ ضُبَيْعَةَ بْنِ حُصَيْنٍ الثَّعْلَبِيِّ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Amru bin Marzuq] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Al Asy'ast bin Sulaim] dari [Abu Burdah] dari [Tsa'labah bin Dlubai'ah] ia berkata, \"Kami masuk menemui [Hudzaifah], ia lalu berkata, \"Sungguh, aku mengetahui seorang laki-laki yang tidak akan terkena buruknya fitnah sedikitpun.\" Tsa'labah berkata, \"Kami lalu pergi hingga mendapati sebuah tenda yang terpasang. Ketika kami masuk ternyata di dalamnya ada Muhammad bin Maslamah. Maka kami pun menanyakan hal itu (perkataan Hudzaifah) kepadanya, ia berkata, \"Aku tidak ingin tinggal bersama di kota kalian hingga jelas fitnah yang terjadi.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Asy'ats bin Sulaim] dari [Abu burdah] dari [Dlubai'ah bin Hushain Ats Tsa'labi] dengan makna yang sama.\""},"3902":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْهُذَلِيُّ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ قَيْسِ بْنِ عَبَّادٍ قَالَقُلْتُ لِعَلِيٍّ رَضِيَ اللَّهُ عَنْهُ أَخْبِرْنَا عَنْ مَسِيرِكَ هَذَا أَعَهْدٌ عَهِدَهُ إِلَيْكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ رَأْيٌ رَأَيْتَهُ فَقَالَ مَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ وَلَكِنَّهُ رَأْيٌ رَأَيْتُهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim Al hudzali] berkata, telah menceritakan kepada kami [Ibnu Ulayyah] dari [Yunus] dari [Al Hasan] dari [Qais bin Abbad] ia berkata, \"Aku berkata kepada [Ali radliallahu 'anhu], \"Kabarkanlah kepada kami tentang perjalananmu ini (ke Irak untuk memerangi Mu'awiyah), apakah itu nasihat yang Rasulullah shallallahu 'alaihi wasallam berikan kepadamu atau hanya sekedar pendapatmu saja?\" Ali menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah memberikan nasihat kepadaku hal itu, tetapi itu hanyalah pendapatku semata.\""},"3903":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْقَاسِمُ بْنُ الْفَضْلِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمْرُقُ مَارِقَةٌ عِنْدَ فُرْقَةٍ مِنْ الْمُسْلِمِينَ يَقْتُلُهَا أَوْلَى الطَّائِفَتَيْنِ بِالْحَقِّ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Al Qasim Ibnul Fadhl] dari [Abu Nadhrah] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada sekelompok orang dari kaum muslimin keluar dengan cepat saat terjadi perpecahan, dan mereka akan dibunuh oleh kelompok yang lebih berhak dengan kebenaran di antara dua kelompok yang ada.\""},"3904":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرٌو يَعْنِي ابْنَ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُوا بَيْنَ الْأَنْبِيَاءِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Amru] -maksudnya Amru bin Yahya- dari [Bapaknya] dari [Abu Sa'id Al Khudri] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kalian membeda-bedakan antara para Nabi.\""},"3905":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يَنْبَغِي لِعَبْدٍ أَنْ يَقُولَ إِنِّي خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Al 'Aliyah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak pantas bagi seorang hamba mengatakan: \"Sesungguhnya aku lebih baik dari Yunus bin Mata.\""},"3906":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ إِسْمَعِيلَ بْنِ أَبِي حَكِيمٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا يَنْبَغِي لِنَبِيٍّ أَنْ يَقُولَ إِنِّي خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Al Harrani] ia berkata; telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Isma'il bin Abu Hakim] dari [Al Qasim bin Muhammad] dari [Abdullah bin Ja'far] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak layak bagi seorang Nabi berkata: \"Aku lebih baik dari Yunus bin Mata.\""},"3907":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ وَمُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ قَالَا حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَعَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ مِنْ الْيَهُودِ وَالَّذِي اصْطَفَى مُوسَى فَرَفَعَ الْمُسْلِمُ يَدَهُ فَلَطَمَ وَجْهَ الْيَهُودِيِّ فَذَهَبَ الْيَهُودِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُونِي عَلَى مُوسَى فَإِنَّ النَّاسَ يُصْعَقُونَ فَأَكُونُ أَوَّلَ مَنْ يُفِيقُ فَإِذَا مُوسَى بَاطِشٌ فِي جَانِبِ الْعَرْشِ فَلَا أَدْرِي أَكَانَ مِمَّنْ صَعِقَ فَأَفَاقَ قَبْلِي أَوْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ عَزَّ وَجَلَّقَالَ أَبُو دَاوُد وَحَدِيثُ ابْنِ يَحْيَى أَتَمُّ","id":"Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] dan [Muhammad bin Yahya bin Faris] keduanya berkata; telah menceritakan kepada kami [Ya'qub] ia berkata; telah menceritakan kepada kami [Bapakku] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dan ['Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki Yahudi berkata 'Demi Dzat Yang mengutus Musa', lalu seorang laki-laki muslim mengangkat tangannya seraya menampar laki-laki Yahudi tersebut. Yahudi tersebut pergi menemui Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal tersebut kepada beliau. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melebih-lebihkan aku di atas Musa. (Pada hari kiamat) manusia akan pingsan, dan aku adalah orang yang paling pertama sadar. Namun ternyata Musa telah berpegangan di sisi Al Arsy, aku tidak tahu apakah beliau termasuk orang yang pingsan lalu sadar sebelum aku atau termasuk orang yang Allah kecualikan.\" Abu Dawud berkata, \"Hadits Ibnu Yahya lebih sempurna.\""},"3908":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُخْتَارِ بْنِ فُلْفُلٍ يَذْكُرُ عَنْ أَنَسٍ قَالَقَالَ رَجُلٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا خَيْرَ الْبَرِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ إِبْرَاهِيمُ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Mukhtar bin Fulful] ia menyebutkan dari [Anas] ia berkata, \"Seorang laki-laki berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai sebaik-baik manusia!\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Itu adalah Ibrahim.\""},"3909":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ فَرُّوخَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا سَيِّدُ وَلَدِ آدَمَ وَأَوَّلُ مَنْ تَنْشَقُّ عَنْهُ الْأَرْضُ وَأَوَّلُ شَافِعٍ وَأَوَّلُ مُشَفَّعٍ","id":"Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Abu Ammar] dari [Abdullah bin Farrukh] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku adalah pemimpin anak Adam, orang yang pertama kali keluar dari perut bumi (dibangkitkan) dan orang yang pertama kali memberi syafaat dan mendapat izin untuk memberikannya.\""},"3910":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ وَمَخْلَدُ بْنُ خَالِدٍ الشَّعِيرِيُّ الْمَعْنَى قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَدْرِي أَتُبَّعٌ لَعِينٌ هُوَ أَمْ لَا وَمَا أَدْرِي أَعُزَيْرٌ نَبِيٌّ هُوَ أَمْ لَا","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutawakkil Al Asqalani] dan [Muhammad bin Khalid Asy Sya'iri] secara makna, ia berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Abu Dzi'b] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak tahu apakah Tubba' adalah orang yang terlaknat atau tidak, dan aku tidak tahu apakah Uzair adalah seorang Nabi atau bukan.\""},"3911":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا أَوْلَى النَّاسِ بِابْنِ مَرْيَمَ الْأَنْبِيَاءُ أَوْلَادُ عَلَّاتٍ وَلَيْسَ بَيْنِي وَبَيْنَهُ نَبِيٌّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Abu Salamah bin 'Abdurrahman] mengabarkan kepadanya bahwa [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku adalah orang yang paling berhak dengan diri Isa bin Maryam, para Nabi adalah saudara, dan antara aku dengan Isa tidak ada seorang Nabi pun.\""},"3912":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ بِضْعٌ وَسَبْعُونَ أَفْضَلُهَا قَوْلُ لَا إِلَهَ إِلَّا اللَّهُ وَأَدْنَاهَا إِمَاطَةُ الْعَظْمِ عَنْ الطَّرِيقِ وَالْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Suhail bin Abu Shalih] dari [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Iman itu ada tujuh puluh cabang, yang paling tinggi adalah ucapan LAA ILAAHA ILLAALLAH dan yang paling rendah adalah menyingkirkan tulang dari jalan, dan malu adalah bagian dari keimanan.\""},"3913":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي أَبُو جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَإِنَّ وَفْدَ عَبْدِ الْقَيْسِ لَمَّا قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُمْ بِالْإِيمَانِ بِاللَّهِ قَالَ أَتَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهَادَ��ُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَصَوْمُ رَمَضَانَ وَأَنْ تُعْطُوا الْخُمْسَ مِنْ الْمَغْنَمِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepadaku [Yahya bin Sa'id] dari [Syu'bah] berkata, telah menceritakan kepadaku [Abu Hamzah] ia berkata; Aku mendengar [Ibnu Abbas] ia berkata, \"Ketika utusan Abdu Qais datang kepada Rasulullah shallallahu 'alaihi wasallam, beliau memerintahkan mereka untuk beriman kepada Allah. Beliau bertanya: \"Tahukah kalian yang dimaksud dengan iman kepada Allah?\" para sahabat menjawab, \"Allah dan Rasul-Nya lebih tahu.\" Beliau bersabda: \"Bersaksi bahwa tidak ada tuhan -yang berhak untuk disembah- selain Allah dan Muhammad adalah Rasulullah, melaksanakan shalat, menunaikan zakat, puasa ramadhan dan engkau keluarkan seperlima ghanimah.\""},"3914":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْعَبْدِ وَبَيْنَ الْكُفْرِ تَرْكُ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemisah antara seorang hamba dengan kekafiran ada meninggalkan shalat.\""},"3915":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ بَكْرِ بْنِ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ قَالَ مَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَلَا دِينٍ أَغْلَبَ لِذِي لُبٍّ مِنْكُنَّ قَالَتْ وَمَا نُقْصَانُ الْعَقْلِ وَالدِّينِ قَالَ أَمَّا نُقْصَانُ الْعَقْلِ فَشَهَادَةُ امْرَأَتَيْنِ شَهَادَةُ رَجُلٍ وَأَمَّا نُقْصَانُ الدِّينِ فَإِنَّ إِحْدَاكُنَّ تُفْطِرُ رَمَضَانَ وَتُقِيمُ أَيَّامًا لَا تُصَلِّي","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Bakr bin Mudhar] dari [Ibnul Had] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa Rasulullah bersabda: \"Aku tidak pernah melihat seorang yang mempunyai hati, yang agama dan akalnya kurang selain kalian (para wanita).\" Seorang wanita bertanya, \"Apakah kekurangan para wanita dalam hal agama dan akal?\" beliau bersabda: \"Kurangnya akal itu adalah, bahwa persaksian dua orang wanita sebanding dengan persaksian seorang laki-laki. Sedangkan kurangnya agama kalian adalah, bahwa salah seorang dari kalian berbuka di sebagian ramadhan (karena haidh atau menyusui) dan tidak mengerjakan shalat selama beberapa hari.\""},"3916":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا تَوَجَّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ فَكَيْفَ الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam (Shalat) menghadap ke arah Ka'bah orang-orang bertanya, \"Wahai Rasulullah, bagaimana dengan orang-orang yang telah meninggal, sementara mereka (dahulu) shalat menghadap ke arah Baitul Maqdis?\" Maka Allah Azza Wa Jalla kemudian menurunkan ayat: '(dan Allah tidak akan menyia-nyiakan imanmu) ' -Qs. Al Baqarah: 143-"},"3917":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَحَبَّ لِلَّهِ وَأَبْغَضَ لِلَّهِ وَأَعْطَى لِلَّهِ وَمَنَعَ لِلَّهِ فَقَدْ اسْتَكْمَلَ الْإِيمَانَ","id":"Telah menceritakan kepada kami [Muammal Ibnul Fadhl] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] dari [Yahya Ibnul Harits] dari [Al Qasim] dari [Abu Umamah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mencintai karena Allah, membenci karena Allah, memberi karena Allah dan melarang (menahan) karena Allah, maka sempurnalah imannya.\""},"3918":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْمَلُ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنُهُمْ خُلُقًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum mukminin yang paling baik imannya adalah yang paling baik akhlaknya.\""},"3919":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ ثَوْرٍ عَنْ مَعْمَرٍ قَالَ وَأَخْبَرَنِي الزُّهْرِيُّ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجَالًا وَلَمْ يُعْطِ رَجُلًا مِنْهُمْ شَيْئًا فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ أَعْطَيْتَ فُلَانًا وَفُلَانًا وَلَمْ تُعْطِ فُلَانًا شَيْئًا وَهُوَ مُؤْمِنٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ مُس��لِمٌ حَتَّى أَعَادَهَا سَعْدٌ ثَلَاثًا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَوْ مُسْلِمٌ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أُعْطِي رِجَالًا وَأَدَعُ مَنْ هُوَ أَحَبُّ إِلَيَّ مِنْهُمْ لَا أُعْطِيهِ شَيْئًا مَخَافَةَ أَنْ يُكَبُّوا فِي النَّارِ عَلَى وُجُوهِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] ia berkata; telah mengabarkan kepadaku [Az Zuhri] dari [Amir bin Sa'd bin Abu Waqash] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah memberikan sesuatu kepada beberapa laki-laki, namun tidak memberikan kepada seseorang dari mereka. sa'd lalu berkata, \"Wahai Rasulullah, engkau memberikan kepada si fulan dan si fulan, tetapi engkau tidak memberikan sesuatu pun kepada si fulan yang lain, padahal ia seorang mukmin?\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Ataukah ia hanya seorang muslim?\" ucapan itu Sa'd ulangi hingga tiga kali, dan Nabi shallallahu 'alaihi wasallam selalu mengatakan: \"Ataukah ia hanya seorang muslim?\" setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Aku memberikan kepada beberapa orang dan tidak memberikan kepada sebagian lain yang (dia) lebih aku sukai dari pada mereka, karena kawatir wajah mereka akan dibenamkan ke dalam api.\""},"3920":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ بَشَّارٍ حَدَّثَنَا سُفْيَانُ الْمَعْنَى قَالَا حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَ بَيْنَ الْمُسْلِمِينَ قَسْمًا فَقُلْتُ أَعْطِ فُلَانًا فَإِنَّهُ مُؤْمِنٌ قَالَ أَوْ مُسْلِمٌ إِنِّي لَأُعْطِي الرَّجُلَ الْعَطَاءَ وَغَيْرُهُ أَحَبُّ إِلَيَّ مِنْهُ مَخَافَةَ أَنْ يُكَبَّ عَلَى وَجْهِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Abdurrazaq]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibrahim bin Basysyar] berkata, telah menceritakan kepada kami [Sufyan] secara makna, keduanya berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Amir bin Sa'd] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam membagi-bagikan sesuatu kepada kaum muslimin.\" Aku (Sa'd) lalu berkata, \"Berilah si fulan, sebab ia seorang mukmin.\" Beliau bersabda: \"Ataukah ia hanya seorang muslim? Sungguh, aku memberikan pemberian kepada seorang laki-laki, sementara yang lain (yang tidak diberi) lebih aku sukai darinya; hal itu karena kawatir jika wajahnya akan dibenamkan ke dalam (neraka).\""},"3921":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ وَاقِدُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنِي عَنْ أَبِيهِ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] berkata; [Waqid bin Abdullah] telah mengabarkan kepadaku dari [Bapaknya] bahwasanya ia mendengar [Ibnu Umar] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian kembali kepada kakafiran sepeninggalku, lalu saling bunuh di antara kalian.\""},"3922":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعٌ مَنْ كُنَّ فِيهِ فَهُوَ مُنَافِقٌ خَالِصٌ وَمَنْ كَانَتْ فِيهِ خَلَّةٌ مِنْهُنَّ كَانَ فِيهِ خَلَّةٌ مِنْ نِفَاقٍ حَتَّى يَدَعَهَا إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا عَاهَدَ غَدَرَ وَإِذَا خَاصَمَ فَجَرَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang pada dirinya ada empat hal, maka ia adalah seorang munafik tulen, namun jika hanya ada sebagian, maka pada dirinya ada sebagian sifat munafik hingga ia meninggalkannya; jika berbicara berdusta, jika berjanji mengingkari, jika diberi amanah khianat dan jika berselisih berlaku curang.\""},"3923":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ الْأَنْطَاكِيُّ أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَالتَّوْبَةُ مَعْرُوضَةٌ بَعْدُ","id":"Telah menceritakan kepada kami [Abu Shalih Al Anthaki] berkata, telah mengabarkan kepada kami [Abu Ishaq Al Fazari] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang berzina tidak disebut mukmin saat berzina, seorang pencuri tidak disebut mukmin saat mencuri, seorang peminum khamer tidak disebut mukmin saat minum khamer, dan pintu taubat akan selalu dibuka setelahnya.\""},"3924":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ سُوَيْدٍ الرَّمْلِيُّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعٌ يَعْنِي ابْنَ زَيْدٍ قَالَ حَدَّثَنِي ابْنُ الْهَادِ أَنَّ سَعِيدَ بْنَ أَبِي سَعِيدٍ الْمَقْبُرِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَنَى الرَّجُلُ خَرَجَ مِنْهُ الْإِيمَانُ كَانَ عَلَيْهِ كَالظُّلَّةِ فَإِذَا انْقَطَعَ رَجَعَ إِلَيْهِ الْإِيمَانُ","id":"Telah menceritakan kepada kami [Ishaq bin Suwaid Ar Ramli] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Nafi'] -maksudnya Nafi' bin Zaid- ia berkata; telah menceritakan kepadaku [Ibnul Had] bahwa [Sa'id bin Abu Sa'id Al Maqburi] menceritakan kepadanya, Bahwasanya ia pernah mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang laki-laki berzina maka keimanan yang ada pada dirinya keluar seperti perginya awan, jika telah selesai maka keimanan tersebut kembali kepadanya.\""},"3925":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عُمَرَ بْنِ مُحَمَّدٍ عَنْ عُمَرَ مَوْلَى غُفْرَةَ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ أُمَّةٍ مَجُوسٌ وَمَجُوسُ هَذِهِ الْأُمَّةِ الَّذِينَ يَقُولُونَ لَا قَدَرَ مَنْ مَاتَ مِنْهُمْ فَلَا تَشْهَدُوا جَنَازَتَهُ وَمَنْ مَرِضَ مِنْهُمْ فَلَا تَعُودُوهُمْ وَهُمْ شِيعَةُ الدَّجَّالِ وَحَقٌّ عَلَى اللَّهِ أَنْ يُلْحِقَهُمْ بِالدَّجَّالِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Umar bin Muhammad] dari [Umar] -mantan budak (yang telah dimerdekakan oleh) Ghufrah- dari [seorang laki-laki] Anshar, dari [Hudzaifah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap umat ada majusinya, dan majusinya umat ini adalah orang-orang yang mengatakan 'tidak ada takdir'. Jika ada yang meninggal dari mereka maka jangan kalian jenguk jenazahnya, dan jika ada yang sakit dari mereka maka jangan kalian jengguk. Mereka adalah kelompoknya Dajjal, maka telah menjadi hak Allah untuk menggabungkan mereka dengan Dajjal.\""},"3926":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ يَزِيدَ بْنَ زُرَيْعٍ وَيَحْيَى بْنَ سَعِيدٍ حَدَّثَاهُمْ قَالَا حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنَا قَسَامَةُ بْنُ زُهَيْرٍ قَالَ حَدَّثَنَا أَبُو مُوسَى الْأَشْعَرِيُّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ خَلَقَ آدَمَ مِنْ قَبْضَةٍ قَبَضَهَا مِنْ جَمِيعِ الْأَرْضِ فَجَاءَ بَنُو آدَمَ عَلَى قَدْرِ الْأَرْضِ جَاءَ مِنْهُمْ الْأَحْمَرُ وَالْأَبْيَضُ وَالْأَسْوَدُ وَبَيْنَ ذَلِكَ وَالسَّهْلُ وَالْحَزْنُ وَالْخَبِيثُ وَالطَّيِّبُ زَادَ فِي حَدِيثِ يَحْيَى وَبَيْنَ ذَلِكَوَالْإِخْبَارُ فِي حَدِيثِ يَزِيدَ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Yazid bin Zurai'] dan [Yahya bin Sa'id] menceritakan kepada mereka, keduanya berkata; telah menceritakan kepada kami [Auf] ia berkata; telah menceritakan kepada kami [Qasamah bin Zuhair] ia berkata; telah menceritakan kepada kami [Abu Musa Al Asy'ari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menciptakan Adam dari segenggam tanah dari semua jenis tanah. Kemudian keturunannya datang beragam sesuai dengan unsur tanahnya. Ada di antara mereka yang berkulit merah, putih, hitam, dan antara warna-warna itu. Ada yang lembut dan ada yang kasar, ada yang buruk dan ada yang baik.\" Dan ada tambahan dalam hadits Yahya; \"dan ada pula di antara (sifat) itu\", adapun lafadz (redaksi) hadits di atas adalah riwayat Yazid. "},"3927":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسٌ عَنْ ابْنِ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ قَالَ كَانَ أَوَّلَ مَنْ تَكَلَّمَ فِي الْقَدَرِ بِالْبَصْرَةِ مَعْبَدٌ الْجُهَنِيُّ فَانْطَلَقْتُ أَنَا وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيُّ حَاجَّيْنِ أَوْ مُعْتَمِرَيْنِ فَقُلْنَا لَوْ لَقِينَا أَحَدًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهُ عَمَّا يَقُولُ هَؤُلَاءِ فِي الْقَدَرِ فَوَفَّقَ اللَّهُ لَنَا عَبْدَ اللَّهِ بْنَ عُمَرَ دَاخِلًا فِي الْمَسْجِدِ فَاكْتَنَفْتُهُ أَنَا وَصَاحِبِي فَظَنَنْتُ أَنَّ صَاحِبِي سَيَكِلُ الْكَلَامَ إِلَيَّ فَقُلْتُ أَبَا عَبْدِ الرَّحْمَنِ إِنَّهُ قَدْ ظَهَرَ قِبَلَنَا نَاسٌ يَقْرَءُونَ الْقُرْآنَ وَيَتَفَقَّرُونَ الْعِلْمَ يَزْعُمُونَ أَنْ لَا قَدَرَ وَالْأَمْرَ أُنُفٌ فَقَالَ إِذَا لَقِيتَ أُولَئِكَ فَأَخْبِرْهُمْ أَنِّي بَرِيءٌ مِنْهُمْ وَهُمْ بُرَآءُ مِنِّي وَالَّذِي يَحْلِفُ بِهِ عَبْدُ اللَّهِ بْنُ عُمَرَ لَوْ أَنَّ لِأَحَدِهِمْ مِثْلَ أُحُدٍ ذَهَبًا فَأَنْفَقَهُ مَا قَبِلَهُ اللَّهُ مِنْهُ حَتَّى يُؤْمِنَ بِالْقَدَرِ ثُمَّ قَالَ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ طَلَعَ عَلَيْنَا رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ شَدِيدُ سَوَادِ الشَّعْرِ لَا يُرَى عَلَيْهِ أَثَرُ السَّفَرِ وَلَا نَعْرِفُهُ حَتَّى جَلَسَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْنَدَ رُكْبَتَيْهِ إِلَى رُكْبَتَيْهِ وَوَضَعَ كَفَّيْهِ عَلَى فَخِذَيْهِ وَقَالَ يَا مُحَمَّدُ أَخْبِرْنِي عَنْ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِسْلَامُ أَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ وَتَصُومَ رَمَضَانَ وَتَحُجَّ الْبَيْتَ إِنْ اسْتَطَعْتَ إِلَيْهِ سَبِيلًا قَالَ صَدَقْتَ قَالَ فَعَجِبْنَا لَهُ يَسْأَلُهُ وَيُصَدِّقُهُ قَالَ فَأَخْبِرْنِي عَنْ الْإِيمَانِ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الْآخِرِ وَتُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ قَالَ صَدَقْتَ قَالَ فَأَخْبِرْنِي عَنْ الْإِحْسَانِ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ فَأَخْبِرْنِي عَنْ السَّاعَةِ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ قَالَ فَأَخْبِرْنِي عَنْ أَمَارَاتِهَا قَالَ أَنْ تَلِدَ الْأَمَةُ رَبَّتَهَا وَأَنْ تَرَى الْحُفَاةَ الْعُرَاةَ الْعَالَةَ رِعَاءَ الشَّاءِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ قَالَ ثُمَّ انْطَلَقَ فَلَبِثْتُ ثَلَاثًا ثُمَّ قَالَ يَا عُمَرُ هَلْ تَدْرِي مَنْ السَّائِلُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ جِبْرِيلُ أَتَاكُمْ يُعَلِّمُكُمْ دِينَكُمْحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُثْمَانَ بْنِ غِيَاثٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ وَحُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَا لَقِيَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ فَذَكَرْنَا لَهُ الْقَدَرَ وَمَا يَقُولُونَ فِيهِ فَذَكَرَ نَحْوَهُ زَادَ قَالَ وَسَأَلَهُ رَجُلٌ مِنْ مُزَيْنَةَ أَوْ جُهَيْنَةَ فَقَالَ يَا رَسُولَ اللَّهِ فِيمَا نَعْمَلُ أَفِي شَيْءٍ قَدْ خَلَا أَوْ مَضَى أَوْ فِي شَيْءٍ يُسْتَأْنَفُ الْآنَ قَالَ فِي شَيْءٍ قَدْ خَلَا وَمَضَى فَقَالَ الرَّجُلُ أَوْ بَعْضُ الْقَوْمِ فَفِيمَ الْعَمَلُ قَالَ إِنَّ أَهْلَ الْجَنَّةِ يُيَسَّرُونَ لِعَمَلِ أَهْلِ الْجَنَّةِ وَإِنَّ أَهْلَ النَّارِ يُيَسَّرُونَ لِعَمَلِ أَهْلِ النَّارِ حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا عَلْقَمَةُ بْنُ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ ابْنِ يَعْمَرَ بِهَذَا الْحَدِيثِ يَزِيدُ وَيَنْقُصُ قَالَ فَمَا الْإِسْلَامُ قَالَ إِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَحَجُّ الْبَيْتِ وَصَوْمُ شَهْرِ رَمَضَانَ وَالِاغْتِسَالُ مِنْ الْجَنَابَةِ قَالَ أَبُو دَاوُد عَلْقَمَةُ مُرْجِئٌ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Kahmas] dari [Ibnu Buraidah] dari [Yahya bin Ya'mar] ia berkata, \"Orang yang pertama kali berbicara masalah takdir di kota Basrah adalah Ma'bad Al Juhani. Aku dan Humaid bin 'Abdurrahman Al Himyari pergi untuk berhaji atau umrah. Kami lalu bergumam, \"Jika nanti kami bertemu dengan salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, maka akan kami tanyakan kepadanya tentang apa yang dikatakan oleh orang-orang seputar takdir. Lalu Allah mentakdirkan kami bertemu dengan [Abdullah bin Umar] ketika ia akan masuk ke dalam masjid, sehingga aku dan sahabatku itu mendekatinya. Aku mengira sahabatku akan mewakilkan pembicaraan itu kepadaku, maka aku pun berkata, \"Wahai Abu 'Abdurrahman, di antara kami telah muncul orang-orang yang membaca Al-Qur'an dan tekun dalam menuntut ilmu, namun mereka menyakini bahwa tidak ada takdir, dan sesuatu itu terjadi begitu saja tanpa ada campur tangan takdir!\" Ibnu Umar lalu berkata, \"Jika kalian berjumpa dengan mereka maka katakanlah bahwa aku berlepas diri dari mereka dan mereka juga berlepas diri dariku. Dan demi Dzat yang Abdullah bin Umar bersumpah atas nama-Nya, sekiranya mereka memiliki emas sebesar gunung uhud, lalu mereka menginfakkannya, maka Allah tidak akan menerimanya hingga mereka beriman dengan takdir.\" Kemudian ia berkata, \" [Umar Ibnul Khaththab] menceritakan kepadaku, ia berkata, \"Sewaktu kami sedang bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki yang mengenakan pakaian yang sangat putih dan rambutnya sangat hitam. Tidak ada tanda-tanda bahwa ia dalam perjalanan yang jauh, namun tidak seorang pun dari kami yang mengenalnya. Kemudian ia mendekati Rasulullah shallallahu 'alaihi wasallam, ia menyandarkan lututnya pada lutut Nabi dan meletakkan kedua telapak tangannya pada kedua paha beliau. Setelah itu ia berkata, \"Wahai Muhammad, kabarkanlah kepadaku tentang Islam?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Islam itu adalah engkau bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah dan Muhammad adalah utusan-Nya. Engkau tegakkan shalat, engkau tunaikan zakat, engkau kerjakan puasa ramadhan dan berhaji ke Baitullah jika mampu.\" Laki-laki itu berkata, \"Engkau benar.\" Umar berkata, \"Kami pun merasa heran kepadanya, ia yang bertanya dan ia sendiri yang membenarkannya\". Laki-laki itu bertanya lagi, \"Kabarkanlah kepadaku tentang iman?\" beliau menjawab: \"Iman adalah engkau beriman kepada Allah, para malaikat-Nya, kitab-kitab-Nya, para Rasul-Nya, hari akhir dan beriman dengan takdir; yang buruk atau yang baik.\" Laki-laki itu berkata, \"Engkau benar.\" Laki-laki itu melanjutkan, \"Kabarkanlah kepadaku apa itu ihsan?\" beliau menjawab: \"Engkau beribadah kepada Allah seakan-akan melihat-Nya, jika engkau tidak dapat melihat-Nya, sesungguhnya Ia dapat melihatmu.\" Laki-laki itu bertanya lagi, \"Kabarkanlah kepadaku tentang hari kiamat?\" beliau menjawab: \"tidaklah orang yang ditanya lebih tahu dari pada yang bertanya.\" Laki-laki itu bertanya, \"Kalau begitu, kabarkanlah kepadaku tanda-tandanya?\" beliau menjawab: \"Jika seorang budak telah melahirkan tuannya, lalu engkau melihat orang-orang yang telanjang kaki (miskin) lagi pengembala domba telah berlomba-lomba membuat bangunan yang tinggi.\" Umar berkata, \"Laki-laki itu lalu pergi, dan aku tetap berdiam diri selama tiga hari. Kemudian beliau bersabda: \"Wahai Umar, tahukah kamu siapa laki-laki yang bertanya itu?\" Aku menjawab, \"Allah dan Rasul-Nya lebih tahu. Beliau bersabda: \"Itu adalah Jibril, ia datang kepada kalian untuk mengajarkan tentang perkara agama kalian.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Utsman bin Ghiyats] ia berkata; telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dan [Humaid bin 'Abdurrahman] keduanya berkata, \"Kami bertemu dengan [Abdullah bin Umar], lalu kami ceritakan kepdanya tentang takdir dan apa yang orang-orang katakan tentang hal itu…. lalu ia menyebutkan sebagaimana hadits tersebut. Namun ia menambahkan, ia berkata \"Lalu ada seorang laki-laki dari Muzainah atau Juhainah bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Wahai Rasulullah, bagaimana kita harus beramal? Apakah amalan itu berdasar pada takdir yang telah berlalu atau berdasar pada sesuatu yang baru?\" beliau menjawab: \"Berdasarkan pada sesuatu yang telah ditetapkan.\" Laki-laki itu, atau sebagian orang bertanya lagi, \"Lalu untuk apa kita beramal?\" beliau menjawab: \"Sesungguhnya ahli surga akan dimudahkan untuk beramal dengan amalan penduduk surga, dan ahli neraka akan dimudahkan untuk beramal dengan amalan penduduk neraka.\" Telah menceritakan kepada kami [Mahmud bin Khalid] berkata, telah menceritakan kepada kami [Al Firyabi] dari [Sufyan] ia berkata; telah menceritakan kepada kami [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Ibnu Ya'mar] dengan hadits yang sama, \"bertambah dan berkurang.\" Ia bertanya, \"Lalu Islam itu apa?\" Beliau menjawab: \"Menegakkan shalat, menunaikan zakat, melaksanakan haji, puasa pada bulan ramadhan, dan mandi junub.\" Abu Dawud berkata, \"Alqamah adalah seorang murjiah.\""},"3928":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ أَبِي فَرْوَةَ الْهَمْدَانِيِّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي ذَرٍّ وَأَبِي هُرَيْرَةَ قَالَاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ بَيْنَ ظَهْرَيْ أَصْحَابِهِ فَيَجِيءُ الْغَرِيبُ فَلَا يَدْرِي أَيُّهُمْ هُوَ حَتَّى يَسْأَلَ فَطَلَبْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَجْعَلَ لَهُ مَجْلِسًا يَعْرِفُهُ الْغَرِيبُ إِذَا أَتَاهُ قَالَ فَبَنَيْنَا لَهُ دُكَّانًا مِنْ طِينٍ فَجَلَسَ عَلَيْهِ وَكُنَّا نَجْلِسُ بِجَنْبَتَيْهِ وَذَكَرَ نَحْوَ هَذَا الْخَبَرِ فَأَقْبَلَ رَجُلٌ فَذَكَرَ هَيْئَتَهُ حَتَّى سَلَّمَ مِنْ طَرَفِ السِّمَاطِ فَقَالَ السَّلَامُ عَلَيْكَ يَا مُحَمَّدُ قَالَ فَرَدَّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Abu Farwah Al Hamdani] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Dzar] dan [Abu Hurairah] keduanya berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam duduk bersama para sahabatnya, tiba-tiba datang orang asing dan tidak seorang pun dari kami yang mengenalnya, hingga ia minta untuk bertemu (beliau). Lalu kami minta izin kepada beliau untuk membuat tempat duduk, hingga orang-orang asing dapat berjumpa dengannya. Kemudian kami membuatkan beliau tempat duduk dari tanah liat yang agak tinggi, lalu beliau duduk di atasnya sementara kami duduk di sampingnya… Lalu ia menyebutkan sebagaimana hadits tersebut. Kemudian datanglah seorang laki-laki…lalu ia menyebutkan keadaan laki-laki itu hingga ia pun mengucapkan salam dari ujung para jama'ah, ia mengucapkan, \"Semoga keselamatan atas kamu wahai Muhammad.\" Ia (perawi) berkata, \"Nabi shallallahu 'alaihi wasallam lalu manjawab salamnya.\""},"3929":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي سِنَانٍ عَنْ وَهْبِ بْنِ خَالِدٍ الْحِمْصِيِّ عَنْ ابْنِ الدَّيْلَمِيِّ قَالَ أَتَيْتُ أُبَيَّ بْنَ كَعْبٍ فَقُلْتُ لَهُوَقَعَ فِي نَفْسِي شَيْءٌ مِنْ الْقَدَرِ فَحَدِّثْنِي بِشَيْءٍ لَعَلَّ اللَّهَ أَنْ يُذْهِبَهُ مِنْ قَلْبِي قَالَ لَوْ أَنَّ اللَّهَ عَذَّبَ أَهْلَ سَمَاوَاتِهِ وَأَهْلَ أَرْضِهِ عَذَّبَهُمْ وَهُوَ غَيْرُ ظَالِمٍ لَهُمْ وَلَوْ رَحِمَهُمْ كَانَتْ رَحْمَتُهُ خَيْرًا لَهُمْ مِنْ أَعْمَالِهِمْ وَلَوْ أَنْفَقْتَ مِثْلَ أُحُدٍ ذَهَبًا فِي سَبِيلِ اللَّهِ مَا قَبِلَهُ اللَّهُ مِنْكَ حَتَّى تُؤْمِنَ بِالْقَدَرِ وَتَعْلَمَ أَنَّ مَا أَصَابَكَ لَمْ يَكُنْ لِيُخْطِئَكَ وَأَنَّ مَا أَخْطَأَكَ لَمْ يَكُنْ لِيُصِيبَكَ وَلَوْ مُتَّ عَلَى غَيْرِ هَذَا لَدَخَلْتَ النَّارَقَالَ ثُمَّ أَتَيْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ فَقَالَ مِثْلَ ذَلِكَ قَالَ ثُمَّ أَتَيْتُ حُذَيْفَةَ بْنَ الْيَمَانِ فَقَالَ مِثْلَ ذَلِكَ قَالَ ثُمَّ أَتَيْتُ زَيْدَ بْنَ ثَابِتٍ فَحَدَّثَنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Abu Sinan] dari [Wahb bin Khalid Al Himshi] dari [Ibnu Ad Dailami] ia berkata, \"Aku mendatangi [Ubay bin Ka'b], lalu aku katakan kepadanya, \"Ada sesuatu yang mengganjal dalam hatiku tentang perkara takdir, maka ceritakanlah kepadaku tentang sesuatu semoga Allah menghilangkan keresahan itu dari dalam hatiku.\" Ia menjawab, \"Jika Allah menyiksa semua makluk yang ada di langit dan di bumi, maka itu bukanlah suatu kezhaliman yang Dia lakukan atas mereka, dan sekiranya Dia memberikan rahmat kepada mereka, sesungguhnya rahmat-Nya adalah lebih baik dari amalan yang telah mereka lakukan. Jika engkau bersedekah dengan emas sebesar gunung uhud di jalan Allah, maka Allah tidak akan menerimanya hingga engkau beriman dengan takdir. Dan engkau mengetahui bahwa apa saja yang ditakdirkan menjadi bagianmu tidak akan meleset darimu, dan apa yang tidak ditakdirkan untuk menjadi bagianmu tidak akan engkau dapatkan. Jika engkau meninggal bukan di atas keyakinan yang demikian ini, maka engkau akan masuk neraka.\" Abu Ad Dailami berkata, \"Kemudian aku mendatangi [Abdullah bin Mas'ud], lalu ia mengatakan seperti itu pula. Aku lalu mendatangi [Hudzaifah Ibnul Yaman], lalu ia mengatakan seperti itu pula. Kemudian aku mendatangi [Zaid bin Tsabit], lalu ia menceritakan kepadaku sebuah hadits Nabi shallallahu 'alaihi wasallam seperti itu pula.\""},"3930":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ الْمَعْنَى قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ طَاوُسًا يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يُخْبِرُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّ آدَمُ وَمُوسَى فَقَالَ مُوسَى يَا آدَمُ أَنْتَ أَبُونَا خَيَّبْتَنَا وَأَخْرَجْتَنَا مِنْ الْجَنَّةِ فَقَالَ آدَمُ أَنْتَ مُوسَى اصْطَفَاكَ اللَّهُ بِكَلَامِهِ وَخَطَّ لَكَ التَّوْرَاةَ بِيَدِهِ تَلُومُنِي عَلَى أَمْرٍ قَدَّرَهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي بِأَرْبَعِينَ سَنَةً فَحَجَّ آدَمُ مُوسَىقَالَ أَحْمَدُ بْنُ صَالِحٍ عَنْ عَمْرٍو عَنْ طَاوُسٍ سَمِعَ أَبَا هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Shalih] secara makna, ia berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] ia mendengar [Thawus] berkata; Aku mendengar [Abu Hurairah] mengabarkan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Adam dan Musa saling berargumentasi. Musa berkata, \"Wahai Adam, engkau adalah bapak kami, engkau telah merugikan kami dan engkau telah menjadikan kami keluar dari surga! Adam menjawab, \"Wahai Musa, Allah telah memilih dan memberimu kitab Taurat, kenapa engaku menyalahkan aku atas suatu perkara yang Allah telah tetapkan terhadapku empat puluh tahun sebelum aku diciptakan?\" Maka Adam dapat mengalahkan Musa.\" Ahmad bin Shalih menyebutkan dari Amru, dari Thawus, ia mendengar dari Abu Hurairah. "},"3931":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَقَالَ رَسُولُ ا��لَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مُوسَى قَالَ يَا رَبِّ أَرِنَا آدَمَ الَّذِي أَخْرَجَنَا وَنَفْسَهُ مِنْ الْجَنَّةِ فَأَرَاهُ اللَّهُ آدَمَ فَقَالَ أَنْتَ أَبُونَا آدَمُ فَقَالَ لَهُ آدَمُ نَعَمْ قَالَ أَنْتَ الَّذِي نَفَخَ اللَّهُ فِيكَ مِنْ رُوحِهِ وَعَلَّمَكَ الْأَسْمَاءَ كُلَّهَا وَأَمَرَ الْمَلَائِكَةَ فَسَجَدُوا لَكَ قَالَ نَعَمْ قَالَ فَمَا حَمَلَكَ عَلَى أَنْ أَخْرَجْتَنَا وَنَفْسَكَ مِنْ الْجَنَّةِ فَقَالَ لَهُ آدَمُ وَمَنْ أَنْتَ قَالَ أَنَا مُوسَى قَالَ أَنْتَ نَبِيُّ بَنِي إِسْرَائِيلَ الَّذِي كَلَّمَكَ اللَّهُ مِنْ وَرَاءِ الْحِجَابِ لَمْ يَجْعَلْ بَيْنَكَ وَبَيْنَهُ رَسُولًا مِنْ خَلْقِهِ قَالَ نَعَمْ قَالَ أَفَمَا وَجَدْتَ أَنَّ ذَلِكَ كَانَ فِي كِتَابِ اللَّهِ قَبْلَ أَنْ أُخْلَقَ قَالَ نَعَمْ قَالَ فِيمَ تَلُومُنِي فِي شَيْءٍ سَبَقَ مِنْ اللَّهِ تَعَالَى فِيهِ الْقَضَاءُ قَبْلِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ فَحَجَّ آدَمُ مُوسَى فَحَجَّ آدَمُ مُوسَى","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Bapaknya] bahwa [Umar Ibnul Khaththab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Musa berkata, \"Wahai Rabb, perlihatkanlah kepadaku Adam, orang yang telah mengeluarkan kami dan dirinya dari surga.\" Lalu Allah memperlihatkan Adam kepadanya, Musa pun berkata, \"Engkau Adam bapak kami!\" Adam menjawab, \"Benar.\" Musa berkata lagi, \"Engkaukah orang yang telah ditiupkan ruh oleh Allah, diberikan pengetahuan tentang nama-nama segala sesuatu, dan Allah memerintahkan para malaikat untuk sujud, lalu mereka sujud kepadamu?\" Adam menjawab, \"Benar.\" Musa bertanya, \"Lalu apa yang mendorongmu untuk mengeluarkan kami serta dirimu dari surga?\" Adam balik bertanya, \"Lalu kamu sendiri siapa?\" Musa menjawab, \"Aku adalah Musa.\" Adam bertanya, \"Kamukah Nabi dari kalangan bani Isra'il yang Allah telah mengajakmu berbicara dari balik tabir tanpa ada seorang perantara?\" Musa menjawab, \"Benar.\" Adam bertanya, \"Tidakkah engkau mengerti bahwa itu semua sudah ditentukan oleh Allah dalam kitab-Nya (Al Lauhul Mahfudh) sebelum aku diciptakan?\" Musa menjawab, \"Benar.\" Adam bertanya, \"Lalu kenapa engkau menyalahkanku atas sesuatu yang telah ditentukan Allah sebelum aku (diciptakan)?\" Ketika itu Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Adam mengalahkan Musa, Adam mengalahkan Musa.\""},"3932":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ رَقَبَةَ بْنِ مَصْقَلَةَ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغُلَامُ الَّذِي قَتَلَهُ الْخَضِرُ طُبِعَ كَافِرًا وَلَوْ عَاشَ لَأَرْهَقَ أَبَوَيْهِ طُغْيَانًا وَكُفْرًا","id":"Telah menceritakan kepada kami [Al Qa'nabi] berkata, telah menceritakan kepada kami [Al Mu'tamir] dari [Bapaknya] dari [Raqabah bin Mashqalah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak kecil yang dibunuh oleh Khidhir ditakdirkan untuk menjadi kafir, jika ia tetap hidup maka ia akan berlaku zhalim kepada kedua orang tuanya dan berlaku kufur.\""},"3933":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ إِسْرَائِيلَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَنَا أُبَيُّ بْنُ كَعْبٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي قَوْلِهِ{ وَأَمَّا الْغُلَامُ فَكَانَ أَبَوَاهُ مُؤْمِنَيْنِ }وَكَانَ طُبِعَ يَوْمَ طُبِعَ كَافِرًا","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] berkata, telah menceritakan kepada kami [Al firyabi] dari [Isra'il] berkata, telah menceritakan kepada kami [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Telah menceritakan kepada kami [Ubay bin Ka'b] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda tentang firman Allah: (dan adapun anak itu, maka kedua orangtuanya adalah orang-orang mukmin) -Qs. Al Kahfi: 80-. Beliau mengatakan: \"Anak itu telah ditakdirkan untuk menjadi kafir.\""},"3934":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قَالَ ابْنُ عَبَّاسٍ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبْصَرَ الْخَضِرُ غُلَامًا يَلْعَبُ مَعَ الصِّبْيَانِ فَتَنَاوَلَ رَأْسَهُ فَقَلَعَهُ فَقَالَ مُوسَى{ أَقَتَلْتَ نَفْسًا زَكِيَّةً }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran Ar Razi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru] dari [Sa'id bin Jubair] ia berkata; [Ibnu Abbas] berkata; telah menceritakan kepadaku [Ubay bin Ka'b] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Khidhir melihat seorang anak kecil yang sedang bermain dengan anak-anak yang lainnya, lalu ia memegang kepala anak tersebut dan membunuhnya. Musa bertanya, \"Mengapa kamu bunuh jiwa yang bersih?\" -Qs. Al Kahfi: 74-. "},"3935":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam pernah ditanya tentang anak-anak kaum musyrikin? Beliau lalu menjawab: \"Allah lebih tahu dengan yang mereka lakukan.\""},"3936":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بَقِيَّةُ ح و حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ وَكَثِيرُ بْنُ عُبَيْدٍ الْمَذْحِجِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ الْمَعْنَى عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ ذَرَارِيُّ الْمُؤْمِنِينَ فَقَالَ هُمْ مِنْ آبَائِهِمْ فَقُلْتُ يَا رَسُولَ اللَّهِ بِلَا عَمَلٍ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ قُلْتُ يَا رَسُولَ اللَّهِ فَذَرَارِيُّ الْمُشْرِكِينَ قَالَ مِنْ آبَائِهِمْ قُلْتُ بِلَا عَمَلٍ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] berkata, telah menceritakan kepada kami [Baqiyyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa bin Marwan Ar Raqqi] dan [Katsir bin Ubaid Al Madzhiji] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Harb] secara makna, dari [Muhammad bin Ziyad] dari [Abdullah bin Abu Qais] dari ['Aisyah] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, bagaimana nasib anak-anak kecil yang orang tua mereka mukmin?\" beliau menjawab: \"Mereka bagian dari bapak-bapak mereka.\" Aku bertanya lagi, \"Wahai Rasulullah, meskipun mereka tidak punya amal?\" beliau menjawab: \"Allah tahu dengan apa yang mereka lakukan.\" Aku bertanya lagi, \"Wahai Rasulullah, bagaimana dengan nasib anak-anak kaum musyrikin?\" beliau menjawab: \"Mereka bagian dari bapak-bapak mereka.\" Aku bertanya lagi, \"Wahai Rasulullah, meskipun mereka tidak punya amal?\" beliau menjawab: \"Allah tahu dengan apa yang mereka lakukan.\""},"3937":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ مِنْ الْأَنْصَارِ يُصَلِّي عَلَيْهِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ طُوبَى لِهَذَا لَمْ يَعْمَلْ شَرًّا وَلَمْ يَدْرِ بِهِ فَقَالَ أَوْ غَيْرُ ذَلِكَ يَا عَائِشَةُ إِنَّ اللَّهَ خَلَقَ الْجَنَّةَ وَخَلَقَ لَهَا أَهْلًا وَخَلَقَهَا لَهُمْ وَهُمْ فِي أَصْلَابِ آبَائِهِمْ وَخَلَقَ النَّارَ وَخَلَقَ لَهَا أَهْلًا وَخَلَقَهَا لَهُمْ وَهُمْ فِي أَصْلَابِ آبَائِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Thalhah bin Yahya] dari ['Aisyah binti Thalhah] dari ['Aisyah] Ummul Mukminin, ia berkata, \"Anak anak kecil dari kaum Anshar (yang telah meninggal) dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, lalu beliau menshalatinya. 'Aisyah berkata, \"Aku bertanya, \"Wahai Rasulullah, beruntung sekali anak kecil ini, ia belum pernah melakukan keburukan dan belum mengenalnya.\" Beliau balik berkata, \"Atau, bahkan tidak demikian wahai 'Aisyah. sesungguhnya Allah menciptakan surga dan menciptakan pula orang-orang yang bakal menghuninya. Allah menciptakan surga bagi mereka di saat mereka masih berada di dalam sulbi orang tua mereka. Allah menciptakan neraka dan menciptakan pula orang-orang yang bakal menghuninya. Allah menciptakan neraka bagi mereka di saat mereka masih berada di dalam sulbi orang tua mereka.\""},"3938":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَوْلُودٍ يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ وَيُنَصِّرَانِهِ كَمَا تَنَاتَجُ الْإِبِلُ مِنْ بَهِيمَةٍ جَمْعَاءَ هَلْ تُحِسُّ مِنْ جَدْعَاءَ قَالُوا يَا رَسُولَ اللَّهِ أَفَرَأَيْتَ مَنْ يَمُوتُ وَهُوَ صَغِيرٌ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap bayi dilahirkan dalam keadaan fitrah, maka kedua orang tuannya-lah yang menjadikan ia yahudi atau nashrani. Sebagaimana unta melahirkan anaknya yang sehat, apakah kamu melihatnya memiliki aib?\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana dengan orang yang meninggal saat masih kecil?\" Beliau menjawab: \"Allah lebih tahu dengan yang mereka lakukan.\""},"3939":{"ar":"قَالَ أَبُو دَاوُد قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا أَسْمَعُ أَخْبَرَكَ يُوسُفُ بْنُ عَمْرٍو أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ مَالِكًاقِيلَ لَهُ إِنَّ أَهْلَ الْأَهْوَاءِ يَحْتَجُّونَ عَلَيْنَا بِهَذَا الْحَدِيثِ قَالَ مَالِكٌ احْتَجَّ عَلَيْهِمْ بِآخِرِهِ قَالُوا أَرَأَيْتَ مَنْ يَمُوتُ وَهُوَ صَغِيرٌ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Abu Dawud berkata, \"Dibacakan dihadapan [Al Harits bin Miskin] -dan aku mendengar- berkata; [Yusuf bin Amru] mengabarkan kepadamu, ia berkata; telah mengabarkan kepada kami [Ibnu Wahb] ia berkata; Aku mendengar [Malik] ditanya, \"Sesungguhnya orang-orang yang mengikuti hawa nafsu menjadikan hadits ini sebagai hujah atas kami?\" Malik berkata, \"Bantahlah hujah mereka dengan kalimat terakhir dalam hadits tersebut.\" Mereka bertanya lagi, \"Apa pendapatmu dengan orang yang meninggal saat masih kecil?\" Malik menjawab, \"Allah lebih tahu dengan apa yang ia lakukan.\""},"3940":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا حَجَّاجُ بْنُ الْمِنْهَالِ قَالَ سَمِعْتُ حَمَّادَ بْنَ سَلَمَةَ يُفَسِّرُ حَدِيثَكُلُّ مَوْلُودٍ يُولَدُ عَلَى الْفِطْرَةِ قَالَ هَذَا عِنْدَنَا حَيْثُ أَخَذَ اللَّهُ عَلَيْهِمْ الْعَهْدَ فِي أَصْلَابِ آبَائِهِمْ حَيْثُ قَالَ{ أَلَسْتُ بِرَبِّكُمْ قَالُوا بَلَى }","id":"Telah menceritakan kepada kami [Al hasan bin Ali] berkata, telah menceritakan kepada kami [Hajjaj Ibnul Minhal] ia berkata; Aku mendengar [Hammad bin Salamah] mentafsirkan hadits, 'Setiap bayi dilahirkan dalam keadaan fitrah', ia berkata, \"Menurut kami, ini adalah perjanjian yang Allah ambil saat mereka masih berada di tulang sulbi bapak-bapak mereka. Yaitu saat Allah berfirman: '(Bukankah Aku Tuhanmu, mereka menjawab, \"Betul, (Engkau Tuhan kami).\" -Qs. Al A'raf: 172-. "},"3941":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي أَبِي عَنْ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَائِدَةُ وَالْمَوْءُودَةُ فِي النَّارِقَالَ يَحْيَى بْنُ زَكَرِيَّا قَالَ أَبِي فَحَدَّثَنِي أَبُو إِسْحَقَ أَنَّ عَا��ِرًا حَدَّثَهُ بِذَلِكَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] berkata, telah menceritakan kepada kami [Ibnu Abu Zaidah] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Amir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita yang mengubur anaknya hidup-hidup dan yang dikubur masuk ke dalam neraka.\" [Yahya bin Zakariya] berkata; [Bapakku] berkata; [Abu Ishaq] menceritakan kepadaku bahwa [Amir] menceritakan hal itu kepadanya, dari [Alqamah], dari [Ibnu Mas'ud], dari Nabi shallallahu 'alaihi wasallam.\""},"3942":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَيْنَ أَبِي قَالَ أَبُوكَ فِي النَّارِ فَلَمَّا قَفَّى قَالَ إِنَّ أَبِي وَأَبَاكَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] berkata, \"Seorang laki-laki berkata, \"Wahai Rasulullah, dimanakah bapakku?\" beliau menjawab: \"Bapakmu ada di neraka.\" Ketika laki-laki itu berlalu pergi, beliau bersabda: \"Sesungguhnya bapakku dan bapakmu ada di dalam neraka.\""},"3943":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ مَجْرَى الدَّمِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan mengalir dalam pembuluh anak Adam layaknya aliran darah.\""},"3944":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ لَهِيعَةَ وَعَمْرُو بْنُ الْحَارِثِ وَسَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ عَطَاءِ بْنِ دِينَارٍ عَنْ حَكِيمِ بْنِ شَرِيكٍ الْهُذَلِيِّ عَنْ يَحْيَى بْنِ مَيْمُونٍ عَنْ رَبِيعَةَ الْجُرَشِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُجَالِسُوا أَهْلَ الْقَدَرِ وَلَا تُفَاتِحُوهُمْ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al hamdani] berkata, telah mengabarkan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Ibnu Lahi'ah] dan [Amru bin Al harits] dan [Sa'id bin Abu Ayyub] dari [Atha bin Dinar] dari [Hakim bin Syarik Al Hudzali] dari [Yahya bin Maimun] dari [Rabi'ah Al jurasyi] dari [Abu Hurairah] dari [Umar Ibnul Khaththab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian duduk bersama orang-orang yang menolak takdir dan jangan kalian serahkan perkara itu kepada hakim mereka.\""},"3945":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ النَّاسُ يَتَسَاءَلُونَ حَتَّى يُقَالَ هَذَا خَلَقَ اللَّهُ الْخَلْقَ فَمَنْ خَلَقَ اللَّهَ فَمَنْ وَجَدَ مِنْ ذَلِكَ شَيْئًا فَلْيَقُلْ آمَنْتُ بِاللَّهِ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] berkata, telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan selalu bertanya-tanya hingga dikatakan, 'Ini makhluk yang Allah telah menciptakannya, lalu siapakan yang menciptakan Allah? ' Maka siapa saja yang mengalami hal semacam itu, hendaklah ia mengatakan 'aku beriman kepada Allah'.\""},"3946":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ قَالَ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَقَ قَالَ حَدَّثَنِي عُتْبَةُ بْنُ مُسْلِمٍ مَوْلَى بَنِي تَيْمٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَ نَحْوَهُ قَالَ فَإِذَا قَالُوا ذَلِكَ فَقُولُوا اللَّهُ أَحَدٌ اللَّهُ الصَّمَدُ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ ثُمَّ لِيَتْفُلْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَسْتَعِذْ مِنْ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Amru] berkata, telah menceritakan kepada kami [Salamah] -maksudnya Salamah Fadhl- ia berkata; telah menceritakan kepadaku [Muhammad] -maksudnya Muahammad bin Ishaq- ia berkata; telah menceritakan kepadaku [Utbah bin Muslim] -mantan budak (yang telah dimerdekakan oleh) Bani Taim- dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, lalu ia menyebutkan seperti hadits tersebut. Beliau bersabda: \"Jika mereka mengucapkan demikian, maka ucapkanlah, \"(Dia-lah Allah, Yang Maha Esa, Allah adalah Tuhan yang bergantung kepada-Nya segala sesuatu. Dia tidak beranak dan tidak pula diperanakkan, dan tidak ada seorang pun yang setara dengan Dia.) ' Setelah itu hendaklah ia meludah ke arah kiri sebanyak tiga kali, dan memohon perlindungan kepada Allah dari setan.\""},"3947":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا الْوَلِيدُ بْنُ أَبِي ثَوْرٍ عَنْ سِمَاكٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمِيرَةَ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَكُنْتُ فِي الْبَطْحَاءِ فِي عِصَابَةٍ فِيهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّتْ بِهِمْ سَحَابَةٌ فَنَظَرَ إِلَيْهَا فَقَالَ مَا تُسَمُّونَ هَذِهِ قَالُوا السَّحَابَ قَالَ وَالْمُزْنَ قَالُوا وَالْمُزْنَ قَالَ وَالْعَنَانَ قَالُوا وَالْعَنَانَ قَالَ أَبُو دَاوُد لَمْ أُتْقِنْ الْعَنَانَ جَيِّدًا قَالَ هَلْ تَدْرُونَ مَا بُعْدُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ قَالُوا لَا نَدْرِي قَالَ إِنَّ بُعْدَ مَا بَيْنَهُمَا إِمَّا وَاحِدَةٌ أَوْ اثْنَتَانِ أَوْ ثَلَاثٌ وَسَبْعُونَ سَنَةً ثُمَّ السَّمَاءُ فَوْقَهَا كَذَلِكَ حَتَّى عَدَّ سَبْعَ سَمَاوَاتٍ ثُمَّ فَوْقَ السَّابِعَةِ بَحْرٌ بَيْنَ أَسْفَلِهِ وَأَعْلَاهُ مِثْلُ مَا بَيْنَ سَمَاءٍ إِلَى سَمَاءٍ ثُمَّ فَوْقَ ذَلِكَ ثَمَانِيَةُ أَوْعَالٍ بَيْنَ أَظْلَافِهِمْ وَرُكَبِهِمْ مِثْلُ مَا بَيْنَ سَمَاءٍ إِلَى سَمَاءٍ ثُمَّ عَلَى ظُهُورِهِمْ الْعَرْشُ مَا بَيْنَ أَسْفَلِهِ وَأَعْلَاهُ مِثْلُ مَا بَيْنَ سَمَاءٍ إِلَى سَمَاءٍ ثُمَّ اللَّهُ تَبَارَكَ وَتَعَالَى فَوْقَ ذَلِكَحَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ سَعْدٍ وَمُحَمَّدُ بْنُ سَعِيدٍ قَالَا أَخْبَرَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ سِمَاكٍ بِإِسْنَادِهِ وَمَعْنَاهُ حَدَّثَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ سِمَاكٍ بِإِسْنَادِهِ وَمَعْنَى هَذَا الْحَدِيثِ الطَّوِيلِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzar] berkata, telah menceritakan kepada kami [Al Walid bin Abu Tsaur] dari [Simak] dari [Abdullah bin Amirah] dari [Al Ahnaf bin Qais] dari [Al Abbas bin Abdul Muthallib] ia berkata, \"Aku pernah berada di wilayah Bathha bersama rombongan yang di dalamnya terdapat Rasulullah shallallahu 'alaihi wasallam. Lalu ada awan yang melintasi mereka, beliau melihat awan itu lalu bersabda: \"Kalian menyebut apa ini?\" para sahabat menjawab, \"Awan.\" Beliau bersabda: \"Dan Al Muzn?\" mereka menjawab, \"Ya, (kami juga menyebutnya) Al Muzn.\" Beliau bersabda: \"Dan Al 'Anan?\" mereka menjawab, \"Ya, dan Al 'Anan.\" -Abu Dawud berkata, \"Aku tidak menghafal lafadz Al 'Anan dengan baik- Beliau lalu bertanya: \"Apakah kalian tahu berapa jarak antara langit dan bumi?\" mereka menjawab, \"Kami tidak tahu.\" Beliau bersabda: \"Sesungguhnya jarak antara keduanya adalah bisa tujuh puluh satu, atau tujuh puluh dua, atau tujuh puluh tiga tahun perjalanan -perawi masih ragu-. kemudian langit yang di atasnya juga seperti itu.\" Hingga beliau menyebutkan tujuh langit. Kemudian setelah langit ketujuh terdapat lautan, jarak antara bawah dan atasnya seperti jarak antara langit dengan langit (yang lain). Kemudian di atasnya terdapat delapan malaikat yang jarak antara telapak kaki dengan lututnya sejauh langit dengan langit yang lainnya. Dan di atas mereka terdapat Arsy, yang antara bagian bawah dengan atasnya sejauh antara langit satu dengan langit yang lainnya. Dan Allah Tabaraka Wa Ta'ala ada di atasnya.\" Telah menceritakan kepada kami [Ahmad bin Abu Suraij] berkata, telah mengabarkan kepada kami ['Abdurrahman bin Abdullah bin Sa'd] dan [Muhammad bin Sa'id] keduanya berkata; telah mengabarkan kepada kami [Amru bin Abu Qais] dari [Simak] dengan sanad dan makna yang sama. Telah menceritakan kepada kami [Ahmad bin Hafsh] ia berkata; telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Simak] dengan sanad yang sama dan makna hadits ini yang panjang. "},"3948":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَأَحْمَدُ بْنُ سَعِيدٍ الرِّبَاطِيُّ قَالُوا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ أَحْمَدُ كَتَبْنَاهُ مِنْ نُسْخَتِهِ وَهَذَا لَفْظُهُ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ يُحَدِّثُ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ جُبَيْرِ بْنِ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ جُهِدَتْ الْأَنْفُسُ وَضَاعَتْ الْعِيَالُ وَنُهِكَتْ الْأَمْوَالُ وَهَلَكَتْ الْأَنْعَامُ فَاسْتَسْقِ اللَّهَ لَنَا فَإِنَّا نَسْتَشْفِعُ بِكَ عَلَى اللَّهِ وَنَسْتَشْفِعُ بِاللَّهِ عَلَيْكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَكَ أَتَدْرِي مَا تَقُولُ وَسَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زَالَ يُسَبِّحُ حَتَّى عُرِفَ ذَلِكَ فِي وُجُوهِ أَصْحَابِهِ ثُمَّ قَالَ وَيْحَكَ إِنَّهُ لَا يُسْتَشْفَعُ بِاللَّهِ عَلَى أَحَدٍ مِنْ خَلْقِهِ شَأْنُ اللَّهِ أَعْظَمُ مِنْ ذَلِكَ وَيْحَكَ أَتَدْرِي مَا اللَّهُ إِنَّ عَرْشَهُ عَلَى سَمَاوَاتِهِ لَهَكَذَا وَقَالَ بِأَصَابِعِهِ مِثْلَ الْقُبَّةِ عَلَيْهِ وَإِنَّهُ لَيَئِطُّ بِهِ أَطِيطَ الرَّحْلِ بِالرَّاكِبِ قَالَ ابْنُ بَشَّارٍ فِي حَدِيثِهِ إِنَّ اللَّهَ فَوْقَ عَرْشِهِ وَعَرْشُهُ فَوْقَ سَمَاوَاتِهِ وَسَاقَ الْحَدِيثَو قَالَ عَبْدُ الْأَعْلَى وَابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ وَجُبَيْرِ بْنِ مُحَمَّدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ وَالْحَدِيثُ بِإِسْنَادِ أَحْمَدَ بْنِ سَعِيدٍ هُوَ الصَّحِيحُ وَافَقَهُ عَلَيْهِ جَمَاعَةٌ مِنْهُمْ يَحْيَى بْنُ مَعِينٍ وَعَلِيُّ بْنُ الْمَدِينِيِّ وَرَوَاهُ جَمَاعَةٌ عَنْ ابْنِ إِسْحَقَ كَمَا قَالَ أَحْمَدُ أَيْضًا وَكَانَ سَمَاعُ عَبْدِ الْأَعْلَى وَابْنِ الْمُثَنَّى وَابْنِ بَشَّارٍ مِنْ نُسْخَةٍ وَاحِدَةٍ فِيمَا بَلَغَنِي","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad] dan [Muhammad Ibnul Mutsanna] dan [Muhammad bin Basysyar] dan [Ahmad bin Sa'id Ar Ribathi] mereka berkata; telah menceritakan kepada kami [Wahb bin Jarir] -Ahmad berkata, \"Kami menulisnya dari buku catatannya, dan ini adalah lafadznya.\"- ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; Aku mendengar [Muhammad bin Ishaq] ia menceritakan dari [Ya'qub bin Utbah] dari [Jubair bin Muhammad bin Jubair bin Muth'im] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Seorang Arab badui mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, jiwa-jiwa telah berat, keluarga telah lemah, harta berkurang, dan binatang ternak telah binasa. Maka mintalah hujan kepada Allah untuk kami, sesungguhnya kami meminta syafaat dengan perantaramu kepada Allah dan dengan perantara Allah kepadamu.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Celaka kamu! Tidakkah kamu tahu apa yang telah kamu ucapkan?\" Rasulullah shallallahu 'alaihi wasallam kemudian bertasbih kepada Allah, dan beliau masih saja bertasbih hingga (kebencian beliau) bisa diketahui dari wajah para sahabatnya. Kemudian beliau bersabda lagi: \"Celaka kamu! Sesungguhnya Allah tidak boleh dijadikan sebagai perantara atas seorang pun dari hamba-Nya, Allah lebih agung dari untuk sekedar dijadikan sebagai wasilah tersebut. Celaka kamu! Tidak tahukah kamu bagaimana Allah itu? Sungguh, Arsy-Nya ada di atas semua langit-Nya seperti ini -lalu isyarat tangannya beliau mengatakan, 'Seperti Kubah, dan Arsy itu berteriak dan menyeru kepada Allah seperti tunggangan berteriak kepada pengendara karena berat-.\" Ibnu Basysyar menyebutkan dalam haditsnya, \"Sesungguhnya Allah berada di atas Arsy, dan Arsy-Nya ada di atas semua langit-Nya…lalu hadits tersebut disebutkan seluruhnya.\" [Abdul A'la], [Ibnul Mutsanna] dan [Ibnu Basysyar] menyebutkan dari [Ya'qub bin Utbah]. Dan [Jubair bin Muhammad bin Jubair] dari [bapaknya], dari [kakeknya]. Dan hadits ini diriwayatkan dengan sanad Ahmad bin Sa'id, dan inilah yang lebih shahih. hal ini telah disepakati oleh sekelompok ulama, seperti [Yahya bin Ma'in] dan [Ali Ibnul Madini]. Sekelompok ulama juga meriwayatkannya dari Ibnu Ishaq, ini menurut keterangan Ahmad. Dan menurut kabar yang sampai kepadaku bahwa riwayat Abdul A'la, Ibnul Mutsanna dan Ibnu Basysyar dari buku yang sama.\""},"3949":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُذِنَ لِي أَنْ أُحَدِّثَ عَنْ مَلَكٍ مِنْ مَلَائِكَةِ اللَّهِ مِنْ حَمَلَةِ الْعَرْشِ إِنَّ مَا بَيْنَ شَحْمَةِ أُذُنِهِ إِلَى عَاتِقِهِ مَسِيرَةُ سَبْعِ مِائَةِ عَامٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hafsh bin Abdullah] ia berkata; telah menceritakan kepadaku [Bapakku] ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Musa bin Uqbah] dari [Muhammad Ibnul Munkadir] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku telah diberi izin untuk menceritakan tentang sesosok malaikat dari malaikat Allah yang bertugas membawa Arsy. Sesungguhnya, jarak antara ujung telinga dengan bahunya adalah perjalanan tujuh ratus tahun.\""},"3950":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ نَصْرٍ وَمُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَرْمَلَةُ يَعْنِي ابْنَ عِمْرَانَ حَدَّثَنِي أَبُو يُونُسَ سُلَيْمُ بْنُ جُبَيْرٍ مَوْلَى أَبِي هُرَيْرَةَ قَالَسَمِعْتُ أَبَا هُرَيْرَةَ يَقْرَأُ هَذِهِ الْآيَةَ{ إِنَّ اللَّهَ يَأْمُرُكُمْ أَنْ تُؤَدُّوا الْأَمَانَاتِ إِلَى أَهْلِهَا إِلَى قَوْلِهِ تَعَالَى سَمِيعًا بَصِيرًا }قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ إِبْهَامَهُ عَلَى أُذُنِهِ وَالَّتِي تَلِيهَا عَلَى عَيْنِهِ قَالَ أَبُو هُرَيْرَةَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا وَيَضَعُ إِصْبَعَيْهِ قَالَ ابْنُ يُونُسَ قَالَ الْمُقْرِئُ يَعْنِي إِنَّ اللَّهَ سَمِيعٌ بَصِيرٌ يَعْنِي أَنَّ لِلَّهِ سَمْعًا وَبَصَرًاقَالَ أَبُو دَاوُد وَهَذَا رَدٌّ عَلَى الْجَهْمِيَّةِ","id":"Telah menceritakan kepada kami [Ali bin Nashr] dan [Muhammad bin Yunus An Nasai] secara makna, keduanya berkata; telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri] berkata, telah menceritakan kepada kami [Harmalah] -maksudnya Harmalah bin Imran- berkata, telah menceritakan kepadaku [Abu Yunus Sulaim bin Jubair] -mantan budak (yang telah dimerdekakan oleh) Abu Hurairah- ia berkata; Aku mendengar [Abu Hurairah] membaca ayat ini: (Sesungguhnya Allah menyuruh kamu menyampaikan amanat kepada yang berhak menerimanya) -Qs. An Nisa: 48- sampai pada firman-Nya (Sesungguhnya Allah adalah Maha Mendengar lagi Maha Melihat). Abu Hurairah berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam meletakkan ibu jarinya ke telinga, sementara jari setelahnya pada mata.\" Abu Hurairah melanjutkan, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam membaca ayat tersebut seraya meletakkan kedua jarinya tersebut.\" Ibnu Yunus berkata, \"Al Muqri menyebutkan bahwa makna ayat: (Sesungguhnya Allah Maha Mendengar dan Maha Melihat) adalah, bahwa Allah memiliki penglihatan dan pendengaran.\" Abu Dawud berkata, \"Ini adalah bantahan untuk orang-orang Jahmiyah.\""},"3951":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ وَوَكِيعٌ وَأَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسًا فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ لَيْلَةَ أَرْبَعَ عَشْرَةَ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا لَا تُضَامُّونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ هَذِهِ الْآيَةَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا }","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dan [Waki'] dan [Abu Usamah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] ia berkata, \"Kami duduk bersama Rasulullah shallallahu 'alaihi wasallam, kemudian beliau melihat bulan purnama, tepatnya malam tanggal empat belas. Beliau bersabda: \"Kalian akan melihat Tuhan kalian seperti kalian melihat rembulan ini, tidak ada yang menghalangi pandangan kalian. Jika kalian mampu untuk melaksanakan shalat sebelum terbit dan tenggelamnya matahari, maka lakukanlah.\" Kemudian beliau membaca ayat dan bertasbihlah dengan memuji Tuhanmu, sebelum terbit matahari dan sebelum terbenamnya-thaahaa; 130-"},"3952":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَهُ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ نَاسٌ يَا رَسُولَ اللَّهِ أَنَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ فِي الظَّهِيرَةِ لَيْسَتْ فِي سَحَابَةٍ قَالُوا لَا قَالَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ لَيْسَ فِي سَحَابَةٍ قَالُوا لَا قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تُضَارُّونَ فِي رُؤْيَتِهِ إِلَّا كَمَا تُضَارُّونَ فِي رُؤْيَةِ أَحَدِهِمَا","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il] berkata, telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari [Bapaknya] Bahwasanya ia mendengarnya menceritakan dari [Abu Hurairah] ia berkata, \"Seseorang bertanya kepada Rasulullah, \"Wahai Rasulullah, apakah kita bisa melihat Tuhan kita pada hari kiamat?\" beliau bersabda: \"Apakah kalian merasa kesulitan ketika melihat matahari saat waktu zhuhur yang tidak ada awannya?\" mereka menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah kalian merasa kesulitan saat melihat rembulan di malam purnama yang tidak ada awannya?\" mereka menjawab, \"Tidak.\" Beliau bersabda: \"Demi Dzat yang jiwaku ada dalam genggaman-Nya, kalian tidak akan kesulitan untuk melihat-Nya kecuali sebagaimana kalian melihat salah satu dari keduanya (matahari atau rembulan).\""},"3953":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ الْمَعْنَى عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعٍ قَالَ مُوسَى ابْنِ عُدُسٍ عَنْ أَبِي رَزِينٍ قَالَ مُوسَى الْعُقَيْلِيِّ قَالَ قُلْتُيَا رَسُولَ اللَّهِ أَكُلُّنَا يَرَى رَبَّهُ قَالَ ابْنُ مُعَاذٍ مُخْلِيًا بِهِ يَوْمَ الْقِيَامَةِ وَمَا آيَةُ ذَلِكَ فِي خَلْقِهِ قَالَ يَا أَبَا رَزِينٍ أَلَيْسَ كُلُّكُمْ يَرَى الْقَمَرَ قَالَ ابْنُ مُعَاذٍ لَيْلَةَ الْبَدْرِ مُخْلِيًا بِهِ ثُمَّ اتَّفَقَا قُلْتُ بَلَى قَالَ فَاللَّهُ أَعْظَمُ قَالَ ابْنُ مُعَاذٍ قَالَ فَإِنَّمَا هُوَ خَلْقٌ مِنْ خَلْقِ اللَّهِ فَاللَّهُ أَجَلُّ وَأَعْظَمُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Syu'bah] secara makna, dari [Ya'la bin Atha] dari [Waki']. [Musa] ibnu 'Udus menyebutkan dari [Abu Razin]. Musa Al Uqaili berkata, \"Aku bertanya, \"Wahai Rasulullah, apakah setiap kami nanti dapat melihat Rabbnya?\" -Ibnu Mu'adz menyebutkan (dalam riwayatnya) - \"tanpa adanya penghalang pada hari kiamat? Lalu apa tanda-tandanya yang ada pada ciptaan-Nya?\" beliau menjawab: \"Wahai Abu Razin, bukankah setiap kalian bisa melihat rembulan?\" -Ibnu Mu'adz menyebutkan (dalam riwayatnya) -, \"pada malam purnama tanpa adanya penghalang?\" -kemudian keduanya sepakat pada lafadz- Aku menjawab, \"Tentu.\" Beliau bersabda: \"Maka Allah lebih agung (dari itu).\" -Ibnu Mu'adz menyebutkan (dalam riwayatnya), \"Beliau bersabda: \"(Rembulan) itu hanyalah makhluk dari sekian makhluk-Nya, dan Allah lebih agung dari itu.\""},"3954":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ أَنَّ أَبَا أُسَامَةَ أَخْبَرَهُمْ عَنْ عُمَرَ بْنِ حَمْزَةَ قَالَ قَالَ سَالِمٌ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطْوِي اللَّهُ السَّمَاوَاتِ يَوْمَ الْقِيَامَةِ ثُمَّ يَأْخُذُهُنَّ بِيَدِهِ الْيُمْنَى ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ الْجَبَّارُونَ أَيْنَ الْمُتَكَبِّرُونَ ثُمَّ يَطْوِي الْأَرَضِينَ ثُمَّ يَأْخُذُهُنَّ قَالَ ابْنُ الْعَلَاءِ بِيَدِهِ الْأُخْرَى ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ الْجَبَّارُونَ أَيْنَ الْمُتَكَبِّرُونَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad Ibnul 'Ala] bahwa [Abu Usamah] mengabarkan kepada mereka dari [Umar bin Hamzah] ia berkata; [Salim] berkata; telah mengabarkan kepadaku [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat Allah akan menggulung semua langit kemudian mengenggamnya dengan tangan kanan, setelah itu Allah berfirman: \"Aku adalah raja! Sekarang dimanakah orang-orang yang berlaku sewenang-wenang, di mana orang-orang yang berlaku sombong!\" Kemudian Allah juga menggulung semua bumi dan menggenggamnya. Ibnul 'Ala menyebutkan, \"Dengan tangan-Nya yang lain. Setelah itu berfirman: \"Aku adalah raja! Sekarang dimanakah orang-orang yang berlaku sewenang-wenang, di mana orang-orang yang berlaku sombong!\""},"3955":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا كُلَّ لَيْلَةٍ إِلَى سَمَاءِ الدُّنْيَا حَتَّى يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Abdullah Al Aghar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap malam Rabb kita turun ke langit dunia di sepertiga malam yang akhir. Lalu Dia berfirman: \"Siapa yang berdoa kepada-Ku maka akan Aku kabulkan, siapa yang meminta kepada-Ku maka akan Aku beri dan siapa yang meminta ampun kepada-Ku maka akan Aku ampuni.\""},"3956":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا عُثْمَانُ بْنُ الْمُغِيرَةِ عَنْ سَالِمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُ نَفْسَهُ عَلَى النَّاسِ فِي الْمَوْقِفِ فَقَالَ أَلَا رَجُلٌ يَحْمِلُنِي إِلَى قَوْمِهِ فَإِنَّ قُرَيْشًا قَدْ مَنَعُونِي أَنْ أُبَلِّغَ كَلَامَ رَبِّي","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Isra'il] berkata, telah menceritakan kepada kami [Utsman Ibnul Mughirah] dari [Salim] dari [Jabir bin Abdullah] ia berkata, \"Pada suatu saat Rasulullah shallallahu 'alaihi wasallam pernah menawarkan dirinya kepada manusia di tempat pemberhentian, beliau bersabda: \"Adakah seorang laki-laki yang mau membawaku kepada kaumnya, sesungguhnya orang-orang Quraisy telah melarang aku menyampaikan pesan Tuhanku.\""},"3957":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَسَعِيدُ بْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَ وَكُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ قَالَتْوَلَشَأْنِي فِي نَفْسِي كَانَ أَحْقَرَ مِنْ أَنْ يَتَكَلَّمَ اللَّهُ فِيَّ بِأَمْرٍ يُتْلَى","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri] berkata, telah mengabarkan kepada kami [Abdullah bin Wahb] ia berkata; telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Urwah Ibnu Az Zubair] dan [Sa'id Ibnul Musayyab] dan [Alqamah bin Waqqash] dan [Ubaidullah bin Abdullah] tentang peristiwa (fitnah) yang menimpa ['Aisyah], setiap dari mereka menceritakan kepadaku sebagian tentang peristiwa 'Aisyah. 'Aisyah berkata, \"Menurutku, perkara yang menimpaku itu lebih hina (tidak pantas) untuk Allah sebutkan pada sesuatu yang dibaca (Al-Qur'an).\""},"3958":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عُمَرَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُجَالِدٍ عَنْ عَامِرٍ يَعْنِي الشَّعْبِيَّ عَنْ عَامِرِ بْنِ شَهْرٍ قَالَكُنْتُ عِنْدَ النَّجَاشِيِّ فَقَرَأَ ابْنٌ لَهُ آيَةً مِنْ الْإِنْجِيلِ فَضَحِكْتُ فَقَالَ أَتَضْحَكُ مِنْ كَلَامِ اللَّهِ","id":"Telah menceritakan kepada kami [Isma'il bin Umar] berkata, telah mengabarkan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Ibnu Abu Zaidah] dari [Mujalid] dari [Amir] -maksudnya Amir Asy Sya'bi- dari [Amir bin Syahr] ia berkata, \"Saat aku sedang bersama Najasyi, salah seorang anaknya membaca ayat dalam kitab Injil hingga aku pun tertawa. Namun Najasyi berkata, \"Akankah kamu mentertawakan kalamullah?\""},"3959":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَوِّذُ الْحَسَنَ وَالْحُسَيْنَ أُعِيذُكُمَا بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ كُلِّ شَيْطَانٍ وَهَامَّةٍ وَمِنْ كُلِّ عَيْنٍ لَامَّةٍ ثُمَّ يَقُولُ كَانَ أَبُوكُمْ يُعَوِّذُ بِهِمَا إِسْمَاعِيلَ وَإِسْحَقَقَالَ أَبُو دَاوُد هَذَا دَلِيلٌ عَلَى أَنَّ الْقُرْآنَ لَيْسَ بِمَخْلُوقٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Minhal bin Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam berdoa minta perlindungan untuk Hasan dan Husain, beliau membaca: \"U'IIDZUKUMAA BIKALIMAATILLAAHIT TAAMMAH MIN KULLI SYAITHAANIN WA HAAMMATIN WA MIN KULLI 'AININ LAAMATIN (Aku memohon perlindungan kepada Allah untuk kalian berdua dengan kalimat-kalimat Allah yang sempurna, dari setiap kejahatan setan dan binatang bisa yang mematikan, dan dari setiap mata yang hasud). Kemudian beliau bersabda: \"Dahulu bapak kalian (Ibrahim) juga pernah minta perlindungan dengan keduanya untuk anaknya; Isma'il dan Ishaq.\" Abu Dawud berkata, \"Ini adalah dalil bahwa Al-Qur'an bukanlah makhluk.\""},"3960":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ الرَّازِيُّ وَعَلِيُّ بْنُ الْحُسَيْنِ ابْنِ إِبْرَاهِيمَ وَعَلِيُّ بْنُ مُسْلِمٍ قَالُوا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَكَلَّمَ اللَّهُ بِالْوَحْيِ سَمِعَ أَهْلُ السَّمَاءِ لِلسَّمَاءِ صَلْصَلَةً كَجَرِّ السِّلْسِلَةِ عَلَى الصَّفَا فَيُصْعَقُونَ فَلَا يَزَالُونَ كَذَلِكَ حَتَّى يَأْتِيَهُمْ جِبْرِيلُ حَتَّى إِذَا جَاءَهُمْ جِبْرِيلُ فُزِّعَ عَنْ قُلُوبِهِمْ قَالَ فَيَقُولُونَ يَا جِبْرِيلُ مَاذَا قَالَ رَبُّكَ فَيَقُولُ الْحَقَّ فَيَقُولُونَ الْحَقَّ الْحَقَّ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij Ar Razi] dan [Ali Ibnul Husain bin Ibrahim] dan [Ali bin Muslim] mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah menyampaikan wahyu maka penduduk langit mendengar gemerincing seperti ada suara rantai yang beradu hingga mereka pingsan. Dan mereka terus dalam kondisi seperti itu hingga datang Jibril, maka ketika Jibril datang mereka pun sadar.\" Beliau bersabda: \"Lalu mereka berkata, \"Wahai Jibril, apa yang disampaikan oleh Rabbmu?\" Jibril menjawab, \"Kebenaran.\" Mereka pun berkata lagi, \"Kebenaran, kebenaran.\""},"3961":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا بَسْطَامُ بْنُ حُرَيْثٍ عَنْ أَشْعَثَ الْحُدَّانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَفَاعَتِي لِأَهْلِ الْكَبَائِرِ مِنْ أُمَّتِي","id":"Telah menceritakan kepada kami [Sulaiman bin harb] berkata, telah menceritakan kepada kami [Bastham bin Huraits] dari [Asy'ats Al Huddani] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Syafaatku berlaku untuk pelaku dosa besar dari umatku.\""},"3962":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ الْحَسَنِ بْنِ ذَكْوَانَ حَدَّثَنَا أَبُو رَجَاءٍ قَالَ حَدَّثَنِي عِمْرَانُ بْنُ حُصَيْنٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ قَوْمٌ مِنْ النَّارِ بِشَفَاعَةِ مُحَمَّدٍ فَيَدْخُلُونَ الْجَنَّةَ وَيُسَمَّوْنَ الْجَهَنَّمِيِّينَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Al Hasan bin Dzakwan] berkata, telah menceritakan kepada kami [Abu Raja] ia berkata; telah menceritakan kepadaku [Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan ada sekelompok orang keluar dari neraka karena syafaat Muhammad, mereka kemudian masuk ke dalam surga, dan mereka diberi nama Al Jahannamiyyun.\""},"3963":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَهْلَ الْجَنَّةِ يَأْكُلُونَ فِيهَا وَيَشْرَبُونَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penduduk surga makan dan minum di dalamnya.\""},"3964":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا أَسْلَمُ عَنْ بِشْرِ بْنِ شَغَافٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصُّورُ قَرْنٌ يُنْفَخُ فِيهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Mu'tamir] ia berkata; Aku mendengar [Bapakku] berkata; telah menceritakan kepada kami [Aslam] dari [Bisyr bin Syaghaf] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ash Shur adalah sangkakala yang ditiup.\""},"3965":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلَّ ابْنِ آدَمَ تَأْكُلُ الْأَرْضُ إِلَّا عَجْبَ الذَّنَبِ مِنْهُ خُلِقَ وَفِيهِ يُرَكَّبُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap anak Adam akan dimakan oleh bumi kecuali tulang ekor, darinya mereka dicipta dan darinya pula mereka akan disusun.\""},"3966":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا خَلَقَ اللَّهُ الْجَنَّةَ قَالَ لِجِبْرِيلَ اذْهَبْ فَانْظُرْ إِلَيْهَا فَذَهَبَ فَنَظَرَ إِلَيْهَا ثُمَّ جَاءَ فَقَالَ أَيْ رَبِّ وَعِزَّتِكَ لَا يَسْمَعُ بِهَا أَحَدٌ إِلَّا دَخَلَهَا ثُمَّ حَفَّهَا بِالْمَكَارِهِ ثُمَّ قَالَ يَا جِبْرِيلُ اذْهَبْ فَانْظُرْ إِلَيْهَا فَذَهَبَ فَنَظَرَ إِلَيْهَا ثُمَّ جَاءَ فَقَالَ أَيْ رَبِّ وَعِزَّتِكَ لَقَدْ خَشِيتُ أَنْ لَا يَدْخُلَهَا أَحَدٌ قَالَ فَلَمَّا خَلَقَ اللَّهُ النَّارَ قَالَ يَا جِبْرِيلُ اذْهَبْ فَانْظُرْ إِلَيْهَا فَذَهَبَ فَنَظَرَ إِلَيْهَا ثُمَّ جَاءَ فَقَالَ أَيْ رَبِّ وَعِزَّتِكَ لَا يَسْمَعُ بِهَا أَحَدٌ فَيَدْخُلُهَا فَحَفَّهَا بِالشَّهَوَاتِ ثُمَّ قَالَ يَا جِبْرِيلُ اذْهَبْ فَانْظُرْ إِلَيْهَا فَذَهَبَ فَنَظَرَ إِلَيْهَا ثُمَّ جَاءَ فَقَالَ أَيْ رَبِّ وَعِزَّتِكَ لَقَدْ خَشِيتُ أَنْ لَا يَبْقَى أَحَدٌ إِلَّا دَخَلَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika selesai menciptakan surga, Allah berfirman kepada Jibril: \"Pergi dan lihatlah surga itu.\" Jibril kemudian pergi dan melihat surga, setelah itu ia kembali lagi seraya berkata, \"Wahai Rabb, demi kemuliaan-Mu, tidak seorang pun yang mendengar tentangnya kecuali ia ingin memasukinya.\" Kemudian Allah menutupi (merintangi) surga dengan hal-hal yang tidak disukai (oleh manusia). Lantas Allah berfirman: \"Wahai Jibril, pergi dan lihatlah surga itu.\" Jibril kemudian pergi dan melihat surga, setelah itu ia kembali lagi seraya berkata, \"Wahai Rabb, demi kemuliaan-Mu, aku kawatir tidak ada seorang pun yang hendak memasukinya.\" Beliau bersabda: \"Ketika selesai menciptakan neraka, Allah berfirman: \"Wahai Jibril, pergi dan lihatlah neraka itu.\" Jibril kemudian pergi dan melihat neraka, setelah itu ia kembali lagi seraya berkata, \"Wahai Rabb, demi kemuliaan-Mu, tidak seorang pun yang mendengar tentangnya kemudian timbul keinginan untuk memasukinya.\" Allah kemudian menutupi neraka dengan syahwat (kesenangan atau yang disukai manusia), lantas Allah berfirman: \"Wahai Jibril, pergi dan lihatlah neraka.\" kemudian Jibril pergi dan melihat neraka, setelah itu ia kembali lagi dan berkata, \"Wahai Rabb, demi kemuliaan-Mu, aku kawatir tidak ada seorang pun yang bakal tersisa (selamat).\""},"3967":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَمَامَكُمْ حَوْضًا مَا بَيْنَ نَاحِيَتَيْهِ كَمَا بَيْنَ جَرْبَاءَ وَأَذْرُحَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di depan kalian ada sebuah telaga, jarak antara ujung yang satu dengan yang lainnya seperti jarak antara Jarba dengan Adzruh.\""},"3968":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي حَمْزَةَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلْنَا مَنْزِلًا فَقَالَ مَا أَنْتُمْ جُزْءٌ مِنْ مِائَةِ أَلْفِ جُزْءٍ مِمَّنْ يَرِدُ عَلَيَّ الْحَوْضَ قَالَ قُلْتُ كَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ سَبْعُ مِائَةٍ أَوْ ثَمَانِ مِائَةٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] berkata, telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Abu Hamzah] dari [Zaid bin Arqam] ia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam singgah pada suatu tempat, beliau lalu bersabda: \"Kalian tidak sampai satu bagian dari seratus ribu bagian orang yang datang untuk minum di telagaku.\" Perawi berkata, \"Berapa jumlah kalian waktu itu?\" Ia menjawab, \"Tujuh ratus atau delapan ratus orang.\""},"3969":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُأَغْفَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِغْفَاءَةً فَرَفَعَ رَأْسَهُ مُتَبَسِّمًا فَإِمَّا قَالَ لَهُمْ وَإِمَّا قَالُوا لَهُ يَا رَسُولَ اللَّهِ لِمَ ضَحِكْتَ فَقَالَ إِنَّهُ أُنْزِلَتْ عَلَيَّ آنِفًا سُورَةٌ فَقَرَأَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ{ إِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ }حَتَّى خَتَمَهَا فَلَمَّا قَرَأَهَا قَالَ هَلْ تَدْرُونَ مَا الْكَوْثَرُ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ نَهْرٌ وَعَدَنِيهِ رَبِّي عَزَّ وَجَلَّ فِي الْجَنَّةِ وَعَلَيْهِ خَيْرٌ كَثِيرٌ عَلَيْهِ حَوْضٌ تَرِدُ عَلَيْهِ أُمَّتِي يَوْمَ الْقِيَامَةِ آنِيَتُهُ عَدَدُ الْكَوَاكِبِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Al Mukhtar bin Fulful] ia berkata; Aku mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam terlelap beberapa saat, setelah itu beliau mengangkat kepala dan tersenyum. (waktu itu) beliau berkata kepada mereka, atau mereka yang berkata kepada beliau, \"Wahai Rasulullah, kenapa engkau tertawa?\" beliau menjawab: \"Baru saja turun kepadaku satu surat.\" Beliau lalu membaca: (Dengan menyebut nama Allah yang Maha Pemurah lagi Maha Penyayang. Sesungguhnya Kami telah memberikan kepadamu ni'mat yang banyak…) hingga akhir ayat. Ketika beliau selesai membacayanya, beliau bertanya: \"Apakah kalian tahu apa yang dimaksud dengan Al kautsar?\" para sahabat menjawab, \"Allah dan Rasul-Nya lebih tahu.\" Beliau bersabda: \"Itu adalah sungai di surga yang janjikan Rabbku kepadaku. Padanya banyak kebaikan. Padanya juga ada telaga yang digunakan untuk minum oleh umatku pada hari kiamat. Gelasnya sejumlah bintang di langit.\""},"3970":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ النَّضْرِ قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا عُرِجَ بِنَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنَّةِ أَوْ كَمَا قَالَ عُرِضَ لَهُ نَهْرٌ حَافَتَاهُ الْيَاقُوتُ الْمُجَيَّبُ أَوْ قَالَ الْمُجَوَّفُ فَضَرَبَ الْمَلَكُ الَّذِي مَعَهُ يَدَهُ فَاسْتَخْرَجَ مِسْكًا فَقَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمَلَكِ الَّذِي مَعَهُ مَا هَذَا قَالَ الْكَوْثَرُ الَّذِي أَعْطَاكَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ashim bin An Nadhr] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; aku mendengar [Bapakku] ia berkata; telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam dinaikkan ke surga, atau sebagaimana yang ia katakan, \"diperlihatkan kepada beliau sebuah sungai yang dua tepinya dihiasi dengan permata. Kemudian malaikat yang bersamanya memukul tangannya hingga keluarlah minyak kesturi. Muhammad shallallahu 'alaihi wasallam lalu bertanya: \"Apa ini?\" malaikat itu menjawab, \"Ini adalah Al kautsar yang Allah Azza Wa Jalla berikan kepadamu.\""},"3971":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ أَبِي حَازِمٍ أَبُو طَالُوتَ قَالَشَهِدْتُ أَبَا بَرْزَةَ دَخَلَ عَلَى عُبَيْدِ اللَّهِ بْنِ زِيَادٍ فَحَدَّثَنِي فُلَانٌ سَمَّاهُ مُسْلِمٌ وَكَانَ فِي السِّمَاطِ فَلَمَّا رَآهُ عُبَيْدُ اللَّهِ قَالَ إِنَّ مُحَمَّدِيَّكُمْ هَذَا الدَّحْدَاحُ فَفَهِمَهَا الشَّيْخُ فَقَالَ مَا كُنْتُ أَحْسَبُ أَنِّي أَبْقَى فِي قَوْمٍ يُعَيِّرُونِي بِصُحْبَةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ عُبَيْدُ اللَّهِ إِنَّ صُحْبَةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكَ زَيْنٌ غَيْرُ شَيْنٍ قَالَ إِنَّمَا بَعَثْتُ إِلَيْكَ لِأَسْأَلَكَ عَنْ الْحَوْضِ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ فِيهِ شَيْئًا فَقَالَ لَهُ أَبُو بَرْزَةَ نَعَمْ لَا مَرَّةً وَلَا ثِنْتَيْنِ وَلَا ثَلَاثًا وَلَا أَرْبَعًا وَلَا خَمْسًا فَمَنْ كَذَّبَ بِهِ فَلَا سَقَاهُ اللَّهُ مِنْهُ ثُمَّ خَرَجَ مُغْضَبًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Abdussalam bin Abu Hazim Abu Thalut] ia berkata; Aku melihat [Abu Barzah] masuk menemui Ubaidullah bin Ziyad, lalu ada seseorang dalam sebuah rombongan bernama Muslim bercerita kepadaku. Ketika Ubaidullah melihatnya, ia berkata, \"Sesungguhnya salah satu dari kelompok Muhammad adalah orang yang gemuk dan pendek.\" Maka Abu Barzah pun mengerti apa yang dikatakan oleh Ubaidullah tersebut. Lantas Abu Barzah berkata, \"Aku tidak menyangka bisa hidup bersama orang-orang yang mencelaku karena aku berkumpul dengan Muhammad shallallahu 'alaihi wasallam.\" Ubaidullah balik berkata, \"Sesungguhnya persahabatanmu dengan Muhammad adalah perhiasan dan tidak ada celanya.\" Ia melanjutkan lagi kata-katanya, \"Dan aku datang kepadamu untuk bertanya perihal telaga, aku pernah mendengar Muhammad shallallahu 'alaihi wasallam menyebut-nyebut tentang itu?\" Abu Barzah menjawab, \"Benar. Tidak hanya satu kali, dua kali, tiga kali, empat kali atau lima kali (beliau sebutkan itu). Maka siapa saja yang mendustainya Allah tidak akan memberinya minum darinya.\" Lalu ia keluar dengan marah.\""},"3972":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُسْلِمَ إِذَا سُئِلَ فِي الْقَبْرِ فَشَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Alqamah bin Martsad] dari [Sa'd bin Ubaidah] dari [Al Bara bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang muslim ditanya dalam kubur, lalu ia bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, dan Muhammad shallallahu 'alaihi wasallam adalah utusan Allah. Maka itu adalah bukti dari firman Allah Azza Wa Jalla: (Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh…) -Qs. Ibrahim: 27-"},"3973":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ الْخَفَّافُ أَبُو نَصْرٍ عَنْ سَعِيد�� عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ نَخْلًا لِبَنِي النَّجَّارِ فَسَمِعَ صَوْتًا فَفَزِعَ فَقَالَ مَنْ أَصْحَابُ هَذِهِ الْقُبُورِ قَالُوا يَا رَسُولَ اللَّهِ نَاسٌ مَاتُوا فِي الْجَاهِلِيَّةِ فَقَالَ تَعَوَّذُوا بِاللَّهِ مِنْ عَذَابِ النَّارِ وَمِنْ فِتْنَةِ الدَّجَّالِ قَالُوا وَمِمَّ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ إِنَّ الْمُؤْمِنَ إِذَا وُضِعَ فِي قَبْرِهِ أَتَاهُ مَلَكٌ فَيَقُولُ لَهُ مَا كُنْتَ تَعْبُدُ فَإِنْ اللَّهُ هَدَاهُ قَالَ كُنْتُ أَعْبُدُ اللَّهَ فَيُقَالُ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ فَيَقُولُ هُوَ عَبْدُ اللَّهِ وَرَسُولُهُ فَمَا يُسْأَلُ عَنْ شَيْءٍ غَيْرِهَا فَيُنْطَلَقُ بِهِ إِلَى بَيْتٍ كَانَ لَهُ فِي النَّارِ فَيُقَالُ لَهُ هَذَا بَيْتُكَ كَانَ لَكَ فِي النَّارِ وَلَكِنَّ اللَّهَ عَصَمَكَ وَرَحِمَكَ فَأَبْدَلَكَ بِهِ بَيْتًا فِي الْجَنَّةِ فَيَقُولُ دَعُونِي حَتَّى أَذْهَبَ فَأُبَشِّرَ أَهْلِي فَيُقَالُ لَهُ اسْكُنْ وَإِنَّ الْكَافِرَ إِذَا وُضِعَ فِي قَبْرِهِ أَتَاهُ مَلَكٌ فَيَنْتَهِرُهُ فَيَقُولُ لَهُ مَا كُنْتَ تَعْبُدُ فَيَقُولُ لَا أَدْرِي فَيُقَالُ لَهُ لَا دَرَيْتَ وَلَا تَلَيْتَ فَيُقَالُ لَهُ فَمَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ فَيَقُولُ كُنْتُ أَقُولُ مَا يَقُولُ النَّاسُ فَيَضْرِبُهُ بِمِطْرَاقٍ مِنْ حَدِيدٍ بَيْنَ أُذُنَيْهِ فَيَصِيحُ صَيْحَةً يَسْمَعُهَا الْخَلْقُ غَيْرُ الثَّقَلَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بِمِثْلِ هَذَا الْإِسْنَادِ نَحْوَهُ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ فَيَأْتِيهِ مَلَكَانِ فَيَقُولَانِ لَهُ فَذَكَرَ قَرِيبًا مِنْ حَدِيثِ الْأَوَّلِ قَالَ فِيهِ وَأَمَّا الْكَافِرُ وَالْمُنَافِقُ فَيَقُولَانِ لَهُ زَادَ الْمُنَافِقَ وَقَالَ يَسْمَعُهَا مَنْ وَلِيَهُ غَيْرُ الثَّقَلَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] berkata, telah menceritakan kepada kami [Abdul Wahhab bin Atha Al Khaffaf Abu Nashr] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah masuk ke sebuah kebun milik bani Najjar, lalu beliau mendengar suara hingga beliau kawatir. Beliau bertanya: \"Siapa yang dikubur ini?\" Para sahabat menjawab, \"Wahai Rasulullah, orang-orang yang mati pada masa Jahilliyah.\" Beliau bersabda: \"Berlindunglah kalian kepada Allah dari siksa neraka dan fitnah Dajjal.\" Para sahabat berkata, \"Wahai Rasulullah, memang kenapa?\" Beliau menjawab: \"Seorang mukmin jika telah diletakkan dalam kuburnya, maka seorang malaikat akan datang kepadanya seraya berkata, \"Apa yang kamu sembah?\" Jika Allah memberinya pentunjuk maka ia akan menjawab, \"Aku menyembah Allah.\" Lalu ditanyakan kepadanya, \"Apa yang kau katakan tentang laki-laki ini (Muhammad)?\" Lalu ia menjawab, \"Dia adalah hamba Allah dan rasul-Nya.\" Dan ia tidak ditanya kecuali pertanyaan tersebut. Lalu ia dibawa menuju rumah yang disediakan untuknya dalam neraka, dikatakan kepadanya, \"Ini adalah rumah yang semula disediakan untukmu di neraka, tetapi Allah telah melindungi dan memberimu rahmat lalu Allah menggantikan rumah di surga.\" Laki-laki mukmin itu pun berkata, \"Biarkanlah aku mengabarkan berita baik ini kepada keluargaku.\" Lalu dikatakan kepadanya, \"Diamlah.\", Dan seorang kafir jika telah diletakkan dalam kuburnya, maka seorang malaikat akan datang kepadanya seraya menghardiknya, lalu malaikat itu bertanya, \"Siapa yang kamu sembah?\" Laki-laki itu menjawab, \"Aku tidak tahu.\" Lalu dikatakan kepadanya, \"Engkau tidak tahu tapi tidak mau membaca!\" Lalu dikatakan kepadanya, \"Apa yang kamu katakan tentang ini (Muhammad)?\" Laki-laki itu menjawab, \"Aku mengatakan sebagaimana yang dikatakan oleh manusia.\" Malaikat itu lalu memukulnya dengan palu besi antara dua telinganya hingga ia melolong dan menjerit kesakitan dengan jeritan yang dapat didengar oleh para semua makhluk kecuali jin dan manusia.\" Telah menceritakan kepada kami Muhammad bin Sulaiman berkata, telah menceritakan kepada kami Abdul Wahhab dengan sanad yang sama; seperti hadits tersebut. Beliau bersabda: \"Jika seorang hamba diletakkan dalam kuburnya, dan orang-orang yang menghantarkannya telah kembali, maka ia dapat mendengar bunyi sandal mereka. setelah itu ada dua malaikat mendatanginya dan bertanya kepadanya. …lalu ia menyebutkan redaksi yang hampir sama dengan hadits pertama ia menyebutkan (dalam riwayatnya); \"Adapun orang kafir dan munafik, maka kedua malaikat itu akan berkata kepadanya\", - ia menambahkan kaliamat, 'munafik', dan ia juga menyebutkan dalam riwayatnya; \"akan dapat didengar oleh makhluk yang disekitarnya selain jin dan manusia.\""},"3974":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَهَذَا لَفْظُ هَنَّادٍ عَنْ الْأَعْمَشِ عَنْ الْمِنْهَالِ عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةِ رَجُلٍ مِنْ الْأَنْصَارِ فَانْتَهَيْنَا إِلَى الْقَبْرِ وَلَمَّا يُلْحَدْ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَلَسْنَا حَوْلَهُ كَأَنَّمَا عَلَى رُءُوسِنَا الطَّيْرُ وَفِي يَدِهِ عُودٌ يَنْكُتُ بِهِ فِي الْأَرْضِ فَرَفَعَ رَأْسَهُ فَقَالَ اسْتَعِيذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ مَرَّتَيْنِ أَوْ ثَلَاثًا زَادَ فِي حَدِيثِ جَرِيرٍ هَاهُنَا وَقَالَ وَإِنَّهُ لَيَسْمَعُ خَفْقَ نِعَالِهِمْ إِذَا وَلَّوْا مُدْبِرِينَ حِينَ يُقَالُ لَهُ يَا هَذَا مَنْ رَبُّكَ وَمَا دِينُكَ وَمَنْ نَبِيُّكَ قَالَ هَنَّادٌ قَالَ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ دِينِيَ الْإِسْلَامُ فَيَقُولَانِ لَهُ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ قَالَ فَيَقُولُ هُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولَانِ وَمَا يُدْرِيكَ فَيَقُولُ قَرَأْتُ كِتَابَ اللَّهِ فَآمَنْتُ بِهِ وَصَدَّقْتُ زَادَ فِي حَدِيثِ جَرِيرٍ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }الْآيَةُ ثُمَّ اتَّفَقَا قَالَ فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ قَدْ صَدَقَ عَبْدِي فَأَفْرِشُوهُ مِنْ الْجَنَّةِ وَافْتَحُوا لَهُ بَابًا إِلَى الْجَنَّةِ وَأَلْبِسُوهُ مِنْ الْجَنَّةِ قَالَ فَيَأْتِيهِ مِنْ رَوْحِهَا وَطِيبِهَا قَالَ وَيُفْتَحُ لَهُ فِيهَا مَدَّ بَصَرِهِ قَالَ وَإِنَّ الْكَافِرَ فَذَكَرَ مَوْتَهُ قَالَ وَتُعَادُ رُوحُهُ فِي جَسَدِهِ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ هَاهْ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ كَذَبَ فَأَفْرِشُوهُ مِنْ النَّارِ وَأَلْبِسُوهُ مِنْ النَّارِ وَافْتَحُوا لَهُ بَابًا إِلَى النَّارِ قَالَ فَيَأْتِيهِ مِنْ حَرِّهَا وَسَمُومِهَا قَالَ وَيُضَيَّقُ عَلَيْهِ قَبْرُهُ حَتَّى تَخْتَلِفَ فِيهِ أَضْلَاعُهُ زَادَ فِي حَدِيثِ جَرِيرٍ قَالَ ثُمَّ يُقَيَّضُ لَهُ أَعْمَى أَبْكَمُ مَعَهُ مِرْزَبَّةٌ مِنْ حَدِيدٍ لَوْ ضُرِبَ بِهَا جَبَلٌ لَصَارَ تُرَابًا قَالَ فَيَضْرِبُهُ بِهَا ضَرْبَةً يَسْمَعُهَا مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ إِلَّا الثَّقَلَيْنِ فَيَصِيرُ تُرَابًا قَالَ ثُمَّ تُعَادُ فِيهِ الرُّوحُحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا الْمِنْهَالُ عَنْ أَبِي عُمَرَ زَاذَانَ قَالَ سَمِعْتُ الْبَرَاءَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hannad As Sari] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] - dan ini adalah lafadz Hannad- dari [Al A'masy] dari [Al Minhal] dari [Zadzan] dari [Al Bara bin Azib] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam keluar untuk melihat jenazah seorang laki-laki Anshar, kami pun tiba di pemakaman. Ketika lubang lahad telah dibuat, Rasulullah shallallahu 'alaihi wasallam duduk, lalu kami ikut duduk di sisinya. Kami diam, seakan-akan di atas kepala kami ada burung. Saat itu beliau memegang sebatang kayu yang ditancapkan ke dalam tanah, beliau lalu mengangkat kepalanya dan bersabda: \"Mintalah perlindungan kepada Allah dari siksa kubur.\" Beliau ucapkan kalimat itu hingga dua atau tiga kali. Demikanlah tambahan dalam hadits Jarir. Beliau melanjutkan: \"Sungguh, mayat itu akan dapat mendengar derap sandal mereka saat berlalau pulang; yakni ketika ditanyakan kepadanya, 'Wahai kamu, siapa Rabbmu? Apa agamamu? Dan siapa Nabimu? ' -Hannad menyebutkan; Beliau bersabda: - \"lalu ada dua malaikat mendatanginya seranya mendudukkannya. Malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Rabbku adalah Allah.\" Malaikat itu bertanya lagi, \"Apa agamamu?\" ia menjawab, \"Agamaku adalah Islam.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Dia adalah Rasulullah shallallahu 'alaihi wasallam.\" malaikat itu bertanya lagi, \"Apa yang kamu ketahui?\" ia menjawab, \"Aku membaca Kitabullah, aku mengimaninya dan membenarkannya.\" Dalam hadits Jarir ditambahkan, \"Maka inilah makna firman Allah: '(Allah meneguhkan (iman) orang-orang yang beriman…) ' hingga akhir ayat. -Qs. Ibrahim: 27- kemudian kedua perawi sepakat pada lafadz, \"Beliau bersabda: \"Kemudian ada suara dari langit yang menyeru, \"Benarlah apa yang dikatakan oleh hamba-Ku, hamparkanlah permadani untuknya di surga, bukakan baginya pintu-pintu surga dan berikan kepadanya pakaian surga.\" beliau melanjutkan: \"Kemudian didatangkan kepadanya wewangian surga, lalu kuburnya diluaskan sejauh mata memandang.\" Beliau melanjutkan: \"Jika yang meninggal adalah orang kafir, maka ruhnya akan dikembalikan kepada jasadnya. Saat itu datanglah dua malaikat serya mendudukkannya. Kedua malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Hah, hah, hah. Aku tidak tahu.\" Malaikat itu bertanya, \"Apa agamamu?\" ia menjawab, \"Hah, hah. Aku tidak tahu.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Hah, hah. Aku tidak tahu.\" Setelah itu terdengar suara dari langit: \"Ia telah berdusta. Berilah ia hamparan permadani dari neraka, berikan pakaian dari neraka, dan bukakanlah pintu-pintu neraka untuknya.\" Beliau melanjutkan: \"Kemudian didatangkan kepadanya panas dan baunya neraka. Lalu kuburnya disempitkan hingga tulangnya saling berhimpitan.\" Dalam hadits Jarir ditambahkan, \"Beliau bersabda: \"Lalu ia dibelenggu dalam keadaan buta dan bisu. Dan baginya disediakan sebuah pemukul dari besi, sekiranya pemukul itu dipukulkan pada sebuah gunung niscaya akan menjadi debu.\" Beliau melanjutkan: \"Laki-laki kafir itu kemudian dipukul dengan pemukul tersebut hingga suaranya dapat didengar oleh semua makhluk; dari ujung timur hingga ujung barat -kecuali jin dan manusia- hingga menjadi debu.\" Beliau meneruskan ceritanya: \"Setelah itu, ruhnya dikembalikan lagi.\" Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada kami [Al Minhal] dari [Abu Umar Zadzan] ia berkata; Aku mendengar [Al Bara] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda…. lalu ia menyebutkan seperti hadits tersebut.\""},"3975":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ وَحُمَيْدُ بْنُ مَسْعَدَةَ أَنَّ إِسْمَعِيلَ بْنَ إِبْرَاهِيمَ حَدَّثَهُمْ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ عَائِشَةَأَنَّهَا ذَكَرَتْ النَّارَ فَبَكَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يُبْكِيكِ قَالَتْ ذَكَرْتُ النَّارَ فَبَكَيْتُ فَهَلْ تَذْكُرُونَ أَهْلِيكُمْ يَوْمَ الْقِيَامَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا فِي ثَلَاثَةِ مَوَاطِنَ فَلَا يَذْكُرُ أَحَدٌ أَحَدًا عِنْدَ الْمِيزَانِ حَتَّى يَعْلَمَ أَيَخِفُّ مِيزَانُهُ أَوْ يَثْقُلُ وَعِنْدَ الْكِتَابِ حِينَ يُقَالُ{ هَاؤُمُ اقْرَءُوا كِتَابِيَهْ }حَتَّى يَعْلَمَ أَيْنَ يَقَعُ كِتَابُهُ أَفِي يَمِينِهِ أَمْ فِي شِمَالِهِ أَمْ مِنْ وَرَاءِ ظَهْرِهِ وَعِنْدَ الصِّرَاطِ إِذَا وُضِعَ بَيْنَ ظَهْرَيْ جَهَنَّمَقَالَ يَعْقُوبُ عَنْ يُونُسَ وَهَذَا لَفْظُ حَدِيثِهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] dan [Humaid bin Mas'adah] bahwa [Isma'il bin Ibrahim] menceritakan kepada mereka, ia berkata; telah mengabarkan kepada kami [Yunus] dari [Al Hasan] dari ['Aisyah] Bahwasanya ia mengingat-ingat neraka lalu menangis. Rasulullah shallallahu 'alaihi wasallam lantas bertanya: \"Apa yang membuatmu menangis?\" 'Aisyah menjawab, \"Aku ingat dengan neraka, lalu aku menangis. Apakah kalian mengingat keluarga kalian pada hari kiamat?\" Beliau bersabda: \"Ada tiga tempat seseorang tidak akan lagi ingat kepada orang lain; saat berada di atas mizan (timbangan amal) hingga ia tahu apakah timbangannya lebih ringan atau berat, ketika menerima buku amalan, yaitu saat dikatakan kepadanya, 'Ambillah, bacalah kitabku (ini) ', hingga ia tahu dari mana bukunya akan diberikan dari sebelah kanan atau sebelah kiri atau dari belakang punggungnya. Dan ketika di atas shirath, yaitu titian di antara dua punggung jahannam.\" Ya'qub menyebutkan dari Yunus, dan ini adalah lafadz haditsnya. "},"3976":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ بَعْدَ نُوحٍ إِلَّا وَقَدْ أَنْذَرَ الدَّجَّالَ قَوْمَهُ وَإِنِّي أُنْذِرُكُمُوهُ فَوَصَفَهُ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَعَلَّهُ سَيُدْرِكُهُ مَنْ قَدْ رَآنِي وَسَمِعَ كَلَامِي قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ قُلُوبُنَا يَوْمَئِذٍ أَمِثْلُهَا الْيَوْمَ قَالَ أَوْ خَيْرٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Khalid Al Hadzdza] dari [Abdullah bin Syaqiq] dari [Abdullah bin Suraqah] dari [Abu Ubaidah Ibnul Jarrah] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang Nabi pun setelah Nuh kecuali telah mengingatkan umatnya tentang Dajjal, dan sesungguhnya aku memperingatkan kalian darinya.\" Rasulullah shallallahu 'alaihi wasallam kemudian menshifati (memberikan gambaran) Dajjal kepada kami, beliau bersabda: \"Bisa jadi orang yang melihat dan mendengarku akan melihat Dajjal.\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana dengan kondisi hati kami waktu itu, apakah seperti sekarang ini?\" Beliau menjawab: \"Ya, baik.\""},"3977":{"ar":"حَدَّثَنَا مَخْلَدٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ فَذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي لَأُنْذِرُكُمُوهُ وَمَا مِنْ نَبِيٍّ إِلَّا قَدْ أَنْذَرَهُ قَوْمَهُ لَقَدْ أَنْذَرَهُ نُوحٌ قَوْمَهُ وَلَكِنِّي سَأَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ تَعْلَمُونَ أَنَّهُ أَعْوَرُ وَأَنَّ اللَّهَ لَيْسَ بِأَعْوَرَ","id":"Telah menceritakan kepada kami [Makhlad] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan orang-orang seraya memuji Allah dengan pujian yang layak bagi-Nya. Kemudian beliau menceritakan tentang Dajjal, beliau bersabda: \"Sungguh, aku akan memberi peringatan kepada kalian tentang Dajjal, dan tidak ada seorang Nabi pun kecuali ia telah memberi peringatan kepada kaumnya darinya. Nuh telah memberi peringatan kepada kaumnya. Tetapi aku akan menyampaikan kepada kalian tentang dajjal dengan suatu ucapan yang belum pernah disampaikan oleh seorang Nabi kepada kaumnya. Ketahuilah sesungguhnya dajjal itu buta sebelah, sementara Allah tidak buta sebelah.\""},"3978":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ وَمَنْدَلٌ عَنْ مُطَرِّفٍ عَنْ أَبِي جَهْمٍ عَنْ خَالِدِ بْنِ وَهْبَانَ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَارَقَ الْجَمَاعَةَ شِبْرًا فَقَدْ خَلَعَ رِبْقَةَ الْإِسْلَامِ مِنْ عُنُقِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zuhair] dan [Abu Bakr bin Ayyasy] dan [Mandal] dari [Mutharrif] dari [Abu Jahm] dari [Khalid bin Wahban] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang meninggalkan jamaah meskipun hanya satu jengkal, sungguh ia telah melepas ikatan Islam dari lehernya.\""},"3979":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُطَرِّفُ بْنُ طَرِيفٍ عَنْ أَبِي الْجَهْمِ عَنْ خَالِدِ بْنِ وَهْبَانَ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَنْتُمْ وَأَئِمَّةٌ مِنْ بَعْدِي يَسْتَأْثِرُونَ بِهَذَا الْفَيْءِ قُلْتُ إِذَنْ وَالَّذِي بَعَثَكَ بِالْحَقِّ أَضَعُ سَيْفِي عَلَى عَاتِقِي ثُمَّ أَضْرِبُ بِهِ حَتَّى أَلْقَاكَ أَوْ أَلْحَقَكَ قَالَ أَوَلَا أَدُلُّكَ عَلَى خَيْرٍ مِنْ ذَلِكَ تَصْبِرُ حَتَّى تَلْقَانِي","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Mutharrif bin Tharif] dari [Abul Jahm] dari [Khalid bin Wahban] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang kalian lakukan jika para pemimpin setelahku saling berebut (mempertahankan) harta fai`?\" Aku menjawab, \"Jika begitu, maka demi Dzat yang mengutusmu dengan Al Haq, aku akan meletakkan pedangku dipundak, aku akan berperang dengannya hingga aku berjumpa denganmu, atau perawi menyebutkan, \"hingga aku menyusulmu.\" Beliau bersabda: \"Maukah aku tunjukkan dengan yang lebih baik dari itu? Bersabarlah hingga engkau berjumpa denganku.\""},"3980":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ دَاوُدَ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْمُعَلَّى بْنِ زِيَادٍ وَهِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ عَلَيْكُمْ أَئِمَّةٌ تَعْرِفُونَ مِنْهُمْ وَتُنْكِرُونَ فَمَنْ أَنْكَرَ قَالَ أَبُو دَاوُد قَالَ هِشَامٌ بِلِسَانِهِ فَقَدْ بَرِئَ وَمَنْ كَرِهَ بِقَلْبِهِ فَقَدْ سَلِمَ وَلَكِنْ مَنْ رَضِيَ وَتَابَعَ فَقِيلَ يَا رَسُولَ اللَّهِ أَفَلَا نَقْتُلُهُمْ قَالَ ابْنُ دَاوُدَ أَفَلَا نُقَاتِلُهُمْ قَالَ لَا مَا صَلَّوْاحَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ حَدَّثَنَا الْحَسَنُ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ الْعَنَزِيِّ عَنْ أُمِّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ فَمَنْ كَرِهَ فَقَدْ بَرِئَ وَمَنْ أَنْكَرَ فَقَدْ سَلِمَ قَالَ قَتَادَةُ يَعْنِي مَنْ أَنْكَرَ بِقَلْبِهِ وَمَنْ كَرِهَ بِقَلْبِهِ","id":"Telah menceritakan kepada kami [Musaddad] dan [Sulaiman bin Dawud] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Al Mu'alla bin Ziyad] dan [Hisyam bin Hassan] dari [Al Hasan] dari [Dhabbah bin Mihshan] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada di antara kalian para pemimpin yang kalian mengenalnya tetapi kalian mengingkarinya. Maka barangsiapa mengingkarinya, Abu Dawud berkata, \"Hisyam menyebutkan, \"dengan lisan, maka ia telah berlepas diri darinya. Siapa yang membenci dengan hatinya maka ia telah selamat. Tetapi siapa yang ridha dan mengikutinya, lalu dikatakan kepadanya, \"Wahai Rasulullah, bagaimana jika kami membununya?\" Ibnu Dawud menyebutkan, \"bagaimana jika kami memeranginya?\" beliau menjawab: \"Jangan, selama mereka masih shalat.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Qatadah] ia berkata; telah menceritakan kepada kami [Al Hasan] dari [Dhabbah bin Mihshan Al 'Anbari] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam dengan makna yang sama. Beliau bersabda: \"Siapa yang membenci, maka ia telah berlepas diri. Dan siapa yang mengingkari, maka ia telah selamat.\" Qatadah berkata, maksudnya \"Siapa yang mengingkari dengan hatinya, dan siapa yang membenci dengan hatinya.\""},"3981":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ فِي أُمَّتِي هَنَاتٌ وَهَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ الْمُسْلِمِينَ وَهُمْ جَمِيعٌ فَاضْرِبُوهُ بِالسَّيْفِ كَائِنًا مَنْ كَانَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Ziyad bin Ilaqah] dari [Arfajah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi pada umatku fitnah dan kebid'ahan, fitnah dan kebid'ahan, fitnah dan kebid'ahan. Maka siapa yang ingin memecah-belah urusan kaum muslimin -ketika mereka bersatu- maka bunuhlah, siapapun dia.\""},"3982":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ وَمُحَمَّدُ بْنُ عِيسَى الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَأَنَّ عَلِيًّا ذَكَرَ أَهْلَ النَّهْرَوَانِ فَقَالَ فِيهِمْ رَجُلٌ مُودَنُ الْيَدِ أَوْ مُخْدَجُ الْيَدِ أَوْ مَثْدُونُ الْيَدِ لَوْلَا أَنْ تَبْطَرُوا لَنَبَّأْتُكُمْ مَا وَعَدَ اللَّهُ الَّذِينَ يَقْتُلُونَهُمْ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ أَنْتَ سَمِعْتَ هَذَا مِنْهُ قَالَ قَالَ إِي وَرَبِّ الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] dan [Muhammad bin Isa] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Abidah] berkata, \" [Ali] menyebut-nyebut tentang penduduk Nahrawan. Ia mengatakan, \"Di antara mereka ada seorang laki-laki yang tangannya kecil atau pendek, sekiranya aku tidak kawatir kalian akan terlalu bergembira, maka aku akan kabarkan kepada kalian tentang apa yang telah Allah janjikan bagi orang-orang yang akan membunuh mereka, melalui lisan Muhammad shallallahu 'alaihi wasallam.\" Abidah berkata, \"Aku bertanya, \"Apakah engkau benar-benar mendengarnya dari beliau?\" Ali menjawab, \"Ya. Demi Dzat pemilik Ka'bah.\""},"3983":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَ عَلِيٌّ عَلَيْهِ السَّلَام إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذُهَيْبَةٍ فِي تُرْبَتِهَا فَقَسَّمَهَا بَيْنَ أَرْبَعَةٍ بَيْنَ الْأَقْرَعِ بْنِ حَابِسٍ الْحَنْظَلِيِّ ثُمَّ الْمُجَاشِعِيِّ وَبَيْنَ عُيَيْنَةَ بْنِ بَدْرٍ الْفَزَارِيِّ وَبَيْنَ زَيْدِ الْخَيْلِ الطَّائِيِّ ثُمَّ أَحَدِ بَنِي نَبْهَانَ وَبَيْنَ عَلْقَمَةَ بْنِ عُلَاثَةَ الْعَامِرِيِّ ثُمَّ أَحَدِ بَنِي كِلَابٍ قَالَ فَغَضِبَتْ قُرَيْشٌ وَالْأَنْصَارُ وَقَالَتْ يُعْطِي صَنَادِيدَ أَهْلِ نَجْدٍ وَيَدَعُنَا فَقَالَ إِنَّمَا أَتَأَلَّفُهُمْ قَالَ فَأَقْبَلَ رَجُلٌ غَائِرُ الْعَيْنَيْنِ مُشْرِفُ الْوَجْنَتَيْنِ نَاتِئُ الْجَبِينِ كَثُّ اللِّحْيَةِ مَحْلُوقٌ قَالَ اتَّقِ اللَّهَ يَا مُحَمَّدُ فَقَالَ مَنْ يُطِيعُ اللَّهَ إِذَا عَصَيْتُهُ أَيَأْمَنُنِي اللَّهُ عَلَى أَهْلِ الْأَرْضِ وَلَا تَأْمَنُونِي قَالَ فَسَأَلَ رَجُلٌ قَتْلَهُ أَحْسِبُهُ خَالِدَ بْنَ الْوَلِيدِ قَالَ فَمَنَعَهُ قَالَ فَلَمَّا وَلَّى قَالَ إِنَّ مِنْ ضِئْضِئِ هَذَا أَوْ فِي عَقِبِ هَذَا قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ يَقْتُلُونَ أَهْلَ الْإِسْلَامِ وَيَدَعُونَ أَهْلَ الْأَوْثَانِ لَئِنْ أَنَا أَدْرَكْتُهُمْ قَتَلْتُهُمْ قَتْلَ عَادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Bapaknya] dari [Ibnu Abu Nu'm] dari [Abu Sa'id Al Khudri] ia berkata, \"Ali radliallahu 'anhu mengirimkan kepada Nabi shallallahu 'alaihi wasallam emas yang masih kotor dengan debu. Beliau kemudian mambagi-bagikannya kepada empat orang; yaitu Al Aqra' bin Habis Al Hanzhali, Al Mujasyi'I, Uyainah bin Badr Al Fazari dan Zaid Al Khail Ath Tha`i. kemudian ke salah orang dari bani Nabhan, Alqamah bin Ulatsah Al 'Amiri dan seorang dari bani Kilab.\" Sa'id Al khudri berkata, \"Orang-orang Quraisy dan Anshar kemudian marah, mereka mengatakan, \"Beliau memberikan kepada tokoh-tokoh penduduk Najd dan membiarkan kita.\" Beliau pun bersabda: \"Aku hanya melunakkan hati mereka.\" Sa'id berkata, \"Kemudian datanglah seorang laki-laki yang matanya cekung, berdahi lebar, janggut panjang dan kepala gundul. Laki-laki itu berkata, \"Wahai Muhammad, bertakwalah kamu kepada Allah!\" Beliau bersabda: \"Siapa yang taat kepada Allah jika aku bermaksiat! Bukankah Allah mempercayaiku untuk menyampaikan amanah kepada penduduk bumi, sementara kalian tidak mempercayaiku.\" Sa'id berkata, \"Lalu ada seorang lelaki yang memohon izin untuk membunuh laki-laki tersebut, dan aku kira orang itu adalah Khalid bin Al Walid. Namun beliau melarangnya.\" Sa'id berkata, \"Ketika orang tersebut telah berlalu pergi, beliau bersabda: \"Sesungguhnya dari keturunan orang ini akan muncul suatu kaum yang membaca Al-Qur'an namun tidak melampaui kerongkongannya. Mereka keluar dari Islam sebagaimana keluarnya anak panah dari busurnya. Mereka membunuh orang-orang Islam namun bersikap baik kepada penyembah berhala. Jika aku mendapati mereka, maka aku akan membunuh mereka sebagaimana pembunuhan kaum Ad (kaumnya Nabi Hud).\""},"3984":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ الْأَنْطَاكِيُّ حَدَّثَنَا الْوَلِيدُ وَمُبَشِّرٌ يَعْنِي ابْنَ إِسْمَعِيلَ الْحَلَبِيَّ عَنْ أَبِي عَمْرٍو قَالَ يَعْنِي الْوَلِيدَ حَدَّثَنَا أَبُو عَمْرٍو قَالَ حَدَّثَنِي قَتَادَةُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَكُونُ فِي أُمَّتِي اخْتِلَافٌ وَفُرْقَةٌ قَوْمٌ يُحْسِنُونَ الْقِيلَ وَيُسِيئُونَ الْفِعْلَ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الدِّينِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ لَا يَرْجِعُونَ حَتَّى يَرْتَدَّ عَلَى فُوقِهِ هُمْ شَرُّ الْخَلْقِ وَالْخَلِيقَةِ طُوبَى لِمَنْ قَتَلَهُمْ وَقَتَلُوهُ يَدْعُونَ إِلَى كِتَابِ اللَّهِ وَلَيْسُوا مِنْهُ فِي شَيْءٍ مَنْ قَاتَلَهُمْ كَانَ أَوْلَى بِاللَّهِ مِنْهُمْ قَالُوا يَا رَسُولَ اللَّهِ مَا سِيمَاهُمْ قَالَ التَّحْلِيقُحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ سِيمَاهُمْ التَّحْلِيقُ وَالتَّسْبِيدُ فَإِذَا رَأَيْتُمُوهُمْ فَأَنِيمُوهُمْ قَالَ أَبُو دَاوُد التَّسْبِيدُ اسْتِئْصَالُ الشَّعْرِ","id":"Telah menceritakan kepada kami [Nashr bin Ashim Al Anthaki] berkata, telah menceritakan kepada kami [Al Walid] dan [Mubasysyir] -maksudnya Mubassyir bin Isma'il Al Halabi- dari [Abu Amru]. Ia (Al Walid) berkata; telah menceritakan kepada kami [Abu Amru] berkata; telah menceritakan kepadaku [Qatadah] dari [Abu Sa'id Al Khudri] dan [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Akan terjadi perbedaan dan perpecahan di antara umatku, sebagian kelompok pandai dalam berbicara namun akhlak mereka buruk. Mereka membaca Al-Qur'an namun tidak sampai melewati kerongkongan. Mereka keluar dari agama sebagaimana anak panah lepas dari busurnya, dan mereka tidak akan kembali lagi hingga anak panah kembali ke busurnya. Mereka adalah seburuk-buruk manusia. Maka beruntunglah orang yang membunuhnya dan mereka membunuhnya. Mereka mengajak kepada Al-Qur'an, tetapi mereka sendiri tidak mengamalkannya sama sekali. Siapa memerangi mereka, maka yang demikian lebih mulia di sisi Allah.\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana ciri-ciri mereka?\" Beliau menjawab: \"Rambutnya dicukur gundul.\" Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ciri mereka adalah rambutnya dicukur gundul dan dicabut, jika kalian mendapati mereka maka bunuhlah.\" Abu Dawud berkata, \"At tasbid adalah mencabut rambut.\""},"3985":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَ قَالَ عَلِيٌّ عَلَيْهِ السَّلَامإِذَا حَدَّثْتُكُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا فَلَأَنْ أَخِرَّ مِنْ السَّمَاءِ أَحَبُّ إِلَيَّ مِنْ أَنْ أَكْذِبَ عَلَيْهِ وَإِذَا حَدَّثْتُكُمْ فِيمَا بَيْنِي وَبَيْنَكُمْ فَإِنَّمَا الْحَرْبُ خَدْعَةٌ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَأْتِي فِي آخِرِ الزَّمَانِ قَوْمٌ حُدَثَاءُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقُولُونَ مِنْ قَوْلِ خَيْرِ الْبَرِيَّةِ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ لَا يُجَاوِزُ إِيمَانُهُمْ حَنَاجِرَهُمْ فَأَيْنَمَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ فَإِنَّ قَتْلَهُمْ أَجْرٌ لِمَنْ قَتَلَهُمْ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Al A'masy] dari [Khaitsamah] dari [Suwaid bin Ghafalah] ia berkata; [Ali radliallahu 'anhu] berkata, \"Jika aku menceritakan kepada kalian sebuah hadits Rasulullah shallallahu 'alaihi wasallam, maka jika aku jatuh dari langit lebih aku sukai dari pada aku harus berdusta. Dan jika aku berbicara tentang suatu permasalahan yang terjadi antara aku dengan kalian, maka sesungguhnya peperangan itu penuh dengan tipu daya. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada akhir zaman nanti akan muncul suatu kaum yang usianya masih muda, namun cita-cita mereka gila. Mereka berbicara berdasarkan perkataan manusia yang paling baik (Muhammad shallallahu 'alaihi wasallam). Tetapi mereka keluar dari Islam seperti keluarnya anak panah dari busurnya. Keimanan mereka tidak melampaui kerongkongan, maka dimanapun kalian mendapati mereka bunuhlah mereka. Sebab membunuh mereka akan diberi pahala pada hari kiamat.\""},"3986":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ أَخْبَرَنِي زَيْدُ بْنُ وَهْبٍ الْجُهَنِيُّأَنَّهُ كَانَ فِي الْجَيْشِ الَّذِينَ كَانُوا مَعَ عَلِيٍّ عَلَيْهِ السَّلَام الَّذِينَ سَارُوا إِلَى الْخَوَارِجِ فَقَالَ عَلِيٌّ عَلَيْهِ السَّلَامأَيُّهَا النَّاسُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ قَوْمٌ مِنْ أُمَّتِي يَقْرَءُونَ الْقُرْآنَ لَيْسَتْ قِرَاءَتُكُمْ إِلَى قِرَاءَتِهِمْ شَيْئًا وَلَا صَلَاتُكُمْ إِلَى صَلَاتِهِمْ شَيْئًا وَلَا صِيَامُكُمْ إِلَى صِيَامِهِمْ شَيْئًا يَقْرَءُونَ الْقُرْآنَ يَحْسِبُونَ أَنَّهُ لَهُمْ وَهُوَ عَلَيْهِمْ لَا تُجَاوِزُ صَلَاتُهُمْ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ لَوْ يَعْلَمُ الْجَيْشُ الَّذِينَ يُصِيبُونَهُمْ مَا قُضِيَ لَهُمْ عَلَى لِسَانِ نَبِيِّهِمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَكَلُوا عَنْ الْعَمَلِ وَآيَةُ ذَلِكَ أَنَّ فِيهِمْ رَجُلًا لَهُ عَضُدٌ وَلَيْسَتْ لَهُ ذِرَاعٌ عَلَى عَضُدِهِ مِثْلُ حَلَمَةِ الثَّدْيِ عَلَيْهِ شَعَرَاتٌ بِيضٌأَفَتَذْهَبُونَ إِلَى مُعَاوِيَةَ وَأَهْلِ الشَّامِ وَتَتْرُكُونَ هَؤُلَاءِ يَخْلُفُونَكُمْ فِي ذَرَارِيِّكُمْ وَأَمْوَالِكُمْ وَاللَّهِ إِنِّي لَأَرْجُو أَنْ يَكُونُوا هَؤُلَاءِ الْقَوْمَ فَإِنَّهُمْ قَدْ سَفَكُوا الدَّمَ الْحَرَامَ وَأَغَارُوا فِي سَرْحِ النَّاسِ فَسِيرُوا عَلَى اسْمِ اللَّهِ قَالَ سَلَمَةُ بْنُ كُهَيْلٍ فَنَزَّلَنِي زَيْدُ بْنُ وَهْبٍ مَنْزِلًا مَنْزِلًا حَتَّى مَرَّ بِنَا عَلَى قَنْطَرَةٍ قَالَ فَلَمَّا الْتَقَيْنَا وَعَلَى الْخَوَارِجِ عَبْدُ اللَّهِ بْنُ وَهْبٍ الرَّاسِبِيُّ فَقَالَ لَهُمْ أَلْقُوا الرِّمَاحَ وَسُلُّوا السُّيُوفَ مِنْ جُفُونِهَا فَإِنِّي أَخَافُ أَنْ يُنَاشِدُوكُمْ كَمَا نَاشَدُوكُمْ يَوْمَ حَرُورَاءَ قَالَ فَوَحَّشُوا بِرِمَاحِهِمْ وَاسْتَلُّوا السُّيُوفَ وَشَجَرَهُمْ النَّاسُ بِرِمَاحِهِمْ قَالَ وَقَتَلُوا بَعْضَهُمْ عَلَى بَعْضِهِمْ قَالَ وَمَا أُصِيبَ مِنْ النَّاسِ يَوْمَئِذٍ إِلَّا رَجُلَانِ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ الْتَمِسُوا فِيهِمْ الْمُخْدَجَ فَلَمْ يَجِدُوا قَالَ فَقَامَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ بِنَفْسِهِ حَتَّى أَتَى نَاسًا قَدْ قُتِلَ بَعْضُهُمْ عَلَى بَعْضٍ فَقَالَ أَخْرِجُوهُمْ فَوَجَدُوهُ مِمَّا يَلِي الْأَرْضَ فَكَبَّرَ وَقَالَ صَدَقَ اللَّهُ وَبَلَّغَ رَسُولُهُ فَقَامَ إِلَيْهِ عَبِيدَةُ السَّلْمَانِيُّ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ لَقَدْ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِي وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ حَتَّى اسْتَحْلَفَهُ ثَلَاثًا وَهُوَ يَحْلِفُ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ جَمِيلِ بْنِ مُرَّةَ قَالَ حَدَّثَنَا أَبُو الْوَضِيءِ قَالَ قَالَ عَلِيٌّ عَلَيْهِ السَّلَام اطْلُبُوا الْمُخْدَجَ فَذَكَرَ الْحَدِيثَ فَاسْتَخْرَجُوهُ مِنْ تَحْتِ ال��قَتْلَى فِي طِينٍ قَالَ أَبُو الْوَضِيءِ فَكَأَنِّي أَنْظُرُ إِلَيْهِ حَبَشِيٌّ عَلَيْهِ قُرَيْطِقٌ لَهُ إِحْدَى يَدَيْنِ مِثْلُ ثَدْيِ الْمَرْأَةِ عَلَيْهَا شُعَيْرَاتٌ مِثْلُ شُعَيْرَاتِ الَّتِي تَكُونُ عَلَى ذَنَبِ الْيَرْبُوعِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Abdul Malik bin Abu Sulaiman] dari [Salamah bin Kuhail] ia berkata; telah mengabarkan kepadaku [Zaid bin Wahb Al Juhani] Bahwasanya ia pernah bergabung dengan pasukan [Ali radliallahu 'anhu] yang menuju kaum Khawarij. Ali lalu berkata, \"Wahai manusia sekalian, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar sekelompok orang dari umatku, mereka membaca Al-Qur'an, dan bacaan kalian terhadap Al-Qur'an tidak sebanding dengan bacaan mereka, shalat kalian tidak sebanding dengan shalat mereka, dan puasa kalian tidak sebanding dengan puasa mereka sedikit pun. Mereka membaca Al-Qur'an dan menyangka bahwa bacaan itu baik untuk mereka, padahal bacaan mereka itu akan menjadi madharat bagi mereka. shalat mereka tidak melebihi kerongkongan mereka. Mereka keluar dari Islam seperti anak panah keluar dari busurnya. Sekiranya pasukan yang memerangi mereka mengetahui keutamaan memerangi mereka, sungguh mereka akan bermalas-malas untuk beramal (setelah memerangi mereka). Ciri-cirinya, di antara mereka ada seorang laki-laki yang mempunyai lengan tetapi tidak mempunyai siku (gemuk dan banyak dagingnya), pada panggal lengannya seperti buah dada dan berambut putih. Apakah kalian akan pergi kepada Mu'awiyah dan penduduk Syam, lalu kalian tinggalkan mereka bersama keluarga dan harta kalian? Demi Allah, sungguh aku sangat menginginkan mereka (memerangi). Sebab mereka telah menumpahkan darah yang diharamkan dan merampas hak manusia. Maka berjalanlah dengan nama Allah.\" -Salamah bin Kuhail berkata; \"Maka Zaid bin Wahab menunjukkan (menyebutkan) kepadaku tempat-tempat yang mereka lalui satu persatu hingga ketika sampai pada sebuah jembatan kami bertemu dengan orang-orang khawarij yang dipimpin oleh Abdullah bin Wahab Ar Rasibi, maka Ali berkata kepada mereka (kaum muslimin); \"Lemparkanlah tombak-tombak kalian dan hunuslah pedang kalian dari sarungnya, karena sesungguhnya aku khawatir jika mereka menuntut perdamaian pada kalian sebagaimana mereka menuntut perdamaian pada kalian di hari Harura, (sehingga setelah itu mereka membangun kekuatan untuk memerangi kaum muslimin), akhirnya pasukan kaum muslimin melemparkan tombak-tombak mereka, dan menghunuskan pedang serta menikam orang-orang khawarij dengan tombak mereka\", Zaid bin Wahab berkata; \"hingga sebagian (kaum muslimin) dapat membunuh sebagian (orang-orang khawarij) \", Zaid Wahab melanjutkan; \"pada waktu itu yang terbunuh dari kaum muslimin hanya dua orang, lalu Ali radliallahu 'anhu berkata; \"carilah di antara mereka Al Mukhdaj\", namun mereka tidak mendapatkannya, Zaid berkata; \"akhirnya Ali berdiri sendiri untuk mencarinya hingga ia sampai pada tumpukan mayat yang saling terbunuh\", Ali berkata; \"Keluarkanlah mereka\", maka akhirnya ia mendapatkan Al Mukhdaj dalam pendaman tanah, ia lantas bertakbir dan berkata; \"Maha benar Allah dan Rasul-Nya yang telah menyampaikannya (tentang informasi kejadian tersebut) \", lalu Abidah As Salmani mendekatinya dan berkata; \"Wahai Amirul mukminin, demi Allah yang tiada Ilah selain Dia, apakah engkau telah mendengar ini dari Rasulullah shallallahu 'alaihi wasallam, Ali berkata; \"Iya, demi Allah yang tiada Ilah selain Dia\", hingga Abidah memintanya untuk bersumpah tiga kali dan Ali pun bersumpah kepadanya tiga kali. telah menceritakan kepada kami [Muhammad bin Ubaid] berkata telah menceritakan kepada kami [Hammad bin Zaid] dari [Jamil bin Murrah] ia berkata; telah menceritakan kepada kami [Abu Al Wadhi`] berkata; Ali 'alahis salam berkata; \"carilah Al Mukhdaj … -lalu ia menyebutkan redaksi hadits- maka mereka mengeluarkannya dari bawah tumpukan mayat di bawah gundukan tanah, Abu Al Wadhi` berkata; \"seakan akan aku melihatnya (Al Mukhdaj) adalah seorang habasyah yang mengenakakan qiba' (sejenis pakaian luar, jaket atau rompi) salah satu tangannya kecil seperti buah dada perempuan yang memiliki bulu bulu kecil seperti bulu yang terdapat pada ekor yarbu' (binatang sejenis tupai).\""},"3987":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ عَنْ نُعَيْمِ بْنِ حَكِيمٍ عَنْ أَبِي مَرْيَمَ قَالَإِنْ كَانَ ذَلِكَ الْمُخْدَجُ لَمَعَنَا يَوْمَئِذٍ فِي الْمَسْجِدِ نُجَالِسُهُ بِاللَّيْلِ وَالنَّهَارِ وَكَانَ فَقِيرًا وَرَأَيْتُهُ مَعَ الْمَسَاكِينِ يَشْهَدُ طَعَامَ عَلِيٍّ عَلَيْهِ السَّلَام مَعَ النَّاسِ وَقَدْ كَسَوْتُهُ بُرْنُسًا لِي قَالَ أَبُو مَرْيَمَ وَكَانَ الْمُخْدَجُ يُسَمَّى نَافِعًا ذَا الثُّدَيَّةِ وَكَانَ فِي يَدِهِ مِثْلُ ثَدْيِ الْمَرْأَةِ عَلَى رَأْسِهِ حَلَمَةٌ مِثْلُ حَلَمَةِ الثَّدْيِ عَلَيْهِ شُعَيْرَاتٌ مِثْلُ سِبَالَةِ السِّنَّوْرِ قَالَ أَبُو دَاوُد وَهُوَ عِنْدَ النَّاسِ اسْمُهُ حَرْقُوسُ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] berkata, telah menceritakan kepada kami [Syababah bin Sawwar] dari [Nu'aim bin Hakim] dari [Abu Maryam] ia berkata, \"Ada seseorang yang pendek bersama kami dalam masjid, kami selalu duduk bersamanya baik di waktu siang maupun malam. Dia seorang yang fakir, aku juga melihatnya bergabung dengan orang-orang miskin menghadiri jamuan Ali radliallahu 'anhu bersama orang banyak. Aku memberinya burnus (sejenis mantel yang bertudung).\" Abu Maryam melanjutkan, \"Laki-laki pendek itu biasa dipanggil dengan nama Nafi', pemilik dua buah dada, tangannya seperti dada perempuan, dan pada panggal lengannya seperti puting susu yang ditumbuhi bulu seperti bulu kucing.\" Abu Dawud berkata, \"Bagi orang-orang ia biasa dipanggil dengan nama Harqus.\""},"3988":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ حَسَنٍ قَالَ حَدَّثَنِي عَمِّي إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُرِيدَ مَالُهُ بِغَيْرِ حَقٍّ فَقَاتَلَ فَقُتِلَ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] ia berkata; telah menceritakan kepadaku [Abdullah bin Hasan] ia berkata; telah menceritakan kepadaku pamanku [Ibrahim bin Muhammad bin Thalhah] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa yang hartanya akan dirampas tanpa hak, lalu ia melawan dan terbunuh maka ia syahid.\""},"3989":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ وَسُلَيْمَانُ بْنُ دَاوُدَ يَعْنِي أَبَا أَيُّوبَ الْهَاشِمِيَّ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ وَمَنْ قُتِلَ دُونَ أَهْلِهِ أَوْ دُونَ دَمِهِ أَوْ دُونَ دِينِهِ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] dan [Sulaiman bin Dawud] -maksudnya Sulaiman Abu Ayyub Al Hasyimi- dari [Ibrahim bin Sa'd] dari [Bapaknya] dari [Abu Ubaidah bin Muhammad bin Ammar bin Yasir] dari [Thalhah bin Abdullah] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa yang dibunuh karena membela hartanya maka ia syahid, siapa yang dibunuh karena membela keluarganya maka ia syahid, atau karena membela darahnya, atau karena membela agamanya maka ia syahid.\""},"3990":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ الشُّعَيْرِيُّ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ يَعْنِي ابْنَ عَمَّارٍ قَالَ حَدَّثَنِي إِسْحَقُ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ قَالَ قَالَ أَنَسٌكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَحْسَنِ النَّاسِ خُلُقًا فَأَرْسَلَنِي يَوْمًا لِحَاجَةٍ فَقُلْتُ وَاللَّهِ لَا أَذْهَبُ وَفِي نَفْسِي أَنْ أَذْهَبَ لِمَا أَمَرَنِي بِهِ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَرَجْتُ حَتَّى أَمُرَّ عَلَى صِبْيَانٍ وَهُمْ يَلْعَبُونَ فِي السُّوقِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَابِضٌ بِقَفَايَ مِنْ وَرَائِي فَنَظَرْتُ إِلَيْهِ وَهُوَ يَضْحَكُ فَقَالَ يَا أُنَيْسُ اذْهَبْ حَيْثُ أَمَرْتُكَ قُلْتُ نَعَمْ أَنَا أَذْهَبُ يَا رَسُولَ اللَّهِ قَالَ أَنَسٌ وَاللَّهِ لَقَدْ خَدَمْتُهُ سَبْعَ سِنِينَ أَوْ تِسْعَ سِنِينَ مَا عَلِمْتُ قَالَ لِشَيْءٍ صَنَعْتُ لِمَ فَعَلْتَ كَذَا وَكَذَا وَلَا لِشَيْءٍ تَرَكْتُ هَلَّا فَعَلْتَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Makhlad bin Khalid Asy Syu'airi] berkata, telah menceritakan kepada kami [Umar bin Yunus] berkata, telah menceritakan kepada kami [Ikrimah] -maksudnya Ikrimah bin Ammar- ia berkata; telah menceritakan kepadaku [Ishaq] -maksudnya Ishaq bin Abdullah bin Abu Thalhah- ia berkata; [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah orang yang paling baik akhlaknya. Suatu hari beliau mengutusku untuk suatu keperluan. Aku lalu berkata, \"Demi Allah, aku tidak akan pergi.\" Padahal dalam hatiku aku ingin pergi melaksanakan perintah perintah Nabi Allah shallallahu 'alaihi wasallam. Kemudian aku pergi hingga aku melewati anak-anak yang sedang bermain di pasar, namun tiba-tiba Rasulullah shallallahu 'alaihi wasallam memagang kerah bajuku dari belakang sambil tertawa. Beliau bersabda: \"Wahai Anas kecil, pergilah sebagaimana yang aku pesan tadi.\" Aku menjawab, \"Baik, ya Rasulullah. Aku akan pergi.\" Anas berkata, \"Demi Allah, aku telah membantu beliau selama tujuh atau sembilan tahun. Namun aku tidak pernah mendapati beliau mengomentari perbuatanku 'Kenapa kamu lakukan begini dan begini'. Atau sesuatu yang aku tinggalkan; 'Kenapa tidak kamu melakukan begini dan begini! '. "},"3991":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَخَدَمْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ سِنِينَ بِالْمَدِينَةِ وَأَنَا غُلَامٌ لَيْسَ كُلُّ أَمْرِي كَمَا يَشْتَهِي صَاحِبِي أَنْ أَكُونَ عَلَيْهِ مَا قَالَ لِي فِيهَا أُفٍّ قَطُّ وَمَا قَالَ لِي لِمَ فَعَلْتَ هَذَا أَوْ أَلَّا فَعَلْتَ هَذَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Sulaiman] -maksudnya Sulaiman bin Mughirah- dari [Tsabit] dari [Anas] ia berkata, \"Aku membantu Nabi shallallahu 'alaihi wasallam di Madinah selama sepuluh tahun. Aku hanyalah seorang anak kecil, tidak semua pelayanan yang aku berikan sesuai dengan hati sahabatku (Nabi shallallahu 'alaihi wasallam). Namun beliau tidak pernah mengatakan 'Hei..! ' Sama sekali kepadaku. Beliau juga tidak pernah mengatakan: \"Kenapa kamu lakukan ini! atau 'Kenapa tidak kamu lakukan begini! '. "},"3992":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا مُحَمَّدُ بْنُ هِلَالٍ أَنَّهُ سَمِعَ أَبَاهُ يُحَدِّثُ قَالَ قَالَ أَبُو هُرَيْرَةَ وَهُوَ يُحَدِّثُنَاكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ مَعَنَا فِي الْمَجْلِسِ يُحَدِّثُنَا فَإِذَا قَامَ قُمْنَا قِيَامًا حَتَّى نَرَاهُ قَدْ دَخَلَ بَعْضَ بُيُوتِ أَزْوَاجِهِ فَحَدَّثَنَا يَوْمًا فَقُمْنَا حِينَ قَامَ فَنَظَرْنَا إِلَى أَعْرَابِيٍّ قَدْ أَدْرَكَهُ فَجَبَذَهُ بِرِدَائِهِ فَحَمَّرَ رَقَبَتَهُ قَالَ أَبُو هُرَيْرَةَ وَكَانَ رِدَاءً خَشِنًا فَالْتَفَتَ فَقَالَ لَهُ الْأَعْرَابِيُّ احْمِلْ لِي عَلَى بَعِيرَيَّ هَذَيْنِ فَإِنَّكَ لَا تَحْمِلُ لِي مِنْ مَالِكَ وَلَا مِنْ مَالِ أَبِيكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَأَسْتَغْفِرُ اللَّهَ لَا وَأَسْتَغْفِرُ اللَّهَ لَا وَأَسْتَغْفِرُ اللَّهَ لَا أَحْمِلُ لَكَ حَتَّى تُقِيدَنِي مِنْ جَبْذَتِكَ الَّتِي جَبَذْتَنِي فَكُلُّ ذَلِكَ يَقُولُ لَهُ الْأَعْرَابِيُّ وَاللَّهِ لَا أُقِيدُكَهَا فَذَكَرَ الْحَدِيثَ قَالَ ثُمَّ دَعَا رَجُلًا فَقَالَ لَهُ احْمِلْ لَهُ عَلَى بَعِيرَيْهِ هَذَيْنِ عَلَى بَعِيرٍ شَعِيرًا وَعَلَى الْآخَرِ تَمْرًا ثُمَّ الْتَفَتَ إِلَيْنَا فَقَالَ انْصَرِفُوا عَلَى بَرَكَةِ اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Muhammad bin Hilal] Bahwasanya ia mendengar [Bapaknya] menceritakan, ia berkata; [Abu Hurairah] menceritakan, ia mengatakan, \"Rasulullah shallallahu 'alaihi wasallam duduk bersama kami membacakan hadits, ketika beliau berdiri kami pun ikut berdiri. hingga kami melihat beliau masuk ke salah satu rumah isterinya. Kemudian beliau membacakan hadits kepada kami di hari yang lain. lalu kami berdiri saat beliau berdiri, lantas kami melihat ke arah seorang Arab badui yang berpapasan dengan beliau. Badui itu menarik selendang beliau hingga lehernya merah.\" [Abu Hurairah] berkata, \"Selendang Nabi tersebut terbuat dari kain yang kasar, beliau lalu menoleh ke belakang. Badui itu berkata, \"Berikan kepadaku bekal (muatan) pada dua untaku ini. Maka sesungguhnya kamu tidak akan mampu memberikan bekal kepadaku baik dari hartamu sendiri maupun harta bapakmu.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Tidak. Dan aku memohon ampun kepada Allah, Tidak. Dan aku memohon ampun kepada Allah, Tidak. Dan aku memohon ampun kepada Allah. Aku tidak akan memberimu hingga engkau memberiku hak qishas karena tarikanmu terhadapku.\" Dan setiap itu pula, orang Arab badui itu berkata, \"Demi Allah, aku tidak akan memberimu hak qishah untuk itu.\" Lalu perawi menyebutkan hadits secara lengkap. Abu Hurairah berkata, \"Kemudian Rasulullah memanggil seorang laki-laki dan berkata kepadanya: \"Berikanlah bekal (muatan) kepadanya di atas dua untanya ini, berilah gandum untuk seekor unta dan kurma unta unta yang lainnya.\" Setelah itu beliau berpaling ke arah kami, beliau bersabda: \"Pergilah dengan berkah dari Allah Ta'ala.\""},"3993":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا قَابُوسُ بْنُ أَبِي ظَبْيَانَ أَنَّ أَبَاهُ حَدَّثَهُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبَّاسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْهَدْيَ الصَّالِحَ وَالسَّمْتَ الصَّالِحَ وَالِاقْتِصَادَ جُزْءٌ مِنْ خَمْسَةٍ وَعِشْرِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Qabus bin Abu Zhabyan] bahwa [Bapaknya] menceritakan kepadanya, ia berkata; telah menceritakan kepada kami [Abdullah bin Abbas] bahwa Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pentunjuk yang baik, ketetapan (dalam agama) yang baik dan kesederhaan adalah satu bagian dari dua puluh lima bagian tanda kenabian.\""},"3994":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سَعِيدٍ يَعْنِي ابْنَ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَظَمَ غَيْظًا وَهُوَ قَادِرٌ عَلَى أَنْ يُنْفِذَهُ دَعَاهُ اللَّهُ عَزَّ وَجَلَّ عَلَى رُءُوسِ الْخَلَائِقِ يَوْمَ الْقِيَامَةِ حَتَّى يُخَيِّرَهُ اللَّهُ مِنْ الْحُورِ الْعِينِ مَا شَاءَقَالَ أَبُو دَاوُد اسْمُ أَبِي مَرْحُومٍ عَبْدُ الرَّحْمَنِ بْنُ مَيْمُونٍ حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ عَنْ بِشْرٍ يَعْنِي ابْنَ مَنْصُورٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سُوَيْدِ بْنِ وَهْبٍ عَنْ رَجُلٍ مِنْ أَبْنَاءِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ مَلَأَهُ اللَّهُ أَمْنًا وَإِيمَانًا لَمْ يَذْكُرْ قِصَّةَ دَعَاهُ اللَّهُ زَادَ وَمَنْ تَرَكَ لُبْسَ ثَوْبِ جَمَالٍ وَهُوَ يَقْدِرُ عَلَيْهِ قَالَ بِشْرٌ أَحْسِبُهُ قَالَ تَوَاضُعًا كَسَاهُ اللَّهُ حُلَّةَ الْكَرَامَةِ وَمَنْ زَوَّجَ لِلَّهِ تَعَالَى تَوَّجَهُ اللَّهُ تَاجَ الْمُلْكِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Sa'id] -maksudnya Said bin Abu Ayyub- dari [Abu Marhum] dari [Sahl bin Mu'adz] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menahan kemarahan padahal ia mampu untuk meluapkannya, maka pada hari kiamat Allah akan memanggilnya di antara manusia, hingga Allah menyuruhnya untuk memilih bidadari sesuka hatinya.\" Abu Dawud berkata, \"Abu Marhum namanya adalah 'Abdurrahman bin Maimun.\" Telah menceritakan kepada kami [Uqbah bin Mukram] berkata, telah menceritakan kepada kami ['Abdurrahman] -maksudnya Abdur Rahman bin Mahdi- dari [Bisyr] -maksudnya Bisyr bin Manshur- dari [Muhammad bin 'Ajlan] dari [Suwaid bin Wahb] dari [seorang laki-laki] di antara anak-anak sahabat Nabi shallallahu 'alaihi wasallam, dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memenuhi keamanan dan keimanan -namun ia tidak menyebutkan kisah dalam hadits sebelumnya-, lalu Allah akan memanggilnya, perawi menambahkan, \"siapa meninggalkan dari memakai pakaian yang bagus padahal ia mampu -[Bisyr] mengatakan; aku mengira beliau mengatakan- karena merendah diri, Maka Allah akan memakaikan baginya baju kemuliaan. Dan barangsiapa menikah karena Allah Ta'ala maka Allah akan memberinya mahkota raja kepadanya.\""},"3995":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَعُدُّونَ الصُّرَعَةَ فِيكُمْ قَالُوا الَّذِي لَا يَصْرَعُهُ الرِّجَالُ قَالَ لَا وَلَكِنَّهُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menurut kalian, siapa yang kalian anggap paling kuat?\" para sahabat menjawab, \"Yaitu orang yang tidak terkalahkan dalam adu gulat.\" Beliau bersabda: \"Bukan itu, orang yang kuat adalah orang yang mampu menahan dirinya saat marah.\""},"3996":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَاسْتَبَّ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَضِبَ أَحَدُهُمَا غَضَبًا شَدِيدًا حَتَّى خُيِّلَ إِلَيَّ أَنَّ أَنْفَهُ يَتَمَزَّعُ مِنْ شِدَّةِ غَضَبِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ كَلِمَةً لَوْ قَالَهَا لَذَهَبَ عَنْهُ مَا يَجِدُهُ مِنْ الْغَضَبِ فَقَالَ مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشَّيْطَانِ الرَّجِيمِ قَالَ فَجَعَلَ مُعَاذٌ يَأْمُرُهُ فَأَبَى وَمَحِكَ وَجَعَلَ يَزْدَادُ غَضَبًا","id":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Abdul Malik bin Umair] dari ['Abdurrahman bin Abu Laila] dari [Mu'adz bin Jabal] ia berkata, \"Ada dua orang laki-laki saling mencela di sisi Nabi shallallahu 'alaihi wasallam, salah seorang dari mereka sangat marah hingga aku berfikir seolah olah hidungnya pecah karena marah yang memuncak. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sungguh, aku benar-benar tahu sebuah kalimat yang jika dibaca oleh seseorang maka akan hilang kemarahan yang ia rasakan.\" Seseorang lalu bertanya, \"Wahai Rasulullah, apa itu?\" beliau bersabda: \"ALLAHUMMA INNI A'UUDZU BIKA MINASYSYAITHAANIRRAJIIM (Ya Allah, aku berlindung kepadamu dari setan yang terkutuk).\" Perawi berkata, \"Mu'adz lantas menyuruh laki-laki itu untuk mengucapkannya, tetapi ia enggan dan justru bertambah amarahnya.\""},"3997":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ قَالَاسْتَبَّ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ أَحَدُهُمَا تَحْمَرُّ عَيْنَاهُ وَتَنْتَفِخُ أَوْدَاجُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ كَلِمَةً لَوْ قَالَهَا هَذَا لَذَهَبَ عَنْهُ الَّذِي يَجِدُ أَعُوذُ بِاللَّهِ مِنْ الشَّيْطَانِ الرَّجِيمِ فَقَالَ الرَّجُلُ هَلْ تَرَى بِي مِنْ جُنُونٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Adi bin Tsabit] dari [Sulaiman bin Shurd] ia berkata, \"Ada dua orang saling mencela di sisi Nabi shallallahu 'alaihi wasallam, salah seorang dari mereka matanya tampak memerah dan urat lehernya tampak menegang. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sungguh, aku tahu sebuah kalimat yang jika dibaca oleh seseorang maka akan hilang apa yang dirasakannya (rasa marah). Yaitu, A'UUDZU BILLAAHI MINAS SYAITHAANIR RAJIIMI (aku berlindung kepada Allah dari setan yang terkutuk).\" Laki-laki yang marah itu lalu berkata, \"Apakah engkau melihatku seperti orang gila?\""},"3998":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ عَنْ أَبِي ذَرٍّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا إِذَا غَضِبَ أَحَدُكُمْ وَهُوَ قَائِمٌ فَلْيَجْلِسْ فَإِنْ ذَهَبَ عَنْهُ الْغَضَبُ وَإِلَّا فَلْيَضْطَجِعْحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ دَاوُدَ عَنْ بَكْرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا ذَرٍّ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ الْحَدِيثَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Abu Harb bin Abul Aswad] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Jika salah seorang dari kalian marah dan ia dalam keadaan berdiri, hendakah ia duduk. Jika rasa marahnya hilang (maka itu yang dikehendaki), jika tidak hendaklah ia berbaring.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari [Dawud] dari [Bakr] bahwa Nabi shallallahu 'alaihi wasallam mengutus Abu Dzar dengan membawa pesan hadits ini.\" Abu Dawud berkata, \"Hadits ini adalah yang paling shahih di antara dua hadits yang ada.\""},"3999":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْمَعْنَى قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو وَائِلٍ الْقَاصُّ قَالَ دَخَلْنَا عَلَى عُرْوَةَ بْنِ مُحَمَّدٍ السَّعْدِيِّ فَكَلَّمَهُ رَجُلٌ فَأَغْضَبَهُ فَقَامَ فَتَوَضَّأَ ثُمَّ رَجَعَ وَقَدْ تَوَضَّأَ فَقَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي عَطِيَّةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْغَضَبَ مِنْ الشَّيْطَانِ وَإِنَّ الشَّيْطَانَ خُلِقَ مِنْ النَّارِ وَإِنَّمَا تُطْفَأُ النَّارُ بِالْمَاءِ فَإِذَا غَضِبَ أَحَدُكُمْ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] dan [Al Hasan bin Ali] secara makna, keduanya berkata; telah menceritakan kepada kami [Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Abu Wail Al Qash] ia berkata, \"Kami masuk menemui [Urwah bin Muhammad As Sa'di], lalu ada seorang laki-laki berbicara dengannya hingga membuatnya murka. Lantas ia berdiri berwudhu dan kembali lagi dalam keadaan telah berwudhu.\" Setelah itu ia berkata, \" [Bapakku] telah menceritakan kepadaku, dari kakekku, [Athiyah]. Ia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya marah itu dari setan dan setan diciptakan dari api, sementara api akan mati dengan air, maka jika salah seorang dari kalian marah hendaklah berwudhu.\""},"4000":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْمَا خُيِّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَمْرَيْنِ إِلَّا اخْتَارَ أَيْسَرَهُمَا مَا لَمْ يَكُنْ إِثْمًا فَإِنْ كَانَ إِثْمًا كَانَ أَبْعَدَ النَّاسِ مِنْهُ وَمَا انْتَقَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَفْسِهِ إِلَّا أَنْ تُنْتَهَكَ حُرْمَةُ اللَّهِ تَعَالَى فَيَنْتَقِمُ لِلَّهِ بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] ia berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam diberi dua pilihan kecuali beliau memilih yang paling mudah dari keduanya selama tidak termasuk dosa. Jika hal itu bagian dari dosa, maka beliau adalah orang yang paling menjauhi dosa di antara manusia. Dan Rasulullah shallallahu 'alaihi wasallam tidak pernah merasa dendam untuk dirinya kecuali jika itu berhubungan dengan pelanggaran terhadap kehormatan Allah, maka beliau dendam karena Allah.\""}};
